INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010a000eqh7mz66yyic8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Który filozof mistyczny wpłynął na koncepcję ''natury Boga'' atakowanej przez Konrada?', '{"options": ["Immanuel Kant", "Jakub Boehme", "Baruch Spinoza", "Gottfried Leibniz"]}', '1', NULL, '{}', '{"explanation": "Jakub Boehme rozróżniał Boga (Ungrund) od Jego ''wiecznej natury'' - Konrad atakuje właśnie tę naturę (''Strzelę przeciw Twej naturze''), nie samego Boga."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010b000fqh7mgxia6tw8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Co oznacza termin ''Ungrund'' w teozofii Boehmego, do której nawiązuje Wielka Improwizacja?', '{"options": ["grzech pierworodny", "bezdeń, otchłań poprzedzająca stworzenie", "natura ludzka", "harmonia wszechświata"]}', '1', NULL, '{}', '{"explanation": "Ungrund (Bezdeń) to w teozofii Boehmego pierwotna otchłań, z której wyłania się zarówno Bóg, jak i siły ciemności - wspólne źródło dobra i zła."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010b000gqh7mno8kb9ci', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Który romantyczny filozof rozwinął koncepcję poety-demiurga, obecną w Wielkiej Improwizacji?', '{"options": ["Hegel", "Schelling", "Fichte", "Schopenhauer"]}', '1', NULL, '{}', '{"explanation": "Friedrich Schelling rozwinął romantyczną filozofię sztuki, w której poeta jest demiurgiem - twórcą światów analogicznym do Boga-Stwórcy."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010b000hqh7molry4ts9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Słowa Konrada ''Stamtąd przyszły siły moje, skąd do Ciebie przyszły Twoje'' nawiązują do jakiej koncepcji?', '{"options": ["panteizmu Spinozy", "wspólnego źródła sił Boga i człowieka (Boehme)", "dualizmu kartezjańskiego", "idei platońskich"]}', '1', NULL, '{}', '{"explanation": "Według Boehmego siły człowieka i Boga mają wspólne źródło w Bezdni (Ungrund) - Konrad powołuje się na tę równość pochodzenia."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010b000iqh7mzjf97vtl', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Co Zofia Stefanowska rozumiała przez ''figurę'' w interpretacji mesjanizmu?', '{"options": ["metaforę poetycką", "sposób przedstawiania jednej realności historycznej przez drugą", "postać literacką", "symbol religijny"]}', '1', NULL, '{}', '{"explanation": "Figura (za Auerbachem) to sposób przedstawiania, gdzie obie rzeczywistości są historyczne - męka Chrystusa jest figurą cierpienia Polski."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010b000jqh7m8h9uw9n3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Dlaczego według Stefanowskiej postać Chrystusa w ''Księgach narodu'' została zsekularyzowana?', '{"options": ["z powodu ateizmu Mickiewicza", "by mogła być figurą losu Polski", "dla uniknięcia cenzury", "pod wpływem oświecenia"]}', '1', NULL, '{}', '{"explanation": "Chrystus jako reformator (nie Zbawiciel) mógł być figurą Polski - zsekularyzowany, by wszystko mogło ''wypełnić się w losie Polski''."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010c000kqh7m6ok6kv5g', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jak Maria Janion określiła funkcję mesjanizmu w polskiej kulturze?', '{"options": ["jako wyraz nacjonalizmu", "jako kompensacyjną odpowiedź na traumę historyczną", "jako kontynuację średniowiecza", "jako wpływ literatury francuskiej"]}', '1', NULL, '{}', '{"explanation": "Janion analizowała mesjanizm przez pryzmat psychoanalizy - jako kompensację traumy, próbę przezwyciężenia ''kompleksu winy'' i poczucia niższości."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclol0003qh6eh1rmricr', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'W jakim mieście toczy się akcja powieści?', '{"options": ["Moskwa", "Petersburg", "Kijów", "Odessa"]}', '1', NULL, '{}', '{"explanation": "Akcja powieści toczy się w Petersburgu - stolicy Rosji carskiej, mieście kontrastów między bogactwem a nędzą."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclol0004qh6eo9l0xagg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Jak ma na imię główny bohater powieści?', '{"options": ["Piotr Raskolnikow", "Rodion Raskolnikow", "Dmitrij Raskolnikow", "Aleksiej Raskolnikow"]}', '1', NULL, '{}', '{"explanation": "Głównym bohaterem jest Rodion Romanowicz Raskolnikow - były student prawa mieszkający w Petersburgu."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclom0009qh6egqd789oa', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Kim jest Porfiry Pietrowicz?', '{"options": ["Lekarz Raskolnikowa", "Śledczy prowadzący sprawę morderstwa", "Przyjaciel Raskolnikowa", "Mąż Duni"]}', '1', NULL, '{}', '{"explanation": "Porfiry Pietrowicz to komisarz śledczy prowadzący sprawę zabójstwa lichwiarki, który psychologicznie rozgrywa Raskolnikowa."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclom000aqh6ehcs1ojf7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Kim jest Razumichin?', '{"options": ["Bratem Raskolnikowa", "Najlepszym przyjacielem Raskolnikowa", "Śledczym", "Lekarzem"]}', '1', NULL, '{}', '{"explanation": "Razumichin to jedyny prawdziwy przyjaciel Raskolnikowa - student, wesoły i dobry człowiek, który później zakocha się w Duni."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclom000eqh6eu80fco1q', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Kim jest Arkadiusz Swidrigajłow?', '{"options": ["Ojcem Duni", "Byłym pracodawcą Duni, libertyn próbujący ją uwieść", "Przyjacielem Raskolnikowa", "Bratem Soni"]}', '1', NULL, '{}', '{"explanation": "Swidrigajłow to były pracodawca Duni, który ją prześladował - cynik i libertyn, który podsłuchał wyznanie Raskolnikowa i później popełnił samobójstwo."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclon000fqh6eicw2qfpi', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Kim jest Piotr Pietrowicz Łużyn?', '{"options": ["Bratem Raskolnikowa", "Narzeczonym Duni, próżnym i podłym karierowiczem", "Lekarzem", "Komisarzem policji"]}', '1', NULL, '{}', '{"explanation": "Łużyn to 45-letni karierowicz, który chce poślubić biedną Dunię, żeby miała wobec niego wdzięczność i była mu podporządkowana."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclon000gqh6e4s77rijp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Dlaczego Sonia stała się prostytutką?', '{"options": ["Z własnego wyboru", "Została zmuszona przez Raskolnikowa", "Z rozpaczy po śmierci ojca", "Aby wykarmić głodujące rodzeństwo i chorą macochę"]}', '3', NULL, '{}', '{"explanation": "Sonia poświęciła się dla rodziny - poszła na żółty bilet, żeby wyżywić troje małych dzieci macochy i chorobliwie zazdrosną Katarzynę Iwanownę."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclon000jqh6e2zeel9a4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Kto w końcu wyszedł za mąż za Razumichina?', '{"options": ["Sonia", "Dunia", "Nastasja", "Katarzyna"]}', '1', NULL, '{}', '{"explanation": "Dunia wyszła za mąż za Razumichina - przyjaciela jej brata, który opiekował się rodziną Raskolnikowów podczas choroby Rodiona."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010c000lqh7m7l6g43nz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Co według Wiktora Weintrauba oznacza termin ''romantyczny tytanizm''?', '{"options": ["kult siły fizycznej", "bunt przeciw Bogu chrześcijańskiemu (nie pogańskim bogom)", "naśladowanie mitologii greckiej", "idealizację przemocy"]}', '1', NULL, '{}', '{"explanation": "Weintraub podkreślał, że polski prometeizm to bunt przeciw Bogu chrześcijańskiemu - co czyni go radykalniejszym niż mit antyczny."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010c000mqh7mqmmwqbd5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Która badaczka analizowała Wielką Improwizację jako ''mechanizm obronny rozbitej podmiotowości''?', '{"options": ["Maria Janion", "Zofia Stefanowska", "Kwiryna Ziemba", "Alina Witkowska"]}', '2', NULL, '{}', '{"explanation": "Kwiryna Ziemba interpretowała utożsamienie z ''Milionem'' jako mechanizm obronny - wzmocnienie ''ja'' przez identyfikację ze zbiorowością."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010c000nqh7mx3jeytfp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Do jakiej biblijnej księgi nawiązuje konflikt Konrada z milczącym Bogiem?', '{"options": ["Księga Rodzaju", "Księga Hioba", "Pieśń nad Pieśniami", "Apokalipsa"]}', '1', NULL, '{}', '{"explanation": "Księga Hioba to archetypiczny tekst o teodycei - niewinny cierpiący pyta Boga o sens cierpienia, Bóg ostatecznie odpowiada z wichru."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010c000oqh7mrqksmkhs', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Co według Alfreda Galla stanowi mesjanizm w perspektywie postkolonialnej?', '{"options": ["wyraz polskiego nacjonalizmu", "kontrdyskurs wobec hegemonii filozofii niemieckiej", "naśladowanie mesjanizmu francuskiego", "formę ucieczki od rzeczywistości"]}', '1', NULL, '{}', '{"explanation": "Gall interpretuje mesjanizm jako świadomą strategię - ''zawłaszczenie dyskursu hegemonialnego'' (Hegla) i stworzenie kontrdyskursu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010f000pqh7mta5drxx7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Czym różni się polski prometeizm od klasycznego mitu Prometeusza?', '{"options": ["brakiem elementu cierpienia", "buntem przeciw Bogu chrześcijańskiemu, nie pogańskim bogom", "happy endem", "brakiem poświęcenia dla ludzkości"]}', '1', NULL, '{}', '{"explanation": "Prometeusz buntował się przeciw Zeusowi (bóg pogański), Konrad - przeciw Bogu chrześcijańskiemu, co czyni bunt bardziej radykalnym i bluźnierczym."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010f000qqh7mr8vtltlx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jaką funkcję pełni omdlenie Konrada w strukturze dramatu?', '{"options": ["tylko dramaturgiczną (napięcie)", "chroni bohatera przed wypowiedzeniem pełnego bluźnierstwa", "symbolizuje śmierć", "pokazuje słabość fizyczną"]}', '1', NULL, '{}', '{"explanation": "Omdlenie można interpretować jako interwencję Opatrzności lub wewnętrzny hamulec - chroni Konrada przed potępieniem."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010f000rqh7myjtj61x0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Na czym polega ambiwalencja żądania ''rządu dusz'' przez Konrada?', '{"options": ["jest zarówno modlitwą, jak i groźbą", "łączy miłość do narodu z pragnieniem despotycznej władzy", "wyraża zarówno wiarę, jak i ateizm", "jest jednocześnie szczere i ironiczne"]}', '1', NULL, '{}', '{"explanation": "Konrad chce władzy z miłości, ale samo pragnienie absolutnej władzy nad duszami ma rysy despotyzmu - to napięcie jest kluczowe."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010f000sqh7mplsf0kl0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Co Mickiewicz miał na myśli pisząc w liście o ''wyrzygnięciu dumy''?', '{"options": ["krytykę arystokracji", "oczyszczenie Konrada z pychy przez Improwizację", "odrzucenie filozofii niemieckiej", "pochwałę pokory"]}', '1', NULL, '{}', '{"explanation": "Mickiewicz pisał, że Konrad musiał ''wyrzygnąć dumę'' - Improwizacja jest katharsis, oczyszczeniem z pychy, które umożliwia przemianę."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010f000tqh7ml3ye16zf', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Który element teozofii Boehmego tłumaczy słowa Konrada o ataku ''przeciw naturze'' Boga?', '{"options": ["koncepcja predestynacji", "rozróżnienie Boga (Ungrund) od Jego ''wiecznej natury'' zawierającej ciemne siły", "idea reinkarnacji", "dualizm dobra i zła"]}', '1', NULL, '{}', '{"explanation": "Boehme rozróżniał absolutny Bóg (Ungrund) od ''wiecznej natury'' zawierającej też ciemne siły. Konrad atakuje tę naturę, nie sam Absolut."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010f000uqh7mz311v72i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Jak Natalia Piórczyńska interpretuje ''lucyferyczny'' charakter buntu Konrada?', '{"options": ["jako satanizm", "jako aspirację do boskości bez odrzucenia Boga", "jako nihilizm", "jako ateizm"]}', '1', NULL, '{}', '{"explanation": "Piórczyńska widzi w buncie Konrada nie szatański nihilizm, lecz lucyferyczną aspirację do boskości - chce być jak Bóg, nie przeciw Bogu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloo000pqh6eje8jvvlo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Jak zakończyła swoje życie Katarzyna Iwanowna?', '{"options": ["Zmarła z gruźlicy podczas żebrania z dziećmi na ulicy", "Została zamordowana", "Popełniła samobójstwo", "Wyzdrowiała"]}', '0', NULL, '{}', '{"explanation": "Katarzyna, wypędzona przez gospodynię, zmusiła dzieci do żebrania na ulicy. Dostała krwotoku i zmarła w mieszkaniu Soni."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloo000tqh6ereqfj4f9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Co Łużyn próbował zrobić Soni podczas stypy?', '{"options": ["Dać jej pieniądze", "Podrzucić jej 100 rubli i oskarżyć o kradzież", "Pomóc jej znaleźć pracę", "Zaproponować małżeństwo"]}', '1', NULL, '{}', '{"explanation": "Łużyn podstępnie wsunął Soni do kieszeni 100 rubli, żeby potem oskarżyć ją o kradzież i zdyskredytować przed rodziną Raskolnikowów. Demaskuje go Lebieziatnikow."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloo000vqh6etee2j1s3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Jak zakończył życie Swidrigajłow?', '{"options": ["Wyjechał za granicę", "Zastrzelił się z rewolweru", "Został zabity przez Dunię", "Umarł z choroby"]}', '1', NULL, '{}', '{"explanation": "Po odrzuceniu przez Dunię Swidrigajłow rozdał pieniądze (dzieciom Marmeladowów, Soni, swojej narzeczonej), a rano zastrzelił się przy wieży celnej."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev7zk0000qhd90hfitfme', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jak nazywał się syn Odyseusza?', '{"options": ["Telemach", "Parys", "Hektor", "Patrokles"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Telemach był synem Odyseusza i Penelopy. W Odysei opisane są także jego przygody."}', '2025-10-24 22:16:52.015', '2025-10-24 22:16:52.015', 'Odyseja');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010g000vqh7mx69vq35b', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Co według filozofii Schellinga oznacza, że poeta jest ''organem Absolutu''?', '{"options": ["poeta jest narzędziem władzy", "przez poetę przemawia nieskończoność, tworzy jak Bóg", "poeta służy państwu", "poeta przekazuje tradycję"]}', '1', NULL, '{}', '{"explanation": "U Schellinga sztuka jest ''organem Absolutu'' - przez geniusza artystycznego przemawia nieskończoność, poeta tworzy światy jak demiurg."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010g000wqh7mphxxjtso', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Jak Leibnizowska teodyceja, krytykowana przez Konrada, wyjaśnia istnienie zła?', '{"options": ["zło jest iluzją", "świat jest najlepszy z możliwych, zło jest koniecznym elementem harmonii", "zło pochodzi od diabła", "Bóg nie jest wszechmocny"]}', '1', NULL, '{}', '{"explanation": "Leibniz twierdził, że żyjemy w ''najlepszym z możliwych światów'' - zło jest konieczne dla większego dobra. Konrad odrzuca tę optymistyczną teodycję."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010g000xqh7mr9knwvns', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Jaką rolę w interpretacji postkolonialnej pełni mesjanizm według koncepcji ''appropriation''?', '{"options": ["jest formą kulturowej kapitulacji", "jest zawłaszczeniem dyskursu hegemonicznego i przekształceniem go na własne potrzeby", "jest odrzuceniem kultury zachodniej", "jest imitacją wzorców niemieckich"]}', '1', NULL, '{}', '{"explanation": "Appropriation (zawłaszczenie) polega na przejęciu dyskursu dominującego (heglizmu) i przekształceniu go - mesjanizm używa kategorii Hegla przeciwko niemu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010g000yqh7mukh3fsh9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Co oznacza ''chytrość rozumu'' (List der Vernunft) w filozofii Hegla i jak mesjanizm ją odwraca?', '{"options": ["rozum manipuluje jednostkami dla postępu; mesjanizm czyni Polskę podmiotem, nie narzędziem", "rozum jest zły; mesjanizm gloryfikuje uczucie", "rozum jest ukryty; mesjanizm go ujawnia", "rozum jest boski; mesjanizm go sekularyzuje"]}', '0', NULL, '{}', '{"explanation": "U Hegla ''chytry rozum'' używa narodów jako narzędzi postępu. Mesjanizm odwraca: Polska nie jest narzędziem, lecz podmiotem zbawienia."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010g000zqh7mxivtbucv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Jakie znaczenie ma fakt, że Wielka Improwizacja jest TRZECIĄ improwizacją Konrada w dramacie?', '{"options": ["symbolizuje Trójcę Świętą", "pokazuje narastanie natchnienia - od pieśni przez hymn do konfrontacji z Bogiem", "nawiązuje do trzech zaborców", "jest przypadkowe"]}', '1', NULL, '{}', '{"explanation": "Zofia Stefanowska analizowała sekwencję trzech improwizacji jako narastanie natchnienia - kulminację stanowi trzecia, najdłuższa."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010i0010qh7mnfj9v8cn', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Co według Ryszarda Przybylskiego oznacza ''milczenie'' Boga w Wielkiej Improwizacji?', '{"options": ["nieistnienie Boga", "potwierdzenie oskarżeń Konrada (Bóg nie ma kontrargumentów)", "próbę cierpliwości", "element dramaturgiczny"]}', '1', NULL, '{}', '{"explanation": "Przybylski interpretował milczenie Boga jako potwierdzenie zarzutów - skoro Bóg nie odpowiada, może nie ma czym się bronić."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010j0011qh7mvfv8tx30', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 4, 'Jak koncepcja ''siedmiu duchów źródłowych'' Boehmego może tłumaczyć strukturę sił w Wielkiej Improwizacji?', '{"options": ["siedem duchów to siedem grzechów głównych", "siły Boga i Konrada mają wspólne kosmiczne źródło w przedwiecznej naturze", "siedem duchów to anioły strzegące Konrada", "odnosi się do siedmiu scen dramatu"]}', '1', NULL, '{}', '{"explanation": "Boehme mówił o ''siedmiu duchach źródłowych'' jako siłach kosmicznych. Konrad powołuje się na wspólne źródło sił - jego i Boga."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010j0012qh7mcmnixkvm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 4, 'Jaką funkcję pełni autocenzura Mickiewicza (niedopowiedzenie bluźnierstwa) według współczesnych interpretacji?', '{"options": ["tylko uniknięcie cenzury carskiej", "utrzymanie ambiwalencji tekstu i ochrona przed jednoznacznym potępieniem bohatera", "brak odwagi artystycznej", "względy religijne autora"]}', '1', NULL, '{}', '{"explanation": "Kwiryna Ziemba i inni badacze widzą w niedopowiedzeniu świadomą strategię - ambiwalencja chroni tekst i bohatera przed jednoznaczną oceną."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010j0013qh7mhz8d3fo1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 4, 'Jak wiersze z rękopisów III cz. Dziadów (''Do Samotności'', ''Te rozkwitłe świeżo drzewa...'') oświetlają genezę Wielkiej Improwizacji?', '{"options": ["nie mają związku z Improwizacją", "pokazują rozpad podmiotowości i mechanizmy obronne, które kulminują w ''Nazywam się Milion''", "są tylko ćwiczeniami stylistycznymi", "przedstawiają innego bohatera"]}', '1', NULL, '{}', '{"explanation": "Kwiryna Ziemba analizowała te liryki jako świadectwo kryzysu podmiotowości Mickiewicza - Improwizacja to próba jej rekonstrukcji przez utożsamienie ze zbiorowością."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010j0014qh7mkg4n5bjy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 4, 'Na czym polega ''paradoks polskiej mentalności postkolonialnej'' według Marii Janion?', '{"options": ["Polacy są jednocześnie kolonizatorami i kolonizowanymi", "poczucie niższości wobec Zachodu kompensowane mesjanistyczną dumą i poczuciem wyższości moralnej", "Polacy naśladują kolonizatorów", "mesjanizm jest formą kolonizacji wewnętrznej"]}', '1', NULL, '{}', '{"explanation": "Janion opisuje ''zamknięte koło niższości i wyższości'' - poczucie peryferyjności kompensowane przekonaniem o moralnej wyższości nad ''zepsutym'' Zachodem."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclop0015qh6er7tmfogl', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Jaką rolę pełni motyw snu w powieści?', '{"options": ["Tylko urozmaicenie fabuły", "Ujawnianie prawdziwych uczuć i sumienia bohatera", "Przepowiadanie przyszłości", "Humor"]}', '1', NULL, '{}', '{"explanation": "Sny (koń, śmiejąca się lichwarka, zaraza) ujawniają prawdziwe uczucia Raskolnikowa, jego sumienie i niemożność pogodzenia się ze zbrodnią."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloq0019qh6ebc0muqhp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Co zrobiła Dunia, gdy Swidrigajłow próbował ją uwieść?', '{"options": ["Zgodziła się", "Uciekła", "Strzeliła do niego z rewolweru (dwa razy chybiła)", "Wezwała pomoc"]}', '2', NULL, '{}', '{"explanation": "Dunia strzeliła do Swidrigajłowa z jego własnego rewolweru - pierwszy raz ledwo go drasnęła, drugi raz nie było naboju. Swidrigajłow ją wtedy wypuścił."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloq001dqh6en9xi4u6p', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 3, 'Które motywy są kluczowe w powieści? (wybierz wszystkie poprawne)', '{"options": ["Grzech i odkupienie", "Teoria nadczłowieka", "Cierpienie jako droga zbawienia", "Miłość romantyczna", "Nędza społeczna", "Walka klas"]}', '[0, 1, 2, 4]', NULL, '{}', '{"explanation": "Kluczowe motywy to: grzech i odkupienie, teoria nadczłowieka, cierpienie zbawcze, nędza społeczna. Miłość i walka klas są drugorzędne."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010j0015qh7mghsfk2ay', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 4, 'Jak rozumieć twierdzenie, że mesjanizm Mickiewicza to ''historiozofia podporządkowanych''?', '{"options": ["jest filozofią dla mas niewykształconych", "jest kontrnarracją tożsamościową wobec dominującego dyskursu (Hegla), przekształcającą słabość w siłę", "podporządkowuje się filozofii niemieckiej", "jest wyrazem religijnego fatalizmu"]}', '1', NULL, '{}', '{"explanation": "Mesjanizm to historiozofia narodu wykluczonego z ''dziejów'' przez Hegla - przekształca marginalizację w wybraństwo, słabość w moc zbawczą."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010j0016qh7myauhcamw', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Które elementy filozofii Boehmego są obecne w Wielkiej Improwizacji?', '{"options": ["koncepcja wspólnego źródła sił Boga i człowieka", "rozróżnienie Boga od Jego ''natury''", "idea reinkarnacji", "siedem duchów źródłowych", "predestynacja kalwińska"]}', '[0, 1, 3]', NULL, '{}', '{"explanation": "Boehme wpływa przez: wspólne źródło sił, rozróżnienie Bóg/natura, siedem duchów. Reinkarnacja i predestynacja to inne tradycje."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010k0017qh7ms8o133m7', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Które interpretacje Wielkiej Improwizacji pojawiają się w tradycji badawczej?', '{"options": ["romantyczno-patriotyczna (szlachetny bunt)", "religijna (grzech pychy wymagający nawrócenia)", "marksistowska (walka klas)", "psychoanalityczna (mechanizmy obronne)", "postkolonialna (kontrdyskurs)"]}', '[0, 1, 3, 4]', NULL, '{}', '{"explanation": "Główne nurty: romantyczny, religijny, psychoanalityczny (Janion), postkolonialny (Gall). Interpretacja marksistowska nie jest typowa dla tego tekstu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010k0018qh7mauo0o6hy', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Dopasuj badacza do głównej tezy interpretacyjnej.', '{"leftColumn": [{"id": "A", "text": "Wiktor Weintraub"}, {"id": "B", "text": "Zofia Stefanowska"}, {"id": "C", "text": "Alfred Gall"}], "rightColumn": [{"id": 1, "text": "''romantyczny tytanizm'' - bunt przeciw Bogu chrześcijańskiemu"}, {"id": 2, "text": "figuralna interpretacja mesjanizmu"}, {"id": 3, "text": "mesjanizm jako postkolonialny kontrdyskurs"}], "matchingType": "scholar_thesis"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{}', '{"explanation": "Weintraub - tytanizm, Stefanowska - figura, Gall - postkolonializm."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010k0019qh7m7r4o7qpf', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Które cechy wyróżniają polski prometeizm od zachodnioeuropejskiego (Byron, Shelley)?', '{"options": ["bunt przeciw Bogu chrześcijańskiemu (nie pogańskim bogom)", "kontekst narodowy (cierpienie narodu, nie jednostki)", "połączenie z mesjanizmem", "całkowite odrzucenie wiary", "wyraźniejsza ambiwalencja (bohater może być ocalony)"]}', '[0, 1, 2, 4]', NULL, '{}', '{"explanation": "Polski prometeizm: chrześcijański kontekst, wymiar narodowy, związek z mesjanizmem, ambiwalencja. NIE całkowite odrzucenie wiary."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010k001aqh7mx6d7ar2q', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Uzupełnij analizę problemu teodycei w Wielkiej Improwizacji.', '{"gaps": [{"id": 1, "options": ["istnienia Boga", "pogodzenia dobrego Boga z istnieniem zła", "wolnej woli", "nieśmiertelności"]}, {"id": 2, "options": ["Augustyna", "Leibniza", "Tomasza z Akwinu", "Kalwina"]}, {"id": 3, "options": ["nieistnienie", "mądrość bez miłości", "słabość", "okrucieństwo"]}, {"id": 4, "options": ["zgodę", "brak kontrargumentów", "gniew", "wybaczenie"]}], "textWithGaps": "Teodyceja to problem [1]. Konrad odrzuca optymistyczną teodycję [2], zarzucając Bogu [3]. Milczenie Boga może oznaczać [4]."}', '[1, 1, 1, 1]', NULL, '{}', '{"explanation": "Teodyceja = problem zła, Leibniz = ''najlepszy ze światów'', zarzut = mądrość bez miłości, milczenie = brak obrony."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010m001bqh7m22sqi17w', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Które funkcje pełniła idea mesjanistyczna dla polskiej emigracji po 1831 roku?', '{"options": ["nadawanie sensu cierpieniu", "mobilizacja polityczna", "zachowanie nadziei w beznadziejnej sytuacji", "budowanie sojuszy z zaborcami", "tworzenie tożsamości zbiorowej na emigracji"]}', '[0, 1, 2, 4]', NULL, '{}', '{"explanation": "Mesjanizm: sens cierpienia, mobilizacja, nadzieja, tożsamość emigracyjna. NIE sojusze z zaborcami - wręcz przeciwnie."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloq001gqh6ez28veu4v', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 3, 'Jakie cechy charakteryzują Petersburg w powieści? (wybierz wszystkie)', '{"options": ["Duszny, gorący klimat", "Brudne ulice i nędzne kamienice", "Knajpy i domy publiczne", "Piękne pałace i parki", "Tłumy biednych ludzi", "Rzeka Newa"]}', '[0, 1, 2, 4, 5]', NULL, '{}', '{"explanation": "Petersburg u Dostojewskiego to miasto duszne, brudne, pełne nędzy, knajp i tłumów biedoty. Piękne pałace są marginesem, miasto pokazane jest przez pryzmat ubogich dzielnic."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclor001iqh6evdp7hs3o', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Kim jest Nastasja w powieści?', '{"options": ["Matką Raskolnikowa", "Służącą gospodyni", "Siostrą Soni", "Sąsiadką"]}', '1', NULL, '{}', '{"explanation": "Nastasja (Nastka) to służąca gospodyni Raskolnikowa - prosta, gadatliwa dziewczyna ze wsi, która przynosi mu jedzenie i sprząta pokój."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclor001mqh6ep1xvzhr2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Kim jest Zosimow w powieści?', '{"options": ["Śledczym", "Lekarzem opiekującym się Raskolnikowem", "Sąsiadem", "Studentem"]}', '1', NULL, '{}', '{"explanation": "Zosimow to młody lekarz, znajomy Razumichina, który opiekował się chorym Raskolnikowem i diagnozował u niego nerwicę i obsesję."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclor001qqh6enggil417', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'W jakiej porze roku toczy się główna akcja powieści?', '{"options": ["Zimą", "Wiosną", "Latem", "Jesienią"]}', '2', NULL, '{}', '{"explanation": "Akcja toczy się w upalne lato - narrator wielokrotnie podkreśla nieznośny upał, kurz i swąd panujący w Petersburgu."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclos001sqh6e4w1xvuy7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Kto z postaci próbował popełnić samobójstwo przez utopienie się?', '{"options": ["Raskolnikow", "Sonia", "Pijana kobieta na moście (Afrosinia)", "Dunia"]}', '2', NULL, '{}', '{"explanation": "Na moście Raskolnikow widzi próbę samobójczą pijanej kobiety, która skacze do kanału. Ratują ją policjanci. To jedna z wielu scen nędzy w powieści."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclos001wqh6eg1qn5i2q', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 3, 'Opisz metody śledcze Porfiriego Pietrowicza.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010n001cqh7moh52e00s', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 4, 'Dopasuj koncepcję filozoficzną do jej manifestacji w Wielkiej Improwizacji.', '{"leftColumn": [{"id": "A", "text": "poeta jako demiurg (Schelling)"}, {"id": "B", "text": "wspólne źródło sił (Boehme)"}, {"id": "C", "text": "problem teodycei (Leibniz/Hiob)"}], "rightColumn": [{"id": 1, "text": "''Cóż Ty większego mogłeś zrobić - Boże?''"}, {"id": 2, "text": "''Stamtąd przyszły siły moje, skąd do Ciebie przyszły Twoje''"}, {"id": 3, "text": "''Ty mądrość, ja miłość mam''"}], "matchingType": "philosophy_manifestation"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{}', '{"explanation": "Demiurg = ''cóż większego'', wspólne źródło = ''stamtąd przyszły'', teodyceja = ''mądrość bez miłości''."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010n001dqh7mr89x7sk4', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 4, 'Które elementy wskazują na ''lucyferyczny'' (nie szatański) charakter buntu Konrada?', '{"options": ["aspiracja do boskości, nie niszczenia", "miłość jako motywacja, nie nienawiść", "pragnienie władzy dla dobra, nie zła", "całkowite odrzucenie Boga", "możliwość ocalenia i nawrócenia"]}', '[0, 1, 2, 4]', NULL, '{}', '{"explanation": "Lucyferyzm: aspiracja do boskości, miłość, dobro jako cel, możliwość ocalenia. NIE całkowite odrzucenie - Konrad zwraca się DO Boga."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010n001eqh7mo2lt9o36', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 5, 'Uzupełnij analizę perspektywy postkolonialnej na mesjanizm.', '{"gaps": [{"id": 1, "options": ["imitacją", "kontrdyskursem", "kontynuacją", "odrzuceniem"]}, {"id": 2, "options": ["języka", "armii", "pieniędzy", "religii"]}, {"id": 3, "options": ["odwrócenie hierarchii (polska dominacja)", "pokój", "rewolucja", "izolacja"]}, {"id": 4, "options": ["polskiej", "uniwersalnej", "niemieckiej", "słowiańskiej"]}], "textWithGaps": "Według Galla mesjanizm jest [1] wobec filozofii Hegla. Mickiewicz używa [2] hegemonii, by ją przezwyciężyć. Celem nie jest [3], lecz stworzenie [4] koncepcji europejskiej."}', '[1, 0, 0, 1]', NULL, '{}', '{"explanation": "Mesjanizm = kontrdyskurs, używa języka hegemonii, cel nie jest dominacja, lecz uniwersalna koncepcja."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010n001fqh7mz6lw7dfz', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 4, 'Które zagrożenia związane z mesjanizmem identyfikowali krytycy (Norwid, Janion)?', '{"options": ["megalomanii narodowa", "gloryfikacja cierpienia prowadząca do bierności", "zatracenie indywidualności w zbiorowości", "wzmocnienie więzi społecznych", "manichejski podział świata na ''świętych'' i ''sługusów szatana''"]}', '[0, 1, 2, 4]', NULL, '{}', '{"explanation": "Zagrożenia: megalomania, cierpiętnictwo, zatracenie ''ja'', manichejski podział. Wzmocnienie więzi to pozytyw, nie zagrożenie."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010n001gqh7mtxw8jvho', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 4, 'Dopasuj fazę Wielkiej Improwizacji do dominującego problemu filozoficznego.', '{"leftColumn": [{"id": "A", "text": "Samotność artysty (język kłamie głosowi)"}, {"id": "B", "text": "Poetycka wszechmoc (pieśń za granicą świata)"}, {"id": "C", "text": "Konfrontacja z Bogiem (mądrość bez miłości)"}], "rightColumn": [{"id": 1, "text": "problem niewyrażalności (romantyczna epistemologia)"}, {"id": 2, "text": "poeta jako demiurg (Schelling)"}, {"id": 3, "text": "problem teodycei (Leibniz, Hiob)"}], "matchingType": "phase_philosophy"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{}', '{"explanation": "Faza I = niewyrażalność, faza II = demiurg, faza IV = teodyceja."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
