INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclos0021qh6ek93dcdjd', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 2, 'Wymień trzy miejsca w Petersburgu, które są ważne dla akcji powieści.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010o001hqh7mwxmnfnr0', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 5, 'Uzupełnij zaawansowaną analizę teozoficznego tła Wielkiej Improwizacji.', '{"gaps": [{"id": 1, "options": ["Logos", "Ungrund", "Pleroma", "Demiurg"]}, {"id": 2, "options": ["tylko dobro", "tylko zło", "zarówno jasne, jak i ciemne siły", "materię"]}, {"id": 3, "options": ["Jego naturę", "Jego istnienie", "Jego wieczność", "Jego stworzenie"]}, {"id": 4, "options": ["przeznaczenie", "źródło/pochodzenie", "zakończenie", "stworzenie"]}], "textWithGaps": "W teozofii Boehmego [1] (Bezdeń) to pierwotna otchłań poprzedzająca rozróżnienie. Z niej wyłania się ''wieczna natura'' zawierająca [2]. Konrad atakuje nie samego Boga, lecz [3]. Powołuje się na wspólne [4] swoich i boskich sił."}', '[1, 2, 0, 1]', NULL, '{}', '{"explanation": "Ungrund = Bezdeń, natura zawiera jasne i ciemne siły, Konrad atakuje naturę, powołuje się na wspólne źródło."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010o001iqh7mx6wg5c0d', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 5, 'Które elementy wskazują na ''ambiwalencję'' Dziadów cz. III jako świadomą strategię artystyczną?', '{"options": ["niedokończone bluźnierstwo (autocenzura chroniąca bohatera)", "zestawienie prometeizmu Konrada z mesjanizmem księdza Piotra bez jednoznacznego rozstrzygnięcia", "możliwość interpretacji omdlenia jako interwencji lub wewnętrznego hamulca", "jednoznaczne potępienie Konrada przez narratora", "otwartość proroctwa ''44'' na różne interpretacje"]}', '[0, 1, 2, 4]', NULL, '{}', '{"explanation": "Ambiwalencja: niedokończenie, zestawienie postaw, wieloznaczność omdlenia, otwartość proroctwa. NIE ma jednoznacznego potępienia."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclol0002qh6e7ncjc6mo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Kto jest autorem powieści *Zbrodnia i kara*?', '{"options": ["Lew Tołstoj", "Fiodor Dostojewski", "Anton Czechow", "Iwan Turgieniew"]}', '1', NULL, '{}', '{"explanation": "Zbrodnia i kara to najsłynniejsza powieść Fiodora Dostojewskiego, opublikowana w 1866 roku."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclom0005qh6etthsn3m8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Kim z wykształcenia jest Raskolnikow?', '{"options": ["Lekarzem", "Studentem prawa", "Inżynierem", "Nauczycielem"]}', '1', NULL, '{}', '{"explanation": "Raskolnikow był studentem prawa, ale z powodu biedy musiał przerwać studia."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclom0006qh6e3t5p8j8i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Ilu ludzi zabił Raskolnikow?', '{"options": ["Jedną osobę", "Dwie osoby", "Trzy osoby", "Cztery osoby"]}', '1', NULL, '{}', '{"explanation": "Raskolnikow zabił dwie osoby: starą lichwiarkę Alonę Iwanownę (planowane morderstwo) i jej siostrę Lizawietę (przypadkowo)."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclom0007qh6ef7y515qo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Kim jest Sonia Marmeladowa?', '{"options": ["Siostra Raskolnikowa", "Gospodyni", "Prostytutka, córka pijaka Marmeladowa", "Lichwarka"]}', '2', NULL, '{}', '{"explanation": "Sonia to córka urzędnika Marmeladowa, która zmuszona nędzą rodziny stała się prostytutką, by utrzymać macochę i jej dzieci."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclom0008qh6ex6cfmnl1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Jak nazywa się siostra Raskolnikowa?', '{"options": ["Dunia", "Sonia", "Katarzyna", "Nastasja"]}', '0', NULL, '{}', '{"explanation": "Awdotia (Dunia) Romanowna to młodsza siostra Raskolnikowa, która pracowała jako guwernantka u państwa Swidrygajłowych."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclom000bqh6e8a0vk2tz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Kim był Siemion Marmeladow?', '{"options": ["Bogatym kupcem", "Pijanym urzędnikiem", "Lekarzem", "Księdzem"]}', '1', NULL, '{}', '{"explanation": "Marmeladow to tragiczna postać pijanego urzędnika, który przez alkoholizm doprowadził rodzinę do skrajnej nędzy i zginął pod kołami powozu."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclom000cqh6e11sbrxv3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Jak nazywa się stara lichwarka zabita przez Raskolnikowa?', '{"options": ["Alona Iwanowna", "Pulcheria Aleksandrowna", "Marta Pietrowna", "Nastasja Fiłipowna"]}', '0', NULL, '{}', '{"explanation": "Alona Iwanowna to 60-letnia lichwarka, u której Raskolnikow zastawiał rzeczy i którą zamordował toporkiem."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclom000dqh6ez451po5a', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Jak nazywała się druga ofiara Raskolnikowa?', '{"options": ["Sonia", "Lizawieta", "Dunia", "Katarzyna"]}', '1', NULL, '{}', '{"explanation": "Lizawieta to przyrodnia siostra lichwiarki - łagodna, prosta kobieta, którą Raskolnikow zabił przypadkowo, gdy wróciła niespodziewanie do mieszkania."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclon000hqh6eb615tmk4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Jaka choroba dotknęła Katarzynę Iwanownę (żonę Marmeladowa)?', '{"options": ["Rak", "Gruźlica (suchoty)", "Tyfus", "Cholera"]}', '1', NULL, '{}', '{"explanation": "Katarzyna Iwanowna cierpiała na gruźlicę - kasłała krwią, miała gorączkę i czerwone plamy na policzkach, ostatecznie zmarła z krwotokiem."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclon000iqh6ed99c17bv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Kto był Nikołaj i dlaczego się przyznał do zbrodni Raskolnikowa?', '{"options": ["Malarz, który chciał przyjąć na siebie cierpienie ze względów religijnych", "Prawdziwy morderca", "Był torturowany przez policję", "Brat Raskolnikowa"]}', '0', NULL, '{}', '{"explanation": "Nikołaj to młody malarz-raskolnik, który malował mieszkanie w dniu zbrodni i fałszywie się przyznał, bo chciał przyjąć cierpienie zgodnie ze swoją wiarą."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclon000kqh6etquuup1x', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Czym Raskolnikow zabił lichwiarkę?', '{"options": ["Nożem", "Rewolwerem", "Toporem", "Trucizną"]}', '2', NULL, '{}', '{"explanation": "Raskolnikow zabił Alonę Iwanownę siekierą (toporem), którą ukradł ze stróżówki tuż przed morderstwem."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclon000lqh6eokeocxdb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Gdzie Raskolnikow ukrył łupy z morderstwa?', '{"options": ["W swoim pokoju", "Pod kamieniem na podwórzu", "U Razumichina", "Wyrzucił do rzeki"]}', '1', NULL, '{}', '{"explanation": "Raskolnikow ukrył łupy (portmonetkę i biżuterię) pod dużym kamieniem na jakimś podwórzu, później nigdy ich nie odkopał."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclon000mqh6edpmjhy2b', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Co stało się z Raskolnikowem po zabójstwie?', '{"options": ["Natychmiast uciekł z miasta", "Popadł w chorobę i gorączkę", "Stał się jeszcze bardziej pewny siebie", "Od razu się przyznał"]}', '1', NULL, '{}', '{"explanation": "Po morderstwie Raskolnikow popadł w chorobliwą gorączkę i majaczy przez kilka dni, traci przytomność, ma halucynacje."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloo000nqh6eyu9kmfgt', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Jak zginął Marmeladow?', '{"options": ["Zmarł z choroby", "Został zamordowany", "Rozjechał go powóz", "Popełnił samobójstwo"]}', '2', NULL, '{}', '{"explanation": "Pijany Marmeladow wpadł pod konie i powóz, odniósł śmiertelne obrażenia i zmarł w obecności rodziny, księdza i Raskolnikowa."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloo000oqh6e3s8mr09l', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Ile pieniędzy Raskolnikow dał rodzinie Marmeladowów po śmierci ojca?', '{"options": ["10 rubli", "20 rubli", "50 rubli", "100 rubli"]}', '1', NULL, '{}', '{"explanation": "Raskolnikow dał Katarzynie Iwanownie 20 rubli - prawie wszystkie pieniądze, które otrzymał od matki. To była duża suma dla niego."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloo000qqh6e1jkd1rs6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Co Raskolnikow zrobił podczas pierwszej wizyty u lichwiarki?', '{"options": ["Od razu ją zabił", "Zastawił zegarek po ojcu i rozpoznał mieszkanie", "Tylko rozmawiał z nią", "Ukradł klucze"]}', '1', NULL, '{}', '{"explanation": "Pierwsza wizyta była próbą - Raskolnikow zastawił zegarek po ojcu, dokładnie zapamiętał rozkład mieszkania, położenie kluczy i miejsce, gdzie stara chowa pieniądze."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloo000rqh6e47ghfb1p', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Dlaczego Raskolnikow wrócił do mieszkania zamordowanej lichwiarki?', '{"options": ["Zapomniał czegoś zabrać", "Aby zostawić list", "W gorączce dzwonił do dzwonka i pytał o krew", "Został zmuszony przez policję"]}', '2', NULL, '{}', '{"explanation": "W gorączkowym stanie Raskolnikow wrócił do mieszkania staruchy, dzwonił do dzwonka i pytał o krew - to bardzo wzbudziło podejrzenia robotników i policji."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloo000sqh6eq6jkbddq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Dlaczego Raskolnikow zemdlał na komisariacie?', '{"options": ["Z głodu", "Usłyszał rozmowę o morderstwie lichwiarki", "Został pobity", "Dostał gorączki"]}', '1', NULL, '{}', '{"explanation": "Raskolnikow został wezwany na komisariat w sprawie długu u gospodyni. Gdy usłyszał rozmowę o morderstwie - dokładnie gdy mówiono o szczegółach - zemdlał ze strachu."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloo000uqh6e8uwvm42v', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Co Swidrigajłow robił podczas wyznania Raskolnikowa Soni?', '{"options": ["Nie było go w pobliżu", "Podsłuchiwał przez ścianę w sąsiednim pokoju", "Stał pod oknem", "Rozmawiał z nimi"]}', '1', NULL, '{}', '{"explanation": "Swidrigajłow mieszkał w sąsiednim pokoju u tej samej gospodyni i podsłuchiwał całą spowiedź Raskolnikowa - dowiedział się o zbrodni."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloo000wqh6esyv0pm55', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 2, 'Jaki artykuł napisał Raskolnikow przed zbrodnią?', '{"options": ["O reformach prawa", "O podziale ludzi na zwyczajnych i niezwyczajnych", "O ekonomii", "O literaturze rosyjskiej"]}', '1', NULL, '{}', '{"explanation": "Raskolnikow napisał artykuł O zbrodni, w którym dzieli ludzi na zwyczajnych (materiał) i niezwyczajnych (prawo do przekroczenia moralności dla wyższego celu)."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclop000xqh6er36n1smo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Jak Raskolnikow dzieli ludzi w swojej teorii?', '{"options": ["Na dobrych i złych", "Na zwyczajnych (materiał) i niezwyczajnych (mających prawo łamać prawo)", "Na bogatych i biednych", "Na wykształconych i niewykształconych"]}', '1', NULL, '{}', '{"explanation": "Teoria Raskolnikowa dzieli ludzi na: zwyczajnych (materiał służący reprodukcji) i niezwyczajnych (prawodawców mających prawo przekroczyć prawo dla wyższego celu)."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclop000yqh6eh2djmmtj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Kogo Raskolnikow podawał jako przykład *człowieka niezwyczajnego*?', '{"options": ["Chrystusa", "Napoleona", "Puszkina", "Piotra Wielkiego"]}', '1', NULL, '{}', '{"explanation": "Raskolnikow podawał Napoleona jako przykład człowieka, który miał prawo przekroczyć prawo moralne dla wielkiego celu - poświęcał tysiące dla własnej wizji."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclop000zqh6ea756u60b', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Co według Raskolnikowa usprawiedliwia zabójstwo lichwiarki?', '{"options": ["Samoobrona", "Jest szkodliwa, jej pieniądze mogą uratować setki ludzi", "Rozkaz władzy", "Zemsta osobista"]}', '1', NULL, '{}', '{"explanation": "Raskolnikow uzasadnia: stara jest szkodliwa, nęka siostrę, jej śmierć to arytmetyka - jedna śmierć za sto uratowanych istnień. Jej pieniądze mogą pomóc tysiącom."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclop0010qh6e99p714n5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 3, 'Dlaczego teoria Raskolnikowa się załamała?', '{"options": ["Zabił nie tylko staruchę, ale i niewinną Lizawietę", "Nie potrafił wykorzystać pieniędzy i dręczyło go sumienie", "Nie był prawdziwym Napoleonem - nie miał siły psychicznej", "Wszystkie powyższe"]}', '3', NULL, '{}', '{"explanation": "Teoria załamała się z wielu powodów: zabił niewinną Lizawietę, nie wykorzystał pieniędzy (ukrył je), dręczyło go sumienie i okazało się, że nie ma siły psychicznej niezwyczajnego."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclop0011qh6e1h849ezb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Co symbolizuje sen Raskolnikowa o biciu konia?', '{"options": ["Tylko wspomnienie z dzieciństwa", "Okrucieństwo i bezsilność wobec zła, zapowiedź morderstwa", "Obawę przed ojcem", "Miłość do zwierząt"]}', '1', NULL, '{}', '{"explanation": "Sen o biciu konia to symbol okrucieństwa świata i zapowiedź przyszłego morderstwa. Mały Rodion próbuje bronić konia - tak jak później będzie się łudzić, że chroni społeczeństwo."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclop0012qh6erelo6n93', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Co symbolizuje ciasny, niski pokój Raskolnikowa?', '{"options": ["Tylko biedę materialną", "Ciasnotę duchową, izolację i zamknięcie w swojej teorii", "Skromność bohatera", "Typowe mieszkanie studenckie"]}', '1', NULL, '{}', '{"explanation": "Pokój jak trumna symbolizuje duchowe uwięzienie Raskolnikowa w swojej teorii, izolację od ludzi, brak powietrza duchowego."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclop0013qh6enhkxbuca', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Co symbolizuje krzyż, który Sonia daje Raskolnikowowi?', '{"options": ["Tylko prezent", "Symbol wiary, cierpienia i drogi do odkupienia", "Ochronę przed złem", "Pamiątkę po Lizawiecie"]}', '1', NULL, '{}', '{"explanation": "Krzyż (cyprysowy - ludowy) symbolizuje przyjęcie cierpienia jako drogi do odkupienia winy. To dar Lizawiety przekazany przez Sonię."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclop0014qh6emnvaiqq9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Co symbolizuje kamień, pod którym Raskolnikow ukrył łupy?', '{"options": ["Tylko miejsce ukrycia", "Ciężar winy przygniatający bohatera", "Bogactwo", "Przypadkowy wybór"]}', '1', NULL, '{}', '{"explanation": "Kamień to symbol ciężaru winy - przygniatającego, nie do uniesienia. Raskolnikow nigdy nie wraca po łupy, bo pieniądze nie były prawdziwym celem."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclop0016qh6ey73yeetb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Jaki fragment Biblii Sonia czytała Raskolnikowowi?', '{"options": ["Kazanie na Górze", "Przypowieść o synu marnotrawnym", "Wskrzeszenie Łazarza", "Stworzenie świata"]}', '2', NULL, '{}', '{"explanation": "Sonia czytała Raskolnikowowi o wskrzeszeniu Łazarza - jako symbol możliwości duchowego zmartwychwstania nawet po największym upadku."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclop0017qh6eifvnivbr', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Co Raskolnikow zrobił na placu, zanim poszedł się przyznać?', '{"options": ["Nic szczególnego", "Ukląkł i pocałował ziemię", "Zaczął krzyczeć", "Uciekł"]}', '1', NULL, '{}', '{"explanation": "Na placu Siennym Raskolnikow, jak radziła Sonia, ukląkł i pocałował ziemię - symboliczny gest pojednania z ludźmi i przyjęcia winy."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloq0018qh6etityd1cb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Gdzie Raskolnikow ostatecznie się przyznał do zbrodni?', '{"options": ["Na ulicy", "W cerkwi", "Na komisariacie", "W więzieniu"]}', '2', NULL, '{}', '{"explanation": "Raskolnikow przyszedł na komisariat do porucznika Procha i powiedział: To ja zabiłem wtedy starą emerytkę i jej siostrę Elżbietę toporem i zrabowałem."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloq001aqh6efc6p58yx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Co według Porfiriego jest największą słabością Raskolnikowa?', '{"options": ["Tchórzostwo", "Brak pieniędzy", "Zbyt wrażliwe sumienie mimo teorii", "Głupota"]}', '2', NULL, '{}', '{"explanation": "Porfiry wyczuwa, że Raskolnikow ma zbyt wrażliwe sumienie - pomimo teorii o prawie do zbrodni, dręczy go poczucie winy i nie może żyć ze świadomością morderstwa."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloq001bqh6ec07co5ua', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Dlaczego Raskolnikow dawał pieniądze biednym pomimo własnej nędzy?', '{"options": ["Był głupi", "Chciał pokazać się jako dobry", "Miał naturę współczującą mimo teorii - był rozdarty wewnętrznie", "Chciał uśpić podejrzenia"]}', '2', NULL, '{}', '{"explanation": "Raskolnikow pomimo teorii o prawie silnych miał współczujące serce - pomagał Marmeladowom, uratował dzieci z ognia. To pokazuje jego wewnętrzne rozdarcie."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloq001cqh6es73xzaf4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Co było największym cierpieniem Raskolnikowa po zbrodni?', '{"options": ["Strach przed aresztowaniem", "Niemożność wykorzystania pieniędzy i świadomość, że nie jest Napoleonem", "Choroba", "Izolacja od rodziny"]}', '1', NULL, '{}', '{"explanation": "Największym cierpieniem była świadomość własnej słabości - nie był prawdziwym Napoleonem, nie potrafił wykorzystać zbrodni, nie miał siły psychicznej niezwyczajnego człowieka."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloq001eqh6e0q755625', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 3, 'Które postaci można nazwać *podwójnikami* Raskolnikowa? (wybierz wszystkie)', '{"options": ["Swidrigajłow", "Łużyn", "Razumichin", "Lebieziatnikow", "Sonia"]}', '[0, 1, 3]', NULL, '{}', '{"explanation": "Podwójnicy Raskolnikowa to: Swidrigajłow (cynik, egoista), Łużyn (egoista-karierowicz), Lebieziatnikow (teoretyk nowych idei). Razumichin i Sonia są przeciwieństwami."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloq001fqh6emrow7xdi', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 3, 'Co wpłynęło na ostateczną decyzję Raskolnikowa o przyznaniu się? (wybierz wszystkie)', '{"options": ["Namowy Soni", "Cierpienie sumienia", "Groźba demaskacji przez Porfiriego", "Strach przed więzieniem", "Potrzeba przyjęcia kary i odkupienia", "Presja rodziny"]}', '[0, 1, 4]', NULL, '{}', '{"explanation": "Wpłynęły: namowy Soni o przyjęciu cierpienia, własne dręczące sumienie i wewnętrzna potrzeba oczyszczenia przez karę. Nie był to strach przed więzieniem."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzcloq001hqh6el5zwmilf', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Ile pieniędzy dostał Raskolnikow od matki w liście?', '{"options": ["20 rubli", "35 rubli", "50 rubli", "100 rubli"]}', '1', NULL, '{}', '{"explanation": "Matka przysłała Raskolnikowowi 35 rubli - niemal wszystkie swoje oszczędności, pożyczone pod zastaw emerytury."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclor001jqh6eyd9bk81d', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Ile kroków było od mieszkania Raskolnikowa do domu lichwiarki?', '{"options": ["500 kroków", "730 kroków", "1000 kroków", "300 kroków"]}', '1', NULL, '{}', '{"explanation": "Raskolnikow dokładnie liczył - było 730 kroków od jego mieszkania do domu staruchy. Wielokrotnie tę drogę przemierzał podczas przygotowań."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclor001kqh6e4j93da2z', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Co Raskolnikow zastawił u lichwiarki podczas pierwszej wizyty?', '{"options": ["Pierścionek siostry", "Zegarek po ojcu", "Książki", "Ubranie"]}', '1', NULL, '{}', '{"explanation": "Podczas pierwszej wizyty Raskolnikow zastawił srebrny zegarek po ojcu za rubla i piętnaście kopiejek, jednocześnie rozpoznając mieszkanie."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclor001lqh6ebdeb8rw6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Ile lat miała Sonia Marmeladowa?', '{"options": ["16 lat", "18 lat", "20 lat", "22 lata"]}', '1', NULL, '{}', '{"explanation": "Sonia miała 18 lat, ale wyglądała jak dziecko - była szczupła, blada, z jasnymi włosami i niebieskimi oczami pełnymi dobroci."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclor001nqh6en2ebb59i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Gdzie trafia Raskolnikow po przyznaniu się?', '{"options": ["Do więzienia w Petersburgu na całe życie", "Na katorgę na Syberii na 8 lat", "Zostaje zwolniony", "Na katorgę na 15 lat"]}', '1', NULL, '{}', '{"explanation": "Raskolnikow zostaje skazany na 8 lat ciężkich robót drugiego rzędu na Syberii. Karę złagodzono dzięki przyznaniu się i okolicznościom łagodzącym."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclor001oqh6e9i73wec6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Co stało się z matką Raskolnikowa?', '{"options": ["Wyjechała za synem na Sybir", "Popadła w chorobę psychiczną i zmarła", "Wyzdrowiała i zamieszkała z Dunią", "Została aresztowana"]}', '1', NULL, '{}', '{"explanation": "Matka Raskolnikowa popadła w chorobę nerwową graniczącą z obłąkaniem, stworzyła sobie własną wersję wydarzeń i zmarła dwa miesiące po wyjeździe syna."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclor001pqh6eh82e73lv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Kto pojechał za Raskolnikowem na Sybir?', '{"options": ["Matka", "Dunia", "Sonia", "Razumichin"]}', '2', NULL, '{}', '{"explanation": "Sonia pojechała za Raskolnikowem na Sybir i mieszkała w pobliżu więzienia, odwiedzając go i wspierając duchowo."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclor001rqh6eqbcjazf9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Dlaczego Raskolnikow przerwał studia?', '{"options": ["Nie interesowało go prawo", "Został wyrzucony za złe zachowanie", "Z powodu skrajnej biedy nie mógł płacić czesnego", "Chciał zostać pisarzem"]}', '2', NULL, '{}', '{"explanation": "Raskolnikow przerwał studia z powodu skrajnej biedy - nie miał pieniędzy na utrzymanie i czesne, przestał chodzić na wykłady i zamknął się w swojej komórce."}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclos001tqh6epbiojofi', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 2, 'Wymień trzy powody, dla których Raskolnikow zabił lichwiarkę.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclos001uqh6esw46cxd6', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 3, 'Wyjaśnij rolę Soni w życiu Raskolnikowa.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhyzclos001vqh6egdjg3f0r', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 3, 'Wyjaśnij, dlaczego Raskolnikow nie wykorzystał pieniędzy ze zbrodni.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 14:55:34.341', '2025-11-14 14:55:34.341', 'Zbrodnia i kara');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010o001jqh7myp2rb0sb', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 5, 'Dopasuj typ interpretacji mesjanizmu do jej kluczowej kategorii.', '{"leftColumn": [{"id": "A", "text": "interpretacja hermeneutyczna (Stefanowska)"}, {"id": "B", "text": "interpretacja psychoanalityczna (Janion)"}, {"id": "C", "text": "interpretacja postkolonialna (Gall)"}], "rightColumn": [{"id": 1, "text": "figura (realność historyczna przedstawia inną realność)"}, {"id": 2, "text": "trauma, kompleks, kompensacja"}, {"id": 3, "text": "appropriation, kontrdyskurs, hegemonia"}], "matchingType": "interpretation_category"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{}', '{"explanation": "Stefanowska = figura (Auerbach), Janion = psychoanaliza (trauma), Gall = postkolonializm (kontrdyskurs)."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1600dgqhfp56bs7pui', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Jaka jest funkcja monologu wewnętrznego w przedstawieniu psychiki Raskolnikowa?', '{"options": ["Pokazuje tylko jego racjonalne rozumowanie", "Ujawnia chaos myślowy, rozdarcie między teorią a sumieniem, walkę wewnętrzną", "Służy jedynie budowaniu napięcia", "Jest wyłącznie narzędziem narracyjnym"]}', '1', NULL, '{}', '{"explanation": "Dostojewski wykorzystuje monolog wewnętrzny do ukazania chaosu psychicznego Raskolnikowa - walki między racjonalną teorią a irracjonalnym sumieniem, co jest kluczem do zrozumienia jego dramatu."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1600dhqhfpc2gonvh1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Co symbolizuje żółty kolor powtarzający się w opisach Petersburga?', '{"options": ["Radość i optymizm", "Chorobę, zgniliznę moralną i duchową", "Bogactwo i przepych", "Młodość bohaterów"]}', '1', NULL, '{}', '{"explanation": "Żółty kolor (żółte tapety, żółte twarze) to symbol choroby moralnej, zepsucia, duchowej zgnilizny przenikającej Petersburg i dusze bohaterów."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1600diqhfpd71q05iv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Jak Dostojewski konstruuje fabułę powieści w relacji do głównego wydarzenia?', '{"options": ["Chronologicznie, zbrodnia na początku akcji", "Zbrodnia jest punktem kulminacyjnym w połowie powieści", "Zbrodnia następuje już na początku, reszta to konsekwencje psychologiczne", "Fabuła jest nielinearna, retrospekcje dominują"]}', '2', NULL, '{}', '{"explanation": "Dostojewski odwraca tradycyjną strukturę kryminalną - zbrodnia następuje już w części I, a cała reszta to analiza jej psychologicznych i moralnych konsekwencji."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1600djqhfphl879u9t', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Jaką funkcję pełni postać Razumichina jako kontrast do Raskolnikowa?', '{"options": ["Jest tylko komicznym bohaterem drugoplanowym", "Reprezentuje zdrową, praktyczną egzystencję bez teorii filozoficznych", "Służy wyłącznie jako pomoc w fabule", "Jest drugim wariantem nadczłowieka"]}', '1', NULL, '{}', '{"explanation": "Razumichin (imię od ''razum'' - rozum) to antyteza Raskolnikowa - człowiek prosty, zdrowy, praktyczny, wolny od destrukcyjnych teorii, pokazujący alternatywną drogę życia."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1600dkqhfp7ylhjoi5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Co reprezentuje scena, gdy Raskolnikow słyszy rozmowę studenta i oficera w karczmie o lichwiarce?', '{"options": ["Przypadek bez większego znaczenia", "Potwierdzenie słuszności jego teorii przez głosy z zewnątrz", "Ostrzeżenie przed zbrodnią", "Jedynie element fabularny"]}', '1', NULL, '{}', '{"explanation": "Podsłuchana rozmowa, w której obcy ludzie wyrażają dokładnie te same myśli co Raskolnikow, działa jak fatalne potwierdzenie - wydaje mu się, że sam los go zachęca do czynu."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1700dlqhfpbljtikb3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Dlaczego Dostojewski nie pokazuje wprost procesu powstawania teorii Raskolnikowa?', '{"options": ["Zapomniał o tym wątku", "Teoria jest już gotowa na początku - autor koncentruje się na jej załamaniu", "Chciał skrócić powieść", "Proces ten jest opisany szczegółowo"]}', '1', NULL, '{}', '{"explanation": "Dostojewski celowo pomija genezę teorii - dostajemy ją jako fakt dokonany, aby skupić się na jej weryfikacji i psychologicznym krachu, co jest istotą dzieła."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1700dmqhfpvulf3vm6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Co oznacza nagły powrót Raskolnikowa do życia społecznego po zbrodni?', '{"options": ["Wyraz zimnej kalkulacji", "Nieświadomy krzyk o pomoc, próbę ucieczki od własnych myśli", "Chęć sprawdzenia czy wzbudza podejrzenia", "Zwykłe znudzenie samotnością"]}', '1', NULL, '{}', '{"explanation": "Chaotyczne wizyty u Razumichina, przypadkowe rozmowy z nieznajomymi to nieświadoma próba ucieczki od siebie, rozpaczliwe szukanie ludzkiego kontaktu jako ratunku."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1700dnqhfp451an8vp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Jaka jest funkcja snu o apokalipsie (zaraza) w epilogu?', '{"options": ["Przepowiednia przyszłości", "Wizja świata zdominowanego przez teorie podobne do teorii Raskolnikowa", "Symbol choroby psychicznej bohatera", "Nawiązanie do Biblii bez głębszego znaczenia"]}', '1', NULL, '{}', '{"explanation": "Sen o zarazie, gdzie wszyscy uważają się za posiadaczy prawdy absolutnej, to wizja świata, w którym teoria nadczłowieka zostałaby powszechnie przyjęta - świata samozniszczenia."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1700doqhfpagcjuvqy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Dlaczego Raskolnikow odczuwa wstręt do jedzenia po zbrodni?', '{"options": ["Jest chory na żołądek", "Symboliczne odrzucenie życia biologicznego, fizyczności - zostaje tylko teoria", "Chce się ukarać głodem", "To objaw gorączki"]}', '1', NULL, '{}', '{"explanation": "Wstręt do jedzenia symbolizuje odrzucenie podstawowych potrzeb życiowych - Raskolnikow próbuje żyć wyłącznie w sferze idei, odcinając się od cielesności i zwykłego ludzkiego życia."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1700dpqhfppemefdhu', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Co symbolizuje fakt, że Raskolnikow nieustannie zapomina zamknąć drzwi?', '{"options": ["Zwykłą roztargnienie", "Nieświadomą potrzebę wykrycia, niemożność życia z tajemnicą", "Chęć ucieczki", "Gościnność"]}', '1', NULL, '{}', '{"explanation": "Otwarte drzwi to symbol niemożności zamknięcia zbrodni w sobie - podświadoma potrzeba ujawnienia prawdy, bo ciężar tajemnicy jest nie do udźwignięcia."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1700dqqhfpirznzdav', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 4, 'Które elementy tworzą atmosferę duszności i klaustrofobii w powieści?', '{"options": ["Ciasne, niskie pokoje jak trumny", "Upał i swąd petersburskiego lata", "Tłumy na ulicach", "Piękne, przestronne place", "Brudne, wąskie schody i podwórka", "Otwarte przestrzenie nad Newą"]}', '[0, 1, 2, 4]', NULL, '{}', '{"explanation": "Dostojewski celowo buduje atmosferę fizycznego i duchowego duszenia się - ciasne pokoje, upał, tłumy, brud tworzą piekielną wizję miasta jako przestrzeni cierpienia."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1700drqhfp5r5b1o9b', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 4, 'Które motywy łączą Raskolnikowa ze Swidrigajłowem?', '{"options": ["Obaj przekroczyli granicę moralności", "Obaj mają teorie o prawie silniejszych", "Obaj nie potrafią żyć z konsekwencjami swoich czynów", "Obaj kochają Dunię", "Obaj doświadczają wizji i duchowych objawień", "Obaj są ateistami"]}', '[0, 2, 3, 4]', NULL, '{}', '{"explanation": "Swidrigajłow to mroczne odbicie Raskolnikowa - obaj przekroczyli granicę, mają wizje (duchy u Swidrigajłowa, sny u Raskolnikowa), nie radzą sobie z konsekwencjami, ale Swidrigajłow wybrał samobójstwo."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1800dsqhfpv4p5mx8e', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 4, 'Wyjaśnij paradoks: dlaczego Raskolnikow, który planował zbrodnię racjonalnie, popełnia tyle błędów podczas jej wykonania?', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1800dtqhfpw4eewh8n', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 4, 'Opisz rolę przypadku w powieści i jego interpretację w kontekście wolnej woli Raskolnikowa.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1800duqhfpo8wel2fw', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 4, 'Jaka jest funkcja scen ulicznych (pijani, samobójcy, nędza) w konstrukcji powieści?', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1800dvqhfphjllakyd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Co symbolizuje nieustanne przechodzenie Raskolnikowa przez mosty nad Newą?', '{"options": ["Tylko element topograficzny", "Symbol granicy między dwoma światami, dwoistości bohatera", "Ucieczka z miasta", "Szukanie kontaktu z przyrodą"]}', '1', NULL, '{}', '{"explanation": "Mosty to symboliczne miejsca przejścia, granicy między światami - normalności a zbrodni, rozumu a obłędu, izolacji a wspólnoty. Oddają wewnętrzną dwoistość Raskolnikowa."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1800dwqhfptifou2k8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Dlaczego Dostojewski umieszcza Sonię i Raskolnikowa w sąsiednich pokojach u tej samej gospodyni?', '{"options": ["Dla wygody fabularnej", "Symbolizuje ich duchowe pokrewieństwo mimo przeciwieństw", "Przypadkowy wybór", "Dla zaoszczędzenia miejsca w powieści"]}', '1', NULL, '{}', '{"explanation": "Bliskość fizyczna mieszkań mimo cienkich ścian symbolizuje duchowe pokrewieństwo dwojga odrzuconych - ich losy są splecione, dzieli ich tylko cienka ściana, tak jak dzieli ich sposób radzenia sobie z życiem."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1800dxqhfpdwixolw2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Co oznacza fakt, że Raskolnikow nie potrafi spojrzeć ludziom w oczy po zbrodni?', '{"options": ["Jest nieśmiały", "Symbolizuje zerwanie więzi z ludzkością, izolację duchową", "Boi się demaskacji", "Ma problemy ze wzrokiem"]}', '1', NULL, '{}', '{"explanation": "Unikanie wzroku to symbol zerwania więzi międzyludzkiej - zbrodnia wypchnęła Raskolnikowa poza nawias ludzkości, nie może już funkcjonować w świecie ludzi."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1800dyqhfpw8jm7cd3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Jaka jest funkcja artystyczna powtarzających się scen gorączki i majaków?', '{"options": ["Zwykły opis choroby", "Dostęp do podświadomości bohatera, prawdy ukrytej przed racjonalnym umysłem", "Budowanie suspense", "Opóźnienie akcji"]}', '1', NULL, '{}', '{"explanation": "Gorączka to moment, gdy kontrola racjonalna słabnie i ujawnia się prawda podświadomości - lęki, wątpliwości, prawdziwe uczucia Raskolnikowa, których nie chce dopuścić do świadomości."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1800dzqhfp4kmdyy8t', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Dlaczego Porfiry nazywa Raskolnikowa ''człowiekiem księgi''?', '{"options": ["Bo dużo czyta", "Bo żyje teorią książkową oderwana od rzeczywistości", "Bo jest pisarzem", "Bo studiował prawo"]}', '1', NULL, '{}', '{"explanation": "Porfiry trafnie diagnozuje problem Raskolnikowa - żyje w świecie abstrakcyjnych idei, teorii wyczytanych z książek, oderwanych od realnego życia i konsekwencji."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1800e0qhfp8stvmekk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Co symbolizuje czerwony kolor w powieści (czerwone plamy Katarzyny, czerwone od krwi ręce)?', '{"options": ["Tylko realistyczny detal", "Symbol winy, grzechu i śmierci wszechobecnej w świecie powieści", "Kolor rewolucji", "Symbol miłości"]}', '1', NULL, '{}', '{"explanation": "Czerwień to kolor krwi, winy, śmierci - pojawia się u ofiar (Katarzyna) i mordercy (ręce Raskolnikowa), tworząc symboliczną sieć powiązań między winą a cierpieniem."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1800e1qhfp930gal0p', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 4, 'Wyjaśnij funkcję postaci Łużyna jako karykaturalnego wariantu teorii Raskolnikowa.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1900e2qhfpedh7igbc', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 4, 'Opisz technikę narracyjną Dostojewskiego w przedstawianiu świadomości Raskolnikowa.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1900e3qhfpoqxv9gab', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Dlaczego Dostojewski każe Raskolnikowowi czytać historię o bogatym człowieku i Łazarzu (oprócz historii wskrzeszenia)?', '{"options": ["Dla budowania religiozności", "Przypowieść o bogaczu i Łazarzu pokazuje odwrócenie wartości - ubogi dostąpi zbawienia", "Przypadkowy wybór fragmentu", "Dla krytyki bogactwa"]}', '1', NULL, '{}', '{"explanation": "Fragment o bogatym człowieku i biednym Łazarzu pokazuje, że w perspektywie eschatologicznej wartości są odwrócone - ubodzy i upadli (Sonia) są bliżej zbawienia niż teoretycy i nadludzie."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1900e4qhfp12hcia9t', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Co symbolizuje fakt, że Raskolnikow wyprowadza się ze swojego pokoju-trumny dopiero po przyznaniu się?', '{"options": ["Zmiana mieszkania bez znaczenia", "Symboliczne wyjście z duchowej śmierci, narodziny do nowego życia", "Zwykła praktyczna decyzja", "Ucieczka przed wspomnieniami"]}', '1', NULL, '{}', '{"explanation": "Pokój był fizyczną realizacją duchowej śmierci i izolacji. Opuszczenie go po przyznaniu się to symboliczne wyjście z grobu, pierwsze stadium zmartwychwstania."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1900e5qhfp27q06uxn', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Jaka jest funkcja dialogów Raskolnikowa z Porfirym?', '{"options": ["Tylko element kryminalny", "Dialektyczna gra, w której Porfiry zmusza Raskolnikowa do konfrontacji z własnymi sprzecznościami", "Zwykłe przesłuchanie", "Budowanie przyjaźni"]}', '1', NULL, '{}', '{"explanation": "Rozmowy z Porfirym to nie przesłuchania, ale dialektyczne pojedynki, w których śledczy metodą sokratejską doprowadza Raskolnikowa do uświadomienia sobie sprzeczności własnej teorii."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1900e6qhfpdyd885m9', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 4, 'Które sceny pokazują ''dwoistość'' Raskolnikowa - współistnienie sprzecznych impulsów?', '{"options": ["Ratowanie dzieci z pożaru mimo egoistycznej teorii", "Dawanie pieniędzy biednym mimo własnej nędzy", "Wstręt do ludzi przy równoczesnej potrzebie kontaktu", "Miłość do matki i siostry", "Nienawiść do wszystkich bez wyjątku", "Racjonalne planowanie przy irracjonalnych błędach"]}', '[0, 1, 2, 3, 5]', NULL, '{}', '{"explanation": "Raskolnikow jest postacią głęboko rozdwojoną - teoria każe być egoistą, natura czyni go współczującym. Ta dwoistość przejawia się we wszystkich jego działaniach i ostatecznie prowadzi do krachu psychicznego."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1900e7qhfp0mw8mnp6', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 4, 'Wyjaśnij symbolikę liczby ''trzy'' w powieści (trzy schody, trzy razy dzwoni, trzeci dzień).', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1900e8qhfp7px79s95', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Jak teoria Raskolnikowa odnosi się do idei Fryderyka Nietzschego o nadczłowieku?', '{"options": ["Są identyczne", "Raskolnikow antycypuje Nietzschego, ale jego teoria jest karykaturą - nadczłowiek to twórca wartości, nie morderca", "Nie mają nic wspólnego", "Nietzsche skopiował Dostojewskiego"]}', '1', NULL, '{}', '{"explanation": "Dostojewski pisze 20 lat przed Nietzschem, antycypując jego idee. Ale pokazuje, dokąd prowadzi wulgaryzacja koncepcji nadczłowieka - do przemocy. Prawdziwy nadczłowiek Nietzschego tworzy wartości, a nie zabija dla pieniędzy."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1900e9qhfpdiciu3yy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Jaka jest funkcja epilogu w strukturze powieści?', '{"options": ["Zwykłe domknięcie fabuły", "Rezygnacja Dostojewskiego z psychologicznego realizmu na rzecz rozwiązania ideologicznego", "Niepotrzebny dodatek", "Pokazanie życia na katordze"]}', '1', NULL, '{}', '{"explanation": "Epilog to świadomy wybór ideologiczny - Dostojewski pokazuje nie psychologiczną ewolucję, ale nagłą przemianę przez miłość i wiarę. To rozwiązanie religijne, nie psychologiczne, co jest przedmiotem debat krytyków."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1900eaqhfpeqss0odw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Jak Dostojewski wykorzystuje ''chronotop progu'' (Bachtin) w konstrukcji powieści?', '{"options": ["Nie wykorzystuje", "Sceny w drzwiach, na schodach, mostach - momenty kryzysu i decyzji egzystencjalnych", "Tylko dla realizmu topograficznego", "Dla budowania suspense"]}', '1', NULL, '{}', '{"explanation": "Według Bachtina, Dostojewski wykorzystuje chronotop progu - przestrzenie graniczne (drzwi, schody, mosty), gdzie dzieją się kluczowe sceny kryzysów i przełomów egzystencjalnych bohaterów."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1900ebqhfplqrwvnmy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Jaka jest relacja między ''zbrodniczą teorią'' Raskolnikowa a ideami socjalizmu utopijnego XIX wieku?', '{"options": ["Nie ma żadnej relacji", "Raskolnikow parodiuje ideę szczęścia większości - chce zabić jednego dla dobra wielu, co jest karykaturą utylitaryzmu", "Popiera socjalizm wprost", "Krytykuje tylko kapitalizm"]}', '1', NULL, '{}', '{"explanation": "Dostojewski polemizuje z utylitaryzmem i socjalizmem - teoria Raskolnikowa to reductio ad absurdum idei ''szczęścia największej liczby''. Pokazuje, że ''arytmetyka moralna'' prowadzi do zbrodni."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1a00ecqhfp4q6cb95v', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Co oznacza scena, gdy Raskolnikow całuje stopę Soni?', '{"options": ["Gest romantyczny", "Symboliczne uznanie świętości cierpienia i pokory - odwrócenie hierarchii wartości", "Upokorzenie", "Zwykły gest szacunku"]}', '1', NULL, '{}', '{"explanation": "Całowanie stóp to gest z Ewangelii (Maria Magdalena i Chrystus). Raskolnikow - nadczłowiek klęka przed prostytutką, uznając, że ona w swoim cierpieniu jest wyższa duchowo. To odwrócenie jego teorii."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1a00edqhfpk094i850', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Jaka jest funkcja ''polifonii'' (wielogłosowości) według Michaiła Bachtina w strukturze powieści?', '{"options": ["Dostojewski nie stosuje polifonii", "Każda postać ma własny, pełnoprawny głos ideologiczny - brak autorytetu narratora", "To tylko technika narracyjna", "Służy wyłącznie realizmowi"]}', '1', NULL, '{}', '{"explanation": "Według Bachtina, Dostojewski tworzy powieść polifoniczną - każda postać (Raskolnikow, Porfiry, Sonia, Swidrigajłow) ma własną autonomiczną ideologię. Autor nie narzuca prawdy, ale organizuje dialog."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1a00eeqhfpddeds1ef', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Dlaczego Raskolnikow ma obsesję na punkcie ''wszy'' jako metafory człowieka?', '{"options": ["Zwykła hipochondria", "Odczłowieczenie jako warunek zbrodni - by zabić, musi uznać ofiarę za nie-człowieka", "Nienawiść do ludzi", "Symbol choroby"]}', '1', NULL, '{}', '{"explanation": "Metafora ''wesz'' to mechanizm odczłowieczenia - Raskolnikow musi mentalnie zdegradować ofiarę do poziomu robactwa, by móc ją zabić. To psychologiczny mechanizm wszystkich zbrodni przeciw ludzkości."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1a00efqhfpyvrz90ov', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 5, 'Jakie funkcje pełni motyw ''podwojenia'' w powieści?', '{"options": ["Pokazanie różnych wariantów tej samej idei", "Ukazanie wieloaspektowości problemu moralnego", "Technika zwierciadlana - bohater widzi siebie w innych", "Zwykła multiplikacja postaci", "Dialektyczna metoda prezentacji idei", "Tylko dla wzbogacenia fabuły"]}', '[0, 1, 2, 4]', NULL, '{}', '{"explanation": "Podwojenie (Raskolnikow-Swidrigajłow, Raskolnikow-Łużyn, Sonia-Dunia) to metoda dialektyczna - pokazanie różnych realizacji tej samej idei, zwierciadlane odbicia pozwalające bohaterowi zobaczyć konsekwencje własnych wyborów."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1a00egqhfpuek9c1la', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 5, 'Przeanalizuj funkcję czasu w powieści - dlaczego akcja trwa tylko kilka dni, a epilog jest oddzielony rokiem?', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1a00ehqhfprpmb5m7r', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 5, 'Wyjaśnij, jak Dostojewski dekonstruuje romantic hero w postaci Raskolnikowa.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1a00eiqhfp65glnwno', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 6, 'Napisz notatkę syntetyczną: ''Petersburg jako postać w powieści - miasto jako siła kształtująca losy bohaterów''.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1a00ejqhfppfxr8sts', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Co oznacza sentencja Porfiriego: ''Cierpienie i ból muszą być zawsze''?', '{"options": ["Pesymizm", "Antropologia chrześcijańska - cierpienie jako część conditio humana i droga do zbawienia", "Sadyzm śledczego", "Krytyka społeczeństwa"]}', '1', NULL, '{}', '{"explanation": "Porfiry wyraża chrześcijańską antropologię Dostojewskiego - cierpienie nie jest przypadłością, ale częścią ludzkiego losu i drogą oczyszczenia. Bez cierpienia niemożliwe jest zbawienie."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1a00ekqhfp17buzg2b', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Jaka jest funkcja sceny, gdy Raskolnikow czyta gazetę o swoim morderstwie?', '{"options": ["Tylko informacja dla czytelnika", "Moment, gdy zbrodnia staje się publiczna, wchodzi do dyskursu społecznego - koniec prywatności czynu", "Zwykły element fabuły kryminalnej", "Źródło informacji o śledztwie"]}', '1', NULL, '{}', '{"explanation": "Czytanie gazety to moment, gdy prywatna zbrodnia staje się faktem publicznym, przedmiotem społecznej dyskusji. Raskolnikow traci kontrolę nad narracją - inni interpretują jego czyn."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1a00elqhfps62thn97', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Dlaczego Dostojewski nie pokazuje bezpośrednio sceny zabicia Lizawiety?', '{"options": ["Zapomniał o tym", "Elipsa dramatyzuje - brak opisu podkreśla chaos i automatyzm drugiego morderstwa", "Cenzura", "Brak miejsca w powieści"]}', '1', NULL, '{}', '{"explanation": "Pominięcie opisu drugiego morderstwa to świadomy zabieg - pokazuje chaos, automatyzm, utratę kontroli. Raskolnikow już nie planuje, tylko reaguje. Elipsa dramatyzuje horror sytuacji."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1b00emqhfpgtvmtx0o', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Jaka jest funkcja postaci Nikołaja (malarza-raskolnika) w ekonomii powieści?', '{"options": ["Tylko element kryminalny", "Kontrast - prawdziwe przyjęcie cierpienia vs fałszywa teoria Raskolnikowa", "Comic relief", "Przypadkowa postać"]}', '1', NULL, '{}', '{"explanation": "Nikołaj to kontrast dla Raskolnikowa - prawdziwie przyjmuje cierpienie z pokory religijnej, nie z pychy intelektualnej. Pokazuje różnicę między autentyczną wiarą a racjonalizacją."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1b00enqhfpnzvyoo3e', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 5, 'Przeanalizuj funkcję ''milczenia'' i tego, co niewypowiedziane w dialogach powieści.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1b00eoqhfpw59m7lhb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Co symbolizuje Ewangelia Soni - konkretny egzemplarz książki jako obiekt?', '{"options": ["Tylko rekwizyt", "Symbol transmisji wiary - dar od Lizawiety, teraz od Soni do Raskolnikowa", "Zwykła książka religijna", "Element dekoracyjny"]}', '1', NULL, '{}', '{"explanation": "Konkretna Ewangelia to obiekt przechodzący z rąk do rąk - od Lizawiety (ofiary) przez Sonię do Raskolnikowa. Symbol transmisji wiary i łączności między ofiarą a katem przez przebaczenie."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1b00epqhfpp8f1a8kh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Jaka jest relacja między ''teorią'' a ''życiem'' w filozofii powieści?', '{"options": ["Teoria jest ważniejsza", "Teoria jest abstrakcyjna i martwa, życie konkretne i żywe - teoria zabija życie", "Teoria i życie są zgodne", "Życie potwierdza teorię"]}', '1', NULL, '{}', '{"explanation": "Dostojewski przeciwstawia martwą abstrakcję teorii żywemu życiu. Teoria Raskolnikowa jest logiczna, ale zabija życie - konkretne, ciepłe, pełne sprzeczności. Powieść to apologia życia przeciw teorii."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1b00eqqhfpl1qx0msq', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 5, 'Opisz funkcję ''fantastycznego realizmu'' w scenach halucynacyjnych i snów.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1b00erqhfpb60hgkkl', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 5, 'W jaki sposób powieść wpisuje się w debatę o ''człowieku nowym'' w kulturze rosyjskiej XIX wieku?', '{"options": ["Nie wpisuje się", "Raskolnikow to karykatura ''nowego człowieka'' nihilistów - Dostojewski pokazuje bankructwo ideału racjonalisty bez moralności", "Popiera ideę ''nowego człowieka''", "Ignoruje tę debatę"]}', '1', NULL, '{}', '{"explanation": "W latach 60. XIX w. nihiliści i radykałowie głosili ideał ''nowego człowieka'' - racjonalnego, wyzwolonego z moralności, egoistę. Dostojewski w Raskolnikowie karykaturuje ten ideał, pokazując jego moralną niemożliwość."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1b00esqhfpavm42qqe', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 5, 'Jak teoria Raskolnikowa odnosi się do koncepcji ''homo sacer'' Giorgio Agambena?', '{"options": ["Nie ma związku", "Lichwarka jako ''życie niegodne życia'' - Raskolnikow tworzy kategorię ludzi, których można zabić bez konsekwencji", "To anachroniczne porównanie", "Raskolnikow nie kategoryzuje ludzi"]}', '1', NULL, '{}', '{"explanation": "Agamben opisuje ''homo sacer'' jako życie pozbawione wartości prawnej, które można zabić. Raskolnikow tworzy podobną kategorię - ''wszy'', ludzie szkodliwi, których śmierć jest moralnie obojętna. To mechanizm biopolityki."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1b00etqhfpidl51u39', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 5, 'Jaka jest funkcja ''karnawalizacji'' (Bachtin) w scenach zbiorowych powieści?', '{"options": ["Dostojewski nie stosuje karnawalizacji", "Sceny stypy, pijaństwa, ulicznych skandali to chwile odwrócenia hierarchii społecznej i ujawnienia prawdy", "To tylko elementy realistyczne", "Dla rozrywki"]}', '1', NULL, '{}', '{"explanation": "Według Bachtina, karnawał u Dostojewskiego to momenty, gdy hierarchie społeczne są zawieszone (stypa, knajpy) i prawda może się ujawnić - tam Łużyn zostaje zdemaskowany, tam Katerina szaleje publicznie."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1b00euqhfpynim5oxm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 5, 'Dlaczego w powieści nie ma opisów przyrody i pejzażu?', '{"options": ["Dostojewski nie lubił przyrody", "Całkowite skupienie na psychologii i przestrzeni miejskiej - przyroda byłaby eskapizmem", "Brak miejsca", "To przypadkowe pominięcie"]}', '1', NULL, '{}', '{"explanation": "U Dostojewskiego (w przeciwieństwie do Tołstoja) nie ma przyrody - wszystko dzieje się w klaustrofobicznym mieście. Przyroda byłaby ucieczką od dramatu moralnego, który musi toczyć się w piekle miejskim."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1b00evqhfp34j3in1f', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 5, 'Jak powieść problematyzuje relację między winą prawną a winą moralną?', '{"options": ["Uznaje je za tożsame", "Pokazuje rozdźwięk - Raskolnikow jest winny prawnie (zabił), ale moralnie to skomplikowane", "Ignoruje prawo", "Prawo i moralność są sprzeczne"]}', '1', NULL, '{}', '{"explanation": "Powieść pokazuje różnicę między winą prawną (morderstwo) a moralną (intencja, konsekwencje). Raskolnikow jest prawnie winny, ale czy moralnie? Zabił ''wszę'' dla wyższego celu. Dostojewski komplikuje proste oceny."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1c00ewqhfpbs2fl2vs', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 5, 'Jaka jest funkcja ''przypadkowej'' śmierci Marmeladowa w strukturze moralnej powieści?', '{"options": ["Tylko element sensacyjny", "Pokazuje, że śmierć jest wszechobecna i przypadkowa - relatywizuje morderstwo Raskolnikowa", "Dla wzruszenia", "Nie ma głębszego znaczenia"]}', '1', NULL, '{}', '{"explanation": "Marmeladow ginie ''przypadkowo'' pod kołami - pokazuje to, że śmierć jest w tym świecie wszechobecna. Kontrastuje z ''zaplanowanym'' morderstwem, ale też je relatywizuje - ile jest warte jedno życie w świecie, gdzie śmierć jest tania?"}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1c00exqhfp883xhu5f', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 6, 'Które aspekty powieści antycypują modernizm literacki XX wieku?', '{"options": ["Strumień świadomości i monolog wewnętrzny", "Fragmentaryczność narracji", "Relatywizm moralny", "Psychologia głębi i nieświadomość", "Klasyczna fabuła linearna", "Epifanie i momenty objawienia"]}', '[0, 1, 3, 5]', NULL, '{}', '{"explanation": "Dostojewski antycypuje modernizm: technika strumienia świadomości, fragmentaryczna narracja, psychologia nieświadomości (sny, pomyłki), epifanie (pocałowanie ziemi). Wyprzedza Joycea i Woolfa o pół wieku."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1c00eyqhfppgqasjnu', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 6, 'Przeanalizuj funkcję ''ekonomii'' i ''pieniądza'' jako siły destrukcyjnej w świecie powieści.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1c00ezqhfpb4kog20c', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 7, 'Notatka syntetyczna: ''Problem teodycei w *Zbrodni i karze* - usprawiedliwienie Boga wobec zła''.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1c00f0qhfph01ptu7h', 'ESSAY', 'WRITING', 'POSITIVISM', 5, 8, 'Temat rozprawki: ''Teoria nadczłowieka Raskolnikowa jako wyraz kryzysu wartości w epoce modernizacji - interpretacja filozoficzno-historyczna''.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1c00f1qhfpzjjr15bw', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 6, 'Wyjaśnij, dlaczego Swidrigajłow popełnia samobójstwo, a Raskolnikow wybiera życie i odkupienie.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1c00f2qhfp96j3gehm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 5, 'Jak teoria ''dialogizmu'' Michaiła Bachtina wyjaśnia konstrukcję świadomości Raskolnikowa?', '{"options": ["Nie wyjaśnia", "Świadomość Raskolnikowa jest areną dialogu sprzecznych głosów - teorii i sumienia", "Raskolnikow ma prostą psychologię", "Bachtinowska teoria nie odnosi się do jednostki"]}', '1', NULL, '{}', '{"explanation": "Według Bachtina, świadomość u Dostojewskiego jest dialogiczna - Raskolnikow to pole bitwy różnych głosów ideologicznych (teoria, sumienie, wpływy innych). Nie ma jednolitego ja, jest wielogłos wewnętrzny."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1c00f3qhfpvty0iqhg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 5, 'W jaki sposób powieść dekonstruuje opozycję dobro/zło?', '{"options": ["Nie dekonstruuje - opozycja jest jasna", "Pokazuje, że dobro i zło współistnieją w każdym człowieku i nie są oddzielnymi esencjami", "Utożsamia dobro ze złem", "Odrzuca moralność w ogóle"]}', '1', NULL, '{}', '{"explanation": "Dostojewski pokazuje, że granica między dobrem a złem przebiega przez każde ludzkie serce. Raskolnikow ratuje dzieci i morduje. Sonia jest prostytutką i świętą. Nie ma czystego dobra ani zła."}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1c00f4qhfp2mq6sras', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 7, 'Napisz notatkę syntetyczną: ''Raskolnikow jako *underground man* - bohater z podziemia nowoczesności''.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1c00f5qhfp2e0d218u', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 6, 'Przeanalizuj funkcję narratora w powieści - czy jest on neutralny, czy zaangażowany ideologicznie?', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmhz2ko1c00f6qhfpbxbhjan3', 'ESSAY', 'WRITING', 'POSITIVISM', 5, 8, 'Rozprawka problemowa: ''Czy *Zbrodnia i kara* jest powieścią anty-nowoczesnościową? - analiza stosunku Dostojewskiego do modernizacji''.', '{}', NULL, NULL, '{}', '{}', '2025-11-14 16:25:49.482', '2025-11-14 16:25:49.482', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010o001kqh7ma61at8g3', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Wyjaśnij, dlaczego Konrad atakuje ''naturę'' Boga, a nie samego Boga. Odwołaj się do teozofii Boehmego.', '{"hint": "Rozróżnienie Bóg (Ungrund) a ''wieczna natura''"}', NULL, NULL, '{}', '{"keyPoints": ["Ungrund/Bezdeń", "wieczna natura", "jasne i ciemne siły", "atak na naturę, nie na Absolut"], "sampleAnswer": "W teozofii Jakuba Boehmego Bóg jako Ungrund (Bezdeń) to absolutna, niepojęta otchłań poprzedzająca wszelkie rozróżnienia. Z niej wyłania się ''wieczna natura'' Boga, która zawiera zarówno jasne, jak i ciemne siły. Konrad, mówiąc ''Strzelę przeciw Twej naturze'', nie atakuje absolutnego Boga, lecz tę ''naturę'' - aspekt bóstwa odpowiedzialny za porządek świata, w tym za cierpienie. To subtelne rozróżnienie pozwala na bunt bez pełnego bluźnierstwa przeciw Absolutowi."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010q001lqh7mtn6c5pkk', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Co oznaczają słowa Konrada ''Stamtąd przyszły siły moje, skąd do Ciebie przyszły Twoje'' i jakie mają źródło filozoficzne?', '{"hint": "Wspólne pochodzenie sił Boga i człowieka"}', NULL, NULL, '{}', '{"keyPoints": ["Boehme", "wspólne źródło", "uzasadnienie roszczeń", "równość pochodzenia"], "sampleAnswer": "Słowa te nawiązują do teozofii Boehmego, według której siły Boga i człowieka mają wspólne źródło w pierwotnej otchłani (Ungrund). Konrad powołuje się na tę wspólnotę pochodzenia, by uzasadnić swoje roszczenia - skoro jego siły (poetyckie, duchowe) pochodzą z tego samego kosmicznego źródła co siły Boga, ma prawo żądać od Boga odpowiedzi, a nawet równać się z Nim. To filozoficzne uzasadnienie prometejskiego buntu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010r001mqh7m3ziuc85c', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Wyjaśnij, czym jest ''teodyceja'' i jak Konrad polemizuje z jej klasycznymi rozwiązaniami.', '{"hint": "Problem pogodzenia dobrego Boga z istnieniem zła"}', NULL, NULL, '{}', '{"keyPoints": ["problem zła", "Leibniz", "najlepszy ze światów", "odrzucenie optymizmu", "mądrość bez miłości"], "sampleAnswer": "Teodyceja to filozoficzny problem pogodzenia istnienia wszechmocnego i dobrego Boga z istnieniem zła i cierpienia w świecie. Klasyczne rozwiązanie Leibniza głosiło, że świat jest ''najlepszy z możliwych'' - zło jest konieczne dla większej harmonii. Konrad odrzuca tę optymistyczną teodycję: cierpienie niewinnych Polaków nie służy żadnemu ''większemu dobru''. Zarzuca Bogu ''mądrość bez miłości'' - Bóg wie o cierpieniu, ale nie interweniuje, co Konrad uznaje za moralnie niedopuszczalne."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010r001nqh7m025hqlcx', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Co oznacza termin ''romantyczny tytanizm'' Wiktora Weintrauba i jak odnosi się do Wielkiej Improwizacji?', '{"hint": "Specyfika polskiego prometeizmu"}', NULL, NULL, '{}', '{"keyPoints": ["bunt przeciw Bogu chrześcijańskiemu", "radykalniejszy niż mit antyczny", "gigantyczne roszczenia", "Weintraub"], "sampleAnswer": "Wiktor Weintraub ukuł termin ''romantyczny tytanizm'' dla opisu specyfiki polskiego prometeizmu. W odróżnieniu od klasycznego mitu, gdzie Prometeusz buntuje się przeciw pogańskim bogom (Zeusowi), Konrad buntuje się przeciw Bogu chrześcijańskiemu - jedynemu, wszechmocnemu, moralnemu. To czyni bunt radykalniejszym i bardziej bluźnierczym. Tytanizm oznacza także gigantyczne roszczenia: Konrad chce być równy Bogu, nie tylko Go oskarżać."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010r001oqh7mwg7xoweg', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Jak Maria Janion interpretowała mesjanizm przez pryzmat psychoanalizy?', '{"hint": "Trauma, kompleks, kompensacja"}', NULL, NULL, '{}', '{"keyPoints": ["trauma historyczna", "kompleks winy", "kompensacja niższości", "mechanizm obronny"], "sampleAnswer": "Maria Janion stosowała do mesjanizmu kategorie psychoanalityczne: trauma, kompleks, kompensacja. Mesjanizm był odpowiedzią na traumę rozbiorów i klęsk powstań - próbą ''przezwyciężenia narodowego kompleksu winy''. Poczucie niższości wobec Zachodu (skolonizowani, peryferyjni) kompensowane było przekonaniem o wyższości moralnej i szczególnej misji. Mesjanizm przekształcał słabość w siłę, porażkę w wybraństwo - mechanizm obronny zbiorowej psychiki."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010r001pqh7mub3l7i88', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Wyjaśnij, czym jest ''figura'' w interpretacji Zofii Stefanowskiej i jak stosuje się do mesjanizmu.', '{"hint": "Sposób przedstawiania jednej realności przez drugą"}', NULL, NULL, '{}', '{"keyPoints": ["Auerbach", "dwie realności historyczne", "zapowiedź i wypełnienie", "nie alegoria"], "sampleAnswer": "Zofia Stefanowska przejęła od Ericha Auerbacha pojęcie ''figury'' - sposobu przedstawiania jednej rzeczy przez drugą, gdzie OBA człony są realnościami historycznymi. Pierwsze wydarzenie ''zapowiada'' drugie, drugie ''wypełnia'' pierwsze. W mesjanizmie męka Chrystusa jest figurą cierpienia Polski: obie rzeczywistości są historyczne, Chrystus zapowiada Polskę, Polska wypełnia schemat chrystologiczny. To nie alegoria (gdzie znaczenie jest abstrakcyjne), lecz związek dwóch konkretnych historii."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010r001qqh7muwsfu29c', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 5, 'Jak Alfred Gall interpretuje mesjanizm w perspektywie postkolonialnej? Wyjaśnij pojęcie ''kontrdyskursu'' i ''appropriation''.', '{"hint": "Zawłaszczenie dyskursu hegemonicznego"}', NULL, NULL, '{}', '{"keyPoints": ["kontrdyskurs wobec Hegla", "appropriation - zawłaszczenie", "użycie języka hegemonii", "słabość jako siła", "cel uniwersalny"], "sampleAnswer": "Alfred Gall stosuje do mesjanizmu kategorię postkolonialnego ''kontrdyskursu''. Heglowska filozofia dziejów marginalizowała Słowian jako narody ''pozahistoryczne''. Mesjanizm był świadomą odpowiedzią - ''appropriation'' (zawłaszczeniem) dyskursu hegemonialnego. Mickiewicz używał języka filozofii niemieckiej (kategorie historiozoficzne), by ją przezwyciężyć i wpisać Polskę w dzieje. Słabość przekształcał w siłę, peryferie w centrum. Celem nie było odwrócenie hierarchii (polska dominacja), lecz stworzenie uniwersalnej koncepcji europejskiej."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010r001rqh7ma2r1gpxs', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 5, 'Jak Kwiryna Ziemba interpretuje utożsamienie Konrada z ''Milionem'' jako mechanizm obronny?', '{"hint": "Rozpad i rekonstrukcja podmiotowości"}', NULL, NULL, '{}', '{"keyPoints": ["kryzys podmiotowości", "trauma emigracji", "mechanizm obronny", "wzmocnienie ja przez zbiorowość", "rozpad i rekonstrukcja"], "sampleAnswer": "Kwiryna Ziemba analizowała wiersze z rękopisów III cz. Dziadów (''Do Samotności'', ''Te rozkwitłe świeżo drzewa...'') jako świadectwo kryzysu podmiotowości Mickiewicza po traumie emigracji. Rozpad indywidualnego ''ja'' prowadzi do mechanizmu obronnego: wzmocnienia podmiotowości przez identyfikację ze zbiorowością. ''Nazywam się Milion'' to nie tylko patriotyczna deklaracja, lecz sposób na rekonstrukcję rozbitego ''ja'' - jednostka słaba staje się silna jako część milionów. To psychologiczna funkcja utożsamienia z narodem."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010s001sqh7mi1bu9jps', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 5, 'Wyjaśnij, dlaczego Heglowska ''chytrość rozumu'' (List der Vernunft) była nie do przyjęcia dla Mickiewicza i jak mesjanizm ją odwraca.', '{"hint": "Narody jako narzędzia vs podmioty dziejów"}', NULL, NULL, '{}', '{"keyPoints": ["chytrość rozumu - narody jako narzędzia", "cierpienie jako konieczność", "odwrócenie: Polska jako podmiot", "świadoma ofiara vs ślepe narzędzie"], "sampleAnswer": "U Hegla ''chytrość rozumu'' oznacza, że duch dziejów używa narodów i jednostek jako narzędzi do realizacji swoich celów - nie są podmiotami, lecz środkami. Cierpienie jest konieczne dla postępu. Dla Mickiewicza było to nie do przyjęcia: narody (Polska) byłyby tylko pionkami, cierpienie - bezsensowną koniecznością. Mesjanizm odwraca ten schemat: Polska nie jest narzędziem, lecz PODMIOTEM zbawienia. Jej cierpienie nie jest instrumentalne, lecz ma własny sens - odkupieńczy. Świadoma ofiara, nie ślepe narzędzie."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010s001tqh7m6hsm5hf1', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 5, 'Na czym polega ''lucyferyczny'' (nie szatański) charakter buntu Konrada według Natalii Piórczyńskiej?', '{"hint": "Aspiracja do boskości vs destrukcja"}', NULL, NULL, '{}', '{"keyPoints": ["lucyferyzm vs satanizm", "aspiracja do boskości", "miłość jako motywacja", "możliwość ocalenia", "pycha, nie nihilizm"], "sampleAnswer": "Natalia Piórczyńska rozróżnia lucyferyzm od satanizmu. Lucyfer to ''niosący światło'', jego bunt wynika z aspiracji do boskości - chce być JAK Bóg, nie PRZECIW Bogu. Konrad nie neguje istnienia Boga, nie chce Go zniszczyć - chce być Mu równy, mieć Jego moc dla dobra narodu. Motywacją jest miłość, nie nienawiść. Aspiruje do demiurgii (tworzenia światów), nie destrukcji. Dlatego możliwe jest jego ocalenie - to pycha niosąca światło (choć błędne), nie ciemność nihilizmu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010s001uqh7mulw0n5a0', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 5, 'Wyjaśnij paradoks ''polskiej mentalności postkolonialnej'' według Marii Janion.', '{"hint": "Zamknięte koło niższości i wyższości"}', NULL, NULL, '{}', '{"keyPoints": ["skolonizowanie - poczucie niższości", "mesjanizm - poczucie wyższości", "błędne koło", "kompleks vs megalomania"], "sampleAnswer": "Janion opisuje paradoks polskiej mentalności postkolonialnej jako ''zamknięte koło niższości i wyższości''. Z jednej strony doświadczenie skolonizowania (rozbiory, marginalizacja w dyskursie zachodnim) rodzi poczucie niższości, peryferyjności wobec ''Zachodu''. Z drugiej - mesjanizm kompensuje to poczucie przekonaniem o wyższości moralnej: my cierpimy za innych, jesteśmy ''Chrystusem narodów'', Zachód jest ''zepsuty''. To błędne koło uniemożliwia zdrową relację z własną historią i innymi narodami - oscylacja między kompleksem niższości a megalomanią."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010s001vqh7m4k82v25s', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 6, 'Przeanalizuj funkcję autocenzury (niedokończonego bluźnierstwa) w Wielkiej Improwizacji jako świadomej strategii artystycznej. Jak wpływa ona na interpretację tekstu?', '{"hint": "Ambiwalencja, ochrona bohatera, wieloznaczność"}', NULL, NULL, '{}', '{"keyPoints": ["ambiwalencja", "ochrona bohatera", "wieloznaczność omdlenia", "różne lektury", "autocenzura Mickiewicza"], "sampleAnswer": "Niedokończone bluźnierstwo (''Tyś nie jest ojcem świata, ale...'') to nie tylko element dramaturgiczny, lecz świadoma strategia artystyczna kreująca ambiwalencję tekstu. Po pierwsze, chroni bohatera przed jednoznacznym potępieniem - skoro nie wypowiedział pełnego bluźnierstwa, jego ocalenie jest możliwe. Po drugie, utrzymuje napięcie interpretacyjne: czy omdlenie to interwencja Opatrzności, czy wewnętrzny hamulec Konrada? Po trzecie, umożliwia różne lektury - romantyczną (szlachetny bunt przerwany w ostatniej chwili) i religijną (grzech pychy powstrzymany łaską). Kwiryna Ziemba widzi tu ''autocenzurę'' Mickiewicza - ochronę tekstu i bohatera przed skrajnościami."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010s001wqh7msgd8y9tz', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 6, 'Jak wiersze z rękopisów III cz. Dziadów (''Do Samotności'', ''Te rozkwitłe świeżo drzewa...'', ''Ja w mej chacie spać nie mogę...'') oświetlają genezę i funkcję Wielkiej Improwizacji?', '{"hint": "Kryzys podmiotowości, petrarkizm, liryka rosyjska"}', NULL, NULL, '{}', '{"keyPoints": ["kryzys podmiotowości", "rozprzężenie więzi", "petrarkizm i liryka rosyjska", "Milion jako rekonstrukcja ja", "Improwizacja jako terapia"], "sampleAnswer": "Kwiryna Ziemba analizuje te wiersze jako świadectwo głębokiego kryzysu podmiotowości Mickiewicza na emigracji. ''Do Samotności'' pokazuje rozpad więzi ze światem, ''Te rozkwitłe świeżo drzewa...'' nawiązuje do petrarkistycznej tradycji liryki miłosnej (kochanek wśród natury), ''Ja w mej chacie...'' łączy petrarkizm z liryką rosyjską (Puszkin). Mickiewicz szuka form dla wyrażenia rozpadu ''ja''. Wielka Improwizacja jest odpowiedzią na ten kryzys: utożsamienie z ''Milionem'' to mechanizm obronny - rekonstrukcja rozbitej podmiotowości przez identyfikację ze zbiorowością. Improwizacja ''leczy'' podmiotowość przez heroiczne przejęcie cierpienia narodu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010s001xqh7mzciq21mp', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 6, 'Porównaj interpretację hermeneutyczną (Stefanowska), psychoanalityczną (Janion) i postkolonialną (Gall) mesjanizmu. Które elementy są wspólne, a które specyficzne dla każdej metody?', '{"hint": "Figura vs trauma vs kontrdyskurs"}', NULL, NULL, '{}', '{"keyPoints": ["figura (hermeneutyka)", "trauma/kompensacja (psychoanaliza)", "kontrdyskurs (postkolonializm)", "wspólne: sens cierpienia", "różne: tekst vs psyche vs władza"], "sampleAnswer": "HERMENEUTYKA (Stefanowska): Mesjanizm to ''figura'' - sposób przedstawiania realności historycznej przez inną. Sekularyzacja Chrystusa służy temu, by mógł być figurą Polski. Główne kategorie: figura, wypełnienie, sens tekstu. PSYCHOANALIZA (Janion): Mesjanizm to kompensacyjna odpowiedź na traumę historyczną. Poczucie niższości kompensowane przekonaniem o wyższości. Kategorie: trauma, kompleks, mechanizm obronny. POSTKOLONIALIZM (Gall): Mesjanizm to kontrdyskurs wobec hegemonii Hegla. Zawłaszczenie języka hegemonii dla własnych celów. Kategorie: appropriation, kontrdyskurs, hegemonia. WSPÓLNE: wszystkie widzą mesjanizm jako odpowiedź na sytuację podporządkowania i próbę nadania sensu cierpieniu. RÓŻNICE: hermeneutyka skupia się na strukturze tekstu, psychoanaliza - na psychice zbiorowej, postkolonializm - na relacjach władzy i dyskursu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010t001yqh7mgo7ahk2s', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 12, 'Przeanalizuj problem teodycei w Wielkiej Improwizacji. Jak Konrad polemizuje z klasycznymi rozwiązaniami tego problemu i czy jego argumentacja jest przekonująca?', '{"hints": ["Teodyceja to problem pogodzenia dobrego Boga z istnieniem zła", "Leibniz: ''najlepszy z możliwych światów''", "Konrad zarzuca: mądrość bez miłości", "Milczenie Boga - różne interpretacje"], "instruction": "Napisz wypracowanie (400-500 słów), w którym:\n- zdefiniujesz problem teodycei\n- przedstawisz klasyczne rozwiązania (Leibniz, Hiob)\n- przeanalizujesz zarzuty Konrada wobec Boga\n- oceń siłę argumentacji Konrada\n- rozważ znaczenie milczenia Boga"}', NULL, NULL, '{}', '{"sampleAnswer": "Teodyceja to filozoficzny problem pogodzenia trzech twierdzeń: Bóg jest wszechmocny, Bóg jest dobry, zło istnieje w świecie. Jeśli Bóg jest wszechmocny i dobry, dlaczego zło istnieje? Klasyczne rozwiązanie Leibniza głosiło, że żyjemy w ''najlepszym z możliwych światów'' - zło jest koniecznym elementem harmonii, służy większemu dobru. Księga Hioba przedstawia inną odpowiedź: Bóg jest ponad ludzkim rozumieniem, Jego plany wykraczają poza naszą pojętność.\n\nKonrad w Wielkiej Improwizacji odrzuca oba rozwiązania. Jego centralny zarzut brzmi: Bóg ma ''mądrość, ale nie ma miłości''. Znaczy to: Bóg wie o cierpieniu Polaków (jest wszechwiedzący), ale nie interweniuje (brak miłości/dobroci). Konrad nie akceptuje argumentu, że cierpienie służy większemu dobru - dla niego cierpienie niewinnych jest po prostu niesprawiedliwe, niezależnie od przyszłych korzyści. ''Miliony'' cierpią teraz, tu i dziś.\n\nArgumentacja Konrada jest emocjonalnie potężna, ale filozoficznie problematyczna. Siła: Konrad mówi z pozycji cierpiącego, nie teoretyka. Jego zarzut jest egzystencjalny, nie akademicki - to krzyk bólu, nie traktat. Przedstawia się jako miłujący bardziej niż Bóg: ''Ja kocham cały naród! Objąłem w ramiona / Wszystkie przeszłe i przyszłe jego pokolenia''.\n\nSłabość: Konrad sam pragnie boskiej władzy (''rząd dusz''), co podważa jego moralną wyższość. Jego ''miłość'' łączy się z pychą i żądzą absolutnej kontroli. Ponadto żąda odpowiedzi, której struktura teologii nie może dać - tajemnica zła pozostaje tajemnicą.\n\nMilczenie Boga jest wieloznaczne. Można je interpretować jako: (1) potwierdzenie oskarżeń - Bóg nie ma kontrargumentów (Przybylski); (2) transcendencję - Bóg jest ponad dialogiem na warunkach człowieka; (3) próbę - jak w Księdze Hioba, milczenie poprzedza objawienie. Mickiewicz zostawia interpretację otwartą.\n\nUważam, że siła Konrada leży nie w logice, lecz w autentyczności. Jego argumentacja nie ''wygrywa'' filozoficznej debaty o teodycei, ale wyraża coś głęboko ludzkiego: odmowę pogodzenia się z cierpieniem w imię abstrakcyjnych uzasadnień."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010t001zqh7mgfiwjcs9', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 12, 'Omów romantyczną koncepcję poety-demiurga w Wielkiej Improwizacji. Jak Konrad realizuje ten ideał i gdzie napotyka jego granice?', '{"hints": ["Schelling: sztuka jako ''organ Absolutu''", "Poeta tworzy światy jak Bóg-stwórca", "Konrad: ''Cóż Ty większego mogłeś zrobić - Boże?''", "Granica: język nie wyraża pełni myśli"], "instruction": "Napisz wypracowanie (400-500 słów), w którym:\n- wyjaśnisz romantyczną koncepcję poety jako demiurga (Schelling)\n- przeanalizujesz, jak Konrad wyraża tę koncepcję\n- wskaż granice i tragizm tej aspiracji\n- odnieś się do problemu niewyrażalności (''język kłamie głosowi'')"}', NULL, NULL, '{}', '{"sampleAnswer": "Romantyczna koncepcja poety-demiurga, rozwinięta przede wszystkim przez Friedricha Schellinga, głosiła, że sztuka jest ''organem Absolutu'' - przez geniusza artystycznego przemawia nieskończoność. Poeta nie naśladuje natury, lecz tworzy własne światy, analogicznie do Boga-Stwórcy. Jest demiurgiem - istotą tworzącą rzeczywistość mocą wyobraźni i słowa.\n\nKonrad w Wielkiej Improwizacji realizuje ten ideał z niespotykaną intensywnością. Już na początku przedstawia się jako twórca absolutny: jego pieśń ''leci w niebiosa'' i dosięga gwiazd. Kluczowe jest pytanie retoryczne: ''Cóż Ty większego mogłeś zrobić - Boże?'' - Konrad zrównuje swoją twórczość z boskim aktem stworzenia. Jego pieśni są jak ''gwiazdy'', jego uczucia ogarniają ''miliony''. W ekstatycznym momencie poeta zdaje się mieć moc demiurgiczną: tworzy światy, wpływa na kosmiczny porządek.\n\nJednak Wielka Improwizacja ukazuje też tragiczne granice tej aspiracji. Pierwsza granica to problem niewyrażalności: ''Język kłamie głosowi, a głos myślom kłamie''. Nawet demiurg nie może w pełni wyrazić tego, co czuje i myśli - słowa są niewystarczające. Pieśń, choć leci ''za granicę świata'', nie może powiedzieć wszystkiego. To tragedia romantycznego poety: ma wizję absolutną, ale narzędzia wyrazu są ograniczone.\n\nDruga granica to różnica między tworzeniem a władaniem. Konrad może tworzyć światy poetyckie, ale nie może realnie zmienić losu narodu. Dlatego żąda ''rządu dusz'' - władzy nad rzeczywistością, nie tylko wyobraźnią. Poezja nie wystarcza. I właśnie tutaj demiurgiczna aspiracja zamienia się w hybris: poeta chce być nie tylko twórcą, ale władcą.\n\nTragizm Konrada polega na tym, że jego geniusz jest realny (tworzy niezwykłą Improwizację), ale bezsilny wobec cierpienia. Poeta może wyrazić ból narodu, ale nie może go usunąć. Może tworzyć światy, ale nie może zbawić tego świata. Wielka Improwizacja jest jednocześnie szczytem i klęską romantycznego ideału poety-demiurga: szczytem - bo pokazuje potęgę słowa; klęską - bo pokazuje jego niewystarczalność."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010t0020qh7mmygpgm12', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 15, 'Przeanalizuj mesjanizm Mickiewicza jako ''kontrdyskurs'' wobec filozofii Hegla w perspektywie postkolonialnej. Oceń trafność tej interpretacji.', '{"hints": ["Hegel: Słowianie poza historią, ''chytrość rozumu''", "Gall: mesjanizm jako appropriation dyskursu hegemonicznego", "Słabość przekształcona w siłę", "Czy Polska XIX wieku to ''kolonia''?"], "instruction": "Napisz wypracowanie (500-600 słów), w którym:\n- przedstawisz stanowisko Hegla wobec Słowian (narody ''pozahistoryczne'')\n- wyjaśnisz pojęcie kontrdyskursu i appropriation\n- przeanalizujesz, jak mesjanizm odpowiada na heglowską marginalizację\n- oceń zalety i ograniczenia interpretacji postkolonialnej"}', NULL, NULL, '{}', '{"sampleAnswer": "Heglowska filozofia dziejów stanowiła w XIX wieku dominujący dyskurs historiozoficzny Europy. Według Hegla, dzieje są procesem samorealizacji ducha przez kolejne ''narody historyczne''. ''Chytrość rozumu'' używa narodów jako narzędzi postępu - gdy wypełnią swoją misję, znikają z areny dziejów. Kluczowe: Słowianie dla Hegla byli narodami ''pozahistorycznymi'' - nierozwiniętymi, niezdolnymi do samowiedzy, pozostającymi poza historią. Ta diagnoza sankcjonowała ich marginalizację i dominację Prus.\n\nAlfred Gall interpretuje mesjanizm Mickiewicza jako postkolonialny ''kontrdyskurs'' wobec tej hegemonii. Postkolonializm bada relacje władzy i dominacji kulturowej. Kluczowym mechanizmem jest ''appropriation'' (zawłaszczenie) - przejęcie dyskursu dominującego i przekształcenie go na własne potrzeby. Sam Mickiewicz pisał, że musi ''przejmować od Zachodu jego język filozoficzny, aby powszechną myśl słowiańską nawiązać do europejskiej''.\n\nJak mesjanizm realizuje appropriation? Po pierwsze, zachowuje heglowski schemat historiozoficzny (dzieje mają sens, narody pełnią role), ale zmienia wnioski: Polska nie jest poza historią - jest jej CENTRUM jako Chrystus narodów. Po drugie, odwraca wartościowanie: słabość (rozbiory, cierpienie) staje się siłą (misja odkupieńcza), peryferie - centrum. Po trzecie, używa kategorii Hegla (duch dziejów) przeciwko niemu - ''Bóg polityczny'' Hegla jest krytykowany jako pruski ideolog. Mesjanizm nie odrzuca heglowskiego języka - zawłaszcza go i przekierowuje.\n\nOcena tej interpretacji wymaga rozważenia jej zalet i ograniczeń. ZALETY: (1) pokazuje mesjanizm jako świadomą strategię, nie tylko kompensacyjną fantazję; (2) łączy literaturę z kontekstem polityczno-dyskursywnym; (3) wyjaśnia, dlaczego Mickiewicz używał kategorii filozofii niemieckiej; (4) unika redukcji do nacjonalizmu czy psychopatologii.\n\nOGRANICZENIA: (1) czy Polska XIX wieku to ''kolonia'' w sensie postkolonialnym? Sytuacja rozbiorów różni się od kolonizacji zamorskiej; (2) czy mesjanizm był tak świadomą strategią, czy raczej wyrazem głębokiej wiary?; (3) interpretacja postkolonialna może zaniedbywać wymiar religijny i egzystencjalny; (4) czy Mickiewicz rzeczywiście znał Hegla wystarczająco, by ''polemizować''?\n\nUważam, że interpretacja Galla jest cenna jako JEDEN z kluczy do mesjanizmu, ale nie jedyny. Pokazuje wymiar dyskursywny i polityczny, którego inne interpretacje (hermeneutyczna, psychoanalityczna) nie wydobywają. Jednocześnie nie wyczerpuje bogactwa tekstu. Mesjanizm był prawdopodobnie zarówno strategią, jak i wiarą, zarówno kontrdyskursem, jak i autentycznym wyrazem cierpienia. Wielość interpretacji odpowiada wielowarstwowości dzieła."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010t0021qh7md3v1f9vx', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 15, 'Przeanalizuj funkcję ''ambiwalencji'' w Dziadach cz. III jako świadomej strategii artystycznej Mickiewicza. Jak niedopowiedzenia i wieloznaczności wpływają na interpretację dzieła?', '{"hints": ["Niedokończone bluźnierstwo: ''Tyś nie jest ojcem świata, ale...''", "Omdlenie: interwencja czy wewnętrzny hamulec?", "Proroctwo ''44'': nigdy niewyjaśnione", "Kwiryna Ziemba: ''autocenzura'' Mickiewicza"], "instruction": "Napisz wypracowanie (500-600 słów), w którym:\n- zdefiniujesz ambiwalencję w kontekście literackim\n- przeanalizujesz kluczowe miejsca niedopowiedzień (bluźnierstwo, omdlenie, proroctwo ''44'')\n- rozważ funkcje ambiwalencji: ochrona bohatera, wielość lektur, napięcie interpretacyjne\n- oceń, czy ambiwalencja wzmacnia czy osłabia przesłanie dzieła"}', NULL, NULL, '{}', '{"sampleAnswer": "Ambiwalencja w literaturze oznacza celową wieloznaczność, która uniemożliwia jednoznaczną interpretację. Dzieło ambiwalentne zawiera napięcia, sprzeczności i niedopowiedzenia, które otwierają pole dla różnych lektur. W Dziadach cz. III Mickiewicz stosuje ambiwalencję jako świadomą strategię artystyczną, której funkcje wykraczają poza efekt estetyczny.\n\nKluczowym miejscem ambiwalencji jest niedokończone bluźnierstwo: ''Tyś nie jest ojcem świata, ale...'' Konrad mdleje, słowo ''car'' dokańcza diabeł. Ta konstrukcja jest wieloznaczna: (1) Czy Konrad SAM wypowiedział bluźnierstwo (bo chciał powiedzieć ''car'')? (2) Czy omdlenie to interwencja Opatrzności chroniąca go przed potępieniem? (3) Czy to wewnętrzny hamulec - sumienie lub strach? Każda odpowiedź prowadzi do innej interpretacji: bohater jako bluźnierca, jako chroniony łaską, jako rozdarta dusza. Mickiewicz nie rozstrzyga.\n\nDrugie miejsce ambiwalencji to samo omdlenie. Czy jest fizyczne (wyczerpanie), duchowe (interwencja), psychologiczne (mechanizm obronny)? Różne interpretacje prowadzą do różnych ocen Konrada. Kwiryna Ziemba mówi o ''autocenzurze'' Mickiewicza - poecie świadomie chroniącym bohatera (i siebie) przed skrajnością.\n\nTrzecie miejsce to proroctwo ''44''. Mickiewicz nigdy go nie wyjaśnił, choć był pytany wielokrotnie. To milczenie jest znaczące: proroctwo MUSI pozostać otwarte, by zachować moc. Gdyby Mickiewicz wskazał konkretną osobę, proroctwo mogłoby być sfalsyfikowane. Otwartość utrzymuje nadzieję i gotowość.\n\nFunkcje ambiwalencji są wielorakie. Po pierwsze, OCHRONA BOHATERA: dzięki niedopowiedzeniu Konrad może być ocalony - nie wypowiedział pełnego bluźnierstwa, więc może przejść pokutę i przemianę. Po drugie, WIELOŚĆ LEKTUR: romantyczny czytelnik widzi szlachetny bunt przerwany w ostatniej chwili; katolicki - grzech pychy powstrzymany łaską. Obie lektury są uprawnione. Po trzecie, NAPIĘCIE INTERPRETACYJNE: dzieło pozostaje żywe, prowokuje do ciągłych reinterpretacji przez niemal 200 lat.\n\nCzy ambiwalencja wzmacnia czy osłabia przesłanie? Pozornie osłabia - brak jasnej ''tezy''. Jednak głębiej: wzmacnia, bo przesłanie Dziadów nie jest prostą doktryną, lecz dramatem duszy. Konrad nie jest wzorem do naśladowania ani antywzorem - jest pytaniem. Mesjanizm nie jest katechizmem, lecz dramatycznym poszukiwaniem sensu. Ambiwalencja odpowiada złożoności ludzkiego doświadczenia: bunt Konrada jest jednocześnie szlachetny i grzeszny, pyszny i miłujący. To właśnie ta złożoność czyni Dziady arcydziełem, nie prostym traktatem ideologicznym."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010t0022qh7mbt890f7k', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 20, 'Porównaj trzy główne paradygmaty interpretacyjne mesjanizmu Mickiewicza: hermeneutyczny (Stefanowska), psychoanalityczny (Janion) i postkolonialny (Gall). Oceń ich komplementarność i ograniczenia oraz zaproponuj syntezę.', '{"hints": ["Stefanowska: figura, wypełnienie, instrumentalne użycie religii", "Janion: trauma, kompleks, kompensacja, mentalność postkolonialna", "Gall: kontrdyskurs, appropriation, hegemonia Hegla", "Czy paradygmaty są komplementarne, czy wykluczające?"], "instruction": "Napisz rozprawkę (600-800 słów), w której:\n- przedstawisz kluczowe kategorie każdego paradygmatu\n- przeanalizujesz, co każdy paradygmat wydobywa, a co pomija\n- rozważ możliwości syntezy i konflikty między paradygmatami\n- oceń, który paradygmat wydaje Ci się najadekwatniejszy i dlaczego"}', NULL, NULL, '{}', '{"sampleAnswer": "Mesjanizm Mickiewicza był od momentu publikacji przedmiotem intensywnych interpretacji. W XX i XXI wieku wykrystalizowały się trzy główne paradygmaty badawcze: hermeneutyczny (Zofia Stefanowska), psychoanalityczny (Maria Janion) i postkolonialny (Alfred Gall). Każdy z nich operuje odmiennymi kategoriami i wydobywa inne aspekty fenomenu.\n\nPARADYGMAT HERMENEUTYCZNY Stefanowskiej koncentruje się na strukturze tekstu i jego relacji do tradycji. Kluczową kategorią jest ''figura'' (za Auerbachem) - sposób przedstawiania jednej realności historycznej przez drugą. Męka Chrystusa jest figurą cierpienia Polski - obie rzeczywistości są historyczne, pierwsza zapowiada drugą, druga ''wypełnia'' pierwszą. Stefanowska podkreśla instrumentalne użycie religii: Księgi i Dziady to ''broszura patriotyczna'', sekularyzacja Chrystusa służy temu, by mógł być figurą Polski. Hermeneutyka WYDOBYWA: strukturę tekstu, relacje intertekstualne, kontekst biblijny i teologiczny. POMIJA: psychologię zbiorową, relacje władzy, wymiar traumatyczny.\n\nPARADYGMAT PSYCHOANALITYCZNY Janion stosuje kategorie psychoanalizy do kultury narodowej. Mesjanizm jest odpowiedzią na traumę (rozbiory, klęski powstań), próbą przezwyciężenia ''kompleksu winy'' i poczucia niższości. Centralne pojęcie to ''kompensacja'': poczucie marginalizacji wobec Zachodu kompensowane przekonaniem o wyższości moralnej. Janion opisuje ''paradoks polskiej mentalności postkolonialnej'' - zamknięte koło niższości i wyższości. Psychoanaliza WYDOBYWA: funkcję psychologiczną mesjanizmu, mechanizmy obronne zbiorowej psychiki, związki między traumą a ideologią. POMIJA: autonomię tekstu literackiego, kontekst filozoficzny, świadomy wymiar strategiczny.\n\nPARADYGMAT POSTKOLONIALNY Galla traktuje mesjanizm jako świadomą strategię emancypacyjną. Kategorie to ''kontrdyskurs'' (odpowiedź na hegemońską filozofię Hegla), ''appropriation'' (zawłaszczenie języka hegemonii i przekształcenie go). Mickiewicz używał kategorii filozofii niemieckiej, by przezwyciężyć marginalizację Słowian. Postkolonializm WYDOBYWA: wymiar polityczny i dyskursywny, świadomy charakter strategii, relacje władzy kulturowej. POMIJA: wymiar religijny i egzystencjalny, specyfikę sytuacji polskiej (czy to rzeczywiście ''kolonializm''?), psychologię jednostkową.\n\nCZY PARADYGMATY SĄ KOMPLEMENTARNE? W znacznej mierze tak. Hermeneutyka analizuje JAK tekst jest zbudowany, psychoanaliza - CZEMU służy psychologicznie, postkolonializm - W JAKIM KONTEKŚCIE władzy powstaje. Można je łączyć: tekst (Stefanowska) odpowiada na traumę (Janion) i jest kontrdyskursem (Gall). Jednak istnieją napięcia: psychoanaliza sugeruje nieświadome mechanizmy, postkolonializm - świadomą strategię. Hermeneutyka koncentruje się na tekście, pozostałe wychodzą poza niego.\n\nPROPOZYCJA SYNTEZY: Mesjanizm był jednocześnie świadomą strategią dyskursywną (Gall) i nieświadomą odpowiedzią na traumę (Janion), wyrażoną w wyrafinowanej formie literackiej (Stefanowska). Nie trzeba wybierać - ludzie mogą być jednocześnie strategami i ofiarami traumy, świadomymi retorami i nieświadomymi kompensatorami.\n\nMOJA OCENA: Paradygmat hermeneutyczny wydaje mi się fundamentalny - bez analizy tekstu pozostałe są spekulacją. Jednak jest niewystarczający: nie wyjaśnia, DLACZEGO Mickiewicz tworzył takie teksty. Tu pomocna jest psychoanaliza (trauma) i postkolonializm (hegemonia). Najadekwatniejsza jest więc synteza: hermeneutyka jako baza, psychoanaliza i postkolonializm jako kontekstualizacja. Mesjanizm to wielowarstwowy fenomen wymagający wielowarstwowej interpretacji."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010t0023qh7m8g22mf3x', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 20, 'Przeanalizuj teozoficzne i filozoficzne źródła Wielkiej Improwizacji (Boehme, Schelling, Leibniz, Księga Hioba). Jak te różne tradycje współistnieją w monologu Konrada i jaką tworzą całość?', '{"hints": ["Boehme: Ungrund, natura Boga, wspólne źródło sił", "Schelling: poeta jako demiurg, organ Absolutu", "Leibniz: teodyceja, ''najlepszy ze światów'' (odrzucona)", "Księga Hioba: niewinny cierpiący pyta Boga"], "instruction": "Napisz rozprawkę (600-800 słów), w której:\n- przedstawisz wkład każdej tradycji filozoficznej/religijnej\n- przeanalizujesz, jak Mickiewicz je łączy lub stawia w napięciu\n- rozważ, czy Wielka Improwizacja jest koherentną syntezą czy eklektycznym zbiorem\n- oceń oryginalność Mickiewicza wobec źródeł"}', NULL, NULL, '{}', '{"sampleAnswer": "Wielka Improwizacja jest tekstem wielowarstwowym, czerpiącym z różnych tradycji filozoficznych i religijnych. Kluczowe źródła to: teozofia Jakuba Boehmego, filozofia sztuki Friedricha Schellinga, problematyka teodycei (Leibniz) oraz tradycja biblijna (Księga Hioba). Analiza ich współistnienia pozwala zrozumieć głębię i oryginalność Mickiewicza.\n\nTEOZOFIA BOEHMEGO dostarcza kosmologicznej podstawy buntu Konrada. Kluczowe pojęcia to: (1) Ungrund (Bezdeń) - pierwotna otchłań poprzedzająca rozróżnienia, wspólne źródło wszystkiego; (2) ''wieczna natura'' Boga - aspekt zawierający zarówno jasne, jak i ciemne siły; (3) wspólne pochodzenie sił boskich i ludzkich. Konrad mówi: ''Stamtąd przyszły siły moje, skąd do Ciebie przyszły Twoje'' - powołuje się na wspólne źródło, by uzasadnić roszczenia. Atak ''przeciw naturze'' Boga (nie samemu Bogu) wykorzystuje rozróżnienie Boehmego. Dzięki teozofii bunt Konrada nie jest prostym ateizmem, lecz wyrafinowaną krytyką kosmicznego porządku.\n\nFILOZOFIA SCHELLINGA dostarcza koncepcji poety-demiurga. W romantycznej filozofii sztuki Schellinga poeta jest ''organem Absolutu'' - przez geniusza przemawia nieskończoność, tworzy on światy jak Bóg-Stwórca. Konrad realizuje ten ideał: ''Cóż Ty większego mogłeś zrobić - Boże?'' - zrównuje swoją twórczość z boskim aktem. Jednak Mickiewicz pokazuje też granice tej koncepcji: ''język kłamie głosowi'' - nawet demiurg nie może w pełni wyrazić wizji. Schelling daje Konradowi aspirację, ale Mickiewicz odsłania jej tragiczność.\n\nTEODYCEA LEIBNIZA stanowi przedmiot krytyki. Leibniz twierdził, że żyjemy w ''najlepszym z możliwych światów'' - zło jest konieczne dla większej harmonii. Konrad explicite odrzuca ten optymizm: cierpienie ''Milionów'' Polaków nie służy żadnemu wyższemu celowi. Zarzut ''mądrość, ale nie miłość'' oznacza: Bóg wie o cierpieniu, ale nie interweniuje - to moralnie nieakceptowalne. Leibniz jest niewymienionym przeciwnikiem.\n\nKSIĘGA HIOBA dostarcza modelu dialogu z milczącym Bogiem. Hiob - niewinny cierpiący - pyta Boga o sens cierpienia. Bóg ostatecznie odpowiada (z wichru), ale nie wyjaśnia - pokazuje swoją wielkość. U Mickiewicza Bóg milczy całkowicie. Różne interpretacje: milczenie jako potwierdzenie oskarżeń (Przybylski) lub jako transcendencja. Konrad jest Hiobem, który nie doczeka odpowiedzi.\n\nCZY TO KOHERENTNA SYNTEZA CZY EKLEKTYZM? Uważam, że to DRAMATYCZNA SYNTEZA - nie logicznie spójna doktryna, lecz koherentna artystycznie całość. Boehme daje metafizyczne zaplecze, Schelling - estetyczne, Leibniz - filozoficzny cel polemiczny, Hiob - egzystencjalny wzorzec. Łączy je PYTANIE o sens cierpienia i POSTAWA buntu-pytania. Napięcia między źródłami (np. Boehme pozwala na bunt ''wewnątrz'' systemu, Hiob pyta ale ulega) tworzą dynamikę, nie sprzeczność. To nie traktat filozoficzny, lecz dramat - a dramat żyje napięciami.\n\nORYGINALNOŚĆ MICKIEWICZA polega nie na wynalezieniu nowych idei, lecz na ich dramatyzacji i ukonkretnieniu. Abstrakcyjne pojęcia Boehmego stają się krzykiem cierpiącego poety, estetyka Schellinga - tragicznym doświadczeniem granic, teodyceja Leibniza - oskarżeniem. Co najważniejsze: Mickiewicz wpisuje te filozoficzne wątki w polski kontekst historyczny. Uniwersalne pytanie o zło staje się pytaniem o sens cierpienia narodu. To połączenie filozofii europejskiej z polskim doświadczeniem historycznym jest właściwą oryginalnością Wielkiej Improwizacji."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010u0024qh7m4e8cf3mq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Który filozof mistyczny wpłynął na koncepcję ''natury Boga'' atakowanej przez Konrada?', '{"options": ["Immanuel Kant", "Jakub Boehme", "Baruch Spinoza", "Gottfried Leibniz"]}', '1', NULL, '{}', '{"explanation": "Jakub Boehme rozróżniał Boga (Ungrund) od Jego ''wiecznej natury'' - Konrad atakuje właśnie tę naturę (''Strzelę przeciw Twej naturze''), nie samego Boga."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010u0025qh7mdl223mq3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Co oznacza termin ''Ungrund'' w teozofii Boehmego, do której nawiązuje Wielka Improwizacja?', '{"options": ["grzech pierworodny", "bezdeń, otchłań poprzedzająca stworzenie", "natura ludzka", "harmonia wszechświata"]}', '1', NULL, '{}', '{"explanation": "Ungrund (Bezdeń) to w teozofii Boehmego pierwotna otchłań, z której wyłania się zarówno Bóg, jak i siły ciemności - wspólne źródło dobra i zła."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010u0026qh7mje7d9y3d', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Który romantyczny filozof rozwinął koncepcję poety-demiurga, obecną w Wielkiej Improwizacji?', '{"options": ["Hegel", "Schelling", "Fichte", "Schopenhauer"]}', '1', NULL, '{}', '{"explanation": "Friedrich Schelling rozwinął romantyczną filozofię sztuki, w której poeta jest demiurgiem - twórcą światów analogicznym do Boga-Stwórcy."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010u0027qh7miyhzvbzm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Słowa Konrada ''Stamtąd przyszły siły moje, skąd do Ciebie przyszły Twoje'' nawiązują do jakiej koncepcji?', '{"options": ["panteizmu Spinozy", "wspólnego źródła sił Boga i człowieka (Boehme)", "dualizmu kartezjańskiego", "idei platońskich"]}', '1', NULL, '{}', '{"explanation": "Według Boehmego siły człowieka i Boga mają wspólne źródło w Bezdni (Ungrund) - Konrad powołuje się na tę równość pochodzenia."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev7zq0001qhd9jm8zyo4r', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 2, 1, 'W którym zdaniu jest błąd?', '{"options": ["Czytam książkę od godziny.", "Idę do lekarza.", "Spotkałem się z problemem.", "Piszę list do babci."]}', '2', NULL, '{language_use,closed_single,difficulty-2,batch-2025-01}', '{"explanation": "Błąd: ''spotkałem się z problemem'' - poprawnie: ''napotkałem problem''"}', '2025-10-24 22:16:52.023', '2025-10-24 22:16:52.023', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010u0028qh7m22wyaxah', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Co Zofia Stefanowska rozumiała przez ''figurę'' w interpretacji mesjanizmu?', '{"options": ["metaforę poetycką", "sposób przedstawiania jednej realności historycznej przez drugą", "postać literacką", "symbol religijny"]}', '1', NULL, '{}', '{"explanation": "Figura (za Auerbachem) to sposób przedstawiania, gdzie obie rzeczywistości są historyczne - męka Chrystusa jest figurą cierpienia Polski."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010v0029qh7mcpso25wx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Dlaczego według Stefanowskiej postać Chrystusa w ''Księgach narodu'' została zsekularyzowana?', '{"options": ["z powodu ateizmu Mickiewicza", "by mogła być figurą losu Polski", "dla uniknięcia cenzury", "pod wpływem oświecenia"]}', '1', NULL, '{}', '{"explanation": "Chrystus jako reformator (nie Zbawiciel) mógł być figurą Polski - zsekularyzowany, by wszystko mogło ''wypełnić się w losie Polski''."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010v002aqh7mwoqcoq1l', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jak Maria Janion określiła funkcję mesjanizmu w polskiej kulturze?', '{"options": ["jako wyraz nacjonalizmu", "jako kompensacyjną odpowiedź na traumę historyczną", "jako kontynuację średniowiecza", "jako wpływ literatury francuskiej"]}', '1', NULL, '{}', '{"explanation": "Janion analizowała mesjanizm przez pryzmat psychoanalizy - jako kompensację traumy, próbę przezwyciężenia ''kompleksu winy'' i poczucia niższości."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010v002bqh7mxxjzz612', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Co według Wiktora Weintrauba oznacza termin ''romantyczny tytanizm''?', '{"options": ["kult siły fizycznej", "bunt przeciw Bogu chrześcijańskiemu (nie pogańskim bogom)", "naśladowanie mitologii greckiej", "idealizację przemocy"]}', '1', NULL, '{}', '{"explanation": "Weintraub podkreślał, że polski prometeizm to bunt przeciw Bogu chrześcijańskiemu - co czyni go radykalniejszym niż mit antyczny."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010v002cqh7mj44quoc0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Która badaczka analizowała Wielką Improwizację jako ''mechanizm obronny rozbitej podmiotowości''?', '{"options": ["Maria Janion", "Zofia Stefanowska", "Kwiryna Ziemba", "Alina Witkowska"]}', '2', NULL, '{}', '{"explanation": "Kwiryna Ziemba interpretowała utożsamienie z ''Milionem'' jako mechanizm obronny - wzmocnienie ''ja'' przez identyfikację ze zbiorowością."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010v002dqh7mhp84wojj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Do jakiej biblijnej księgi nawiązuje konflikt Konrada z milczącym Bogiem?', '{"options": ["Księga Rodzaju", "Księga Hioba", "Pieśń nad Pieśniami", "Apokalipsa"]}', '1', NULL, '{}', '{"explanation": "Księga Hioba to archetypiczny tekst o teodycei - niewinny cierpiący pyta Boga o sens cierpienia, Bóg ostatecznie odpowiada z wichru."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010v002eqh7m4wkut85w', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Co według Alfreda Galla stanowi mesjanizm w perspektywie postkolonialnej?', '{"options": ["wyraz polskiego nacjonalizmu", "kontrdyskurs wobec hegemonii filozofii niemieckiej", "naśladowanie mesjanizmu francuskiego", "formę ucieczki od rzeczywistości"]}', '1', NULL, '{}', '{"explanation": "Gall interpretuje mesjanizm jako świadomą strategię - ''zawłaszczenie dyskursu hegemonialnego'' (Hegla) i stworzenie kontrdyskursu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010w002fqh7mr8zxe3ao', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Czym różni się polski prometeizm od klasycznego mitu Prometeusza?', '{"options": ["brakiem elementu cierpienia", "buntem przeciw Bogu chrześcijańskiemu, nie pogańskim bogom", "happy endem", "brakiem poświęcenia dla ludzkości"]}', '1', NULL, '{}', '{"explanation": "Prometeusz buntował się przeciw Zeusowi (bóg pogański), Konrad - przeciw Bogu chrześcijańskiemu, co czyni bunt bardziej radykalnym i bluźnierczym."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010w002gqh7mngv31hfb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jaką funkcję pełni omdlenie Konrada w strukturze dramatu?', '{"options": ["tylko dramaturgiczną (napięcie)", "chroni bohatera przed wypowiedzeniem pełnego bluźnierstwa", "symbolizuje śmierć", "pokazuje słabość fizyczną"]}', '1', NULL, '{}', '{"explanation": "Omdlenie można interpretować jako interwencję Opatrzności lub wewnętrzny hamulec - chroni Konrada przed potępieniem."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010w002hqh7mwzr27rzh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Na czym polega ambiwalencja żądania ''rządu dusz'' przez Konrada?', '{"options": ["jest zarówno modlitwą, jak i groźbą", "łączy miłość do narodu z pragnieniem despotycznej władzy", "wyraża zarówno wiarę, jak i ateizm", "jest jednocześnie szczere i ironiczne"]}', '1', NULL, '{}', '{"explanation": "Konrad chce władzy z miłości, ale samo pragnienie absolutnej władzy nad duszami ma rysy despotyzmu - to napięcie jest kluczowe."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010w002iqh7mxdc1g87t', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Co Mickiewicz miał na myśli pisząc w liście o ''wyrzygnięciu dumy''?', '{"options": ["krytykę arystokracji", "oczyszczenie Konrada z pychy przez Improwizację", "odrzucenie filozofii niemieckiej", "pochwałę pokory"]}', '1', NULL, '{}', '{"explanation": "Mickiewicz pisał, że Konrad musiał ''wyrzygnąć dumę'' - Improwizacja jest katharsis, oczyszczeniem z pychy, które umożliwia przemianę."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010w002jqh7mpuvcpnmd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Który element teozofii Boehmego tłumaczy słowa Konrada o ataku ''przeciw naturze'' Boga?', '{"options": ["koncepcja predestynacji", "rozróżnienie Boga (Ungrund) od Jego ''wiecznej natury'' zawierającej ciemne siły", "idea reinkarnacji", "dualizm dobra i zła"]}', '1', NULL, '{}', '{"explanation": "Boehme rozróżniał absolutny Bóg (Ungrund) od ''wiecznej natury'' zawierającej też ciemne siły. Konrad atakuje tę naturę, nie sam Absolut."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010w002kqh7ml174pw91', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Jak Natalia Piórczyńska interpretuje ''lucyferyczny'' charakter buntu Konrada?', '{"options": ["jako satanizm", "jako aspirację do boskości bez odrzucenia Boga", "jako nihilizm", "jako ateizm"]}', '1', NULL, '{}', '{"explanation": "Piórczyńska widzi w buncie Konrada nie szatański nihilizm, lecz lucyferyczną aspirację do boskości - chce być jak Bóg, nie przeciw Bogu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010x002lqh7m7kcpf988', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Co według filozofii Schellinga oznacza, że poeta jest ''organem Absolutu''?', '{"options": ["poeta jest narzędziem władzy", "przez poetę przemawia nieskończoność, tworzy jak Bóg", "poeta służy państwu", "poeta przekazuje tradycję"]}', '1', NULL, '{}', '{"explanation": "U Schellinga sztuka jest ''organem Absolutu'' - przez geniusza artystycznego przemawia nieskończoność, poeta tworzy światy jak demiurg."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010x002mqh7mybnyxmue', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Jak Leibnizowska teodyceja, krytykowana przez Konrada, wyjaśnia istnienie zła?', '{"options": ["zło jest iluzją", "świat jest najlepszy z możliwych, zło jest koniecznym elementem harmonii", "zło pochodzi od diabła", "Bóg nie jest wszechmocny"]}', '1', NULL, '{}', '{"explanation": "Leibniz twierdził, że żyjemy w ''najlepszym z możliwych światów'' - zło jest konieczne dla większego dobra. Konrad odrzuca tę optymistyczną teodycję."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010x002nqh7m4r41x5fg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Jaką rolę w interpretacji postkolonialnej pełni mesjanizm według koncepcji ''appropriation''?', '{"options": ["jest formą kulturowej kapitulacji", "jest zawłaszczeniem dyskursu hegemonicznego i przekształceniem go na własne potrzeby", "jest odrzuceniem kultury zachodniej", "jest imitacją wzorców niemieckich"]}', '1', NULL, '{}', '{"explanation": "Appropriation (zawłaszczenie) polega na przejęciu dyskursu dominującego (heglizmu) i przekształceniu go - mesjanizm używa kategorii Hegla przeciwko niemu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010x002oqh7mxowitmjj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Co oznacza ''chytrość rozumu'' (List der Vernunft) w filozofii Hegla i jak mesjanizm ją odwraca?', '{"options": ["rozum manipuluje jednostkami dla postępu; mesjanizm czyni Polskę podmiotem, nie narzędziem", "rozum jest zły; mesjanizm gloryfikuje uczucie", "rozum jest ukryty; mesjanizm go ujawnia", "rozum jest boski; mesjanizm go sekularyzuje"]}', '0', NULL, '{}', '{"explanation": "U Hegla ''chytry rozum'' używa narodów jako narzędzi postępu. Mesjanizm odwraca: Polska nie jest narzędziem, lecz podmiotem zbawienia."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010x002pqh7m4n6v7a8z', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Jakie znaczenie ma fakt, że Wielka Improwizacja jest TRZECIĄ improwizacją Konrada w dramacie?', '{"options": ["symbolizuje Trójcę Świętą", "pokazuje narastanie natchnienia - od pieśni przez hymn do konfrontacji z Bogiem", "nawiązuje do trzech zaborców", "jest przypadkowe"]}', '1', NULL, '{}', '{"explanation": "Zofia Stefanowska analizowała sekwencję trzech improwizacji jako narastanie natchnienia - kulminację stanowi trzecia, najdłuższa."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010x002qqh7m5e1mdifg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Co według Ryszarda Przybylskiego oznacza ''milczenie'' Boga w Wielkiej Improwizacji?', '{"options": ["nieistnienie Boga", "potwierdzenie oskarżeń Konrada (Bóg nie ma kontrargumentów)", "próbę cierpliwości", "element dramaturgiczny"]}', '1', NULL, '{}', '{"explanation": "Przybylski interpretował milczenie Boga jako potwierdzenie zarzutów - skoro Bóg nie odpowiada, może nie ma czym się bronić."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010y002rqh7m0sfwriwo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 4, 'Jak koncepcja ''siedmiu duchów źródłowych'' Boehmego może tłumaczyć strukturę sił w Wielkiej Improwizacji?', '{"options": ["siedem duchów to siedem grzechów głównych", "siły Boga i Konrada mają wspólne kosmiczne źródło w przedwiecznej naturze", "siedem duchów to anioły strzegące Konrada", "odnosi się do siedmiu scen dramatu"]}', '1', NULL, '{}', '{"explanation": "Boehme mówił o ''siedmiu duchach źródłowych'' jako siłach kosmicznych. Konrad powołuje się na wspólne źródło sił - jego i Boga."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010y002sqh7mxsrl9lge', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 4, 'Jaką funkcję pełni autocenzura Mickiewicza (niedopowiedzenie bluźnierstwa) według współczesnych interpretacji?', '{"options": ["tylko uniknięcie cenzury carskiej", "utrzymanie ambiwalencji tekstu i ochrona przed jednoznacznym potępieniem bohatera", "brak odwagi artystycznej", "względy religijne autora"]}', '1', NULL, '{}', '{"explanation": "Kwiryna Ziemba i inni badacze widzą w niedopowiedzeniu świadomą strategię - ambiwalencja chroni tekst i bohatera przed jednoznaczną oceną."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010y002tqh7mzpcq1oey', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 4, 'Jak wiersze z rękopisów III cz. Dziadów (''Do Samotności'', ''Te rozkwitłe świeżo drzewa...'') oświetlają genezę Wielkiej Improwizacji?', '{"options": ["nie mają związku z Improwizacją", "pokazują rozpad podmiotowości i mechanizmy obronne, które kulminują w ''Nazywam się Milion''", "są tylko ćwiczeniami stylistycznymi", "przedstawiają innego bohatera"]}', '1', NULL, '{}', '{"explanation": "Kwiryna Ziemba analizowała te liryki jako świadectwo kryzysu podmiotowości Mickiewicza - Improwizacja to próba jej rekonstrukcji przez utożsamienie ze zbiorowością."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010y002uqh7m9io2md56', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 4, 'Na czym polega ''paradoks polskiej mentalności postkolonialnej'' według Marii Janion?', '{"options": ["Polacy są jednocześnie kolonizatorami i kolonizowanymi", "poczucie niższości wobec Zachodu kompensowane mesjanistyczną dumą i poczuciem wyższości moralnej", "Polacy naśladują kolonizatorów", "mesjanizm jest formą kolonizacji wewnętrznej"]}', '1', NULL, '{}', '{"explanation": "Janion opisuje ''zamknięte koło niższości i wyższości'' - poczucie peryferyjności kompensowane przekonaniem o moralnej wyższości nad ''zepsutym'' Zachodem."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010y002vqh7mfxn2ujol', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 4, 'Jak rozumieć twierdzenie, że mesjanizm Mickiewicza to ''historiozofia podporządkowanych''?', '{"options": ["jest filozofią dla mas niewykształconych", "jest kontrnarracją tożsamościową wobec dominującego dyskursu (Hegla), przekształcającą słabość w siłę", "podporządkowuje się filozofii niemieckiej", "jest wyrazem religijnego fatalizmu"]}', '1', NULL, '{}', '{"explanation": "Mesjanizm to historiozofia narodu wykluczonego z ''dziejów'' przez Hegla - przekształca marginalizację w wybraństwo, słabość w moc zbawczą."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010y002wqh7mvc6ttk3t', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Które elementy filozofii Boehmego są obecne w Wielkiej Improwizacji?', '{"options": ["koncepcja wspólnego źródła sił Boga i człowieka", "rozróżnienie Boga od Jego ''natury''", "idea reinkarnacji", "siedem duchów źródłowych", "predestynacja kalwińska"]}', '[0, 1, 3]', NULL, '{}', '{"explanation": "Boehme wpływa przez: wspólne źródło sił, rozróżnienie Bóg/natura, siedem duchów. Reinkarnacja i predestynacja to inne tradycje."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010z002xqh7mz9o1xp0b', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Które interpretacje Wielkiej Improwizacji pojawiają się w tradycji badawczej?', '{"options": ["romantyczno-patriotyczna (szlachetny bunt)", "religijna (grzech pychy wymagający nawrócenia)", "marksistowska (walka klas)", "psychoanalityczna (mechanizmy obronne)", "postkolonialna (kontrdyskurs)"]}', '[0, 1, 3, 4]', NULL, '{}', '{"explanation": "Główne nurty: romantyczny, religijny, psychoanalityczny (Janion), postkolonialny (Gall). Interpretacja marksistowska nie jest typowa dla tego tekstu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010z002yqh7mbx1486qo', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Dopasuj badacza do głównej tezy interpretacyjnej.', '{"leftColumn": [{"id": "A", "text": "Wiktor Weintraub"}, {"id": "B", "text": "Zofia Stefanowska"}, {"id": "C", "text": "Alfred Gall"}], "rightColumn": [{"id": 1, "text": "''romantyczny tytanizm'' - bunt przeciw Bogu chrześcijańskiemu"}, {"id": 2, "text": "figuralna interpretacja mesjanizmu"}, {"id": 3, "text": "mesjanizm jako postkolonialny kontrdyskurs"}], "matchingType": "scholar_thesis"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{}', '{"explanation": "Weintraub - tytanizm, Stefanowska - figura, Gall - postkolonializm."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010z002zqh7m5zot6xyj', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Które cechy wyróżniają polski prometeizm od zachodnioeuropejskiego (Byron, Shelley)?', '{"options": ["bunt przeciw Bogu chrześcijańskiemu (nie pogańskim bogom)", "kontekst narodowy (cierpienie narodu, nie jednostki)", "połączenie z mesjanizmem", "całkowite odrzucenie wiary", "wyraźniejsza ambiwalencja (bohater może być ocalony)"]}', '[0, 1, 2, 4]', NULL, '{}', '{"explanation": "Polski prometeizm: chrześcijański kontekst, wymiar narodowy, związek z mesjanizmem, ambiwalencja. NIE całkowite odrzucenie wiary."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010z0030qh7mtstm0cmz', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Uzupełnij analizę problemu teodycei w Wielkiej Improwizacji.', '{"gaps": [{"id": 1, "options": ["istnienia Boga", "pogodzenia dobrego Boga z istnieniem zła", "wolnej woli", "nieśmiertelności"]}, {"id": 2, "options": ["Augustyna", "Leibniza", "Tomasza z Akwinu", "Kalwina"]}, {"id": 3, "options": ["nieistnienie", "mądrość bez miłości", "słabość", "okrucieństwo"]}, {"id": 4, "options": ["zgodę", "brak kontrargumentów", "gniew", "wybaczenie"]}], "textWithGaps": "Teodyceja to problem [1]. Konrad odrzuca optymistyczną teodycję [2], zarzucając Bogu [3]. Milczenie Boga może oznaczać [4]."}', '[1, 1, 1, 1]', NULL, '{}', '{"explanation": "Teodyceja = problem zła, Leibniz = ''najlepszy ze światów'', zarzut = mądrość bez miłości, milczenie = brak obrony."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip010z0031qh7myq4j7cqv', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Które funkcje pełniła idea mesjanistyczna dla polskiej emigracji po 1831 roku?', '{"options": ["nadawanie sensu cierpieniu", "mobilizacja polityczna", "zachowanie nadziei w beznadziejnej sytuacji", "budowanie sojuszy z zaborcami", "tworzenie tożsamości zbiorowej na emigracji"]}', '[0, 1, 2, 4]', NULL, '{}', '{"explanation": "Mesjanizm: sens cierpienia, mobilizacja, nadzieja, tożsamość emigracyjna. NIE sojusze z zaborcami - wręcz przeciwnie."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip01100032qh7ms770flmv', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 4, 'Dopasuj koncepcję filozoficzną do jej manifestacji w Wielkiej Improwizacji.', '{"leftColumn": [{"id": "A", "text": "poeta jako demiurg (Schelling)"}, {"id": "B", "text": "wspólne źródło sił (Boehme)"}, {"id": "C", "text": "problem teodycei (Leibniz/Hiob)"}], "rightColumn": [{"id": 1, "text": "''Cóż Ty większego mogłeś zrobić - Boże?''"}, {"id": 2, "text": "''Stamtąd przyszły siły moje, skąd do Ciebie przyszły Twoje''"}, {"id": 3, "text": "''Ty mądrość, ja miłość mam''"}], "matchingType": "philosophy_manifestation"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{}', '{"explanation": "Demiurg = ''cóż większego'', wspólne źródło = ''stamtąd przyszły'', teodyceja = ''mądrość bez miłości''."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip01100033qh7m1f7ftvyu', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 4, 'Które elementy wskazują na ''lucyferyczny'' (nie szatański) charakter buntu Konrada?', '{"options": ["aspiracja do boskości, nie niszczenia", "miłość jako motywacja, nie nienawiść", "pragnienie władzy dla dobra, nie zła", "całkowite odrzucenie Boga", "możliwość ocalenia i nawrócenia"]}', '[0, 1, 2, 4]', NULL, '{}', '{"explanation": "Lucyferyzm: aspiracja do boskości, miłość, dobro jako cel, możliwość ocalenia. NIE całkowite odrzucenie - Konrad zwraca się DO Boga."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip01100034qh7m9mv74lhs', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 5, 'Uzupełnij analizę perspektywy postkolonialnej na mesjanizm.', '{"gaps": [{"id": 1, "options": ["imitacją", "kontrdyskursem", "kontynuacją", "odrzuceniem"]}, {"id": 2, "options": ["języka", "armii", "pieniędzy", "religii"]}, {"id": 3, "options": ["odwrócenie hierarchii (polska dominacja)", "pokój", "rewolucja", "izolacja"]}, {"id": 4, "options": ["polskiej", "uniwersalnej", "niemieckiej", "słowiańskiej"]}], "textWithGaps": "Według Galla mesjanizm jest [1] wobec filozofii Hegla. Mickiewicz używa [2] hegemonii, by ją przezwyciężyć. Celem nie jest [3], lecz stworzenie [4] koncepcji europejskiej."}', '[1, 0, 0, 1]', NULL, '{}', '{"explanation": "Mesjanizm = kontrdyskurs, używa języka hegemonii, cel nie jest dominacja, lecz uniwersalna koncepcja."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip01100035qh7m7xo061jk', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 4, 'Które zagrożenia związane z mesjanizmem identyfikowali krytycy (Norwid, Janion)?', '{"options": ["megalomanii narodowa", "gloryfikacja cierpienia prowadząca do bierności", "zatracenie indywidualności w zbiorowości", "wzmocnienie więzi społecznych", "manichejski podział świata na ''świętych'' i ''sługusów szatana''"]}', '[0, 1, 2, 4]', NULL, '{}', '{"explanation": "Zagrożenia: megalomania, cierpiętnictwo, zatracenie ''ja'', manichejski podział. Wzmocnienie więzi to pozytyw, nie zagrożenie."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip01110036qh7mqemzrvqz', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 4, 'Dopasuj fazę Wielkiej Improwizacji do dominującego problemu filozoficznego.', '{"leftColumn": [{"id": "A", "text": "Samotność artysty (język kłamie głosowi)"}, {"id": "B", "text": "Poetycka wszechmoc (pieśń za granicą świata)"}, {"id": "C", "text": "Konfrontacja z Bogiem (mądrość bez miłości)"}], "rightColumn": [{"id": 1, "text": "problem niewyrażalności (romantyczna epistemologia)"}, {"id": 2, "text": "poeta jako demiurg (Schelling)"}, {"id": 3, "text": "problem teodycei (Leibniz, Hiob)"}], "matchingType": "phase_philosophy"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{}', '{"explanation": "Faza I = niewyrażalność, faza II = demiurg, faza IV = teodyceja."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip01110037qh7muxyyj666', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 5, 'Uzupełnij zaawansowaną analizę teozoficznego tła Wielkiej Improwizacji.', '{"gaps": [{"id": 1, "options": ["Logos", "Ungrund", "Pleroma", "Demiurg"]}, {"id": 2, "options": ["tylko dobro", "tylko zło", "zarówno jasne, jak i ciemne siły", "materię"]}, {"id": 3, "options": ["Jego naturę", "Jego istnienie", "Jego wieczność", "Jego stworzenie"]}, {"id": 4, "options": ["przeznaczenie", "źródło/pochodzenie", "zakończenie", "stworzenie"]}], "textWithGaps": "W teozofii Boehmego [1] (Bezdeń) to pierwotna otchłań poprzedzająca rozróżnienie. Z niej wyłania się ''wieczna natura'' zawierająca [2]. Konrad atakuje nie samego Boga, lecz [3]. Powołuje się na wspólne [4] swoich i boskich sił."}', '[1, 2, 0, 1]', NULL, '{}', '{"explanation": "Ungrund = Bezdeń, natura zawiera jasne i ciemne siły, Konrad atakuje naturę, powołuje się na wspólne źródło."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip01110038qh7m7wjrtge4', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 5, 'Które elementy wskazują na ''ambiwalencję'' Dziadów cz. III jako świadomą strategię artystyczną?', '{"options": ["niedokończone bluźnierstwo (autocenzura chroniąca bohatera)", "zestawienie prometeizmu Konrada z mesjanizmem księdza Piotra bez jednoznacznego rozstrzygnięcia", "możliwość interpretacji omdlenia jako interwencji lub wewnętrznego hamulca", "jednoznaczne potępienie Konrada przez narratora", "otwartość proroctwa ''44'' na różne interpretacje"]}', '[0, 1, 2, 4]', NULL, '{}', '{"explanation": "Ambiwalencja: niedokończenie, zestawienie postaw, wieloznaczność omdlenia, otwartość proroctwa. NIE ma jednoznacznego potępienia."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip01110039qh7mu1swoqyg', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 5, 'Dopasuj typ interpretacji mesjanizmu do jej kluczowej kategorii.', '{"leftColumn": [{"id": "A", "text": "interpretacja hermeneutyczna (Stefanowska)"}, {"id": "B", "text": "interpretacja psychoanalityczna (Janion)"}, {"id": "C", "text": "interpretacja postkolonialna (Gall)"}], "rightColumn": [{"id": 1, "text": "figura (realność historyczna przedstawia inną realność)"}, {"id": 2, "text": "trauma, kompleks, kompensacja"}, {"id": 3, "text": "appropriation, kontrdyskurs, hegemonia"}], "matchingType": "interpretation_category"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{}', '{"explanation": "Stefanowska = figura (Auerbach), Janion = psychoanaliza (trauma), Gall = postkolonializm (kontrdyskurs)."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0111003aqh7mp9sxpf4y', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Wyjaśnij, dlaczego Konrad atakuje ''naturę'' Boga, a nie samego Boga. Odwołaj się do teozofii Boehmego.', '{"hint": "Rozróżnienie Bóg (Ungrund) a ''wieczna natura''"}', NULL, NULL, '{}', '{"keyPoints": ["Ungrund/Bezdeń", "wieczna natura", "jasne i ciemne siły", "atak na naturę, nie na Absolut"], "sampleAnswer": "W teozofii Jakuba Boehmego Bóg jako Ungrund (Bezdeń) to absolutna, niepojęta otchłań poprzedzająca wszelkie rozróżnienia. Z niej wyłania się ''wieczna natura'' Boga, która zawiera zarówno jasne, jak i ciemne siły. Konrad, mówiąc ''Strzelę przeciw Twej naturze'', nie atakuje absolutnego Boga, lecz tę ''naturę'' - aspekt bóstwa odpowiedzialny za porządek świata, w tym za cierpienie. To subtelne rozróżnienie pozwala na bunt bez pełnego bluźnierstwa przeciw Absolutowi."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0112003bqh7mti2asy5g', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Co oznaczają słowa Konrada ''Stamtąd przyszły siły moje, skąd do Ciebie przyszły Twoje'' i jakie mają źródło filozoficzne?', '{"hint": "Wspólne pochodzenie sił Boga i człowieka"}', NULL, NULL, '{}', '{"keyPoints": ["Boehme", "wspólne źródło", "uzasadnienie roszczeń", "równość pochodzenia"], "sampleAnswer": "Słowa te nawiązują do teozofii Boehmego, według której siły Boga i człowieka mają wspólne źródło w pierwotnej otchłani (Ungrund). Konrad powołuje się na tę wspólnotę pochodzenia, by uzasadnić swoje roszczenia - skoro jego siły (poetyckie, duchowe) pochodzą z tego samego kosmicznego źródła co siły Boga, ma prawo żądać od Boga odpowiedzi, a nawet równać się z Nim. To filozoficzne uzasadnienie prometejskiego buntu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0112003cqh7mz3xf37zj', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Wyjaśnij, czym jest ''teodyceja'' i jak Konrad polemizuje z jej klasycznymi rozwiązaniami.', '{"hint": "Problem pogodzenia dobrego Boga z istnieniem zła"}', NULL, NULL, '{}', '{"keyPoints": ["problem zła", "Leibniz", "najlepszy ze światów", "odrzucenie optymizmu", "mądrość bez miłości"], "sampleAnswer": "Teodyceja to filozoficzny problem pogodzenia istnienia wszechmocnego i dobrego Boga z istnieniem zła i cierpienia w świecie. Klasyczne rozwiązanie Leibniza głosiło, że świat jest ''najlepszy z możliwych'' - zło jest konieczne dla większej harmonii. Konrad odrzuca tę optymistyczną teodycję: cierpienie niewinnych Polaków nie służy żadnemu ''większemu dobru''. Zarzuca Bogu ''mądrość bez miłości'' - Bóg wie o cierpieniu, ale nie interweniuje, co Konrad uznaje za moralnie niedopuszczalne."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0112003dqh7m8itwdwwe', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Co oznacza termin ''romantyczny tytanizm'' Wiktora Weintrauba i jak odnosi się do Wielkiej Improwizacji?', '{"hint": "Specyfika polskiego prometeizmu"}', NULL, NULL, '{}', '{"keyPoints": ["bunt przeciw Bogu chrześcijańskiemu", "radykalniejszy niż mit antyczny", "gigantyczne roszczenia", "Weintraub"], "sampleAnswer": "Wiktor Weintraub ukuł termin ''romantyczny tytanizm'' dla opisu specyfiki polskiego prometeizmu. W odróżnieniu od klasycznego mitu, gdzie Prometeusz buntuje się przeciw pogańskim bogom (Zeusowi), Konrad buntuje się przeciw Bogu chrześcijańskiemu - jedynemu, wszechmocnemu, moralnemu. To czyni bunt radykalniejszym i bardziej bluźnierczym. Tytanizm oznacza także gigantyczne roszczenia: Konrad chce być równy Bogu, nie tylko Go oskarżać."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0112003eqh7mifz84fer', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Jak Maria Janion interpretowała mesjanizm przez pryzmat psychoanalizy?', '{"hint": "Trauma, kompleks, kompensacja"}', NULL, NULL, '{}', '{"keyPoints": ["trauma historyczna", "kompleks winy", "kompensacja niższości", "mechanizm obronny"], "sampleAnswer": "Maria Janion stosowała do mesjanizmu kategorie psychoanalityczne: trauma, kompleks, kompensacja. Mesjanizm był odpowiedzią na traumę rozbiorów i klęsk powstań - próbą ''przezwyciężenia narodowego kompleksu winy''. Poczucie niższości wobec Zachodu (skolonizowani, peryferyjni) kompensowane było przekonaniem o wyższości moralnej i szczególnej misji. Mesjanizm przekształcał słabość w siłę, porażkę w wybraństwo - mechanizm obronny zbiorowej psychiki."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0112003fqh7mnuncvy8w', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Wyjaśnij, czym jest ''figura'' w interpretacji Zofii Stefanowskiej i jak stosuje się do mesjanizmu.', '{"hint": "Sposób przedstawiania jednej realności przez drugą"}', NULL, NULL, '{}', '{"keyPoints": ["Auerbach", "dwie realności historyczne", "zapowiedź i wypełnienie", "nie alegoria"], "sampleAnswer": "Zofia Stefanowska przejęła od Ericha Auerbacha pojęcie ''figury'' - sposobu przedstawiania jednej rzeczy przez drugą, gdzie OBA człony są realnościami historycznymi. Pierwsze wydarzenie ''zapowiada'' drugie, drugie ''wypełnia'' pierwsze. W mesjanizmie męka Chrystusa jest figurą cierpienia Polski: obie rzeczywistości są historyczne, Chrystus zapowiada Polskę, Polska wypełnia schemat chrystologiczny. To nie alegoria (gdzie znaczenie jest abstrakcyjne), lecz związek dwóch konkretnych historii."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0112003gqh7ma8fsurmk', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 5, 'Jak Alfred Gall interpretuje mesjanizm w perspektywie postkolonialnej? Wyjaśnij pojęcie ''kontrdyskursu'' i ''appropriation''.', '{"hint": "Zawłaszczenie dyskursu hegemonicznego"}', NULL, NULL, '{}', '{"keyPoints": ["kontrdyskurs wobec Hegla", "appropriation - zawłaszczenie", "użycie języka hegemonii", "słabość jako siła", "cel uniwersalny"], "sampleAnswer": "Alfred Gall stosuje do mesjanizmu kategorię postkolonialnego ''kontrdyskursu''. Heglowska filozofia dziejów marginalizowała Słowian jako narody ''pozahistoryczne''. Mesjanizm był świadomą odpowiedzią - ''appropriation'' (zawłaszczeniem) dyskursu hegemonialnego. Mickiewicz używał języka filozofii niemieckiej (kategorie historiozoficzne), by ją przezwyciężyć i wpisać Polskę w dzieje. Słabość przekształcał w siłę, peryferie w centrum. Celem nie było odwrócenie hierarchii (polska dominacja), lecz stworzenie uniwersalnej koncepcji europejskiej."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0113003hqh7mogiowb9c', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 5, 'Jak Kwiryna Ziemba interpretuje utożsamienie Konrada z ''Milionem'' jako mechanizm obronny?', '{"hint": "Rozpad i rekonstrukcja podmiotowości"}', NULL, NULL, '{}', '{"keyPoints": ["kryzys podmiotowości", "trauma emigracji", "mechanizm obronny", "wzmocnienie ja przez zbiorowość", "rozpad i rekonstrukcja"], "sampleAnswer": "Kwiryna Ziemba analizowała wiersze z rękopisów III cz. Dziadów (''Do Samotności'', ''Te rozkwitłe świeżo drzewa...'') jako świadectwo kryzysu podmiotowości Mickiewicza po traumie emigracji. Rozpad indywidualnego ''ja'' prowadzi do mechanizmu obronnego: wzmocnienia podmiotowości przez identyfikację ze zbiorowością. ''Nazywam się Milion'' to nie tylko patriotyczna deklaracja, lecz sposób na rekonstrukcję rozbitego ''ja'' - jednostka słaba staje się silna jako część milionów. To psychologiczna funkcja utożsamienia z narodem."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0113003iqh7mefpnjgz5', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 5, 'Wyjaśnij, dlaczego Heglowska ''chytrość rozumu'' (List der Vernunft) była nie do przyjęcia dla Mickiewicza i jak mesjanizm ją odwraca.', '{"hint": "Narody jako narzędzia vs podmioty dziejów"}', NULL, NULL, '{}', '{"keyPoints": ["chytrość rozumu - narody jako narzędzia", "cierpienie jako konieczność", "odwrócenie: Polska jako podmiot", "świadoma ofiara vs ślepe narzędzie"], "sampleAnswer": "U Hegla ''chytrość rozumu'' oznacza, że duch dziejów używa narodów i jednostek jako narzędzi do realizacji swoich celów - nie są podmiotami, lecz środkami. Cierpienie jest konieczne dla postępu. Dla Mickiewicza było to nie do przyjęcia: narody (Polska) byłyby tylko pionkami, cierpienie - bezsensowną koniecznością. Mesjanizm odwraca ten schemat: Polska nie jest narzędziem, lecz PODMIOTEM zbawienia. Jej cierpienie nie jest instrumentalne, lecz ma własny sens - odkupieńczy. Świadoma ofiara, nie ślepe narzędzie."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0113003jqh7m4j3gdwhk', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 5, 'Na czym polega ''lucyferyczny'' (nie szatański) charakter buntu Konrada według Natalii Piórczyńskiej?', '{"hint": "Aspiracja do boskości vs destrukcja"}', NULL, NULL, '{}', '{"keyPoints": ["lucyferyzm vs satanizm", "aspiracja do boskości", "miłość jako motywacja", "możliwość ocalenia", "pycha, nie nihilizm"], "sampleAnswer": "Natalia Piórczyńska rozróżnia lucyferyzm od satanizmu. Lucyfer to ''niosący światło'', jego bunt wynika z aspiracji do boskości - chce być JAK Bóg, nie PRZECIW Bogu. Konrad nie neguje istnienia Boga, nie chce Go zniszczyć - chce być Mu równy, mieć Jego moc dla dobra narodu. Motywacją jest miłość, nie nienawiść. Aspiruje do demiurgii (tworzenia światów), nie destrukcji. Dlatego możliwe jest jego ocalenie - to pycha niosąca światło (choć błędne), nie ciemność nihilizmu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0113003kqh7mnr3mx5dv', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 5, 'Wyjaśnij paradoks ''polskiej mentalności postkolonialnej'' według Marii Janion.', '{"hint": "Zamknięte koło niższości i wyższości"}', NULL, NULL, '{}', '{"keyPoints": ["skolonizowanie - poczucie niższości", "mesjanizm - poczucie wyższości", "błędne koło", "kompleks vs megalomania"], "sampleAnswer": "Janion opisuje paradoks polskiej mentalności postkolonialnej jako ''zamknięte koło niższości i wyższości''. Z jednej strony doświadczenie skolonizowania (rozbiory, marginalizacja w dyskursie zachodnim) rodzi poczucie niższości, peryferyjności wobec ''Zachodu''. Z drugiej - mesjanizm kompensuje to poczucie przekonaniem o wyższości moralnej: my cierpimy za innych, jesteśmy ''Chrystusem narodów'', Zachód jest ''zepsuty''. To błędne koło uniemożliwia zdrową relację z własną historią i innymi narodami - oscylacja między kompleksem niższości a megalomanią."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0113003lqh7m4dfsaji2', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 6, 'Przeanalizuj funkcję autocenzury (niedokończonego bluźnierstwa) w Wielkiej Improwizacji jako świadomej strategii artystycznej. Jak wpływa ona na interpretację tekstu?', '{"hint": "Ambiwalencja, ochrona bohatera, wieloznaczność"}', NULL, NULL, '{}', '{"keyPoints": ["ambiwalencja", "ochrona bohatera", "wieloznaczność omdlenia", "różne lektury", "autocenzura Mickiewicza"], "sampleAnswer": "Niedokończone bluźnierstwo (''Tyś nie jest ojcem świata, ale...'') to nie tylko element dramaturgiczny, lecz świadoma strategia artystyczna kreująca ambiwalencję tekstu. Po pierwsze, chroni bohatera przed jednoznacznym potępieniem - skoro nie wypowiedział pełnego bluźnierstwa, jego ocalenie jest możliwe. Po drugie, utrzymuje napięcie interpretacyjne: czy omdlenie to interwencja Opatrzności, czy wewnętrzny hamulec Konrada? Po trzecie, umożliwia różne lektury - romantyczną (szlachetny bunt przerwany w ostatniej chwili) i religijną (grzech pychy powstrzymany łaską). Kwiryna Ziemba widzi tu ''autocenzurę'' Mickiewicza - ochronę tekstu i bohatera przed skrajnościami."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0114003mqh7motachtac', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 6, 'Jak wiersze z rękopisów III cz. Dziadów (''Do Samotności'', ''Te rozkwitłe świeżo drzewa...'', ''Ja w mej chacie spać nie mogę...'') oświetlają genezę i funkcję Wielkiej Improwizacji?', '{"hint": "Kryzys podmiotowości, petrarkizm, liryka rosyjska"}', NULL, NULL, '{}', '{"keyPoints": ["kryzys podmiotowości", "rozprzężenie więzi", "petrarkizm i liryka rosyjska", "Milion jako rekonstrukcja ja", "Improwizacja jako terapia"], "sampleAnswer": "Kwiryna Ziemba analizuje te wiersze jako świadectwo głębokiego kryzysu podmiotowości Mickiewicza na emigracji. ''Do Samotności'' pokazuje rozpad więzi ze światem, ''Te rozkwitłe świeżo drzewa...'' nawiązuje do petrarkistycznej tradycji liryki miłosnej (kochanek wśród natury), ''Ja w mej chacie...'' łączy petrarkizm z liryką rosyjską (Puszkin). Mickiewicz szuka form dla wyrażenia rozpadu ''ja''. Wielka Improwizacja jest odpowiedzią na ten kryzys: utożsamienie z ''Milionem'' to mechanizm obronny - rekonstrukcja rozbitej podmiotowości przez identyfikację ze zbiorowością. Improwizacja ''leczy'' podmiotowość przez heroiczne przejęcie cierpienia narodu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0114003nqh7munilp3ay', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 6, 'Porównaj interpretację hermeneutyczną (Stefanowska), psychoanalityczną (Janion) i postkolonialną (Gall) mesjanizmu. Które elementy są wspólne, a które specyficzne dla każdej metody?', '{"hint": "Figura vs trauma vs kontrdyskurs"}', NULL, NULL, '{}', '{"keyPoints": ["figura (hermeneutyka)", "trauma/kompensacja (psychoanaliza)", "kontrdyskurs (postkolonializm)", "wspólne: sens cierpienia", "różne: tekst vs psyche vs władza"], "sampleAnswer": "HERMENEUTYKA (Stefanowska): Mesjanizm to ''figura'' - sposób przedstawiania realności historycznej przez inną. Sekularyzacja Chrystusa służy temu, by mógł być figurą Polski. Główne kategorie: figura, wypełnienie, sens tekstu. PSYCHOANALIZA (Janion): Mesjanizm to kompensacyjna odpowiedź na traumę historyczną. Poczucie niższości kompensowane przekonaniem o wyższości. Kategorie: trauma, kompleks, mechanizm obronny. POSTKOLONIALIZM (Gall): Mesjanizm to kontrdyskurs wobec hegemonii Hegla. Zawłaszczenie języka hegemonii dla własnych celów. Kategorie: appropriation, kontrdyskurs, hegemonia. WSPÓLNE: wszystkie widzą mesjanizm jako odpowiedź na sytuację podporządkowania i próbę nadania sensu cierpieniu. RÓŻNICE: hermeneutyka skupia się na strukturze tekstu, psychoanaliza - na psychice zbiorowej, postkolonializm - na relacjach władzy i dyskursu."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0114003oqh7mxp2b84w3', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 12, 'Przeanalizuj problem teodycei w Wielkiej Improwizacji. Jak Konrad polemizuje z klasycznymi rozwiązaniami tego problemu i czy jego argumentacja jest przekonująca?', '{"hints": ["Teodyceja to problem pogodzenia dobrego Boga z istnieniem zła", "Leibniz: ''najlepszy z możliwych światów''", "Konrad zarzuca: mądrość bez miłości", "Milczenie Boga - różne interpretacje"], "instruction": "Napisz wypracowanie (400-500 słów), w którym:\n- zdefiniujesz problem teodycei\n- przedstawisz klasyczne rozwiązania (Leibniz, Hiob)\n- przeanalizujesz zarzuty Konrada wobec Boga\n- oceń siłę argumentacji Konrada\n- rozważ znaczenie milczenia Boga"}', NULL, NULL, '{}', '{"sampleAnswer": "Teodyceja to filozoficzny problem pogodzenia trzech twierdzeń: Bóg jest wszechmocny, Bóg jest dobry, zło istnieje w świecie. Jeśli Bóg jest wszechmocny i dobry, dlaczego zło istnieje? Klasyczne rozwiązanie Leibniza głosiło, że żyjemy w ''najlepszym z możliwych światów'' - zło jest koniecznym elementem harmonii, służy większemu dobru. Księga Hioba przedstawia inną odpowiedź: Bóg jest ponad ludzkim rozumieniem, Jego plany wykraczają poza naszą pojętność.\n\nKonrad w Wielkiej Improwizacji odrzuca oba rozwiązania. Jego centralny zarzut brzmi: Bóg ma ''mądrość, ale nie ma miłości''. Znaczy to: Bóg wie o cierpieniu Polaków (jest wszechwiedzący), ale nie interweniuje (brak miłości/dobroci). Konrad nie akceptuje argumentu, że cierpienie służy większemu dobru - dla niego cierpienie niewinnych jest po prostu niesprawiedliwe, niezależnie od przyszłych korzyści. ''Miliony'' cierpią teraz, tu i dziś.\n\nArgumentacja Konrada jest emocjonalnie potężna, ale filozoficznie problematyczna. Siła: Konrad mówi z pozycji cierpiącego, nie teoretyka. Jego zarzut jest egzystencjalny, nie akademicki - to krzyk bólu, nie traktat. Przedstawia się jako miłujący bardziej niż Bóg: ''Ja kocham cały naród! Objąłem w ramiona / Wszystkie przeszłe i przyszłe jego pokolenia''.\n\nSłabość: Konrad sam pragnie boskiej władzy (''rząd dusz''), co podważa jego moralną wyższość. Jego ''miłość'' łączy się z pychą i żądzą absolutnej kontroli. Ponadto żąda odpowiedzi, której struktura teologii nie może dać - tajemnica zła pozostaje tajemnicą.\n\nMilczenie Boga jest wieloznaczne. Można je interpretować jako: (1) potwierdzenie oskarżeń - Bóg nie ma kontrargumentów (Przybylski); (2) transcendencję - Bóg jest ponad dialogiem na warunkach człowieka; (3) próbę - jak w Księdze Hioba, milczenie poprzedza objawienie. Mickiewicz zostawia interpretację otwartą.\n\nUważam, że siła Konrada leży nie w logice, lecz w autentyczności. Jego argumentacja nie ''wygrywa'' filozoficznej debaty o teodycei, ale wyraża coś głęboko ludzkiego: odmowę pogodzenia się z cierpieniem w imię abstrakcyjnych uzasadnień."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0114003pqh7mv3kue593', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 12, 'Omów romantyczną koncepcję poety-demiurga w Wielkiej Improwizacji. Jak Konrad realizuje ten ideał i gdzie napotyka jego granice?', '{"hints": ["Schelling: sztuka jako ''organ Absolutu''", "Poeta tworzy światy jak Bóg-stwórca", "Konrad: ''Cóż Ty większego mogłeś zrobić - Boże?''", "Granica: język nie wyraża pełni myśli"], "instruction": "Napisz wypracowanie (400-500 słów), w którym:\n- wyjaśnisz romantyczną koncepcję poety jako demiurga (Schelling)\n- przeanalizujesz, jak Konrad wyraża tę koncepcję\n- wskaż granice i tragizm tej aspiracji\n- odnieś się do problemu niewyrażalności (''język kłamie głosowi'')"}', NULL, NULL, '{}', '{"sampleAnswer": "Romantyczna koncepcja poety-demiurga, rozwinięta przede wszystkim przez Friedricha Schellinga, głosiła, że sztuka jest ''organem Absolutu'' - przez geniusza artystycznego przemawia nieskończoność. Poeta nie naśladuje natury, lecz tworzy własne światy, analogicznie do Boga-Stwórcy. Jest demiurgiem - istotą tworzącą rzeczywistość mocą wyobraźni i słowa.\n\nKonrad w Wielkiej Improwizacji realizuje ten ideał z niespotykaną intensywnością. Już na początku przedstawia się jako twórca absolutny: jego pieśń ''leci w niebiosa'' i dosięga gwiazd. Kluczowe jest pytanie retoryczne: ''Cóż Ty większego mogłeś zrobić - Boże?'' - Konrad zrównuje swoją twórczość z boskim aktem stworzenia. Jego pieśni są jak ''gwiazdy'', jego uczucia ogarniają ''miliony''. W ekstatycznym momencie poeta zdaje się mieć moc demiurgiczną: tworzy światy, wpływa na kosmiczny porządek.\n\nJednak Wielka Improwizacja ukazuje też tragiczne granice tej aspiracji. Pierwsza granica to problem niewyrażalności: ''Język kłamie głosowi, a głos myślom kłamie''. Nawet demiurg nie może w pełni wyrazić tego, co czuje i myśli - słowa są niewystarczające. Pieśń, choć leci ''za granicę świata'', nie może powiedzieć wszystkiego. To tragedia romantycznego poety: ma wizję absolutną, ale narzędzia wyrazu są ograniczone.\n\nDruga granica to różnica między tworzeniem a władaniem. Konrad może tworzyć światy poetyckie, ale nie może realnie zmienić losu narodu. Dlatego żąda ''rządu dusz'' - władzy nad rzeczywistością, nie tylko wyobraźnią. Poezja nie wystarcza. I właśnie tutaj demiurgiczna aspiracja zamienia się w hybris: poeta chce być nie tylko twórcą, ale władcą.\n\nTragizm Konrada polega na tym, że jego geniusz jest realny (tworzy niezwykłą Improwizację), ale bezsilny wobec cierpienia. Poeta może wyrazić ból narodu, ale nie może go usunąć. Może tworzyć światy, ale nie może zbawić tego świata. Wielka Improwizacja jest jednocześnie szczytem i klęską romantycznego ideału poety-demiurga: szczytem - bo pokazuje potęgę słowa; klęską - bo pokazuje jego niewystarczalność."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0114003qqh7mzqn2de8s', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 15, 'Przeanalizuj mesjanizm Mickiewicza jako ''kontrdyskurs'' wobec filozofii Hegla w perspektywie postkolonialnej. Oceń trafność tej interpretacji.', '{"hints": ["Hegel: Słowianie poza historią, ''chytrość rozumu''", "Gall: mesjanizm jako appropriation dyskursu hegemonicznego", "Słabość przekształcona w siłę", "Czy Polska XIX wieku to ''kolonia''?"], "instruction": "Napisz wypracowanie (500-600 słów), w którym:\n- przedstawisz stanowisko Hegla wobec Słowian (narody ''pozahistoryczne'')\n- wyjaśnisz pojęcie kontrdyskursu i appropriation\n- przeanalizujesz, jak mesjanizm odpowiada na heglowską marginalizację\n- oceń zalety i ograniczenia interpretacji postkolonialnej"}', NULL, NULL, '{}', '{"sampleAnswer": "Heglowska filozofia dziejów stanowiła w XIX wieku dominujący dyskurs historiozoficzny Europy. Według Hegla, dzieje są procesem samorealizacji ducha przez kolejne ''narody historyczne''. ''Chytrość rozumu'' używa narodów jako narzędzi postępu - gdy wypełnią swoją misję, znikają z areny dziejów. Kluczowe: Słowianie dla Hegla byli narodami ''pozahistorycznymi'' - nierozwiniętymi, niezdolnymi do samowiedzy, pozostającymi poza historią. Ta diagnoza sankcjonowała ich marginalizację i dominację Prus.\n\nAlfred Gall interpretuje mesjanizm Mickiewicza jako postkolonialny ''kontrdyskurs'' wobec tej hegemonii. Postkolonializm bada relacje władzy i dominacji kulturowej. Kluczowym mechanizmem jest ''appropriation'' (zawłaszczenie) - przejęcie dyskursu dominującego i przekształcenie go na własne potrzeby. Sam Mickiewicz pisał, że musi ''przejmować od Zachodu jego język filozoficzny, aby powszechną myśl słowiańską nawiązać do europejskiej''.\n\nJak mesjanizm realizuje appropriation? Po pierwsze, zachowuje heglowski schemat historiozoficzny (dzieje mają sens, narody pełnią role), ale zmienia wnioski: Polska nie jest poza historią - jest jej CENTRUM jako Chrystus narodów. Po drugie, odwraca wartościowanie: słabość (rozbiory, cierpienie) staje się siłą (misja odkupieńcza), peryferie - centrum. Po trzecie, używa kategorii Hegla (duch dziejów) przeciwko niemu - ''Bóg polityczny'' Hegla jest krytykowany jako pruski ideolog. Mesjanizm nie odrzuca heglowskiego języka - zawłaszcza go i przekierowuje.\n\nOcena tej interpretacji wymaga rozważenia jej zalet i ograniczeń. ZALETY: (1) pokazuje mesjanizm jako świadomą strategię, nie tylko kompensacyjną fantazję; (2) łączy literaturę z kontekstem polityczno-dyskursywnym; (3) wyjaśnia, dlaczego Mickiewicz używał kategorii filozofii niemieckiej; (4) unika redukcji do nacjonalizmu czy psychopatologii.\n\nOGRANICZENIA: (1) czy Polska XIX wieku to ''kolonia'' w sensie postkolonialnym? Sytuacja rozbiorów różni się od kolonizacji zamorskiej; (2) czy mesjanizm był tak świadomą strategią, czy raczej wyrazem głębokiej wiary?; (3) interpretacja postkolonialna może zaniedbywać wymiar religijny i egzystencjalny; (4) czy Mickiewicz rzeczywiście znał Hegla wystarczająco, by ''polemizować''?\n\nUważam, że interpretacja Galla jest cenna jako JEDEN z kluczy do mesjanizmu, ale nie jedyny. Pokazuje wymiar dyskursywny i polityczny, którego inne interpretacje (hermeneutyczna, psychoanalityczna) nie wydobywają. Jednocześnie nie wyczerpuje bogactwa tekstu. Mesjanizm był prawdopodobnie zarówno strategią, jak i wiarą, zarówno kontrdyskursem, jak i autentycznym wyrazem cierpienia. Wielość interpretacji odpowiada wielowarstwowości dzieła."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0114003rqh7msjmaxpb0', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 15, 'Przeanalizuj funkcję ''ambiwalencji'' w Dziadach cz. III jako świadomej strategii artystycznej Mickiewicza. Jak niedopowiedzenia i wieloznaczności wpływają na interpretację dzieła?', '{"hints": ["Niedokończone bluźnierstwo: ''Tyś nie jest ojcem świata, ale...''", "Omdlenie: interwencja czy wewnętrzny hamulec?", "Proroctwo ''44'': nigdy niewyjaśnione", "Kwiryna Ziemba: ''autocenzura'' Mickiewicza"], "instruction": "Napisz wypracowanie (500-600 słów), w którym:\n- zdefiniujesz ambiwalencję w kontekście literackim\n- przeanalizujesz kluczowe miejsca niedopowiedzień (bluźnierstwo, omdlenie, proroctwo ''44'')\n- rozważ funkcje ambiwalencji: ochrona bohatera, wielość lektur, napięcie interpretacyjne\n- oceń, czy ambiwalencja wzmacnia czy osłabia przesłanie dzieła"}', NULL, NULL, '{}', '{"sampleAnswer": "Ambiwalencja w literaturze oznacza celową wieloznaczność, która uniemożliwia jednoznaczną interpretację. Dzieło ambiwalentne zawiera napięcia, sprzeczności i niedopowiedzenia, które otwierają pole dla różnych lektur. W Dziadach cz. III Mickiewicz stosuje ambiwalencję jako świadomą strategię artystyczną, której funkcje wykraczają poza efekt estetyczny.\n\nKluczowym miejscem ambiwalencji jest niedokończone bluźnierstwo: ''Tyś nie jest ojcem świata, ale...'' Konrad mdleje, słowo ''car'' dokańcza diabeł. Ta konstrukcja jest wieloznaczna: (1) Czy Konrad SAM wypowiedział bluźnierstwo (bo chciał powiedzieć ''car'')? (2) Czy omdlenie to interwencja Opatrzności chroniąca go przed potępieniem? (3) Czy to wewnętrzny hamulec - sumienie lub strach? Każda odpowiedź prowadzi do innej interpretacji: bohater jako bluźnierca, jako chroniony łaską, jako rozdarta dusza. Mickiewicz nie rozstrzyga.\n\nDrugie miejsce ambiwalencji to samo omdlenie. Czy jest fizyczne (wyczerpanie), duchowe (interwencja), psychologiczne (mechanizm obronny)? Różne interpretacje prowadzą do różnych ocen Konrada. Kwiryna Ziemba mówi o ''autocenzurze'' Mickiewicza - poecie świadomie chroniącym bohatera (i siebie) przed skrajnością.\n\nTrzecie miejsce to proroctwo ''44''. Mickiewicz nigdy go nie wyjaśnił, choć był pytany wielokrotnie. To milczenie jest znaczące: proroctwo MUSI pozostać otwarte, by zachować moc. Gdyby Mickiewicz wskazał konkretną osobę, proroctwo mogłoby być sfalsyfikowane. Otwartość utrzymuje nadzieję i gotowość.\n\nFunkcje ambiwalencji są wielorakie. Po pierwsze, OCHRONA BOHATERA: dzięki niedopowiedzeniu Konrad może być ocalony - nie wypowiedział pełnego bluźnierstwa, więc może przejść pokutę i przemianę. Po drugie, WIELOŚĆ LEKTUR: romantyczny czytelnik widzi szlachetny bunt przerwany w ostatniej chwili; katolicki - grzech pychy powstrzymany łaską. Obie lektury są uprawnione. Po trzecie, NAPIĘCIE INTERPRETACYJNE: dzieło pozostaje żywe, prowokuje do ciągłych reinterpretacji przez niemal 200 lat.\n\nCzy ambiwalencja wzmacnia czy osłabia przesłanie? Pozornie osłabia - brak jasnej ''tezy''. Jednak głębiej: wzmacnia, bo przesłanie Dziadów nie jest prostą doktryną, lecz dramatem duszy. Konrad nie jest wzorem do naśladowania ani antywzorem - jest pytaniem. Mesjanizm nie jest katechizmem, lecz dramatycznym poszukiwaniem sensu. Ambiwalencja odpowiada złożoności ludzkiego doświadczenia: bunt Konrada jest jednocześnie szlachetny i grzeszny, pyszny i miłujący. To właśnie ta złożoność czyni Dziady arcydziełem, nie prostym traktatem ideologicznym."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0115003sqh7mooqo7ii3', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 20, 'Porównaj trzy główne paradygmaty interpretacyjne mesjanizmu Mickiewicza: hermeneutyczny (Stefanowska), psychoanalityczny (Janion) i postkolonialny (Gall). Oceń ich komplementarność i ograniczenia oraz zaproponuj syntezę.', '{"hints": ["Stefanowska: figura, wypełnienie, instrumentalne użycie religii", "Janion: trauma, kompleks, kompensacja, mentalność postkolonialna", "Gall: kontrdyskurs, appropriation, hegemonia Hegla", "Czy paradygmaty są komplementarne, czy wykluczające?"], "instruction": "Napisz rozprawkę (600-800 słów), w której:\n- przedstawisz kluczowe kategorie każdego paradygmatu\n- przeanalizujesz, co każdy paradygmat wydobywa, a co pomija\n- rozważ możliwości syntezy i konflikty między paradygmatami\n- oceń, który paradygmat wydaje Ci się najadekwatniejszy i dlaczego"}', NULL, NULL, '{}', '{"sampleAnswer": "Mesjanizm Mickiewicza był od momentu publikacji przedmiotem intensywnych interpretacji. W XX i XXI wieku wykrystalizowały się trzy główne paradygmaty badawcze: hermeneutyczny (Zofia Stefanowska), psychoanalityczny (Maria Janion) i postkolonialny (Alfred Gall). Każdy z nich operuje odmiennymi kategoriami i wydobywa inne aspekty fenomenu.\n\nPARADYGMAT HERMENEUTYCZNY Stefanowskiej koncentruje się na strukturze tekstu i jego relacji do tradycji. Kluczową kategorią jest ''figura'' (za Auerbachem) - sposób przedstawiania jednej realności historycznej przez drugą. Męka Chrystusa jest figurą cierpienia Polski - obie rzeczywistości są historyczne, pierwsza zapowiada drugą, druga ''wypełnia'' pierwszą. Stefanowska podkreśla instrumentalne użycie religii: Księgi i Dziady to ''broszura patriotyczna'', sekularyzacja Chrystusa służy temu, by mógł być figurą Polski. Hermeneutyka WYDOBYWA: strukturę tekstu, relacje intertekstualne, kontekst biblijny i teologiczny. POMIJA: psychologię zbiorową, relacje władzy, wymiar traumatyczny.\n\nPARADYGMAT PSYCHOANALITYCZNY Janion stosuje kategorie psychoanalizy do kultury narodowej. Mesjanizm jest odpowiedzią na traumę (rozbiory, klęski powstań), próbą przezwyciężenia ''kompleksu winy'' i poczucia niższości. Centralne pojęcie to ''kompensacja'': poczucie marginalizacji wobec Zachodu kompensowane przekonaniem o wyższości moralnej. Janion opisuje ''paradoks polskiej mentalności postkolonialnej'' - zamknięte koło niższości i wyższości. Psychoanaliza WYDOBYWA: funkcję psychologiczną mesjanizmu, mechanizmy obronne zbiorowej psychiki, związki między traumą a ideologią. POMIJA: autonomię tekstu literackiego, kontekst filozoficzny, świadomy wymiar strategiczny.\n\nPARADYGMAT POSTKOLONIALNY Galla traktuje mesjanizm jako świadomą strategię emancypacyjną. Kategorie to ''kontrdyskurs'' (odpowiedź na hegemońską filozofię Hegla), ''appropriation'' (zawłaszczenie języka hegemonii i przekształcenie go). Mickiewicz używał kategorii filozofii niemieckiej, by przezwyciężyć marginalizację Słowian. Postkolonializm WYDOBYWA: wymiar polityczny i dyskursywny, świadomy charakter strategii, relacje władzy kulturowej. POMIJA: wymiar religijny i egzystencjalny, specyfikę sytuacji polskiej (czy to rzeczywiście ''kolonializm''?), psychologię jednostkową.\n\nCZY PARADYGMATY SĄ KOMPLEMENTARNE? W znacznej mierze tak. Hermeneutyka analizuje JAK tekst jest zbudowany, psychoanaliza - CZEMU służy psychologicznie, postkolonializm - W JAKIM KONTEKŚCIE władzy powstaje. Można je łączyć: tekst (Stefanowska) odpowiada na traumę (Janion) i jest kontrdyskursem (Gall). Jednak istnieją napięcia: psychoanaliza sugeruje nieświadome mechanizmy, postkolonializm - świadomą strategię. Hermeneutyka koncentruje się na tekście, pozostałe wychodzą poza niego.\n\nPROPOZYCJA SYNTEZY: Mesjanizm był jednocześnie świadomą strategią dyskursywną (Gall) i nieświadomą odpowiedzią na traumę (Janion), wyrażoną w wyrafinowanej formie literackiej (Stefanowska). Nie trzeba wybierać - ludzie mogą być jednocześnie strategami i ofiarami traumy, świadomymi retorami i nieświadomymi kompensatorami.\n\nMOJA OCENA: Paradygmat hermeneutyczny wydaje mi się fundamentalny - bez analizy tekstu pozostałe są spekulacją. Jednak jest niewystarczający: nie wyjaśnia, DLACZEGO Mickiewicz tworzył takie teksty. Tu pomocna jest psychoanaliza (trauma) i postkolonializm (hegemonia). Najadekwatniejsza jest więc synteza: hermeneutyka jako baza, psychoanaliza i postkolonializm jako kontekstualizacja. Mesjanizm to wielowarstwowy fenomen wymagający wielowarstwowej interpretacji."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiip0115003tqh7m0fv9q5pu', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 20, 'Przeanalizuj teozoficzne i filozoficzne źródła Wielkiej Improwizacji (Boehme, Schelling, Leibniz, Księga Hioba). Jak te różne tradycje współistnieją w monologu Konrada i jaką tworzą całość?', '{"hints": ["Boehme: Ungrund, natura Boga, wspólne źródło sił", "Schelling: poeta jako demiurg, organ Absolutu", "Leibniz: teodyceja, ''najlepszy ze światów'' (odrzucona)", "Księga Hioba: niewinny cierpiący pyta Boga"], "instruction": "Napisz rozprawkę (600-800 słów), w której:\n- przedstawisz wkład każdej tradycji filozoficznej/religijnej\n- przeanalizujesz, jak Mickiewicz je łączy lub stawia w napięciu\n- rozważ, czy Wielka Improwizacja jest koherentną syntezą czy eklektycznym zbiorem\n- oceń oryginalność Mickiewicza wobec źródeł"}', NULL, NULL, '{}', '{"sampleAnswer": "Wielka Improwizacja jest tekstem wielowarstwowym, czerpiącym z różnych tradycji filozoficznych i religijnych. Kluczowe źródła to: teozofia Jakuba Boehmego, filozofia sztuki Friedricha Schellinga, problematyka teodycei (Leibniz) oraz tradycja biblijna (Księga Hioba). Analiza ich współistnienia pozwala zrozumieć głębię i oryginalność Mickiewicza.\n\nTEOZOFIA BOEHMEGO dostarcza kosmologicznej podstawy buntu Konrada. Kluczowe pojęcia to: (1) Ungrund (Bezdeń) - pierwotna otchłań poprzedzająca rozróżnienia, wspólne źródło wszystkiego; (2) ''wieczna natura'' Boga - aspekt zawierający zarówno jasne, jak i ciemne siły; (3) wspólne pochodzenie sił boskich i ludzkich. Konrad mówi: ''Stamtąd przyszły siły moje, skąd do Ciebie przyszły Twoje'' - powołuje się na wspólne źródło, by uzasadnić roszczenia. Atak ''przeciw naturze'' Boga (nie samemu Bogu) wykorzystuje rozróżnienie Boehmego. Dzięki teozofii bunt Konrada nie jest prostym ateizmem, lecz wyrafinowaną krytyką kosmicznego porządku.\n\nFILOZOFIA SCHELLINGA dostarcza koncepcji poety-demiurga. W romantycznej filozofii sztuki Schellinga poeta jest ''organem Absolutu'' - przez geniusza przemawia nieskończoność, tworzy on światy jak Bóg-Stwórca. Konrad realizuje ten ideał: ''Cóż Ty większego mogłeś zrobić - Boże?'' - zrównuje swoją twórczość z boskim aktem. Jednak Mickiewicz pokazuje też granice tej koncepcji: ''język kłamie głosowi'' - nawet demiurg nie może w pełni wyrazić wizji. Schelling daje Konradowi aspirację, ale Mickiewicz odsłania jej tragiczność.\n\nTEODYCEA LEIBNIZA stanowi przedmiot krytyki. Leibniz twierdził, że żyjemy w ''najlepszym z możliwych światów'' - zło jest konieczne dla większej harmonii. Konrad explicite odrzuca ten optymizm: cierpienie ''Milionów'' Polaków nie służy żadnemu wyższemu celowi. Zarzut ''mądrość, ale nie miłość'' oznacza: Bóg wie o cierpieniu, ale nie interweniuje - to moralnie nieakceptowalne. Leibniz jest niewymienionym przeciwnikiem.\n\nKSIĘGA HIOBA dostarcza modelu dialogu z milczącym Bogiem. Hiob - niewinny cierpiący - pyta Boga o sens cierpienia. Bóg ostatecznie odpowiada (z wichru), ale nie wyjaśnia - pokazuje swoją wielkość. U Mickiewicza Bóg milczy całkowicie. Różne interpretacje: milczenie jako potwierdzenie oskarżeń (Przybylski) lub jako transcendencja. Konrad jest Hiobem, który nie doczeka odpowiedzi.\n\nCZY TO KOHERENTNA SYNTEZA CZY EKLEKTYZM? Uważam, że to DRAMATYCZNA SYNTEZA - nie logicznie spójna doktryna, lecz koherentna artystycznie całość. Boehme daje metafizyczne zaplecze, Schelling - estetyczne, Leibniz - filozoficzny cel polemiczny, Hiob - egzystencjalny wzorzec. Łączy je PYTANIE o sens cierpienia i POSTAWA buntu-pytania. Napięcia między źródłami (np. Boehme pozwala na bunt ''wewnątrz'' systemu, Hiob pyta ale ulega) tworzą dynamikę, nie sprzeczność. To nie traktat filozoficzny, lecz dramat - a dramat żyje napięciami.\n\nORYGINALNOŚĆ MICKIEWICZA polega nie na wynalezieniu nowych idei, lecz na ich dramatyzacji i ukonkretnieniu. Abstrakcyjne pojęcia Boehmego stają się krzykiem cierpiącego poety, estetyka Schellinga - tragicznym doświadczeniem granic, teodyceja Leibniza - oskarżeniem. Co najważniejsze: Mickiewicz wpisuje te filozoficzne wątki w polski kontekst historyczny. Uniwersalne pytanie o zło staje się pytaniem o sens cierpienia narodu. To połączenie filozofii europejskiej z polskim doświadczeniem historycznym jest właściwą oryginalnością Wielkiej Improwizacji."}', '2025-11-28 10:01:15.031', '2025-11-28 10:01:15.031', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyn009mqh7m7679lvdh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Gdzie powstały Dziady część III?', '{"options": ["w Wilnie", "w Paryżu", "w Dreźnie", "w Petersburgu"]}', '2', NULL, '{}', '{"explanation": "Mickiewicz napisał III część Dziadów w Dreźnie w 1832 roku, po upadku powstania listopadowego."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyn009nqh7mhpj2hpcq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'W którym roku Mickiewicz napisał Dziady część III?', '{"options": ["1823", "1828", "1832", "1840"]}', '2', NULL, '{}', '{"explanation": "Dziady cz. III powstały w 1832 roku w Dreźnie, tuż po upadku powstania listopadowego."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyn009oqh7mk4s6wily', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Jak nazywał się główny bohater Dziadów cz. III?', '{"options": ["Gustaw", "Konrad", "Kordian", "Wallenrod"]}', '1', NULL, '{}', '{"explanation": "Głównym bohaterem jest Konrad - poeta i więzień polityczny."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyn009pqh7m47kg2ip5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'W jakim mieście rozgrywa się akcja Dziadów cz. III?', '{"options": ["w Warszawie", "w Wilnie", "w Krakowie", "w Petersburgu"]}', '1', NULL, '{}', '{"explanation": "Akcja toczy się głównie w Wilnie - w klasztorze bazylianów zamienionym na więzienie."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyn009qqh7m1a9u8oam', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Po jakim wydarzeniu historycznym powstały Dziady cz. III?', '{"options": ["po insurekcji kościuszkowskiej", "po powstaniu listopadowym", "po powstaniu styczniowym", "po kongresie wiedeńskim"]}', '1', NULL, '{}', '{"explanation": "Dziady cz. III powstały bezpośrednio po klęsce powstania listopadowego (1830-1831)."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyo009rqh7mrmwqxfr8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Jak nazywa się najważniejszy monolog Konrada w Dziadach cz. III?', '{"options": ["Mała Improwizacja", "Wielka Improwizacja", "Widzenie", "Proroctwo"]}', '1', NULL, '{}', '{"explanation": "Wielka Improwizacja to centralny monolog dramatu, w którym Konrad buntuje się przeciw Bogu."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyo009sqh7mdusm8ggu', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Kim z zawodu jest Konrad?', '{"options": ["żołnierzem", "poetą", "księdzem", "urzędnikiem"]}', '1', NULL, '{}', '{"explanation": "Konrad jest poetą - twórcą romantycznym, który wierzy w moc swojej poezji."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyo009tqh7mgtetde4g', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Jak nazywał się bohater przed przemianą w Konrada?', '{"options": ["Gustaw", "Adam", "Wallenrod", "Jacek"]}', '0', NULL, '{}', '{"explanation": "W Prologu następuje symboliczna przemiana - Gustaw (bohater IV części) staje się Konradem."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyo009uqh7mlh67up6y', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Kto otrzymuje dar widzenia przyszłości Polski?', '{"options": ["Konrad", "ksiądz Piotr", "Senator Nowosilcow", "Ewa"]}', '1', NULL, '{}', '{"explanation": "Ksiądz Piotr - pokorny zakonnik - otrzymuje widzenie profetyczne o przyszłości Polski."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyo009vqh7mpzr1v0ve', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Co oznacza termin ''mesjanizm''?', '{"options": ["wiara w nadejście zbawiciela lub szczególną misję narodu", "kult przeszłości i tradycji", "dążenie do rewolucji", "filozofia pesymizmu"]}', '0', NULL, '{}', '{"explanation": "Mesjanizm to wiara w nadejście mesjasza lub w szczególną, zbawczą misję narodu."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyo009wqh7mpe1qx8gv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Jak w mesjanizmie polskim określano Polskę?', '{"options": ["Perła Europy", "Chrystus narodów", "Feniks Wschodu", "Tarcza chrześcijaństwa"]}', '1', NULL, '{}', '{"explanation": "Polska była nazywana ''Chrystusem narodów'' - jej cierpienie miało przynieść zbawienie Europy."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyo009xqh7mi8f0qgn4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Ilu zaborców miała Polska w czasach Mickiewicza?', '{"options": ["dwóch", "trzech", "czterech", "pięciu"]}', '1', NULL, '{}', '{"explanation": "Polska była podzielona między trzech zaborców: Rosję, Prusy i Austrię."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyo009yqh7mawgkg987', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Co symbolizują trzy gwoździe w Widzeniu księdza Piotra?', '{"options": ["trzy cnoty teologalne", "trzech zaborców Polski", "trzy części Dziadów", "trzy grzechy główne"]}', '1', NULL, '{}', '{"explanation": "Trzy gwoździe przybijające ukrzyżowaną Polskę symbolizują trzech zaborców: Rosję, Prusy i Austrię."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyo009zqh7mjgom0hkq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Przeciwko komu buntuje się Konrad w Wielkiej Improwizacji?', '{"options": ["przeciwko carowi", "przeciwko Bogu", "przeciwko szlachcie", "przeciwko Europie"]}', '1', NULL, '{}', '{"explanation": "Konrad buntuje się przeciwko Bogu, oskarżając Go o obojętność wobec cierpienia narodu polskiego."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyo00a0qh7mxa12hqi2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Czego żąda Konrad od Boga w Wielkiej Improwizacji?', '{"options": ["bogactwa", "władzy nad duszami (rządu dusz)", "nieśmiertelności", "zemsty na wrogach"]}', '1', NULL, '{}', '{"explanation": "Konrad żąda ''rządu dusz'' - władzy nad duszami ludzkimi, by móc uszczęśliwić naród."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyp00a1qh7m7nlw8uv4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Kto modli się za Konrada podczas jego buntu?', '{"options": ["ksiądz Piotr", "Ewa", "anioły", "więźniowie"]}', '1', NULL, '{}', '{"explanation": "Ewa - postać kobieca z sąsiedniej celi - modli się za Konrada, co przyczynia się do jego ocalenia."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyp00a2qh7mffoy4z1r', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Co przerywa bluźnierstwo Konrada?', '{"options": ["interwencja anioła", "utrata przytomności", "wejście strażników", "głos Boga"]}', '1', NULL, '{}', '{"explanation": "Konrad mdleje, zanim wypowie najgorsze bluźnierstwo - zdanie kończy za niego diabeł."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyp00a3qh7me1et37v7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Kto przeprowadza egzorcyzmy nad Konradem?', '{"options": ["biskup", "ksiądz Piotr", "anioł", "zakonnik bazylianin"]}', '1', NULL, '{}', '{"explanation": "Ksiądz Piotr przeprowadza egzorcyzmy, uwalniając Konrada od złych duchów."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyp00a4qh7m0qmutu90', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Jak nazywa się postawa buntu przeciw Bogu w imię ludzkości?', '{"options": ["mesjanizm", "prometeizm", "mistycyzm", "sceptycyzm"]}', '1', NULL, '{}', '{"explanation": "Prometeizm to postawa buntu przeciw Bogu/bogom w imię dobra ludzkości - od mitycznego Prometeusza."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyp00a5qh7m74tsrl5c', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Gdzie przebywają więźniowie w Dziadach cz. III?', '{"options": ["w Cytadeli warszawskiej", "w klasztorze bazylianów w Wilnie", "na Sybirze", "w twierdzy w Petersburgu"]}', '1', NULL, '{}', '{"explanation": "Akcja rozgrywa się w klasztorze bazylianów w Wilnie, zamienionym na więzienie dla spiskowców."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyp00a6qh7m9zk1wlf0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Jak nazywa się tajemniczy zbawiciel z Widzenia księdza Piotra?', '{"options": ["syn Marii", "czterdzieści i cztery", "wskrzesiciel ludu", "orzeł biały"]}', '1', NULL, '{}', '{"explanation": "Ksiądz Piotr widzi przyszłego zbawiciela, którego ''imię czterdzieści i cztery'' - to jedno z największych zagadek literatury polskiej."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyp00a7qh7ml760y39r', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Kto jako pierwszy użył terminu ''mesjanizm'' w 1831 roku?', '{"options": ["Adam Mickiewicz", "Józef Hoene-Wroński", "Andrzej Towiański", "Juliusz Słowacki"]}', '1', NULL, '{}', '{"explanation": "Termin ''mesjanizm'' wprowadził polski filozof i matematyk Józef Hoene-Wroński w 1831 roku."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyp00a8qh7mgojngw3f', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Jakim słowem Konrad chce nazwać Boga, ale nie kończy zdania?', '{"options": ["tyran", "car", "kat", "szatan"]}', '1', NULL, '{}', '{"explanation": "Konrad próbuje powiedzieć ''Tyś nie jest ojcem świata, ale...'' - słowo ''car'' dokańcza za niego diabeł."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyp00a9qh7mz5w21c0i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Z którym krajem Europa jest porównana do Piłata w Widzeniu księdza Piotra?', '{"options": ["z Anglią", "z Francją", "z Niemcami", "z Hiszpanią"]}', '1', NULL, '{}', '{"explanation": "Francja jest porównana do Piłata, który ''umywa ręce'' - nie bierze odpowiedzialności za rozbiory Polski."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyp00aaqh7mh1wx9cb9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Jak Konrad określa siebie w Wielkiej Improwizacji, utożsamiając się z narodem?', '{"options": ["Nazywam się Polak", "Nazywam się Milion", "Nazywam się Męczennik", "Nazywam się Ofiara"]}', '1', NULL, '{}', '{"explanation": "''Nazywam się Milion - bo za miliony kocham i cierpię katusze'' - Konrad utożsamia się z całym cierpiącym narodem."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyq00abqh7mqlcx94pk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Co według Konrada kłamie głosowi, a głos kłamie myślom?', '{"options": ["serce", "dusza", "język", "rozum"]}', '2', NULL, '{}', '{"explanation": "''Język kłamie głosowi, a głos myślom kłamie'' - Konrad wyraża romantyczny problem niewyrażalności uczuć."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyq00acqh7mxgrqx2wm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Jakiego filozofa niemieckiego krytykował Mickiewicz za marginalizowanie Słowian?', '{"options": ["Kanta", "Hegla", "Schopenhauera", "Fichtego"]}', '1', NULL, '{}', '{"explanation": "Mickiewicz polemizował z Heglem, którego filozofia dziejów wykluczała Słowian z grona ''narodów historycznych''."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyq00adqh7m6dqai2ar', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Jaki proces historyczny stanowił bezpośrednie tło biograficzne dla Dziadów cz. III?', '{"options": ["proces Piotra Wysockiego", "proces filomatów i filaretów", "powstanie kościuszkowskie", "sejm wielki"]}', '1', NULL, '{}', '{"explanation": "Proces filomatów i filaretów (1823-1824) w Wilnie - sam Mickiewicz był zamieszany w tę sprawę."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyq00aeqh7mx28n8kag', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Co zarzuca Konrad Bogu w Wielkiej Improwizacji?', '{"options": ["że stworzył zły świat", "że ma mądrość bez miłości", "że nie istnieje", "że jest słaby"]}', '1', NULL, '{}', '{"explanation": "Konrad zarzuca Bogu, że ma ''mądrość bez miłości'' - jest rozumny, ale obojętny na ludzkie cierpienie."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyq00afqh7mr8ndvuon', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Która postać biblijna jest wzorem dla mesjanistycznej wizji Polski?', '{"options": ["Mojżesz", "Abraham", "Chrystus", "Dawid"]}', '2', NULL, '{}', '{"explanation": "Chrystus jest wzorem - Polska jak Chrystus cierpi, umiera i zmartwychwstanie dla zbawienia narodów."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyq00agqh7mka6yk5ou', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Co oznacza termin ''prometeizm'' w kontekście literatury?', '{"options": ["naśladowanie stylu greckiego", "poświęcenie jednostki dla dobra ogółu i bunt przeciw siłom wyższym", "dążenie do poznania naukowego", "kult natury"]}', '1', NULL, '{}', '{"explanation": "Prometeizm to postawa poświęcenia jednostki dla ludzkości i buntu przeciw niesprawiedliwej władzy - od Prometeusza, który wykradł ogień dla ludzi."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyq00ahqh7m10fltu4j', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Co symbolizuje improwizacja jako forma wypowiedzi w romantyzmie?', '{"options": ["przypadkowość tworzenia", "spontaniczne natchnienie i geniusz poetycki", "brak przygotowania", "prostotę i ludowość"]}', '1', NULL, '{}', '{"explanation": "Improwizacja była dowodem geniuszu - tworzenie w stanie natchnienia, bez przygotowania, było ideałem romantycznym."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyq00aiqh7mk1sc8rwt', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Jaki problem filozoficzny jest centralny dla Wielkiej Improwizacji?', '{"options": ["problem istnienia Boga", "problem teodycei (jak pogodzić dobrego Boga z istnieniem zła)", "problem wolnej woli", "problem poznania"]}', '1', NULL, '{}', '{"explanation": "Teodyceja - jak wytłumaczyć istnienie zła i cierpienia, skoro Bóg jest dobry i wszechmocny - to główny problem Improwizacji."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyq00ajqh7mt68ah9ao', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Która cecha różni prometeizm Konrada od mesjanizmu księdza Piotra?', '{"options": ["miłość do ojczyzny", "postawa wobec Boga (bunt vs pokora)", "znajomość przyszłości", "obecność w więzieniu"]}', '1', NULL, '{}', '{"explanation": "Konrad buntuje się przeciw Bogu (prometeizm), ksiądz Piotr pokornie przyjmuje Jego wolę (mesjanizm)."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyr00akqh7mn3vtpp4j', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Czym według Konrada jest jego uczucie do narodu?', '{"options": ["obowiązkiem obywatelskim", "miłością jak kochanka, ojca i matki razem", "romantycznym idealizmem", "religijnym powołaniem"]}', '1', NULL, '{}', '{"explanation": "Konrad opisuje swoją miłość do narodu jako połączenie miłości ojca, kochanka i matki - totalną i wszechogarniającą."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyr00alqh7md5xlwexy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Jak nazywa się średniowieczny gatunek literacki, który ilustruje walkę duchów o duszę?', '{"options": ["epos", "psychomachia", "apologia", "hagiografia"]}', '1', NULL, '{}', '{"explanation": "Psychomachia (walka o duszę) - alegoria walki cnót i grzechów; w Dziadach aniołowie i diabły walczą o duszę Konrada."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyr00amqh7myu4k8twm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Co w romantycznej filozofii oznaczało przekonanie, że poeta jest demiurgiem?', '{"options": ["że poeta jest zwykłym rzemieślnikiem", "że poeta tworzy własne światy jak Bóg-stwórca", "że poeta jest naśladowcą natury", "że poeta jest prorokiem"]}', '1', NULL, '{}', '{"explanation": "Poeta-demiurg to romantyczna koncepcja twórcy jako stwórcy światów - analogicznie do Boga tworzącego wszechświat."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyr00anqh7m0cmdeny4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Który badacz literatury wprowadził termin ''romantyczny tytanizm''?', '{"options": ["Maria Janion", "Wiktor Weintraub", "Zofia Stefanowska", "Stanisław Pigoń"]}', '1', NULL, '{}', '{"explanation": "Wiktor Weintraub ukuł termin ''romantyczny tytanizm'' dla opisu buntu przeciw Bogu u Mickiewicza."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyr00aoqh7mxerxh4kp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Na ile głównych faz dzieli się zazwyczaj Wielka Improwizacja?', '{"options": ["dwie", "trzy", "cztery", "pięć"]}', '2', NULL, '{}', '{"explanation": "Wielką Improwizację dzieli się na cztery fazy: samotność artysty, poetycka wszechmoc, utożsamienie z narodem, konfrontacja z Bogiem."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyr00apqh7m8ed9c050', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Co według mesjanizmu miało nastąpić po ''śmierci'' Polski?', '{"options": ["zapomnienie", "zmartwychwstanie", "wcielenie do innych narodów", "powrót do przeszłości"]}', '1', NULL, '{}', '{"explanation": "Według mesjanizmu Polska, podobnie jak Chrystus, zmartwychwstanie po swojej ''śmierci'' (rozbiorach)."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyr00aqqh7mebllhrrz', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Które postacie występują w Dziadach cz. III?', '{"options": ["Konrad", "Kordian", "ksiądz Piotr", "Wallenrod", "Ewa"]}', '[0, 2, 4]', NULL, '{}', '{"explanation": "W Dziadach cz. III występują: Konrad (główny bohater), ksiądz Piotr (mistyk), Ewa (modli się za Konrada). Kordian i Wallenrod to bohaterowie innych utworów."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyr00arqh7mkf5a9znv', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Które państwa były zaborcami Polski w czasach Mickiewicza?', '{"options": ["Rosja", "Francja", "Prusy", "Anglia", "Austria"]}', '[0, 2, 4]', NULL, '{}', '{"explanation": "Trzej zaborcy to: Rosja (największy zabór), Prusy (zabór zachodni), Austria (zabór południowy - Galicja)."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyr00asqh7mzpuq1bvm', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Które cechy charakteryzują romantycznego bohatera jak Konrad?', '{"options": ["indywidualizm", "racjonalizm", "bunt przeciw światu", "posłuszeństwo władzy", "uczuciowość"]}', '[0, 2, 4]', NULL, '{}', '{"explanation": "Konrad jako bohater romantyczny: indywidualista, buntownik, kieruje się uczuciami - przeciwieństwo racjonalizmu i posłuszeństwa."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyr00atqh7m6ix8svfb', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Które utwory napisał Adam Mickiewicz?', '{"options": ["Pan Tadeusz", "Kordian", "Dziady", "Nie-Boska komedia", "Ballady i romanse"]}', '[0, 2, 4]', NULL, '{}', '{"explanation": "Mickiewicz napisał: Pan Tadeusz, Dziady, Ballady i romanse. Kordian to Słowacki, Nie-Boska komedia to Krasiński."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfys00auqh7mohyu89jd', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Które elementy występują w Widzeniu księdza Piotra?', '{"options": ["obraz ukrzyżowanej Polski", "proroctwo o mesjaszu", "dialog z Bogiem", "szczegółowy opis bitwy", "wizja zmartwychwstania narodu"]}', '[0, 1, 4]', NULL, '{}', '{"explanation": "Widzenie zawiera: alegorię ukrzyżowanej Polski, proroctwo o ''44'', wizję zmartwychwstania. Nie ma dialogu z Bogiem ani opisu bitwy."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfys00avqh7mk02f8oam', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Które postawy są obecne w Dziadach cz. III?', '{"options": ["mesjanizm", "pozytywizm", "prometeizm", "realizm", "patriotyzm"]}', '[0, 2, 4]', NULL, '{}', '{"explanation": "W Dziadach cz. III: mesjanizm (ksiądz Piotr), prometeizm (Konrad), patriotyzm (cały utwór). Pozytywizm i realizm to późniejsze epoki."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfys00awqh7m9crakuhv', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Dopasuj postać do jej roli w dramacie.', '{"leftColumn": [{"id": "A", "text": "Konrad"}, {"id": "B", "text": "ksiądz Piotr"}, {"id": "C", "text": "Ewa"}], "rightColumn": [{"id": 1, "text": "buntownik przeciw Bogu"}, {"id": 2, "text": "pokorny wizjoner"}, {"id": 3, "text": "zbawcza modlitwa"}], "matchingType": "character_role"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{}', '{"explanation": "Konrad buntuje się (prometeizm), ksiądz Piotr pokornie przyjmuje widzenia (mesjanizm), Ewa modli się za Konrada."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfys00axqh7mdna6zl49', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Dopasuj fazę Wielkiej Improwizacji do jej opisu.', '{"leftColumn": [{"id": "A", "text": "Faza I"}, {"id": "B", "text": "Faza II"}, {"id": "C", "text": "Faza III"}], "rightColumn": [{"id": 1, "text": "samotność poety"}, {"id": 2, "text": "poetycka wszechmoc"}, {"id": 3, "text": "utożsamienie z narodem"}], "matchingType": "improvisation_phases"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{}', '{"explanation": "Struktura Improwizacji: najpierw samotność artysty, potem ekstaza twórcza, następnie ''Nazywam się Milion''."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfys00ayqh7monoffbz2', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Dopasuj pojęcie do definicji.', '{"leftColumn": [{"id": "A", "text": "mesjanizm"}, {"id": "B", "text": "prometeizm"}, {"id": "C", "text": "teodyceja"}], "rightColumn": [{"id": 1, "text": "wiara w zbawczą misję narodu"}, {"id": 2, "text": "bunt jednostki dla dobra ludzkości"}, {"id": 3, "text": "uzasadnienie istnienia zła w świecie"}], "matchingType": "concept_definition"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{}', '{"explanation": "Mesjanizm - misja narodu, prometeizm - bunt za ludzkość, teodyceja - problem zła u dobrego Boga."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfys00azqh7mlgc9g8gd', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Które zarzuty stawia Konrad Bogu w Wielkiej Improwizacji?', '{"options": ["że ma mądrość bez miłości", "że jest obojętny na cierpienie", "że nie istnieje", "że nie daje mu władzy nad duszami", "że stworzył piękny świat"]}', '[0, 1, 3]', NULL, '{}', '{"explanation": "Konrad zarzuca Bogu: brak miłości mimo mądrości, obojętność na cierpienie, odmowę władzy. Nie neguje istnienia Boga ani piękna świata."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfys00b0qh7mx1lim4em', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Które sceny następują PO Wielkiej Improwizacji?', '{"options": ["egzorcyzmy księdza Piotra", "Widzenie księdza Piotra", "przemiana Gustawa w Konrada", "modlitwa Ewy", "Salon warszawski"]}', '[0, 1, 4]', NULL, '{}', '{"explanation": "Po Improwizacji: egzorcyzmy, Widzenie, Salon warszawski. Przemiana Gustawa jest w Prologu (przed Improwizacją), modlitwa Ewy - podczas."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfys00b1qh7mymg5jn3h', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Które elementy symboliki chrześcijańskiej występują w mesjanizmie polskim?', '{"options": ["ukrzyżowanie", "zmartwychwstanie", "raj utracony", "trzy gwoździe", "sąd ostateczny"]}', '[0, 1, 3]', NULL, '{}', '{"explanation": "Mesjanizm wykorzystuje: ukrzyżowanie (cierpienie Polski), zmartwychwstanie (odzyskanie niepodległości), trzy gwoździe (trzej zaborcy)."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfys00b2qh7mprrjnxmx', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Uzupełnij zdanie o Wielkiej Improwizacji.', '{"gaps": [{"id": 1, "options": ["modli się", "buntuje się", "płacze", "milczy"]}, {"id": 2, "options": ["bogactwa", "zemsty", "rządu dusz", "nieśmiertelności"]}, {"id": 3, "options": ["Bogiem", "poetami", "narodem (Milionem)", "naturą"]}], "textWithGaps": "Konrad w Wielkiej Improwizacji [1] przeciwko Bogu, żąda [2] i utożsamia się z [3]."}', '[1, 2, 2]', NULL, '{}', '{"explanation": "Konrad buntuje się, żąda rządu dusz (władzy nad duszami) i mówi ''Nazywam się Milion''."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyt00b3qh7myw8nnt6k', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Uzupełnij zdanie o mesjanizmie.', '{"gaps": [{"id": 1, "options": ["władcą", "Chrystusem", "strażnikiem", "sędzią"]}, {"id": 2, "options": ["przypadkowy", "odkupieńczy", "karny", "polityczny"]}, {"id": 3, "options": ["zapomnienie", "kara", "zmartwychwstanie", "upadek"]}], "textWithGaps": "Według mesjanizmu Polska jest [1] narodów, jej cierpienie ma charakter [2], a po ''śmierci'' nastąpi [3]."}', '[1, 1, 2]', NULL, '{}', '{"explanation": "Polska = Chrystus narodów, cierpienie ma charakter odkupieńczy, po nim nastąpi zmartwychwstanie."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyt00b4qh7mnpojaeg7', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Które twierdzenia o prometeizmie są prawdziwe?', '{"options": ["nazwa pochodzi od mitycznego Prometeusza", "oznacza pokorę wobec Boga", "zakłada poświęcenie jednostki dla ludzkości", "jest identyczny z mesjanizmem", "zawiera element buntu przeciw siłom wyższym"]}', '[0, 2, 4]', NULL, '{}', '{"explanation": "Prometeizm: od Prometeusza, poświęcenie dla ludzkości, bunt. NIE jest pokorą ani nie jest tożsamy z mesjanizmem."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyt00b5qh7m9ce3ew0b', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Dopasuj symbol do znaczenia w Dziadach cz. III.', '{"leftColumn": [{"id": "A", "text": "trzy gwoździe"}, {"id": "B", "text": "krzyż"}, {"id": "C", "text": "czterdzieści i cztery"}], "rightColumn": [{"id": 1, "text": "trzej zaborcy"}, {"id": 2, "text": "cierpienie narodu"}, {"id": 3, "text": "tajemniczy zbawiciel"}], "matchingType": "symbol_meaning"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{}', '{"explanation": "Trzy gwoździe = trzej zaborcy, krzyż = cierpienie Polski, 44 = przyszły mesjasz narodowy."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyt00b6qh7mikgt3w82', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Które cechy różnią Konrada od księdza Piotra?', '{"options": ["Konrad jest pyszny, ksiądz Piotr pokorny", "Konrad buntuje się, ksiądz Piotr modli się", "Konrad jest poetą, ksiądz Piotr zakonnikiem", "Konrad kocha Polskę, ksiądz Piotr nie", "Konrad żąda władzy, ksiądz Piotr przyjmuje wizje"]}', '[0, 1, 2, 4]', NULL, '{}', '{"explanation": "Różnice: pycha vs pokora, bunt vs modlitwa, poeta vs zakonnik, żądanie vs przyjmowanie. Obaj kochają Polskę."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyt00b7qh7mhz6vndmp', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Które wydarzenia historyczne wpłynęły na powstanie Dziadów cz. III?', '{"options": ["powstanie listopadowe", "powstanie styczniowe", "proces filomatów", "kongres wiedeński", "zsyłka Mickiewicza do Rosji"]}', '[0, 2, 4]', NULL, '{}', '{"explanation": "Wpływy: powstanie listopadowe (1830-31), proces filomatów (1823-24), zsyłka Mickiewicza. Powstanie styczniowe było później (1863)."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyt00b8qh7mcypb3uv2', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Kim był Konrad przed przemianą opisaną w Prologu Dziadów cz. III?', '{"hint": "Imię bohatera z IV części Dziadów"}', NULL, NULL, '{}', '{"keyPoints": ["Gustaw", "przemiana", "IV część Dziadów", "nieszczęśliwy kochanek"], "sampleAnswer": "Konrad był wcześniej Gustawem - bohaterem IV części Dziadów, nieszczęśliwym kochankiem. W Prologu następuje symboliczna przemiana: Gustaw ''umarł'', narodził się Konrad - poeta-bojownik o wolność narodu."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyt00b9qh7ms5i81kwh', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Co oznacza słowo ''mesjanizm'' i skąd pochodzi?', '{"hint": "Nawiązanie do postaci biblijnej"}', NULL, NULL, '{}', '{"keyPoints": ["mesjasz", "zbawiciel", "misja narodu", "cierpienie odkupieńcze"], "sampleAnswer": "Mesjanizm pochodzi od słowa ''mesjasz'' (hebr. namaszczony) - zbawiciel oczekiwany przez Izraelitów. W polskim romantyzmie oznacza wiarę w szczególną, zbawczą misję narodu polskiego wobec innych narodów."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyt00baqh7mmr3dbk2f', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Czego żąda Konrad od Boga w Wielkiej Improwizacji?', '{"hint": "Rodzaj władzy"}', NULL, NULL, '{}', '{"keyPoints": ["rząd dusz", "władza nad duszami", "uszczęśliwienie narodu", "milczenie Boga"], "sampleAnswer": "Konrad żąda od Boga ''rządu dusz'' - władzy nad duszami ludzkimi. Chce tej mocy, by móc uszczęśliwić naród i zakończyć jego cierpienie. Bóg jednak milczy i nie odpowiada na żądanie."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyt00bbqh7mufhwcp5o', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Co symbolizują trzy gwoździe w Widzeniu księdza Piotra?', '{"hint": "Trzy państwa"}', NULL, NULL, '{}', '{"keyPoints": ["trzej zaborcy", "Rosja", "Prusy", "Austria", "ukrzyżowanie"], "sampleAnswer": "Trzy gwoździe symbolizują trzech zaborców Polski: Rosję, Prusy i Austrię. Polska jest przedstawiona jako ukrzyżowana niewiasta, przybita do krzyża przez te trzy mocarstwa - podobnie jak Chrystus był przybity gwoździami."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyu00bcqh7mjub9i2yf', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Dlaczego Polska była nazywana ''Chrystusem narodów''?', '{"hint": "Analogia do męki i zmartwychwstania"}', NULL, NULL, '{}', '{"keyPoints": ["cierpienie niewinne", "analogia do Chrystusa", "zmartwychwstanie", "zbawienie narodów"], "sampleAnswer": "Polska była nazywana Chrystusem narodów, bo według mesjanizmu jej los jest analogiczny do losu Chrystusa: cierpi niewinnie (rozbiory), ''umiera'' na krzyżu (utrata niepodległości), ale zmartwychwstanie i przyniesie zbawienie innym narodom."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyu00bdqh7mcvaovelw', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Co przerywa bluźnierstwo Konrada i kto dokańcza jego słowa?', '{"hint": "Stan fizyczny bohatera i istota nadprzyrodzona"}', NULL, NULL, '{}', '{"keyPoints": ["utrata przytomności", "omdlenie", "diabeł", "car"], "sampleAnswer": "Konrad traci przytomność (mdleje) w momencie, gdy chce nazwać Boga ''carem''. Bluźniercze zdanie dokańcza za niego diabeł, który mówi słowo ''car''. Dzięki omdleniu Konrad nie wypowiada osobiście najgorszego bluźnierstwa."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyu00beqh7mwunl8zy0', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Kto i dlaczego modli się za Konrada podczas Wielkiej Improwizacji?', '{"hint": "Kobieca postać z sąsiedniej celi"}', NULL, NULL, '{}', '{"keyPoints": ["Ewa", "modlitwa wstawiennicza", "ocalenie", "pokora vs pycha"], "sampleAnswer": "Za Konrada modli się Ewa - postać kobieca przebywająca w sąsiedniej celi. Jej modlitwa wstawiennicza przyczynia się do ocalenia Konrada przed potępieniem. Reprezentuje moc pokornej modlitwy w kontraście z pychą Konrada."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyu00bfqh7mj7a71dic', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Co oznacza słynne zdanie Konrada ''Nazywam się Milion''?', '{"hint": "Utożsamienie z grupą"}', NULL, NULL, '{}', '{"keyPoints": ["utożsamienie z narodem", "ja zbiorowe", "cierpienie za miliony", "miłość do narodu"], "sampleAnswer": "Słowa ''Nazywam się Milion - bo za miliony kocham i cierpię katusze'' oznaczają utożsamienie się Konrada z całym cierpiącym narodem polskim. Przestaje mówić tylko o sobie - jego ''ja'' staje się ''ja'' zbiorowym milionów Polaków."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyu00bgqh7m0ng186co', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Wyjaśnij, czym różni się prometeizm Konrada od mesjanizmu księdza Piotra.', '{"hint": "Stosunek do Boga: bunt vs pokora"}', NULL, NULL, '{}', '{"keyPoints": ["bunt vs pokora", "żądanie vs przyjmowanie", "aktywność vs bierność", "pycha vs pokora"], "sampleAnswer": "Prometeizm Konrada polega na buncie przeciw Bogu, żądaniu władzy i oskarżaniu Stwórcy o obojętność - to postawa aktywna, tytaniczna. Mesjanizm księdza Piotra to pokorne przyjmowanie woli Bożej i oczekiwanie zbawienia ''z góry''. Konrad chce wymusić zbawienie, ksiądz Piotr je przyjmuje."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyu00bhqh7m8ssttxo6', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Co oznacza zarzut Konrada, że Bóg ma ''mądrość, ale nie ma miłości''?', '{"hint": "Problem teodycei"}', NULL, NULL, '{}', '{"keyPoints": ["wszechwiedzący ale obojętny", "problem teodycei", "cierpienie bez pomocy", "zło w świecie"], "sampleAnswer": "Konrad zarzuca Bogu, że choć jest wszechwiedzący (mądry), pozostaje obojętny na ludzkie cierpienie (brak miłości). Wie o cierpieniu Polski, ale nie interweniuje. To klasyczny problem teodycei: jak pogodzić dobroć Boga z istnieniem zła w świecie."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyu00biqh7md7s49r54', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Wyjaśnij, dlaczego romantyczna improwizacja była uważana za dowód geniuszu poetyckiego.', '{"hint": "Spontaniczność, natchnienie"}', NULL, NULL, '{}', '{"keyPoints": ["spontaniczność", "natchnienie", "bezpośredni kontakt z wyższą siłą", "Mickiewicz jako improwizator"], "sampleAnswer": "Improwizacja była dowodem geniuszu, bo poeta tworzył spontanicznie, bez przygotowania, w stanie natchnienia. Oznaczała bezpośredni kontakt z wyższymi siłami - muza czy duch przemawiał przez poetę. Sam Mickiewicz słynął jako improwizator, a improwizacja była romantycznym ideałem twórczości."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyu00bjqh7mlqxbxt5w', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Co oznacza tajemnicze proroctwo o zbawicielu, którego ''imię czterdzieści i cztery''?', '{"hint": "Nierozwiązana zagadka"}', NULL, NULL, '{}', '{"keyPoints": ["zagadka literacka", "różne interpretacje", "Mickiewicz nie wyjaśnił", "mesjasz narodowy"], "sampleAnswer": "Proroctwo o ''44'' to jedna z największych zagadek literatury polskiej. Ksiądz Piotr widzi przyszłego zbawiciela narodu, którego ''imię czterdzieści i cztery''. Próbowano je interpretować jako: Mickiewicza (inicjały A.M.), Napoleona, symbol zbiorowy. Mickiewicz nigdy nie wyjaśnił tej liczby."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyu00bkqh7milg2z1hz', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Dlaczego Francja jest porównana do Piłata w Widzeniu księdza Piotra?', '{"hint": "Umywanie rąk"}', NULL, NULL, '{}', '{"keyPoints": ["umywanie rąk", "brak odpowiedzialności", "możliwość pomocy", "analogia do Piłata"], "sampleAnswer": "Francja jest jak Piłat, bo ''umywa ręce'' - nie bierze odpowiedzialności za losy Polski mimo możliwości pomocy. Tak jak Piłat wiedział o niewinności Chrystusa, ale pozwolił na ukrzyżowanie, tak Francja wiedziała o krzywdzie Polski, ale nie interweniowała."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyv00blqh7m5kzmz0sk', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Wyjaśnij, co oznaczają słowa Konrada ''Język kłamie głosowi, a głos myślom kłamie''.', '{"hint": "Problem wyrażenia uczuć"}', NULL, NULL, '{}', '{"keyPoints": ["niewyrażalność", "ograniczenia języka", "przepaść między myślą a słowem", "romantyczny topos"], "sampleAnswer": "Słowa te wyrażają romantyczny problem niewyrażalności - uczucia i myśli są zbyt wielkie, by słowa mogły je oddać. Głos nie wyraża w pełni myśli, a język (słowa) nie oddaje głosu. Poeta czuje tragiczną niemożność pełnego wyrażenia swojego wnętrza - to ograniczenie nawet dla geniusza."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyv00bmqh7mcy9hg5fg', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Co to jest psychomachia i jak przejawia się w Dziadach cz. III?', '{"hint": "Walka duchów o duszę"}', NULL, NULL, '{}', '{"keyPoints": ["walka o duszę", "aniołowie vs diabły", "alegoria", "konflikt wewnętrzny"], "sampleAnswer": "Psychomachia to średniowieczny gatunek alegoryczny przedstawiający walkę o duszę człowieka. W Dziadach przejawia się w scenie, gdy aniołowie i diabły walczą o duszę Konrada po Improwizacji. Diabły chcą go pogrążyć, anioły bronią. To dramatyzacja wewnętrznego konfliktu bohatera."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyv00bnqh7m332w5stc', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Wyjaśnij związek między procesem filomatów a treścią Dziadów cz. III.', '{"hint": "Autobiograficzne tło"}', NULL, NULL, '{}', '{"keyPoints": ["tajne organizacje", "Wilno", "zsyłka Mickiewicza", "tło autobiograficzne"], "sampleAnswer": "Proces filomatów i filaretów (1823-24) to śledztwo carskie przeciw tajnym organizacjom młodzieżowym w Wilnie. Mickiewicz był w nie zamieszany i zesłany do Rosji. Dziady cz. III nawiązują bezpośrednio: więzienie bazylianów, przesłuchania, zsyłki - to tło autobiograficzne dramatu."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyv00boqh7mm3gqfy7q', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'W jaki sposób dramat Mickiewicza polemizuje z filozofią Hegla?', '{"hint": "Miejsce Słowian w historii"}', NULL, NULL, '{}', '{"keyPoints": ["Słowianie poza historią", "kontrdyskurs", "słabość jako siła", "odwrócenie hierarchii"], "sampleAnswer": "Hegel uważał Słowian za narody ''pozahistoryczne'', nierozwinięte. Mesjanizm Mickiewicza to kontrdyskurs: Polska nie jest marginesem historii, lecz jej centrum - jako Chrystus narodów ma szczególną misję zbawczą. Słabość staje się siłą, cierpienie - drogą do chwały."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyv00bpqh7muylj2n1c', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Jaką funkcję pełni scena Salonu warszawskiego w strukturze dramatu?', '{"hint": "Portret społeczeństwa"}', NULL, NULL, '{}', '{"keyPoints": ["satyra na arystokrację", "obojętność", "służalczość", "kontrast z patriotami"], "sampleAnswer": "Salon warszawski to scena realistyczno-satyryczna pokazująca polskie społeczeństwo wyższe: arystokrację obojętną na losy narodu, służalczość wobec zaborcy, konformizm. Stanowi kontrast z heroizmem więźniów i patriotyzmem młodzieży - pokazuje, że wrogiem są też Polacy bez ducha."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyv00bqqh7muubiaqyv', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 8, 'Przedstaw i oceń postawę Konrada w Wielkiej Improwizacji. Czy jego bunt jest uzasadniony?', '{"hints": ["Pamiętaj o kontekście: Konrad mówi po klęsce powstania", "Rozważ różne perspektywy: romantyczną i religijną", "Weź pod uwagę miłość Konrada do narodu"], "instruction": "Napisz wypracowanie (200-300 słów), w którym:\n- przedstawisz główne zarzuty Konrada wobec Boga\n- wyjaśnisz, czego Konrad żąda i dlaczego\n- ocenisz, czy jego postawa zasługuje na podziw czy potępienie\n- odwołaj się do kontekstu historycznego (powstanie listopadowe)"}', NULL, NULL, '{}', '{"sampleAnswer": "Wielka Improwizacja jest sceną buntu Konrada przeciw Bogu w imię cierpiącego narodu. Konrad zarzuca Stwórcy, że ma ''mądrość bez miłości'' - wie o cierpieniu Polaków, ale pozostaje obojętny. Żąda ''rządu dusz'', by móc uszczęśliwić naród własną mocą.\n\nOcena tej postawy jest niejednoznaczna. Z perspektywy romantycznej Konrad zasługuje na podziw: jego bunt wynika z głębokiej miłości (''za miliony kocham i cierpię katusze''), nie z egoizmu. Po klęsce powstania listopadowego pytanie o sens cierpienia niewinnych było naturalne i bolesne.\n\nZ drugiej strony, Konrad popada w pychę - uważa się za równego Bogu, żąda boskiej władzy. Nie prosi, lecz żąda. Struktura dramatu sugeruje, że ta pycha jest niebezpieczna: Konrad prawie wypowiada bluźnierstwo i potrzebuje egzorcyzmów.\n\nUważam, że bunt Konrada jest zrozumiały, ale nie w pełni uzasadniony. Jego miłość jest szlachetna, ale forma buntu - pycha zamiast pokory - prowadzi na manowce. Dramat pokazuje, że drogą do zbawienia jest raczej postawa księdza Piotra: pokorne przyjęcie cierpienia w nadziei na zmartwychwstanie."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyv00brqh7mu47u900n', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 8, 'Wyjaśnij ideę mesjanizmu w Dziadach cz. III. Dlaczego Polska była nazywana ''Chrystusem narodów''?', '{"hints": ["Skup się na symbolice: krzyż, gwoździe, zmartwychwstanie", "Pamiętaj o kontekście: rozbiory, utrata niepodległości", "Wyjaśnij funkcję mesjanizmu jako źródła nadziei"], "instruction": "Napisz wypracowanie (200-300 słów), w którym:\n- wyjaśnisz, co oznacza mesjanizm\n- przedstawisz analogię między Polską a Chrystusem\n- odwołasz się do Widzenia księdza Piotra\n- wyjaśnisz, jaką nadzieję dawała ta idea Polakom"}', NULL, NULL, '{}', '{"sampleAnswer": "Mesjanizm to wiara w szczególną, zbawczą misję narodu polskiego. Według tej idei Polska była nazywana ''Chrystusem narodów'', bo jej los stanowił analogię do losu Jezusa Chrystusa.\n\nPodobieństwo jest wielopoziomowe. Chrystus cierpiał niewinnie za grzechy ludzkości - Polska cierpi niewinnie pod zaborami za ''grzechy'' Europy (obojętność, egoizm narodów). Chrystus został ukrzyżowany - Polska jest ''ukrzyżowana'' przez trzech zaborców, symbolizowanych jako trzy gwoździe. Chrystus zmartwychwstał - Polska zmartwychwstanie i odzyska niepodległość.\n\nNajpełniej tę analogię przedstawia Widzenie księdza Piotra. Pokorny zakonnik widzi Polskę jako ukrzyżowaną niewiastę, której ręce i nogi przybite są trzema gwoździami (Rosja, Prusy, Austria). Widzi też przyszłego zbawiciela (''czterdzieści i cztery'') oraz zmartwychwstanie narodu.\n\nIdea ta dawała Polakom nadzieję w pozornie beznadziejnej sytuacji. Po klęsce powstania listopadowego, gdy wydawało się, że Polska przepadła na zawsze, mesjanizm tłumaczył: to nie koniec, lecz etap - jak śmierć Chrystusa nie była końcem, lecz drogą do zmartwychwstania. Cierpienie nie jest bezsensowne - ma wymiar zbawczy. Polska nie tylko odzyska wolność, ale przyczyni się do wyzwolenia innych narodów."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyv00bsqh7m06w9frpu', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 10, 'Porównaj postawy Konrada i księdza Piotra wobec Boga i cierpienia narodu. Która postawa jest przedstawiona jako właściwa droga do zbawienia?', '{"hints": ["Zwróć uwagę na strukturę dramatu: co następuje po buncie Konrada?", "Porównaj: pycha vs pokora, bunt vs modlitwa, żądanie vs przyjmowanie", "Zastanów się: kto otrzymuje dar widzenia przyszłości?"], "instruction": "Napisz wypracowanie (300-400 słów), w którym:\n- scharakteryzujesz postawę Konrada (prometeizm)\n- scharakteryzujesz postawę księdza Piotra (mesjanizm)\n- porównasz obie postawy, wskazując różnice\n- zinterpretujesz, którą postawę dramat przedstawia jako właściwą\n- uzasadnij swoją interpretację"}', NULL, NULL, '{}', '{"sampleAnswer": "Konrad i ksiądz Piotr reprezentują dwie odmienne postawy wobec Boga i cierpienia narodu: prometeizm i mesjanizm.\n\nKonrad przyjmuje postawę prometejską - buntuje się przeciw Bogu w imię cierpiącego narodu. Zarzuca Stwórcy, że ma ''mądrość bez miłości'', żąda ''rządu dusz'' - władzy nad ludzkością. Jego postawa jest aktywna, tytaniczna, oparta na przeświadczeniu o własnej wyjątkowości (''Nazywam się Milion''). Konrad nie prosi - żąda. Nie ufa - oskarża. W kulminacji próbuje nawet nazwać Boga ''carem''.\n\nKsiądz Piotr reprezentuje przeciwstawną postawę mesjanistyczną. Jest pokorny, modli się, przyjmuje wolę Bożą. Nie buntuje się przeciw cierpieniu, lecz szuka w nim sensu. Nie żąda władzy - otrzymuje dar widzenia jako łaskę. Jego postawa jest bierna w sensie braku buntu, ale aktywna w modlitwie i ufności.\n\nKluczowe różnice: pycha vs pokora, bunt vs akceptacja, żądanie vs przyjmowanie, bluźnierstwo vs modlitwa.\n\nStruktura dramatu sugeruje, że właściwą drogą jest postawa księdza Piotra. Bunt Konrada kończy się upadkiem - traci przytomność, prawie popada w potępienie, potrzebuje egzorcyzmów. To właśnie pokorny ksiądz Piotr, nie pyszny Konrad, otrzymuje widzenie przyszłości Polski. Zbawienie ''przyjdzie z góry'', jak mówi proroctwo - nie zostanie wymuszone ludzką wolą.\n\nJednocześnie dramat nie odrzuca całkowicie postawy Konrada. Jego miłość do narodu jest autentyczna i szlachetna. Oczyszczony przez egzorcyzmy, może stać się ''sługą wiary''. Być może przesłanie jest takie: prometejska energia musi zostać przemieniona i podporządkowana wyższemu celowi - ale sama w sobie prowadzi na manowce."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmiipdfyv00btqh7mxrj916cn', 'ESSAY', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 10, 'Omów funkcję idei mesjanistycznej w Dziadach cz. III jako odpowiedzi na klęskę powstania listopadowego.', '{"hints": ["Pomyśl o mesjanizmie jako sposobie radzenia sobie z traumą", "Rozważ funkcję nadziei w sytuacji beznadziejnej", "Zastanów się też nad ciemnymi stronami: pycha, cierpiętnictwo"], "instruction": "Napisz wypracowanie (300-400 słów), w którym:\n- przedstawisz kontekst historyczny: klęska powstania, trauma narodowa\n- wyjaśnisz, jak mesjanizm nadawał sens cierpieniu\n- zanalizujesz, jaką funkcję psychologiczną i społeczną pełniła ta idea\n- oceń zalety i zagrożenia związane z mesjanizmem"}', NULL, NULL, '{}', '{"sampleAnswer": "Klęska powstania listopadowego (1830-31) była traumą dla narodu polskiego. Dziesiątki tysięcy powstańców wyemigrowało (Wielka Emigracja), represje carskie się nasiliły, nadzieje na szybkie odzyskanie niepodległości legły w gruzach. W tej sytuacji pojawiło się fundamentalne pytanie: czy cierpienie Polski ma jakikolwiek sens?\n\nMesjanizm Mickiewicza był odpowiedzią na to pytanie. Przez analogię do Chrystusa nadawał cierpieniu Polski wymiar sakralny i zbawczy. Rozbiory nie są bezsensowną klęską - to ''ukrzyżowanie'', etap na drodze do ''zmartwychwstania''. Polska nie umiera naprawdę - jej ''śmierć'' jest pozorna, jak śmierć Chrystusa. Co więcej, przez swoje cierpienie Polska przyczyni się do zbawienia innych narodów.\n\nFunkcja psychologiczna tej idei była ogromna. Dawała nadzieję w sytuacji beznadziejnej. Przemieniała poczucie klęski w poczucie misji. Zamiast pytać ''dlaczego my?'' - pozwalała odpowiedzieć ''właśnie my, bo jesteśmy wybrani''. To nie porażka, lecz powołanie. Społecznie mesjanizm mobilizował do wytrwania, dawał sens emigracji i konspiracji.\n\nJednak mesjanizm niósł też zagrożenia. Mógł prowadzić do megalomanii narodowej - przekonania o wyższości moralnej nad innymi. Gloryfikacja cierpienia mogła usprawiedliwiać bierność: zamiast działać, wystarczy cierpieć. Wiara w zbawienie ''z góry'' mogła demobilizować.\n\nDziady cz. III pokazują tę ambiwalencję. Widzenie księdza Piotra daje nadzieję, ale pycha Konrada - też forma mesjanistyczna - prowadzi niemal do potępienia. Może przesłanie jest takie: mesjanizm jest lekarstwem na rozpacz, ale jak każde lekarstwo - w nadmiarze staje się trucizną."}', '2025-11-28 10:11:40.943', '2025-11-28 10:11:40.943', 'Dziady cz. III');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srky0002qh49cvxl92wq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kto jest autorem tragedii ''Król Edyp''?', '{"options": ["Ajschylos", "Eurypides", "Arystofanes", "Sofokles"]}', '3', NULL, '{Sofokles,antyk,autorstwo}', '{"explanation": "''Król Edyp'' to tragedia napisana przez Sofoklesa, jednego z trzech wielkich tragików greckich. Utwór powstał około 429 r. p.n.e."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srkz0003qh49ochrd3v5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'W jakim mieście toczy się akcja ''Króla Edypa''?', '{"options": ["Teby", "Ateny", "Korynt", "Delfy"]}', '0', NULL, '{Teby,"miejsce akcji"}', '{"explanation": "Akcja tragedii toczy się w Tebach, mieście, którego Edyp jest królem. Teby to starożytne miasto greckie w Beocji."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srkz0004qh496h0j49cl', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kim byli prawdziwi rodzice Edypa?', '{"options": ["Polybos i Meropa", "Kreon i Eurydyka", "Lajos i Jokasta", "Tyrezjasz i Antygona"]}', '2', NULL, '{Lajos,Jokasta,"rodzice Edypa"}', '{"explanation": "Prawdziwymi rodzicami Edypa byli Lajos (król Teb) i Jokasta (królowa Teb). Polybos i Meropa to przybrani rodzice z Koryntu."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srkz0005qh49fmy9fb5m', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kim byli przybrani rodzice Edypa?', '{"options": ["Lajos i Jokasta", "Polybos i Meropa", "Kreon i Eurydyka", "Zeus i Hera"]}', '1', NULL, '{Polybos,Meropa,Korynt}', '{"explanation": "Przybranymi rodzicami Edypa byli Polybos i Meropa - para królewska z Koryntu, którzy wychowali go jak własnego syna."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srkz0006qh49s7n1t2jk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co głosiła przepowiednia dana Lajosowi?', '{"options": ["Że zostanie królem Teb", "Że pokona Sfinksa", "Że ożeni się z boginią", "Że zginie z rąk własnego syna"]}', '3', NULL, '{przepowiednia,Lajos,fatum}', '{"explanation": "Wyrocznia delficka przepowiedziała Lajosowi, że zginie z rąk własnego syna. Ta przepowiednia była przyczyną porzucenia niemowlęcia Edypa."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srkz0007qh49jwk45qhn', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co głosiła przepowiednia dana Edypowi w Delfach?', '{"options": ["Że zabije ojca i poślubi matkę", "Że zostanie wielkim królem", "Że pokona wszystkich wrogów", "Że będzie żył wiecznie"]}', '0', NULL, '{przepowiednia,Edyp,fatum,wyrocznia}', '{"explanation": "Wyrocznia delficka przepowiedziała Edypowi, że zabije własnego ojca i poślubi własną matkę. Ta straszna przepowiednia skłoniła go do opuszczenia Koryntu."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srkz0008qh49daamlhfq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Dlaczego Edyp opuścił Korynt?', '{"options": ["Został wygnany przez króla", "Szukał przygód", "Chciał uniknąć spełnienia przepowiedni", "Został porwany przez rozbójników"]}', '2', NULL, '{Korynt,ucieczka,przepowiednia}', '{"explanation": "Edyp opuścił Korynt, by chronić Polybosa i Meropę, których uważał za swoich prawdziwych rodziców. Chciał uniknąć spełnienia strasznej przepowiedni."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srkz0009qh49w2j2yzqi', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Gdzie Edyp zabił swojego ojca Lajosa?', '{"options": ["W Tebach", "Na rozstaju trzech dróg", "W Koryncie", "W Delfach"]}', '1', NULL, '{"rozstaj dróg",ojcobójstwo,Lajos}', '{"explanation": "Edyp zabił Lajosa na rozstaju trzech dróg (w pobliżu Fokidy), nie wiedząc, że to jego biologiczny ojciec. Doszło tam do konfliktu o pierwszeństwo przejazdu."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srkz000aqh49pq074lnx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jakiego potwora pokonał Edyp, ratując Teby?', '{"options": ["Minotaura", "Meduze", "Hydrę", "Sfinksa"]}', '3', NULL, '{Sfinks,zagadka,Teby}', '{"explanation": "Edyp pokonał Sfinksa - potwora z głową kobiety i ciałem lwa, który zadawał podróżnym zagadkę i pożerał tych, którzy nie potrafili jej rozwiązać."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl0000bqh49dkmmry4w', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co było nagrodą za pokonanie Sfinksa?', '{"options": ["Tron Teb i ręka królowej", "Złoto i klejnoty", "Nieśmiertelność", "Własne królestwo w Koryncie"]}', '0', NULL, '{nagroda,Sfinks,Jokasta}', '{"explanation": "Za pokonanie Sfinksa Edyp otrzymał tron Teb i rękę królowej Jokasty - nie wiedząc, że to jego własna matka."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl0000cqh49y7ix7qvk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jaka plaga nawiedziła Teby na początku dramatu?', '{"options": ["Powódź", "Trzęsienie ziemi", "Najazd wrogów", "Zaraza (mór)"]}', '3', NULL, '{zaraza,Teby,"początek dramatu"}', '{"explanation": "Na początku dramatu Teby nawiedza straszliwa zaraza - ludzie umierają, kobiety rodzą martwe dzieci, plony gniją na polach."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl0000dqh49cc5b2l3o', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kim jest Kreon w dramacie?', '{"options": ["Ojcem Edypa", "Bratem Jokasty", "Ślepym wróżbitą", "Posłańcem z Koryntu"]}', '1', NULL, '{Kreon,postacie,Jokasta}', '{"explanation": "Kreon jest bratem Jokasty, a więc szwagrem (i zarazem wujem) Edypa. To on zostaje wysłany do Delf po odpowiedź wyroczni."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl0000eqh49x22dfd9u', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kim jest Tyrezjasz?', '{"options": ["Ślepym wróżbitą", "Królem Koryntu", "Posłańcem bogów", "Pasterzem z Kiteronu"]}', '0', NULL, '{Tyrezjasz,wróżbita,postacie}', '{"explanation": "Tyrezjasz to słynny ślepy wróżbita tebański, który zna prawdę o Edypie, ale początkowo nie chce jej wyjawić."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl0000fqh49oz579ud8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Ile dzieci miał Edyp z Jokastą?', '{"options": ["Dwoje", "Troje", "Czworo", "Nie miał dzieci"]}', '2', NULL, '{"dzieci Edypa",Antygona,Ismena,Polinejkes,Eteokles}', '{"explanation": "Edyp miał z Jokastą czworo dzieci: córki Antygonę i Ismenę oraz synów Polinejkesa i Eteoklesa."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl0000gqh49b5p5bejk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jak zginęła Jokasta?', '{"options": ["Została zamordowana", "Skoczyła ze skały", "Wypiła truciznę", "Powiesiła się"]}', '3', NULL, '{Jokasta,śmierć,samobójstwo}', '{"explanation": "Jokasta powiesiła się w pałacu po odkryciu straszliwej prawdy - że jej mąż Edyp jest jednocześnie jej synem."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl0000hqh49briq4tvo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Czym Edyp oślepił samego siebie?', '{"options": ["Nożem", "Rozżarzonym żelazem", "Szpilkami z szaty Jokasty", "Własnymi palcami"]}', '2', NULL, '{oślepienie,Edyp,samokaleczenie}', '{"explanation": "Edyp oślepił się szpilkami (zapinkami, broszami) wyrwanymi z szaty martwej Jokasty."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl0000iqh49wi9d8urg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Do jakiego rodzaju literackiego należy ''Król Edyp''?', '{"options": ["Epika", "Liryka", "Dramat", "Synkretyzm"]}', '2', NULL, '{dramat,gatunek,tragedia}', '{"explanation": "''Król Edyp'' to dramat - a konkretnie tragedia antyczna, jeden z trzech głównych rodzajów literackich."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl1000jqh49d4ej86qx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jaki gatunek literacki reprezentuje ''Król Edyp''?', '{"options": ["Tragedia", "Komedia", "Epos", "Satyra"]}', '0', NULL, '{tragedia,gatunek,antyk}', '{"explanation": "''Król Edyp'' to tragedia - gatunek dramatyczny przedstawiający konflikt wybitnej jednostki z siłami wyższymi, zakończony katastrofą."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl1000kqh497p4dpclb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co oznacza imię ''Edyp''?', '{"options": ["Szczęśliwy król", "Syn bogów", "Mądry władca", "Pękata stopa"]}', '3', NULL, '{imię,Edyp,etymologia}', '{"explanation": "Imię Edyp (gr. Oidipus) oznacza ''pękata stopa'' lub ''spuchnięta stopa'' - nawiązuje do ran na stopach, które zadano mu jako niemowlęciu przed porzuceniem."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl1000lqh493dx6x8fa', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Dlaczego niemowlęciu Edypowi przebito stopy?', '{"options": ["To był rytualny obrzęd", "By nie mógł wrócić do domu", "By można było go powiesić na drzewie i porzucić", "Zrobił to przypadkiem pasterz"]}', '2', NULL, '{stopy,porzucenie,niemowlę}', '{"explanation": "Niemowlęciu przebito i związano stopy, by można było powiesić je na gałęzi drzewa w górach Kiteronu, gdzie miało zginąć."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl1000mqh49kq1tar5f', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'W jakich górach porzucono niemowlę Edypa?', '{"options": ["Olimp", "Parnas", "Ida", "Kiteron"]}', '3', NULL, '{Kiteron,góry,porzucenie}', '{"explanation": "Niemowlę Edypa porzucono w górach Kiteronu - paśmie górskim między Beocją a Attyką."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl1000nqh49ykgn5wri', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Który bóg był patronem wyroczni, która przepowiedziała los Edypa?', '{"options": ["Zeus", "Apollo", "Ares", "Dionizos"]}', '1', NULL, '{Apollo,wyrocznia,Delfy,bogowie}', '{"explanation": "Apollo to bóg, którego wyrocznia w Delfach przepowiedziała los zarówno Lajosowi, jak i Edypowi. Wyrocznia delficka była najważniejszą wyrocznią w starożytnej Grecji."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl1000oqh497xw6t8ph', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Czym zajmował się chór w tragedii greckiej?', '{"options": ["Grał role głównych bohaterów", "Komentował wydarzenia i wyrażał uczucia zbiorowe", "Tylko śpiewał pieśni religijne", "Walczył z bohaterami"]}', '1', NULL, '{chór,"tragedia grecka",kompozycja}', '{"explanation": "Chór w tragedii greckiej komentował wydarzenia, wyrażał uczucia zbiorowe, reprezentował społeczność i formułował ogólne prawdy moralne."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl1000pqh49w3o5ggwf', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kogo reprezentuje chór w ''Królu Edypie''?', '{"options": ["Młodzież tebańską", "Kapłanów Apollina", "Żołnierzy królewskich", "Starców tebańskich"]}', '3', NULL, '{chór,starcy,Teby}', '{"explanation": "W ''Królu Edypie'' chór składa się ze starców tebańskich - reprezentantów ludu, którzy komentują wydarzenia i wyrażają troskę o losy miasta."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl2000qqh49s4yowe3j', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co to jest ''fatum''?', '{"options": ["Przeznaczenie, los, który musi się spełnić", "Rodzaj klątwy", "Bóg zemsty", "Rodzaj ofiary dla bogów"]}', '0', NULL, '{fatum,przeznaczenie,los}', '{"explanation": "Fatum to przeznaczenie, nieuchronny los wyznaczony przez bogów, którego nie można uniknąć ani zmienić. Jest centralnym pojęciem tragedii greckiej."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl2000rqh49ejp3lnoa', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jak kończy się dramat ''Król Edyp''?', '{"options": ["Edyp ginie w walce", "Edyp zostaje bogiem", "Edyp zostaje oślepiony i skazany na wygnanie", "Edyp odzyskuje tron"]}', '2', NULL, '{zakończenie,wygnanie,oślepienie}', '{"explanation": "Dramat kończy się tragicznie - Edyp sam się oślepia i zostaje skazany na wygnanie z Teb, które tak dobrze rządził."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl2000sqh49j7s51n9k', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest ''hybris'' w tragedii greckiej?', '{"options": ["Miłość do ojczyzny", "Wierność bogom", "Pycha, nadmierna duma obrażająca bogów", "Odwaga wojownika"]}', '2', NULL, '{hybris,pycha,"tragedia grecka"}', '{"explanation": "Hybris to pycha, nadmierna pewność siebie i duma, która obraża bogów i prowadzi do upadku bohatera. U Edypa przejawia się m.in. w przekonaniu, że może oszukać przeznaczenie."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl2000tqh49726hgxtb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest ''hamartia''?', '{"options": ["Błąd tragiczny, wina bohatera prowadząca do katastrofy", "Końcowa pieśń chóru", "Mowa bohatera do publiczności", "Zmiana losu na lepsze"]}', '0', NULL, '{hamartia,"błąd tragiczny",Arystoteles}', '{"explanation": "Hamartia to błąd tragiczny, wina lub pomyłka bohatera, która prowadzi do jego upadku. U Edypa to zarówno pycha, jak i nieświadomość własnej tożsamości."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl2000uqh49uswnl660', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest ''perypetia''?', '{"options": ["Pieśń pochwalna", "Końcowe przemówienie", "Wejście chóru", "Nagły zwrot akcji, odmiana losu"]}', '3', NULL, '{perypetia,"zwrot akcji",Arystoteles}', '{"explanation": "Perypetia to nagły zwrot akcji, gwałtowna odmiana losu bohatera - zwykle z dobrego na zły. W ''Królu Edypie'' następuje gdy Edyp odkrywa, kim naprawdę jest."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl2000vqh49pkfwof50', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest ''anagnorisis''?', '{"options": ["Klątwa rzucona przez bogów", "Moment rozpoznania, odkrycia prawdy", "Samobójstwo bohatera", "Interwencja bogów"]}', '1', NULL, '{anagnorisis,rozpoznanie,Arystoteles}', '{"explanation": "Anagnorisis to moment rozpoznania, nagłego odkrycia prawdy przez bohatera. W ''Królu Edypie'' następuje gdy Edyp uświadamia sobie, że sam jest mordercą Lajosa i synem Jokasty."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl3000wqh49d4m3r92e', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest ''katharsis''?', '{"options": ["Przekleństwo bogów", "Rytuał ofiarny", "Oczyszczenie duszy widza przez litość i trwogę", "Śmierć bohatera"]}', '2', NULL, '{katharsis,oczyszczenie,Arystoteles}', '{"explanation": "Katharsis to oczyszczenie duszy widza przez przeżycie litości i trwogi podczas oglądania tragedii. To cel tragedii według Arystotelesa."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl3000xqh498x2feq7a', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest ''ironia tragiczna''?', '{"options": ["Sytuacja gdy widz wie więcej niż bohater", "Żart opowiedziany przez bohatera", "Kpina z bogów", "Fałszywa przepowiednia"]}', '0', NULL, '{"ironia tragiczna","ironia dramatyczna",dramatyzm}', '{"explanation": "Ironia tragiczna (dramatyczna) to sytuacja, gdy widz wie więcej niż bohater - np. wie, że Edyp przeklina sam siebie, szukając mordercy Lajosa."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl3000yqh49su8ypp5g', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Który filozof uznał ''Króla Edypa'' za wzorcową tragedię?', '{"options": ["Platon", "Sokrates", "Heraklit", "Arystoteles"]}', '3', NULL, '{Arystoteles,Poetyka,"wzorcowa tragedia"}', '{"explanation": "Arystoteles w swojej ''Poetyce'' uznał ''Króla Edypa'' za wzorcową realizację tragedii, idealnie spełniającą wszystkie wymagania gatunku."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl3000zqh499dwcj5fp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co Edyp obiecuje zrobić z mordercą Lajosa?', '{"options": ["Nagrodzić go", "Uczynić go królem", "Wygnać go i obłożyć klątwą", "Oddać mu Jokastę"]}', '2', NULL, '{klątwa,wygnanie,"ironia tragiczna"}', '{"explanation": "Edyp publicznie obiecuje wygnać mordercę Lajosa i obłożyć go klątwą - nie wiedząc, że tym samym przeklina samego siebie."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl30010qh49ir1hwub6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Dlaczego Tyrezjasz początkowo nie chce wyjawić prawdy?', '{"options": ["Nie zna odpowiedzi", "Boi się gniewu bogów", "Został przekupiony przez Kreona", "Wie, że prawda zniszczy Edypa"]}', '3', NULL, '{Tyrezjasz,prawda,współczucie}', '{"explanation": "Tyrezjasz wie, że wyjawienie prawdy zniszczy Edypa, dlatego początkowo milczy. Mówi: ''Biada, o biada tej wiedzy, co szkodę niesie wiedzącym''."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl30011qh49xhkdwacn', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'O co Edyp niesłusznie oskarża Kreona?', '{"options": ["O zabójstwo Lajosa", "O spisek mający na celu przejęcie tronu", "O romans z Jokastą", "O kradzież skarbca"]}', '1', NULL, '{Kreon,oskarżenie,spisek}', '{"explanation": "Edyp niesłusznie oskarża Kreona o spisek z Tyrezjaszem, mający na celu obalenie go i przejęcie tronu Teb."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl30012qh49orx6xblc', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jaka cecha charakteru Edypa prowadzi go do odkrycia prawdy?', '{"options": ["Chciwość", "Tchórzostwo", "Lenistwo", "Upór i dążenie do prawdy"]}', '3', NULL, '{"charakter Edypa",upór,prawda}', '{"explanation": "Paradoksalnie to pozytywna cecha Edypa - upór i nieugięte dążenie do prawdy - prowadzi go do katastrofy. Nie chce poprzestać na niepełnej wiedzy."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl30013qh49frhympla', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Czym jest ''konflikt tragiczny'' w dramacie?', '{"options": ["Sporem między bohaterami", "Walką zbrojną", "Zderzeniem jednostki z siłą wyższą, bez możliwości zwycięstwa", "Kłótnią rodzinną"]}', '2', NULL, '{"konflikt tragiczny","tragedia grecka",fatum}', '{"explanation": "Konflikt tragiczny to zderzenie wybitnej jednostki z siłą wyższą (bogami, przeznaczeniem, prawami moralnymi), w którym bohater nie ma szans na zwycięstwo."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl40014qh49teoa8fej', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co przynosi posłaniec z Koryntu?', '{"options": ["Wieść o wojnie", "Złoto od króla", "Wieść o śmierci Polybosa i propozycję tronu dla Edypa", "Rozkaz aresztowania Edypa"]}', '2', NULL, '{posłaniec,Korynt,Polybos}', '{"explanation": "Posłaniec przynosi wieść o śmierci Polybosa (przybranego ojca Edypa) i propozycję objęcia tronu Koryntu. Paradoksalnie ta ''dobra'' wiadomość przyspiesza odkrycie prawdy."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl40015qh49dclt3to4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jaką funkcję pełni prolog w tragedii greckiej?', '{"options": ["Kończy dramat", "Wprowadza widza w sytuację przed rozpoczęciem właściwej akcji", "Zawiera tylko pieśni chóru", "Przedstawia bogów"]}', '1', NULL, '{prolog,"kompozycja tragedii",wstęp}', '{"explanation": "Prolog to część wstępna tragedii, która wprowadza widza w sytuację i przedstawia okoliczności przed wejściem chóru i rozpoczęciem właściwej akcji."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl40016qh494wniq2qc', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest ''parodos'' w tragedii greckiej?', '{"options": ["Pieśń chóru wchodzącego na orchestrę", "Końcowa mowa bohatera", "Monolog króla", "Scena walki"]}', '0', NULL, '{parodos,chór,"kompozycja tragedii"}', '{"explanation": "Parodos to pieśń chóru wchodzącego na orchestrę - pierwszy występ chóru w tragedii, następujący po prologu."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl40017qh49z747mhxp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest ''stasimon'' w tragedii greckiej?', '{"options": ["Pieśń chóru wykonywana między epizodami", "Scena walki", "Przemowa bohatera", "Wejście posłańca"]}', '0', NULL, '{stasimon,chór,"kompozycja tragedii"}', '{"explanation": "Stasimon to pieśń chóru stojącego na orchestrze, wykonywana między epizodami (aktami) tragedii. Służy komentowaniu wydarzeń."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl40018qh49u0tnni4q', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest ''eksodos'' w tragedii greckiej?', '{"options": ["Początek dramatu", "Środkowa część tragedii", "Pieśń pochwalna", "Końcowa część tragedii, wyjście chóru"]}', '3', NULL, '{eksodos,zakończenie,"kompozycja tragedii"}', '{"explanation": "Eksodos to końcowa część tragedii, obejmująca ostatnie wydarzenia i wyjście chóru z orchestry. Zawiera często podsumowanie i morał."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl40019qh49fy8yhk9g', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Ile jedności obowiązywało w tragedii greckiej według klasycystów?', '{"options": ["Jedna", "Dwie", "Cztery", "Trzy"]}', '3', NULL, '{"trzy jedności","zasady dramatu",klasycyzm}', '{"explanation": "W tragedii greckiej (według późniejszej interpretacji klasycystów) obowiązywały trzy jedności: miejsca, czasu i akcji."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl4001aqh49riakc2ot', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Która z trzech jedności oznacza, że akcja powinna trwać nie dłużej niż jeden dzień?', '{"options": ["Jedność miejsca", "Jedność akcji", "Jedność stylu", "Jedność czasu"]}', '3', NULL, '{"jedność czasu","trzy jedności","zasady dramatu"}', '{"explanation": "Jedność czasu wymaga, by akcja dramatu trwała nie dłużej niż 24 godziny (jeden obrót słońca). ''Król Edyp'' spełnia tę zasadę."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl5001bqh49sxjxvzzo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kto prowadzi dialog z chórem w imieniu całej grupy?', '{"options": ["Protagonist", "Deuteragonista", "Herold", "Koryfej"]}', '3', NULL, '{koryfej,chór,"przewodnik chóru"}', '{"explanation": "Koryfej to przewodnik chóru, który prowadził dialogi z aktorami w imieniu całej grupy chórzystów."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl5001cqh498i42nl03', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Dlaczego Edyp się oślepia zamiast popełnić samobójstwo?', '{"options": ["Boi się śmierci", "Chce żyć, by cierpieć jako kara, i nie chce widzieć rodziny w Hadesie", "Bogowie mu zabraniają", "Kreon go powstrzymuje"]}', '1', NULL, '{oślepienie,kara,samoukaranie}', '{"explanation": "Edyp wybiera oślepienie jako formę kary - chce żyć w ciemności i cierpieniu. Nie chce też po śmierci spotkać w Hadesie rodziców, których tak zhańbił."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl5001dqh497n2tpu7h', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jaką rolę pełni pasterz z Kiteronu w dramacie?', '{"options": ["Jest mordercą Lajosa", "Pomaga Edypowi uciec", "Dostarcza ostatecznego dowodu na tożsamość Edypa", "Zabija Jokastę"]}', '2', NULL, '{pasterz,Kiteron,świadek}', '{"explanation": "Pasterz z Kiteronu to były sługa Lajosa, który zamiast zabić niemowlę, oddał je pasterzowi z Koryntu. Jego zeznanie ostatecznie potwierdza tożsamość Edypa."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl5001eqh49894vmsgy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jak Jokasta próbuje uspokoić Edypa co do przepowiedni?', '{"options": ["Mówi, że przepowiednie zawsze się spełniają", "Radzi mu uciec z Teb", "Podaje przykład ''niespełnionej'' przepowiedni o śmierci Lajosa", "Każe zabić Tyrezjasza"]}', '2', NULL, '{Jokasta,przepowiednia,"ironia tragiczna"}', '{"explanation": "Jokasta próbuje uspokoić Edypa, mówiąc że przepowiednie są fałszywe - bo Lajos miał zginąć z rąk syna, a przecież syn umarł jako niemowlę. Nie wie, jak bardzo się myli."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl5001fqh49nhnhzpxo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co symbolizuje ślepota w ''Królu Edypie''?', '{"options": ["Fizyczną słabość", "Karę bogów za bluźnierstwo", "Duchową mądrość vs. duchową ślepotę", "Starość"]}', '2', NULL, '{ślepota,symbol,Tyrezjasz}', '{"explanation": "Ślepota symbolizuje paradoks mądrości i niewiedzy: ślepy Tyrezjasz ''widzi'' prawdę, podczas gdy widzący Edyp jest ''ślepy'' na prawdę o sobie. Na końcu Edyp sam się oślepia, jakby uznając tę symboliczną prawdę."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl5001gqh49w2atndps', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Która córka Edypa jest bohaterką innej tragedii Sofoklesa?', '{"options": ["Ismena", "Helena", "Elektra", "Antygona"]}', '3', NULL, '{Antygona,"córka Edypa",Sofokles}', '{"explanation": "Antygona, córka Edypa, jest tytułową bohaterką innej tragedii Sofoklesa. Opowiada ona o konflikcie między prawem boskim a ludzkim."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl5001hqh49i2tagbgo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co oznacza greckie słowo ''tragoidia''?', '{"options": ["Smutna opowieść", "Wielki dramat", "Pieśń kozła", "Płacz bogów"]}', '2', NULL, '{tragedia,etymologia,kozioł}', '{"explanation": "''Tragoidia'' dosłownie oznacza ''pieśń kozła'' (tragos = kozioł, oide = pieśń). Wiąże się to prawdopodobnie z rytuałami ku czci Dionizosa, z których wywodzi się tragedia."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl6001iqh490d3kq55v', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Na cześć jakiego boga odbywały się przedstawienia tragiczne w Atenach?', '{"options": ["Zeusa", "Apollina", "Aresa", "Dionizosa"]}', '3', NULL, '{Dionizos,"teatr grecki",festiwal}', '{"explanation": "Przedstawienia tragiczne odbywały się podczas Wielkich Dionizjów - święta ku czci Dionizosa, boga wina, płodności i teatru."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl6001jqh49ob71ng1i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Czym różni się tragizm Edypa od tragizmu Antygony?', '{"options": ["Edyp świadomie wybiera zło, Antygona - dobro", "Edyp jest niewinny, Antygona winna", "Edyp działa nieświadomie, Antygona świadomie wybiera między dwiema wartościami", "Nie ma żadnej różnicy"]}', '2', NULL, '{tragizm,Antygona,porównanie}', '{"explanation": "Edyp popełnia zbrodnie nieświadomie (ironia tragiczna), podczas gdy Antygona świadomie dokonuje wyboru między prawem boskim a ludzkim, wiedząc o konsekwencjach."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl6001kqh49r80rjgj2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jakie przesłanie formułuje chór w słowach końcowych dramatu?', '{"options": ["Że bogowie są niesprawiedliwi", "Że Edyp był dobrym królem", "Że nikogo nie można nazwać szczęśliwym przed końcem życia", "Że należy uciekać przed przeznaczeniem"]}', '2', NULL, '{przesłanie,chór,mądrość}', '{"explanation": "Chór kończy dramat słowami: ''śmiertelnika tu żadnego zwać szczęśliwym nie należy, aż bez cierpień i bez klęski krańców życia nie przebieży'' - to przestroga przed przedwczesnym osądzaniem losu."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl6001lqh49hynaxvim', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jak nazywa się zasada decorum w tragedii greckiej?', '{"options": ["Wymóg pokazywania scen przemocy", "Wymóg komicznych wstawek", "Wymóg szczęśliwego zakończenia", "Wymóg stosowności - bohater musi odpowiadać swojej pozycji społecznej"]}', '3', NULL, '{decorum,stosowność,"zasady dramatu"}', '{"explanation": "Decorum to zasada stosowności wymagająca, by bohater tragiczny był postacią wysokiego stanu i zachowywał się odpowiednio do swojej pozycji. Edyp jako król spełnia ten wymóg."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl6001mqh49sw5wphgt', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Dlaczego sceny przemocy nie były pokazywane na scenie greckiej?', '{"options": ["Obowiązywała zasada decorum i szacunek dla widza", "Brakowało efektów specjalnych", "Aktorzy nie umieli grać takich scen", "Bogowie tego zakazywali"]}', '0', NULL, '{przemoc,decorum,"teatr grecki"}', '{"explanation": "Zasada decorum i szacunek dla widza wymagały, by sceny przemocy (jak samobójstwo Jokasty czy oślepienie Edypa) działy się poza sceną, a relacjonował je posłaniec."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl6001nqh49z5df9w9u', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 2, 'Które postacie są dziećmi Edypa i Jokasty?', '{"options": ["Antygona", "Kreon", "Ismena", "Tyrezjasz", "Eteokles"]}', '[0, 2, 4]', NULL, '{"dzieci Edypa",Antygona,Ismena,Eteokles}', '{"explanation": "Dziećmi Edypa i Jokasty są: Antygona, Ismena (córki) oraz Eteokles i Polinejkes (synowie). Kreon to brat Jokasty, a Tyrezjasz to wróżbita."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl6001oqh492pz3f8bo', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 2, 'Które stwierdzenia o Edypie są prawdziwe?', '{"options": ["Pokonał Sfinksa", "Był synem Polybosa i Meropy biologicznie", "Ożenił się z własną matką", "Zabił własnego ojca", "Urodził się w Koryncie"]}', '[0, 2, 3]', NULL, '{Edyp,fakty,biografia}', '{"explanation": "Edyp pokonał Sfinksa, ożenił się z matką Jokastą i zabił ojca Lajosa. Polybos i Meropa byli jego przybranymi rodzicami, a urodził się w Tebach."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl7001pqh49139o2k0d', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 2, 'Które zbrodnie popełnił Edyp (nawet nieświadomie)?', '{"options": ["Ojcobójstwo", "Kazirodztwo", "Kradzież", "Zdradę stanu", "Bluźnierstwo"]}', '[0, 1]', NULL, '{zbrodnie,ojcobójstwo,kazirodztwo}', '{"explanation": "Edyp popełnił dwie najcięższe zbrodnie w pojęciu starożytnych Greków: ojcobójstwo (zabił Lajosa) i kazirodztwo (poślubił matkę Jokastę)."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl7001qqh49892luqdf', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 2, 'Które miasta są związane z historią Edypa?', '{"options": ["Teby", "Ateny", "Korynt", "Sparta", "Delfy"]}', '[0, 2, 4]', NULL, '{Teby,Korynt,Delfy,miejsca}', '{"explanation": "Teby - miejsce urodzenia i panowania Edypa. Korynt - gdzie wychowali go przybrani rodzice. Delfy - gdzie usłyszał przepowiednię od wyroczni."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl7001rqh49djlxk879', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Które elementy należą do struktury tragedii greckiej?', '{"options": ["Prolog", "Parodos", "Intermezzo", "Stasimon", "Eksodos"]}', '[0, 1, 3, 4]', NULL, '{"struktura tragedii",prolog,parodos,stasimon,eksodos}', '{"explanation": "Struktura tragedii greckiej obejmuje: prolog (wstęp), parodos (wejście chóru), epizody i stasimony (pieśni chóru), eksodos (zakończenie). Intermezzo to element opery, nie tragedii."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl7001sqh493utclkqy', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Które cechy charakteryzują bohatera tragicznego według Arystotelesa?', '{"options": ["Wysokie urodzenie", "Całkowita niewinność", "Hamartia (błąd tragiczny)", "Szczęśliwe zakończenie", "Wzbudzanie litości i trwogi"]}', '[0, 2, 4]', NULL, '{"bohater tragiczny",Arystoteles,hamartia}', '{"explanation": "Bohater tragiczny według Arystotelesa: wysoko urodzony, popełnia hamartię (błąd), wzbudza litość i trwogę. Nie jest całkowicie niewinny ani całkowicie zły, a jego los kończy się katastrofą."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl7001tqh49fy0xbk7a', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Które terminy związane z tragedią grecką pochodzą z ''Poetyki'' Arystotelesa?', '{"options": ["Katharsis", "Leitmotiv", "Perypetia", "Anagnorisis", "Collage"]}', '[0, 2, 3]', NULL, '{Arystoteles,Poetyka,terminy}', '{"explanation": "Z ''Poetyki'' Arystotelesa pochodzą: katharsis (oczyszczenie), perypetia (zwrot akcji), anagnorisis (rozpoznanie). Leitmotiv to termin muzyczny, collage - z sztuk plastycznych."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl7001uqh496s15gh04', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Które z poniższych są przykładami ironii tragicznej w ''Królu Edypie''?', '{"options": ["Edyp przeklina mordercę Lajosa, nie wiedząc, że to on sam", "Edyp szydzi ze ''ślepoty'' Tyrezjasza", "Jokasta podaje przykład ''niespełnionej'' przepowiedni", "Kreon zostaje oskarżony o spisek", "Edyp ucieka z Koryntu, by uniknąć przepowiedni"]}', '[0, 1, 2, 4]', NULL, '{"ironia tragiczna",paradoks,nieświadomość}', '{"explanation": "Wszystkie te sytuacje oprócz oskarżenia Kreona są przykładami ironii tragicznej - bohaterowie mówią lub działają, nie znając prawdy, którą zna widz."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl7001vqh49t0ngr7ph', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Które funkcje pełni chór w ''Królu Edypie''?', '{"options": ["Komentuje wydarzenia", "Walczy z bohaterami", "Reprezentuje społeczność tebańską", "Formułuje prawdy ogólne", "Zabija Jokastę"]}', '[0, 2, 3]', NULL, '{chór,"funkcje chóru",komentarz}', '{"explanation": "Chór komentuje wydarzenia, reprezentuje społeczność (starców tebańskich), formułuje prawdy ogólne o życiu i losie. Nie bierze udziału w akcji fizycznej."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl7001wqh49lfjg1wnf', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Które cechy charakteryzują Edypa jako władcę?', '{"options": ["Troska o poddanych", "Chciwość", "Dążenie do prawdy", "Tchórzostwo", "Poczucie odpowiedzialności"]}', '[0, 2, 4]', NULL, '{Edyp,władca,"cechy pozytywne"}', '{"explanation": "Edyp to dobry władca: troszczy się o poddanych (chce uwolnić miasto od zarazy), dąży do prawdy i czuje się odpowiedzialny za los Teb."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl8001xqh49m5hdbur8', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Dopasuj postać do jej roli w dramacie.', '{"leftColumn": [{"id": "A", "text": "Tyrezjasz"}, {"id": "B", "text": "Kreon"}, {"id": "C", "text": "Jokasta"}], "rightColumn": [{"id": "1", "text": "brat królowej"}, {"id": "2", "text": "ślepy wróżbita"}, {"id": "3", "text": "żona i matka Edypa"}], "matchingType": "character_role"}', '[[0, 1], [1, 0], [2, 2]]', NULL, '{postacie,dopasowanie,role}', '{"explanation": "Tyrezjasz - ślepy wróżbita, Kreon - brat królowej Jokasty, Jokasta - żona i jednocześnie matka Edypa."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl8001yqh49i7nmi571', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Dopasuj termin do jego znaczenia.', '{"leftColumn": [{"id": "A", "text": "Hybris"}, {"id": "B", "text": "Katharsis"}, {"id": "C", "text": "Fatum"}], "rightColumn": [{"id": "1", "text": "przeznaczenie"}, {"id": "2", "text": "pycha"}, {"id": "3", "text": "oczyszczenie"}], "matchingType": "term_definition"}', '[[0, 1], [1, 2], [2, 0]]', NULL, '{terminy,definicje,dopasowanie}', '{"explanation": "Hybris - pycha obrażająca bogów, katharsis - oczyszczenie duszy widza, fatum - nieuchronne przeznaczenie."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl8001zqh49jxx2mdim', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Dopasuj miejsce do wydarzenia z życia Edypa.', '{"leftColumn": [{"id": "A", "text": "Kiteron"}, {"id": "B", "text": "Rozstaj trzech dróg"}, {"id": "C", "text": "Delfy"}], "rightColumn": [{"id": "1", "text": "zabójstwo Lajosa"}, {"id": "2", "text": "porzucenie niemowlęcia"}, {"id": "3", "text": "otrzymanie przepowiedni"}], "matchingType": "place_event"}', '[[0, 1], [1, 0], [2, 2]]', NULL, '{miejsca,wydarzenia,dopasowanie}', '{"explanation": "Kiteron - góry, gdzie porzucono niemowlę. Rozstaj trzech dróg - miejsce zabójstwa Lajosa. Delfy - wyrocznia, gdzie Edyp usłyszał przepowiednię."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl80020qh49n54n0rl3', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Dopasuj element struktury tragedii do jego opisu.', '{"leftColumn": [{"id": "A", "text": "Prolog"}, {"id": "B", "text": "Parodos"}, {"id": "C", "text": "Eksodos"}], "rightColumn": [{"id": "1", "text": "wejście chóru"}, {"id": "2", "text": "część wstępna"}, {"id": "3", "text": "zakończenie i wyjście chóru"}], "matchingType": "structure_description"}', '[[0, 1], [1, 0], [2, 2]]', NULL, '{struktura,tragedia,kompozycja}', '{"explanation": "Prolog - część wstępna przed wejściem chóru. Parodos - pieśń towarzysząca wejściu chóru. Eksodos - zakończenie z wyjściem chóru."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl80021qh49kwrpjucp', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 2, 'Uzupełnij zdanie o przepowiedni danej Edypowi.', '{"gaps": [{"id": 1, "options": ["Atenach", "Delfach", "Tebach", "Koryncie"]}, {"id": 2, "options": ["uratuje", "zabije", "znajdzie", "opuści"]}, {"id": 3, "options": ["opuści", "zabije", "poślubi", "znajdzie"]}], "textWithGaps": "Wyrocznia w [1] przepowiedziała Edypowi, że [2] własnego ojca i [3] własną matkę."}', '[1, 1, 2]', NULL, '{przepowiednia,wyrocznia,uzupełnianka}', '{"explanation": "Wyrocznia w Delfach przepowiedziała Edypowi, że zabije własnego ojca i poślubi własną matkę."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl90022qh490iirlxoc', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 2, 'Uzupełnij informacje o nagrodzie za pokonanie Sfinksa.', '{"gaps": [{"id": 1, "options": ["Minotaura", "Sfinksa", "Hydry", "Meduzy"]}, {"id": 2, "options": ["Aten", "Koryntu", "Teb", "Sparty"]}, {"id": 3, "options": ["Heleny", "Jokasty", "Antygony", "Ismeny"]}], "textWithGaps": "Za pokonanie [1] Edyp otrzymał tron [2] i rękę królowej [3]."}', '[1, 2, 1]', NULL, '{Sfinks,nagroda,Jokasta}', '{"explanation": "Za pokonanie Sfinksa Edyp otrzymał tron Teb i rękę królowej Jokasty."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl90023qh499hsfclsu', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Uzupełnij informacje o strukturze tragedii.', '{"gaps": [{"id": 1, "options": ["eksodosu", "prologu", "stasimonu", "epizodu"]}, {"id": 2, "options": ["prologu", "eksodosu", "parodosu", "stasimonu"]}, {"id": 3, "options": ["parodosu", "prologu", "eksodosu", "stasimonu"]}], "textWithGaps": "Tragedia grecka składa się z [1] (części wstępnej), [2] (pieśni wejścia chóru), epizodów i stasimonów oraz [3] (zakończenia)."}', '[1, 2, 2]', NULL, '{struktura,tragedia,kompozycja}', '{"explanation": "Tragedia grecka: prolog (wstęp), parodos (pieśń wejścia chóru), epizody i stasimony, eksodos (zakończenie)."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl90024qh49lkglylsu', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Uzupełnij informacje o katharsis.', '{"gaps": [{"id": 1, "options": ["Platona", "Sokratesa", "Arystotelesa", "Heraklita"]}, {"id": 2, "options": ["zniszczenie", "oczyszczenie", "wzmocnienie", "osłabienie"]}, {"id": 3, "options": ["gniewu", "radości", "litości", "obojętności"]}], "textWithGaps": "Według [1] celem tragedii jest katharsis, czyli [2] duszy widza przez przeżycie [3] i trwogi."}', '[2, 1, 2]', NULL, '{katharsis,Arystoteles,tragedia}', '{"explanation": "Według Arystotelesa celem tragedii jest katharsis - oczyszczenie duszy widza przez przeżycie litości i trwogi."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl90025qh49g5t0rbmn', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Uzupełnij informacje o ironii tragicznej.', '{"gaps": [{"id": 1, "options": ["bohater", "chór", "widz", "autor"]}, {"id": 2, "options": ["widz", "bohater", "chór", "bogowie"]}, {"id": 3, "options": ["chwali", "przeklina", "nagradza", "chroni"]}], "textWithGaps": "Ironia tragiczna polega na tym, że [1] wie więcej niż [2]. W ''Królu Edypie'' wiemy, że Edyp [3] sam siebie, szukając mordercy Lajosa."}', '[2, 1, 1]', NULL, '{"ironia tragiczna",widz,bohater}', '{"explanation": "Ironia tragiczna: widz wie więcej niż bohater. Wiemy, że Edyp przeklina sam siebie, szukając mordercy Lajosa."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl90026qh493jai95vs', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, na czym polega ironia tragiczna w scenie, gdy Edyp przeklina mordercę Lajosa.', '{"requirements": ["Wyjaśnienie pojęcia ironii tragicznej", "Wskazanie, że Edyp nie wie, iż przeklina samego siebie", "Podkreślenie kontrastu między wiedzą widza a niewiedzą bohatera"]}', NULL, NULL, '{"ironia tragiczna",klątwa,analiza}', '{"sampleAnswer": "Ironia tragiczna polega na tym, że widz wie więcej niż bohater. W tej scenie Edyp publicznie przeklina mordercę Lajosa i zapowiada mu wygnanie - nie wiedząc, że to on sam zabił króla. Widz zna prawdę i obserwuje, jak Edyp nieświadomie ściąga klątwę na własną głowę, co potęguje tragizm sytuacji."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl90027qh492mkz34g2', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, dlaczego próby ucieczki przed przeznaczeniem paradoksalnie doprowadziły do jego spełnienia.', '{"requirements": ["Wskazanie działań Lajosa (porzucenie syna)", "Wskazanie działań Edypa (ucieczka z Koryntu)", "Wyjaśnienie paradoksu - ucieczka prowadzi do spełnienia przepowiedni"]}', NULL, NULL, '{fatum,paradoks,przepowiednia}', '{"sampleAnswer": "Lajos porzucił syna w górach, by uniknąć śmierci z jego rąk - ale dzięki temu Edyp trafił do Koryntu i nie znał prawdziwych rodziców. Edyp uciekł z Koryntu, by nie zabić ojca - ale właśnie ta ucieczka doprowadziła go na rozstaj dróg, gdzie zabił Lajosa. Paradoks polega na tym, że działania mające zapobiec przepowiedni stały się narzędziem jej spełnienia."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srl90028qh49tdzlfgou', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij symboliczne znaczenie ślepoty w dramacie ''Król Edyp''.', '{"requirements": ["Porównanie ślepego Tyrezjasza i widzącego Edypa", "Wskazanie na paradoks: ślepiec widzi prawdę, widzący jest ślepy duchowo", "Odniesienie do samooślepienia Edypa"]}', NULL, NULL, '{ślepota,symbol,Tyrezjasz,Edyp}', '{"sampleAnswer": "Ślepota symbolizuje paradoks mądrości i niewiedzy. Ślepy Tyrezjasz ''widzi'' prawdę o Edypie, podczas gdy widzący król jest ''ślepy'' na własną tożsamość. Gdy Edyp w końcu ''przejrzał'' (poznał prawdę), sam się oślepił - jakby uznając, że wzrok fizyczny jest bezwartościowy wobec ślepoty duchowej, jakiej doświadczał."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srla0029qh49gmzxzfjp', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, na czym polega konflikt tragiczny w ''Królu Edypie''.', '{"requirements": ["Definicja konfliktu tragicznego", "Wskazanie stron konfliktu (jednostka vs fatum)", "Podkreślenie nieuchronności klęski bohatera"]}', NULL, NULL, '{"konflikt tragiczny",fatum,jednostka}', '{"sampleAnswer": "Konflikt tragiczny to zderzenie wybitnej jednostki z siłą wyższą, w którym bohater nie może zwyciężyć. W ''Królu Edypie'' jest to starcie Edypa z fatum - nieuchronnym przeznaczeniem. Mimo inteligencji, dobrych intencji i władzy królewskiej, Edyp nie może uciec przed losem wyznaczonym przez bogów. Każda jego próba uniknięcia przepowiedni przybliża jej spełnienie."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srla002aqh49wta4xw33', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, czym jest hamartia i jak przejawia się u Edypa.', '{"requirements": ["Definicja hamartii (błąd tragiczny)", "Wskazanie przejawów hamartii u Edypa", "Związek między hamartią a upadkiem bohatera"]}', NULL, NULL, '{hamartia,"błąd tragiczny",Arystoteles}', '{"sampleAnswer": "Hamartia to błąd tragiczny bohatera prowadzący do jego upadku. U Edypa przejawia się na dwóch poziomach: jako hybris (pycha, przekonanie o możliwości oszukania losu) oraz jako nieświadomość własnej tożsamości. Jego upór w dążeniu do prawdy, choć sam w sobie szlachetny, prowadzi do katastrofy - odkrycia, że sam jest mordercą i kazirodcą."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srla002bqh49q0ayb4uv', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Jakie funkcje pełni chór w tragedii ''Król Edyp''? Podaj trzy przykłady.', '{"requirements": ["Wymienienie trzech funkcji chóru", "Odniesienie do konkretnych scen lub wypowiedzi chóru", "Wskazanie znaczenia chóru dla odbioru tragedii"]}', NULL, NULL, '{chór,funkcje,"tragedia grecka"}', '{"sampleAnswer": "Chór pełni trzy główne funkcje: 1) komentuje wydarzenia - np. wyraża wątpliwości po oskarżeniach Tyrezjasza; 2) reprezentuje społeczność tebańską - błaga bogów o ratunek od zarazy; 3) formułuje prawdy ogólne - kończy dramat sentencją o kruchości ludzkiego szczęścia. Chór pomaga widzowi zrozumieć głębszy sens wydarzeń."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srla002cqh498at5dmbc', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, dlaczego Edyp wybrał oślepienie zamiast samobójstwa.', '{"requirements": ["Wskazanie motywacji Edypa", "Odniesienie do pojęcia kary i cierpienia", "Związek z Hadesem i rodziną"]}', NULL, NULL, '{oślepienie,kara,samoukaranie}', '{"sampleAnswer": "Edyp wybrał oślepienie jako formę kary surowszej niż śmierć - chciał żyć w ciemności i cierpieniu, by odpokutować zbrodnie. Ponadto nie chciał po śmierci spotkać w Hadesie rodziców, których tak zhańbił. Oślepienie jest też symbolicznym aktem - skoro jego oczy nie dostrzegły prawdy, gdy widział, to nie zasługują na oglądanie czegokolwiek."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srla002dqh49wtg4g623', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, co oznacza przesłanie końcowe chóru: ''śmiertelnika tu żadnego zwać szczęśliwym nie należy''.', '{"requirements": ["Interpretacja sentencji", "Odniesienie do losu Edypa", "Uniwersalne znaczenie przesłania"]}', NULL, NULL, '{przesłanie,chór,mądrość}', '{"sampleAnswer": "Chór głosi, że nikogo nie można nazwać szczęśliwym, dopóki nie zakończy życia. Los Edypa - z potężnego, mądrego króla stał się ślepym wygnańcem - pokazuje, jak gwałtownie może się odmienić fortuna. Przesłanie ma wymiar uniwersalny: przestrzega przed pychą i przypomina o kruchości ludzkiego szczęścia. Dopiero śmierć kończy niepewność losu."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srla002eqh49zu0snyt7', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Porównaj postawę Edypa i Jokasty wobec przepowiedni i prawdy.', '{"requirements": ["Charakterystyka postawy Edypa (dążenie do prawdy)", "Charakterystyka postawy Jokasty (unikanie prawdy)", "Wskazanie konsekwencji obu postaw"]}', NULL, NULL, '{Edyp,Jokasta,prawda,porównanie}', '{"sampleAnswer": "Edyp nieugięcie dąży do poznania prawdy, mimo ostrzeżeń - jego upór prowadzi do odkrycia straszliwej prawdy, ale zachowuje godność przez przyjęcie odpowiedzialności. Jokasta próbuje unikać prawdy, bagatelizuje przepowiednie, błaga Edypa, by przestał szukać - gdy poznaje prawdę, popełnia samobójstwo. Edyp reprezentuje heroiczne mierzenie się z losem, Jokasta - ucieczkę."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srla002fqh49459fuktg', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, dlaczego Arystoteles uznał ''Króla Edypa'' za wzorcową tragedię.', '{"requirements": ["Wskazanie cech bohatera tragicznego spełnionych przez Edypa", "Odniesienie do perypetii i anagnorisis", "Związek z katharsis"]}', NULL, NULL, '{Arystoteles,Poetyka,"wzorcowa tragedia"}', '{"sampleAnswer": "Arystoteles uznał ''Króla Edypa'' za wzór, bo idealnie realizuje wymagania tragedii: Edyp jest wysoko urodzony, ale nie całkiem zły ani całkiem dobry - popełnia hamartię. Dramat zawiera doskonałą perypetię (zwrot losu) zbiegającą się z anagnorisis (rozpoznaniem prawdy). Całość wzbudza litość i trwogę, prowadząc do katharsis - oczyszczenia emocji widza."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srla002gqh49lqw9tmhx', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, co to znaczy, że Edyp jest ''niewinnym winowajcą''.', '{"requirements": ["Wskazanie zbrodni Edypa", "Podkreślenie nieświadomości działania", "Paradoks winy i niewinności"]}', NULL, NULL, '{wina,niewinność,paradoks}', '{"sampleAnswer": "Edyp popełnił najcięższe zbrodnie - ojcobójstwo i kazirodztwo - ale działał nieświadomie. Nie wiedział, że człowiek na rozstaju dróg to jego ojciec, ani że Jokasta to jego matka. Nie miał złych intencji, wręcz starał się uniknąć zbrodni. Jest więc ''niewinnym winowajcą'' - ponosi konsekwencje czynów, które popełnił bez winy moralnej, co potęguje tragizm jego losu."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srlb002hqh49tbqe1j22', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Jak rozumiesz słowa Tyrezjasza: ''Biada, o biada tej wiedzy, co szkodę niesie wiedzącym''?', '{"requirements": ["Wyjaśnienie kontekstu wypowiedzi", "Interpretacja znaczenia wiedzy w dramacie", "Odniesienie do losu Edypa"]}', NULL, NULL, '{Tyrezjasz,wiedza,cierpienie}', '{"sampleAnswer": "Tyrezjasz wie, że wyjawienie prawdy o Edypie zniszczy króla, dlatego początkowo odmawia mówienia. Jego słowa wyrażają tragiczny paradoks: wiedza, która powinna być wartością, może przynieść zniszczenie. W przypadku Edypa poznanie prawdy o własnej tożsamości prowadzi do katastrofy. Wiedza Tyrezjasza jest ciężarem - wie zbyt wiele, by być szczęśliwym."}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srlb002iqh493g7hl0s7', 'ESSAY', 'WRITING', 'ANTIQUITY', 2, 10, 'Czy Edyp jest ofiarą losu, czy sam sprowadził na siebie nieszczęście? Uzasadnij swoje stanowisko, odwołując się do tragedii Sofoklesa ''Król Edyp''.', '{"wordLimit": {"max": 350, "min": 200}, "requirements": ["Sformułowanie tezy", "Argumenty z odwołaniem do tekstu", "Analiza roli fatum i charakteru Edypa", "Podsumowanie"]}', NULL, NULL, '{rozprawka,fatum,charakter,wina}', '{"rubric": {"teza": "Jasne sformułowanie stanowiska (2 pkt)", "analiza": "Pogłębiona analiza problemu (2 pkt)", "kompozycja": "Logiczna struktura i poprawność językowa (2 pkt)", "argumentacja": "Trafne argumenty z odwołaniem do tekstu (4 pkt)"}}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srlb002jqh49kx2rnobn', 'ESSAY', 'WRITING', 'ANTIQUITY', 2, 10, 'Jak tragedia ''Król Edyp'' odpowiada na pytanie o granice ludzkiego poznania i możliwości człowieka? Rozważ problem, odwołując się do dramatu Sofoklesa.', '{"wordLimit": {"max": 350, "min": 200}, "requirements": ["Sformułowanie tezy", "Analiza dążenia Edypa do prawdy", "Refleksja nad rolą fatum", "Odniesienie do przesłania dramatu"]}', NULL, NULL, '{rozprawka,poznanie,granice,człowiek}', '{"rubric": {"teza": "Jasne sformułowanie stanowiska (2 pkt)", "refleksja": "Pogłębiona refleksja filozoficzna (2 pkt)", "kompozycja": "Logiczna struktura i poprawność językowa (2 pkt)", "argumentacja": "Trafne argumenty z odwołaniem do tekstu (4 pkt)"}}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk47srlb002kqh49k71956ra', 'ESSAY', 'WRITING', 'ANTIQUITY', 2, 10, 'Czy dążenie do prawdy jest wartością, nawet jeśli prowadzi do cierpienia? Rozważ problem na podstawie ''Króla Edypa'' Sofoklesa.', '{"wordLimit": {"max": 350, "min": 200}, "requirements": ["Sformułowanie tezy", "Analiza postawy Edypa wobec prawdy", "Rozważenie konsekwencji poznania prawdy", "Uniwersalne znaczenie problemu"]}', NULL, NULL, '{rozprawka,prawda,cierpienie,wartości}', '{"rubric": {"teza": "Jasne sformułowanie stanowiska (2 pkt)", "refleksja": "Pogłębiona refleksja aksjologiczna (2 pkt)", "kompozycja": "Logiczna struktura i poprawność językowa (2 pkt)", "argumentacja": "Trafne argumenty z odwołaniem do tekstu (4 pkt)"}}', '2026-01-07 16:10:20.947', '2026-01-07 16:10:20.947', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd5006zqh49usfom8ys', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Jaką technikę dramaturgiczną zastosował Sofokles, rozpoczynając akcję in medias res?', '{"options": ["Retrospekcję - przeszłość poznajemy stopniowo w trakcie śledztwa", "Antycypację - widzimy przyszłe wydarzenia", "Ramę narracyjną - opowieść w opowieści", "Symultanizm - równoległe wątki akcji"]}', '0', NULL, '{"technika dramaturgiczna",retrospekcja,"in medias res"}', '{"explanation": "Sofokles rozpoczyna dramat w momencie zarazy, a przeszłość Edypa poznajemy stopniowo dzięki retrospekcji."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd50070qh49crui7m2s', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'W jaki sposób Sofokles buduje napięcie dramatyczne poprzez strukturę informacji?', '{"options": ["Widz i bohater poznają prawdę jednocześnie", "Widz zna mit, więc wie więcej niż Edyp - to źródło ironii tragicznej", "Bohater wie więcej niż widz", "Chór przekazuje widzowi tajne informacje"]}', '1', NULL, '{"napięcie dramatyczne","ironia tragiczna",mit}', '{"explanation": "Grecki widz znał mit o Edypie. Ta asymetria wiedzy jest źródłem ironii tragicznej."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd50071qh493gm8fago', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Która interpretacja hamartii Edypa jest zgodna z arystotelesowską koncepcją błędu tragicznego?', '{"options": ["Hamartia to grzech moralny zasługujący na karę", "Hamartia to wrodzona skłonność do zła", "Hamartia to błąd poznawczy lub pomyłka, niekoniecznie wina moralna", "Hamartia to brak pobożności wobec bogów"]}', '2', NULL, '{hamartia,Arystoteles,interpretacja}', '{"explanation": "Według współczesnej interpretacji Arystotelesa, hamartia to raczej błąd poznawczy niż wina moralna."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd50072qh49ldqsz1x1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Co różni grecką koncepcję winy (ate) od nowożytnego pojęcia odpowiedzialności moralnej?', '{"options": ["Grecka ate wymaga świadomego działania", "Nowożytna odpowiedzialność ignoruje skutki", "Nie ma żadnej różnicy między tymi pojęciami", "Grecka ate obejmuje też niezawinione splamienie, niezależnie od intencji"]}', '3', NULL, '{ate,wina,"kultura grecka"}', '{"explanation": "Grecka koncepcja ate obejmowała obiektywne splamienie niezależnie od intencji."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd50073qh490aegz94p', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Jak można interpretować postać Tyrezjasza w kontekście opozycji między wiedzą boską a ludzką?', '{"options": ["Tyrezjasz jest medium przekazującym wiedzę niedostępną śmiertelnikom", "Tyrezjasz reprezentuje zwykłą ludzką mądrość", "Tyrezjasz symbolizuje naukowe poznanie świata", "Tyrezjasz uosabia sceptycyzm wobec bogów"]}', '0', NULL, '{Tyrezjasz,"wiedza boska",medium}', '{"explanation": "Tyrezjasz jako ślepy wieszcz jest medium między światem boskim a ludzkim."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd60074qh49jpy7z2td', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Jaką funkcję pełni motyw zarazy w strukturze dramatu?', '{"options": ["Jest tylko tłem historycznym bez głębszego znaczenia", "Symbolizuje gniew bogów i stanowi motor akcji śledczej", "Reprezentuje chorobę psychiczną Edypa", "Jest metaforą konfliktów politycznych w Tebach"]}', '1', NULL, '{zaraza,symbol,"motor akcji"}', '{"explanation": "Zaraza symbolizuje gniew bogów i stanowi motor akcji - zmusza Edypa do rozpoczęcia śledztwa."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd60075qh49burabh6o', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'W jaki sposób Sofokles wykorzystuje technikę stychomytii w dialogu Edypa z Tyrezjaszem?', '{"options": ["Długie monologi budują spokojną atmosferę", "Pieśni chóru przerywają dialog co kilka wersów", "Krótkie, szybkie repliki potęgują napięcie konfrontacji", "Aktorzy mówią jednocześnie tworząc kakofonie"]}', '2', NULL, '{stychomytia,"technika dramaturgiczna",dialog}', '{"explanation": "Stychomytia to technika szybkiej wymiany krótkich replik, budująca napięcie."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd60076qh49zhdcwp3y', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Jak należy rozumieć paradoks, że Edyp rozwiązał zagadkę Sfinksa o człowieku, ale nie rozpoznał samego siebie?', '{"options": ["Edyp był po prostu nieuważny", "Sofokles popełnił błąd logiczny w fabule", "Sfinks zadał łatwiejsze pytanie niż życiowe dylematy", "To ironia - abstrakcyjna mądrość nie gwarantuje samopoznania"]}', '3', NULL, '{Sfinks,zagadka,samopoznanie,ironia}', '{"explanation": "To głęboka ironia: Edyp potrafił odpowiedzieć na abstrakcyjne pytanie, ale nie rozpoznał własnej tożsamości."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd60077qh49fl4bllee', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Która interpretacja samooślepienia Edypa uwzględnia jego symboliczny wymiar?', '{"options": ["To akt uznania własnej duchowej ślepoty i odmowa patrzenia na świat, który zdradził", "Edyp chciał tylko uniknąć widoku martwej Jokasty", "Samooślepienie było przypadkowym odruchem w szoku", "Edyp chciał wzbudzić litość u Tebańczyków"]}', '0', NULL, '{samooślepienie,symbol,interpretacja}', '{"explanation": "Samooślepienie ma głęboki wymiar symboliczny: Edyp uznaje, że był duchowo ślepy."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd60078qh49nxcqnig1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Jak Jokasta funkcjonuje jako postać tragiczna w dramacie?', '{"options": ["Jest tylko bierną ofiarą bez własnej charakterystyki", "Reprezentuje racjonalny sceptycyzm, który ostatecznie zawodzi w obliczu prawdy", "Służy wyłącznie jako obiekt miłosny dla Edypa", "Jest antagonistką działającą przeciw Edypowi"]}', '1', NULL, '{Jokasta,sceptycyzm,"postać tragiczna"}', '{"explanation": "Jokasta reprezentuje racjonalny sceptycyzm - bagatelizuje przepowiednie, ale jej postawa ostatecznie zawodzi."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd60079qh499sjxkjej', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Co oznacza określenie Edypa jako ''pharmakos'' (kozła ofiarnego)?', '{"options": ["Edyp jest lekarzem leczącym miasto", "Edyp jest kapłanem składającym ofiary bogom", "Edyp musi być wydalony, by oczyścić wspólnotę ze skazy", "Edyp to aptekarz przygotowujący lekarstwa na zarazę"]}', '2', NULL, '{pharmakos,"kozioł ofiarny",rytuał}', '{"explanation": "Pharmakos to rytualna figura kozła ofiarnego - osoby wydalanej ze wspólnoty, by zabrać ze sobą skalanie."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev7zv0002qhd9byxigjel', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 3, 2, 'Który motyw NIE jest typowy dla baroku?', '{"options": ["vanitas - przemijanie", "carpe diem - chwytaj dzień", "praca organiczna", "theatrum mundi - świat jako teatr"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,baroque,batch-2025-01}', '{"explanation": "Praca organiczna to hasło pozytywizmu, nie baroku"}', '2025-10-24 22:16:52.027', '2025-10-24 22:16:52.027', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd6007aqh495yb88wad', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Jak można zinterpretować rolę przypadku (tyche) wobec przeznaczenia (moira) w tragedii?', '{"options": ["Przypadek całkowicie determinuje losy bohaterów", "Sofokles całkowicie odrzuca ideę przeznaczenia", "Przypadek i przeznaczenie wykluczają się nawzajem", "Przeznaczenie i przypadek współdziałają - przypadkowe zdarzenia realizują wyrok losu"]}', '3', NULL, '{tyche,moira,przeznaczenie,przypadek}', '{"explanation": "Przypadek i przeznaczenie współdziałają. Pozornie przypadkowe zdarzenia okazują się narzędziami realizacji wyroku losu."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd7007bqh49f76xwim5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 1, 'Jak interpretuje tragizm Edypa filozofia egzystencjalna (np. Camus)?', '{"options": ["Jako dowód na sprawiedliwość boską", "Jako przestrogę przed niemoralnością", "Jako ilustrację teorii ewolucji", "Jako model buntu przeciw absurdowi i godnego przyjęcia losu"]}', '3', NULL, '{egzystencjalizm,Camus,absurd,interpretacja}', '{"explanation": "Dla egzystencjalistów jak Camus, Edyp jest wzorem godnego stawienia czoła absurdowi egzystencji."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd7007cqh49nlgg6qj1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 1, 'Jak psychoanaliza Freuda wykorzystała mit o Edypie?', '{"options": ["Jako model nieświadomych pragnień seksualnych wobec rodzica przeciwnej płci", "Jako ilustrację kompleksu niższości", "Jako przykład zdrowych relacji rodzinnych", "Jako alegorię konfliktu klasowego"]}', '0', NULL, '{Freud,psychoanaliza,"kompleks Edypa"}', '{"explanation": "Freud wykorzystał mit do sformułowania ''kompleksu Edypa'' - teorii o nieświadomych pragnieniach seksualnych dziecka wobec rodzica przeciwnej płci."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd7007dqh49qbck0m6c', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 1, 'Jak strukturalizm (Levi-Strauss) interpretuje mit o Edypie?', '{"options": ["Jako opis historycznych wydarzeń w Tebach", "Jako system opozycji binarnych: autochtonizm vs. narodziny z rodziców", "Jako prostą baśń ludową bez głębszej struktury", "Jako tekst wyłącznie religijny"]}', '1', NULL, '{strukturalizm,Levi-Strauss,"opozycje binarne"}', '{"explanation": "Levi-Strauss analizował mit edypalny jako system opozycji binarnych dotyczących pochodzenia człowieka."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd7007eqh49f6zbzaip', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 1, 'Jaki jest związek między ''Królem Edypem'' a arystotelesowską koncepcją mimesis?', '{"options": ["Tragedia jest dokładną kopią rzeczywistości", "Mimesis to całkowite odrzucenie rzeczywistości", "Mimesis oznacza naśladowanie działań ludzi szlachetniejszych niż przeciętni", "Tragedia naśladuje tylko wydarzenia komiczne"]}', '2', NULL, '{mimesis,Arystoteles,naśladownictwo}', '{"explanation": "Według Arystotelesa tragedia jest mimesis działań ludzi ''lepszych od nas'' - szlachetnych, wysoko urodzonych."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd7007fqh49rmvsjax3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 1, 'Jak Nietzsche w ''Narodzinach tragedii'' interpretował postać Edypa?', '{"options": ["Jako przykład słabości i dekadencji", "Jako wzór apollińskiego ładu i harmonii", "Jako postać całkowicie pozbawioną znaczenia filozoficznego", "Jako wcielenie dionizyjskiej mądrości zdobytej przez cierpienie i transgresję"]}', '3', NULL, '{Nietzsche,dionizyjskość,transgresja}', '{"explanation": "Nietzsche widział w Edypie wcielenie dionizyjskiej mądrości - wiedzy zdobytej przez cierpienie i transgresję."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd7007gqh49bxsdhs05', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 1, 'Co oznacza termin ''spoudaios'' w arystotelesowskiej teorii bohatera tragicznego?', '{"options": ["Bohater powinien być ''poważny'', szlachetny, lepszy moralnie od przeciętnego człowieka", "Bohater musi być idealnie dobry bez wad", "Bohater musi pochodzić z niskich warstw społecznych", "Bohater powinien być postacią komiczną"]}', '0', NULL, '{spoudaios,Arystoteles,"bohater tragiczny"}', '{"explanation": "Spoudaios oznacza człowieka ''poważnego'', szlachetnego, moralnie lepszego od przeciętnego."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd7007hqh49v4tg4hiv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 1, 'Jak interpretować relację między wolną wolą a determinizmem w świetle współczesnej filozofii działania?', '{"options": ["Edyp jest całkowicie zdeterminowany, nie ma wolnej woli", "Edyp ma wolność w obrębie zdeterminowanej struktury - wybiera jak reagować na sytuację", "Edyp ma pełną wolność, fatum nie istnieje", "Pytanie o wolną wolę jest nieistotne dla interpretacji tragedii"]}', '1', NULL, '{"wolna wola",determinizm,"filozofia działania"}', '{"explanation": "Współczesna interpretacja uznaje kompatybilizm: Edyp działa w zdeterminowanej strukturze, ale zachowuje wolność w sposobie reakcji."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd7007iqh495i51diwd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 1, 'Jaką rolę w tragedii pełni tzw. ''podwójna motywacja'' (double determination)?', '{"options": ["Wydarzenia mają tylko przyczynę naturalną", "Wydarzenia mają tylko przyczynę boską", "Wydarzenia mają jednocześnie przyczynę ludzką i boską, współistniejące bez sprzeczności", "Motywacja jest całkowicie nieistotna dla fabuły"]}', '2', NULL, '{"podwójna motywacja",przyczynowość,"double determination"}', '{"explanation": "Double determination oznacza, że wydarzenia mają jednocześnie przyczynę ludzką i boską."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd7007jqh49f5zjz02d', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 1, 'Jak René Girard interpretował mit edypalny w kontekście teorii mimetycznej?', '{"options": ["Jako opowieść o szczęśliwym dzieciństwie", "Jako instrukcję moralną dla młodzieży", "Jako mechanizm kozła ofiarnego rozładowujący przemoc społeczną", "Jako tekst o znaczeniu wyłącznie estetycznym"]}', '2', NULL, '{Girard,"teoria mimetyczna","kozioł ofiarny"}', '{"explanation": "Girard widział w micie przykład mechanizmu kozła ofiarnego: wspólnota w kryzysie projektuje winę na jednostkę."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd8007kqh49t3yxkvwp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 1, 'Co oznacza arystotelesowskie pojęcie ''to philokalon'' w odniesieniu do bohatera tragicznego?', '{"options": ["Miłość do złota i bogactwa", "Skłonność do przemocy", "Obojętność wobec wartości", "Umiłowanie piękna moralnego, szlachetność duszy"]}', '3', NULL, '{"to philokalon",Arystoteles,szlachetność}', '{"explanation": "To philokalon oznacza ''umiłowanie piękna'' w sensie etycznym - szlachetność duszy, dążenie do tego, co moralnie piękne."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd8007lqh49ll18iohr', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Która scena stanowi punkt kulminacyjny (klimaks) tragedii?', '{"options": ["Rozmowa Edypa z kapłanem na początku", "Konfrontacja z Tyrezjaszem", "Moment rozpoznania - zeznanie pasterza potwierdzające tożsamość Edypa", "Wejście chóru w parodos"]}', '2', NULL, '{klimaks,"punkt kulminacyjny",rozpoznanie}', '{"explanation": "Punkt kulminacyjny to moment zeznania pasterza, gdzie zbiega się perypetia z anagnorisis."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd8007mqh49ipy8c1bz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Jak chór reaguje na oskarżenia Tyrezjasza wobec Edypa?', '{"options": ["Zachowuje wstrzemięźliwość - nie chce potępić króla bez dowodów", "Natychmiast potępia Edypa", "Opuszcza scenę w proteście", "Atakuje fizycznie Tyrezjasza"]}', '0', NULL, '{chór,reakcja,Tyrezjasz}', '{"explanation": "Chór zachowuje mądrą wstrzemięźliwość - nie chce potępić dobrego króla na podstawie samych oskarżeń."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd8007nqh495wp9vgud', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Co symbolizuje rozstaj trzech dróg (triodon) w kontekście losu Edypa?', '{"options": ["Tylko geograficzne miejsce bez symboliki", "Punkt wyboru, gdzie zbiegają się różne możliwości - i gdzie wybór prowadzi do katastrofy", "Symbol bogactwa i dobrobytu", "Metafora szczęśliwego dzieciństwa"]}', '1', NULL, '{"rozstaj dróg",symbol,wybór}', '{"explanation": "Rozstaj trzech dróg to symbol punktu wyboru, momentu krytycznego."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd8007oqh49apoutq30', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Jak Sofokles buduje kontrast między początkiem a końcem dramatu?', '{"options": ["Na początku i na końcu sytuacja jest identyczna", "Na początku Edyp jest biedny, na końcu bogaty", "Początkowo Edyp jest czczony jako zbawca miasta, na końcu - wygnany jako skalany", "Dramat nie ma wyraźnego kontrastu"]}', '2', NULL, '{kontrast,kompozycja,perypetia}', '{"explanation": "Głęboki kontrast: na początku Edyp jest czczony, na końcu - oślepiony i wygnany. To doskonała perypetia."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd8007pqh49nt5xoueb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Jaką funkcję dramaturgiczną pełni postać posłańca z Koryntu?', '{"options": ["Jest tylko tłem bez znaczenia dla fabuły", "Próbuje ukryć prawdę przed Edypem", "Reprezentuje siły wrogie Edypowi", "Jego ''dobra wiadomość'' paradoksalnie przyspiesza odkrycie prawdy"]}', '3', NULL, '{posłaniec,ironia,perypetia}', '{"explanation": "Posłaniec przychodzi z ''dobrą wiadomością'', która paradoksalnie przyspiesza odkrycie prawdy."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd8007qqh492fw4mytq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Jak należy rozumieć słowa chóru o ''pokoleniach śmiertelnych''?', '{"options": ["Jako refleksję o znikomości i kruchości ludzkiego losu", "Jako pochwałę ludzkiego życia", "Jako zachętę do hedonizmu", "Jako pochwałę bogów"]}', '0', NULL, '{chór,refleksja,"conditio humana"}', '{"explanation": "Słowa chóru ''O śmiertelnych pokolenia! Życie wasze, to cień cienia'' to refleksja o conditio humana - kruchości ludzkiego losu."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd8007rqh494yjf4ynh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 1, 'Jak Bernard Knox interpretuje Edypa jako ''człowieka tyranosa''?', '{"options": ["Jako okrutnego despotę bez zalet", "Jako self-made mana, władcę z własnych zasług, nie z dynastii", "Jako marionetkę bogów bez własnej woli", "Jako postać całkowicie negatywną"]}', '1', NULL, '{Knox,tyrannos,"demokracja ateńska"}', '{"explanation": "Bernard Knox interpretuje Edypa jako ''tyranosa'' - władcę, który zdobył tron dzięki własnym zasługom."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd8007sqh49rwulrpuc', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 1, 'Co Jan Kott miał na myśli porównując Edypa do pułapki na myszy?', '{"options": ["Edyp jest łowcą szkodników", "Edyp jest małą, nieznaczącą postacią", "Struktura dramatu jest jak pułapka - każdy ruch Edypa zbliża go do katastrofy", "Porównanie nie ma sensu interpretacyjnego"]}', '2', NULL, '{Kott,pułapka,"struktura dramatu"}', '{"explanation": "Kott porównał strukturę do pułapki: każde działanie Edypa zbliża go do katastrofy."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd9007tqh49ib5ueu6z', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Które elementy są charakterystyczne dla techniki dramaturgicznej Sofoklesa w ''Królu Edypie''?', '{"options": ["Retrospekcja - odsłanianie przeszłości w toku akcji", "Ironia tragiczna - widz wie więcej niż bohater", "Linearna narracja od narodzin do śmierci", "Stychomytia - szybka wymiana replik", "Całkowity brak chóru"]}', '[0, 1, 3]', NULL, '{"technika dramaturgiczna",retrospekcja,ironia,stychomytia}', '{"explanation": "Sofokles stosuje: retrospekcję, ironię tragiczną, stychomytię. Narracja NIE jest linearna, a chór jest obecny."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd9007uqh49z3pl3b2a', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Które interpretacje hamartii Edypa są uznawane przez współczesnych badaczy?', '{"options": ["Hamartia jako błąd poznawczy - nierozpoznanie rodziców", "Hamartia jako hybris - pycha wobec bogów i ludzi", "Hamartia jako przypadkowy pech bez związku z bohaterem", "Hamartia jako gwałtowność charakteru prowadząca do pochopnych decyzji", "Hamartia jako świadome zło moralne"]}', '[0, 1, 3]', NULL, '{hamartia,interpretacja,badania}', '{"explanation": "Współcześni badacze uznają wieloaspektowość hamartii: błąd poznawczy, hybris, gwałtowność. Nie jest to przypadek ani świadome zło."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd9007vqh490ylk8dex', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Które funkcje pełni zagadka Sfinksa w strukturze mitu i dramatu?', '{"options": ["Ustanawia Edypa jako rozwiązującego zagadki - który nie rozpoznaje siebie", "Uzasadnia objęcie tronu i małżeństwo z Jokastą", "Jest całkowicie nieistotnym epizodem", "Wprowadza motyw człowieka jako istoty złożonej i zmiennej", "Pokazuje przypadkowość sukcesu Edypa"]}', '[0, 1, 3]', NULL, '{Sfinks,zagadka,funkcja}', '{"explanation": "Zagadka Sfinksa: ustanawia ironię, uzasadnia tron i małżeństwo, wprowadza motyw człowieka."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd9007wqh4950zzg8y1', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 2, 'Które elementy ''Króla Edypa'' były przedmiotem interpretacji psychoanalitycznej?', '{"options": ["Nieświadome zabójstwo ojca i małżeństwo z matką - kompleks Edypa", "Oślepienie jako symboliczna kastracja", "Pragnienie prawdy jako sublimacja", "Struktura stasimonów chóru", "Zagadka Sfinksa jako pytanie o tożsamość"]}', '[0, 1, 4]', NULL, '{psychoanaliza,Freud,interpretacja}', '{"explanation": "Psychoanaliza interpretowała: relację Edyp-Lajos-Jokasta jako wzór kompleksu, oślepienie jako symboliczną kastrację, zagadkę jako pytanie o tożsamość."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd9007xqh49jj8zjskh', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 2, 'Które aspekty ''Króla Edypa'' były istotne dla egzystencjalistycznej interpretacji?', '{"options": ["Konfrontacja z absurdem egzystencji", "Przyjęcie odpowiedzialności mimo niewinności", "Optymistyczna wiara w sprawiedliwość bogów", "Godność w obliczu nieuchronnej katastrofy", "Ucieczka od wolności poprzez determinizm"]}', '[0, 1, 3]', NULL, '{egzystencjalizm,absurd,odpowiedzialność}', '{"explanation": "Egzystencjaliści cenili: konfrontację z absurdem, przyjęcie odpowiedzialności, godność w katastrofie."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd9007yqh49kt2r8m6m', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Dopasuj postać do jej funkcji dramaturgicznej.', '{"leftColumn": [{"id": "A", "text": "Tyrezjasz"}, {"id": "B", "text": "Posłaniec z Koryntu"}, {"id": "C", "text": "Pasterz z Kiteronu"}, {"id": "D", "text": "Kreon"}], "rightColumn": [{"id": "1", "text": "fałszywie oskarżony, foil dla gwałtowności Edypa"}, {"id": "2", "text": "katalizator końcowego rozpoznania"}, {"id": "3", "text": "głos prawdy boskiej, prorok"}, {"id": "4", "text": "ironiczna ''dobra wiadomość'' przyspieszająca odkrycie"}], "matchingType": "character_function"}', '[[0, 2], [1, 3], [2, 1], [3, 0]]', NULL, '{postacie,"funkcja dramaturgiczna",dopasowanie}', '{"explanation": "Tyrezjasz - głos prawdy boskiej; Posłaniec - paradoksalna ''dobra wiadomość''; Pasterz - ostateczny dowód; Kreon - foil dla gwałtowności."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd9007zqh49c1vl0vep', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 2, 'Dopasuj teoretyka do jego interpretacji ''Króla Edypa''.', '{"leftColumn": [{"id": "A", "text": "Freud"}, {"id": "B", "text": "Nietzsche"}, {"id": "C", "text": "Arystoteles"}, {"id": "D", "text": "Girard"}], "rightColumn": [{"id": "1", "text": "wzorcowa realizacja tragedii, perypetia i anagnorisis"}, {"id": "2", "text": "kompleks nieświadomych pragnień seksualnych"}, {"id": "3", "text": "dionizyjska mądrość przez transgresję"}, {"id": "4", "text": "mechanizm kozła ofiarnego"}], "matchingType": "theorist_interpretation"}', '[[0, 1], [1, 2], [2, 0], [3, 3]]', NULL, '{teoretycy,interpretacja,dopasowanie}', '{"explanation": "Freud - kompleks Edypa; Nietzsche - dionizyjska mądrość; Arystoteles - wzorcowa tragedia; Girard - kozioł ofiarny."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sd90080qh49dwadtcdp', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Uzupełnij informacje o arystotelesowskiej teorii tragedii.', '{"gaps": [{"id": 1, "options": ["prolog", "perypetia", "parodos", "eksodos"]}, {"id": 2, "options": ["stasimon", "anagnorisis", "kommos", "epizod"]}, {"id": 3, "options": ["hybris", "hamartia", "katharsis", "mimesis"]}], "textWithGaps": "Według Arystotelesa, najlepsza tragedia to ta, w której [1] i [2] zbiegają się w jednym momencie, jak w ''Królu Edypie''. Celem tragedii jest wywołanie [3] - oczyszczenia emocji widza."}', '[1, 1, 2]', NULL, '{Arystoteles,perypetia,anagnorisis,katharsis}', '{"explanation": "Arystoteles uważał, że najlepsza tragedia łączy perypetię z anagnorisis. Cel to katharsis."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sda0081qh49cpmjz304', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 2, 'Uzupełnij informacje o interpretacji Nietzschego.', '{"gaps": [{"id": 1, "options": ["apollińskiej", "dionizyjskiej", "sokratycznej", "platońskiej"]}, {"id": 2, "options": ["racjonalizm", "transgresję", "pobożność", "ascezę"]}, {"id": 3, "options": ["dionizyjski", "sokratyczny", "apolliński", "platoński"]}], "textWithGaps": "Nietzsche w ''Narodzinach tragedii'' widział w Edypie przykład [1] mądrości - wiedzy zdobytej przez cierpienie i [2]. Tragedia grecka łączy według niego żywioł [3] (ład, forma) i dionizyjski (chaos, upojenie)."}', '[1, 1, 2]', NULL, '{Nietzsche,dionizyjskość,apolliński}', '{"explanation": "Nietzsche: dionizyjska mądrość przez transgresję. Tragedia łączy żywioł apolliński i dionizyjski."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sda0082qh49fyyjbzi3', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 3, 'Zinterpretuj paradoks, że racjonalne działania Edypa (ucieczka z Koryntu, śledztwo w Tebach) prowadzą do irracjonalnej katastrofy.', '{"requirements": ["Wskazanie racjonalnych motywacji Edypa", "Analiza paradoksu: rozum jako narzędzie własnej zagłady", "Odniesienie do greckiej koncepcji losu"]}', NULL, NULL, '{racjonalizm,paradoks,fatum}', '{"sampleAnswer": "Edyp działa racjonalnie: ucieka z Koryntu, by chronić ''rodziców'', prowadzi śledztwo, by ocalić miasto. Paradoks polega na tym, że właśnie ta rozumność staje się narzędziem realizacji losu. Sofokles pokazuje granice ludzkiego rozumu wobec sił wyższych."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sda0083qh49aefvwub9', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 3, 'Porównaj funkcję dwóch pasterzy (tebańskiego i korynckiego) w mechanizmie odkrywania prawdy.', '{"requirements": ["Charakterystyka roli pasterza tebańskiego", "Charakterystyka roli pasterza korynckiego", "Analiza ich współdziałania w odsłonięciu prawdy"]}', NULL, NULL, '{pasterze,"odkrycie prawdy",struktura}', '{"sampleAnswer": "Pasterz koryncki paradoksalnie przychodzi z ''dobrą wiadomością'', ale ujawnia, że Edyp był adoptowany. Pasterz tebański to były sługa Lajosa - jego zeznanie zamyka łańcuch dowodów. Razem tworzą ''most'' między Tebami a Koryntem, między przeszłością a teraźniejszością."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sda0084qh49k4aq70pe', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 3, 'Wyjaśnij, jak Sofokles wykorzystuje motyw widzenia i ślepoty jako strukturalną zasadę organizującą dramat.', '{"requirements": ["Analiza opozycji Tyrezjasz (ślepy/widzący) vs Edyp (widzący/ślepy)", "Rola motywu w budowaniu ironii tragicznej", "Znaczenie samooślepienia jako kulminacji motywu"]}', NULL, NULL, '{widzenie,ślepota,struktura,motyw}', '{"sampleAnswer": "Motyw widzenia/ślepoty organizuje cały dramat: ślepy Tyrezjasz ''widzi'' prawdę, widzący Edyp jest ''ślepy'' na własną tożsamość. Samooślepienie to kulminacja: Edyp uznaje, że był duchowo ślepy, i rezygnuje z fizycznego wzroku."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sda0085qh497rze6wpm', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 3, 'Przeanalizuj rolę chóru w tworzeniu dystansu refleksyjnego wobec wydarzeń scenicznych.', '{"requirements": ["Funkcja komentarza chóru", "Związek chóru z widzem (reprezentacja odbiorcy)", "Przykłady refleksji chóru uogólniających sens wydarzeń"]}', NULL, NULL, '{chór,"dystans refleksyjny",komentarz}', '{"sampleAnswer": "Chór tworzy dystans refleksyjny: komentuje wydarzenia, wyrażając wątpliwości i emocje widza; uogólnia sens wydarzeń, formułując prawdy o ludzkim losie; reprezentuje perspektywę społeczności. Dzięki temu widz zyskuje ramy interpretacyjne dla indywidualnej tragedii Edypa."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sda0086qh490dx4zyxb', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 3, 'Wyjaśnij pojęcie ''miasma'' (zmaza, skalanie) i jego znaczenie dla rozumienia sytuacji Edypa.', '{"requirements": ["Definicja miasma w kontekście religii greckiej", "Związek między miasmą a zarazą w Tebach", "Konieczność usunięcia skalania"]}', NULL, NULL, '{miasma,skalanie,"religia grecka"}', '{"sampleAnswer": "Miasma to obiektywne skalanie powstające z przelania krwi lub naruszenia tabu. Obecność skazonej osoby zatruwa wspólnotę - stąd zaraza w Tebach. Edyp jako morderca i kazirodca jest źródłem miasmy niezależnie od intencji. By miasto mogło się oczyścić, źródło skalania musi być usunięte."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sda0087qh49diiow0so', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Zinterpretuj scenę konfrontacji Edypa z Tyrezjaszem w kontekście konfliktu między wiedzą ludzką a boską.', '{"requirements": ["Charakterystyka postaw obu postaci", "Analiza sporu jako konfliktu epistemologicznego", "Implikacje dla rozumienia granic ludzkiego poznania"]}', NULL, NULL, '{Tyrezjasz,Edyp,epistemologia,konflikt}', '{"sampleAnswer": "Konfrontacja reprezentuje konflikt dwóch typów wiedzy: Edyp uosabia rozum ludzki - śledczy, empiryczny; Tyrezjasz reprezentuje wiedzę boską - irracjonalną z ludzkiej perspektywy, ale absolutną. Konflikt pokazuje granice ludzkiego poznania: rozum Edypa nie ma dostępu do prawd ostatecznych."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sda0088qh49a37iinuf', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Przeanalizuj problem teodycei (sprawiedliwości bogów) w ''Królu Edypie''.', '{"requirements": ["Pytanie o sprawiedliwość kary wobec nieświadomego bohatera", "Różne interpretacje: bogowie sprawiedliwi vs obojętni vs okrutni", "Możliwość rozwiązania problemu w kontekście tragedii greckiej"]}', NULL, NULL, '{teodyceja,"sprawiedliwość bogów",problem}', '{"sampleAnswer": "Tragedia stawia problem teodycei: czy bogowie są sprawiedliwi, karząc nieświadomego Edypa? Interpretacje różnią się: jedni widzą sprawiedliwy porządek, inni obojętność bogów, jeszcze inni okrucieństwo. Być może Sofokles nie rozwiązuje problemu, lecz go stawia - pytanie pozostaje otwarte."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sda0089qh49tqmj6ft6', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Porównaj postawę Edypa wobec prawdy z postawą Jokasty. Co te postawy mówią o kondycji ludzkiej?', '{"requirements": ["Analiza dążenia Edypa do prawdy za wszelką cenę", "Analiza unikania prawdy przez Jokastę", "Filozoficzne implikacje obu postaw"]}', NULL, NULL, '{Edyp,Jokasta,prawda,"kondycja ludzka"}', '{"sampleAnswer": "Edyp reprezentuje heroiczne dążenie do prawdy - nawet gdy wszyscy ostrzegają. Jokasta uosabia pragmatyczny sceptycyzm - bagatelizuje przepowiednie, chce żyć w nieświadomości. Obie postawy kończą się tragicznie, ale Edyp zachowuje godność przez przyjęcie odpowiedzialności."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sdb008aqh49dmepnd2q', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Zinterpretuj ''Króla Edypa'' jako dramat o epistemologicznym kryzysie - o granicach ludzkiego poznania.', '{"requirements": ["Edyp jako symbol racjonalnego poznania", "Klęska rozumu wobec prawd ostatecznych", "Znaczenie motywu zagadki Sfinksa w tym kontekście"]}', NULL, NULL, '{epistemologia,poznanie,rozum,granice}', '{"sampleAnswer": "Edyp uosabia grecki ideał rozumowego poznania: rozwiązał zagadkę Sfinksa, prowadzi śledztwo metodycznie. Jednak jego rozum ponosi klęskę - abstrakcyjna wiedza o człowieku nie dała mu samopoznania. Dramat pokazuje granice rozumu wobec ślepoty na temat siebie."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sdb008bqh4945avzxwh', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Jak interpretować finałową transformację Edypa w kontekście greckiej koncepcji heroizmu?', '{"requirements": ["Analiza zmiany statusu Edypa (z króla na wygnańca)", "Związek z koncepcją herosa (heros kultowy)", "Znaczenie cierpienia dla osiągnięcia statusu heroicznego"]}', NULL, NULL, '{heros,transformacja,"heroizm grecki"}', '{"sampleAnswer": "W greckiej religii heros to postać, która przez cierpienie osiąga szczególny status. Edyp przechodzi transformację: z króla-zbawcy staje się skalonym wygnańcem. Jednak właśnie to cierpienie przekształca go w herosa kultowego. Paradoks heroizmu greckiego: wielkość osiąga się przez katastrofę."}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sdb008cqh49oemc93lc', 'ESSAY', 'WRITING', 'ANTIQUITY', 3, 12, 'Czy ironia tragiczna w ''Królu Edypie'' służy wyłącznie budowaniu napięcia dramatycznego, czy ma też głębsze znaczenie filozoficzne? Rozważ problem na podstawie analizy wybranych scen.', '{"wordLimit": {"max": 500, "min": 300}, "requirements": ["Definicja ironii tragicznej", "Analiza min. 2-3 przykładów ironii w dramacie", "Interpretacja filozoficznego znaczenia ironii", "Synteza: relacja między techniką dramaturgiczną a przesłaniem"]}', NULL, NULL, '{"ironia tragiczna",filozofia,"rozprawka analityczna"}', '{"rubric": {"analiza": "Wnikliwa analiza przykładów (4 pkt)", "definicja": "Precyzyjne wyjaśnienie pojęcia (2 pkt)", "kompozycja": "Struktura, argumentacja, język (2 pkt)", "interpretacja": "Głęboka interpretacja filozoficzna (4 pkt)"}}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sdb008dqh49fbom7icr', 'ESSAY', 'WRITING', 'ANTIQUITY', 3, 12, 'Przeanalizuj rolę chóru jako mediatora między światem dramatu a widzem. Jakie funkcje pełni chór w ''Królu Edypie'' i jak wpływa na odbiór tragedii?', '{"wordLimit": {"max": 500, "min": 300}, "requirements": ["Charakterystyka chóru w tragedii greckiej (kontekst)", "Analiza konkretnych funkcji chóru w ''Królu Edypie''", "Relacja chóru z bohaterami i z widzem", "Ocena znaczenia chóru dla przesłania dramatu"]}', NULL, NULL, '{chór,mediacja,"odbiór tragedii"}', '{"rubric": {"analiza": "Szczegółowa analiza roli chóru (4 pkt)", "relacje": "Analiza relacji chór-bohaterowie i chór-widz (4 pkt)", "kontekst": "Znajomość funkcji chóru w tragedii (2 pkt)", "kompozycja": "Struktura, argumentacja, język (2 pkt)"}}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sdb008eqh49mxq8xy56', 'ESSAY', 'WRITING', 'ANTIQUITY', 4, 15, 'Zinterpretuj ''Króla Edypa'' jako dramat o epistemologicznych granicach człowieka. Jak Sofokles przedstawia konflikt między pragnieniem wiedzy a ograniczeniami ludzkiego poznania?', '{"wordLimit": {"max": 600, "min": 400}, "requirements": ["Wprowadzenie problematyki epistemologicznej", "Analiza Edypa jako symbolu racjonalnego poznania", "Interpretacja klęski rozumu", "Filozoficzne wnioski o kondycji ludzkiej", "Odniesienie do współczesnych kontekstów (opcjonalnie)"]}', NULL, NULL, '{epistemologia,poznanie,rozum,filozofia}', '{"rubric": {"analiza": "Wnikliwa analiza motywów epistemologicznych (5 pkt)", "kompozycja": "Struktura, argumentacja, język (2 pkt)", "problematyka": "Precyzyjne wprowadzenie problematyki (3 pkt)", "interpretacja": "Głęboka interpretacja filozoficzna (5 pkt)"}}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sdb008fqh49udzn5fh1', 'ESSAY', 'WRITING', 'ANTIQUITY', 4, 15, 'Porównaj interpretację ''Króla Edypa'' u Arystotelesa i u jednego wybranego teoretyka nowożytnego (Freud, Nietzsche, Girard lub inny). Jakie aspekty dramatu uwypukla każda z tych lektur?', '{"wordLimit": {"max": 600, "min": 400}, "requirements": ["Prezentacja interpretacji arystotelesowskiej", "Prezentacja wybranej interpretacji nowożytnej", "Porównanie: co obie lektury eksponują, co pomijają", "Własna ocena użyteczności obu podejść", "Synteza: co różne interpretacje mówią o bogactwie tekstu"]}', NULL, NULL, '{Arystoteles,interpretacja,teoria,porównanie}', '{"rubric": {"ocena": "Własna refleksja krytyczna (3 pkt)", "kompozycja": "Struktura, argumentacja, język (2 pkt)", "nowożytna": "Rzetelna prezentacja interpretacji nowożytnej (3 pkt)", "arystoteles": "Rzetelna prezentacja interpretacji arystotelesowskiej (3 pkt)", "porównanie": "Wnikliwe porównanie obu podejść (4 pkt)"}}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk489sdb008gqh49fkpqjjek', 'ESSAY', 'WRITING', 'ANTIQUITY', 4, 15, 'Czy cierpienie Edypa ma sens? Rozważ problem teodycei i sprawiedliwości losu w ''Królu Edypie'', odwołując się do różnych interpretacji filozoficznych.', '{"wordLimit": {"max": 600, "min": 400}, "requirements": ["Wprowadzenie problemu teodycei", "Analiza ''winy'' i ''kary'' Edypa", "Prezentacja różnych stanowisk", "Własne stanowisko z uzasadnieniem", "Odniesienie do uniwersalnego wymiaru problemu"]}', NULL, NULL, '{teodyceja,cierpienie,sens,filozofia}', '{"rubric": {"analiza": "Wnikliwa analiza winy i kary (4 pkt)", "problem": "Precyzyjne wprowadzenie problemu (3 pkt)", "kompozycja": "Struktura, argumentacja, język (2 pkt)", "stanowisko": "Własna, uzasadniona refleksja (2 pkt)", "interpretacje": "Rzetelna prezentacja różnych stanowisk (4 pkt)"}}', '2026-01-07 16:23:35.129', '2026-01-07 16:23:35.129', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev7zy0003qhd9s22j6l8o', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 1, 1, 'Które słowo jest NIEPOPRAWNE ortograficznie?', '{"options": ["rzeczpospolita", "Rzeszów", "rzeka", "rzeźba"]}', '0', NULL, '{language_use,closed_single,difficulty-1,batch-2025-01}', '{"explanation": "Wyraz ''Rzeczpospolita'' jako nazwa państwa polskiego musi być pisany wielką literą. Jest to nazwa własna, podobnie jak ''Polska'' czy ''Niemcy''. Małą literą piszemy tylko gdy mówimy o rzeczpospolitej jako formie ustroju (np. ''rzeczpospolita rzymska'')."}', '2025-10-24 22:16:52.031', '2025-10-24 22:16:52.031', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8010004qhd9fus96eaz', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 2, 1, 'Co to jest antonim?', '{"options": ["słowo obce", "słowo podobne brzmieniem", "słowo o przeciwnym znaczeniu", "słowo wieloznaczne"], "contextLinks": [{"type": "text", "title": "Antonim - relacja znaczeniowa", "content": "Antonim to wyraz o znaczeniu przeciwnym do innego wyrazu. Antonimy tworzą pary przeciwstawne: biały - czarny, dobry - zły, wysoki - niski, gorący - zimny. Rozróżniamy antonimy gradacyjne (dopuszczające stopniowanie: ciepły - zimny), komplementarne (wykluczające się: żywy - martwy) oraz konwersywne (relacyjne: kupić - sprzedać, dawać - brać).", "trigger": "antonim", "moreInfoLink": ""}]}', '2', NULL, '{language_use,closed_single,difficulty-2,batch-2025-01}', '{"explanation": "Antonim to słowo o przeciwnym znaczeniu (np. dobry - zły, gorący - zimny). Słowo obce to zapożyczenie z innego języka, słowa podobne brzmieniem to paronimy (np. efekt - afekt), a słowo wieloznaczne to polisem (np. zamek - budowla lub urządzenie)."}', '2025-10-24 22:16:52.034', '2025-10-24 22:16:52.034', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8050005qhd9pp01gzso', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Który utwór NIE jest dramatem?', '{"options": ["Dziady", "Pan Tadeusz", "Kordian", "Nie-Boska komedia"], "contextLinks": [{"type": "text", "title": "Dramat jako rodzaj literacki", "content": "Dramat to utwór literacki przeznaczony do wystawienia na scenie teatralnej. Charakteryzuje się dialogiem postaci, podziałem na akty i sceny, didaskaliami (wskazówkami scenicznymi) oraz brakiem narratora. W romantyzmie popularne były dramaty romantyczne (np. ''Dziady'', ''Kordian''), łączące elementy realizmu z fantastyką i symboliką. Dramat różni się od epiki (opowiadanie, powieść) i liryki (wiersz).", "trigger": "dramatem", "moreInfoLink": ""}]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Pan Tadeusz to epopeja (gatunek epicki), nie dramat. Utwór Mickiewicza ma formę poematu narracyjnego z narratorem opowiadającym historię. Pozostałe utwory (Dziady, Kordian, Nie-Boska komedia) to dramaty - utwory dialogowe przeznaczone do wystawienia na scenie."}', '2025-10-24 22:16:52.037', '2025-10-24 22:16:52.037', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8080006qhd96r5f0dn3', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 3, 2, 'Który środek stylistyczny dominuje?', '{"text": "Życie to podróż bez mapy, gdzie każdy krok to zagadka.", "options": ["personifikacja", "metafora rozbudowana", "porównanie", "epitet"], "contextLinks": [{"type": "text", "title": "Środki stylistyczne w języku", "content": "Środki stylistyczne to zabiegi językowe służące upiększeniu wypowiedzi i wzmocnieniu jej wyrazu. Należą do nich m.in.: metafora (przenośnia bez słowa porównującego: ''czas to pieniądz''), porównanie (zestawienie z użyciem ''jak'', ''jakby'': ''biały jak śnieg''), personifikacja (nadanie cech ludzkich: ''wiatr szeptał''), epitet (określenie barwne: ''srebrny księżyc''). Środki te wzbogacają tekst i nadają mu artystyczny charakter.", "trigger": "środek stylistyczny", "moreInfoLink": ""}]}', '1', NULL, '{language_use,closed_single,difficulty-3,batch-2025-01}', '{"explanation": "To metafora rozbudowana - życie zostało porównane do podróży bez użycia słowa ''jak'' czy ''jakby''. Metafora jest rozwinięta przez kolejne obrazy (brak mapy, kroki jako zagadki). Nie ma tu personifikacji (brak cech ludzkich nadanych rzeczom), porównania (brak ''jak'') ani epitetu (brak przymiotnika określającego)."}', '2025-10-24 22:16:52.04', '2025-10-24 22:16:52.04', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev80b0007qhd9yqpm6588', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ENLIGHTENMENT', 2, 1, 'Który gatunek był popularny w oświeceniu?', '{"options": ["ballada", "hymn", "bajka alegoryczna", "powieść gotycka"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,enlightenment,batch-2025-01}', NULL, '2025-10-24 22:16:52.044', '2025-10-24 22:16:52.044', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev80f0008qhd9tjhbq9bz', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 1, 1, 'Ile samogłosek nosowych występuje w języku polskim?', '{"options": ["1", "2", "3", "4"]}', '1', NULL, '{language_use,closed_single,difficulty-1,batch-2025-01}', '{"explanation": "ą i ę"}', '2025-10-24 22:16:52.047', '2025-10-24 22:16:52.047', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev80i0009qhd948p0br48', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Który symbol pojawia się w Weselu Wyspiańskiego?', '{"options": ["biały orzeł", "róża", "złoty róg", "krzyż"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,young_poland,batch-2025-01}', NULL, '2025-10-24 22:16:52.05', '2025-10-24 22:16:52.05', 'Wesele');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev80l000aqhd9msfxehmw', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 2, 1, 'Które zdanie jest poprawne składniowo?', '{"options": ["Spotkałem się z przyjacielem do kina.", "Idę do fryzjera na obcięcie włosów.", "Byłem u lekarza w sprawie badań.", "Poszedłem z kolegą po zakupach."]}', '2', NULL, '{language_use,closed_single,difficulty-2,batch-2025-01}', NULL, '2025-10-24 22:16:52.053', '2025-10-24 22:16:52.053', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev80o000bqhd90cmyqdlp', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 3, 2, 'Jaka figura retoryczna?', '{"text": "Przyszedł, zobaczył, zwyciężył.", "options": ["metafora", "anafora", "asyndeton", "epifora"]}', '2', NULL, '{language_use,closed_single,difficulty-3,batch-2025-01}', '{"explanation": "Asyndeton - brak spójników między członami"}', '2025-10-24 22:16:52.056', '2025-10-24 22:16:52.056', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev80r000cqhd9uegzchck', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', NULL, 1, 1, 'Który poeta NIE był romantykiem?', '{"options": ["Adam Mickiewicz", "Juliusz Słowacki", "Jan Kochanowski", "Cyprian Norwid"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,batch-2025-01}', '{"explanation": "Kochanowski to renesans"}', '2025-10-24 22:16:52.059', '2025-10-24 22:16:52.059', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev80t000dqhd9azhz6b2i', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 2, 1, 'Co oznacza „mieć węża w kieszeni”?', '{"options": ["nosić zwierzę", "być niebezpiecznym", "być skąpym", "być podstępnym"]}', '2', NULL, '{language_use,closed_single,difficulty-2,batch-2025-01}', NULL, '2025-10-24 22:16:52.062', '2025-10-24 22:16:52.062', NULL);
