INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev811000gqhd95jxrm0vw', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 3, 2, 'Określ funkcję składniową: „Mama dała *córce* prezent.”', '{"options": ["dopełnienie bliższe", "dopełnienie dalsze", "okolicznik", "przydawka"]}', '1', NULL, '{language_use,closed_single,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.07', '2025-10-24 22:16:52.07', NULL);
