INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev816000iqhd94efpfbij', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 2, 1, 'W którym przypadku występuje wyraz „domem”?', '{"options": ["mianownik", "dopełniacz", "narzędnik", "miejscownik"]}', '2', NULL, '{language_use,closed_single,difficulty-2,batch-2025-01}', NULL, '2025-10-24 22:16:52.075', '2025-10-24 22:16:52.075', NULL);
