INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev883003hqhd9hlaylbc9', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 4, 'Uzupełnij analizę składniową.', '{"gaps": [{"id": 1, "options": ["mianowniku", "dopełniaczu", "celowniku", "bierniku"]}, {"id": 2, "options": ["podmiotu", "dopełnienia dalszego", "dopełnienia bliższego", "okolicznika"]}, {"id": 3, "options": ["mianowniku", "dopełniaczu", "celowniku", "bierniku"]}], "textWithGaps": "W zdaniu ''Mama kupiła córce nową książkę'' słowo ''córce'' jest w [1] przypadku i pełni funkcję [2], a ''książkę'' jest w [3] przypadku."}', '[2, 1, 3]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.324', '2025-10-24 22:16:52.324', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev886003iqhd9tlhyadoo', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 4, 'Dopasuj cechy do odpowiednich bohaterów romantycznych.', '{"leftColumn": [{"id": "A", "text": "Konrad z ''Dziadów'' cz. III"}, {"id": "B", "text": "Kordian z dramatu Słowackiego"}, {"id": "C", "text": "Anhelli z poematu Słowackiego"}], "rightColumn": [{"id": 1, "text": "bunt prometejski przeciw Bogu"}, {"id": 2, "text": "wahanie i niezdecydowanie"}, {"id": 3, "text": "cierpienie i ofiara za naród"}], "matchingType": "character_traits"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-4,romanticism,batch-2025-01}', NULL, '2025-10-24 22:16:52.326', '2025-10-24 22:16:52.326', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ev0095qh49cuzh7q2m', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Jak psychoanaliza Freuda wykorzystała mit o Edypie?', '{"options": ["Jako model nieświadomych pragnień seksualnych wobec rodzica przeciwnej płci", "Jako ilustrację kompleksu niższości", "Jako przykład zdrowych relacji rodzinnych", "Jako alegorię konfliktu klasowego"]}', '0', NULL, '{Freud,psychoanaliza,"kompleks Edypa"}', '{"explanation": "Freud wykorzystał mit do sformułowania ''kompleksu Edypa'' - teorii o nieświadomych pragnieniach seksualnych dziecka wobec rodzica przeciwnej płci."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev888003jqhd9q3mnoq3t', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 5, 4, 'Uzupełnij lukę odpowiednią formą - zaawansowana składnia.', '{"gaps": [{"id": 1, "options": ["zbieg", "zbiegu", "zbiegiem", "zbiegowi"]}, {"id": 2, "options": ["zaistniały", "zaistniałyby", "zaistnieją", "zaistniałaby"]}, {"id": 3, "options": ["zdołałbym", "zdołam", "zdołałem", "zdołać"]}], "textWithGaps": "Gdyby nie [1] pewnych okoliczności, które [2] w nieoczekiwanym momencie, nigdy nie [3] poznać prawdy o wydarzeniach sprzed lat."}', '[1, 0, 0]', NULL, '{language_use,closed_multiple,difficulty-5,batch-2025-01}', NULL, '2025-10-24 22:16:52.329', '2025-10-24 22:16:52.329', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev88b003kqhd9t1uxlonk', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', NULL, 4, 3, 'Które fragmenty zawierają motywy vanitas (przemijania)?', '{"options": ["Człowiek - jako kwiat na polu - ścięty bywa", "Raduj się młodzieńcze, póki czas", "Słońce wschodzi i zachodzi", "Wesele taniec, śpiew - a potem cmentarz, grób", "Wiosna budzi przyrodę do życia"]}', '[0, 3]', NULL, '{historical_literary,closed_multiple,difficulty-4,batch-2025-01}', NULL, '2025-10-24 22:16:52.331', '2025-10-24 22:16:52.331', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev88d003lqhd9j7it8x78', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 5, 4, 'Dopasuj cytaty filozoficzne do ich interpretacji językoznawczych.', '{"leftColumn": [{"id": "A", "text": "Granice mego języka są granicami mego świata"}, {"id": "B", "text": "Świat jest wszystkim, co ma miejsce"}, {"id": "C", "text": "O czym nie można mówić, o tym trzeba milczeć"}], "rightColumn": [{"id": 1, "text": "relatywizm językowy - język kształtuje poznanie"}, {"id": 2, "text": "realizm językowy - fakty niezależne od języka"}, {"id": 3, "text": "granice ekspresji językowej"}], "matchingType": "quotes_to_interpretations"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{language_use,closed_multiple,difficulty-5,batch-2025-01}', NULL, '2025-10-24 22:16:52.333', '2025-10-24 22:16:52.333', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev88f003mqhd981dzo1iy', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 4, 'Dopasuj symbole młodopolskie do ich znaczeń.', '{"leftColumn": [{"id": "A", "text": "złoty róg (Staff)"}, {"id": "B", "text": "Chochoł (Wyspiański)"}, {"id": "C", "text": "harfa (Tetmajer)"}], "rightColumn": [{"id": 1, "text": "afirmacja życia mimo cierpienia"}, {"id": 2, "text": "paraliż narodowy i niemoc"}, {"id": 3, "text": "poezja jako wyraz bólu duszy"}], "matchingType": "symbols_meanings"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-5,young_poland,batch-2025-01}', NULL, '2025-10-24 22:16:52.336', '2025-10-24 22:16:52.336', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev88h003nqhd9xx5seu0g', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 4, 3, 'Które zdania zawierają błędy składniowe typowe dla polszczyzny potocznej?', '{"options": ["Czekam na ciebie od godziny", "Idę do fryzjera na obcięcie włosów", "Spotkałem się z tym problemem", "Książka, którą czytałem była ciekawa", "Poszedłem do lekarza po receptę"]}', '[1, 2]', NULL, '{language_use,closed_multiple,difficulty-4,batch-2025-01}', NULL, '2025-10-24 22:16:52.338', '2025-10-24 22:16:52.338', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev88k003oqhd998hyujew', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', NULL, 5, 5, 'Uzupełnij analizę literacką odpowiednimi terminami.', '{"gaps": [{"id": 1, "options": ["symultaniczna", "retrospektywna", "liniowa", "cykliczna"]}, {"id": 2, "options": ["równoległe", "następujące", "kontrastowe", "paralelne"]}, {"id": 3, "options": ["realistyczna", "alegoryczna", "dokumentalna", "biograficzna"]}], "textWithGaps": "W ''Weselu'' Wyspiańskiego dominuje [1] konstrukcja dramatyczna, gdzie akcja rozwija się poprzez [2] sceny, a kluczową rolę pełni [3] symbolika postaci."}', '[0, 3, 1]', NULL, '{historical_literary,closed_multiple,difficulty-5,batch-2025-01}', NULL, '2025-10-24 22:16:52.34', '2025-10-24 22:16:52.34', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev88m003pqhd9n7wukx2t', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 5, 3, 'Które konstrukcje są przykładami hipotaksy (zdań podrzędnych)?', '{"options": ["Kiedy pada deszcz, zostaję w domu i czytam książki.", "Pada deszcz, więc zostałem w domu.", "Ponieważ pada, choć słońce świeci, wziąłem parasol.", "Pada i wieje.", "Chociaż pada, poszedłem na spacer, który był bardzo przyjemny."]}', '[0, 2, 4]', NULL, '{language_use,closed_multiple,difficulty-5,batch-2025-01}', NULL, '2025-10-24 22:16:52.342', '2025-10-24 22:16:52.342', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev88o003qqhd9wp4bapyg', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Dopasuj postacie z ''Lalki'' do reprezentowanych przez nie postaw.', '{"leftColumn": [{"id": "A", "text": "Stanisław Wokulski"}, {"id": "B", "text": "Ignacy Rzecki"}, {"id": "C", "text": "Julian Ochocki"}], "rightColumn": [{"id": 1, "text": "romantic idealizm vs pozytywistyczna praca"}, {"id": 2, "text": "wierność tradycji i honor kupiecka"}, {"id": 3, "text": "nauka i wynalazczość"}], "matchingType": "characters_attitudes"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-4,positivism,batch-2025-01}', NULL, '2025-10-24 22:16:52.344', '2025-10-24 22:16:52.344', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev88q003rqhd9zauco2bl', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 5, 4, 'Uzupełnij tekst naukowy odpowiednimi terminami lingwistycznymi.', '{"gaps": [{"id": 1, "options": ["wrodzona", "nabyta", "społeczna", "kulturowa"]}, {"id": 2, "options": ["performancja", "gramatyka", "składnia", "semantyka"]}, {"id": 3, "options": ["Fonologia", "Morfologia", "Struktura", "Pragmatyka"]}], "textWithGaps": "Według teorii Chomsky''ego, [1] kompetencja językowa to wiedza, którą posiadamy, podczas gdy [2] to rzeczywiste użycie języka. [3] głęboka reprezentuje znaczenie, a powierzchniowa - formę."}', '[0, 0, 2]', NULL, '{language_use,closed_multiple,difficulty-5,batch-2025-01}', NULL, '2025-10-24 22:16:52.347', '2025-10-24 22:16:52.347', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev88t003sqhd981p02ux5', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', NULL, 5, 3, 'Które fragmenty zawierają ironię romantyczną?', '{"options": ["Sam sobie przyglądał się z boku, jakby był kimś innym", "Śmiech przez łzy - to paradoks ludzkiego losu", "Autor wkracza w tekst: ''Nie wiem, co dalej z nim będzie...''", "Życie jest piękne i straszne zarazem", "Bohater umiera, ale narrator żyje dalej"]}', '[0, 2, 4]', NULL, '{historical_literary,closed_multiple,difficulty-5,batch-2025-01}', NULL, '2025-10-24 22:16:52.349', '2025-10-24 22:16:52.349', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev88v003tqhd93xfwlc1d', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 4, 3, 'Które wyrażenia są przykładami eufemizmów (łagodzenia)?', '{"options": ["odejść na wieczny spoczynek (umrzeć)", "osoba w podeszłym wieku (starzec)", "dać w twarz (uderzyć)", "być w ciąży (być brzuchatą)", "wyzionąć ducha (umrzeć)"]}', '[0, 1, 3]', NULL, '{language_use,closed_multiple,difficulty-4,batch-2025-01}', NULL, '2025-10-24 22:16:52.351', '2025-10-24 22:16:52.351', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev88x003uqhd9k2et1woa', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 5, 5, 'Dopasuj techniki narracyjne postmodernistyczne do przykładów.', '{"leftColumn": [{"id": "A", "text": "metafikcja"}, {"id": "B", "text": "intertekstualność"}, {"id": "C", "text": "pastisz"}], "rightColumn": [{"id": 1, "text": "narrator komentuje proces pisania książki"}, {"id": 2, "text": "cytaty i aluzje do innych dzieł"}, {"id": 3, "text": "naśladowanie stylu różnych epok"}], "matchingType": "techniques_examples"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-5,contemporary,batch-2025-01}', NULL, '2025-10-24 22:16:52.354', '2025-10-24 22:16:52.354', NULL);
