INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8am004lqhd9vitge3cm', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 3, 'Przyporządkuj funkcje języka do przykładów.', '{"leftColumn": [{"id": "A", "text": "Halo? Słyszysz mnie?"}, {"id": "B", "text": "Jestem bardzo szczęśliwy!"}, {"id": "C", "text": "Woda wrze w 100°C"}], "rightColumn": [{"id": 1, "text": "funkcja fatyczna"}, {"id": 2, "text": "funkcja emotywna"}, {"id": 3, "text": "funkcja poznawcza"}], "matchingType": "language_functions"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.414', '2025-10-24 22:16:52.414', NULL);
