INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8at004oqhd91liqqp5k', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 3, 'Uzupełnij analizę stylistyczną.', '{"gaps": [{"id": 1, "options": ["''spadały''", "''złote''", "''drzew''", "''z''"]}, {"id": 2, "options": ["''złote''", "''spadały''", "''liście''", "''drzew''"]}, {"id": 3, "options": ["podmiotu", "orzeczenia", "przydawki", "dopełnienia"]}], "textWithGaps": "W zdaniu ''Złote liście spadały z drzew'' epitet [1] określa rzeczownik [2] i pełni funkcję [3]."}', '[1, 2, 2]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.421', '2025-10-24 22:16:52.421', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8av004pqhd9bsuhsa4k', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'W których zdaniach występuje apostrofa?', '{"options": ["O Muzo! Wspomóż mnie!", "Pada deszcz.", "Litwo! Ojczyzno moja!", "Czytam książkę.", "Boże, pomóż nam!"]}', '[0, 2, 4]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.424', '2025-10-24 22:16:52.424', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8ax004qqhd9eyc00mgc', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'Które wyrażenia są frazeologizmami?', '{"options": ["rzucać słowa na wiatr", "iść do domu", "mieć muchy w nosie", "czytać książkę", "robić z igły widły"]}', '[0, 2, 4]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.426', '2025-10-24 22:16:52.426', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8b0004rqhd9oty416gj', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 3, 1, 'Przeczytaj fragment i odpowiedz na pytanie.', '{"options": ["apostrofa", "metafora", "porównanie", "symbol"], "question": "Jaki środek stylistyczny dominuje w tym fragmencie?", "sourceText": {"text": "Który skrzywdziłeś człowieka prostego\nŚmiechem nad krzywdą jego wybuchając,\nGromadę błaznów koło siebie mając\nNa pomieszanie dobrego i złego...", "title": "Który skrzywdziłeś", "author": "Czesław Miłosz"}}', '0', NULL, '{language_use,closed_single,difficulty-3,batch-2025-01}', '{"explanation": "Apostrofa - zwrot do osoby ''który skrzywdziłeś''"}', '2025-10-24 22:16:52.428', '2025-10-24 22:16:52.428', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8b2004sqhd99jomk2t8', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 3, 1, 'Przeczytaj fragment i określ dominujący środek stylistyczny.', '{"options": ["paradoks", "metafora", "porównanie", "hiperbola"], "question": "Jaki środek stylistyczny dominuje w tym fragmencie?", "sourceText": {"text": "Nic dwa razy się nie zdarza\ni nie zdarzy. Z tej przyczyny\nzrodziliśmy się bez wprawy\ni pomrzemy bez rutyny.", "title": "Nic dwa razy", "author": "Wisława Szymborska"}}', '0', NULL, '{language_use,closed_single,difficulty-3,batch-2025-01}', '{"explanation": "Paradoks - sprzeczność pozorna: ''bez wprawy/bez rutyny''"}', '2025-10-24 22:16:52.43', '2025-10-24 22:16:52.43', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8b4004tqhd958286ksk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', NULL, 2, 1, 'Przeczytaj fragment i określ epokę literacką.', '{"options": ["renesans", "barok", "oświecenie", "romantyzm"], "question": "Z której epoki pochodzi ten fragment?", "sourceText": {"text": "Biada temu, kto żyw będąc, śmierci wzywa,\nBo tego śmierć nie słucha, kto jej wzywać śmie.", "author": "nieznany"}}', '1', NULL, '{historical_literary,closed_single,difficulty-2,batch-2025-01}', '{"explanation": "Barok - motyw vanitas, śmierci"}', '2025-10-24 22:16:52.433', '2025-10-24 22:16:52.433', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8b7004uqhd9fh9llpje', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 2, 1, 'Określ typ zdania.', '{"options": ["pojedyncze rozwinięte", "złożone współrzędnie", "złożone podrzędnie", "wielokrotnie złożone"], "question": "Jakie to zdanie?", "sentence": "Gdyby nie padało, poszlibyśmy na spacer."}', '2', NULL, '{language_use,closed_single,difficulty-2,batch-2025-01}', '{"explanation": "Zdanie złożone podrzędnie okolicznikowe warunku"}', '2025-10-24 22:16:52.435', '2025-10-24 22:16:52.435', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8b9004vqhd9dve2t04t', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 3, 1, 'Zinterpretuj symbol w kontekście.', '{"context": "W ''Lalce'' Prusa motyw lalki pojawia się wielokrotnie.", "options": ["dzieciństwo bohatera", "sztuczność relacji społecznych", "zabawkę", "przemysł"], "question": "Co symbolizuje lalka w powieści?"}', '1', NULL, '{language_use,closed_single,difficulty-3,batch-2025-01}', '{"explanation": "Lalka symbolizuje sztuczność i pustkę relacji społecznych"}', '2025-10-24 22:16:52.437', '2025-10-24 22:16:52.437', NULL);
