INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8es006kqhd9s186vs6o', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 2, 'Kto jest autorem ''Tanga''?', '{"options": ["Mrożek", "Różewicz", "Herbert", "Gombrowicz"]}', '0', NULL, '{historical_literary,closed_single,difficulty-4,contemporary,batch-2025-01}', NULL, '2025-10-24 22:16:52.565', '2025-10-24 22:16:52.565', 'Tango');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8eu006lqhd9ju9xpuac', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Który artysta był twórcą hasła ''sztuka dla sztuki''?', '{"options": ["Przybyszewski", "Wyspiański", "Żeromski", "Reymont"]}', '0', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', NULL, '2025-10-24 22:16:52.567', '2025-10-24 22:16:52.567', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8ex006mqhd9kev0hxm5', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 2, 1, 'Który wyraz jest przysłówkiem?', '{"options": ["zielony", "zieleń", "zielono", "zielenieć"]}', '2', NULL, '{language_use,closed_single,difficulty-2,batch-2025-01}', '{"explanation": "Przysłówek odpowiada na pytanie ''jak?'' - zielono."}', '2025-10-24 22:16:52.569', '2025-10-24 22:16:52.569', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8ez006nqhd9cnyloy4y', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 3, 1, 'W którym zdaniu występuje orzeczenie złożone?', '{"options": ["Anna czyta.", "Piotr będzie czytał.", "Dzieci śpią.", "Mama gotuje."]}', '1', NULL, '{language_use,closed_single,difficulty-3,batch-2025-01}', '{"explanation": "Orzeczenie złożone składa się z czasownika posiłkowego i głównego."}', '2025-10-24 22:16:52.571', '2025-10-24 22:16:52.571', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8f1006oqhd9nqzt0icc', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 1, 1, 'Która część mowy odmienia się przez przypadki?', '{"options": ["czasownik", "rzeczownik", "przysłówek", "wykrzyknik"]}', '1', NULL, '{language_use,closed_single,difficulty-1,batch-2025-01}', NULL, '2025-10-24 22:16:52.574', '2025-10-24 22:16:52.574', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8f3006pqhd9p680dzwa', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Przeczytaj fragment i określ jego funkcję w strukturze utworu.', '{"options": ["eksponuje konflikt wewnętrzny bohatera", "ukazuje dojrzewanie do misji mesjańskiej", "przedstawia zwątpienie w sens walki", "zapowiada klęskę powstania"], "question": "Jaka jest funkcja tego monologu w strukturze dramatu?", "sourceText": {"text": "Ty mi dajesz odwagę, siłę, zapał do boju,\nTy mi każesz wytrwać na posterunku,\nBo wiem: dla mojej ziemi, dla mego narodu\nŻyję, walczę i cierpię.", "title": "Dziady cz. III", "author": "Adam Mickiewicz"}}', '1', NULL, '{historical_literary,closed_single,difficulty-4,romanticism,batch-2025-01}', '{"explanation": "Fragment pokazuje proces duchowego dojrzewania Konrada do przyjęcia misji narodowej."}', '2025-10-24 22:16:52.576', '2025-10-24 22:16:52.576', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8f6006qqhd9qd3yqfn9', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 5, 3, 'Przeanalizuj środki stylistyczne w kontekście znaczeniowym.', '{"text": "Ciemność widzę, ciemność nieprzebytą,\nJako gęsty, jaki straszny las.", "options": ["metafora - wizualizacja lęku egzystencjalnego", "porównanie - intensyfikacja uczucia zagubienia", "symbol - reprezentacja niewiedzy", "personifikacja - ożywienie abstrakcji"], "question": "Który środek stylistyczny dominuje i jaką pełni funkcję?"}', '1', NULL, '{language_use,closed_single,difficulty-5,batch-2025-01}', '{"explanation": "Porównanie ''jako... las'' służy wzmocnieniu wrażenia bezradności wobec nieznanego."}', '2025-10-24 22:16:52.578', '2025-10-24 22:16:52.578', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8f8006rqhd9sfch7z75', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 3, 'Interpretacja symboliczna w kontekście ideologii epoki.', '{"context": "W ''Lalce'' Wokulski chce wznieść się balonem i obserwować Warszawę z góry.", "options": ["ucieczkę od rzeczywistości społecznej", "próbę obiektywnego spojrzenia na mechanizmy społeczne", "romantyczny idealizm i oderwanie od realności", "triumf nauki nad przesądami"], "question": "Co symbolizuje ta scena w kontekście pozytywistycznego programu?"}', '1', NULL, '{historical_literary,closed_single,difficulty-5,positivism,batch-2025-01}', '{"explanation": "Balon symbolizuje pozytywistyczną potrzebę dystansu i naukowej obserwacji społeczeństwa."}', '2025-10-24 22:16:52.58', '2025-10-24 22:16:52.58', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8fb006sqhd9osqbxsbk', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 4, 2, 'Określ funkcję interpunkcji w kontekście semantycznym.', '{"options": ["wprowadza wyjaśnienie i podkreśla kontrast", "sygnalizuje przerwę w mówieniu", "zastępuje opuszczone słowa", "oddziela człony wyliczenia"], "question": "Jaka jest funkcja myślnika w tym zdaniu?", "sentence": "Milczenie - to kamień węgielny mądrości; słowo - to jej ruina."}', '0', NULL, '{language_use,closed_single,difficulty-4,batch-2025-01}', '{"explanation": "Myślnik wprowadza definicję i wzmacnia antytezę milczenie-słowo."}', '2025-10-24 22:16:52.584', '2025-10-24 22:16:52.584', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evahm0133qhd9a2azg0kz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 1, 'Kto jest autorem tragedii ''Makbet''?', '{"options": ["Christopher Marlowe", "William Shakespeare", "Ben Jonson", "Thomas Kyd"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,renaissance,batch-2025-01}', '{"explanation": "Autorem ''Makbeta'' jest William Shakespeare. Tragedia powstała około 1606 roku."}', '2025-10-24 22:16:55.259', '2025-10-24 22:16:55.259', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ew0096qh49jm691ztx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Jak strukturalizm (Levi-Strauss) interpretuje mit o Edypie?', '{"options": ["Jako opis historycznych wydarzeń w Tebach", "Jako system opozycji binarnych dotyczących pochodzenia człowieka", "Jako prostą baśń ludową bez głębszej struktury", "Jako tekst wyłącznie religijny"]}', '1', NULL, '{strukturalizm,Levi-Strauss,"opozycje binarne"}', '{"explanation": "Levi-Strauss analizował mit edypalny jako system opozycji binarnych: autochtonizm vs. narodziny z rodziców."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8fe006tqhd90id4v8q5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 3, 'Analiza intertekstualna - rozpoznaj nawiązanie.', '{"text": "Postać Chochoła w ''Weselu'' wypowiada kwestie nawiązujące do wcześniejszych dzieł.", "options": ["romantyczny demonizm i ''Dziadów'' Mickiewicza", "ludowa bajka o strachu na wróble", "realistyczna obserwacja wsi polskiej", "symbolika chrześcijańska"], "question": "Do jakiej tradycji literackiej nawiązuje figura Chochoła?"}', '0', NULL, '{historical_literary,closed_single,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Chochoł jest alegoriąparaliżu narodowego, nawiązuje do ''Dziadów'' i romantycznego mesjanizmu."}', '2025-10-24 22:16:52.586', '2025-10-24 22:16:52.586', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8fg006uqhd9y57pdo04', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 5, 3, 'Rozpoznaj figurę retoryczną i jej pragmatyczną funkcję.', '{"text": "Czyż nie widzisz, że milczy? Czyż nie słyszysz tej ciszy? Czyż nie czujesz tego braku?", "options": ["pytanie retoryczne - wzbudzanie emocji odbiorcy", "anafora - rytmizacja wypowiedzi", "gradacja pytań retorycznych - nasilanie dramatyzmu", "polipton - gra słowna"], "question": "Jaka figura retoryczna dominuje i co wyraża?"}', '2', NULL, '{language_use,closed_single,difficulty-5,batch-2025-01}', '{"explanation": "Połączenie anafory (''Czyż'') z gradacją tworzy nasilający się dramatyzm."}', '2025-10-24 22:16:52.588', '2025-10-24 22:16:52.588', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8fi006vqhd9m5e8s8as', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 3, 'Interpretacja motywu w kontekście filozofii absurdu.', '{"motif": "Powtarzające się pytanie Artura: ''Gdzie są formy?''", "options": ["nostalgię za Belle Époque", "próbę nadania sensu chaotycznej rzeczywistości", "krytykę mieszczańskich konwenansów", "tęsknotę za autorytetem ojca"], "question": "Co symbolizuje obsesja Artura na punkcie ''form''?"}', '1', NULL, '{historical_literary,closed_single,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Formy reprezentują porządek i sens, których Artur desperacko szuka w absurdalnym świecie."}', '2025-10-24 22:16:52.591', '2025-10-24 22:16:52.591', 'Tango');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8fl006wqhd9o4ahq8hs', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 4, 2, 'Określ typ i funkcję zdania złożonego.', '{"options": ["wielokrotnie złożone: przyczyna → skutek → przeciwstawienie", "współrzędnie złożone z łącznikiem ''a''", "podrzędnie złożone okolicznikowe", "równoważniki zdań"], "question": "Jaki typ zdania i jakie relacje logiczne łączą człony?", "sentence": "Ponieważ deszcz padał bez przerwy, a wiatr łamał gałęzie, postanowiliśmy zostać w domu, choć wcześniej planowaliśmy wycieczkę."}', '0', NULL, '{language_use,closed_single,difficulty-4,batch-2025-01}', '{"explanation": "Zdanie zawiera przyczynę (ponieważ), łącznik (a) i przeciwstawienie (choć)."}', '2025-10-24 22:16:52.593', '2025-10-24 22:16:52.593', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8fn006xqhd9mhcc1z5e', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 5, 3, 'Rozpoznaj poetykę i jej filozoficzne podstawy.', '{"text": "Nic w przyrodzie nie ginie,\nPył się z pyłem zrównuje -\nJeno cienka struna\nW ludzkim sercu tli.", "author": "Leopold Staff", "options": ["nihilizm - brak trwałych wartości", "witalizm - afirmacja życia mimo przemijania", "pesymizm - świadomość nieuchronności śmierci", "panteizm - jedność z naturą"], "question": "Jaka idea filozoficzna dominuje w tym fragmencie?"}', '1', NULL, '{historical_literary,closed_single,difficulty-5,interwar,batch-2025-01}', '{"explanation": "Staff podkreśla ''cienką strunę'' w sercu - symbol niezniszczalnego ludzkiego ducha."}', '2025-10-24 22:16:52.595', '2025-10-24 22:16:52.595', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8fp006yqhd9h5s9n699', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 5, 3, 'Analiza semantyczna neologizmu w kontekście.', '{"text": "Witkacy pisał o ''niezaspokojeniu metafizycznym'' jako źródle sztuki.", "options": ["frustrację materialistyczną", "egzystencjalną pustę i pytanie o sens bytu", "konflikt między ciałem a duchem", "krytykę religii"], "question": "Co oznacza neologizm ''niezaspokojenie metafizyczne''?"}', '1', NULL, '{language_use,closed_single,difficulty-5,batch-2025-01}', '{"explanation": "Termin Witkacego opisuje fundamentalny niepokój egzystencjalny człowieka."}', '2025-10-24 22:16:52.598', '2025-10-24 22:16:52.598', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8fr006zqhd9fwfk5jdu', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 4, 2, 'Interpretacja motywu vanitas w kontekście barokowej estetyki.', '{"text": "Czego chcesz od nas, Panie, za Twe hojne dary?\nCzegóż - jeno abyśmy żyli nie marnie.", "options": ["carpe diem - chwytaj dzień", "vanitas - marność życia", "memento mori - pamiętaj o śmierci", "ubi sunt - gdzie są dawni?"], "question": "Jaka idea barokowa dominuje w tym fragmencie?"}', '1', NULL, '{historical_literary,closed_single,difficulty-4,baroque,batch-2025-01}', '{"explanation": "Fragment wyraża świadomość przemijania i marności doczesności."}', '2025-10-24 22:16:52.6', '2025-10-24 22:16:52.6', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8fu0070qhd9ljss67r8', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 4, 2, 'Określ funkcję enjambement w kontekście znaczeniowym.', '{"text": "Wiatr od strony morza\nwieje, a w nim zapach\nsoli i wodorostów.", "options": ["imitacja naturalnego rytmu oddechu", "podkreślenie napięcia semantycznego", "wizualizacja ruchu wiatru i fal", "zakłócenie regularności wersyfikacyjnej"], "question": "Jaka jest funkcja przerzutni w tym fragmencie?"}', '2', NULL, '{language_use,closed_single,difficulty-4,batch-2025-01}', '{"explanation": "Przerzutnia naśladuje falowy ruch wiatru morskiego."}', '2025-10-24 22:16:52.602', '2025-10-24 22:16:52.602', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8fw0071qhd9mqcpio8x', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 3, 'Rozpoznaj koncepcję filozoficzną w utworze renesansowym.', '{"context": "Ksantypa wygłasza mowę o godności człowieka.", "options": ["antropocentryzm i humanizm renesansowy", "teocentryzm średniowieczny", "determinizm barokowy", "racjonalizm oświeceniowy"], "question": "Jaka idea filozoficzna leży u podstaw tej mowy?"}', '0', NULL, '{historical_literary,closed_single,difficulty-5,renaissance,batch-2025-01}', '{"explanation": "Renesans stawiał człowieka w centrum - homo mensura."}', '2025-10-24 22:16:52.604', '2025-10-24 22:16:52.604', 'Odprawa posłów greckich');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8fy0072qhd9n0eklwk2', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 5, 3, 'Analiza składniowa - rozpoznaj funkcję konstrukcji bezokolicznikowej.', '{"options": ["oba są podmiotami", "''milczeć'' - podmiot, ''godzić się'' - orzecznik", "oba są orzeczeniami", "''milczeć'' - dopełnienie, ''godzić się'' - okolicznik"], "question": "Jaka jest funkcja składniowa bezokoliczników w tym zdaniu?", "sentence": "Milczeć znaczy godzić się na zło."}', '1', NULL, '{language_use,closed_single,difficulty-5,batch-2025-01}', '{"explanation": "Bezokolicznik podmiotowy + orzeczenie ''znaczy'' + bezokolicznik w funkcji orzecznika."}', '2025-10-24 22:16:52.606', '2025-10-24 22:16:52.606', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8g00073qhd9swxv04p0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ENLIGHTENMENT', 4, 3, 'Interpretacja satyry w kontekście programu oświecenia.', '{"options": ["wszelką religijność jako przesąd", "hipokryzję i wyzyskiwanie ludzi przez zepsuty kler", "instytucję monastycyzmu jako taką", "niewykształcenie duchowieństwa"], "question": "Jaki aspekt rzeczywistości krytykuje Krasicki w ''Mona chomachia''?"}', '1', NULL, '{historical_literary,closed_single,difficulty-4,enlightenment,batch-2025-01}', '{"explanation": "Krasicki krytykuje nadużycia, nie samą wiarę - typowo oświeceniowo."}', '2025-10-24 22:16:52.609', '2025-10-24 22:16:52.609', 'Monachomachia');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8g30074qhd9exlduihk', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 4, 2, 'Rozróżnienie między homonimami a polisemią.', '{"options": ["oba to homonimia", "pierwszy - homonimia, drugi - polisemia", "pierwszy - polisemia, drugi - homonimia", "oba to polisemia"], "examples": ["zamek (budowla) / zamek (w drzwiach)", "góra (wzniesienie) / góra (kierunek)"], "question": "Które przykłady reprezentują homonimię, a które polisemię?"}', '1', NULL, '{language_use,closed_single,difficulty-4,batch-2025-01}', '{"explanation": "Zamki to różne słowa (homonimia), góra to jedno słowo z różnymi znaczeniami (polisemia)."}', '2025-10-24 22:16:52.611', '2025-10-24 22:16:52.611', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8g50075qhd984qrp393', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 5, 3, 'Interpretacja strategii narracyjnej postmodernistycznej.', '{"author": "Olga Tokarczuk", "options": ["strukturalizm - szukanie głębokich struktur", "postmodernizm - krytyka wielkich narracji", "realizm - wierność rzeczywistości", "symbolizm - ukryte znaczenia"], "question": "Jaka filozofia stoi za tą strategią narracyjną?", "technique": "Narrator w ''Biegunach'' łamie konwencje narracyjne, miesza gatunki, prezentuje fragmentaryczność."}', '1', NULL, '{historical_literary,closed_single,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "Fragmentaryczność i mieszanie gatunków to typowe strategie postmodernistyczne."}', '2025-10-24 22:16:52.614', '2025-10-24 22:16:52.614', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8g80076qhd97p544jb6', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 5, 3, 'Analiza pragmatyczna wypowiedzi - rozpoznaj akt mowy.', '{"options": ["asertyw - stwierdzenie faktu", "komisyw - zobowiązanie do działania", "ekspresyw - wyrażenie emocji", "deklaratyw - zmiana stanu rzeczy"], "question": "Jaki typ aktu mowy reprezentuje ta wypowiedź według teorii Austina?", "sentence": "Obiecuję, że przyjdę jutro o dziesiątej."}', '1', NULL, '{language_use,closed_single,difficulty-5,batch-2025-01}', '{"explanation": "Obietnica to komisyw - mówiący zobowiązuje się do przyszłego działania."}', '2025-10-24 22:16:52.616', '2025-10-24 22:16:52.616', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8ga0077qhd9aabeymgo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 2, 'Interpretacja symbolu narodowego w kontekście mesjanizmu.', '{"text": "Polska jest Chrystusem narodów - cierpi za grzechy innych.", "options": ["mesjanizm polski - misja zbawcza narodu", "patriotyzm - miłość do ojczyzny", "nacjonalizm - wyższość własnego narodu", "internacjonalizm - solidarność narodów"], "question": "Jaka idea romantyczna jest wyrażona w tym stwierdzeniu?"}', '0', NULL, '{historical_literary,closed_single,difficulty-4,romanticism,batch-2025-01}', '{"explanation": "Mesjanizm - wiara w zbawczą misję Polski wobec innych narodów."}', '2025-10-24 22:16:52.619', '2025-10-24 22:16:52.619', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8gd0078qhd98dsaq3l4', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 4, 2, 'Rozpoznaj typ błędu językowego i jego przyczynę.', '{"options": ["kontaminacja - ''spotkać się z kimś'' + ''pójść do kina''", "pleonazm - nadmiarowość", "tautologia - powtórzenie", "paralelizm składniowy - błędna analogia"], "question": "Jaki błąd występuje w tym zdaniu?", "sentence": "Spotkałem się z kolegą do kina."}', '0', NULL, '{language_use,closed_single,difficulty-4,batch-2025-01}', '{"explanation": "Kontaminacja dwóch konstrukcji: ''spotkałem się z kolegą'' i ''poszedłem z kolegą do kina''."}', '2025-10-24 22:16:52.621', '2025-10-24 22:16:52.621', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8gf0079qhd9auze6jc6', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 4, 2, 'Co to jest anakolut?', '{"options": ["Powtórzenie wyrazu", "Niedokończone zdanie", "Niezgodność składniowa", "Pytanie retoryczne"]}', '2', NULL, '{language_use,closed_single,difficulty-4,batch-2025-01}', NULL, '2025-10-24 22:16:52.624', '2025-10-24 22:16:52.624', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8gi007aqhd9j5994qto', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 2, 1, 'Który wyraz jest złożeniem?', '{"options": ["pisać", "napisać", "czasopismo", "pisarz"]}', '2', NULL, '{language_use,closed_single,difficulty-2,batch-2025-01}', NULL, '2025-10-24 22:16:52.626', '2025-10-24 22:16:52.626', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8gl007bqhd99xzsubkt', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 3, 1, 'W którym zdaniu występuje dopełnienie?', '{"options": ["Pada deszcz.", "Jan czyta książkę.", "Dzieci śpią.", "Jest zimno."]}', '1', NULL, '{language_use,closed_single,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.629', '2025-10-24 22:16:52.629', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8gn007cqhd98itbma0f', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 2, 1, 'Co to jest pleonazm?', '{"options": ["Skrót myślowy", "Nadmiar słów", "Brak wyrazu", "Zmiana szyku"]}', '1', NULL, '{language_use,closed_single,difficulty-2,batch-2025-01}', '{"explanation": "Pleonazm to użycie zbędnych, powtarzających się znaczeniowo wyrazów."}', '2025-10-24 22:16:52.631', '2025-10-24 22:16:52.631', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8gq007dqhd9it0spkeq', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 4, 2, 'W którym wyrażeniu występuje oksymoron?', '{"options": ["głucha cisza", "biały śnieg", "gorąca kawa", "zimna woda"]}', '0', NULL, '{language_use,closed_single,difficulty-4,batch-2025-01}', '{"explanation": "Oksymoron to zestawienie sprzecznych pojęć."}', '2025-10-24 22:16:52.634', '2025-10-24 22:16:52.634', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8gt007eqhd9mlxjrgf6', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 1, 1, 'Która litera jest spółgłoską?', '{"options": ["a", "e", "k", "y"]}', '2', NULL, '{language_use,closed_single,difficulty-1,batch-2025-01}', NULL, '2025-10-24 22:16:52.637', '2025-10-24 22:16:52.637', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8gw007fqhd98jgwwg3d', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 3, 1, 'Co to jest eufonia?', '{"options": ["Błąd językowy", "Dźwięczność wypowiedzi", "Rodzaj metafory", "Typ zdania"]}', '1', NULL, '{language_use,closed_single,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.64', '2025-10-24 22:16:52.64', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8gy007gqhd923mvhyq5', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 6, 'Napisz notatkę porównawczą o bohaterach romantycznych.', '{"topic": "Porównaj postawę Konrada z ''Dziadów'' i Kordiana z dramatu Słowackiego", "requirements": ["cechy Konrada (3 punkty)", "cechy Kordiana (3 punkty)", "główna różnica między nimi", "150-200 słów"]}', NULL, NULL, '{historical_literary,synthesis_note,difficulty-3,romanticism,batch-2025-01}', NULL, '2025-10-24 22:16:52.643', '2025-10-24 22:16:52.643', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8h2007hqhd9tbxyjlfr', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 6, 'Opisz program pozytywizmu.', '{"topic": "Jakie były główne założenia pozytywizmu polskiego?", "requirements": ["praca organiczna - wyjaśnienie", "praca u podstaw - przykłady", "rola nauki i edukacji", "odrzucenie romantyzmu", "200-250 słów"]}', NULL, NULL, '{historical_literary,synthesis_note,difficulty-3,positivism,batch-2025-01}', NULL, '2025-10-24 22:16:52.646', '2025-10-24 22:16:52.646', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8h4007iqhd9lf73qa5k', 'SYNTHESIS_NOTE', 'LANGUAGE_USE', NULL, 2, 5, 'Wyjaśnij różnice między rodzajami zdań.', '{"topic": "Czym różni się zdanie pojedyncze od złożonego?", "requirements": ["definicja zdania pojedynczego + przykład", "definicja zdania współrzędnie złożonego + przykład", "definicja zdania podrzędnie złożonego + przykład", "120-150 słów"]}', NULL, NULL, '{language_use,synthesis_note,difficulty-2,batch-2025-01}', NULL, '2025-10-24 22:16:52.649', '2025-10-24 22:16:52.649', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8h7007jqhd9ehf4gm3y', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 3, 6, 'Scharakteryzuj epokę renesansu.', '{"topic": "Jakie były główne cechy renesansu w Polsce?", "requirements": ["humanizm - co to znaczy", "zainteresowanie antykiem", "najważniejsi twórcy (3 osoby)", "przykładowe dzieła", "180-220 słów"]}', NULL, NULL, '{historical_literary,synthesis_note,difficulty-3,renaissance,batch-2025-01}', NULL, '2025-10-24 22:16:52.651', '2025-10-24 22:16:52.651', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8h9007kqhd9t1ih2tvb', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', NULL, 4, 8, 'Napisz notatkę syntetyzującą - porównanie koncepcji.', '{"topic": "Porównaj koncepcje bohatera literackiego w romantyzmie i pozytywizmie", "requirements": ["cechy bohatera romantycznego (3 punkty)", "cechy bohatera pozytywistycznego (3 punkty)", "kluczowe różnice (kontekst ideowy epok)", "przykłady: Konrad vs Wokulski", "250-300 słów", "struktura: wprowadzenie, porównanie, wnioski"]}', NULL, NULL, '{historical_literary,synthesis_note,difficulty-4,batch-2025-01}', '{"expectedConcepts": ["romantyzm: indywidualizm, bunt, wyjątkowość", "pozytywizm: praca organiczna, realizm, użyteczność", "różnice ideologiczne"]}', '2025-10-24 22:16:52.654', '2025-10-24 22:16:52.654', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8hc007lqhd901gxuk74', 'SYNTHESIS_NOTE', 'LANGUAGE_USE', NULL, 5, 8, 'Analiza i synteza - ewolucja pojęcia w historii języka.', '{"topic": "Opisz ewolucję funkcji metafory w literaturze polskiej od baroku do współczesności", "requirements": ["funkcja metafory w baroku (vanitas, emblematyka)", "metafora romantyczna (symbol, wieloznaczność)", "metafora awangardowa (innowacja, zaskoczenie)", "metafora postmodernistyczna (gra znaczeń)", "300-350 słów", "przykłady dla każdej epoki"]}', NULL, NULL, '{language_use,synthesis_note,difficulty-5,batch-2025-01}', '{"expectedConcepts": ["metafora barokowa - dydaktyka", "metafora romantyczna - emocja", "metafora awangardowa - eksperyment", "metafora postmodernistyczna - dekonstrukcja"]}', '2025-10-24 22:16:52.656', '2025-10-24 22:16:52.656', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8he007mqhd9a3vnamt2', 'SYNTHESIS_NOTE', 'LANGUAGE_USE', NULL, 4, 5, 'Porównaj dwa fragmenty pod względem stylu i przesłania.', '{"text1": {"author": "Mickiewicz", "fragment": "Ojczyzno moja! Ty jesteś jak zdrowie..."}, "text2": {"author": "Norwid", "fragment": "Ojczyzna to wielki zbiorowy obowiązek..."}, "requirements": ["porównanie stylu", "różnice w pojmowaniu ojczyzny", "kontekst epok", "80-100 słów"]}', NULL, NULL, '{language_use,synthesis_note,difficulty-4,batch-2025-01}', NULL, '2025-10-24 22:16:52.659', '2025-10-24 22:16:52.659', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8hh007nqhd9j9of2rib', 'SYNTHESIS_NOTE', 'LANGUAGE_USE', NULL, 3, 5, 'Napisz notatkę syntetyzującą: Rodzaje zdań złożonych w języku polskim (70-90 słów).', '{"requirements": ["zdania współrzędnie złożone", "zdania podrzędnie złożone", "przykłady", "70-90 słów"]}', NULL, NULL, '{language_use,synthesis_note,difficulty-3,batch-2025-01}', '{"explanation": "Notka powinna zawierać: podział na współrzędne (łączne, przeciwstawne, rozłączne) i podrzędne (podmiotowe, przydawkowe, dopełnieniowe, okolicznikowe)"}', '2025-10-24 22:16:52.661', '2025-10-24 22:16:52.661', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8hj007oqhd9y8anpfzy', 'SYNTHESIS_NOTE', 'LANGUAGE_USE', NULL, 4, 5, 'Sporządź notatkę: Funkcje języka według Romana Jakobsona (80-100 słów).', '{"requirements": ["6 funkcji języka", "krótka charakterystyka każdej", "80-100 słów"]}', NULL, NULL, '{language_use,synthesis_note,difficulty-4,batch-2025-01}', '{"explanation": "Funkcje: emotywna, konatywna, fatyczna, metajęzykowa, poetycka, poznawcza"}', '2025-10-24 22:16:52.664', '2025-10-24 22:16:52.664', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8hl007pqhd9jwcvd4xm', 'SYNTHESIS_NOTE', 'LANGUAGE_USE', NULL, 3, 5, 'Napisz notatkę: Zapożyczenia językowe w polszczyźnie (60-80 słów).', '{"requirements": ["typy zapożyczeń", "przykłady z różnych języków", "60-80 słów"]}', NULL, NULL, '{language_use,synthesis_note,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.666', '2025-10-24 22:16:52.666', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8hp007qqhd9qkhw4s0d', 'SYNTHESIS_NOTE', 'LANGUAGE_USE', NULL, 4, 5, 'Sporządź syntezę: Odmiany stylistyczne języka polskiego (90-110 słów).', '{"requirements": ["style funkcjonalne", "cechy charakterystyczne", "90-110 słów"]}', NULL, NULL, '{language_use,synthesis_note,difficulty-4,batch-2025-01}', NULL, '2025-10-24 22:16:52.669', '2025-10-24 22:16:52.669', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8hr007rqhd9bb0qn6a1', 'SYNTHESIS_NOTE', 'LANGUAGE_USE', NULL, 5, 5, 'Napisz notatkę: Ewolucja języka polskiego od średniowiecza do dziś (100-120 słów).', '{"requirements": ["główne etapy rozwoju", "najważniejsze zmiany", "100-120 słów"]}', NULL, NULL, '{language_use,synthesis_note,difficulty-5,batch-2025-01}', NULL, '2025-10-24 22:16:52.671', '2025-10-24 22:16:52.671', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8ht007sqhd9x0s5dqxk', 'SYNTHESIS_NOTE', 'LANGUAGE_USE', NULL, 3, 5, 'Sporządź syntezę: Części mowy w języku polskim (70-90 słów).', '{"requirements": ["podział na odmienne i nieodmienne", "przykłady", "70-90 słów"]}', NULL, NULL, '{language_use,synthesis_note,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.674', '2025-10-24 22:16:52.674', NULL);
