INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8jl008hqhd9rfd0umcf', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', NULL, 3, 4, 'Dopasuj pierwsze wersy do tytułów utworów.', '{"leftColumn": [{"id": "A", "text": "Litwo! Ojczyzno moja!"}, {"id": "B", "text": "Nam strzelać nie kazano"}, {"id": "C", "text": "Wlazł kotek na płotek"}, {"id": "D", "text": "Bogurodzica dziewica"}], "instruction": "Wybierz poprawne pary (np. A-1, B-2)", "rightColumn": [{"id": 1, "text": "Pan Tadeusz"}, {"id": 2, "text": "Reduta Ordona"}, {"id": 3, "text": "Bajki i przypowieści"}, {"id": 4, "text": "Bogurodzica"}], "matchingType": "first_lines_to_titles"}', '[[0, 0], [1, 1], [2, 2], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.737', '2025-10-24 22:16:52.737', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8jn008iqhd9ppycvoi3', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 2, 3, 'Uzupełnij luki poprawnymi formami wyrazów.', '{"gaps": [{"id": 1, "options": ["był", "jest", "będzie", "bywa"]}, {"id": 2, "options": ["romantyzm", "romantyzmu", "romantyzmie", "romantyzmem"]}, {"id": 3, "options": ["czytane są", "czyta się", "czytają", "czytano"]}], "textWithGaps": "Mickiewicz [1] największym poetą polskiego [2]. Jego utwory [3] do dziś."}', '[1, 1, 0]', NULL, '{language_use,closed_multiple,difficulty-2,batch-2025-01}', '{"explanation": "jest (czas teraźniejszy), romantyzmu (dopełniacz), czytane są (strona bierna)"}', '2025-10-24 22:16:52.74', '2025-10-24 22:16:52.74', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evahp0134qhd9t7dgwzvv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 1, 'Gdzie toczy się akcja tragedii?', '{"options": ["w Anglii", "w Irlandii", "w Szkocji", "w Walii"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,renaissance,batch-2025-01}', '{"explanation": "Akcja ''Makbeta'' toczy się w Szkocji w XI wieku."}', '2025-10-24 22:16:55.261', '2025-10-24 22:16:55.261', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evahr0135qhd9sqmsw2fs', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 1, 'Kim jest Duncan w tragedii?', '{"options": ["bratem Makbeta", "synem Makbeta", "królem Szkocji", "wrogiem Szkocji"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,renaissance,batch-2025-01}', '{"explanation": "Duncan jest prawowitym królem Szkocji, którego zabija Makbet."}', '2025-10-24 22:16:55.263', '2025-10-24 22:16:55.263', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8jq008jqhd9qpgjkjrt', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', NULL, 4, 5, 'Uzupełnij tabelę - przyporządkuj cechy do epok.', '{"rows": [{"gaps": [1, 2, 3], "epoch": "Renesans"}, {"gaps": [4, 5, 6], "epoch": "Romantyzm"}, {"gaps": [7, 8, 9], "epoch": "Pozytywizm"}], "headers": ["Epoka", "Hasło", "Gatunek", "Przedstawiciel"], "options": {"genres": ["sonet", "ballada", "nowela"], "authors": ["Kochanowski", "Mickiewicz", "Prus"], "slogans": ["humanizm", "mesjanizm", "praca organiczna"]}, "tableType": "epochs_characteristics"}', '[0, 0, 0, 1, 1, 1, 2, 2, 2]', NULL, '{historical_literary,closed_multiple,difficulty-4,batch-2025-01}', NULL, '2025-10-24 22:16:52.743', '2025-10-24 22:16:52.743', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8jt008kqhd918ps9t78', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', NULL, 2, 4, 'Dopasuj postacie do utworów, w których występują.', '{"options": ["Wokulski - Lalka", "Konrad - Dziady", "Judym - Ludzie bezdomni", "Kmicic - Potop", "Wokulski - Dziady", "Konrad - Potop", "Judym - Lalka", "Kmicic - Ludzie bezdomni"]}', '[0, 1, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,batch-2025-01}', '{"explanation": "Wokulski to bohater ''Lalki'', Konrad - ''Dziadów'', Judym - ''Ludzi bezdomnych'', Kmicic - ''Potopu''"}', '2025-10-24 22:16:52.746', '2025-10-24 22:16:52.746', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8jw008lqhd9uvyfxpe6', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 2, 3, 'Uzupełnij luki w tekście odpowiednimi formami wyrazów.', '{"gaps": [{"id": 1, "options": ["najważniejszy", "najważniejszym", "najważniejszego", "najważniejszemu"]}, {"id": 2, "options": ["renesansu", "renesansie", "renesansem", "renesansowi"]}, {"id": 3, "options": ["Trenów", "Trenami", "Treny", "Trenom"]}], "textWithGaps": "Jan Kochanowski był [1] poetą polskiego [2]. Jego [3] to arcydzieło literatury."}', '[1, 0, 2]', NULL, '{language_use,closed_multiple,difficulty-2,batch-2025-01}', '{"explanation": "Poprawne formy: najważniejszym (narzędnik), renesansu (dopełniacz), Treny (mianownik)"}', '2025-10-24 22:16:52.748', '2025-10-24 22:16:52.748', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8jy008mqhd9kvlsb9p8', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 2, 2, 'Które wyrazy są nieodmienne?', '{"options": ["wczoraj", "dom", "szybko", "ale"]}', '[0, 2, 3]', NULL, '{language_use,closed_multiple,difficulty-2,batch-2025-01}', '{"explanation": "Wczoraj (przysłówek), szybko (przysłówek), ale (spójnik) są nieodmienne"}', '2025-10-24 22:16:52.751', '2025-10-24 22:16:52.751', NULL);
