INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8k8008qqhd9qbs88hbv', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Które motywy są charakterystyczne dla romantyzmu?', '{"options": ["natura", "rozum", "uczucia", "mistycyzm"]}', '[0, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-3,romanticism,batch-2025-01}', NULL, '2025-10-24 22:16:52.76', '2025-10-24 22:16:52.76', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8ka008rqhd950qj9r6j', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', NULL, 2, 2, 'Które epoki literackie przypadały na XIX wiek?', '{"options": ["romantyzm", "pozytywizm", "renesans", "Młoda Polska"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,batch-2025-01}', NULL, '2025-10-24 22:16:52.762', '2025-10-24 22:16:52.762', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8kc008sqhd9brbmr66z', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', NULL, 4, 2, 'Którzy poeci tworzyli poezję lingwistyczną?', '{"options": ["Białoszewski", "Karpowicz", "Herbert", "Szymborska"]}', '[0, 1]', NULL, '{historical_literary,closed_multiple,difficulty-4,batch-2025-01}', NULL, '2025-10-24 22:16:52.765', '2025-10-24 22:16:52.765', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8kf008tqhd96srpdi6f', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 2, 2, 'Które wyrazy są przysłówkami?', '{"options": ["szybko", "szybki", "wczoraj", "biec"]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-2,batch-2025-01}', '{"explanation": "Przysłówki to: szybko (sposób) i wczoraj (czas). ''Szybki'' to przymiotnik, ''biec'' to czasownik."}', '2025-10-24 22:16:52.767', '2025-10-24 22:16:52.767', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8kh008uqhd9aoe7v4kv', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'W których zdaniach występuje porównanie?', '{"options": ["Był silny jak dąb.", "Miał stalowe nerwy.", "Płakał jak dziecko.", "Jego serce było z kamienia."]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', '{"explanation": "Porównania używają słów ''jak'', ''jakby'', ''niby''. Opcje B i D to metafory."}', '2025-10-24 22:16:52.769', '2025-10-24 22:16:52.769', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8kj008vqhd9m8umzajh', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'Które wyrazy pochodzą z języka łacińskiego?', '{"options": ["konstytucja", "komputer", "uniwersytet", "telefon"]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', '{"explanation": "Konstytucja i uniwersytet to zapożyczenia z łaciny. Komputer to anglicyzm, telefon - z greki."}', '2025-10-24 22:16:52.771', '2025-10-24 22:16:52.771', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8kl008wqhd9rm3pyqo7', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 4, 2, 'W których zdaniach występuje elipsa (wyrzutnia)?', '{"options": ["Ja do kina, ty do teatru.", "Czytam książkę.", "On lubi jabłka, ona - gruszki.", "Idę spać."]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-4,batch-2025-01}', '{"explanation": "Elipsa to pominięcie wyrazu domyślnego. W A brak ''idę'', w C brak ''lubi''."}', '2025-10-24 22:16:52.774', '2025-10-24 22:16:52.774', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8kn008xqhd99nwl77vp', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 2, 2, 'Które wyrazy są rzeczownikami abstrakcyjnymi?', '{"options": ["miłość", "stół", "piękno", "dom"]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-2,batch-2025-01}', '{"explanation": "Rzeczowniki abstrakcyjne to nazwy pojęć, uczuć, cech: miłość, piękno."}', '2025-10-24 22:16:52.776', '2025-10-24 22:16:52.776', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8kq008yqhd90xj1qqcr', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'W których wyrazach występuje przyrostek?', '{"options": ["pisarz", "napisać", "pisemny", "pismo"]}', '[0, 2, 3]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', '{"explanation": "Przyrostki: -arz (pisarz), -emny (pisemny), -mo (pismo). ''Napisać'' ma przedrostek."}', '2025-10-24 22:16:52.778', '2025-10-24 22:16:52.778', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8ks008zqhd922i9gkzp', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 4, 2, 'Które zdania są bezosobowe?', '{"options": ["Było zimno.", "Pada deszcz.", "Mówiono o tym.", "Jan śpi."]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-4,batch-2025-01}', '{"explanation": "Zdania bezosobowe nie mają podmiotu: ''było zimno'', ''mówiono''. ''Pada deszcz'' ma podmiot (deszcz)."}', '2025-10-24 22:16:52.78', '2025-10-24 22:16:52.78', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8ku0090qhd9g4h07bop', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 2, 2, 'Które wyrazy są homonimami?', '{"options": ["zamek (budowla) / zamek (do drzwi)", "duży / mały", "bal (zabawa) / bal (drewno)", "iść / chodzić"]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-2,batch-2025-01}', '{"explanation": "Homonimy to wyrazy o tym samym brzmieniu, ale różnych znaczeniach."}', '2025-10-24 22:16:52.782', '2025-10-24 22:16:52.782', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8kw0091qhd9qa9vl3l7', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'W których zdaniach występuje inwersja (szyk przestawny)?', '{"options": ["Piękna była ta noc.", "Anna czyta książkę.", "Przyszedł wczoraj Jan.", "Dzieci bawią się."]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', '{"explanation": "Inwersja to nietypowy szyk wyrazów. Normalnie: ''Ta noc była piękna'', ''Jan przyszedł wczoraj''."}', '2025-10-24 22:16:52.784', '2025-10-24 22:16:52.784', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8ky0092qhd9wy3dn3me', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 4, 2, 'Które środki stylistyczne należą do figur słów?', '{"options": ["metafora", "pytanie retoryczne", "epitet", "apostrofa"]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-4,batch-2025-01}', '{"explanation": "Figury słów: metafora, epitet. Pytanie retoryczne i apostrofa to figury myśli."}', '2025-10-24 22:16:52.787', '2025-10-24 22:16:52.787', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8l10093qhd9fz1etiex', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 2, 2, 'Które wyrazy są zaimkami?', '{"options": ["on", "bardzo", "nikt", "szybko"]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-2,batch-2025-01}', '{"explanation": "Zaimki: on (osobowy), nikt (nieokreślony). ''Bardzo'' i ''szybko'' to przysłówki."}', '2025-10-24 22:16:52.789', '2025-10-24 22:16:52.789', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8l30094qhd9hd6ryvir', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'W których wyrazach ''u'' piszemy przez ''ó''?', '{"options": ["krol", "gura", "woda", "roza"]}', '[0, 1, 3]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', '{"explanation": "Przez ''ó'' piszemy: król, góra, róża. ''Woda'' przez ''o''."}', '2025-10-24 22:16:52.791', '2025-10-24 22:16:52.791', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8l50095qhd9itbgoi6h', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 4, 2, 'Które zdania zawierają równoważnik zdania?', '{"options": ["Cisza nocna.", "Jan śpi.", "Proszę wejść.", "Pada deszcz."]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-4,batch-2025-01}', '{"explanation": "Równoważniki zdania nie mają podmiotu i orzeczenia: ''Cisza nocna'', ''Proszę wejść''."}', '2025-10-24 22:16:52.794', '2025-10-24 22:16:52.794', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8l80096qhd9jkbby4hl', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 2, 2, 'Które wyrazy są przymiotnikami?', '{"options": ["piękny", "pięknie", "czerwony", "czerwień"]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-2,batch-2025-01}', '{"explanation": "Przymiotniki: piękny, czerwony. „Pięknie” to przysłówek, „czerwień” to rzeczownik."}', '2025-10-24 22:16:52.796', '2025-10-24 22:16:52.796', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8la0097qhd9d9ax8p3m', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'W których zdaniach występuje podmiot szeregowy?', '{"options": ["Jan i Maria przyszli.", "On śpiewa.", "Pies, kot i chomik bawią się.", "Dzieci grają."]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', '{"explanation": "Podmiot szeregowy składa się z kilku członów: ''Jan i Maria'', ''Pies, kot i chomik''."}', '2025-10-24 22:16:52.798', '2025-10-24 22:16:52.798', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8lc0098qhd9cxdrguil', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 4, 2, 'Które figury należą do tropów?', '{"options": ["metonimia", "anafora", "synekdocha", "paralelizm"]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-4,batch-2025-01}', '{"explanation": "Tropy (przenośnie): metonimia, synekdocha. Anafora i paralelizm to figury składniowe."}', '2025-10-24 22:16:52.8', '2025-10-24 22:16:52.8', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8le0099qhd9t8b6vrla', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 2, 2, 'Które wyrazy są wykrzyknikami?', '{"options": ["ach", "bardzo", "ojej", "szybko"]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-2,batch-2025-01}', '{"explanation": "Wykrzykniki wyrażają emocje: ach, ojej. „Bardzo” i „szybko” to przysłówki."}', '2025-10-24 22:16:52.803', '2025-10-24 22:16:52.803', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8lh009aqhd9gdyu2m7m', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'W których zdaniach występuje przerzutnia?', '{"options": ["I nagle / Cisza.", "Jan czyta książkę.", "Widziałem go tam, gdzie / Nikt nie chodzi.", "Pada deszcz."]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', '{"explanation": "Przerzutnia to przeniesienie części zdania do następnego wersu."}', '2025-10-24 22:16:52.805', '2025-10-24 22:16:52.805', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8lj009bqhd9kp4263a8', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 4, 2, 'Które zdania są złożone współrzędnie?', '{"options": ["Przyszedł i usiadł.", "Myślę, że masz rację.", "Pada deszcz, lecz jest ciepło.", "Kiedy świeci słońce, jest wesoło."]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-4,batch-2025-01}', '{"explanation": "Zdania współrzędnie łączą równorzędne części: ''i usiadł'', ''lecz jest ciepło''."}', '2025-10-24 22:16:52.807', '2025-10-24 22:16:52.807', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8ll009cqhd9glklq6k2', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'Które wyrazy zawierają dyftongi?', '{"options": ["auto", "kot", "Europa", "dom"]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', '{"explanation": "Dyftongi to połączenia samogłosek: au-to, Eu-ropa."}', '2025-10-24 22:16:52.81', '2025-10-24 22:16:52.81', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8ln009dqhd9lhmneopn', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'W których zdaniach występuje metafora?', '{"options": ["Czas płynie jak rzeka.", "Jego serce jest z kamienia.", "Słońce zachodzi.", "Morze wspomnień zalewa mnie."]}', '[1, 3]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.812', '2025-10-24 22:16:52.812', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8lq009eqhd99vyzar34', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 2, 2, 'Które wyrazy są synonimami?', '{"options": ["dom", "mieszkanie", "budynek", "chata"]}', '[0, 1, 3]', NULL, '{language_use,closed_multiple,difficulty-2,batch-2025-01}', NULL, '2025-10-24 22:16:52.814', '2025-10-24 22:16:52.814', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8ls009fqhd9wh3g7sx1', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'W których wyrazach występuje przedrostek?', '{"options": ["napisać", "pisać", "podpisać", "spisać"]}', '[0, 2, 3]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.816', '2025-10-24 22:16:52.816', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8lu009gqhd9rncwsmfc', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 4, 2, 'Które zdania zawierają zdanie podrzędne?', '{"options": ["Myślę, więc jestem.", "Gdy świeci słońce, jest ciepło.", "Przyszedł i usiadł.", "Wiem, że masz rację."]}', '[1, 3]', NULL, '{language_use,closed_multiple,difficulty-4,batch-2025-01}', NULL, '2025-10-24 22:16:52.819', '2025-10-24 22:16:52.819', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8lw009hqhd93hp3q5rh', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 1, 2, 'Wyjaśnij różnicę między dwoma wyrazami.', '{"words": ["''rz'' i ''ż''"], "instruction": "Podaj przykłady wyrazów z „rz” i wyjaśnij, kiedy piszemy „rz” a kiedy ''ż''."}', NULL, NULL, '{language_use,short_answer,difficulty-1,batch-2025-01}', NULL, '2025-10-24 22:16:52.821', '2025-10-24 22:16:52.821', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ew0097qh49stfx28kf', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Jak Nietzsche w ''Narodzinach tragedii'' interpretował postać Edypa?', '{"options": ["Jako przykład słabości i dekadencji", "Jako wzór apollińskiego ładu i harmonii", "Jako wcielenie dionizyjskiej mądrości zdobytej przez cierpienie i transgresję", "Jako postać całkowicie pozbawioną znaczenia filozoficznego"]}', '2', NULL, '{Nietzsche,dionizyjskość,transgresja}', '{"explanation": "Nietzsche widział w Edypie wcielenie dionizyjskiej mądrości - wiedzy zdobytej przez cierpienie i naruszenie naturalnego porządku."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8m1009jqhd9w0x9mzhl', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Opisz głównego bohatera.', '{"instruction": "Kim jest Tadeusz Soplica? Opisz go w 2-3 zdaniach."}', NULL, NULL, '{historical_literary,short_answer,difficulty-1,romanticism,batch-2025-01}', NULL, '2025-10-24 22:16:52.826', '2025-10-24 22:16:52.826', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8m4009kqhd9ebg43vfw', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 3, 4, 'Przekształć zdanie zachowując sens.', '{"hints": ["zamień ''kiedy'' na inny spójnik", "zachowaj relację przyczyna-skutek"], "transformation": "Zmień zdanie podrzędne na współrzędne (użyj spójnika ''więc'' lub ''dlatego'').", "originalSentence": "Kiedy pada deszcz, zostaję w domu."}', NULL, NULL, '{language_use,short_answer,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.828', '2025-10-24 22:16:52.828', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8m6009lqhd9036ioend', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 2, 3, 'Wyjaśnij znaczenie frazeologizmu.', '{"phrase": "wziąć nogi za pas", "instruction": "Co oznacza to wyrażenie? Podaj przykład użycia w zdaniu."}', NULL, NULL, '{language_use,short_answer,difficulty-2,batch-2025-01}', NULL, '2025-10-24 22:16:52.83', '2025-10-24 22:16:52.83', NULL);
