INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8mb009nqhd9u00eu0fg', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 1, 2, 'Podaj przykłady części mowy.', '{"instruction": "Wymień 3 rzeczowniki, 3 czasowniki i 3 przymiotniki związane z tematem ''szkoła''."}', NULL, NULL, '{language_use,short_answer,difficulty-1,batch-2025-01}', NULL, '2025-10-24 22:16:52.835', '2025-10-24 22:16:52.835', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8md009oqhd9sq4yuqsy', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 3, 4, 'Analiza środków stylistycznych.', '{"text": "Wiatr szeptał tajemnice, drzewa kłaniały się, a niebo płakało deszczem.", "instruction": "Wskaż środki stylistyczne w tym zdaniu i wyjaśnij ich funkcję."}', NULL, NULL, '{language_use,short_answer,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.838', '2025-10-24 22:16:52.838', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8mf009pqhd9kx8l9eoi', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Porównaj dwa utwory.', '{"works": ["''Ballady i romanse'' Mickiewicza", "''Balladyna'' Słowackiego"], "instruction": "Wskaż dwie różnice między tymi utworami (forma, temat, bohaterowie)."}', NULL, NULL, '{historical_literary,short_answer,difficulty-3,romanticism,batch-2025-01}', NULL, '2025-10-24 22:16:52.84', '2025-10-24 22:16:52.84', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8mi009qqhd9th809wvq', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 2, 3, 'Określ funkcję interpunkcji.', '{"sentence": "Anna, która jest moją siostrą, studiuje medycynę.", "instruction": "Wyjaśnij, do czego służą przecinki w tym zdaniu."}', NULL, NULL, '{language_use,short_answer,difficulty-2,batch-2025-01}', NULL, '2025-10-24 22:16:52.842', '2025-10-24 22:16:52.842', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8mk009rqhd9wuip6p9t', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 1, 2, 'Ułóż jedno poprawne zdanie, używając wszystkich tych wyrazów.', '{"words": ["książka", "czytać", "ciekawy"]}', NULL, NULL, '{language_use,short_answer,difficulty-1,batch-2025-01}', NULL, '2025-10-24 22:16:52.844', '2025-10-24 22:16:52.844', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8mm009sqhd98qjgvh0n', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ENLIGHTENMENT', 2, 3, 'Wyjaśnij cel utworu.', '{"instruction": "Jaki cel miały bajki Krasickiego? Co chciał osiągnąć autor?"}', NULL, NULL, '{historical_literary,short_answer,difficulty-2,enlightenment,batch-2025-01}', NULL, '2025-10-24 22:16:52.846', '2025-10-24 22:16:52.846', 'Bajki');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8mo009tqhd9ozrnmq8s', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 3, 4, 'Przeprowadź analizę zdania - zadanie wieloetapowe.', '{"text": "Mała ojczyzna to azyl, to miejsce, z którego patrzy się na świat.", "steps": [{"id": 1, "instruction": "Określ typ zdania", "expectedAnswer": "złożone współrzędnie"}, {"id": 2, "instruction": "Wskaż środki stylistyczne", "expectedAnswer": "metafora, powtórzenie"}, {"id": 3, "instruction": "Określ funkcję ''to''", "expectedAnswer": "orzecznik"}, {"id": 4, "instruction": "Wyjaśnij znaczenie metafory", "expectedAnswer": "bezpieczne miejsce"}]}', NULL, NULL, '{language_use,short_answer,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.848', '2025-10-24 22:16:52.848', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8mq009uqhd979xjcawm', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 2, 3, 'Wyjaśnij różnicę znaczeniową.', '{"sentences": ["Pada deszcz.", "Pada śnieg."], "instruction": "Czy oba zdania mają tę samą budowę? Co się zmienia? Odpowiedz w 2-3 zdaniach."}', NULL, NULL, '{language_use,short_answer,difficulty-2,batch-2025-01}', NULL, '2025-10-24 22:16:52.851', '2025-10-24 22:16:52.851', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8mt009vqhd94r8zusnm', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', NULL, 1, 2, 'Opisz epokę w 3 słowach kluczowych.', '{"epoch": "Romantyzm", "instruction": "Podaj 3 słowa, które najlepiej charakteryzują romantyzm i krótko wyjaśnij każde."}', NULL, NULL, '{historical_literary,short_answer,difficulty-1,batch-2025-01}', NULL, '2025-10-24 22:16:52.853', '2025-10-24 22:16:52.853', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8mv009wqhd9dkcg51u2', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 5, 4, 'Wykonaj analizę językową fragmentu - zadanie wieloetapowe.', '{"text": "Nie dość na tem: wszak Rzym, co świat posiadał, \nPrzeminął; Trzej Monarchowie, których wielka władza \nJak morze sie rozlewała, przeminęli...", "steps": [{"id": 1, "instruction": "Określ rodzaj zdania pod względem składniowym", "expectedAnswer": "złożone współrzędnie z elementami podrzędności"}, {"id": 2, "instruction": "Wskaż dominujące środki stylistyczne i ich funkcję", "expectedAnswer": "metafora (władza jak morze), symbol (Rzym, Monarchowie), anafora (przeminął)"}, {"id": 3, "instruction": "Określ funkcję interpunkcji (dwukropek, średnik)", "expectedAnswer": "dwukropek - zapowiedź argumentacji/wyjaśnienia, średnik - oddziela równorzędne człony wyliczenia"}, {"id": 4, "instruction": "Zinterpretuj przesłanie ideowe fragmentu w kontekście epoki barokowej", "expectedAnswer": "motyw vanitas - przemijanie potęg i marność ziemskiej chwały"}]}', NULL, NULL, '{language_use,short_answer,difficulty-5,batch-2025-01}', '{"expectedConcepts": ["składnia złożona", "metafora", "vanitas", "interpunkcja"]}', '2025-10-24 22:16:52.855', '2025-10-24 22:16:52.855', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8mx009xqhd9mguslzzl', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 4, 'Analiza porównawcza - wyjaśnij różnicę między pojęciami.', '{"concepts": ["ironia romantyczna", "ironia postmodernistyczna"], "instruction": "Wyjaśnij, czym różnią się te dwa typy ironii. Podaj przykład literacki dla każdej z nich.", "requirements": ["definicja obu pojęć", "wskazanie różnic", "przykłady z literatury", "150-200 słów"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-4,contemporary,batch-2025-01}', '{"expectedConcepts": ["ironia romantyczna - dystans autora", "ironia postmodernistyczna - podważanie prawdy", "przykłady: Słowacki vs Tokarczuk"]}', '2025-10-24 22:16:52.858', '2025-10-24 22:16:52.858', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8n0009yqhd98odnjks9', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 5, 4, 'Przekształć zdanie zachowując sens, ale zmieniając strukturę.', '{"hints": ["użyj połączenia współrzędnego", "zamień zdania podrzędne na główne", "zachowaj relacje logiczne"], "transformation": "Przekształć to zdanie na trzy krótsze zdania pojedyncze, zachowując wszystkie informacje.", "originalSentence": "Mimo że padało, wyszedłem, ponieważ musiałem kupić chleb, którego brakowało w domu."}', NULL, NULL, '{language_use,short_answer,difficulty-5,batch-2025-01}', '{"expectedAnswer": "Padało. Wyszedłem jednak. Musiałem kupić chleb, bo w domu go brakowało."}', '2025-10-24 22:16:52.861', '2025-10-24 22:16:52.861', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8n3009zqhd9r4gx9zo1', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 5, 'Interpretacja symbolu w kontekście całości utworu.', '{"symbol": "złoty róg", "context": "Poeta rozdaje go gościom weselnym, ale nikt nie potrafi zagrać.", "instruction": "Zinterpretuj symbolikę złotego rogu w kontekście: \n1) sytuacji Polski pod zaborami\n2) postaci Poety w dramacie\n3) tytułowego wesela jako metafory narodu", "requirements": ["interpretacja wielowarstwowa", "odniesienie do kontekstu historycznego", "200-250 słów"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-5,young_poland,batch-2025-01}', '{"expectedConcepts": ["róg - symbol wezwania do czynu", "niemoc narodu", "odpowiedzialność inteligencji", "paraliż narodowy"]}', '2025-10-24 22:16:52.863', '2025-10-24 22:16:52.863', 'Wesele');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8n600a0qhd9y9u2sv8r', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 1, 1, 'Podaj przeciwieństwo wyrazu „duży”.', '{"expectedAnswer": "mały", "acceptableAnswers": ["mały", "malutki", "niewielki"]}', NULL, NULL, '{language_use,short_answer,difficulty-1,batch-2025-01}', NULL, '2025-10-24 22:16:52.866', '2025-10-24 22:16:52.866', NULL);
