INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8ov00arqhd97jahctna', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', NULL, 3, 3, 'Oceń prawdziwość stwierdzeń i uzasadnij.', '{"statements": ["Pozytywizm był reakcją na klęskę powstania styczniowego.", "Jan Kochanowski napisał pierwszą polską tragedię.", "Lalka Prusa to powieść naturalistyczna."], "instruction": "Dla każdego zdania napisz P (prawda) lub F (fałsz) i krótko uzasadnij"}', NULL, NULL, '{historical_literary,short_answer,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:52.928', '2025-10-24 22:16:52.928', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8oy00asqhd9gu8e98v3', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 4, 4, 'Przeprowadź analizę językową fragmentu - zadanie wieloetapowe.', '{"text": "Mała ojczyzna to azyl, to miejsce, z którego patrzy się na świat.", "steps": [{"task": "Określ typ zdania", "expected": "złożone współrzędnie"}, {"task": "Wskaż środki stylistyczne", "expected": "metafora, powtórzenie"}, {"task": "Określ funkcję ''to''", "expected": "orzecznik"}, {"task": "Wyjaśnij znaczenie metafory", "expected": "bezpieczne miejsce"}]}', NULL, NULL, '{language_use,short_answer,difficulty-4,batch-2025-01}', NULL, '2025-10-24 22:16:52.93', '2025-10-24 22:16:52.93', NULL);
