INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8px00b8qhd9s55e91d5', 'SYNTHESIS_NOTE', 'LANGUAGE_USE', NULL, 4, 5, 'Porównaj style dwóch fragmentów.', '{"text1": {"author": "Prus", "fragment": "Wokulski siedział nieruchomo, wpatrzony w jedną bryłę węgla."}, "text2": {"author": "Żeromski", "fragment": "Dusza jego rwała się ku wyżynom, ku ideałom!"}, "requirements": ["różnice stylistyczne", "realizm vs modernizm", "środki wyrazu", "80-100 słów"]}', NULL, NULL, '{language_use,synthesis_note,difficulty-4,batch-2025-01}', NULL, '2025-10-24 22:16:52.966', '2025-10-24 22:16:52.966', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8pz00b9qhd97moy47cj', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', NULL, 4, 5, 'Na podstawie fragmentów napisz notatkę o motywie.', '{"topic": "Motyw lotu w literaturze", "sources": [{"work": "Lalka", "fragment": "Wokulski marzył o lataniu..."}, {"work": "Ikarus", "fragment": "Wzniósł się ponad chmury..."}, {"work": "Lot", "fragment": "Pragnienie wzniesienia się..."}], "requirements": ["symbolika", "różne ujęcia", "90-110 słów"]}', NULL, NULL, '{historical_literary,synthesis_note,difficulty-4,batch-2025-01}', NULL, '2025-10-24 22:16:52.968', '2025-10-24 22:16:52.968', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ew0098qh49g9vbq0bd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Jak René Girard interpretował mit edypalny w kontekście teorii mimetycznej?', '{"options": ["Jako opowieść o szczęśliwym dzieciństwie", "Jako instrukcję moralną dla młodzieży", "Jako tekst o znaczeniu wyłącznie estetycznym", "Jako mechanizm kozła ofiarnego rozładowujący przemoc społeczną"]}', '3', NULL, '{Girard,"teoria mimetyczna","kozioł ofiarny"}', '{"explanation": "Girard widział w micie przykład mechanizmu kozła ofiarnego: wspólnota w kryzysie projektuje winę na jednostkę, której wydalenie przywraca porządek."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
