INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8vp00dyqhd94piu0bvk', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 3, 'Uzupełnij charakterystykę programu pozytywizmu.', '{"gaps": [{"id": 1, "options": ["naukę", "walkę zbrojną", "poezję", "sztukę"]}, {"id": 2, "options": ["rewolucji", "pracy organicznej", "romantyzmu", "mistyki"]}, {"id": 3, "options": ["sztukę", "wojnę", "edukację", "religię"]}], "textWithGaps": "Pozytywiści odrzucili [1] na rzecz [2], promowali [3] jako drogę do rozwoju."}', '[1, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', NULL, '2025-10-24 22:16:53.174', '2025-10-24 22:16:53.174', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8vr00dzqhd9c0y58m5t', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 1, 1, 'Które słowo jest BŁĘDNIE napisane?', '{"options": ["przyjaciel", "najlepszy", "czwartek", "wszysko"]}', '3', NULL, '{language_use,closed_single,difficulty-1,batch-2025-01}', '{"explanation": "Poprawnie: wszystko"}', '2025-10-24 22:16:53.176', '2025-10-24 22:16:53.176', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8vt00e0qhd92ceg0bjg', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 4, 4, 'W których fragmentach występuje PARADOKS?', '{"options": ["Im więcej wiem, tym bardziej wiem, że nic nie wiem.", "Słońce świeci jasno.", "Milczenie krzyczy głośniej niż słowa.", "Pada deszcz i świeci słońce.", "Żywy trup leżał na ziemi."]}', '[0, 2, 4]', NULL, '{language_use,closed_multiple,difficulty-4,batch-2025-01}', NULL, '2025-10-24 22:16:53.178', '2025-10-24 22:16:53.178', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8vw00e1qhd91pwr9olb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 3, 2, 'Który motyw NIE jest typowy dla baroku?', '{"options": ["vanitas - przemijanie", "carpe diem - chwytaj dzień", "praca organiczna", "theatrum mundi - świat jako teatr"], "contextLinks": [{"type": "text", "title": "Barok - epoka XVII wieku", "content": "Barok to epoka literacka i artystyczna XVII wieku, charakteryzująca się kontrastami, bogactwem form i pesymistyczną wizją świata. Główne motywy barokowe to vanitas (przemijanie), carpe diem (korzystaj z chwili), theatrum mundi (świat jako teatr) oraz memento mori (pamiętaj o śmierci). Barok przeciwstawia ziemskie i niebiańskie, piękno i brzydotę, życie i śmierć.", "trigger": "baroku", "moreInfoLink": ""}]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,baroque,batch-2025-01}', '{"explanation": "Praca organiczna to hasło pozytywizmu (XIX w.), nie baroku (XVII w.). Pozytywistyczne hasło ''pracy organicznej'' oznaczało stopniową, systematyczną pracę u podstaw społeczeństwa - rozwój gospodarczy, edukację i samoorganizację. Pozostałe trzy motywy (vanitas, carpe diem, theatrum mundi) są kluczowymi ideami barokowymi, wyrażającymi przemijanie, zmysłowość i teatralność życia."}', '2025-10-24 22:16:53.18', '2025-10-24 22:16:53.18', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8vy00e2qhd9co6cwdsi', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 3, 4, 'Przeprowadź wieloetapową analizę zdania.', '{"text": "Cisza nocna, głęboka, nieprzebyta otulała śpiące miasto.", "steps": [{"id": 1, "instruction": "Wskaż wszystkie epitety", "expectedAnswer": "nocna, głęboka, nieprzebyta, śpiące"}, {"id": 2, "instruction": "Określ funkcję składniową ''miasto''", "expectedAnswer": "dopełnienie"}, {"id": 3, "instruction": "Jaki nastrój budują epitety?", "expectedAnswer": "tajemniczy, spokojny, niesamowity"}]}', NULL, NULL, '{language_use,short_answer,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:53.182', '2025-10-24 22:16:53.182', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8w000e3qhd9qxwkgko0', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 5, 'Dopasuj symbol młodopolski do interpretacji.', '{"leftColumn": [{"id": "A", "text": "Chochoł w ''Weselu''"}, {"id": "B", "text": "Złoty róg"}, {"id": "C", "text": "Wernyhora"}], "rightColumn": [{"id": 1, "text": "wezwanie do czynu narodowego"}, {"id": 2, "text": "mit mesjanistyczny, przepowiednia"}, {"id": 3, "text": "paraliż, strach, niemoc"}], "matchingType": "symbol_interpretation"}', '[[0, 2], [1, 0], [2, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-5,young_poland,batch-2025-01}', NULL, '2025-10-24 22:16:53.185', '2025-10-24 22:16:53.185', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8w300e4qhd974az5f9g', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 2, 1, 'Co to jest kontaminacja?', '{"options": ["zanieczyszczenie środowiska", "połączenie dwóch wyrażeń w jedno błędne", "zapożyczenie obce", "skrót wyrazowy"]}', '1', NULL, '{language_use,closed_single,difficulty-2,batch-2025-01}', '{"explanation": "Np. ''pójść z kolegą do kina'' (pójść do kina + iść z kolegą)"}', '2025-10-24 22:16:53.187', '2025-10-24 22:16:53.187', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8w500e5qhd9fu8jo703', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 5, 5, 'Uzupełnij zaawansowaną analizę stylistyczną.', '{"gaps": [{"id": 1, "options": ["metafora", "porównanie", "symbol", "alegoria"]}, {"id": 2, "options": ["hiperbolę", "kontrast", "paralelizm składniowy", "elipsę"]}, {"id": 3, "options": ["pozytywny", "negatywny", "neutralny", "ambiwalentny"]}], "textWithGaps": "W zdaniu ''Ręce miał jak szpadle, serce jak kamień'' występuje [1] podwójna, gdzie obie części używają [2], tworząc [3] obraz postaci."}', '[1, 2, 1]', NULL, '{language_use,closed_multiple,difficulty-5,batch-2025-01}', NULL, '2025-10-24 22:16:53.19', '2025-10-24 22:16:53.19', NULL);
