INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8z700fkqhd912xciqgt', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 5, 'Uzupełnij charakterystykę technik narracyjnych.', '{"gaps": [{"id": 1, "options": ["realizm", "intertekstualność", "naturalizm", "symbolizm"]}, {"id": 2, "options": ["mimezę", "metafikcję", "opis", "dialog"]}, {"id": 3, "options": ["linearna", "fragmentaryczna", "obiektywna", "wszechwiedzą ca"]}], "textWithGaps": "W postmodernizmie dominuje [1], literatura często stosuje [2], a narracja bywa [3]."}', '[1, 1, 1]', NULL, '{historical_literary,closed_multiple,difficulty-4,contemporary,batch-2025-01}', NULL, '2025-10-24 22:16:53.3', '2025-10-24 22:16:53.3', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8z900flqhd9375o5fkn', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 3, 4, 'Przekształć zdanie złożone na proste.', '{"hints": ["użyj spójników współrzędnych", "zachowaj relację przyczyny i skutku"], "transformation": "Przekształć na 2-3 zdania pojedyncze, zachowując wszystkie informacje i relacje logiczne.", "originalSentence": "Kiedy pada, zostaję w domu, ponieważ nie lubię mokrej pogody."}', NULL, NULL, '{language_use,short_answer,difficulty-3,batch-2025-01}', NULL, '2025-10-24 22:16:53.302', '2025-10-24 22:16:53.302', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev8zc00fmqhd93saw0ee7', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 2, 1, 'Jaki to stopień przymiotnika?', '{"word": "najmądrzejszy", "options": ["równy", "wyższy", "najwyższy", "nie jest przymiotnikiem"]}', '2', NULL, '{language_use,closed_single,difficulty-2,batch-2025-01}', NULL, '2025-10-24 22:16:53.304', '2025-10-24 22:16:53.304', NULL);
