INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev90a00g2qhd9a9yd7612', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 2, 1, 'W którym zdaniu poprawnie zastosowano przecinki?', '{"options": ["Jan, który przyszedł wczoraj jest moim bratem.", "Jan który przyszedł wczoraj, jest moim bratem.", "Jan, który przyszedł wczoraj, jest moim bratem.", "Jan który, przyszedł wczoraj jest moim bratem."]}', '2', NULL, '{language_use,closed_single,difficulty-2,batch-2025-01,interpunkcja,przecinek}', NULL, '2025-10-24 22:16:53.339', '2025-10-24 22:16:53.339', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev90c00g3qhd9fq6po1gv', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 4, 3, 'Przeredaguj poniższe zdanie, eliminując pleonazm i tautologię: ''W dniu dzisiejszym cofnęliśmy się do tyłu, aby ponownie jeszcze raz przeanalizować całość wszystkich dokumentów.''', '{"requirements": ["Zachowanie sensu", "Eliminacja nadmiaru", "Poprawność stylistyczna"]}', NULL, NULL, '{language_use,short_answer,difficulty-4,batch-2025-01,stylistyka,pleonazm,tautologia}', NULL, '2025-10-24 22:16:53.341', '2025-10-24 22:16:53.341', NULL);
