INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev90j00g6qhd9w4zpu5ff', 'SYNTHESIS_NOTE', 'LANGUAGE_USE', NULL, 4, 4, 'Napisz notatkę na temat: ''Frazeologizmy biblijne w języku polskim - źródła i znaczenia'' (80-100 słów).', '{"requirements": ["Minimum 3 przykłady frazeologizmów", "Wyjaśnienie pochodzenia", "Współczesne znaczenie", "Zachowanie limitu słów"]}', NULL, '{"criteria": [{"name": "Przykłady frazeologizmów", "points": 1}, {"name": "Wyjaśnienie pochodzenia", "points": 1}, {"name": "Znaczenie współczesne", "points": 1}, {"name": "Forma i spójność", "points": 1}]}', '{language_use,synthesis_note,difficulty-4,batch-2025-01,frazeologia,Biblia,notatka}', NULL, '2025-10-24 22:16:53.347', '2025-10-24 22:16:53.347', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev90l00g7qhd9o2u3q347', 'SHORT_ANSWER', 'WRITING', NULL, 3, 2, 'Jakie znaczenie dla rozumienia tekstów ma użycie słownictwa wartościującego w tytułach ''Niebezpieczna sztuczna inteligencja'' i ''Sztuczna przeciętność''?', '{"context": "Przeanalizuj tytuły dwóch artykułów o sztucznej inteligencji.", "requirements": ["Wyjaśnij funkcję słownictwa wartościującego", "Odnieś się do obu tytułów"]}', NULL, '{"criteria": [{"name": "Identyfikacja słownictwa wartościującego", "points": 1}, {"name": "Wyjaśnienie funkcji", "points": 1}]}', '{writing,short_answer,difficulty-3,batch-2025-01,"słownictwo wartościujące",tytuł,funkcja}', NULL, '2025-10-24 22:16:53.35', '2025-10-24 22:16:53.35', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev90o00g8qhd9d19sguhr', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 2, 1, 'Który środek stylistyczny dominuje w zdaniu: ''Cisza krzyczała mu do ucha''?', '{"options": ["oksymoron", "porównanie", "epitet", "metonimia"]}', '0', NULL, '{language_use,closed_single,difficulty-2,batch-2025-01,"środki stylistyczne",oksymoron}', NULL, '2025-10-24 22:16:53.352', '2025-10-24 22:16:53.352', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev90r00g9qhd97dgdknsn', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'Które ze środków retorycznych występują we fragmencie: ''Piszmy więc o sztucznej inteligencji, debatujmy i twórzmy jej wizje – póki jeszcze możemy...''?', '{"options": ["wyliczenie", "gradacja", "wielokropek (aposiopeza)", "pytanie retoryczne", "apostrofa"]}', '[0, 2]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01,retoryka,"środki stylistyczne"}', NULL, '2025-10-24 22:16:53.355', '2025-10-24 22:16:53.355', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev90t00gaqhd9hbdu3jgy', 'SYNTHESIS_NOTE', 'LANGUAGE_USE', NULL, 4, 4, 'Na podstawie dwóch tekstów o sztucznej inteligencji napisz notatkę syntetyzującą na temat: ''Współczesny człowiek wobec sztucznej inteligencji''.', '{"texts": ["Tekst 1: Aleksandra Stanisławska - ''Niebezpieczna sztuczna inteligencja''", "Tekst 2: Łukasz Lamża - ''Sztuczna przeciętność''"], "requirements": ["60-90 wyrazów", "Przedstawienie stanowisk obu autorów", "Wskazanie podobieństw i różnic", "Zachowanie spójności"]}', NULL, '{"criteria": [{"name": "Przedstawienie stanowisk", "points": 1}, {"name": "Zestawienie stanowisk", "points": 1}, {"name": "Spójność", "points": 1}, {"name": "Poprawność językowa", "points": 1}]}', '{language_use,synthesis_note,difficulty-4,batch-2025-01,"notatka syntetyzująca",AI,synteza}', NULL, '2025-10-24 22:16:53.357', '2025-10-24 22:16:53.357', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev90v00gbqhd9j5r9kasi', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 2, 1, 'Jaka funkcja języka dominuje w zdaniu: ''Architektura, sztuka związana z precyzyjnym rysunkiem i ścisłym planowaniem''?', '{"options": ["informatywna", "ekspresywna", "impresywna", "poetycka"]}', '0', NULL, '{language_use,closed_single,difficulty-2,batch-2025-01,"funkcje języka"}', NULL, '2025-10-24 22:16:53.36', '2025-10-24 22:16:53.36', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev90x00gcqhd9pbw3s0r0', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 3, 2, 'Wyjaśnij, na czym polega ironia w sformułowaniu ''Słowo śnieżka nie w pełni oddaje mordercze warunki''.', '{"requirements": ["Identyfikacja kontrastu", "Wyjaśnienie efektu"]}', NULL, NULL, '{language_use,short_answer,difficulty-3,batch-2025-01,ironia,"środki stylistyczne"}', NULL, '2025-10-24 22:16:53.362', '2025-10-24 22:16:53.362', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev90z00gdqhd95piswars', 'CLOSED_SINGLE', 'LANGUAGE_USE', NULL, 1, 1, 'Wskaż zdanie, w którym poprawnie użyto imiesłowu przysłówkowego:', '{"options": ["Czytając książkę, zadzwonił telefon.", "Czytając książkę, usłyszałem dzwonek.", "Czytając książkę, mama zawołała na obiad.", "Czytając książkę, przyszedł listonosz."]}', '1', NULL, '{language_use,closed_single,difficulty-1,batch-2025-01,imiesłów,składnia}', NULL, '2025-10-24 22:16:53.364', '2025-10-24 22:16:53.364', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev91100geqhd90t8wncxg', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'W których wyrazach występuje upodobnienie wsteczne?', '{"options": ["prośba", "krzesło", "wszyscy", "jakże", "babka"]}', '[0, 3, 4]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01,fonetyka,upodobnienia}', NULL, '2025-10-24 22:16:53.366', '2025-10-24 22:16:53.366', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev91300gfqhd9ec0ies7p', 'SHORT_ANSWER', 'LANGUAGE_USE', NULL, 2, 2, 'Przekształć zdanie złożone współrzędnie w pojedyncze: ''Nadeszła wiosna i ptaki powróciły z ciepłych krajów.''', '{"hint": "Użyj konstrukcji z okolicznikiem czasu"}', NULL, NULL, '{language_use,short_answer,difficulty-2,batch-2025-01,składnia,przekształcenia}', NULL, '2025-10-24 22:16:53.368', '2025-10-24 22:16:53.368', NULL);
