INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ew0099qh49jnhek5uu', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Jak interpretuje tragizm Edypa filozofia egzystencjalna (np. Camus)?', '{"options": ["Jako model buntu przeciw absurdowi i godnego przyjęcia losu", "Jako dowód na sprawiedliwość boską", "Jako przestrogę przed niemoralnością", "Jako ilustrację teorii ewolucji"]}', '0', NULL, '{egzystencjalizm,Camus,absurd}', '{"explanation": "Dla egzystencjalistów jak Camus, Edyp jest wzorem godnego stawienia czoła absurdowi egzystencji - heroiczny bunt przez akceptację, nie przez ucieczkę."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
