INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev91v00gsqhd985n73bqv', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 4, 'Porównaj sposób przedstawienia doświadczenia wojny w poezji Krzysztofa Kamila Baczyńskiego i Tadeusza Różewicza. Napisz notatkę syntetyzującą (90-110 słów).', '{"requirements": ["Pokolenie Kolumbów vs ocaleni", "Różnice w poetyce", "Stosunek do heroizmu", "Cytaty z wierszy"]}', NULL, '{"criteria": [{"name": "Charakterystyka poetów", "points": 1}, {"name": "Analiza różnic", "points": 1}, {"name": "Przykłady z tekstów", "points": 1}, {"name": "Synteza i spójność", "points": 1}]}', '{historical_literary,synthesis_note,difficulty-4,contemporary,batch-2025-01,Baczyński,Różewicz,wojna,poezja}', NULL, '2025-10-24 22:16:53.396', '2025-10-24 22:16:53.396', NULL);
