INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev93x00hpqhd9ydaa6utr', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'W ''Tango'' Mrożka główny konflikt dotyczy:', '{"options": ["starcia tradycji z anarchią", "walki klasowej", "konfliktu pokoleń", "sporu religijnego"]}', '0', NULL, '{historical_literary,closed_single,difficulty-2,contemporary,batch-2025-01,Mrożek,Tango,konflikt}', NULL, '2025-10-24 22:16:53.469', '2025-10-24 22:16:53.469', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev93z00hqqhd9qgor2kcz', 'ESSAY', 'WRITING', NULL, 5, 35, 'Samotność jako doświadczenie egzystencjalne w literaturze XX wieku. Omów problem, analizując wybrane utwory.', '{"requirements": ["Minimum 400 słów", "Odwołanie do co najmniej dwóch lektur obowiązkowych", "Kontekst filozoficzny (egzystencjalizm)", "Własna teza interpretacyjna", "Struktura: wstęp, rozwinięcie, zakończenie"], "suggestedWorks": ["Dżuma - Albert Camus", "Tango - Sławomir Mrożek", "Inny świat - Gustaw Herling-Grudziński"]}', NULL, '{"criteria": [{"name": "Spełnienie formalnych warunków", "points": 1}, {"name": "Kompetencje literackie i kulturowe", "points": 16}, {"name": "Kompozycja wypowiedzi", "points": 7}, {"name": "Język wypowiedzi", "points": 11}]}', '{writing,essay,difficulty-5,batch-2025-01,rozprawka,samotność,egzystencjalizm,"XX wiek"}', NULL, '2025-10-24 22:16:53.472', '2025-10-24 22:16:53.472', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev94100hrqhd9ri8a815v', 'ESSAY', 'WRITING', NULL, 5, 35, 'Czy sztuka może ocalić człowieka? Rozważ problem w kontekście literatury obozowej i wojennej.', '{"requirements": ["Minimum 400 słów", "Przykłady ocalenia przez sztukę", "Przykłady, gdy sztuka nie wystarcza", "Odwołanie do świadectw historycznych", "Własne stanowisko"], "suggestedWorks": ["Medaliony - Zofia Nałkowska", "Pożegnanie z Marią - Tadeusz Borowski", "Pianista - Władysław Szpilman"]}', NULL, NULL, '{writing,essay,difficulty-5,batch-2025-01,sztuka,wojna,ocalenie,"literatura obozowa"}', NULL, '2025-10-24 22:16:53.474', '2025-10-24 22:16:53.474', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev94400hsqhd9mjtxn2uw', 'SHORT_ANSWER', 'WRITING', NULL, 4, 6, 'Napisz recenzję spektaklu teatralnego ''Wesele'' w reżyserii współczesnej, zwracając uwagę na aktualizację przesłania Wyspiańskiego (250-300 słów).', '{"requirements": ["Ocena inscenizacji", "Współczesne odczytanie", "Elementy scenografii i reżyserii", "Rekomendacja"]}', NULL, NULL, '{writing,short_answer,difficulty-4,batch-2025-01,recenzja,teatr,Wesele,aktualizacja}', NULL, '2025-10-24 22:16:53.476', '2025-10-24 22:16:53.476', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev94600htqhd9d44kaip0', 'SHORT_ANSWER', 'WRITING', NULL, 3, 4, 'Napisz przemówienie z okazji Narodowego Czytania ''Lalki'' Bolesława Prusa, zachęcające młodzież do lektury (200-250 słów).', '{"requirements": ["Apostrofa do młodzieży", "Argumenty za czytaniem klasyki", "Aktualność ''Lalki''", "Elementy retoryczne"]}', NULL, NULL, '{writing,short_answer,difficulty-3,batch-2025-01,przemówienie,retoryka,Lalka,"promocja czytelnictwa"}', NULL, '2025-10-24 22:16:53.478', '2025-10-24 22:16:53.478', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ew009bqh49c5ry1n3s', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Jak Bernard Knox interpretuje Edypa jako ''człowieka tyranosa''?', '{"options": ["Jako okrutnego despotę bez zalet", "Jako marionetkę bogów bez własnej woli", "Jako self-made mana, władcę z własnych zasług, model ateńskiej samowystarczalności", "Jako postać całkowicie negatywną"]}', '2', NULL, '{Knox,tyrannos,"demokracja ateńska"}', '{"explanation": "Knox interpretuje Edypa jako ''tyranosa'' w pozytywnym sensie - władcę, który zdobył tron dzięki własnym zasługom, model ateńskiego ideału."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev94800huqhd9l45ixoxf', 'ESSAY', 'WRITING', NULL, 5, 35, 'Kreacja bohatera romantycznego w literaturze polskiej i europejskiej. Omów zagadnienie, odwołując się do wybranych utworów.', '{"requirements": ["Minimum 400 słów", "Odwołanie do lektury obowiązkowej", "Odwołanie do innego utworu literackiego", "Dwa konteksty (np. historyczny, filozoficzny)", "Wypowiedź argumentacyjna"], "suggestedWorks": ["Dziady cz. III - Adam Mickiewicz", "Kordian - Juliusz Słowacki", "Cierpienia młodego Wertera - J.W. Goethe", "Konrad Wallenrod - Adam Mickiewicz"]}', NULL, '{"criteria": [{"name": "Spełnienie formalnych warunków", "points": 1}, {"name": "Kompetencje literackie i kulturowe", "points": 16}, {"name": "Kompozycja wypowiedzi", "points": 7}, {"name": "Język wypowiedzi", "points": 11}]}', '{writing,essay,difficulty-5,batch-2025-01,rozprawka,romantyzm,bohater}', NULL, '2025-10-24 22:16:53.48', '2025-10-24 22:16:53.48', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev94a00hvqhd9bfl9z0fq', 'ESSAY', 'WRITING', NULL, 5, 35, 'Motyw buntu w literaturze różnych epok. Porównaj realizację tego motywu w wybranych utworach.', '{"requirements": ["Minimum 400 słów", "Co najmniej dwa utwory z różnych epok", "Analiza porównawcza", "Kontekst historyczny i filozoficzny"]}', NULL, NULL, '{writing,essay,difficulty-5,batch-2025-01,"motyw buntu",porównanie,epoki}', NULL, '2025-10-24 22:16:53.483', '2025-10-24 22:16:53.483', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev94d00hwqhd9rfqgkwej', 'ESSAY', 'WRITING', NULL, 5, 35, 'Czy literatura może zmieniać rzeczywistość? Rozważ problem, odwołując się do wybranych przykładów.', '{"requirements": ["Minimum 400 słów", "Przykłady z różnych epok", "Własne stanowisko z uzasadnieniem"]}', NULL, NULL, '{writing,essay,difficulty-5,batch-2025-01,"funkcje literatury",społeczeństwo}', NULL, '2025-10-24 22:16:53.485', '2025-10-24 22:16:53.485', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev94f00hxqhd9ixqtr737', 'ESSAY', 'WRITING', NULL, 5, 35, 'Różne oblicza patriotyzmu w literaturze polskiej. Omów zagadnienie na wybranych przykładach.', '{"requirements": ["Minimum 400 słów", "Przykłady z co najmniej trzech epok", "Ewolucja pojęcia patriotyzmu"]}', NULL, NULL, '{writing,essay,difficulty-5,batch-2025-01,patriotyzm,"literatura polska"}', NULL, '2025-10-24 22:16:53.487', '2025-10-24 22:16:53.487', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev94h00hyqhd9p1gnxl7t', 'SHORT_ANSWER', 'WRITING', NULL, 4, 5, 'Napisz charakterystykę porównawczą Wokulskiego i Judyma jako bohaterów pozytywistycznych (200-250 słów).', '{"requirements": ["Podobieństwa postaw", "Różnice w realizacji ideałów", "Ocena postaci"]}', NULL, NULL, '{writing,short_answer,difficulty-4,batch-2025-01,charakterystyka,pozytywizm,porównanie}', NULL, '2025-10-24 22:16:53.49', '2025-10-24 22:16:53.49', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev94j00hzqhd9ua8pl1w8', 'SHORT_ANSWER', 'WRITING', NULL, 3, 4, 'Zinterpretuj tytuł „Wesela” Wyspiańskiego w kontekście problematyki utworu (150-200 słów).', '{"hint": "Rozważ znaczenie dosłowne i symboliczne"}', NULL, NULL, '{writing,short_answer,difficulty-3,batch-2025-01,interpretacja,tytuł,Wesele}', NULL, '2025-10-24 22:16:53.492', '2025-10-24 22:16:53.492', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev94l00i0qhd9diai6q06', 'SYNTHESIS_NOTE', 'LANGUAGE_USE', NULL, 4, 5, 'Na podstawie dwóch fragmentów felietonów - Joanny Szczepkowskiej i Krzysztofa Vargi - określ cechy stylu felietonowego i różnice w sposobie argumentacji (100-120 słów).', '{"texts": ["Fragment 1: Felieton o social mediach", "Fragment 2: Felieton o współczesnej kulturze"], "requirements": ["Cechy gatunku", "Porównanie stylów", "Przykłady środków językowych", "Wnioski"]}', NULL, NULL, '{language_use,synthesis_note,difficulty-4,batch-2025-01,felieton,styl,"analiza porównawcza"}', NULL, '2025-10-24 22:16:53.494', '2025-10-24 22:16:53.494', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev94n00i1qhd9u0syqr9c', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', NULL, 4, 4, 'Dokonaj analizy i interpretacji wiersza Juliana Tuwima ''Do krytyków''. Zwróć uwagę na ironię i środki stylistyczne.', '{"text": "[Tu będzie pełny tekst wiersza]", "requirements": ["Określenie tematu", "Analiza środków stylistycznych", "Interpretacja ironii", "Kontekst biograficzny"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-4,batch-2025-01,Tuwim,interpretacja,ironia,Skamander}', NULL, '2025-10-24 22:16:53.496', '2025-10-24 22:16:53.496', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev94p00i2qhd9kwx4t8a0', 'SHORT_ANSWER', 'WRITING', NULL, 3, 3, 'Napisz pastisz bajki Ignacego Krasickiego, poruszając współczesny problem społeczny (100-150 słów). Zachowaj charakterystyczne cechy stylu.', '{"requirements": ["Morał", "Alegoria", "Naśladowanie stylu Krasickiego", "Współczesna problematyka"]}', NULL, NULL, '{writing,short_answer,difficulty-3,batch-2025-01,pastisz,bajka,Krasicki,"pisanie kreatywne"}', NULL, '2025-10-24 22:16:53.498', '2025-10-24 22:16:53.498', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev94s00i3qhd93wgyp4rz', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 3, 2, 'W tekście współczesnego rapu odnajdujemy następujące środki stylistyczne:', '{"text": "Fragment tekstu rapowego z aluzjami literackimi", "options": ["aliteracja", "asonans", "anafora", "elipsa", "neologizm", "archaizm"]}', '[0, 1, 2, 4]', NULL, '{language_use,closed_multiple,difficulty-3,batch-2025-01,rap,"środki stylistyczne",współczesność}', NULL, '2025-10-24 22:16:53.5', '2025-10-24 22:16:53.5', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev94u00i4qhd98tq7psbe', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', NULL, 4, 3, 'Jak obraz ''Melancholia I'' Albrechta Dürera koresponduje z poezją barokową? Wskaż trzy wspólne motywy.', '{"image": "durer_melancholia.jpg", "requirements": ["Analiza obrazu", "Przykłady z poezji barokowej", "Wspólne motywy (vanitas, melancholia, kontemplacja)"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-4,batch-2025-01,malarstwo,barok,komparatystyka,Dürer}', NULL, '2025-10-24 22:16:53.502', '2025-10-24 22:16:53.502', NULL);
