INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev95h00ifqhd94fbwi6rq', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', NULL, 3, 2, 'Czym jest trzynastozgłoskowiec i w jakim utworze został użyty?', '{"hint": "Polski wers narodowy"}', NULL, NULL, '{historical_literary,short_answer,difficulty-3,batch-2025-01,wersyfikacja,"Pan Tadeusz"}', NULL, '2025-10-24 22:16:53.526', '2025-10-24 22:16:53.526', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev95j00igqhd91wiz84kq', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', NULL, 3, 2, 'Które cechy są charakterystyczne dla naturalizmu?', '{"options": ["determinizm", "idealizacja rzeczywistości", "biologizm", "spirytualizm", "przedstawianie brzydoty", "eskapizm"]}', '[0, 2, 4]', NULL, '{historical_literary,closed_multiple,difficulty-3,batch-2025-01,naturalizm,"prądy literackie"}', NULL, '2025-10-24 22:16:53.527', '2025-10-24 22:16:53.527', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev95l00ihqhd9x881qch1', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', NULL, 4, 3, 'Zinterpretuj symbolikę kamieni w ''Kamiennym świecie'' Tadeusza Borowskiego.', '{"requirements": ["Kontekst obozowy", "Dehumanizacja", "Symbolika"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-4,batch-2025-01,Borowski,symbolika,wojna}', NULL, '2025-10-24 22:16:53.53', '2025-10-24 22:16:53.53', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev95n00iiqhd9a4ck0ouw', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', NULL, 3, 2, 'Wyjaśnij kontekst biograficzny ''Trenów'' Jana Kochanowskiego.', '{"hint": "Śmierć córki Urszulki"}', NULL, NULL, '{historical_literary,short_answer,difficulty-3,batch-2025-01,Treny,"kontekst biograficzny"}', NULL, '2025-10-24 22:16:53.532', '2025-10-24 22:16:53.532', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev95p00ijqhd9muqx2cud', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', NULL, 3, 1, 'Która filozofia wpłynęła na twórczość Jana Kochanowskiego?', '{"options": ["stoicyzm", "epikureizm", "platonizm", "egzystencjalizm"]}', '0', NULL, '{historical_literary,closed_single,difficulty-3,batch-2025-01,filozofia,renesans,Kochanowski}', NULL, '2025-10-24 22:16:53.534', '2025-10-24 22:16:53.534', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev95r00ikqhd9vx2uh7ay', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', NULL, 4, 3, 'Wskaż i omów nawiązania do ''Hamleta'' w ''Fortepianie Szopena'' C.K. Norwida.', '{"requirements": ["Cytaty", "Interpretacja", "Funkcja nawiązań"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-4,batch-2025-01,intertekstualność,Norwid,Shakespeare}', NULL, '2025-10-24 22:16:53.536', '2025-10-24 22:16:53.536', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev95t00ilqhd931lhqvdl', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Która data oznacza koniec epoki starożytności?', '{"options": ["323 r. p.n.e.", "44 r. p.n.e.", "476 r. n.e.", "1453 r. n.e."]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Koniec starożytności to rok 476 n.e., kiedy germański wódz Odoaker obalił ostatniego cesarza rzymskiego Romulusa Augustulusa."}', '2025-10-24 22:16:53.538', '2025-10-24 22:16:53.538', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev95v00imqhd9zfsu0axs', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Skąd pochodzi nazwa ''antyk''?', '{"options": ["z greckiego słowa ''antikos''", "z łacińskiego słowa ''antiquus''", "z egipskiego słowa ''antykwa''", "z fenickiego słowa ''antik''"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Nazwa antyk pochodzi od łacińskiego słowa ''antiquus'', co oznacza ''dawny, zamierzchły, stary''."}', '2025-10-24 22:16:53.54', '2025-10-24 22:16:53.54', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev95y00inqhd995lhz1pk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co oznacza greckie słowo ''philosophia''?', '{"options": ["miłość do piękna", "miłość do mądrości", "miłość do prawdy", "miłość do nauki"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Filozofia pochodzi z greckiego: phileo – miłuję, sophia – mądrość. Oznacza ''umiłowanie mądrości''."}', '2025-10-24 22:16:53.542', '2025-10-24 22:16:53.542', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96000ioqhd9bg3b8ofv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Który filozof wypowiedział słynne zdanie ''Wiem, że nic nie wiem''?', '{"options": ["Platon", "Arystoteles", "Sokrates", "Heraklit"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Sokrates powtarzał ''Wiem, że nic nie wiem'', przyznając się do niewiedzy i ciągłego dążenia do poznania."}', '2025-10-24 22:16:53.544', '2025-10-24 22:16:53.544', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96200ipqhd9flb26mpv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kto był uczniem Sokratesa i założycielem Akademii Platońskiej?', '{"options": ["Arystoteles", "Platon", "Diogenes", "Epikur"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Platon był uczniem Sokratesa i założył Akademię Platońską, tworząc filozofię idealistyczną."}', '2025-10-24 22:16:53.546', '2025-10-24 22:16:53.546', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96400iqqhd97wwyqnyg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Który filozof powiedział ''Wszystko płynie'' i ''Nie można wejść dwa razy do tej samej rzeki''?', '{"options": ["Sokrates", "Heraklit z Efezu", "Tales z Miletu", "Pitagoras"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Heraklit z Efezu głosił, że wszystko się zmienia. Jego maksyma to ''Panta rhei'' – ''Wszystko płynie''."}', '2025-10-24 22:16:53.548', '2025-10-24 22:16:53.548', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96600irqhd92wvpkmzx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kto założył szkołę filozoficzną stoików?', '{"options": ["Epikur", "Zenon z Kition", "Diogenes", "Arystyp"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Zenon z Kition założył szkołę stoików, która głosiła życie w zgodzie z rozumem i naturą."}', '2025-10-24 22:16:53.551', '2025-10-24 22:16:53.551', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96800isqhd9vsuen8i3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Który filozof był twórcą epikureizmu?', '{"options": ["Zenon", "Arystyp", "Epikur z Samos", "Diogenes"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Epikur z Samos był twórcą epikureizmu – filozofii dążenia do szczęścia przez przyjemność rozumianą jako brak cierpienia."}', '2025-10-24 22:16:53.553', '2025-10-24 22:16:53.553', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96a00itqhd9w4voqj9w', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co głosili cynicy, czyli przedstawiciele greckiej szkoły filozoficznej?', '{"options": ["że trzeba dążyć do przyjemności", "że trzeba żyć w zgodzie z naturą i rozumem, odrzucając normy społeczne", "że prawda jest względna", "że trzeba zachować wewnętrzny spokój"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Cynicy głosili ideał życia w zgodzie z naturą, kierując się rozumem i odrzucając ogólnie przyjęte normy. Najsławniejszy cynik to Diogenes, zwany ''filozofem z beczki''."}', '2025-10-24 22:16:53.555', '2025-10-24 22:16:53.555', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96d00iuqhd9rcdbjh3o', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co było maksymą epikurejczyków?', '{"options": ["''Wiem, że nic nie wiem''", "''Carpe diem'' - chwytaj dzień", "''Wszystko płynie''", "''Poznaj samego siebie''"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Maksyma epikurejczyków to ''Carpe diem'' – ''chwytaj dzień''. Epikur kazał powiesić na frontonie szkoły: ''Gościu, tutaj będzie Ci dobrze, tutaj najwyższym dobrem jest przyjemność''."}', '2025-10-24 22:16:53.557', '2025-10-24 22:16:53.557', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96f00ivqhd9hgbq1dqk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kto był uczniem Platona i nauczycielem Aleksandra Wielkiego?', '{"options": ["Sokrates", "Arystoteles", "Epikur", "Pitagoras"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Arystoteles był uczniem Platona, a później nauczycielem Aleksandra Wielkiego. Jest twórcą podstaw logiki, botaniki, psychologii i retoryki."}', '2025-10-24 22:16:53.559', '2025-10-24 22:16:53.559', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96h00iwqhd90lpw9m9q', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest stoicyzm jako postawa życiowa?', '{"options": ["dążenie do przyjemności", "niewzruszony spokój, panowanie nad sobą, równowaga duchowa", "odrzucenie wszelkich norm społecznych", "relatywizm w poznaniu prawdy"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Stoicyzm to postawa życiowa polegająca na niewzruszonym spokoju, panowaniu nad sobą i równowadze duchowej. Stoicy cenili hart ducha i wewnętrzny spokój."}', '2025-10-24 22:16:53.561', '2025-10-24 22:16:53.561', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96j00ixqhd9fr24pz2p', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kim byli sofiści?', '{"options": ["żołnierzami spartańskimi", "wędrowymi nauczycielami uczącymi retoryki i filozofii", "kapłanami świątyń greckich", "rzeźbiarzami"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Sofiści byli wędrowymi nauczycielami, którzy za pieniądze uczyli retoryki, polityki, filozofii i etyki. Ich maksymą było ''człowiek jest miarą rzeczy''."}', '2025-10-24 22:16:53.564', '2025-10-24 22:16:53.564', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96l00iyqhd9q0at2wby', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Który filozof został nazwany ''ojcem medycyny''?', '{"options": ["Arystoteles", "Tales", "Hipokrates", "Pitagoras"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Hipokrates został nazwany ''ojcem medycyny''. Uważał, że środowisko ma decydujący wpływ na zdrowie człowieka."}', '2025-10-24 22:16:53.566', '2025-10-24 22:16:53.566', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96n00izqhd9xk5348sf', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Który filozof stworzył dualizm świata – teorię o współistnieniu świata idei i świata materialnego?', '{"options": ["Sokrates", "Platon", "Arystoteles", "Heraklit"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Platon stworzył platonizm – dualizm świata. Według niego istnieje świat idei (niedostępny zmysłom) i świat materialny (niedoskonała kopia idei)."}', '2025-10-24 22:16:53.568', '2025-10-24 22:16:53.568', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96p00j0qhd9ikjtrsho', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kto napisał eposy ''Iliada'' i ''Odyseja''?', '{"options": ["Hezjod", "Wergiliusz", "Homer", "Horacy"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Homer jest autorem dwóch najsławniejszych eposów antycznych: ''Iliady'' i ''Odysei''."}', '2025-10-24 22:16:53.57', '2025-10-24 22:16:53.57', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96r00j1qhd92x54m6g4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Ile dni wojny trojańskiej opisuje ''Iliada''?', '{"options": ["10 dni", "50 dni", "100 dni", "cały okres 10 lat wojny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "''Iliada'' opisuje ostatnie pięćdziesiąt dni wojny trojańskiej, nie całą wojnę."}', '2025-10-24 22:16:53.572', '2025-10-24 22:16:53.572', 'Iliada');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96t00j2qhd9fff6qcuq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Ile lat trwał powrót Odyseusza do Itaki?', '{"options": ["5 lat", "10 lat", "15 lat", "20 lat"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Powrót Odyseusza do Itaki po wojnie trojańskiej trwał 10 lat, wypełnionych licznymi przygodami."}', '2025-10-24 22:16:53.574', '2025-10-24 22:16:53.574', 'Odyseja');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96v00j3qhd92s9m4lm7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jak nazywała się żona Odyseusza?', '{"options": ["Helena", "Penelopa", "Ifigenia", "Andromache"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Penelopa była wierną żoną Odyseusza, która czekała na niego przez 10 lat, odpierając zaloty pretendentów."}', '2025-10-24 22:16:53.576', '2025-10-24 22:16:53.576', 'Odyseja');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev96x00j4qhd9hhen9ibn', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jak nazywał się syn Odyseusza?', '{"options": ["Telemach", "Parys", "Hektor", "Patrokles"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Telemach był synem Odyseusza i Penelopy. W ''Odysei'' opisane są także jego przygody."}', '2025-10-24 22:16:53.578', '2025-10-24 22:16:53.578', 'Odyseja');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97000j5qhd9pxsm0jgz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jakim metrum zostały napisane ''Iliada'' i ''Odyseja''?', '{"options": ["heksametrem daktylicznym", "pentametrem jambicznym", "trochejem", "amfibrachem"]}', '0', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Oba eposy Homera zostały napisane heksametrem daktylicznym – rytmem składającym się z sześciu stóp."}', '2025-10-24 22:16:53.58', '2025-10-24 22:16:53.58', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97300j6qhd98lkt9j05', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest ''kwestia homerycka''?', '{"options": ["pytanie o tematykę dzieł Homera", "spór o to, czy Homer rzeczywiście istniał i czy był autorem eposów", "problem z tłumaczeniem dzieł Homera", "zagadnienie moralności w eposach"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Kwestia homerycka to spór z XVIII wieku o to, czy Homer istniał. Przypuszczano, że utwory mogły być dziełem wędrownych śpiewaków – aojdów."}', '2025-10-24 22:16:53.583', '2025-10-24 22:16:53.583', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97500j7qhd9659abdki', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co to jest epos?', '{"options": ["krótki utwór liryczny", "rozbudowany utwór wierszowany opowiadający o legendarnych bohaterach", "utwór dramatyczny", "krótka forma epicka"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Epos to najstarszy gatunek literacki epiki – długi, wierszowany utwór opowiadający o legendarnych i historycznych bohaterach na tle ważnych wydarzeń."}', '2025-10-24 22:16:53.586', '2025-10-24 22:16:53.586', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97800j8qhd9hp1e4es6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kto napisał ''Teogonię'' – utwór o pochodzeniu bogów?', '{"options": ["Homer", "Hezjod", "Horacy", "Safona"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Hezjod był autorem ''Teogonii'' – eposu religijnego opisującego narodziny bogów."}', '2025-10-24 22:16:53.588', '2025-10-24 22:16:53.588', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97a00j9qhd9btvf9nis', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kim byli trzej wielcy tragicy greccy?', '{"options": ["Homer, Hezjod, Wergiliusz", "Sofokles, Ajschylos, Eurypides", "Horacy, Safona, Anakreont", "Platon, Arystoteles, Sokrates"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Trzej wielcy tragicy greccy to: Sofokles (''Antygona''), Ajschylos (''Oresteja'') i Eurypides (''Medea'')."}', '2025-10-24 22:16:53.591', '2025-10-24 22:16:53.591', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97d00jaqhd9bscxnf12', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Skąd wywodzi się teatr grecki?', '{"options": ["z obrzędów ku czci Afrodyty", "z obrzędów ku czci Dionizosa – dionizji", "z obrzędów ku czci Zeusa", "z obrzędów ku czci Apollina"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Teatr grecki wywodzi się z dionizji – obrzędów ku czci boga Dionizosa. Były to święta związane z winem i zabawami ludowymi."}', '2025-10-24 22:16:53.593', '2025-10-24 22:16:53.593', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97f00jbqhd9l2jw4tbq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest katharsis?', '{"options": ["rodzaj tragedii", "oczyszczenie, rozładowanie emocji pod wpływem sztuki", "styl w architekturze", "część teatru greckiego"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Katharsis (z greckiego katharos – oczyszczenie) to rozładowanie doznawanych wzruszeń pod wpływem sztuki, zwłaszcza tragedii."}', '2025-10-24 22:16:53.595', '2025-10-24 22:16:53.595', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97h00jcqhd9zzbureoj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Ile aktorów mogło występować jednocześnie na scenie w tragedii greckiej?', '{"options": ["dwóch", "trzech", "czterech", "pięciu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "W tragedii greckiej liczba aktorów występujących na scenie nie mogła przekraczać trzech."}', '2025-10-24 22:16:53.597', '2025-10-24 22:16:53.597', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97j00jdqhd9htxiobgk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest mimesis?', '{"options": ["rodzaj tragedii", "naśladowanie natury przez sztukę", "zasada filozoficzna", "styl architektoniczny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Mimesis to naśladowanie rzeczywistości przez sztukę. Według tej zasady należy odtwarzać świat, a nie go wymyślać."}', '2025-10-24 22:16:53.599', '2025-10-24 22:16:53.599', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97l00jeqhd9gzdjmvxj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest fatum?', '{"options": ["rodzaj tragedii", "przeznaczenie, los wyznaczony przez bogów", "część chóru", "styl w rzeźbie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Fatum to przeznaczenie, to co przewidziane i zrządzone przez bogów, zły los. W tragedii greckiej losy ludzi są podporządkowane fatum."}', '2025-10-24 22:16:53.601', '2025-10-24 22:16:53.601', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97n00jfqhd95doi4vdq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Która poetka grecka była nazywana ''dziesiątą Muzą''?', '{"options": ["Helena", "Ifigenia", "Safona", "Penelopa"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Safona była wybitną poetką z wyspy Lesbos, którą Platon nazywał ''dziesiątą Muzą''. Pisała pieśni miłosne i weselne."}', '2025-10-24 22:16:53.603', '2025-10-24 22:16:53.603', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97p00jgqhd9ul8cbfqc', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co to jest strofa saficka?', '{"options": ["zwrotka składająca się z trzech wierszy jedenastozgłoskowych i czwartego pięciogłoskowego", "zwrotka złożona z czterech wersów ośmiozgłoskowych", "dwuwers elegijny", "czterowiersz rymowany"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Strofa saficka, nazwana od imienia poetki Safony, składa się z trzech wierszy jedenastozgłoskowych i czwartego pięciogłoskowego."}', '2025-10-24 22:16:53.606', '2025-10-24 22:16:53.606', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97r00jhqhd9beykxjn7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co to są anakreontyki?', '{"options": ["długie eposy bohaterskie", "krótkie utwory o tematyce biesiadnej lub miłosnej", "tragedie greckie", "hymny ku czci bogów"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Anakreontyki to krótkie utwory o lekkiej tematyce biesiadnej lub miłosnej, nazwane od imienia poety Anakronta."}', '2025-10-24 22:16:53.608', '2025-10-24 22:16:53.608', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97t00jiqhd9zcgwydf0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kto tworzył poezję tyrtejską – patriotyczną, nawołującą do walki?', '{"options": ["Anakreont", "Tyrtajos", "Safona", "Pindar"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Tyrtajos tworzył elegie patriotyczne, zachęcając do walki w obronie ojczyzny. Od jego imienia pochodzi określenie ''poezja tyrtejska''."}', '2025-10-24 22:16:53.61', '2025-10-24 22:16:53.61', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97v00jjqhd97osyrj9o', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Ile stylów architektonicznych wyróżniano w starożytnej Grecji?', '{"options": ["dwa", "trzy", "cztery", "pięć"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "W greckiej architekturze wyróżniano trzy style: dorycki, joński i koryncki."}', '2025-10-24 22:16:53.612', '2025-10-24 22:16:53.612', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97x00jkqhd9ykqilodf', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Który styl architektoniczny charakteryzował się zdobieniami w kształcie ślimaków przypominających baranie rogi?', '{"options": ["dorycki", "joński", "koryncki", "toskański"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Styl joński charakteryzował się zdobieniami w postaci ślimaczków przypominających baranie rogi oraz wysmuklonym trzonem kolumny."}', '2025-10-24 22:16:53.614', '2025-10-24 22:16:53.614', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev97z00jlqhd9weqtwzzg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Który styl architektoniczny był najpóźniejszy i najbardziej zdobny, z ornamentami w kształcie liści?', '{"options": ["dorycki", "joński", "koryncki", "rzymski"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Styl koryncki był najpóźniejszym stylem w architekturze greckiej, charakteryzował się zdobieniami w kształcie pionowych liści wygiętych do tyłu."}', '2025-10-24 22:16:53.616', '2025-10-24 22:16:53.616', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98200jmqhd9cux5ib2g', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Którzy z wymienionych byli najsłynniejszymi rzeźbiarzami starożytnej Grecji?', '{"options": ["Fidiasz, Praksyteles, Poliklet", "Homer, Hezjod, Horacy", "Sofokles, Ajschylos, Eurypides", "Sokrates, Platon, Arystoteles"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Najsłynniejszymi rzeźbiarzami starożytnej Grecji byli: Fidiasz, Praksyteles i Poliklet."}', '2025-10-24 22:16:53.618', '2025-10-24 22:16:53.618', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98400jnqhd91snkktyq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co to jest politeizm?', '{"options": ["wiara w jednego Boga", "wiara w wielu bogów", "brak wiary w bogów", "wiara w siły natury"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Politeizm to wiara w wielu bogów. Taki charakter miała religia starożytnej Grecji i Rzymu (mitologia)."}', '2025-10-24 22:16:53.62', '2025-10-24 22:16:53.62', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98600joqhd9y8wb1uiu', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co to jest monoteizm?', '{"options": ["wiara w wielu bogów", "wiara w jednego Boga", "brak wiary", "wiara w bogów natury"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Monoteizm to wiara w jednego Boga. W starożytności monoteistycznym wyznaniem było chrześcijaństwo."}', '2025-10-24 22:16:53.622', '2025-10-24 22:16:53.622', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98800jpqhd9xrwtibxe', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co według mitologii greckiej było na początku, przed powstaniem świata?', '{"options": ["Chaos", "Zeus", "Gaja", "Eros"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Według mitologii greckiej na początku był Chaos – bezkształtna masa, otchłań łącząca ogień, wodę, powietrze i ziemię."}', '2025-10-24 22:16:53.624', '2025-10-24 22:16:53.624', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98a00jqqhd94pni35bd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kto był ojcem pierwszych bogów greckich?', '{"options": ["Zeus", "Uranos", "Kronos", "Hades"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Uranos (Niebo) był ojcem pierwszych bogów – tytanów, cyklopów i sturękich olbrzymów. Został zabity przez swojego syna Kronosa."}', '2025-10-24 22:16:53.626', '2025-10-24 22:16:53.626', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98c00jrqhd99slvis9t', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kim była Gaja w mitologii greckiej?', '{"options": ["boginią miłości", "Ziemią, matką pierwszych bogów", "boginią mądrości", "boginią polowań"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Gaja to Ziemia, matka pierwszych bogów. Z Uranosem (Niebem) zrodziła tytanów i inne istoty."}', '2025-10-24 22:16:53.628', '2025-10-24 22:16:53.628', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98e00jsqhd9x6nawotl', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kto był głównym bogiem w panteonie greckim?', '{"options": ["Hades", "Posejdon", "Zeus", "Apollo"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Zeus był najwyższym bogiem w panteonie greckim, władcą nieba i piorunów."}', '2025-10-24 22:16:53.63', '2025-10-24 22:16:53.63', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98g00jtqhd9ir9bd37v', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Która bogini rzuciła złote jabłko z napisem ''dla najpiękniejszej'', wywołując wojnę trojańską?', '{"options": ["Afrodyta", "Hera", "Eris - bogini niezgody", "Atena"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Bogini niezgody Eris rzuciła złote jabłko z napisem ''dla najpiękniejszej'' między Herę, Atenę i Afrodytę, co stało się przyczyną wojny trojańskiej."}', '2025-10-24 22:16:53.632', '2025-10-24 22:16:53.632', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98i00juqhd9pk61qn0g', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kto był królem Sparty, którego żonę Helenę porwał Parys?', '{"options": ["Agamemnon", "Achilles", "Menelaos", "Odyseusz"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Menelaos był królem Sparty i mężem Heleny. Jej porwanie przez Parysa stało się przyczyną wojny trojańskiej."}', '2025-10-24 22:16:53.634', '2025-10-24 22:16:53.634', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98k00jvqhd9lk8l8hiq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kto wpadł na pomysł drewnianego konia trojańskiego?', '{"options": ["Achilles", "Agamemnon", "Odyseusz", "Hektor"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Odyseusz wymyślił podstęp z drewnianym koniem, w którym ukryli się greccy żołnierze. Dzięki temu Grecy zdobyli Troję."}', '2025-10-24 22:16:53.636', '2025-10-24 22:16:53.636', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98m00jwqhd9d3vkdq2g', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Ile ksiąg zawiera Biblia?', '{"options": ["46", "66", "73", "80"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Biblia zawiera 73 księgi – 46 w Starym Testamencie i 27 w Nowym Testamencie."}', '2025-10-24 22:16:53.638', '2025-10-24 22:16:53.638', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98o00jxqhd98owtyyav', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jak nazywa się pierwszych pięć ksiąg Starego Testamentu?', '{"options": ["Ewangelie", "Tora (Pięcioksiąg)", "Psalmy", "Prorocy"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Pierwsze pięć ksiąg Starego Testamentu to Tora, czyli Pięcioksiąg: Księga Rodzaju, Wyjścia, Kapłańska, Liczb i Powtórzonego Prawa."}', '2025-10-24 22:16:53.64', '2025-10-24 22:16:53.64', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98q00jyqhd9ng3vt8j3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Ile ewangelii znajduje się w Nowym Testamencie?', '{"options": ["dwie", "trzy", "cztery", "pięć"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "W Nowym Testamencie znajdują się cztery ewangelie: św. Mateusza, św. Marka, św. Łukasza i św. Jana."}', '2025-10-24 22:16:53.642', '2025-10-24 22:16:53.642', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98s00jzqhd9tif404is', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest konflikt tragiczny w tragedii antycznej?', '{"options": ["walka bohatera z wrogiem", "starcie dwóch równorzędnych racji moralnych, między którymi nie można dokonać wyboru", "spór między bogami", "kłótnia w rodzinie królewskiej"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Konflikt tragiczny to starcie dwóch równorzędnych racji moralnych. Bohater musi wybierać między wartościami, które są jednakowo ważne, co prowadzi do katastrofy."}', '2025-10-24 22:16:53.644', '2025-10-24 22:16:53.644', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98u00k0qhd9jbjq2i0o', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest wina tragiczna (hamartia)?', '{"options": ["celowe popełnienie zbrodni", "złamanie prawa boskiego", "błędna ocena własnej sytuacji prowadząca do klęski", "zdrada ojczyzny"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Wina tragiczna (hamartia) to błędna ocena własnej sytuacji przez bohatera. Podejmuje on decyzje, które - mimo dobrych intencji - prowadzą go do klęski."}', '2025-10-24 22:16:53.646', '2025-10-24 22:16:53.646', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98w00k1qhd9avoe1dzh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Co to jest hybris w kontekście tragedii greckiej?', '{"options": ["mądrość i rozsądek", "pycha i przekroczenie granic wyznaczonych przez bogów", "sprawiedliwość królewska", "odwaga w walce"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Hybris to pycha, zuchwałość i przekroczenie granic wyznaczonych przez bogów i naturę. W tragedii greckiej hybris zawsze prowadzi do nemezis - kary ze strony bogów."}', '2025-10-24 22:16:53.649', '2025-10-24 22:16:53.649', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev98y00k2qhd9t0chn3kp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jak nazywa się pierwsza część tragedii greckiej, która wprowadza w akcję?', '{"options": ["parodos", "prologos", "stasimon", "eksodos"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Prologos (prolog) to pierwsza część tragedii, która pełniła funkcję przedmowy i wprowadzała widzów w akcję."}', '2025-10-24 22:16:53.651', '2025-10-24 22:16:53.651', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99000k3qhd9bgeb2xoh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jak nazywa się wstępna pieśń chóru wchodzącego na orchestrę?', '{"options": ["eksodos", "stasimon", "parodos", "kommos"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Parodos to wstępna, wejściowa pieśń chóru wchodzącego na orchestrę."}', '2025-10-24 22:16:53.653', '2025-10-24 22:16:53.653', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99200k4qhd9l841ljoq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jak nazywa się punkt kulminacyjny tragedii, w którym bohater wyraża swój lament?', '{"options": ["stasimon", "parodos", "kommos", "epejsodion"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Kommos to punkt kulminacyjny tragedii – lament bohatera wyrażający szczyt rozpaczy."}', '2025-10-24 22:16:53.655', '2025-10-24 22:16:53.655', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99500k5qhd9fkc8gaeb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Która zasada tragedii antycznej mówi, że nie wolno przeplatać scen tragicznych z komicznymi?', '{"options": ["zasada trzech jedności", "zasada decorum", "zasada jedności estetyki", "zasada mimesis"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Zasada jedności estetyki głosiła, że nie wolno przeplatać scen tragicznych z komicznymi. Tragedia musiała zachować jednolity, podniosły ton."}', '2025-10-24 22:16:53.657', '2025-10-24 22:16:53.657', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99700k6qhd95tsv0tvi', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co oznacza zasada decorum w tragedii antycznej?', '{"options": ["zachowanie jedności miejsca", "podniosły język i styl, brak krwawych scen na scenie", "występowanie trzech aktorów", "obecność chóru"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Zasada decorum oznaczała zachowanie stosowności – podniosły język i styl oraz brak przedstawiania krwawych scen na scenie."}', '2025-10-24 22:16:53.659', '2025-10-24 22:16:53.659', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99900k7qhd9ise24jzj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Jaka była rola chóru w tragedii greckiej?', '{"options": ["grał głównego bohatera", "komentował wydarzenia i wyrażał opinie zbiorowe", "tworzył scenografię", "zastępował narratora epicką opowieścią"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Chór komentował wydarzenia, wyrażał opinie zbiorowe społeczeństwa, dokonywał refleksji moralnych i filozoficznych nad losem bohaterów."}', '2025-10-24 22:16:53.661', '2025-10-24 22:16:53.661', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99b00k8qhd95atzo77y', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest paralelizm fabuły w eposie antycznym?', '{"options": ["powtarzanie tych samych scen", "równoczesne występowanie dwóch ciągów wydarzeń w fabule", "porównywanie bohaterów", "podział na księgi"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Paralelizm fabuły to cecha eposu antycznego, w której równocześnie występują dwa ciągi wydarzeń (np. w Odysei: przygody Telemacha i wędrówka Odyseusza)."}', '2025-10-24 22:16:53.663', '2025-10-24 22:16:53.663', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99d00k9qhd9w5lt92zw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Jaki typ eposu reprezentuje ''Iliada''?', '{"options": ["epos religijny", "epos rycerski", "epos fantastyczny", "epos dydaktyczny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "''Iliada'' to epos rycerski, opisujący wojnę trojańską i czyny bohaterów wojennych."}', '2025-10-24 22:16:53.665', '2025-10-24 22:16:53.665', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99f00kaqhd917ylbnk8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Jaki typ eposu reprezentuje ''Odyseja''?', '{"options": ["epos religijny", "epos rycerski", "epos fantastyczny", "epos historyczny"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "''Odyseja'' to epos fantastyczny, pełen niezwykłych przygód, mitycznych stworzeń i magicznych miejsc."}', '2025-10-24 22:16:53.667', '2025-10-24 22:16:53.667', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99h00kbqhd9d7040wgd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Która technika narracyjna występuje w ''Odysei'', gdy Odyseusz opowiada o swoich przygodach na dworze Alkinoosa?', '{"options": ["prospekcja", "retrospekcja", "paralelizm", "inwokacja"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "W ''Odysei'' występuje retrospekcja – Odyseusz na dworze króla Alkinoosa opowiada o swoich wcześniejszych przygodach."}', '2025-10-24 22:16:53.669', '2025-10-24 22:16:53.669', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99j00kcqhd97luzsi6f', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest inwokacja w eposie?', '{"options": ["zakończenie utworu", "wezwanie do Muzy na początku utworu", "opis bitwy", "dialog bohaterów"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Inwokacja to wezwanie do Muzy na początku eposu, w którym poeta prosi o natchnienie i pomoc w opowiadaniu historii."}', '2025-10-24 22:16:53.671', '2025-10-24 22:16:53.671', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99l00kdqhd9d2trfrt8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Która cecha NIE jest typowa dla eposu antycznego?', '{"options": ["wszechwiedzący narrator", "uroczysty, patetyczny styl", "intymny ton wypowiedzi", "nagromadzenie epitetów"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Intymny ton wypowiedzi jest charakterystyczny dla liryki, nie dla eposu. Epos cechuje się uroczystym, patetycznym stylem."}', '2025-10-24 22:16:53.674', '2025-10-24 22:16:53.674', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99n00keqhd9g3aiqnkx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest oda?', '{"options": ["krótki utwór satyryczny", "utwór liryczny o patetycznym stylu i pochwalnym charakterze", "długi epos bohaterski", "tragedia w trzech aktach"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Oda to utwór liryczny o patetycznym stylu i pochwalnym charakterze, opiewający ważne wydarzenie, osobę lub idee."}', '2025-10-24 22:16:53.676', '2025-10-24 22:16:53.676', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99q00kfqhd90frt0eqw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kto był najsławniejszym twórcą poezji chóralnej, sławiącym zwycięzców igrzysk olimpijskich?', '{"options": ["Anakreont", "Safona", "Pindar", "Tyrtajos"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Pindar był najwybitniejszym twórcą poezji chóralnej, sławił zwycięzców igrzysk olimpijskich w uroczystych odach."}', '2025-10-24 22:16:53.678', '2025-10-24 22:16:53.678', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99s00kgqhd94ar4kdnm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Która poetka prowadziła szkołę dla dziewcząt na wyspie Lesbos?', '{"options": ["Helena", "Penelopa", "Safona", "Andromache"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Safona prowadziła szkołę dla dziewcząt z arystokratycznych domów na wyspie Lesbos, ucząc muzyki, poezji i tańca."}', '2025-10-24 22:16:53.68', '2025-10-24 22:16:53.68', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99u00khqhd9401yt7bd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest elegia?', '{"options": ["wesoły utwór biesiadny", "utwór liryczny o smutnej tematyce", "długi epos", "komedia satyryczna"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Elegia to gatunek liryczny o zazwyczaj smutnej, melancholijnej tematyce, często związanej ze śmiercią lub stratą."}', '2025-10-24 22:16:53.682', '2025-10-24 22:16:53.682', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99w00kiqhd9uipy5fns', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest tren?', '{"options": ["utwór weselny", "pieśń żałobna, lament nad zmarłym", "hymn pochwalny", "utwór biesiadny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Tren to pieśń żałobna, lament nad zmarłym. Gatunek ten powstał w antyku."}', '2025-10-24 22:16:53.685', '2025-10-24 22:16:53.685', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev99y00kjqhd9e5xwivtj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Kto był najsławniejszym komiediopisarzem greckim?', '{"options": ["Sofokles", "Arystofanes", "Menander", "Plautus"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Arystofanes był najsławniejszym komiediopisarzem greckim. Jego komedie miały charakter satyryczny i polityczny."}', '2025-10-24 22:16:53.687', '2025-10-24 22:16:53.687', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9a100kkqhd9hh9kcd7w', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Co to są mity teogoniczne?', '{"options": ["mity o powstawaniu świata", "mity o pochodzeniu bogów", "mity o powstawaniu człowieka", "mity o pochodzeniu bohaterów"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Mity teogoniczne to mity mówiące o pochodzeniu i narodzinach bogów (z greckiego theos – bóg)."}', '2025-10-24 22:16:53.689', '2025-10-24 22:16:53.689', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9a300klqhd9giwk25is', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Co to są mity kosmogoniczne?', '{"options": ["mity o pochodzeniu bogów", "mity o powstawaniu świata i kosmosu", "mity o bohaterach", "mity o wojnach"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Mity kosmogoniczne to mity mówiące o powstawaniu świata i kosmosu (z greckiego kosmos – świat, porządek)."}', '2025-10-24 22:16:53.691', '2025-10-24 22:16:53.691', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9a500kmqhd9gjpdch90', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Co to są mity genealogiczne?', '{"options": ["mity o powstawaniu świata", "mity o pochodzeniu bogów", "mity mówiące o pochodzeniu bohaterów i rodów", "mity o końcu świata"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Mity genealogiczne to mity mówiące o pochodzeniu bohaterów i rodów, przedstawiające ich historię rodzinną."}', '2025-10-24 22:16:53.694', '2025-10-24 22:16:53.694', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9a700knqhd9boeg02s9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jaki tytan zabił swojego ojca Uranosa i został później obalony przez własnego syna?', '{"options": ["Atlas", "Kronos", "Prometeusz", "Epimeteusz"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Kronos zabił swojego ojca Uranosa, a później został obalony przez własnego syna Zeusa, co zapoczątkowało erę bogów olimpijskich."}', '2025-10-24 22:16:53.696', '2025-10-24 22:16:53.696', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9a900koqhd9ftj8q2vi', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kim była Reja w mitologii greckiej?', '{"options": ["żoną Uranosa", "żoną Kronosa i matką Zeusa", "żoną Zeusa", "córką Zeusa"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Reja była tytanidą, żoną Kronosa i matką głównych bogów olimpijskich: Zeusa, Hery, Posejdona, Hadesa, Demeter i Hestii."}', '2025-10-24 22:16:53.698', '2025-10-24 22:16:53.698', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ac00kpqhd96il9nvi3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kim była Hera w mitologii greckiej?', '{"options": ["boginią mądrości", "boginią miłości", "żoną Zeusa, boginią małżeństwa", "boginią polowań"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Hera była żoną Zeusa i boginią małżeństwa, opiekunką rodziny i wierności małżeńskiej."}', '2025-10-24 22:16:53.7', '2025-10-24 22:16:53.7', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ae00kqqhd9ddncrz09', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kim był Posejdon?', '{"options": ["bogiem wojny", "bogiem mórz i oceanów", "bogiem podziemi", "bogiem słońca"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Posejdon był bogiem mórz, oceanów i trzęsień ziemi, bratem Zeusa."}', '2025-10-24 22:16:53.702', '2025-10-24 22:16:53.702', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ew009cqh49bytt59p3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Co Jan Kott miał na myśli porównując strukturę ''Króla Edypa'' do pułapki?', '{"options": ["Edyp jest łowcą szkodników", "Edyp jest małą, nieznaczącą postacią", "Porównanie nie ma sensu interpretacyjnego", "Każdy ruch Edypa paradoksalnie zbliża go do katastrofy"]}', '3', NULL, '{Kott,pułapka,"struktura dramatu"}', '{"explanation": "Kott porównał dramaturgiczną strukturę do pułapki: każde działanie Edypa, każda próba ucieczki od prawdy, zbliża go do katastrofy."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ew009dqh49ot9y87ak', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Jak postmodernistyczna krytyka problematyzuje opozycję ślepota/widzenie w tragedii?', '{"options": ["Pokazuje, że granica między widzeniem a ślepotą jest niestabilna i dekonstruuje się", "Akceptuje prosty podział na ślepych i widzących", "Ignoruje motyw ślepoty jako nieistotny", "Uznaje ślepotę za wyłącznie fizyczną przypadłość"]}', '0', NULL, '{dekonstrukcja,postmodernizm,"opozycja binarna"}', '{"explanation": "Postmodernistyczna lektura pokazuje, że opozycja ślepota/widzenie jest niestabilna: ślepy ''widzi'', widzący jest ''ślepy'' - kategorie przenikają się nawzajem."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ew009eqh49ruhnqtjs', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Jaką rolę w tragedii pełni tzw. ''podwójna motywacja'' (double determination)?', '{"options": ["Wydarzenia mają tylko przyczynę naturalną", "Wydarzenia mają jednocześnie przyczynę ludzką i boską, współistniejące bez sprzeczności", "Wydarzenia mają tylko przyczynę boską", "Motywacja jest całkowicie nieistotna dla fabuły"]}', '1', NULL, '{"podwójna motywacja",przyczynowość,"double determination"}', '{"explanation": "Double determination oznacza, że wydarzenia mają jednocześnie przyczynę ludzką (decyzje) i boską (fatum) - oba poziomy współistnieją bez sprzeczności."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ex009fqh49b9ng28dv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Jak interpretować relację między wolną wolą a determinizmem w świetle kompatybilizmu?', '{"options": ["Edyp jest całkowicie zdeterminowany, nie ma wolnej woli", "Edyp ma pełną wolność, fatum nie istnieje", "Edyp ma wolność w obrębie zdeterminowanej struktury - wybiera jak reagować na sytuację", "Pytanie o wolną wolę jest nieistotne dla interpretacji tragedii"]}', '2', NULL, '{"wolna wola",determinizm,kompatybilizm}', '{"explanation": "Kompatybilizm uznaje, że Edyp działa w zdeterminowanej strukturze (fatum), ale zachowuje wolność w sposobie reakcji - to źródło jego godności."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ex009gqh49knhwjpe7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Co oznacza arystotelesowskie pojęcie ''to philokalon'' w odniesieniu do bohatera tragicznego?', '{"options": ["Miłość do złota i bogactwa", "Skłonność do przemocy", "Obojętność wobec wartości", "Umiłowanie piękna moralnego, szlachetność duszy"]}', '3', NULL, '{"to philokalon",Arystoteles,szlachetność}', '{"explanation": "To philokalon oznacza ''umiłowanie piękna'' w sensie etycznym - szlachetność duszy, dążenie do tego, co moralnie piękne."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ex009hqh490jn7q3dj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Jakie jest znaczenie ''Edypa w Kolonie'' dla interpretacji ''Króla Edypa''?', '{"options": ["Pokazuje dalszy los Edypa - przemianę ze skazonego wygnańca w świętego herosa", "To całkowicie niezwiązana sztuka", "Zaprzecza wydarzeniom z ''Króla Edypa''", "Jest komedią o Edypie"]}', '0', NULL, '{"Edyp w Kolonie",heros,przemiana}', '{"explanation": "''Edyp w Kolonie'' pokazuje dalszy los: ślepy wygnaniec staje się świętym herosem chroniącym Ateny - transformacja ze skazonego w świętego."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ex009iqh49kl23bita', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Jaki jest związek między ''Królem Edypem'' a arystotelesowską koncepcją mimesis?', '{"options": ["Tragedia jest dokładną kopią rzeczywistości", "Mimesis oznacza naśladowanie działań ludzi szlachetniejszych niż przeciętni", "Mimesis to całkowite odrzucenie rzeczywistości", "Tragedia naśladuje tylko wydarzenia komiczne"]}', '1', NULL, '{mimesis,Arystoteles,naśladownictwo}', '{"explanation": "Według Arystotelesa tragedia jest mimesis działań ludzi ''lepszych od nas'' - szlachetnych, wysoko urodzonych. Nie jest kopią, lecz twórczym przedstawieniem."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ex009jqh494rpdw749', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Jak Walter Kaufmann krytykował freudowską interpretację mitu edypalnego?', '{"options": ["Uznawał ją za całkowicie słuszną", "Ignorował Freuda w swoich pracach", "Wskazywał, że Edyp NIE pragnął zabić ojca ani poślubić matki - działał nieświadomie", "Twierdził, że Freud nie znał greki"]}', '2', NULL, '{Kaufmann,"krytyka Freuda",nieświadomość}', '{"explanation": "Kaufmann wskazywał, że freudowska interpretacja jest błędna: Edyp nie pragnął zbrodni, wręcz uciekał przed nimi. Mit dotyczy nieświadomości, nie ukrytych pragnień."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ex009kqh49ye1fqyzc', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 1, 'Co oznacza pojęcie ''anagnorisis złożona'' (complex recognition) w teorii tragedii?', '{"options": ["Rozpoznanie dotyczy tylko jednej osoby", "Rozpoznanie nie ma znaczenia dla fabuły", "Rozpoznanie obejmuje jednocześnie tożsamość i sytuację moralną - jak u Edypa", "Rozpoznanie jest fałszywe"]}', '2', NULL, '{anagnorisis,"rozpoznanie złożone",teoria}', '{"explanation": "Anagnorisis złożona to rozpoznanie obejmujące jednocześnie tożsamość (kim jestem) i sytuację moralną (co uczyniłem) - jak u Edypa, który odkrywa że jest synem Lajosa i mordercą ojca."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ex009lqh497k0bnkky', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 2, 'Które elementy ''Króla Edypa'' były przedmiotem interpretacji psychoanalitycznej?', '{"options": ["Nieświadome zabójstwo ojca i małżeństwo z matką - kompleks Edypa", "Oślepienie jako symboliczna kastracja", "Struktura stasimonów chóru", "Zagadka Sfinksa jako pytanie o tożsamość podmiotu", "Zaraza jako metafora ekonomiczna"]}', '[0, 1, 3]', NULL, '{psychoanaliza,Freud,interpretacja}', '{"explanation": "Psychoanaliza interpretowała: relację Edyp-Lajos-Jokasta jako wzór kompleksu, oślepienie jako symboliczną kastrację, zagadkę Sfinksa jako pytanie o tożsamość."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ag00krqhd9cwxev5ff', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kim był Hades?', '{"options": ["bogiem wojny", "bogiem mórz", "władcą podziemi i królestwa zmarłych", "bogiem słońca"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Hades był władcą podziemi i królestwa zmarłych, bratem Zeusa i Posejdona."}', '2025-10-24 22:16:53.704', '2025-10-24 22:16:53.704', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9aj00ksqhd96s4mbura', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kim była Atena?', '{"options": ["boginią miłości", "boginią mądrości, wojny sprawiedliwej i rzemiosła", "boginią polowań", "boginią małżeństwa"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Atena była boginią mądrości, wojny sprawiedliwej, rzemiosła i strategii. Według mitu narodziła się z głowy Zeusa."}', '2025-10-24 22:16:53.707', '2025-10-24 22:16:53.707', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9al00ktqhd9u47ehiy4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kim była Afrodyta?', '{"options": ["boginią mądrości", "boginią miłości i piękna", "boginią polowań", "boginią rolnictwa"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Afrodyta była boginią miłości, piękna i pożądania. Według mitu narodziła się z piany morskiej."}', '2025-10-24 22:16:53.709', '2025-10-24 22:16:53.709', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9an00kuqhd95l1il59y', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kim był Apollo?', '{"options": ["bogiem wojny", "bogiem słońca, muzyki, poezji i wróżbiarstwa", "bogiem morza", "bogiem podziemi"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Apollo był bogiem słońca, światła, muzyki, poezji, sztuki i wróżbiarstwa. Patron delickiej wyroczni."}', '2025-10-24 22:16:53.711', '2025-10-24 22:16:53.711', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ap00kvqhd9yaqn6s2i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kim była Artemida?', '{"options": ["boginią miłości", "boginią mądrości", "boginią polowań i księżyca", "boginią wojny"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Artemida była boginią polowań, księżyca i dziewictwa, siostrą bliźniaczką Apollina."}', '2025-10-24 22:16:53.714', '2025-10-24 22:16:53.714', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ar00kwqhd967cuhov9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kim był Ares?', '{"options": ["bogiem miłości", "bogiem wojny i przemocy", "bogiem rzemiosła", "bogiem handlu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Ares był bogiem wojny, przemocy i krwawych bitew, synem Zeusa i Hery."}', '2025-10-24 22:16:53.716', '2025-10-24 22:16:53.716', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9au00kxqhd9tg3700fx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kim był Hermes?', '{"options": ["bogiem wojny", "posłańcem bogów, opiekunem podróżnych i handlarzy", "bogiem morza", "bogiem rolnictwa"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Hermes był posłańcem bogów, opiekunem podróżnych, handlarzy i złodziei, przewodnikiem dusz do Hadesu."}', '2025-10-24 22:16:53.718', '2025-10-24 22:16:53.718', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9aw00kyqhd9nxora3xq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Kim był Hefajstos?', '{"options": ["bogiem wojny", "bogiem ognia, kowalstwa i rzemiosła", "bogiem morza", "bogiem wina"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Hefajstos był bogiem ognia, kowalstwa, rzemiosła i metalurgii. Wytwarzał broń i przedmioty dla bogów."}', '2025-10-24 22:16:53.72', '2025-10-24 22:16:53.72', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ay00kzqhd9kejuysdq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kim był Dionizos?', '{"options": ["bogiem wojny", "bogiem wina, radości i teatru", "bogiem morza", "bogiem słońca"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Dionizos był bogiem wina, radości, płodności i teatru. Na jego cześć odbywały się dionizje, z których wywodzi się teatr grecki."}', '2025-10-24 22:16:53.723', '2025-10-24 22:16:53.723', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9b000l0qhd9z8nsrzy1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Kim była Demeter?', '{"options": ["boginią wojny", "boginią rolnictwa, żniw i płodności ziemi", "boginią polowań", "boginią mądrości"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Demeter była boginią rolnictwa, żniw, płodności ziemi i pór roku. Matka Persefony."}', '2025-10-24 22:16:53.725', '2025-10-24 22:16:53.725', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9b300l1qhd9bcf0w176', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Kto był najsłynniejszym dowódcą greckim w wojnie trojańskiej?', '{"options": ["Achilles", "Agamemnon", "Odyseusz", "Menelaos"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Agamemnon, król Miken i brat Menelaosa, był naczelnym dowódcą wojsk greckich w wojnie trojańskiej."}', '2025-10-24 22:16:53.727', '2025-10-24 22:16:53.727', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9b500l2qhd9ftvy1jep', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kto był największym wojownikiem greckim w wojnie trojańskiej?', '{"options": ["Agamemnon", "Odyseusz", "Achilles", "Patrokles"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Achilles był największym wojownikiem greckim, niemal nieśmiertelnym bohaterem o nadludzkiej sile."}', '2025-10-24 22:16:53.729', '2025-10-24 22:16:53.729', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9b700l3qhd9ouj75kuv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kim był Hektor w wojnie trojańskiej?', '{"options": ["królem Sparty", "największym wojownikiem trojańskim, bratem Parysa", "królem Itaki", "wróżbitą"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Hektor był największym wojownikiem trojańskim i głównym obrońcą Troi, bratem Parysa."}', '2025-10-24 22:16:53.731', '2025-10-24 22:16:53.731', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9b900l4qhd99pt4xl88', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Kim był Patrokles?', '{"options": ["królem Itaki", "przyjacielem Achillesa zabitym przez Hektora", "królem Troi", "prorokiem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Patrokles był ukochanym przyjacielem Achillesa. Jego śmierć z rąk Hektora sprowadziła Achillesa z powrotem do walki."}', '2025-10-24 22:16:53.733', '2025-10-24 22:16:53.733', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9bb00l5qhd9ksyhrl9r', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Kim był Priam?', '{"options": ["królem Sparty", "królem Troi, ojcem Hektora i Parysa", "królem Itaki", "wodzem greckim"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Priam był królem Troi, ojcem Hektora i Parysa. Zginął podczas zdobycia miasta."}', '2025-10-24 22:16:53.735', '2025-10-24 22:16:53.735', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evama0155qhd9r13i59tg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Ile ksiąg liczy ''Pan Tadeusz''?', '{"options": ["10", "12", "14", "24"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "''Pan Tadeusz'' składa się z 12 ksiąg pisanych wierszem (13-zgłoskowcem). Jest to nawiązanie do tradycji epopei antycznych."}', '2025-10-24 22:16:55.426', '2025-10-24 22:16:55.426', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9bd00l6qhd95es6wgai', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Która księga Biblii zawiera historię stworzenia świata?', '{"options": ["Księga Wyjścia", "Księga Rodzaju", "Księga Psalmów", "Księga Mądrości"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Księga Rodzaju (Genesis) zawiera historię stworzenia świata w sześć dni oraz dzieje pierwszych ludzi."}', '2025-10-24 22:16:53.738', '2025-10-24 22:16:53.738', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9bf00l7qhd9aewi8wol', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'W której księdze Biblii opisane jest wyjście Izraelitów z Egiptu?', '{"options": ["Księga Rodzaju", "Księga Wyjścia (Exodus)", "Księga Liczb", "Księga Jozuego"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Księga Wyjścia (Exodus) opisuje wyjście Izraelitów z niewoli egipskiej pod wodzą Mojżesza."}', '2025-10-24 22:16:53.74', '2025-10-24 22:16:53.74', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9bh00l8qhd989jtujk1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Którą księgę Biblii stanowią modlitwy i pieśni?', '{"options": ["Księga Przysłów", "Księga Psalmów", "Księga Mądrości", "Pieśń nad Pieśniami"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Księga Psalmów zawiera 150 modlitw i pieśni, tradycyjnie przypisywanych królowi Dawidowi."}', '2025-10-24 22:16:53.742', '2025-10-24 22:16:53.742', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9bk00l9qhd9hm67dw34', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Co to jest Apokalipsa św. Jana?', '{"options": ["ewangelia opisująca życie Jezusa", "księga prorocza o końcu świata i Sądzie Ostatecznym", "zbiór przypowieści", "historia pierwszych chrześcijan"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Apokalipsa (Objawienie) św. Jana to księga prorocza opisująca wizje końca świata i Sądu Ostatecznego."}', '2025-10-24 22:16:53.744', '2025-10-24 22:16:53.744', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9bm00laqhd916lcu718', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'W jakich językach została napisana Biblia?', '{"options": ["tylko po grecku", "tylko po hebrajsku", "po aramejsku, hebrajsku i grecku", "po łacinie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Biblia została napisana w trzech językach: aramejskim, hebrajskim (Stary Testament) i grecku (Nowy Testament)."}', '2025-10-24 22:16:53.746', '2025-10-24 22:16:53.746', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9bo00lbqhd9mxwzljwy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Który filozof rzymski był nauczycielem cesarza Nerona?', '{"options": ["Cyceron", "Seneka", "Marek Aureliusz", "Pliniusz"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Seneka był filozofem stoickim, nauczycielem i opiekunem cesarza Nerona. Tworzył pisma etyczne i tragedie."}', '2025-10-24 22:16:53.748', '2025-10-24 22:16:53.748', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9bq00lcqhd9x7k4t1jd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Który cesarz rzymski był nazywany ''filozofem na tronie''?', '{"options": ["Neron", "Marek Aureliusz", "August", "Kaligula"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Marek Aureliusz był cesarzem rzymskim i filozofem stoickim, nazywanym ''filozofem na tronie''. Głosił idee humanitaryzmu i sprawiedliwości."}', '2025-10-24 22:16:53.75', '2025-10-24 22:16:53.75', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9bs00ldqhd9dy3cmup4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Kto był doskonałym mówcą rzymskim, autorem mów sądowych i politycznych?', '{"options": ["Seneka", "Cyceron", "Horacy", "Wergiliusz"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Cyceron był doskonałym mówcą, autorem wielu mów sądowych i politycznych oraz dzieł z retoryki."}', '2025-10-24 22:16:53.752', '2025-10-24 22:16:53.752', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9bu00leqhd91t27zsqo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Który filozof starożytny uważał, że podstawowym elementem świata jest ogień?', '{"options": ["Tales z Miletu", "Heraklit z Efezu", "Anaksymenes", "Pitagoras"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Heraklit z Efezu uważał, że podstawowym elementem świata jest ogień. Jako pierwszy zainteresował się poznaniem poprzez zgłębianie ludzkiej duszy."}', '2025-10-24 22:16:53.755', '2025-10-24 22:16:53.755', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9bw00lfqhd9pxleaptf', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Który filozof starożytny uważał, że podstawowym elementem świata jest woda?', '{"options": ["Heraklit", "Tales z Miletu", "Anaksymenes", "Sokrates"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Tales z Miletu uważał, że główną przyczyną powstania świata była woda."}', '2025-10-24 22:16:53.757', '2025-10-24 22:16:53.757', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9by00lgqhd9mnsx5atp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Który filozof starożytny uważał, że podstawowym elementem świata jest powietrze?', '{"options": ["Tales", "Heraklit", "Anaksymenes", "Pitagoras"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Anaksymenes za podstawowy element świata uznawał powietrze. W zależności od jego gęstości powstawał ogień, woda, człowiek czy ziemia."}', '2025-10-24 22:16:53.759', '2025-10-24 22:16:53.759', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9c000lhqhd99b4kfvl8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Który filozof wysunął teorię kulistości ziemi?', '{"options": ["Sokrates", "Anaksymander", "Tales", "Heraklit"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Anaksymander wysunął teorię kulistości ziemi i uważał, że pod wpływem ruchu wyłoniło się ciepło i zimno."}', '2025-10-24 22:16:53.761', '2025-10-24 22:16:53.761', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9c300liqhd9bd7su4l3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Który filozof jest twórcą Twierdzenia Pitagorasa?', '{"options": ["Sokrates", "Platon", "Pitagoras", "Euklides"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Pitagoras był znakomitym matematykiem i filozofem, twórcą Twierdzenia Pitagorasa. Uważał, że ziemia ma kształt kuli."}', '2025-10-24 22:16:53.763', '2025-10-24 22:16:53.763', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9c500ljqhd9h4tok5s0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 1, 'Który rzymski poeta był autorem ''Eneidy''?', '{"options": ["Horacy", "Owidiusz", "Wergiliusz", "Cyceron"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Wergiliusz był autorem ''Eneidy'' – eposu o Eneasz, trojańskim bohaterze, który stał się przodkiem Rzymian."}', '2025-10-24 22:16:53.765', '2025-10-24 22:16:53.765', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9c700lkqhd9iyuay5ua', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Który poeta rzymski tworzył pieśni i ody, m.in. ''Carpe diem''?', '{"options": ["Wergiliusz", "Horacy", "Owidiusz", "Katullus"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Horacy był twórcą pieśni i od. Jego słynne ''Carpe diem'' (chwytaj dzień) stało się maksymą epikurejską."}', '2025-10-24 22:16:53.767', '2025-10-24 22:16:53.767', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9c900llqhd9ln9c1e94', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Dopasuj filozofów do ich głównych twierdzeń.', '{"leftColumn": [{"id": "A", "text": "Sokrates"}, {"id": "B", "text": "Heraklit"}, {"id": "C", "text": "Platon"}, {"id": "D", "text": "Arystoteles"}], "rightColumn": [{"id": 1, "text": "Wszystko płynie, nic nie stoi w miejscu"}, {"id": 2, "text": "Świat idei i świat materialny"}, {"id": 3, "text": "Do poznania potrzebne są rozum i zmysły"}, {"id": 4, "text": "Wiem, że nic nie wiem"}], "matchingType": "philosopher_thesis"}', '[[0, 3], [1, 0], [2, 1], [3, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Sokrates: ''Wiem, że nic nie wiem'', Heraklit: ''Wszystko płynie'', Platon: dualizm światów, Arystoteles: poznanie przez rozum i zmysły."}', '2025-10-24 22:16:53.77', '2025-10-24 22:16:53.77', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9cb00lmqhd9mk2hmfay', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Dopasuj szkoły filozoficzne do ich głównych założeń.', '{"leftColumn": [{"id": "A", "text": "Stoicy"}, {"id": "B", "text": "Epikurejczycy"}, {"id": "C", "text": "Cynicy"}, {"id": "D", "text": "Sofiści"}], "rightColumn": [{"id": 1, "text": "Człowiek jest miarą rzeczy"}, {"id": 2, "text": "Życie w zgodzie z naturą, odrzucenie norm społecznych"}, {"id": 3, "text": "Carpe diem - chwytaj dzień"}, {"id": 4, "text": "Niewzruszony spokój i równowaga duchowa"}], "matchingType": "school_principle"}', '[[0, 3], [1, 2], [2, 1], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Stoicy głosili spokój i równowagę, epikurejczycy - carpe diem, cynicy - życie zgodne z naturą, sofiści - relatywizm poznania."}', '2025-10-24 22:16:53.772', '2025-10-24 22:16:53.772', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ce00lnqhd9hqw60md1', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Dopasuj bogów greckich do ich rzymskich odpowiedników.', '{"leftColumn": [{"id": "A", "text": "Zeus"}, {"id": "B", "text": "Hera"}, {"id": "C", "text": "Afrodyta"}, {"id": "D", "text": "Ares"}], "rightColumn": [{"id": 1, "text": "Mars"}, {"id": 2, "text": "Jowisz (Jupiter)"}, {"id": 3, "text": "Juno"}, {"id": 4, "text": "Wenus"}], "matchingType": "gods_equivalents"}', '[[0, 1], [1, 2], [2, 3], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Zeus = Jowisz, Hera = Juno, Afrodyta = Wenus, Ares = Mars."}', '2025-10-24 22:16:53.774', '2025-10-24 22:16:53.774', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9cg00loqhd9kqpaowe7', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Dopasuj bogów do ich funkcji w mitologii greckiej.', '{"leftColumn": [{"id": "A", "text": "Apollo"}, {"id": "B", "text": "Artemida"}, {"id": "C", "text": "Hermes"}, {"id": "D", "text": "Dionizos"}], "rightColumn": [{"id": 1, "text": "Bóg wina i teatru"}, {"id": 2, "text": "Posłaniec bogów"}, {"id": 3, "text": "Bogini polowań"}, {"id": 4, "text": "Bóg słońca i muzyki"}], "matchingType": "gods_functions"}', '[[0, 3], [1, 2], [2, 1], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Apollo - słońce i muzyka, Artemida - polowania, Hermes - posłaniec, Dionizos - wino i teatr."}', '2025-10-24 22:16:53.777', '2025-10-24 22:16:53.777', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9cj00lpqhd9c42h8fkv', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Które cechy charakteryzują sztukę antyczną? (wybierz wszystkie poprawne)', '{"options": ["mimesis - naśladowanie natury", "asymetria i chaos", "piękno, symetria i harmonia", "przedstawianie młodości, zdrowia i siły", "unikanie przedstawiania człowieka", "pokazywanie brzydoty i starości"]}', '[0, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Sztuka antyczna charakteryzowała się mimesis, pięknem, symetrią, harmonią i przedstawianiem młodości oraz zdrowia. Unikano brzydoty i starości."}', '2025-10-24 22:16:53.779', '2025-10-24 22:16:53.779', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9cl00lqqhd9p3zgyrcl', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Które elementy należą do budowy tragedii antycznej? (wybierz wszystkie poprawne)', '{"options": ["prologos", "rozwikłanie", "parodos", "stasimon", "monolog wewnętrzny", "eksodos"]}', '[0, 2, 3, 5]', NULL, '{historical_literary,closed_multiple,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Budowa tragedii: prologos, parodos, epejsodion, stasimon, kommos, eksodos. Rozwikłanie i monolog wewnętrzny nie należą do klasycznej struktury."}', '2025-10-24 22:16:53.781', '2025-10-24 22:16:53.781', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9cn00lrqhd9rop9jy7f', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Które zasady obowiązywały w tragedii antycznej? (wybierz wszystkie poprawne)', '{"options": ["zasada trzech jedności (miejsca, czasu, akcji)", "dowolna liczba aktorów", "ograniczenie liczby aktorów do trzech", "losy ludzi zależne od fatum", "obecność scen krwawych na scenie", "rola komentatora pełniona przez chór"]}', '[0, 2, 3, 5]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Zasady tragedii: trzech jedności, max. trzech aktorów, fatum, chór jako komentator. Sceny krwawe nie były pokazywane na scenie (zasada decorum)."}', '2025-10-24 22:16:53.783', '2025-10-24 22:16:53.783', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9cp00lsqhd9thswygm4', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Dopasuj typy mitów do ich treści.', '{"leftColumn": [{"id": "A", "text": "Mity kosmogoniczne"}, {"id": "B", "text": "Mity teogoniczne"}, {"id": "C", "text": "Mity antropogeniczne"}, {"id": "D", "text": "Mity genealogiczne"}], "rightColumn": [{"id": 1, "text": "O pochodzeniu bohaterów i rodów"}, {"id": 2, "text": "O powstawaniu świata"}, {"id": 3, "text": "O pochodzeniu bogów"}, {"id": 4, "text": "O powstawaniu człowieka"}], "matchingType": "myth_types"}', '[[0, 1], [1, 2], [2, 3], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Kosmogoniczne - powstanie świata, teogoniczne - pochodzenie bogów, antropogeniczne - powstanie człowieka, genealogiczne - dzieje rodów."}', '2025-10-24 22:16:53.786', '2025-10-24 22:16:53.786', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evahv0137qhd9feaugyic', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 1, 'Co przepowiadają wiedźmy Makbetowi przy pierwszym spotkaniu?', '{"options": ["że zginie w bitwie", "że straci wszystko", "że zostanie królem", "że będzie miał syna"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,renaissance,batch-2025-01}', '{"explanation": "Wiedźmy przepowiadają, że Makbet zostanie tanem Cawdor, a następnie królem."}', '2025-10-24 22:16:55.267', '2025-10-24 22:16:55.267', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9cs00ltqhd98t489x2y', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Uzupełnij informacje o eposie homeryckim.', '{"gaps": [{"id": 1, "options": ["pentametrem", "heksametrem daktylicznym", "trochejem", "jambem"]}, {"id": 2, "options": ["10", "30", "50", "100"]}, {"id": 3, "options": ["religijnego", "rycerskiego", "fantastycznego", "dydaktycznego"]}, {"id": 4, "options": ["religijny", "rycerski", "fantastyczny", "historyczny"]}], "textWithGaps": "Homerydy eposy zostały napisane [1], który składa się z sześciu stóp. ''Iliada'' opisuje ostatnie [2] dni wojny trojańskiej i jest przykładem eposu [3]. Natomiast ''Odyseja'' to epos [4], opisujący powrót Odyseusza do Itaki."}', '[1, 2, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Eposy Homera napisane są heksametrem daktylicznym. ''Iliada'' opisuje 50 dni wojny i jest eposem rycerskim, ''Odyseja'' to epos fantastyczny."}', '2025-10-24 22:16:53.788', '2025-10-24 22:16:53.788', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9cu00luqhd9jlm7dtxv', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Które gatunki literackie powstały w antyku? (wybierz wszystkie poprawne)', '{"options": ["epopeja (epos)", "sonet", "tragedia", "oda", "ballada", "elegia", "hymn", "nowela"]}', '[0, 2, 3, 5, 6]', NULL, '{historical_literary,closed_multiple,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "W antyku powstały: epopeja, tragedia, komedia, oda, elegia, hymn, tren, bajka, sielanka. Sonet, ballada i nowela to gatunki późniejsze."}', '2025-10-24 22:16:53.791', '2025-10-24 22:16:53.791', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9cx00lvqhd9jiny1gg9', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, czym jest mimesis w sztuce antycznej i podaj przykład jej zastosowania.', '{"instruction": "Zdefiniuj pojęcie mimesis i wyjaśnij, jak realizowano je w sztuce starożytnej. (40-60 słów)"}', NULL, '{"criteria": ["definicja mimesis jako naśladowania natury (1 pkt)", "przykład zastosowania w rzeźbie, malarstwie lub literaturze (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["naśladowanie", "rzeczywistość", "realizm", "natura", "wierność"], "expectedAnswer": "Mimesis to zasada naśladowania rzeczywistości przez sztukę. W starożytności artyści nie wymyślali świata, lecz wiernie go odtwarzali. Rzeźbiarze jak Fidiasz czy Praksyteles tworzyli realistyczne posągi bogów i ludzi, przedstawiając harmonię i piękno ciała. W literaturze Homer szczegółowo opisywał przedmioty i sytuacje."}', '2025-10-24 22:16:53.793', '2025-10-24 22:16:53.793', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9cz00lwqhd9vchve2um', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Opisz, na czym polegała zasada trzech jedności w tragedii antycznej.', '{"instruction": "Wymień i krótko scharakteryzuj trzy jedności obowiązujące w tragedii greckiej. (40-60 słów)"}', NULL, '{"criteria": ["wymienienie trzech jedności (1 pkt)", "krótkie wyjaśnienie każdej z nich (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["miejsce", "czas", "akcja", "24 godziny", "jeden wątek"], "expectedAnswer": "Zasada trzech jedności obejmowała: jedność miejsca (akcja toczy się w jednym miejscu), jedność czasu (wydarzenia trwają maksymalnie 24 godziny) oraz jedność akcji (występuje jeden główny wątek fabularny bez wątków pobocznych). Zasady te miały zapewnić spójność i wiarygodność przedstawienia."}', '2025-10-24 22:16:53.796', '2025-10-24 22:16:53.796', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9d200lxqhd9nolw3jba', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Wyjaśnij pojęcie hybris i podaj, jakie skutki wywoływała w tragedii greckiej.', '{"instruction": "Zdefiniuj hybris i opisz jej konsekwencje dla bohatera tragicznego. (40-60 słów)"}', NULL, '{"criteria": ["definicja hybris jako pychy i przekroczenia granic (1 pkt)", "wskazanie konsekwencji - nemezis, katastrofa (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-3,antiquity,batch-2025-01}', '{"keyWords": ["pycha", "przekroczenie granic", "nemezis", "kara bogów", "katastrofa"], "expectedAnswer": "Hybris to pycha, zuchwałość i przekroczenie granic wyznaczonych przez bogów oraz naturę. W tragedii greckiej hybris zawsze prowadziła do nemezis - kary ze strony bogów. Bohater wykazujący hybris nieuchronnie zmierzał ku katastrofie i upadkowi, gdyż bogowie nie tolerowali ludzkiej zarozumiałości."}', '2025-10-24 22:16:53.798', '2025-10-24 22:16:53.798', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9d400lyqhd9g73d9x73', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Scharakteryzuj rolę chóru w tragedii greckiej.', '{"instruction": "Wyjaśnij, jakie funkcje pełnił chór w przedstawieniu tragicznym. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie funkcji komentatora wydarzeń (1 pkt)", "wskazanie innych funkcji: głos społeczeństwa, refleksje moralne (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["komentator", "opinie zbiorowe", "refleksje moralne", "pieśni", "głos społeczeństwa"], "expectedAnswer": "Chór pełnił funkcję komentatora wydarzeń, wyrażał opinie zbiorowe społeczeństwa i dokonywał refleksji moralnych. Śpiewał pieśni w kluczowych momentach tragedii, pomagając widzom zrozumieć działania bohaterów. Reprezentował głos rozsądku i tradycji, często ostrzegając przed konsekwencjami pochopnych decyzji."}', '2025-10-24 22:16:53.8', '2025-10-24 22:16:53.8', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9d600lzqhd9azsqur2u', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Wyjaśnij, czym różni się konflikt tragiczny od zwykłego konfliktu dramatycznego.', '{"instruction": "Scharakteryzuj specyfikę konfliktu tragicznego w tragedii antycznej. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie równorzędności racji moralnych (1 pkt)", "wyjaśnienie niemożności dokonania wyboru bez konsekwencji (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-3,antiquity,batch-2025-01}', '{"keyWords": ["równorzędne racje", "niemożność wyboru", "obie strony słuszne", "katastrofa", "wartości"], "expectedAnswer": "Konflikt tragiczny to starcie dwóch równorzędnych racji moralnych, między którymi bohater nie może dokonać wyboru bez poważnych konsekwencji. Obie strony konfliktu mają słuszne argumenty i wartości. Wybór jednej opcji oznacza naruszenie drugiej równie ważnej wartości, co prowadzi do nieuchronnej katastrofy."}', '2025-10-24 22:16:53.803', '2025-10-24 22:16:53.803', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9d900m0qhd96jwec57m', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Opisz główne założenia stoicyzmu jako postawy życiowej.', '{"instruction": "Wyjaśnij, w czym według stoików tkwiło szczęście i jak powinien żyć człowiek. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie spokoju, hartu ducha i opanowania (1 pkt)", "życie w zgodzie z naturą i rozumem (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["spokój", "hart ducha", "natura", "rozum", "równowaga duchowa"], "expectedAnswer": "Stoicy głosili, że szczęście osiąga się przez życie w zgodzie z naturą i rozumem. Cenili niewzruszony spokój, opanowanie, hart ducha i wewnętrzną równowagę duchową nawet w trudnych chwilach. Człowiek powinien zachować stoicki spokój wobec przeciwności losu i sumiennie wykonywać swoje obowiązki."}', '2025-10-24 22:16:53.805', '2025-10-24 22:16:53.805', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9db00m1qhd9rpf1v2kd', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, czym różniła się filozofia epikurejczyków od hedonizmu.', '{"instruction": "Opisz, jak epikurejczycy rozumieli przyjemność i szczęście. (40-60 słów)"}', NULL, '{"criteria": ["przyjemność jako brak cierpienia, bólu i strachu (1 pkt)", "zachowanie zasad moralnych, umiarkowanie (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["brak cierpienia", "spokój ducha", "ataraksja", "umiarkowanie", "zasady moralne"], "expectedAnswer": "Epikurejczycy, w przeciwieństwie do hedonistów, rozumieli przyjemność jako brak bólu, strachu i cierpienia, nie jako doznawanie zmysłowych uciech. Szczęście osiągano przez spokój ducha (ataraksja) i przestrzeganie zasad moralnych. Epikur głosił umiarkowanie i prostotę życia, nie rozpustę."}', '2025-10-24 22:16:53.807', '2025-10-24 22:16:53.807', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9dd00m2qhd95urj24m2', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Scharakteryzuj dualizm platońskiego świata idei i świata materialnego.', '{"instruction": "Wyjaśnij koncepcję dwóch światów według Platona i ich wzajemną relację. (50-70 słów)"}', NULL, '{"criteria": ["opisanie świata idei jako doskonałego i niezmiennego (1 pkt)", "opisanie świata materialnego jako niedoskonałej kopii idei (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-3,antiquity,batch-2025-01}', '{"keyWords": ["świat idei", "doskonały", "niezmienny", "kopia", "cień", "pierwowzór"], "expectedAnswer": "Według Platona istnieją dwa światy: świat idei i świat materialny. Świat idei jest doskonały, niezmienny i wieczny, niedostępny zmysłom, poznawalny tylko rozumem. Świat materialny to jedynie niedoskonała kopia, cień świata idei, dostępny naszym zmysłom. Wszystko co widzimy to tylko odbicie doskonałych pierwowzorów - idei."}', '2025-10-24 22:16:53.81', '2025-10-24 22:16:53.81', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9df00m3qhd97ubztwxw', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Opisz mit o wojnie trojańskiej - jej przyczynę i sposób zakończenia.', '{"instruction": "Wyjaśnij, jak doszło do wojny i w jaki sposób Grecy zdobyli Troję. (50-70 słów)"}', NULL, '{"criteria": ["wskazanie przyczyny: porwanie Heleny przez Parysa (1 pkt)", "opisanie podstępu z koniem trojańskim (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["Helena", "Parys", "koń trojański", "podstęp", "Odyseusz"], "expectedAnswer": "Wojna trojańska wybuchła, gdy Parys porwał Helenę, żonę spartańskiego króla Menelaosa. W odwecie wojska greckie pod wodzą Agamemnona oblegały Troję przez 10 lat. Grecy zdobyli miasto dzięki podstępowi Odyseusza - zbudowali drewnianego konia, w którym ukryli się wojownicy. Trojańczycy wprowadzili konia do miasta, a w nocy Grecy wyszli i zdobyli Troję."}', '2025-10-24 22:16:53.812', '2025-10-24 22:16:53.812', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9dh00m4qhd97z1s2yi1', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Wyjaśnij koncepcję katharsis w kontekście tragedii greckiej.', '{"instruction": "Opisz, czym jest katharsis i jak działała na widzów tragedii. (40-60 słów)"}', NULL, '{"criteria": ["definicja katharsis jako oczyszczenia emocjonalnego (1 pkt)", "mechanizm działania - rozładowanie emocji poprzez oglądanie tragedii (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-3,antiquity,batch-2025-01}', '{"keyWords": ["oczyszczenie", "emocje", "strach", "litość", "rozładowanie"], "expectedAnswer": "Katharsis (z greckiego katharos – oczyszczenie) to rozładowanie doznawanych wzruszeń pod wpływem sztuki. Widzowie tragedii, obserwując cierpienie bohaterów, przeżywali strach i litość, co pozwalało im na oczyszczenie z własnych negatywnych emocji. Teatr pełnił funkcję terapeutyczną dla społeczeństwa."}', '2025-10-24 22:16:53.814', '2025-10-24 22:16:53.814', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9dk00m5qhd9t291bpix', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Który styl greckiej architektury charakteryzował się masywnym trzonem kolumny bez zdobień?', '{"options": ["styl koryncki", "styl joński", "styl dorycki", "styl attycki"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Styl dorycki cechował się surowością, masywnym trzonem kolumny i brakiem upiększeń."}', '2025-10-24 22:16:53.816', '2025-10-24 22:16:53.816', 'Sztuka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9dm00m6qhd9ira88k9u', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Który styl architektury greckiej miał charakterystyczne ''ślimaczki'' przypominające baranie rogi?', '{"options": ["styl joński", "styl dorycki", "styl koryncki", "styl attycki"]}', '0', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Styl joński charakteryzował się zdobieniami w kształcie ślimaczków przypominających baranie rogi."}', '2025-10-24 22:16:53.818', '2025-10-24 22:16:53.818', 'Sztuka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9do00m7qhd9p9n6yb91', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Który styl był najpóźniejszy w architekturze greckiej i miał zdobienia w kształcie liści?', '{"options": ["styl dorycki", "styl attycki", "styl joński", "styl koryncki"]}', '3', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Styl koryncki był najpóźniejszy i wyróżniał się pionowymi liśćmi pnącymi się ku kapitelowi."}', '2025-10-24 22:16:53.82', '2025-10-24 22:16:53.82', 'Sztuka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9dq00m8qhd9459eb0ij', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jak nazywa się słynna świątynia Ateny na greckim Akropolu?', '{"options": ["Koloseum", "Panteon", "Partenon", "Forum"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Partenon to świątynia Ateny znajdująca się na ateńskim Akropolu."}', '2025-10-24 22:16:53.823', '2025-10-24 22:16:53.823', 'Sztuka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9dt00m9qhd9d5qhpykj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jak nazywa się rzymski amfiteatr, w którym odbywały się walki gladiatorów?', '{"options": ["Koloseum", "Panteon", "Partenon", "Akropol"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Koloseum to rzymski amfiteatr, w którym odbywały się walki gladiatorów i inne widowiska."}', '2025-10-24 22:16:53.825', '2025-10-24 22:16:53.825', 'Sztuka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9dv00maqhd9qfuimi9k', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kim był Fidiasz?', '{"options": ["filozofem", "poetą", "rzeźbiarzem", "wodzem"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Fidiasz był jednym z najbardziej znanych rzeźbiarzy starożytnej Grecji."}', '2025-10-24 22:16:53.827', '2025-10-24 22:16:53.827', 'Sztuka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9dx00mbqhd9baed0hj8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co oznacza pojęcie ''fatum''?', '{"options": ["mądrość", "odwaga", "przeznaczenie zrządzone przez bogów", "szczęście"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Fatum to przeznaczenie, to co przewidziane i zrządzone przez bogów, nieuchronny los."}', '2025-10-24 22:16:53.83', '2025-10-24 22:16:53.83', 'Pojęcia');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evahx0138qhd9jgbon1f2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 1, 'Kim jest Banko?', '{"options": ["wrogiem Makbeta", "przyjacielem Makbeta", "królem Anglii", "synem Duncana"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,renaissance,batch-2025-01}', '{"explanation": "Banko jest przyjacielem i towarzyszem broni Makbeta."}', '2025-10-24 22:16:55.269', '2025-10-24 22:16:55.269', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9dz00mcqhd910fpwmrk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest epos?', '{"options": ["krótki wiersz liryczny", "utwór dramatyczny", "długi, wierszowany utwór opowiadający o legendarnych bohaterach", "pieśń religijna"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Epos to długi, wierszowany utwór epicki opowiadający o legendarnych i historycznych bohaterach na tle ważnych wydarzeń."}', '2025-10-24 22:16:53.832', '2025-10-24 22:16:53.832', 'Pojęcia');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9e100mdqhd907h9l4cg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co to jest oda?', '{"options": ["utwór dramatyczny", "utwór liryczny o patetycznym stylu i pochwalnym charakterze", "opowieść mitologiczna", "krótki wiersz miłosny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Oda to utwór liryczny o patetycznym stylu i pochwalnym charakterze, opiewający ważne wydarzenia, osoby lub idee."}', '2025-10-24 22:16:53.834', '2025-10-24 22:16:53.834', 'Pojęcia');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9e400meqhd9ji0be0e4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co to jest mit?', '{"options": ["dokument historyczny", "bajeczna opowieść wyjaśniająca powstanie świata i bogów", "traktat filozoficzny", "pieśń religijna"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Mit to bajeczna opowieść narracyjna wyjaśniająca powstawanie świata, bogów, herosów i ludzi."}', '2025-10-24 22:16:53.836', '2025-10-24 22:16:53.836', 'Pojęcia');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9e600mfqhd9xhmaf5md', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jakie mity wyjaśniają pochodzenie bogów?', '{"options": ["kosmogoniczne", "antropologiczne", "teogoniczne", "genealogiczne"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Mity teogoniczne to te, które opowiadają o pochodzeniu i narodzinach bogów."}', '2025-10-24 22:16:53.838', '2025-10-24 22:16:53.838', 'Pojęcia');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9e800mgqhd9g0b21dlr', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Jaka data jest umownym początkiem epoki średniowiecza w Europie?', '{"options": ["1453 r.", "476 r.", "1066 r.", "800 r."]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Rok 476 n.e. - upadek Cesarstwa Zachodniorzymskiego - jest umowną datą początku średniowiecza w Europie."}', '2025-10-24 22:16:53.84', '2025-10-24 22:16:53.84', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ea00mhqhd9yrqxv0ep', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Skąd pochodzi nazwa ''średniowiecze''?', '{"options": ["od łacińskiego medium aevum - wieki średnie", "od greckiego mesos chronos", "od francuskiego moyen age", "od niemieckiego Mittelalter"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Nazwa średniowiecze pochodzi od łacińskiego wyrażenia medium aevum, oznaczającego ''wieki średnie'' - czas między antykiem a renesansem."}', '2025-10-24 22:16:53.842', '2025-10-24 22:16:53.842', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ec00miqhd98d44p4bg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co oznacza termin ''teocentryzm''?', '{"options": ["podporządkowanie życia królowi", "podporządkowanie życia rozumowi", "podporządkowanie życia naturze", "podporządkowanie życia Bogu"]}', '3', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Teocentryzm (z gr. theos - Bóg) oznacza podporządkowanie wszystkich dziedzin życia Bogu."}', '2025-10-24 22:16:53.844', '2025-10-24 22:16:53.844', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ee00mjqhd9o1kit7bi', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Która data kończy epokę średniowiecza w Europie?', '{"options": ["1410 r. - bitwa pod Grunwaldem", "1492 r. - odkrycie Ameryki", "1517 r. - początek reformacji", "1453 r. - upadek Konstantynopola"]}', '3', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Rok 1453 (upadek Konstantynopola) jest najpowszechniej przyjmowaną datą końca średniowiecza, choć podaje się też inne daty: 1492 (odkrycie Ameryki) lub 1517 (reformacja)."}', '2025-10-24 22:16:53.846', '2025-10-24 22:16:53.846', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9eg00mkqhd97czs4ujp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Kto nadał nazwę ''średniowiecze'' tej epoce?', '{"options": ["filozofowie średniowieczni", "ludzie renesansu", "historycy XIX wieku", "uczeni starożytni"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Nazwę ''średniowiecze'' nadali humaniści renesansowi, traktując tę epokę z lekceważeniem jako okres między ważnym dla nich antykiem a odrodzeniem."}', '2025-10-24 22:16:53.848', '2025-10-24 22:16:53.848', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ei00mlqhd9bpqp95d3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Na ile okresów dzieli się epoka średniowiecza?', '{"options": ["na 2 okresy", "na 5 okresów", "na 3 okresy", "na 4 okresy"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Średniowiecze dzieli się na trzy okresy: wczesne (V-X w.), dojrzałe/pełne (XI-XIII w.) i późne (XIV-XV w.)."}', '2025-10-24 22:16:53.85', '2025-10-24 22:16:53.85', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ek00mmqhd9cslc97yi', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Kto jest twórcą augustynizmu?', '{"options": ["św. Tomasz z Akwinu", "św. Franciszek z Asyżu", "św. Anzelm", "św. Augustyn"]}', '3', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Augustynizm to kierunek filozoficzny stworzony przez świętego Augustyna, nawiązujący do filozofii Platona."}', '2025-10-24 22:16:53.852', '2025-10-24 22:16:53.852', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9el00mnqhd9944d6w6c', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Kto jest twórcą tomizmu?', '{"options": ["św. Tomasz z Akwinu", "św. Augustyn", "św. Franciszek", "św. Anzelm"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Tomizm to kierunek filozoficzny stworzony przez świętego Tomasza z Akwinu, nawiązujący do filozofii Arystotelesa."}', '2025-10-24 22:16:53.854', '2025-10-24 22:16:53.854', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9eo00moqhd9pytrwdh6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co oznacza łacińskie wyrażenie ''memento mori''?', '{"options": ["żyj chwilą", "pamiętaj o śmierci", "poznaj samego siebie", "carpe diem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Memento mori to łacińskie wyrażenie oznaczające ''pamiętaj o śmierci'' - jedno z kluczowych haseł średniowiecza."}', '2025-10-24 22:16:53.856', '2025-10-24 22:16:53.856', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ep00mpqhd95s4w30go', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co oznacza francuskie określenie ''danse macabre''?', '{"options": ["taniec życia", "taniec dworski", "taniec śmierci", "taniec weselny"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Danse macabre (taniec śmierci) to średniowieczny motyw przedstawiający śmierć tańczącą ze wszystkimi stanami."}', '2025-10-24 22:16:53.858', '2025-10-24 22:16:53.858', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9er00mqqhd9xzlioel6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Jaki był dominujący język warstw wykształconych w średniowieczu?', '{"options": ["greka", "łacina", "język hebrajski", "starofrancuski"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Łacina była uniwersalnym językiem nauki, Kościoła i literatury w średniowiecznej Europie."}', '2025-10-24 22:16:53.86', '2025-10-24 22:16:53.86', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9et00mrqhd919dwzqiy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co oznacza termin ''hagiografia''?', '{"options": ["pisanie kronik", "sztuka kaznodziejska", "żywotopisarstwo świętych", "pisanie apokryfów"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Hagiografia to gatunek literacki obejmujący żywoty świętych, legendy i biografie postaci świętych."}', '2025-10-24 22:16:53.862', '2025-10-24 22:16:53.862', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ev00msqhd94besxc5j', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co to jest misterium?', '{"options": ["utwór satyryczny", "kronika historyczna", "dramat religijny o tematyce biblijnej", "pieśńrycerska"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Misterium to średniowieczny dramat religijny, którego treść czerpana była z Biblii."}', '2025-10-24 22:16:53.864', '2025-10-24 22:16:53.864', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ey00mtqhd9sc5gzlsw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Jak nazywał się średniowieczny dramat religijny ukazujący cuda świętych?', '{"options": ["misterium", "moralitet", "mirakl", "farsa"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Mirakl (od łac. miraculum - cud) to dramat ukazujący sceny z życia świętych zawierające elementy cudowności."}', '2025-10-24 22:16:53.866', '2025-10-24 22:16:53.866', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9f000muqhd9m44d5qge', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co to jest moralitet?', '{"options": ["zbiór pouczeń moralnych", "dramat o charakterze dydaktyczno-moralizatorskim", "traktat filozoficzny", "pieśń religijna"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Moralitet to średniowieczny dramat o charakterze dydaktycznym, pokazujący walkę cnót i przywary ludzkich."}', '2025-10-24 22:16:53.868', '2025-10-24 22:16:53.868', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9f200mvqhd9loouj6cg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co oznacza francuskie wyrażenie ''chanson de geste''?', '{"options": ["pieśń miłosna", "pieśń religijna", "pieśń ludowa", "pieśń o czynach"]}', '3', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Chanson de geste (pieśń o czynach) to gatunek epicki opiewający bohaterskie czyny rycerzy."}', '2025-10-24 22:16:53.87', '2025-10-24 22:16:53.87', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9f400mwqhd93l6o6ct8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co to jest plankt?', '{"options": ["pieśń o czynach rycerskich", "utwór wyrażający żal po zmarłym", "dramat religijny", "kronika dziejów"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Plankt (od łac. planktus - płacz) to gatunek wyrażający żal i cierpienie, często po śmierci Chrystusa."}', '2025-10-24 22:16:53.872', '2025-10-24 22:16:53.872', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9f600mxqhd9685t8uul', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Jaki styl architektoniczny dominował we wczesnym średniowieczu?', '{"options": ["gotycki", "barokowy", "renesansowy", "romański"]}', '3', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Styl romański dominował w X-XIII wieku, charakteryzował się masywnością i prostotą form."}', '2025-10-24 22:16:53.874', '2025-10-24 22:16:53.874', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9f800myqhd9990ho5m4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Który styl architektoniczny charakteryzuje się strzelistością i witrażami?', '{"options": ["romański", "barokowy", "gotycki", "renesansowy"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Styl gotycki (XII-XV w.) charakteryzuje się strzelistością, wysokimi oknami i bogato zdobionymi witrażami."}', '2025-10-24 22:16:53.877', '2025-10-24 22:16:53.877', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9fa00mzqhd93qo0vo06', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co charakteryzowało budowle romańskie?', '{"options": ["wysokie witraże i strzelistość", "grube mury i małe okna", "bogata ornamentyka", "kopuły i kolumnady"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Budowle romańskie miały grube mury, małe okna i charakteryzowały się masywnością oraz funkcją obronną."}', '2025-10-24 22:16:53.879', '2025-10-24 22:16:53.879', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9fc00n0qhd90vimsb5g', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Który wzorzec osobowy reprezentował całkowite wyrzeczenie się dóbr doczesnych?', '{"options": ["rycerz", "asceta", "władca", "trubadur"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Asceta to wzorzec osobowy charakteryzujący się całkowitym wyrzeczeniem dóbr doczesnych i życiem w ascezie."}', '2025-10-24 22:16:53.881', '2025-10-24 22:16:53.881', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9fe00n1qhd9khaeb9q5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co było główną cechą wzorca rycerza chrześcijańskiego?', '{"options": ["dążenie do bogactwa", "kontemplacja i modlitwa", "honor, odwaga i wiara", "życie w ubóstwie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Rycerz chrześcijański charakteryzował się honorem, odwagą, wiernością i głęboką wiarą -walczył w obronie chrześcijaństwa."}', '2025-10-24 22:16:53.883', '2025-10-24 22:16:53.883', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9fh00n2qhd9wsn2vq7p', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co to jest scholastyka?', '{"options": ["system edukacji", "styl w sztuce", "metoda filozoficzna wyjaśniania prawd wiary rozumem", "gatunek literacki"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Scholastyka to metoda filozoficzna polegająca na racjonalnym wyjaśnianiu prawd wiary."}', '2025-10-24 22:16:53.885', '2025-10-24 22:16:53.885', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9fj00n3qhd9gyghog40', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Kto propagował franciszkanizm?', '{"options": ["św. Franciszek z Asyżu", "św. Augustyn", "św. Tomasz z Akwinu", "św. Anzelm"]}', '0', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Franciszkanizm to nurt zapoczątkowany przez świętego Franciszka z Asyżu, głoszący miłość do wszystkich stworzeń."}', '2025-10-24 22:16:53.887', '2025-10-24 22:16:53.887', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9fl00n4qhd9aea5urwh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co oznacza termin ''uniwersalizm średniowieczny''?', '{"options": ["różnorodność kultur w Europie", "wspólnota religii, kultury i norm w całej Europie", "wolność religijna", "podział na narody"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Uniwersalizm średniowieczny oznaczał wspólnotę religii, języka, kultury i norm społecznych w całej Europie."}', '2025-10-24 22:16:53.89', '2025-10-24 22:16:53.89', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9fn00n5qhd9yii9z2xj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co to jest feudalizm?', '{"options": ["system demokratyczny", "system polityczno-gospodarczy oparty na hierarchii lennej", "system republikański", "monarchia absolutna"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Feudalizm to średniowieczny system społeczno-gospodarczy oparty na hierarchii, lenach i zależnościach wasalnych."}', '2025-10-24 22:16:53.892', '2025-10-24 22:16:53.892', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9fp00n6qhd9w1klg88n', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Co oznacza motyw ''stabat mater dolorosa''?', '{"options": ["Madonna z Dzieciątkiem", "Matka Boska w chwale", "stała Matka boleściwa - Maryja pod krzyżem", "Zwiastowanie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Stabat Mater Dolorosa (stała Matka boleściwa) to motyw przedstawiający Maryję cierpiącą pod krzyżem Chrystusa."}', '2025-10-24 22:16:53.894', '2025-10-24 22:16:53.894', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9fr00n7qhd9sh6ttzyz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Co to jest pieta?', '{"options": ["przedstawienie narodzin Chrystusa", "przedstawienie Ostatniej Wieczerzy", "przedstawienie Maryi z martwym Chrystusem na kolanach", "przedstawienie ukrzyżowania"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Pieta (wł. litość) to przedstawienie Matki Boskiej trzymającej na kolanach ciało Chrystusa zdjęte z krzyża."}', '2025-10-24 22:16:53.896', '2025-10-24 22:16:53.896', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9fu00n8qhd9fabfwktj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Co to jest deesis?', '{"options": ["przedstawienie Trójcy Świętej", "przedstawienie Chrystusa jako sędziego z Maryją i Janem Chrzcicielem", "przedstawienie apostołów", "scena Zwiastowania"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Deesis (gr. prośba) to przedstawienie Chrystusa Sędziego z Maryją po prawej i Janem Chrzcicielem po lewej stronie."}', '2025-10-24 22:16:53.898', '2025-10-24 22:16:53.898', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9fv00n9qhd9k9jdv5je', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Który gatunek literacki zawierał opisy dziejów historycznych?', '{"options": ["misterium", "moralitet", "kronika", "plankt"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Kronika to gatunek historiograficzny zawierający chronologiczny opis wydarzeń historycznych."}', '2025-10-24 22:16:53.9', '2025-10-24 22:16:53.9', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9fy00naqhd9mwbgccfj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Jaki charakter miała literatura średniowieczna?', '{"options": ["rozrywkowy", "dydaktyczno-moralizatorski", "satyryczny", "liryczny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Literatura średniowieczna miała przede wszystkim charakter dydaktyczny i moralizatorski - służyła pouczaniu."}', '2025-10-24 22:16:53.902', '2025-10-24 22:16:53.902', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9g000nbqhd98z0ykdi2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co to jest pareneza?', '{"options": ["gatunek literacki", "styl architektoniczny", "tendencja do tworzenia wzorców do naśladowania", "nurt filozoficzny"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Pareneza (gr. zachęcanie) to tendencja w literaturze do tworzenia wzorców postępowania i pouczania."}', '2025-10-24 22:16:53.904', '2025-10-24 22:16:53.904', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9g200ncqhd9yet8icv3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Dlaczego większość dzieł średniowiecznych była anonimowa?', '{"options": ["ze strachu przed prześladowaniami", "z powodu analfabetyzmu", "tworzono Ad maiorem Dei gloriam - ku większej chwale Boga", "nie było systemu praw autorskich"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Dzieła były anonimowe, bo tworzono je na chwałę Bożą, nie dla ziemskiej sławy autora."}', '2025-10-24 22:16:53.906', '2025-10-24 22:16:53.906', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9g400ndqhd9svijm9gd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co to są archaizmy?', '{"options": ["nowe słowa", "słowa zapożyczone", "słowa, które wyszły z użycia", "synonimy"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Archaizmy to wyrazy, które wyszły z użycia we współczesnym języku, zachowane w starych tekstach."}', '2025-10-24 22:16:53.908', '2025-10-24 22:16:53.908', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9g600neqhd983v3cbwm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Do jakiej filozofii nawiązywał augustynizm?', '{"options": ["Arystotelesa", "Sokratesa", "Platona", "Heraklita"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Augustynizm nawiązywał do filozofii Platona, przyjmując dualistyczną wizję świata."}', '2025-10-24 22:16:53.91', '2025-10-24 22:16:53.91', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9g700nfqhd964b7s13b', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Do jakiej filozofii nawiązywał tomizm?', '{"options": ["Arystotelesa", "Platona", "Sokratesa", "Epikura"]}', '0', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Tomizm przystosował do potrzeb teologii chrześcijańskiej filozofię Arystotelesa."}', '2025-10-24 22:16:53.912', '2025-10-24 22:16:53.912', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9g900ngqhd9mw5oomji', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Jaki był podstawowy element konstrukcyjny budowli romańskich?', '{"options": ["łuk ostrołukowy", "kolumna koryncka", "łuk półkolisty", "kopuła"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Podstawowym elementem konstrukcyjnym architektury romańskiej był łuk półkolisty."}', '2025-10-24 22:16:53.914', '2025-10-24 22:16:53.914', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9gc00nhqhd9gukjfmqk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Jaki typ łuku charakteryzuje budowle gotyckie?', '{"options": ["łuk półkolisty", "łuk podkowy", "łuk ostrołukowy", "łuk pełny"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Budowle gotyckie charakteryzuje łuk ostrołukowy, który umożliwiał budowanie wyższych konstrukcji."}', '2025-10-24 22:16:53.916', '2025-10-24 22:16:53.916', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9gd00niqhd9mnuaytwp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Jak nazywali się wędrowni poeci-śpiewacy średniowiecza?', '{"options": ["bardowie i trubadurzy", "menestrelowie", "minstrele", "wszystkie odpowiedzi są poprawne"]}', '3', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Wędrownych poetów-śpiewaków nazywano różnie: trubadurami, bardami, menestrelami, minstrelami."}', '2025-10-24 22:16:53.918', '2025-10-24 22:16:53.918', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9gf00njqhd9rkboyxl9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Co głosił franciszkanizm?', '{"options": ["umartwianie ciała", "miłość do natury i wszystkich stworzeń", "przewagę duszy nad ciałem", "ascezę i pustelnictwo"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Franciszkanizm głosił miłość do przyrody, świata i wszystkich zwierząt oraz życie w ubóstwie bez umartwiania."}', '2025-10-24 22:16:53.92', '2025-10-24 22:16:53.92', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9gh00nkqhd9fx0gg422', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Co według augustynizmu było najważniejsze w człowieku?', '{"options": ["rozum", "dusza", "ciało", "uczucia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Augustynizm głosił przewagę duszy nad rozumem i ciałem - dusza była najważniejszym elementem ludzkiej natury."}', '2025-10-24 22:16:53.922', '2025-10-24 22:16:53.922', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9gk00nlqhd9cbj71yvg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Jak tomizm pojmował człowieka?', '{"options": ["jako istotę tylko duchową", "jako istotę tylko cielesną", "jako połączenie duszy i ciała", "jako istotę tragiczną"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Tomizm uważał, że człowiek stanowi harmonijne połączenie duszy i ciała - oba pochodzą od Boga."}', '2025-10-24 22:16:53.924', '2025-10-24 22:16:53.924', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9gm00nmqhd9706o9uzv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co to jest apokryf?', '{"options": ["tekst o losach świętych niekanoniczny", "kronika historyczna", "pieśń religijna", "dramat moralizatorski"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Apokryf to tekst o tematyce religijnej lub świętych, który nie został uznany przez Kościół za kanoniczny."}', '2025-10-24 22:16:53.926', '2025-10-24 22:16:53.926', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9go00nnqhd93ff73f8r', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co oznacza łacińskie wyrażenie ''ars moriendi''?', '{"options": ["sztuka życia", "sztuka umierania", "sztuka walki", "sztuka miłości"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Ars moriendi to ''sztuka umierania'' - zbiór zasad dotyczących właściwego, chrześcijańskiego umierania."}', '2025-10-24 22:16:53.928', '2025-10-24 22:16:53.928', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ex009mqh49g1cqdy4o', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 2, 'Dopasuj teoretyka do kluczowego pojęcia jego interpretacji ''Króla Edypa''.', '{"leftColumn": [{"id": "A", "text": "Arystoteles"}, {"id": "B", "text": "Freud"}, {"id": "C", "text": "Nietzsche"}, {"id": "D", "text": "Girard"}], "rightColumn": [{"id": "1", "text": "kompleks Edypa"}, {"id": "2", "text": "katharsis i hamartia"}, {"id": "3", "text": "kozioł ofiarny (pharmakos)"}, {"id": "4", "text": "dionizyjskość i transgresja"}], "matchingType": "theorist_concept"}', '[[0, 1], [1, 0], [2, 3], [3, 2]]', NULL, '{teoretycy,pojęcia,dopasowanie}', '{"explanation": "Arystoteles - katharsis/hamartia; Freud - kompleks Edypa; Nietzsche - dionizyjskość; Girard - kozioł ofiarny."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ey009nqh49l9tmy6kq', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Zinterpretuj scenę konfrontacji Edypa z Tyrezjaszem jako konflikt dwóch typów wiedzy: ludzkiej (racjonalnej) i boskiej (profetycznej).', '{"requirements": ["Charakterystyka epistemologii Edypa (rozum, śledztwo)", "Charakterystyka wiedzy Tyrezjasza (objawienie, profetyzm)", "Analiza konfliktu i jego rozstrzygnięcia"]}', NULL, NULL, '{Tyrezjasz,epistemologia,"konflikt wiedzy"}', '{"sampleAnswer": "Edyp uosabia rozum ludzki - empiryczny, śledczy, pewny siebie. Tyrezjasz reprezentuje wiedzę boską - irracjonalną z ludzkiej perspektywy, ale absolutną. Edyp odrzuca rewelacje wróżbity jako spisek, bo nie pasują do jego racjonalnego obrazu. Konflikt rozstrzyga się na korzyść wiedzy profetycznej - rozum Edypa okazuje się ślepy, podczas gdy ''ślepy'' Tyrezjasz znał prawdę od początku."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ey009oqh49kc4r38jv', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Przeanalizuj problem teodycei w ''Królu Edypie'': czy bogowie są sprawiedliwi, karząc nieświadomego Edypa?', '{"requirements": ["Przedstawienie problemu: kara za nieświadome czyny", "Różne interpretacje: bogowie sprawiedliwi vs obojętni vs okrutni", "Własna refleksja na temat rozwiązania problemu"]}', NULL, NULL, '{teodyceja,"sprawiedliwość bogów",nieświadomość}', '{"sampleAnswer": "Tragedia stawia problem teodycei: czy bogowie są sprawiedliwi, karząc nieświadomego Edypa? Interpretacje różnią się: jedni widzą porządek kosmiczny (skalanie wymaga oczyszczenia niezależnie od intencji), inni obojętność bogów (los jest ślepy), jeszcze inni okrucieństwo. Sofokles nie rozstrzyga problemu - tragedia pokazuje absurd ludzkiej kondycji, gdzie niewinność nie chroni przed cierpieniem."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9gq00noqhd94zllmvw0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Jaki typ wiersza dominował w średniowieczu?', '{"options": ["sylabiczny", "sylabotonicznyintonacyjno-zdaniowy", "intonacyjno-zdaniowy", "toniczny"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "W średniowieczu dominował wiersz intonacyjno-zdaniowy (składniowo-rymowy), w którym jedno zdanie = jeden wers."}', '2025-10-24 22:16:53.93', '2025-10-24 22:16:53.93', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9gs00npqhd9cvvcfum0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Kiedy w Polsce rozpoczyna się epoka średniowiecza?', '{"options": ["w X wieku - 966 r.", "w V wieku", "w XI wieku", "w IX wieku"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "W Polsce średniowiecze rozpoczyna się w drugiej połowie X wieku, umownie w 966 roku - chrzest Polski."}', '2025-10-24 22:16:53.932', '2025-10-24 22:16:53.932', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9gu00nqqhd9eexjqeod', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Co to jest psychomachia?', '{"options": ["teoria psychologiczna", "walka dobra ze złem o duszę przed śmiercią", "gatunek literacki", "nurt filozoficzny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Psychomachia to motyw walki aniołów i demonów o duszę człowieka tuż przed śmiercią."}', '2025-10-24 22:16:53.934', '2025-10-24 22:16:53.934', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ey009pqh4959p5bz27', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Porównaj interpretację Freuda i Nietzschego: jak każdy z nich rozumiał znaczenie mitu o Edypie?', '{"requirements": ["Prezentacja interpretacji Freuda (kompleks Edypa)", "Prezentacja interpretacji Nietzschego (dionizyjskość)", "Wskazanie fundamentalnych różnic w podejściu"]}', NULL, NULL, '{Freud,Nietzsche,"porównanie interpretacji"}', '{"sampleAnswer": "Freud widział w micie uniwersalny wzorzec nieświadomych pragnień: dziecko pragnie rodzica przeciwnej płci i rywalizuje z rodzicem tej samej płci. Nietzsche interpretował Edypa jako wcielenie dionizyjskiej mądrości - wiedzy zdobytej przez transgresję i cierpienie, przełamanie apollińskiego ładu. Różnica fundamentalna: Freud psychologizuje mit (struktura psychiki), Nietzsche ontologizuje go (natura bytu i poznania)."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ey009qqh490k3h56po', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Wyjaśnij pojęcie ''pharmakos'' (kozła ofiarnego) i jego znaczenie dla rozumienia losu Edypa w kontekście teorii Girarda.', '{"requirements": ["Definicja pharmakos w religii greckiej", "Mechanizm kozła ofiarnego według Girarda", "Aplikacja do sytuacji Edypa"]}', NULL, NULL, '{pharmakos,Girard,"kozioł ofiarny"}', '{"sampleAnswer": "Pharmakos to rytualna figura kozła ofiarnego - osoby wydalanej ze wspólnoty, by zabrać skalanie. Girard widział w tym mechanizm rozładowania przemocy społecznej: wspólnota w kryzysie (zaraza) projektuje winę na jednostkę, której wygnanie przywraca porządek. Edyp doskonale pasuje do schematu: jest obcy (przybyły z Koryntu), wzniesiony wysoko (król), a potem strącony. Mit maskuje przemoc zbiorową jako sprawiedliwą karę."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ey009rqh49j2nfls1g', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Jak rozumieć transformację Edypa z króla-zbawcy w herosa kultowego w świetle greckiej religii?', '{"requirements": ["Pojęcie herosa w religii greckiej", "Związek cierpienia z heroizacją", "Znaczenie ''Edypa w Kolonie'' dla tej interpretacji"]}', NULL, NULL, '{heros,heroizacja,"religia grecka"}', '{"sampleAnswer": "W religii greckiej heros to postać, która przez transgresję i cierpienie osiąga szczególny status - staje się potęgą chroniącą lub niszczącą po śmierci. Edyp przechodzi transformację: z króla-zbawcy przez skazonego wygnańca do herosa kultowego (w ''Edypie w Kolonie'' chroni Ateny). Paradoks: wielkość osiąga się przez katastrofę, cierpienie jest drogą do transcendencji. Oślepiony wygnaniec jest bliższy boskości niż potężny król."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ey009sqh49dfddy6gj', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Zinterpretuj ''Króla Edypa'' jako dramat o granicach ludzkiego poznania, odnosząc się do motywu zagadki Sfinksa.', '{"requirements": ["Paradoks: Edyp rozwiązał zagadkę o człowieku, ale nie poznał siebie", "Krytyka racjonalizmu zawarta w dramacie", "Epistemologiczne przesłanie tragedii"]}', NULL, NULL, '{epistemologia,Sfinks,samopoznanie}', '{"sampleAnswer": "Paradoks centralny: Edyp odpowiedział na abstrakcyjne pytanie o naturę człowieka (''co chodzi na czterech, dwóch, trzech nogach?''), ale nie rozpoznał własnej tożsamości. Dramat jest krytyką racjonalistycznej hybris - wiary w nieograniczoną moc poznania. Możemy poznać ogólne prawdy, ale nie możemy wznieść się ponad własną ślepotę na temat siebie. Intelekt nie gwarantuje samopoznania - to tragiczne przesłanie epistemologiczne."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ey009tqh493b10a5sg', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Przeanalizuj funkcję ironii tragicznej jako narzędzia filozoficznego, nie tylko dramaturgicznego.', '{"requirements": ["Ironia jako technika budowania napięcia", "Ironia jako komentarz o ludzkiej kondycji", "Przykłady z dramatu ilustrujące oba wymiary"]}', NULL, NULL, '{"ironia tragiczna",filozofia,"kondycja ludzka"}', '{"sampleAnswer": "Ironia tragiczna to nie tylko technika dramaturgiczna, ale narzędzie filozoficzne. Buduje napięcie (widz wie, że Edyp przeklina siebie), ale też komentuje kondycję ludzką: pokazuje przepaść między tym, co człowiek wie o sobie, a tym, kim naprawdę jest. Gdy Edyp szydzi ze ''ślepoty'' Tyrezjasza, ironia odsłania uniwersalną prawdę: wszyscy możemy być ślepi na prawdę o sobie. Ironia staje się figurą ludzkiej nieświadomości egzystencjalnej."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ey009uqh49dnbp4xcw', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Jak egzystencjalizm (Camus, Sartre) reinterpretował postać Edypa wobec problemu absurdu i wolności?', '{"requirements": ["Pojęcie absurdu i buntu w egzystencjalizmie", "Edyp jako model stawienia czoła absurdowi", "Kwestia wolności w zdeterminowanym świecie"]}', NULL, NULL, '{egzystencjalizm,absurd,wolność}', '{"sampleAnswer": "Dla egzystencjalistów Edyp jest wzorem stawienia czoła absurdowi - sytuacji, gdzie niewinność nie chroni przed cierpieniem. Camus widział w nim heroiczny bunt: nie przez ucieczkę czy samobójstwo, ale przez godne przyjęcie losu i odpowiedzialności. Mimo determinizmu (fatum) Edyp zachowuje wolność w sposobie reakcji - wybiera jak żyć po katastrofie. To wolność ''drugiego stopnia'': nie możemy wybierać losu, ale możemy wybierać postawę wobec niego."}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ey009vqh49s0ee41tm', 'ESSAY', 'WRITING', 'ANTIQUITY', 5, 15, 'Porównaj interpretację ''Króla Edypa'' u Arystotelesa z interpretacją jednego wybranego teoretyka XX wieku (Freud, Nietzsche, Girard lub inny). Jakie aspekty dramatu uwypukla każda z tych lektur i co pomija?', '{"wordLimit": {"max": 600, "min": 400}, "requirements": ["Rzetelna prezentacja interpretacji arystotelesowskiej", "Rzetelna prezentacja wybranej interpretacji nowożytnej", "Porównanie: co każda lektura eksponuje, co pomija", "Własna ocena użyteczności obu podejść", "Synteza: co różne interpretacje mówią o bogactwie tekstu"]}', NULL, NULL, '{Arystoteles,interpretacja,porównanie,hermeneutyka}', '{"rubric": {"ocena": "Własna refleksja krytyczna (3 pkt)", "kompozycja": "Struktura, argumentacja, język (2 pkt)", "nowożytna": "Rzetelna prezentacja interpretacji nowożytnej (3 pkt)", "arystoteles": "Rzetelna prezentacja interpretacji arystotelesowskiej (3 pkt)", "porównanie": "Wnikliwe porównanie obu podejść (4 pkt)"}}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ez009wqh49r4mn8gya', 'ESSAY', 'WRITING', 'ANTIQUITY', 5, 15, 'Czy cierpienie Edypa ma sens? Rozważ problem teodycei i sprawiedliwości losu w ''Królu Edypie'', odwołując się do różnych interpretacji filozoficznych (grecka koncepcja ate, egzystencjalizm, inne).', '{"wordLimit": {"max": 600, "min": 400}, "requirements": ["Precyzyjne wprowadzenie problemu teodycei", "Analiza ''winy'' i ''kary'' Edypa w różnych perspektywach", "Prezentacja min. 2 różnych stanowisk filozoficznych", "Własne stanowisko z uzasadnieniem", "Odniesienie do uniwersalnego wymiaru problemu"]}', NULL, NULL, '{teodyceja,cierpienie,sens,filozofia}', '{"rubric": {"analiza": "Wnikliwa analiza winy i kary (4 pkt)", "problem": "Precyzyjne wprowadzenie problemu (3 pkt)", "kompozycja": "Struktura, argumentacja, język (2 pkt)", "stanowisko": "Własna, uzasadniona refleksja (2 pkt)", "interpretacje": "Rzetelna prezentacja różnych stanowisk (4 pkt)"}}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ez009xqh49nmp3qr5g', 'ESSAY', 'WRITING', 'ANTIQUITY', 5, 15, 'Zinterpretuj ''Króla Edypa'' jako dramat o granicach ludzkiego poznania. Jak Sofokles przedstawia konflikt między pragnieniem wiedzy a ograniczeniami ludzkiego rozumu?', '{"wordLimit": {"max": 600, "min": 400}, "requirements": ["Wprowadzenie problematyki epistemologicznej", "Analiza Edypa jako symbolu racjonalnego poznania", "Interpretacja klęski rozumu (Sfinks vs. samopoznanie)", "Rola Tyrezjasza jako kontrastu epistemologicznego", "Filozoficzne wnioski o kondycji ludzkiej"]}', NULL, NULL, '{epistemologia,poznanie,rozum,"granice wiedzy"}', '{"rubric": {"analiza": "Wnikliwa analiza motywów epistemologicznych (5 pkt)", "kompozycja": "Struktura, argumentacja, język (2 pkt)", "problematyka": "Precyzyjne wprowadzenie problematyki (3 pkt)", "interpretacja": "Głęboka interpretacja filozoficzna (5 pkt)"}}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmk56s4ez009yqh49vfvyadea', 'ESSAY', 'WRITING', 'ANTIQUITY', 5, 15, 'Przeanalizuj ''Króla Edypa'' w świetle teorii kozła ofiarnego René Girarda. Jak mit edypalny funkcjonuje jako mechanizm rozładowania przemocy społecznej?', '{"wordLimit": {"max": 600, "min": 400}, "requirements": ["Prezentacja teorii mimetycznej Girarda", "Analiza Edypa jako pharmakos (kozła ofiarnego)", "Funkcja zarazy jako kryzysu społecznego", "Mechanizm projekcji winy i wygnania", "Krytyczna ocena interpretacji girardowskiej"]}', NULL, NULL, '{Girard,"kozioł ofiarny",przemoc,"teoria mimetyczna"}', '{"rubric": {"teoria": "Rzetelna prezentacja teorii Girarda (3 pkt)", "analiza": "Wnikliwa aplikacja do tekstu (5 pkt)", "krytyka": "Krytyczna ocena interpretacji (4 pkt)", "kompozycja": "Struktura, argumentacja, język (3 pkt)"}}', '2026-01-08 08:29:37.496', '2026-01-08 08:29:37.496', 'Król Edyp');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npuf0000qhk4kt9v7qjd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Kto jest autorką powieści „Nad Niemnem”?', '{"options": ["Maria Konopnicka", "Eliza Orzeszkowa", "Bolesław Prus", "Henryk Sienkiewicz"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "„Nad Niemnem” to powieść Elizy Orzeszkowej, opublikowana w 1888 roku. Jest uważana za jedno z najważniejszych dzieł polskiego pozytywizmu."}', '2026-03-17 21:03:38.391', '2026-03-17 21:03:38.391', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npup0001qhk4tp9eq6h6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Nad jaką rzeką rozgrywa się akcja powieści „Nad Niemnem”?', '{"options": ["Nad Wisłą", "Nad Bugiem", "Nad Niemnem", "Nad Dnieprem"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Akcja powieści rozgrywa się nad rzeką Niemen, na terenach dawnej Litwy (dzisiejsza Białoruś, okolice Grodna). Niemen jest nie tylko tłem, ale i ważnym symbolem w utworze."}', '2026-03-17 21:03:38.401', '2026-03-17 21:03:38.401', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npus0002qhk4dz24nmmy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Kim jest Justyna Orzelska w powieści „Nad Niemnem”?', '{"options": ["Żoną Benedykta Korczyńskiego", "Ubogą krewną Korczyńskich, mieszkającą w Korczynie", "Córką Andrzeja Korczyńskiego", "Służącą w dworze korczyńskim"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Justyna Orzelska jest cioteczną siostrzenicą Benedykta Korczyńskiego. Po śmierci matki i utracie majątku przez ojca zamieszkała w Korczynie jako uboga krewna."}', '2026-03-17 21:03:38.404', '2026-03-17 21:03:38.404', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npuu0003qhk4p8ds8rk9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Kto jest właścicielem dworu w Korczynie?', '{"options": ["Andrzej Korczyński", "Teofil Różyc", "Benedykt Korczyński", "Ignacy Orzelski"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Korczyn jest odziedziczonym po ojcu majątkiem Benedykta Korczyńskiego, najmłodszego z trzech braci. Benedykt ciężko pracuje, by utrzymać majątek w dobie popowstaniowych trudności."}', '2026-03-17 21:03:38.407', '2026-03-17 21:03:38.407', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npuw0004qhk4vmv15zpd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Kto opowiada legendę o Janie i Cecylii?', '{"options": ["Benedykt Korczyński", "Stary Jakub Bohatyrowicz", "Anzelm Bohatyrowicz", "Jan Bohatyrowicz"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Legendę o Janie i Cecylii, protoplastach rodu Bohatyrowiczów, opowiada Anzelm Bohatyrowicz — stryj Jana, przy grobowcu przodków w parowie nadniemeńskim."}', '2026-03-17 21:03:38.409', '2026-03-17 21:03:38.409', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npuz0005qhk4loo4ran6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Jaką funkcję pełni Marta Korczyńska w dworze korczyńskim?', '{"options": ["Jest żoną Benedykta", "Jest nauczycielką dzieci", "Prowadzi dom i gospodarstwo domowe", "Jest guwernantką Leoni"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Marta Korczyńska, kuzynka Benedykta, prowadzi cały dom — nadzoruje kuchnię, przygotowuje posiłki, dba o porządek i zapasy. Jest niezastąpiona w codziennym funkcjonowaniu Korczyna."}', '2026-03-17 21:03:38.411', '2026-03-17 21:03:38.411', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npv10006qhk4priq7o8r', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Które z poniższych postaci mieszkają w dworze korczyńskim?', '{"options": ["Benedykt Korczyński", "Marta Korczyńska", "Teofil Różyc", "Ignacy Orzelski"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,positivism,batch-2025-01}', '{"explanation": "W Korczynie mieszkają: Benedykt (właściciel), jego żona Emilia, Marta (kuzynka prowadząca dom), Justyna i jej ojciec Ignacy Orzelski (ubodzy krewni) oraz Teresa Plińska (towarzyszka Emilii). Różyc jest sąsiadem z Wołowszczyzny."}', '2026-03-17 21:03:38.414', '2026-03-17 21:03:38.414', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npv40007qhk4se4o1j78', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Które cechy charakteryzują Martę Korczyńską?', '{"options": ["Pracowitość i zaradność", "Szorstki, basowy głos i częsty kaszel", "Delikatność i słabe zdrowie", "Noszenie kwiecistych pantofli"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Marta jest pracowita, zaradna, ma gruby, ochrypły głos i dręczy ją kaszel. Nosi charakterystyczne kwieciste pantofle. To Emilia Korczyńska, nie Marta, cechuje się delikatnością i słabym zdrowiem."}', '2026-03-17 21:03:38.416', '2026-03-17 21:03:38.416', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npv70008qhk4297lcdsj', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Które stwierdzenia o Emilii Korczyńskiej są prawdziwe?', '{"options": ["Cierpi na liczne dolegliwości nerwowe", "Spędza większość czasu w swoich dwóch ulubionych pokojach", "Aktywnie prowadzi gospodarstwo domowe", "Teresa Plińska jest jej towarzyszką i lektorką"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Emilia jest hipochondryczką cierpiącą na globus histericus, migreny i inne dolegliwości. Żyje zamknięta w swoich pokojach, czytając książki i robiąc robótki ręczne. Teresa jest jej wierną towarzyszką. Gospodarstwem zajmuje się Marta, nie Emilia."}', '2026-03-17 21:03:38.419', '2026-03-17 21:03:38.419', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npv90009qhk4fxgocjmq', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Jak nazywa się zaścianek szlachecki sąsiadujący z Korczynem, zamieszkały przez drobną szlachtę?', '{}', '"Bohatyrowicze"', NULL, '{historical_literary,short_answer,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Bohatyrowicze to okolica (zaścianek) szlachecki nad Niemnem, sąsiadujący z dworem korczyńskim. Mieszka tam kilkadziesiąt rodzin drobnej szlachty, w tym rodzina Jana i Anzelma Bohatyrowiczów."}', '2026-03-17 21:03:38.422', '2026-03-17 21:03:38.422', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npvc000aqhk4k03nhcmn', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kim jest Teofil Różyc?', '{"options": ["Ubogim szlachcicem z okolicy", "Zamożnym arystokratą, kuzynem Kirłowej, nowym sąsiadem Korczyńskich", "Bratem Benedykta Korczyńskiego", "Ekonomem w majątku korczyńskim"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Teofil Różyc to zamożny arystokrata, krewny żony Kirły, który niedawno osiadł w pobliskiej Wołowszczyźnie. Jest człowiekiem światowym, zrujnowanym przez rozrzutne życie i uzależnionym od morfiny."}', '2026-03-17 21:03:38.424', '2026-03-17 21:03:38.424', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npve000bqhk4xcyg3zzp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Co stało się z Andrzejem Korczyńskim, najstarszym bratem Benedykta?', '{"options": ["Wyjechał za granicę i nie wrócił", "Zginął w powstaniu styczniowym wraz z Jerzym Bohatyrowiczem", "Zmarł na chorobę w Korczynie", "Został zesłany na Syberię"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Andrzej Korczyński zginął w powstaniu styczniowym 1863 roku razem ze swoim przyjacielem Jerzym Bohatyrowiczem (ojcem Jana). Miejsce ich śmierci — las za Niemnem — nazwano potem Mogiłą."}', '2026-03-17 21:03:38.426', '2026-03-17 21:03:38.426', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npvh000cqhk4mi5l03uv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Czym zajmuje się Jan Bohatyrowicz?', '{"options": ["Jest urzędnikiem w miasteczku", "Pracuje jako ekonom u Korczyńskich", "Jest rolnikiem — sam orze, zbiera plony i prowadzi gospodarstwo", "Handluje drewnem na Niemnie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Jan Bohatyrowicz jest rolnikiem, który sam uprawia ziemię — orze, zbiera plony, prowadzi pasiekę i sad. Mówi, że wyoranie morga ziemi to dla niego „tak jak prawie na spacer pójść”."}', '2026-03-17 21:03:38.429', '2026-03-17 21:03:38.429', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npvj000dqhk4ca2gar0t', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Na jakim instrumencie gra Ignacy Orzelski?', '{"options": ["Na fortepianie", "Na skrzypcach", "Na gitarze", "Na flecie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Ignacy Orzelski jest utalentowanym skrzypkiem, który graniu poświęca prawie cały swój czas. Podczas gry przemienia się — z dobrodusznego starca staje się natchnionym artystą. Justyna akompaniuje mu na fortepianie."}', '2026-03-17 21:03:38.432', '2026-03-17 21:03:38.432', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npvl000eqhk40jcnggt7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Jaki był wcześniejszy związek uczuciowy Justyny Orzelskiej?', '{"options": ["Była zakochana w Różycu, który ją porzucił", "Była zakochana w Janie Bohatyrowiczu od dzieciństwa", "Kochała Zygmunta Korczyńskiego, ale rodzina nie dopuściła do małżeństwa", "Nigdy wcześniej nikogo nie kochała"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Justyna od młodości kochała swojego kuzyna Zygmunta Korczyńskiego. Ich związek trwał lata, ale rodzina (szczególnie matka Zygmunta, pani Andrzejowa, i ciotka Darzecka) nie dopuściła do małżeństwa, uważając Justynę za niegodną partię."}', '2026-03-17 21:03:38.434', '2026-03-17 21:03:38.434', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npvo000fqhk4aq3lnx69', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Które pary przedstawiają motyw miłości w powieści?', '{"options": ["Jan Bohatyrowicz i Justyna Orzelska", "Anzelm Bohatyrowicz i Marta Korczyńska", "Benedykt Korczyński i Teresa Plińska", "Witold Korczyński i Marynia Kirlanka"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Orzeszkowa przedstawia kilka modeli miłości: dojrzałą miłość Jana i Justyny, niespełnioną — Anzelma i Marty, młodzieńczą przyjaźń/miłość — Witolda i Maryni. Benedykt i Teresa nie łączy żaden wątek uczuciowy."}', '2026-03-17 21:03:38.436', '2026-03-17 21:03:38.436', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npvr000gqhk4tmx8ae2c', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Z jakimi problemami zmaga się Benedykt Korczyński?', '{"options": ["Długi bankowe i hipoteczne obciążające Korczyn", "Ciągłe procesy sądowe z sąsiadami o ziemię", "Brak porozumienia z żoną Emilią", "Alkoholizm i hazard"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Benedykt boryka się z długami (bankowe raty, posag siostry, posag żony), procesami o ziemię z Bohatyrowiczami i innymi sąsiadami oraz nieszczęśliwym małżeństwem z Emilią, która nie rozumie jego trosk i zarzuca mu prozaiczność."}', '2026-03-17 21:03:38.439', '2026-03-17 21:03:38.439', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npvt000hqhk4trx82alu', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Które fakty dotyczące rodu Bohatyrowiczów są prawdziwe?', '{"options": ["Nazwa rodu pochodzi od bohaterskiej pracy ich przodków", "Szlachectwo nadał im król Zygmunt August", "Protoplastami rodu byli Jan i Cecylia", "Rod ten zawsze był bardzo bogaty"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Według legendy opowiedzianej przez Anzelma, Jan i Cecylia wykarczowali puszczę nad Niemnem. Król Zygmunt August nadał ich potomkom szlachectwo i nazwisko Bohatyrowiczów (od bohaterstwa w pracy). Rod nigdy nie był bogaty — żyli jako drobna szlachta."}', '2026-03-17 21:03:38.441', '2026-03-17 21:03:38.441', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npvw000iqhk47sxjre22', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Jakie nazwisko nadał król Zygmunt August potomkom Jana i Cecylii i od czego je wywodził?', '{}', '"Bohatyrowicze — od bohaterstwa w pracy"', NULL, '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Król Zygmunt August, ujrzawszy dokonania Jana i Cecylii, nobilitował ich ród i nadał mu nazwisko Bohatyrowiczów — wywiedzione od bohaterstwa (bohatyrstwa), jakim było wykarczowanie puszczy i stworzenie kwitnącej osady."}', '2026-03-17 21:03:38.444', '2026-03-17 21:03:38.444', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npvy000jqhk4rhvc8ufd', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Jak nazywa się miejsce w lesie za Niemnem, które po śmierci Andrzeja Korczyńskiego zmieniło swoją dotychczasową nazwę?', '{}', '"Mogiła (wcześniej zwane Świerkowym)"', NULL, '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Uroczysko leśne za Niemnem, wcześniej zwane Świerkowym (od sosen i jodeł), po śmierci Andrzeja Korczyńskiego i Jerzego Bohatyrowicza zaczęto powszechnie nazywać Mogiłą. Nowa nazwa stała się jedynym „grobowcem” najstarszego z braci Korczyńskich."}', '2026-03-17 21:03:38.447', '2026-03-17 21:03:38.447', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npw0000kqhk4tynssn2p', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Co co roku Orzeszkowa mówi o Justynie, przyrównując ją do postaci antycznej, kiedy ta prowadzi ojca przez salon?', '{}', '"Antygonę"', NULL, '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Gdy Justyna z podniesioną głową prowadzi przez salon swojego siwowłosego, przygarbionego ojca (upokorzonego przez Kirłę), narrator porównuje ją do Antygony — symbolu godności i miłości do ojca."}', '2026-03-17 21:03:38.449', '2026-03-17 21:03:38.449', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npw3000lqhk48nwbb91a', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Dlaczego Marta Korczyńska odrzuciła Anzelma Bohatyrowicza?', '{"options": ["Nie kochała go i wolała innego mężczyznę", "Rodzina zabroniła jej tego małżeństwa pod groźbą wydziedziczenia", "Bała się ludzkiego śmiechu i ciężkiej pracy fizycznej", "Anzelm był już wówczas ciężko chory i niezdolny do pracy"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Marta wyznaje Justynie, że dwie przyczyny sprawiły, że odrzuciła Anzelma: strach przed wyśmianiem przez rodzinę i znajomych oraz lęk przed ciężką fizyczną pracą, jaką musiałaby wykonywać jako żona drobnego szlachcica. Przyznaje, że było to jej „wieczne głupstwo”."}', '2026-03-17 21:03:38.451', '2026-03-17 21:03:38.451', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npw5000mqhk4i30abixt', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Co studiuje Witold Korczyński?', '{"options": ["Prawo na uniwersytecie", "Sztuki piękne w Monachium", "Agronomię (gospodarstwo rolne)", "Medycynę w Petersburgu"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Witold jest uczniem szkoły agronomicznej. Odziedziczył po ojcu zamiłowanie do ziemi i gospodarstwa wiejskiego. Reprezentuje ideały młodego pokolenia pozytywistów — chce modernizować rolnictwo i podnosić poziom życia ludu."}', '2026-03-17 21:03:38.453', '2026-03-17 21:03:38.453', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npwa000nqhk4b62hloha', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Jaka jest główna przyczyna nieszczęścia Emilii Korczyńskiej?', '{"options": ["Bieda i niedostatek materialny w Korczynie", "Zdrada męża z inną kobietą", "Poczucie osamotnienia, brak wrażeń i niezrozumienie ze strony męża", "Tęsknota za zmarłymi bliskimi"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Emilia cierpi na pustkę egzystencjalną — brak wrażeń, piękna, poezji w życiu. Nie rozumie się z mężem, który poświęca się pracy gospodarskiej. Skarży się na „pustynię” życia w Korczynie. Benedykt zarzuca jej, że jej skargi to „przestarzała i złej wody romansowość”."}', '2026-03-17 21:03:38.458', '2026-03-17 21:03:38.458', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npwc000oqhk4lg8tx4u1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Co robi Justyna Orzelska z listem i tomem wierszy Musseta, które przesłał jej Zygmunt Korczyński?', '{"options": ["Przeczytała list, wzruszyła się i napisała odpowiedź", "Schowała list i książkę jako pamiątkę dawnej miłości", "Przeczytała list, ale rozdarła go na drobne kawałki", "Oddała list Marcie, prosząc ją o radę"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Justyna przeczytała list Zygmunta i wzruszyła się wspomnieniami, ale ostatecznie rozdarła kartkę na drobne płatki i rozrzuciła za oknem. Symbolizuje to jej definitywne odcięcie się od przeszłości i dawnej miłości."}', '2026-03-17 21:03:38.46', '2026-03-17 21:03:38.46', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npwe000pqhk4wo45i3iz', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Które motywy literackie są obecne w powieści „Nad Niemnem”?', '{"options": ["Motyw pracy jako wartości nadającej sens życiu", "Motyw powstania styczniowego ukryty przed cenzurą", "Motyw natury jako tła i zwierciadła uczuć bohaterów", "Motyw pojedynku rycerskiego"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-3,positivism,batch-2025-01}', '{"explanation": "W „Nad Niemnem” kluczowe są: motyw pracy (wzorcowa praca Jana, Marty, Benedykta), motyw powstania styczniowego (ukryty pod mową ezopową — nigdy nie nazwanego wprost), motyw natury (rozbudowane opisy przyrody nadniemeńskiej). Nie ma motywu pojedynku rycerskiego."}', '2026-03-17 21:03:38.463', '2026-03-17 21:03:38.463', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npwg000qqhk4m52j5opq', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Które stwierdzenia o legendzie Jana i Cecylii są prawdziwe?', '{"options": ["Pełni funkcję mitu założycielskiego rodu Bohatyrowiczów", "Gloryfikuje pracę jako źródło szlachectwa i godności", "Jest historią spisaną w kronikach i drukowaną w książkach", "Przekazywana była ustnie z pokolenia na pokolenie"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Legenda o Janie i Cecylii jest mitem założycielskim Bohatyrowiczów. Gloryfikuje pracę — to bohaterstwo pracy (nie miecza) dało im szlachectwo. Jak zaznacza Anzelm, „nikt jej nie opisywał i w książkach nie drukował” — przekazywano ją ustnie."}', '2026-03-17 21:03:38.465', '2026-03-17 21:03:38.465', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npwj000rqhk458q4chng', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Które postacie reprezentują pozytywne wartości według Orzeszkowej?', '{"options": ["Jan Bohatyrowicz — pracowity rolnik", "Marta Korczyńska — oddana pracy gospodyni", "Zygmunt Korczyński — utalentowany artysta", "Witold Korczyński — student z ideałami społecznymi"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Orzeszkowa wartościuje postacie według stosunku do pracy, narodu i ludzi. Jan, Marta i Witold realizują pozytywne ideały. Zygmunt jest postacią negatywną — rozpieszczony, nie pracuje, nie umie kochać, okazuje pogardę wobec otoczenia."}', '2026-03-17 21:03:38.468', '2026-03-17 21:03:38.468', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npwl000sqhk41h4ifdin', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Jakie znaczenie symboliczne ma legenda o Janie i Cecylii w strukturze powieści?', '{}', '"Jest mitem założycielskim rodu Bohatyrowiczów i wzorcem etycznym — gloryfikuje pracę, miłość i równość jako źródła szlachectwa"', NULL, '{historical_literary,short_answer,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Legenda pełni kilka funkcji: jest mitem fundacyjnym rodu Bohatyrowiczów, wzorcem idealnej miłości opartej na wspólnej pracy, ideowym programem autorki (praca, nie urodzenie, jest źródłem godności) oraz zapowiedzią losów Justyny i Jana, którzy powielą model Jana i Cecylii."}', '2026-03-17 21:03:38.47', '2026-03-17 21:03:38.47', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npwn000tqhk4a4b1to77', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Jak lekarze nazywają chorobę Anzelma Bohatyrowicza i ile lat trwała?', '{}', '"Hipokondria (choroba bardziej duszna niż cielesna); trwała dziewięć lat"', NULL, '{historical_literary,short_answer,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Lekarze nazwali chorobę Anzelma „hipokondrią” — chorobą „więcej duszną niżeli cielesną”. Przez dziewięć lat był bezwładny i pogrążony w bólach. Źródłem były traumatyczne przeżycia — śmierć brata w powstaniu i odrzucenie przez Martę."}', '2026-03-17 21:03:38.472', '2026-03-17 21:03:38.472', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npwp000uqhk4gxtjtga9', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Dlaczego Kirłowa odmawia propozycji Różyca, by jej mąż zarządzał Wołowszczyzną?', '{}', '"Bo wie, że mąż nie nadaje się do takiej pracy — nie lubi pracować i nie podołałby zarządzaniu, co zaszkodziłoby majątkom Różyca"', NULL, '{historical_literary,short_answer,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Kirłowa, mimo że propozycja byłaby dla jej rodziny wielkim szczęściem, odmawia z uczciwości — wie, że Bolesław Kirło nie lubi pracować, nie ma doświadczenia w zarządzaniu i nie podołałby. Nie chce szkodzić krewnemu. Ta scena pokazuje jej szlachetność i prawdomówność."}', '2026-03-17 21:03:38.474', '2026-03-17 21:03:38.474', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npws000vqhk4o7q3o0so', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Porównaj małżeństwo Benedykta i Emilii Korczyńskich z legendą o Janie i Cecylii. Wskaż najważniejsze różnice i wnioski, jakie płyną z tego zestawienia.', '{}', '"Małżeństwo Korczyńskich to antymodel wobec legendy: Jan i Cecylia łączyła wspólna praca i wzajemne wsparcie, Benedykt i Emilia żyją w dwóch osobnych światach — on pogrążony w pracy, ona w marzeniach o pięknie i wrażeniach. Legenda pokazuje, że szczęście wymaga wspólnego celu i równego udziału w trudach życia."', NULL, '{historical_literary,synthesis_note,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Jan i Cecylia stanowią idealny model miłości opartej na wspólnej pracy, wzajemnym wsparciu i poświęceniu. Benedykt i Emilia to model przeciwny — nie rozumieją się, mają różne wartości (on: praca i obowiązek; ona: piękno, wrażenia, poezja), żyją obok siebie, nie razem. Orzeszkowa sugeruje, że przyczyną ich nieszczęścia jest brak wspólnego celu i wzajemnego zrozumienia."}', '2026-03-17 21:03:38.476', '2026-03-17 21:03:38.476', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npwv000wqhk4yjeud0qt', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 2, 'Dlaczego Benedykt nie chce sprzedać zaniemeńskiego lasu, mimo że to rozwiązałoby jego problemy finansowe?', '{"options": ["Las przynosi mu ogromne dochody z drewna", "W lesie tym znajduje się mogiła jego brata Andrzeja", "Prawo zabrania mu sprzedaży lasu", "Las jest własnością wspólną z Bohatyrowiczami"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Benedykt mówi Darzeckiemu szeptem, że w lesie jest „to… tamto… mogiła” — grób Andrzeja i powstańców. Dodaje, że patrząc na nią „zdaje mu się, że to kościół”. Sentyment ten Darzecki nazywa „sentymentalnością” — Benedykt się z nim zgadza ustami, ale sercem zachowuje to jako świętość."}', '2026-03-17 21:03:38.479', '2026-03-17 21:03:38.479', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npwx000xqhk41j76078d', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 2, 'Jaką funkcję pełni w powieści scena, w której Justyna bierze do ręki sierp i zaczyna żąć?', '{"options": ["Jest komicznym przerywnikiem fabularnym", "Symbolizuje jej przełom duchowy — odnalezienie sensu życia w pracy", "Pokazuje, że Justyna chce zaimponować Janowi swoją siłą", "Jest wyrazem jej buntu przeciwko Korczyńskim"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Moment, w którym Jan podaje Justynie sierp, a ona go przyjmuje, jest kluczowym punktem zwrotnym powieści. Symbolizuje jej przełom duchowy — odrzucenie bezczyności i odnalezienie sensu w pracy fizycznej. To realizacja pozytywistycznej idei pracy jako wartości nadającej sens życiu."}', '2026-03-17 21:03:38.481', '2026-03-17 21:03:38.481', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npwz000yqhk4dezet4zx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 2, 'Co oznacza charakterystyczny zwrot Benedykta Korczyńskiego „to… tamto… tego…”?', '{"options": ["Jest to przejaw jego niskiego wykształcenia", "Służy do zastępowania treści, o których nie może lub nie chce mówić wprost — szczególnie o powstaniu", "Jest to regionalizm gwarowy litewski", "Wyraża jego znudzenie rozmówcami"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Zwrot „to… tamto… tego…” to mowa ezopowa Benedykta — służy do omijania tematów niebezpiecznych lub bolesnych, szczególnie związanych z powstaniem styczniowym. W warunkach cenzury carskiej nie można było mówić wprost o powstaniu, a ten nawyk przeszedł u Benedykta także na inne drażliwe tematy."}', '2026-03-17 21:03:38.483', '2026-03-17 21:03:38.483', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npx1000zqhk4tzcru53g', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 2, 'Jakie kryteria stosuje Orzeszkowa do moralnej oceny swoich bohaterów?', '{"options": ["Stosunek do pracy i ziemi", "Bogactwo materialne i pozycja społeczna", "Stosunek do tradycji narodowej i pamięci o powstaniu", "Sposób traktowania innych ludzi, niezależnie od ich statusu"]}', '[0, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Orzeszkowa ocenia postacie według trzech kryteriów: stosunku do pracy (Jan, Marta — pozytywne; Zygmunt, Emilia — negatywne), stosunku do tradycji narodowej i pamięci o powstaniu (Benedykt, Anzelm — szanują; Darzecki — odrzuca jako „sentymentalność”) oraz traktowania ludzi (Jan szanuje każdego; Darzecki pogardza uboższymi)."}', '2026-03-17 21:03:38.486', '2026-03-17 21:03:38.486', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npx40010qhk4m9z6c6vr', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 2, 'Jakie analogie łączą „Nad Niemnem” z „Panem Tadeuszem” Mickiewicza?', '{"options": ["Rozbudowane opisy przyrody jako tło dla akcji", "Wątek miłosny kończący waśń dwóch rodów", "Akcja rozgrywająca się na Litwie", "Główny bohater jest poetą romantycznym"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Analogie z „Panem Tadeuszem”: rozbudowane opisy przyrody litewskiej, wątek miłosny kończący waśń rodów (Justyna-Jan = Zosia-Tadeusz), litewska sceneria. Różnicą jest krytyczne spojrzenie Orzeszkowej na szlachtę, podczas gdy Mickiewicz ją idealizował."}', '2026-03-17 21:03:38.488', '2026-03-17 21:03:38.488', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npx60011qhk4pgq7ujaw', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 3, 'Jaką rolę odgrywa mogiła powstańcza w fabule i symbolice powieści?', '{}', '"Jest sacrum — ukrytym grobem powstańców styczniowych, miejscem pamięci łączącym dwór z zaściankiem. Symbolizuje wspólną przeszłość i wartości, które powinny jednoczyć podzielone społeczeństwo."', NULL, '{historical_literary,short_answer,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Mogiła jest zbiorowym grobem czterdziestu poległych powstańców, w tym Andrzeja Korczyńskiego i Jerzego Bohatyrowicza. Ukryta w borze, nieoznaczona, zapominana przez świat — symbolizuje wypartą pamięć o powstaniu. Łączy dwór (Korczyńscy) z zaściankiem (Bohatyrowicze) wspólną ofiarą krwi. Scena wizyty Justyny na Mogile jest momentem jej duchowego przebudzenia."}', '2026-03-17 21:03:38.49', '2026-03-17 21:03:38.49', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npx90012qhk4tcbnt3se', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 3, 'W jaki sposób Orzeszkowa nawiązuje do powstania styczniowego, mimo że nigdy nie nazywa go wprost?', '{}', '"Stosuje mowę ezopową: niedokończone zdania Benedykta (\"to… tamto…\"), nieoznaczoną mogiłę w lesie, wspomnienia Anzelma o \"stukach i grzmotach\" zza rzeki, zmianę nazwy lasu na „Mogiłę”, żałobę Andrzejowej, sieroctwo Zygmunta."', NULL, '{historical_literary,short_answer,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Ze względu na cenzurę carską Orzeszkowa nigdy nie używa słowa „powstanie”. Stosuje technikę mowy ezopowej: Benedykt mówi „to… tamto…”, Anzelm opowiada o odgłosach bitwy jako „stukach i grzmotach”, las zmienia nazwę na „Mogiłę”, Andrzejowa nosi wieczną żałobę, a Korczyńscy mówią o przeżyciach niedomówieniami i gestami."}', '2026-03-17 21:03:38.494', '2026-03-17 21:03:38.494', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npxb0013qhk47caz1zo0', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 3, 'Kim jest Witold Korczyński jako postać ideowa i jaką rolę pełni w powieści?', '{}', '"Jest porte-parole (głosem) autorki — przedstawicielem młodego pokolenia pozytywistów. Krytykuje próżniactwo wyższych sfer, domaga się pracy u podstaw, oświaty i solidarności z ludem. Łączy ideały narodowe z programem społecznym."', NULL, '{historical_literary,short_answer,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Witold jest studentem agronomii, który chce modernizować wieś i pomagać chłopom. Krytykuje Darzeckiego za snobizm, Zygmunta za bezczyność, nawet ojca za nadskakiwanie bogatemu szwagrowi. Doradza chłopom kopanie studni, budowę młyna. Anzelm widzi w nim „latorośl” — nadzieję na odrodzenie ideałów, które zginęły z powstańcami."}', '2026-03-17 21:03:38.496', '2026-03-17 21:03:38.496', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npxe0014qhk4ug1ep4ge', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Przeanalizuj konflikt między Benedyktem a Witoldem Korczyńskim. Jakie są jego przyczyny, przebieg i znaczenie dla wymowy powieści?', '{}', '"Konflikt wynika z różnicy pokoleń i doświadczeń: Benedykt, złamany przez życie, stał się pragmatyczny i pokorny wobec bogatszych; Witold, idealistyczny student, krytykuje ojca za nadskakiwanie Darzeckiemu i zaniedbanie siostry. Obaj są porywczy i dumni — kłócą się gwałtownie, ale łączy ich miłość do ziemi. Konflikt symbolizuje napięcie między rezygnacją starego pokolenia a ideałami młodego. Benedykt nazywa syna „powracającą falą” — rozpoznaje w nim dawne ideały, z których sam zrezygnował."', NULL, '{historical_literary,synthesis_note,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Kłótnia ojca z synem po wizycie Darzeckiego to kluczowa scena ukazująca napięcie pokoleniowe. Witold zarzuca ojcu pokorę wobec snobistycznego szwagra i wychowywanie Leoni na „salonową lalkę”. Benedykt czuje się urażony, ale w głębi dostrzega prawdę w słowach syna. Ich konflikt ma znaczenie ogólniejsze — symbolizuje pytanie o to, jak żyć godnie w trudnych czasach: przez pragmatyczny kompromis (Benedykt) czy bezkompromisowy idealizm (Witold)."}', '2026-03-17 21:03:38.499', '2026-03-17 21:03:38.499', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npxg0015qhk4nq7xdl4j', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Porównaj dwie miłości Justyny Orzelskiej — do Zygmunta Korczyńskiego i do Jana Bohatyrowicza. Czym się różnią i co mówią o ewolucji bohaterki?', '{}', '"Miłość do Zygmunta była romantyczna, oparta na poezji i marzeniach, ale zakończyła się rozczarowaniem i upokorzeniem — ujawniła przepaść stanową. Miłość do Jana rodzi się ze wspólnoty wartości: szacunku dla pracy, natury i tradycji. Ewolucja od Zygmunta do Jana to przemiana Justyny z biernej, cierpiącej „królewny” w kobietę świadomie wybierającą własną drogę opartą na pracy i prawdziwym partnerstwie."', NULL, '{historical_literary,synthesis_note,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Związek z Zygmuntem — to model miłości romantycznej: czytanie Musseta, poetyczne wyznania, ale też egoizm i fałsz (Zygmunt chce jej „duszy”, nie oferując nic poza słowami). Związek z Janem — to model pozytywistyczny: rodzi się z wspólnych przeżyć (spacery, praca, legenda o przodkach), opiera się na wzajemnym szacunku i wspólnym celu. Rozdarcie listu Zygmunta i przyjęcie sierpa od Jana to symboliczne momenty tej przemiany."}', '2026-03-17 21:03:38.501', '2026-03-17 21:03:38.501', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npxj0016qhk44ly3ok07', 'ESSAY', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 5, 'Czy praca jest wartością, która nadaje sens życiu bohaterów „Nad Niemnem”? Odpowiedz, odwołując się do losów wybranych postaci.', '{}', '"W pracy należy odwołać się do: legendy Jana i Cecylii (praca = źródło szlachectwa), Jana Bohatyrowicza (praca jako naturalny sposób życia), Marty (praca mimo osobistych nieszczęść), Benedykta (praca jako obowiązek wobec rodziny), Justyny (odnalezienie sensu w żniwach), Emilii (bezczyność = choroba i nieszczęście). Praca w powieści jest wartością naczelną — ci, którzy pracują, są szczęśliwsi i moralniejsi."', NULL, '{historical_literary,essay,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Praca jest centralną wartością powieści. Orzeszkowa pokazuje ją przez kontrast: pracowici (Jan, Marta, Benedykt, Kirłowa) żyją godnie i mają cel, bezczynni (Emilia, Zygmunt, Różyc) cierpią na nudę i pustkę. Legenda Jana i Cecylii ustanawia pracę jako fundament szlachectwa. Scena żniw, w której Justyna bierze sierp, jest momentem jej duchowego odrodzenia. Praca w „Nad Niemnem” to nie tylko zarabianie na chleb — to sposób na zachowanie godności i więzi z ziemią ojczystą."}', '2026-03-17 21:03:38.503', '2026-03-17 21:03:38.503', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npxn0017qhk4f8gnqxna', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 3, 'Jaką technikę literacką stosuje Orzeszkowa, przedstawiając powstanie styczniowe w warunkach cenzury carskiej?', '{"options": ["Alegorię — powstanie przedstawione jest jako bajka o zwierzętach", "Mowę ezopową — powstanie jest obecne, ale nigdy nie nazwane wprost, sugerowane niedopowiedzeniami i symbolami", "Parabola — powstanie jest opisane jako przypowieść biblijna", "Groteska — powstanie jest wyśmiane i zdegradowane"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,positivism,batch-2025-01}', '{"explanation": "Orzeszkowa stosuje mowę ezopową (język aluzji i niedomówień). Powstanie nie jest nigdy nazwane — obecne jest poprzez: zmianę nazwy lasu na „Mogiłę”, żałobę Andrzejowej, opowieść Anzelma o „stukach i grzmotach”, frazę Benedykta „to… tamto…”, ukrytą zbiorową mogiłę w borze. Ta technika pozwoliła obejść cenzurę i jednocześnie uczynić powstanie centralnym doświadczeniem bohaterów."}', '2026-03-17 21:03:38.508', '2026-03-17 21:03:38.508', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npxq0018qhk40g0ctuw7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 3, 'Z jakim gatunkiem literackim badacze porównują „Nad Niemnem” i dlaczego?', '{"options": ["Z powieścią gotycką — z powodu mrocznej atmosfery i tajemnic", "Z eposem szlacheckim — ze względu na panoramę społeczną, rozbudowane opisy przyrody i mitologizację przeszłości", "Z dramatem naturalistycznym — z powodu biologicznego determinizmu postaci", "Z powieścią epistolarną — z powodu licznych listów wymienianych przez bohaterów"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,positivism,batch-2025-01}', '{"explanation": "„Nad Niemnem” porównywane jest z eposem szlacheckim (jak „Pan Tadeusz”): ma szeroką panoramę społeczną, rozbudowane opisy przyrody, mitologizację przeszłości (legenda Jana i Cecylii), wątek miłosny kończący waśń rodów i podniosły ton w scenach kluczowych (mogiła, parów). Orzeszkowa jednak, w odróżnieniu od Mickiewicza, krytycznie ocenia szlachtę."}', '2026-03-17 21:03:38.51', '2026-03-17 21:03:38.51', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npxs0019qhk4ub05jwb1', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 3, 'Które stwierdzenia o ideowym przesłaniu powieści „Nad Niemnem” są trafne?', '{"options": ["Praca na ziemi jest formą patriotyzmu i zachowania polskości", "Podziały stanowe są sztuczne — szlachectwo ducha ważniejsze od herbu", "Pamięć o powstaniu powinna motywować do walki zbrojnej", "Solidarność społeczna między stanami jest warunkiem przetrwania narodu"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-5,positivism,batch-2025-01}', '{"explanation": "Orzeszkowa głosi: praca na roli to forma patriotyzmu (utrzymanie ziemi w polskich rękach), podziały stanowe należy przezwyciężać (małżeństwo Justyny z Janem), solidarność społeczna jest konieczna (Witold jako głos autorki). Nie wzywa jednak do walki zbrojnej — po klęsce powstania proponuje pracę organiczną jako drogę do odrodzenia."}', '2026-03-17 21:03:38.513', '2026-03-17 21:03:38.513', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npxv001aqhk4ctudgxan', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 4, 'Jaki typ narracji stosuje Orzeszkowa w „Nad Niemnem” i jaką funkcję pełni narrator?', '{}', '"Narracja trzecioosobowa z ograniczoną wszechwiedzą — narrator relacjonuje wydarzenia z dystansu, ale wnika w myśli i uczucia wybranych postaci (głównie Justyny i Benedykta). Zachowuje pozorny obiektywizm, ale poprzez dobór szczegółów i porównań wyraźnie wartościuje postawy bohaterów."', NULL, '{historical_literary,short_answer,difficulty-5,positivism,batch-2025-01}', '{"explanation": "Narrator „Nad Niemnem” jest trzecioosobowy, wszechwiedzący, ale selektywny — wnika w psychikę niektórych postaci (Justyna, Benedykt, Marta), inne pokazuje z zewnątrz (Kirło, Darzecki). Stosuje technikę kontrastu: zestawia pracujących z próżniakami, prawdziwą miłość z pozorną. Nie komentuje wprost, ale poprzez ironiczne opisy (np. Darzeckiego, Emilii) wyraźnie ocenia postawy bohaterów. Charakterystyczna jest też technika panoramiczna — szerokie opisy przyrody i społeczności."}', '2026-03-17 21:03:38.515', '2026-03-17 21:03:38.515', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npxx001bqhk4i045vrkz', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 4, 'W jaki sposób „Nad Niemnem” realizuje idee pozytywizmu i jednocześnie wykracza poza nie?', '{}', '"Realizuje idee pozytywizmu poprzez kult pracy organicznej, solidaryzm społeczny, emancypację (Justyna wybiera niezależność), edukację ludu (Witold). Wykracza poza nie poprzez: romantyczną wrażliwość na przyrodę, mitologizację przeszłości (legenda), liryzm scen miłosnych, ukrytą apoteozę czynu powstańczego — łączy pozytywistyczny pragmatyzm z romantycznym idealizmem."', NULL, '{historical_literary,short_answer,difficulty-5,positivism,batch-2025-01}', '{"explanation": "„Nad Niemnem” łączy pozytywizm z romantyzmem. Pozytywistyczne są: kult pracy (Jan, Marta, Kirłowa), hasło solidaryzmu między stanami (małżeństwo Justyny i Jana), postulat edukacji (Witold), krytyka próżniactwa (Zygmunt, Emilia). Romantyczne natomiast: rozbudowane opisy przyrody, poetyzacja przeszłości (legenda, mogiła), liryzm uczuć, ukryty kult bohaterstwa powstańczego. Orzeszkowa nie odrzuca romantyzmu — przenosi go z polityki do pracy i codziennego bohaterstwa."}', '2026-03-17 21:03:38.518', '2026-03-17 21:03:38.518', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npy0001cqhk4evc7fhrf', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 5, 'Przeanalizuj symbolikę przestrzeni w „Nad Niemnem”. Jaką rolę odgrywają: dwór korczyński, zaścianek Bohatyrowiczów, parów z grobowcem Jana i Cecylii, mogiła powstańcza oraz piaski nadniemeńskie?', '{}', '"Dwór = zamknięcie, stagnacja, pozory (duszny pokój Emilii vs. przestrzeń salonu). Zaścianek = autentyczność, praca, życie (otwarte ogrody, sad Anzelma). Parów z grobowcem = sacrum tradycji, mit założycielski, wieczność. Mogiła powstańcza = sacrum patriotyczne, samotna i zapomniana ofiara. Piaski = przestrzeń przejścia, liminalność — tu Jan widział ojca po raz ostatni, tu przebiega granica między życiem a śmiercią, historią a teraźniejszością. Justyna, przemieszczając się między tymi przestrzeniami, dokonuje duchowej transformacji."', NULL, '{historical_literary,synthesis_note,difficulty-5,positivism,batch-2025-01}', '{"explanation": "Przestrzeń w „Nad Niemnem” jest ściśle symboliczna. Dwór Korczyńskich z dusznym buduarem Emilii symbolizuje zamknięcie i stagnację; zaścianek z sadami i ogrodami — naturalność i pracę. Dwa grobowce — legendowy i powstańczy — tworzą sacrum powieści: łączą mityczną przeszłość z historyczną ofiarą. Piaski nadniemeńskie to przestrzeń progowa — miejsce ostatniego pożegnania Jana z ojcem, ale i droga do mogiły. Ruch Justyny z dworu do zaścianka, przez parów do mogiły, jest wędrówką inicjacyjną: od pustki do sensu, od izolacji do wspólnoty."}', '2026-03-17 21:03:38.52', '2026-03-17 21:03:38.52', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npy4001dqhk4l163o7fk', 'ESSAY', 'WRITING', 'POSITIVISM', 5, 10, '„Nad Niemnem” Elizy Orzeszkowej nazywane jest „pozytywistycznym eposem narodowym”. Uzasadnij lub podważ tę tezę, odwołując się do treści i formy powieści oraz porównując ją z „Panem Tadeuszem”Adama Mickiewicza.', '{}', '"Wypracowanie powinno zawierać: cechy eposu w powieści (panorama społeczna, mit założycielski — legenda, podniosły ton kluczowych scen, opisy przyrody, wątek miłosny kończący waśń rodów), analogie z „Panem Tadeuszem” (Litwa, przyroda, dwa zwaśnione rody, miłość jako pojednanie), różnice (krytycyzm Orzeszkowej wobec szlachty, pozytywistyczny kult pracy zamiast romantycznego czynu zbrojnego, ukryty wątek powstania), wniosek — powieść łączy cechy eposu z powieścią realistyczną, co czyni ją unikalnym gatunkowo dziełem."', NULL, '{writing,essay,difficulty-5,positivism,batch-2025-01}', '{"explanation": "„Nad Niemnem” łączy cechy eposu (szerokie ujęcie społeczne, legenda pełniąca funkcję mitu, podniosłość tonu, opisy przyrody, wątek waśni rodów rozwiązanej przez miłość) z powieścią realistyczną (psychologia postaci, krytyka społeczna, problemy ekonomiczne). Analogie z „Panem Tadeuszem”: Litwa, przyroda, dwa rody, miłość młodych = pojednanie. Różnice: Orzeszkowa krytykuje szlachtę (Darzecki, Zygmunt), gloryfikuje pracę zamiast czynu zbrojnego, powstanie jest tematem ukrytym (mowa ezopowa). Teza o „eposie” jest uzasadniona formą, ale treść jest wyraźnie pozytywistyczna — stąd oxymoron „pozytywistyczny epos”."}', '2026-03-17 21:03:38.525', '2026-03-17 21:03:38.525', 'Nad Niemnem');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npy7001eqhk4isb6ztjl', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 4, 'Napisz notatkę syntetyczną na podany temat:', '{"topic": "Tomasz Judym jako bohater tragiczny — analiza konfliktu między szczęściem osobistym a imperatywem moralnym", "wordLimit": {"max": 200, "min": 150}, "requirements": ["Wyjaśnij, na czym polega tragizm Judyma", "Odwołaj się do sceny rozstania z Joasią", "Porównaj Judyma z innym bohaterem tragicznym (np. Antygona, Konrad)", "Oceń decyzję Judyma — czy była słuszna?", "150-200 słów"]}', '"Notatka powinna: zdefiniować tragizm jako konflikt między dwoma pozytywnymi wartościami; pokazać, że Judym rezygnuje z miłości nie z pogardy dla niej, lecz z przekonania, że dom i rodzina „zabiją” w nim zapał do walki z nędzą; porównać go z Antygona (obie postacie kierują się imperatywem moralnym kosztem osobistego szczęścia); przedstawić otwartość interpretacji — czy Judym postąpił słusznie, czy był nazbyt radykalny."', NULL, '{historical_literary,synthesis_note,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Tragizm Judyma jest centralnym problemem interpretacyjnym powieści. Podobnie jak Antygona staje przed wyborem między prawem boskim a ludzkim, Judym musi wybrać między miłością a obowiązkiem wobec biedoty. Kluczowe jest, że żaden z tych wyborów nie jest zły — to właśnie czyni sytuację tragiczną. Scena z rozdartą sosną symbolizuje cenę, jaką Judym płaci za swoją decyzję."}', '2026-03-17 21:03:38.528', '2026-03-17 21:03:38.528', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npyb001fqhk4jiswc3om', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 3, 'Jak można interpretować postać Tomasza Judyma w kontekście Nietzscheańskiej koncepcji nadczłowieka?', '{"options": ["Judym jest klasycznym nadczłowiekiem — gardzi moralnością stada i narzuca światu własną wolę", "Judym łączy cechy nadczłowieka (samotność, odrzucenie konwencji, wola mocy) z chrześcijańskim imperatywem służby — jest „nadczłowiekiem na opak”", "Judym całkowicie odrzuca filozofię Nietzschego i realizuje wyłącznie etykę chrześcijańską", "Judym nie ma nic wspólnego z nadczłowiekiem — jest po prostu idealistycznym lekarzem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Judym wykazuje cechy nadczłowieka: samotność, odrzucenie opinii tłumu, heroiczną wolę. Jednak zamiast dążyć do władzy — poświęca się dla najsłabszych. Żeromski tworzy syntezę nietzscheanizmu i etyki społecznej, co badacze nazywają „nadczłowiekiem na opak” lub „prometeizmem społecznym”."}', '2026-03-17 21:03:38.531', '2026-03-17 21:03:38.531', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npye001gqhk40qcz0454', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 3, 'Która z interpretacji epizodycznej postaci Korzeckiego najlepiej oddaje jej funkcję w strukturze powieści?', '{"options": ["Korzecki to komiczna postać, wprowadzona dla odprężenia fabularnego", "Korzecki to sobowtór Judyma — ucieleśnia wariant losu, w którym wrażliwość bez czynu prowadzi do autodestrukcji", "Korzecki reprezentuje pokolenie pozytywistów rozczarowanych niepowodzeniem pracy organicznej", "Korzecki symbolizuje wyłącznie kryzys wiary religijnej w epoce modernizmu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Korzecki jest lustrzanym odbiciem Judyma: obaj są wrażliwi, samotni i cierpią na widok niesprawiedliwości. Różnica polega na tym, że Judym sublimuje cierpienie w czyn społeczny, a Korzecki — pozbawiony tej drogi — popada w nihilizm i samobójstwo. Jego śmierć jest ostrzeżeniem dla Judyma i czytelnika."}', '2026-03-17 21:03:38.535', '2026-03-17 21:03:38.535', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npyh001hqhk4m89efqbh', 'CLOSED_SINGLE', 'LANGUAGE_USE', 'YOUNG_POLAND', 5, 3, 'Który fragment najlepiej ilustruje technikę mowy pozornie zależnej (erlebte Rede) w powieści?', '{"options": ["— Ojciec mój był szewcem, a w dodatku lichym szewcem na Ciepłej ulicy — powiedział Judym.", "Szedł przed siebie ciemną ulicą. Cóż to za miasto! Wszędzie błoto, ciemność, zapach gnijących odpadków. Precz stąd!", "Doktor Czernisz uśmiechnął się i powiedział: — To bardzo ciekawe, panie kolego.", "Joanna napisała w dzienniku: „Jestem sama na świecie”."]}', '1', NULL, '{language_use,closed_single,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Mowa pozornie zależna łączy perspektywę narratora z głosem bohatera bez cudzysłowu i czasownika mówienia. Fragment B: narrator relacjonuje („Szedł”), ale wykrzyknienia „Cóż to za miasto!” i „Precz stąd!” to myśli Judyma przełożone na narrację trzecioosobową. A — dialog, C — mowa zależna, D — cytat z dziennika."}', '2026-03-17 21:03:38.537', '2026-03-17 21:03:38.537', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npyk001iqhk4v179p748', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 3, 'Które z poniższych kontekstów interpretacyjnych są uzasadnione przy analizie „Ludzi bezdomnych”?', '{"options": ["Kontekst marksistowski — walka klas, wyzysk robotników, krytyka kapitalizmu", "Kontekst egzystencjalny — samotność jednostki, absurd cierpienia, wolność wyboru", "Kontekst postkolonialny — Polska jako kraj skolonizowany, emigracja jako wygnanie", "Kontekst feministyczny — dziennik Joanny jako głos kobiecy, krytyka patriarchalnych ograniczeń"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Kontekst marksistowski: Żeromski opisuje wyzysk robotników, nędzę proletariatu, konflikt między klasami. Egzystencjalny: samotność Judyma, Korzeckiego, pytanie o sens cierpienia. Feministyczny: dziennik Joanny porusza kwestie niezależności kobiet, pracy, samotności guwernantki. Kontekst postkolonialny jest możliwy, ale najmniej uzasadniony — Żeromski nie tematyzuje bezpośrednio relacji kolonialnych."}', '2026-03-17 21:03:38.54', '2026-03-17 21:03:38.54', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npyn001jqhk47ei7enuh', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 3, 'Które elementy świadczą o tym, że „Ludzie bezdomni” są powieścią modernistyczną, a nie pozytywistyczną?', '{"options": ["Luźna, epizodyczna kompozycja zamiast linearnej fabuły", "Obecność narratora wszechwiedzącego z wyraźną tezą ideową", "Psychizacja pejzażu i liryzacja prozy", "Subiektywizm narracji — wewnętrzny monolog, mowa pozornie zależna, dziennik"]}', '[0, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Cechy modernistyczne: luźna kompozycja (brak ciągłej akcji, epizodyczność), psychizacja pejzażu (przyroda odzwierciedla psychikę), subiektywizm (mowa pozornie zależna, dziennik Joanny). Narrator wszechwiedzący z tezą to cecha pozytywistyczna — Żeromski odchodzi od niej na rzecz wielogłosowości."}', '2026-03-17 21:03:38.543', '2026-03-17 21:03:38.543', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npyp001kqhk4b1f66crx', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 3, 'Czy Tomasz Judym ponosi winę tragiczną? Uzasadnij odpowiedź, odwołując się do koncepcji hamartii Arystotelesa.', '{"instruction": "Odwołaj się do definicji hamartii (błędu tragicznego) i przeanalizuj, czy decyzja Judyma o rozstaniu z Joasią jest błędem, wyborem, czy koniecznością."}', '"Hamartia to błąd tragiczny — nie grzech moralny, lecz pomyłka w ocenie sytuacji. Judym nie popełnia klasycznej hamartii, bo jego decyzja jest świadoma i przemyślana. Można jednak argumentować, że jego hamartia to hybris — pycha społecznika, który uważa, że sam musi zbawić świat. Alternatywna interpretacja: Judym nie ma winy — jest ofiarą systemu, który stawia go przed niemożliwym wyborem. Tragizm polega na tym, że nawet słuszna decyzja niesie cierpienie."', NULL, '{historical_literary,short_answer,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "To pytanie wymaga znajomości poetyki Arystotelesa i umiejętności zastosowania jej do powieści XIX-wiecznej. Kluczowe jest rozróżnienie między winą moralną a błędem tragicznym oraz argumentacja, czy Judym jest sprawcą, czy ofiarą swojego losu."}', '2026-03-17 21:03:38.545', '2026-03-17 21:03:38.545', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npyr001lqhk4vjuslkh8', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 3, 'Porównaj obraz nędzy w „Ludziach bezdomnych” Żeromskiego z obrazem nędzy na Powiślu w „Lalce” Prusa. Wskaż podobieństwa i różnice.', '{"instruction": "Uwzględnij techniki literackie, intencję autorską i wymowę ideową obu opisów."}', '"Podobieństwa: obaj autorzy stosują naturalistyczny opis warunków życia biedoty — sutereny, brud, choroby, wyzysk. Obaj krytykują obojętność wyższych warstw. Różnice: Prus opisuje nędzę z perspektywy zewnętrznego obserwatora (Wokulski na Powiślu), zachowując dystans realisty. Żeromski angażuje się emocjonalnie — stosuje liryzację, psychizację pejzażu, mowę pozornie zależną, by czytelnik przeżył nędzę „od wewnątrz”. U Prusa nędza jest argumentem w dyskusji o pracy organicznej; u Żeromskiego — wezwaniem do radykalnego czynu."', NULL, '{historical_literary,short_answer,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "To typowe pytanie maturalne na poziomie rozszerzonym — wymaga porównania dwóch lektur, znajomości technik literackich i umiejętności syntezy."}', '2026-03-17 21:03:38.548', '2026-03-17 21:03:38.548', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npyu001mqhk4opl6d1zk', 'SHORT_ANSWER', 'LANGUAGE_USE', 'YOUNG_POLAND', 5, 3, 'Przeanalizuj funkcję zmiany narratora w powieści „Ludzie bezdomni”. Dlaczego Żeromski wprowadza rozdział „Zwierzenia” w formie dziennika?', '{}', '"Zmiana z narracji trzecioosobowej na dziennik pierwszoosobowy pełni kilka funkcji: 1) Polifoniczność — wprowadza drugi głos, równoważąc perspektywę Judyma. 2) Intymność — dziennik ujawnia myśli i uczucia, do których narrator trzecioosobowy nie ma pełnego dostępu. 3) Emancypacja Joanny — daje jej podmiotowość, czyni z niej pełnoprawną bohaterkę, nie tylko obiekt uczuć Judyma. 4) Kontrast narracyjny — zmiana formy odświeża percepcję czytelnika i podkreśla wielogłosowość powieści modernistycznej."', NULL, '{language_use,short_answer,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Pytanie wymaga rozumienia narratologii i umiejętności analizy struktury powieści. Kluczowe jest dostrzeżenie, że zmiana narratora nie jest przypadkowa, lecz służy celom ideowym i artystycznym."}', '2026-03-17 21:03:38.55', '2026-03-17 21:03:38.55', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npyw001nqhk4fpg3tn8s', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 5, 'Napisz notatkę syntetyczną na podany temat:', '{"topic": "„Ludzie bezdomni” jako powieść o klęsce idealizmu — czy Judym przegrywa?", "wordLimit": {"max": 250, "min": 200}, "requirements": ["Rozważ, czy Judym ponosi klęskę (utrata miłości, posady, samotność) czy odnosi zwycięstwo moralne", "Porównaj jego los z losem Korzeckiego — który wariant jest gorszy?", "Odwołaj się do symboliki rozdartej sosny", "Sformułuj własną ocenę — optymistyczną lub pesymistyczną interpretację zakończenia", "200-250 słów"]}', '"Notatka powinna rozważyć dwie interpretacje: pesymistyczną (Judym traci wszystko — miłość, dom, pozycję; jego walka jest syzyfowa, system się nie zmieni) i optymistyczną (Judym zachowuje integralność moralną, nie zdradza swoich ideałów, jego samotność jest ceną za autentyczność). Porównanie z Korzeckim: ten, kto nie działa, ginie; Judym przynajmniej żyje i walczy. Sosna: rozdarcie jest bolesne, ale drzewo żyje — jak Judym."', NULL, '{historical_literary,synthesis_note,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Otwartość zakończenia „Ludzi bezdomnych” to celowy zabieg Żeromskiego. Powieść nie daje jednoznacznej odpowiedzi — zmusza czytelnika do samodzielnej oceny. Na maturze ceniona jest umiejętność sformułowania własnego stanowiska z argumentacją."}', '2026-03-17 21:03:38.552', '2026-03-17 21:03:38.552', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npz0001oqhk4kjpfhorj', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 5, 'Napisz notatkę syntetyczną na podany temat:', '{"topic": "Rola kobiet w „Ludziach bezdomnych” — Joanna Podborska jako bohaterka (nie)zależna", "wordLimit": {"max": 250, "min": 200}, "requirements": ["Przedstaw sytuację życiową Joanny — pochodzenie, praca, samotność", "Przeanalizuj jej dziennik jako wyraz podmiotowości i niezależności intelektualnej", "Oceń, czy Joanna jest postacią emancypacyjną, czy wciąż zależną od mężczyzn", "Odwołaj się do kontekstu epoki — sytuacja kobiet pod koniec XIX wieku", "200-250 słów"]}', '"Notatka powinna: przedstawić Joannę jako sierotkę-guwernantkę zależną materialnie od pracodawców, ale niezależną intelektualnie (dziennik, refleksje o feminizmie, teatrze, literaturze). Wskazać napięcie: Joanna jest wykształcona i wrażliwa, ale system społeczny skazuje ją na rolę służebną. Jej dziennik to akt emancypacji — daje jej głos w powieści zdominowanej przez perspektywę Judyma. Jednak zakończenie (Joanna płacze po odejściu Judyma) pokazuje, że jej los zależy od decyzji mężczyzny. Kontekst: pod koniec XIX w. kobieta bez majątku miała ograniczone możliwości samodzielnego życia."', NULL, '{historical_literary,synthesis_note,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Analiza feministyczna „Ludzi bezdomnych” to współczesny kontekst interpretacyjny, ceniony na maturze rozszerzonej. Joanna jest jedną z najbardziej złożonych postaci kobiecych w literaturze Młodej Polski."}', '2026-03-17 21:03:38.556', '2026-03-17 21:03:38.556', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npz2001pqhk46uk2yo1g', 'ESSAY', 'WRITING', 'YOUNG_POLAND', 4, 35, 'Czy poświęcenie osobistego szczęścia dla dobra ogółu jest heroizmem, czy egoizmem? Rozważ problem, odwołując się do „Ludzi bezdomnych” Stefana Żeromskiego i innego tekstu kultury.', '{"wordLimit": {"min": 300}, "requirements": ["Sformułuj tezę — czy Judym jest bohaterem, czy egoistą (narzuca swój idealizm kosztem Joasi)?", "Odwołaj się do co najmniej dwóch scen z powieści", "Przywołaj inny tekst kultury (np. Antygona, Mały Książę, film)", "Zachowaj strukturę rozprawki: wstęp — argumenty — kontrargumenty — podsumowanie", "Minimum 300 słów"]}', '"Rozprawka powinna rozważyć dwa stanowiska: 1) Heroizm — Judym rezygnuje z własnego szczęścia, by pomagać najsłabszym; działa z imperatywu moralnego, nie z egoizmu. 2) Egoizm — Judym nie pyta Joasi o zdanie, narzuca jej swoją wizję świata; jego „poświęcenie” jest formą pychy. Oba stanowiska powinny być poparte argumentami z tekstu. Dodatkowy tekst kultury — np. Antygona (poświęcenie dla wyższych wartości kosztem życia), Mały Książę (odpowiedzialność za tych, których się oswoiło)."', NULL, '{writing,essay,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "To typowy temat rozprawki maturalnej na poziomie rozszerzonym. Kluczowa jest umiejętność dostrzeżenia ambiwalencji postawy Judyma i sformułowania własnego stanowiska z argumentacją."}', '2026-03-17 21:03:38.558', '2026-03-17 21:03:38.558', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npz5001qqhk47wexpa7g', 'ESSAY', 'WRITING', 'YOUNG_POLAND', 5, 35, 'Lekarz wobec systemu — od Judyma do współczesności. Czy postulaty Tomasza Judyma są aktualne? Rozważ, odwołując się do powieści i wybranego kontekstu współczesnego.', '{"wordLimit": {"min": 300}, "requirements": ["Przedstaw postulaty Judyma z odczytu u Czerniszów", "Odnieś je do współczesnych dyskusji o dostępie do służby zdrowia", "Rozważ, czy lekarz powinien być „aktywistą społecznym” czy wyłącznie specjalistą", "Sformułuj własną ocenę z argumentami", "Minimum 300 słów"]}', '"Rozprawka powinna: zrekonstruować postulaty Judyma (lekarze powinni walczyć z przyczynami chorób biedoty, nie tylko je leczyć), odnieść je do współczesności (nierówności w dostępie do opieki zdrowotnej, komercjalizacja medycyny, ruch lekarzy-aktywistów), rozważyć dwa stanowiska: 1) medycyna jako misja społeczna, 2) medycyna jako zawód wymagający profesjonalnego dystansu."', NULL, '{writing,essay,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Temat łączy analizę literacką z refleksją o współczesności — ceniony na maturze rozszerzonej. Wymaga umiejętności aktualizacji problematyki XIX-wiecznej powieści."}', '2026-03-17 21:03:38.561', '2026-03-17 21:03:38.561', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv3npz7001rqhk4kfjwwumg', 'ESSAY', 'WRITING', 'YOUNG_POLAND', 5, 35, 'Samotność jako cena za wierność ideałom. Rozważ problem, odwołując się do losów Tomasza Judyma i jednej innej postaci literackiej.', '{"wordLimit": {"min": 300}, "requirements": ["Zdefiniuj, czym jest samotność w kontekście powieści — wybraną czy narzuconą?", "Przeanalizuj scenę rozstania z Joasią i scenę z rozdartą sosną", "Porównaj Judyma z inną samotną postacią (np. Konrad z „Dziadów”, Raskolnikow, Antygona, Werter)", "Sformułuj wniosek — czy wierność ideałom skazuje na samotność?", "Minimum 300 słów"]}', '"Rozprawka powinna: rozróżnić samotność wybraną (Judym — świadomie odrzuca dom) i narzuconą (Joanna — sierota bez wyboru); przeanalizować motywacje Judyma (dług wobec biedoty, przekonanie, że dom „zabije” zapał); porównać z Konradem z Dziadów III (samotność prometejska, poświęcenie dla narodu) lub Raskolnikowem (samotność po przekroczeniu normy moralnej); sformułować wniosek — np. że samotność jest kosztem integralności, ale niekoniecznie jedyną drogą (kontrargument: czy nie można walczyć o sprawiedliwość i kochać jednocześnie?)."', NULL, '{writing,essay,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Motyw samotności to jeden z najczęstszych tematów maturalnych. Kluczowe jest pokazanie, że samotność Judyma nie jest prostym poświęceniem, lecz złożonym wyborem z konsekwencjami dla obu stron."}', '2026-03-17 21:03:38.564', '2026-03-17 21:03:38.564', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gsk0000qhzi7xz9tyow', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Kto jest autorem powieści „Ludzie bezdomni”?', '{"options": ["Bolesław Prus", "Stefan Żeromski", "Władysław Reymont", "Henryk Sienkiewicz"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "„Ludzie bezdomni” to powieść Stefana Żeromskiego, napisana w 1899 roku w Zakopanem. Jest jednym z najważniejszych dzieł polskiej literatury młodopolskiej."}', '2026-03-17 21:16:39.812', '2026-03-17 21:16:39.812', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gsv0001qhziryo9sb0n', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Jaki zawód wykonuje Tomasz Judym?', '{"options": ["Adwokat", "Inżynier", "Lekarz", "Nauczyciel"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Tomasz Judym jest lekarzem-chirurgiem. Ukończył medycynę w Warszawie, a następnie odbywał praktykę w klinikach paryskich w dziedzinie chirurgii."}', '2026-03-17 21:16:39.824', '2026-03-17 21:16:39.824', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gsy0002qhzib0vklvxy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Czym z zawodu zajmował się ojciec Tomasza Judyma?', '{"options": ["Był krawcem", "Był stolarzem", "Był szewcem", "Był rzeźnikiem"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Ojciec Tomasza Judyma był szewcem na ulicy Ciepłej w Warszawie. Sam Judym wyznaje to otwarcie przy pierwszym spotkaniu z panią Niewadzką w Luwrze: „Ojciec mój był szewcem, a w dodatku lichym szewcem na Ciepłej ulicy”."}', '2026-03-17 21:16:39.827', '2026-03-17 21:16:39.827', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gt10003qhzi58oalhat', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'W którym muzeum Tomasz Judym ogląda posąg Wenus z Milo?', '{"options": ["W Muzeum Orsay", "W Luwrze", "W Galerii Luksemburskiej", "W British Museum"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Judym ogląda posąg Wenus z Milo w Luwrze (Louvre) w Paryżu. Właśnie tam po raz pierwszy spotyka pannę Joannę Podborską i wnuczki pani Niewadzkiej."}', '2026-03-17 21:16:39.829', '2026-03-17 21:16:39.829', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gt30004qhzirb1d9oah', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Jak nazywa się zakład leczniczy, w którym Judym pracuje jako asystent dyrektora?', '{"options": ["Nałęczów", "Cisy", "Busko-Zdrój", "Ciechocinek"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Cisy to fikcyjny zakład leczniczy (kurort), wzorowany na Nałęczowie. Judym trafia tam jako asystent dyrektora, doktora Węglichowskiego, na zaproszenie tego ostatniego."}', '2026-03-17 21:16:39.831', '2026-03-17 21:16:39.831', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gt50005qhziy7aln2oa', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Jaki zawód wykonuje Joanna Podborska?', '{"options": ["Jest lekarką", "Jest nauczycielką i guwernantką", "Jest malarką", "Jest aktorką"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Joanna Podborska jest nauczycielką i guwernantką. Opiekuje się wnuczkami pani Niewadzkiej — pannami Natalią i Wandą Orszeńskimi. Sama utrzymuje się z dawania lekcji prywatnych."}', '2026-03-17 21:16:39.833', '2026-03-17 21:16:39.833', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gt80006qhzihmuza8vr', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'W których miastach i miejscowościach rozgrywa się akcja powieści „Ludzie bezdomni”?', '{"options": ["Paryż", "Warszawa", "Kraków", "Cisy (fikcyjny zakład leczniczy)"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Akcja „Ludzi bezdomnych” rozgrywa się w Paryżu (tom I), Warszawie (tom I), Cisach — fikcyjnym zakładzie leczniczym wzorowanym na Nałęczowie (tom I i II) oraz w Zagłębiu Dąbrowskim (tom II). Kraków nie jest miejscem akcji powieści."}', '2026-03-17 21:16:39.837', '2026-03-17 21:16:39.837', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gtb0007qhzim68m28y0', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Które z wymienionych postaci są wnuczkami pani Niewadzkiej?', '{"options": ["Joanna Podborska", "Natalia Orszeńska", "Wanda Orszeńska", "Helena Kalinowicz"]}', '[1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Wnuczkami pani Niewadzkiej są panny Natalia i Wanda Orszeńskie — sieroty, które wychowuje babka. Joanna Podborska jest ich nauczycielką i przyjaciółką, a Helena Kalinowicz to córka dyrektora kopalni."}', '2026-03-17 21:16:39.839', '2026-03-17 21:16:39.839', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gte0008qhzier2ew4uw', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Które z podanych informacji o Tomaszu Judymie są prawdziwe?', '{"options": ["Pochodzi z ubogiej rodziny rzemieślniczej", "Studiował medycynę w Paryżu od początku", "Ukończył medycynę w Warszawie", "Odbywał praktykę chirurgiczną w Paryżu"]}', '[0, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Judym pochodzi z rodziny szewca z ulicy Ciepłej w Warszawie, ukończył medycynę w Warszawie, a następnie wyjechał na praktykę chirurgiczną do Paryża. Nie studiował medycyny w Paryżu — tam jedynie pracował w klinikach."}', '2026-03-17 21:16:39.842', '2026-03-17 21:16:39.842', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gtg0009qhziaxz17ofd', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Przy okazji jakiego zdarzenia Tomasz Judym po raz pierwszy spotyka pannę Joannę Podborską i panny Orszeńskie?', '{}', '"Judym spotyka je po raz pierwszy w Luwrze w Paryżu, podczas oglądania posągu Wenus z Milo. Ustąpił im miejsca na ławeczce, a następnie zaoferował pomoc w znalezieniu drogi do rzeźby Amora i Psyche Canovy."', NULL, '{historical_literary,short_answer,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Spotkanie w Luwrze jest sceną otwierającą powieść i kluczowym momentem fabularnym. Judym rozpoznaje w przybyszkach Polki po zasłyszanej rozmowie po polsku."}', '2026-03-17 21:16:39.845', '2026-03-17 21:16:39.845', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gti000aqhzi1es2a7oa', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Co jest głównym tematem odczytu, który Tomasz Judym wygłasza w salonie doktora Czernisza?', '{"options": ["Nowe odkrycia w chirurgii", "Higiena życia najuboższych warstw i obowiązki lekarzy wobec nich", "Porównanie systemów szpitalnych Francji i Polski", "Przyczyny rozprzestrzeniania się gruźlicy w miastach"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "W swoim odczycie Judym omawia warunki higieniczne życia najuboższych, opisuje nędzę paryskich noclegowni i warszawskich suteren, a przede wszystkim zarzuca lekarzom, że są „lekarzami ludzi bogatych” i zaniedbują swoje obowiązki wobec biedoty."}', '2026-03-17 21:16:39.847', '2026-03-17 21:16:39.847', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gtk000bqhzix5s2eaia', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Kim jest doktor Chmielnicki i jaką rolę odgrywa w życiu Judyma?', '{"options": ["Jest profesorem medycyny, który recenzuje odczyt Judyma", "Jest żydowskim lekarzem, który współczuje Judymowi i pośredniczy w znalezieniu mu posady w Cisach", "Jest rywalem Judyma w staraniach o pannę Podborską", "Jest dyrektorem szpitala, w którym Judym pracuje w Warszawie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Doktor Chmielnicki to lekarz żydowskiego pochodzenia, który po nieudanym odczycie Judyma jako jedyny okazuje mu szczere współczucie. To on pośredniczy w znalezieniu Judymowi posady asystenta w Cisach u doktora Węglichowskiego."}', '2026-03-17 21:16:39.849', '2026-03-17 21:16:39.849', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gtn000cqhzidxby1484', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Co Judym postanawia zrobić w zakończeniu powieści?', '{"options": ["Wyjechać z Joasią za granicę", "Poślubić Joasię i założyć szpital w Zagłębiu", "Zerwać z Joasią i poświęcić się pracy dla biednych", "Wrócić do Cisów i pogodzić się z dyrektorem"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "W ostatnim rozdziale Judym rozstaje się z Joasią, uznając, że nie może mieć „ani ojca, ani matki, ani żony”, dopóki trwa nędza najuboższych. Zrywa z osobistym szczęściem, by poświęcić się pracy społecznej."}', '2026-03-17 21:16:39.852', '2026-03-17 21:16:39.852', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gtr000dqhzimbxdk352', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Kto wychował Tomasza Judyma i umożliwił mu zdobycie wykształcenia?', '{"options": ["Brat Wiktor i jego żona", "Ciotka, dawna kurtyzana", "Doktor Czernisz i jego żona", "Proboszcz z rodzinnej parafii"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Judyma wychowała ciotka, która — jak sam przyznaje — „niegdyś była cudną dziewczyną” i prowadziła wystawne życie. Zebrała pieniądze, wynajęła mieszkanie i wzięła małego Tomasza od rodziny, opłacając mu edukację, choć traktowała go surowo."}', '2026-03-17 21:16:39.855', '2026-03-17 21:16:39.855', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gtt000eqhzisuyw35as', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'W jaki sposób Judym traci posadę w Cisach?', '{"options": ["Zostaje zwolniony za romans z panną Natalią", "Pobija administratora Krzywosąda podczas kłótni o szlam w rzece i dyrektor rozwiązuje z nim umowę", "Sam składa rezygnację, nie mogąc znieść braku reform", "Pani Niewadzka nakazuje jego zwolnienie za naruszenie regulaminu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Judym, wściekły na zanieczyszczanie rzeki szlamem ze stawu, nazywa Krzywosąda „starym osłem”, a gdy ten podnosi pięść, chwyta go za gardziel i wrzuca do bagna. Dyrektor Węglichowski natychmiast rozwiązuje z nim umowę listem."}', '2026-03-17 21:16:39.857', '2026-03-17 21:16:39.857', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gtv000fqhzicg41mdhb', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Które dzieła sztuki pełnią funkcję symboli w powieści „Ludzie bezdomni”?', '{"leftColumn": [{"id": "A", "text": "Wenus z Milo"}, {"id": "B", "text": "„Ubogi rybak” Puvis de Chavannes''a"}, {"id": "C", "text": "Kwiat tuberozy"}, {"id": "D", "text": "Rozdarta sosna"}], "rightColumn": [{"id": "1", "text": "Piękno, miłość, harmonia"}, {"id": "2", "text": "Nędza, krzywda społeczna"}, {"id": "3", "text": "Wewnętrzne rozdarcie Judyma"}, {"id": "4", "text": "Bezużyteczne piękno (Karbowski)"}], "matchingType": "characters_to_traits"}', '[[0, 0], [1, 1], [2, 3], [3, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Wenus z Milo symbolizuje piękno i urodę życia. Obraz „Ubogi rybak” — nędzę i krzywdę społeczną. Kwiat tuberozy — bezużyteczne piękno, do którego Judym porównuje utracjusza Karbowskiego. Rozdarta sosna — wewnętrzne rozdarcie bohatera po rozstaniu z Joasią."}', '2026-03-17 21:16:39.86', '2026-03-17 21:16:39.86', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gtx000gqhzig48xtu8k', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Uzupełnij zdania, wybierając poprawne opcje:', '{"gaps": [{"id": 1, "options": ["Wiktor", "Henryk", "Wacław", "Oleś"]}, {"id": 2, "options": ["kopalni węgla", "stalowni", "hucie szkła", "drukarni"]}, {"id": 3, "options": ["czekolady", "cygar", "tkanin", "zapałek"]}], "textWithGaps": "Brat Tomasza Judyma nazywa się (1) i pracuje w (2). Żona brata Tomasza pracuje w fabryce (3)."}', '[0, 1, 1]', NULL, '{historical_literary,closed_multiple,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Brat Tomasza to Wiktor Judym, robotnik pracujący przy stalowni (gruszce Bessemera). Jego żona (Judymowa) pracuje w fabryce cygar, w okropnych warunkach — w dusznym powietrzu pełnym pyłu tytoniowego."}', '2026-03-17 21:16:39.862', '2026-03-17 21:16:39.862', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gu0000hqhziruaarw43', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Które stwierdzenia dotyczące Joanny Podborskiej są prawdziwe?', '{"options": ["Pochodzi ze zubożałej rodziny ziemiańskiej", "Prowadzi dziennik, w którym opisuje swoje przemyślenia", "Wychowała się w zamożnym domu w Warszawie", "Straciła brata Wacława, który zmarł na dalekim zesłaniu"]}', '[0, 1]', NULL, '{historical_literary,closed_multiple,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Joanna pochodzi ze zubożałej rodziny — straciła rodziców, wychowywała się w Kielcach u ciotki Ludwiki. Prowadzi dziennik (rozdział „Zwierzenia”). Nie wychowała się w zamożnym domu. Brat Wacław zmarł, ale na zesłaniu na Syberii, a nie „dalekim” — umarł prawdopodobnie podczas podróży naukowej."}', '2026-03-17 21:16:39.864', '2026-03-17 21:16:39.864', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gu2000iqhzi1zgvkmfp', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Opisz, w jakich warunkach pracowała bratowa Judyma w fabryce cygar.', '{"hints": ["duszące powietrze", "pył tytoniu", "tempo pracy"]}', '"Judymowa pracowała w fabryce cygar w okropnych warunkach. Duszące powietrze było pełne pyłu tytoniowego, który żarł gardziel i oczy. Praca odbywała się w szalonym tempie — czteroosobowe zespoły pakowały tysiąc funtów tytoniu dziennie, poświęcając na jedną paczkę zaledwie dziesięć sekund."', NULL, '{historical_literary,short_answer,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Opis fabryki cygar to jeden z naturalistycznych fragmentów powieści. Żeromski szczegółowo pokazuje wyniszczającą pracę fizyczną kobiet, eksponując biologiczne skutki takich warunków."}', '2026-03-17 21:16:39.866', '2026-03-17 21:16:39.866', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gu4000jqhzi3or9jrv1', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Kim jest M. Les (Leszczykowski) i jaką rolę odgrywa w historii zakładu w Cisach?', '{}', '"M. Les to bogaty kupiec polskiego pochodzenia, mieszkający w Konstantynopolu. Jest największym udziałowcem zakładu w Cisach, dawnym przyjacielem Niewadzkiego. Finansuje z „cichej kasy” reformy Judyma, choć sam nigdy do Cisów nie przyjechał. Jest idealistą, który marzy o ucywilizowaniu rodzinnej okolicy."', NULL, '{historical_literary,short_answer,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Leszczykowski to postać łącząca twardą praktykę kupiecką z marzycielskim idealizmem. Jego pseudonim M. Les (skrót od Leszczykowski) to jedyne, co z polskiego nazwiska mogło przetrwać w handlu turecko-angielsko-francuskim."}', '2026-03-17 21:16:39.868', '2026-03-17 21:16:39.868', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gu7000kqhzi5g1m9m62', 'SHORT_ANSWER', 'LANGUAGE_USE', 'YOUNG_POLAND', 2, 1, 'Wyjaśnij znaczenie poniższego hasła w kontekście powieści „Ludzie bezdomni”:', '{"slogan": "Lekarz dzisiejszy — to lekarz ludzi bogatych"}', '"To centralna teza odczytu Judyma. Oznacza, że lekarze jego epoki koncentrują się na leczeniu warstw zamożnych, zaniedbując higienę i zdrowie biedoty. Judym uważa, że stan lekarski powinien wziąć odpowiedzialność za warunki życia najuboższych."', NULL, '{language_use,short_answer,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Zdanie to pada podczas odczytu u Czerniszów i wywołuje skandal wśród warszawskich lekarzy. Jest to klucz do zrozumienia ideowej postawy Judyma w całej powieści."}', '2026-03-17 21:16:39.871', '2026-03-17 21:16:39.871', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gu9000lqhzi6b71utso', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Dlaczego odczyt Judyma u doktorostwa Czerniszów kończy się porażką?', '{"options": ["Judym nie przygotował się merytorycznie i popełnia błędy naukowe", "Odczyt jest zbyt radykalny — zarzuca lekarzom zaniedbywanie biedoty, a zgromadzeni nie uznają takich obowiązków za lekarskie", "Żona doktora Czernisza przerywa wystąpienie, uznając je za nudne", "Judym plagiatuje pracę innego lekarza i zostaje publicznie zdemaskowany"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Odczyt Judyma jest odrzucony, ponieważ jego postulaty — żeby lekarze walczyli z przyczynami chorób biedoty, a nie tylko je leczyli — uznano za utopijne i niestosowne. Doktor Kalecki łagodnie, a doktor Płowicz ostro krytykują jego idee jako „mrzonki”."}', '2026-03-17 21:16:39.873', '2026-03-17 21:16:39.873', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44guc000mqhzihe7k8mmw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Co symbolizuje obraz „Ubogi rybak” Puvis de Chavannes''a przywołany w powieści?', '{"options": ["Piękno i harmonię życia", "Nędzę, krzywdę społeczną i cierpienie najuboższych", "Bezużyteczne piękno arystokracji", "Tęsknotę za utraconą ojczyzną"], "sourceText": {"text": "Chudy człowiek, a właściwie nie człowiek, lecz antropoid z przedmieścia wielkiej stolicy, obrosły kłakami (...) stał znowu przed nim ze swą podrywką zanurzoną w wodę.", "title": "Ludzie bezdomni", "author": "Stefan Żeromski"}}', '1', NULL, '{historical_literary,closed_single,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "„Ubogi rybak” jest symbolem nędzy i krzywdy społecznej — stanowi kontrast wobec Wenus z Milo, symbolizującej piękno i harmonię. Obraz ten głęboko porusza Judyma i zapowiada główny konflikt powieści."}', '2026-03-17 21:16:39.876', '2026-03-17 21:16:39.876', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gue000nqhzinijfcnvu', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Z jakim problemem zdrowotnym walczy Judym w Cisach i jaką napotyka przeszkodę?', '{"options": ["Walczy z epidemią tyfusu, ale brakuje mu leków", "Walczy z malarią wywołaną wilgocią ze stawów i sadzawek, ale dyrektor i administrator nie zgadzają się na osuszenie terenu", "Walczy z gruźlicą wśród kuracjuszów, ale zakład nie ma pieniędzy na leczenie", "Walczy z ospą wśród dzieci, ale rodzice odmawiają szczepień"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Judym odkrywa, że malaria w Cisach spowodowana jest stojącą wodą w stawach i sadzawkach parkowych. Proponuje osuszenie terenu i podniesienie dna rzeki, ale napotyka opór dyrektora Węglichowskiego i administratora Krzywosąda, którzy bronią istniejących urządzeń wodnych."}', '2026-03-17 21:16:39.879', '2026-03-17 21:16:39.879', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44guh000oqhzi9i0k7j4m', 'CLOSED_SINGLE', 'LANGUAGE_USE', 'YOUNG_POLAND', 3, 2, 'Który z poniższych zabiegów stylistycznych jest charakterystyczny dla tzw. „żeromszczyzny”?', '{"options": ["Stosowanie wyłącznie krótkich, prostych zdań", "Łączenie realizmu z symbolizmem, impresjonizmem i liryzacją prozy", "Konsekwentne stosowanie narracji pierwszoosobowej", "Unikanie opisów przyrody na rzecz dialogów"]}', '1', NULL, '{language_use,closed_single,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "„Żeromszczyzna” to styl łączący różne techniki pisarskie: realizm, naturalizm, impresjonizm, symbolizm. Charakteryzuje się liryzacją prozy, psychizacją pejzażu (opisy przyrody odzwierciedlające stany ducha bohaterów) oraz emocjonalnym zaangażowaniem narratora."}', '2026-03-17 21:16:39.882', '2026-03-17 21:16:39.882', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44guk000pqhziwh0ce2cj', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Które z poniższych motywów literackich obecne są w powieści „Ludzie bezdomni”?', '{"options": ["Motyw poświęcenia osobistego szczęścia dla dobra ogółu", "Motyw bezdomności w sensie dosłownym i metaforycznym", "Motyw zemsty za doznane krzywdy", "Motyw niespełnionej miłości"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "„Ludzie bezdomni” poruszają motywy: poświęcenia (rezygnacja Judyma ze szczęścia), bezdomności (dosłownej — nędzarze; metaforycznej — Judym, Joasia, emigranci), niespełnionej miłości (Judym i Joasia). Motyw zemsty nie jest obecny w powieści."}', '2026-03-17 21:16:39.884', '2026-03-17 21:16:39.884', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gum000qqhziv2vbot48', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Które stwierdzenia o tytule powieści „Ludzie bezdomni” są trafne?', '{"options": ["Tytuł odnosi się wyłącznie do paryskich nędzarzy z noclegowni Château-Rouge", "Tytuł ma znaczenie metaforyczne — bezdomny jest też Judym, wyrzekający się domu dla idei", "Bezdomna jest Joanna Podborska — guwernantka bez własnego kąta", "Tytuł nawiązuje do biblijnego motywu wygnania z raju"]}', '[1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Tytuł ma wiele warstw znaczeniowych: bezdomni dosłownie to paryska i warszawska biedota, ale metaforycznie bezdomny jest sam Judym (świadomie wyrzekający się domu), Joasia (guwernantka bez stałego miejsca), emigranci. Tytuł nie nawiązuje bezpośrednio do biblijnego wygnania z raju."}', '2026-03-17 21:16:39.886', '2026-03-17 21:16:39.886', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44guo000rqhzirsan219r', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Połącz postacie z ich cechami lub rolami w powieści:', '{"leftColumn": [{"id": "A", "text": "Krzywosąd Chobrzański"}, {"id": "B", "text": "Doktor Węglichowski"}, {"id": "C", "text": "Karbowski"}, {"id": "D", "text": "Korzecki"}], "rightColumn": [{"id": "1", "text": "Inżynier-filozofem z nerwicą, który popełnia samobójstwo"}, {"id": "2", "text": "Dyrektor zakładu, ceniony lekarz, ale konserwatywny"}, {"id": "3", "text": "Przystojny lekkoduch i karciarz, ukochany panny Natalii"}, {"id": "4", "text": "Administrator Cisów, antykwariusz-samouk, majsterkowicz"}], "matchingType": "characters_to_traits"}', '[[0, 3], [1, 1], [2, 2], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Krzywosąd to administrator Cisów, dawny antykwariusz z Monachium, który sam naprawia wszystko w zakładzie. Węglichowski to dyrektor i lekarz, szanowany, ale niechętny reformom. Karbowski — przystojny karciarz, w którym zakochuje się Natalia Orszeńska. Korzecki — inżynier-filozof, cierpiący na pavor nocturnus, który popełnia samobójstwo."}', '2026-03-17 21:16:39.889', '2026-03-17 21:16:39.889', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gus000sqhzin1dqrnec', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Odpowiedz na pytania dotyczące rozdziału „Zwierzenia”:', '{"steps": [{"id": 1, "instruction": "Kto jest narratorką tego rozdziału?"}, {"id": 2, "instruction": "Jaką formę literacką przybiera ten rozdział?"}, {"id": 3, "instruction": "Jakie problemy i tematy porusza narratorka w swoich zapisach?"}]}', '"1) Narratorką jest Joanna Podborska. 2) Rozdział ma formę dziennika (pamiętnika) prowadzonego od października do czerwca. 3) Joanna porusza tematy: samotności guwernantki, śmierci brata Wacława, trudów pracy nauczycielskiej, feminizmu i roli kobiet, wrażeń estetycznych (teatr, literatura), tęsknoty za domem rodzinnym."', NULL, '{historical_literary,short_answer,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Rozdział „Zwierzenia” to jedyny fragment powieści pisany w pierwszej osobie (forma dziennika). Ujawnia wewnętrzny świat Joanny — jej wrażliwość, inteligencję, samotność i społeczne zaangażowanie."}', '2026-03-17 21:16:39.892', '2026-03-17 21:16:39.892', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44guu000tqhzisv3hgmom', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Jaką funkcję pełni scena w Château-Rouge w kontekście odczytu Judyma?', '{"instruction": "Wyjaśnij, czym jest Château-Rouge, co tam widział Judym i jak to doświadczenie wpłynęło na jego poglądy."}', '"Château-Rouge to paryska noclegownia dla nędzarzy, w której Judym spędził jedną dobę. Widział tam setki biedaków śpiących na podłodze, prostytutki, zbieraczy niedopałków — najniższą warstwę społeczeństwa. To doświadczenie bezpośredniego kontaktu z nędzą stało się fundamentem jego przekonań o obowiązku lekarzy wobec biedoty i materiałem do odczytu u Czerniszów."', NULL, '{historical_literary,short_answer,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Opis Château-Rouge to naturalistyczny fragment powieści, wzorowany na autentycznych materiałach, które Żeromski zbierał o paryskich noclegowniach. Stanowi argumentacyjny rdzeń odczytu Judyma."}', '2026-03-17 21:16:39.895', '2026-03-17 21:16:39.895', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gux000uqhziz90td88e', 'SHORT_ANSWER', 'LANGUAGE_USE', 'YOUNG_POLAND', 3, 2, 'Wyjaśnij, czym jest psychizacja pejzażu i podaj przykład z powieści „Ludzie bezdomni”.', '{}', '"Psychizacja pejzażu to technika narracyjna, w której opisy przyrody odzwierciedlają stan psychiczny bohatera. Przykładem jest rozdział „Smutek” — jesienny park ze spadającymi liśćmi, chłodem i ciszą oddaje wewnętrzny smutek Judyma po nieudanym odczycie. Kolejny przykład to rozdział „Przyjdź” — wiosenna przyroda z kwitnącymi krzewami wyraża radość i tęsknotę miłosną."', NULL, '{language_use,short_answer,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Psychizacja pejzażu to jeden z najcharakterystyczniejszych elementów „żeromszczyzny”. Żeromski nie tyle opisuje przyrodę, ile każe jej „mówić” uczuciami bohatera."}', '2026-03-17 21:16:39.897', '2026-03-17 21:16:39.897', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44guz000vqhzih26gyfsq', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 3, 'Napisz notatkę syntetyczną na podany temat:', '{"topic": "Znaczenie kontrastowych dzieł sztuki w „Ludziach bezdomnych” — Wenus z Milo i „Ubogi rybak”", "wordLimit": {"max": 150, "min": 100}, "requirements": ["Opisz symbolikę obu dzieł", "Wyjaśnij funkcję kontrastu między nimi", "Odnieś się do postaci Tomasza Judyma", "100-150 słów"]}', '"Notatka powinna zawierać: Wenus z Milo — symbol piękna, harmonii, miłości, świata ludzi bogatych; „Ubogi rybak” — symbol nędzy, krzywdy społecznej, cierpienia. Kontrast między nimi zapowiada główny dylemat powieści i rozdarcie Judyma między pragnieniem pięknego życia a poczuciem obowiązku wobec biedoty. Oba dzieła definiują wrażliwość bohatera — zdolnego do odczuwania zarówno zachwytu pięknem, jak i bólu na widok ludzkiego cierpienia."', NULL, '{historical_literary,synthesis_note,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Żeromski celowo umieścił oba symbole w pierwszym rozdziale, by zapowiedzieć problematykę powieści. Wrażliwość Judyma na oba bieguny rzeczywistości — piękno i nędzę — jest kluczem do zrozumienia jego tragicznego wyboru."}', '2026-03-17 21:16:39.899', '2026-03-17 21:16:39.899', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gv1000wqhziu8rl0sxz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 2, 'Jaką funkcję w strukturze powieści pełni rozdział „Zwierzenia”, będący dziennikiem Joanny Podborskiej?', '{"options": ["Służy wyłącznie jako przerywnik fabularny oddzielający dwa tomy powieści", "Ujawnia wewnętrzny świat Joanny, równoważy perspektywę Judyma i wprowadza problematykę kobiecą oraz egzystencjalną", "Jest zapisem historycznym dokumentującym realia Warszawy końca XIX wieku", "Stanowi krytykę systemu edukacji w zaborze rosyjskim"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Rozdział „Zwierzenia” zmienia perspektywę narracyjną — z trzeciej osoby na dziennik pisany przez Joannę. Ujawnia jej głębię intelektualną i emocjonalną, porusza kwestie feminizmu, samotności, śmierci, sensu pracy. Równoważy obraz Judyma, pokazując, że Joanna jest równie głębokim i złożonym bohaterem."}', '2026-03-17 21:16:39.901', '2026-03-17 21:16:39.901', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gv4000xqhzixw0erbkm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 2, 'Dlaczego decyzję Judyma o rozstaniu z Joasią można uznać za tragiczną?', '{"options": ["Ponieważ Joasia nie kocha go naprawdę i odrzuca jego oświadczyny", "Ponieważ zmusza go do niej zewnętrzna siła — dyrektor Węglichowski", "Ponieważ Judym wybiera między dwoma wartościami — miłością i powołaniem do pracy dla biednych — i każdy wybór oznacza stratę", "Ponieważ Joasia jest już zaręczona z kimś innym"]}', '2', NULL, '{historical_literary,closed_single,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Tragizm Judyma polega na konieczności wyboru między dwoma pozytywnymi wartościami: osobistym szczęściem (miłość do Joasi) a imperatywem moralnym (praca dla najuboższych). Oba dążenia są szlachetne, ale nie dają się pogodzić w jego sumieniu. To klasyczny model konfliktu tragicznego."}', '2026-03-17 21:16:39.904', '2026-03-17 21:16:39.904', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gv8000yqhziozybahtb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 2, 'Co łączy, a co różni Tomasza Judyma i Joannę Podborską jako „ludzi bezdomnych”?', '{"options": ["Oboje są bezdomni w sensie materialnym — nie mają mieszkań ani pieniędzy", "Oboje są bezdomni duchowo — pozbawieni przynależności klasowej i rodzinnego ciepła — ale Judym świadomie wybiera bezdomność, a Joasia jest nią dotknięta przez los", "Oboje świadomie odrzucają możliwość posiadania domu dla kariery zawodowej", "Joasia jest bezdomna tylko materialnie, podczas gdy Judym tylko duchowo"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Oboje są „bezdomni” — pozbawieni rodzin, korzeni, stabilności. Joasia straciła rodzinny dom jako sierota i guwernantka, tęskni za nim (Głogi, Mękarzyce). Judym natomiast świadomie odrzuca możliwość założenia domu, uznając, że dług wobec biedoty uniemożliwia mu posiadanie rodziny."}', '2026-03-17 21:16:39.908', '2026-03-17 21:16:39.908', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gva000zqhzilatka2jx', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 2, 'Które cechy powieści młodopolskiej realizuje utwór „Ludzie bezdomni”?', '{"options": ["Luźna kompozycja i wielowątkowość", "Obecność symbolizmu, impresjonizmu i naturalizmu w jednym dziele", "Konsekwentna narracja pierwszoosobowa przez całą powieść", "Liryzacja prozy i subiektywizacja świata przedstawionego"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "„Ludzie bezdomni” realizują cechy powieści młodopolskiej: luźną kompozycję (epizodyczność, brak ciągłej akcji), współistnienie różnych estetyk (symbolizm, naturalizm, impresjonizm), liryzację prozy (poetyckie opisy przyrody, psychizacja pejzażu). Narracja jest trzecioosobowa, z wyjątkiem rozdziału „Zwierzenia” (dziennik Joanny)."}', '2026-03-17 21:16:39.91', '2026-03-17 21:16:39.91', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gvc0010qhzivgf7ytr9', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 2, 'Które z poniższych interpretacji końcowej sceny z rozdartą sosną są uzasadnione?', '{"options": ["Sosna symbolizuje wewnętrzne rozdarcie Judyma — między miłością a obowiązkiem", "Sosna symbolizuje triumf Judyma nad egoizmem", "Krwawe krople żywicy nawiązują do cierpienia Judyma po utracie Joasi", "Płacz, którego Judym nie potrafi zidentyfikować, wyraża uniwersalność ludzkiego cierpienia"]}', '[0, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Rozdarta sosna to centralny symbol powieści. Jej pień rozszarpany odzwierciedla rozdarcie duszy Judyma. Krople żywicy odpowiadają jego łzom i cierpieniu. Pytanie „Kto płacze?” — Joasia, kopalnia czy sosna — wskazuje na uniwersalność bólu. Nie ma tu jednak triumfu — scena wyraża czystą agonię, nie zwycięstwo."}', '2026-03-17 21:16:39.912', '2026-03-17 21:16:39.912', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gve0011qhzien7gejr0', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 3, 'Porównaj postawę Tomasza Judyma wobec społeczeństwa z postawą środowiska lekarskiego Warszawy. Dlaczego doszło do konfliktu?', '{}', '"Judym uważa, że lekarze mają obowiązek walczyć z przyczynami chorób biedoty — likwidować sutereny, wymuszać higienę w fabrykach, zakazywać powrotu chorych do szkodliwych warunków. Środowisko lekarskie (Kalecki, Płowicz) traktuje medycynę jako fach — leczy się chorobę, nie naprawia świata. Konflikt wynika z fundamentalnej różnicy: Judym widzi w medycynie posłannictwo społeczne, inni — zawód jak każdy inny."', NULL, '{historical_literary,short_answer,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Ten konflikt jest osią ideową powieści. Odpowiedź doktora Chmielnickiego: „Medycyna — to fach” podsumowuje stanowisko oponentów. Judym stoi sam przeciwko całemu środowisku, co prefiguruje jego późniejszą samotność."}', '2026-03-17 21:16:39.915', '2026-03-17 21:16:39.915', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gvh0012qhzi5uklbx20', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 3, 'Scharakteryzuj postać inżyniera Korzeckiego i wyjaśnij, jaką funkcję pełni jego samobójstwo w powieści.', '{}', '"Korzecki to inżynier pracujący w Zagłębiu — człowiek wykształcony, wrażliwy, cierpiący na głęboką nerwicę egzystencjalną (pavor nocturnus). Próbuje zwalczyć strach przed śmiercią, filozofuje o wolności ducha. Jego samobójstwo jest aktem ostatecznego wyzwolenia — cytatem z Platona zapowiada, że Dajmonion nie stawia mu oporu. Dla Judyma śmierć Korzeckiego jest szokiem i ostrzeżeniem — pokazuje, dokąd może prowadzić absolutna samotność wrażliwego intelektualisty."', NULL, '{historical_literary,short_answer,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Korzecki to alter ego Judyma — obaj są wrażliwi na cierpienie, ale Korzecki nie znajduje drogi do czynu i ginie. Jego postać służy jako przestroga i kontrapunkt dla Judyma."}', '2026-03-17 21:16:39.917', '2026-03-17 21:16:39.917', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gvj0013qhzi8xyik1ri', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 3, 'Jak Żeromski kreśli obraz nędzy polskich miast i wsi? Podaj przynajmniej trzy przykłady z powieści.', '{}', '"1) Ulica Ciepła i Krochmalna w Warszawie — ciemne sutereny, brudne podwórza, nędza żydowskiej dzielnicy, choroba psychiczna sąsiadki trzymanej w kajdanach. 2) Fabryka cygar — kobiety pracujące w dusznym powietrzu pełnym pyłu tytoniowego, rytm pracy jak maszyny. 3) Zagłębie Dąbrowskie — „budy” robotnicze obok cynkowni, chore, wynaturzone dzieci, woda zatruta odpadami przemysłowymi. 4) Czworaki w Cisach — dzieci chore na malarię z powodu bagnistych sadzawek."', NULL, '{historical_literary,short_answer,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Żeromski stosuje technikę naturalistyczną — szczegółowe, fizjologiczne opisy warunków życia. Każde miejsce akcji staje się ilustracją tej samej tezy: nędza jest wszechobecna i systematycznie ignorowana."}', '2026-03-17 21:16:39.919', '2026-03-17 21:16:39.919', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv44gvm0014qhzi7a7t0bgj', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 4, 'Napisz notatkę syntetyczną na podany temat:', '{"topic": "Bezdomność dosłowna i metaforyczna w powieści „Ludzie bezdomni” — porównaj różne wymiary bezdomności na przykładzie wybranych postaci", "wordLimit": {"max": 200, "min": 150}, "requirements": ["Wyjaśnij dosłowny wymiar bezdomności (nędzarze, robotnicy)", "Wyjaśnij metaforyczny wymiar bezdomności (Judym, Joanna, emigranci)", "Porównaj bezdomność wybraną i narzuconą przez los", "Odwołaj się do co najmniej trzech postaci", "150-200 słów"]}', '"Notatka powinna zawierać: bezdomność dosłowna — nędzarze z Château-Rouge, robotnicy z Zagłębia, lokatorzy warszawskich suteren; bezdomność metaforyczna — Judym (świadomie wybiera samotność), Joanna (sierota, guwernantka bez stałego domu, tęskni za Głogami), Wiktor (emigrant za chlebem), Korzecki (bezdomność egzystencjalna). Kluczowy kontrast: Judym wybiera bezdomność z imperatywu moralnego, Joanna jest bezdomna z przymusu losu, nędzarze — z systemu ekonomicznego."', NULL, '{historical_literary,synthesis_note,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Wielowymiarowość tytułowego pojęcia jest kluczem do interpretacji powieści. Żeromski pokazuje, że bezdomność to nie tylko brak dachu nad głową, ale też brak przynależności, sensu, bliskości."}', '2026-03-17 21:16:39.922', '2026-03-17 21:16:39.922', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9gw00nrqhd94z94lqzg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Jaki był charakter kronik średniowiecznych?', '{"options": ["obiektywny i naukowy", "fikcyjny i rozrywkowy", "panegiryczny i dydaktyczny", "satyryczny"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Kroniki miały charakter panegiryczny (pochwalny) i dydaktyczny, często powstawały na zamówienie władców."}', '2025-10-24 22:16:53.936', '2025-10-24 22:16:53.936', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9gy00nsqhd9btorje3r', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co to jest legenda w średniowieczu?', '{"options": ["mit starożytny", "opowiadanie o świętym z elementami cudownymi", "kronika historyczna", "pieśń ludowa"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Legenda to średniowieczny gatunek opowiadający o życiu świętych, zawierający elementy fantastyczne i cudowne."}', '2025-10-24 22:16:53.938', '2025-10-24 22:16:53.938', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9h000ntqhd9zuowlalw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co to jest romans rycerski?', '{"options": ["utwór o tematyce miłosnej z elementami przygodowymi", "kronika wojenna", "pieśń o czynach", "dramat historyczny"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Romans rycerski to utwór o tematyce miłosnej, zawierający elementy przygodowe, magiczne i rycerskie."}', '2025-10-24 22:16:53.94', '2025-10-24 22:16:53.94', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9h200nuqhd9sjcmop7o', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Jaką funkcję pełniły budowle romańskie oprócz religijnej?', '{"options": ["mieszkalną", "handlową", "obronną", "gospodarczą"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Budowle romańskie pełniły podwójną funkcję: religijną i obronną - miały grube mury i małe okna."}', '2025-10-24 22:16:53.942', '2025-10-24 22:16:53.942', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9h400nvqhd9459da0w0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Co symbolizowały katedry gotyckie swoją strzelistością?', '{"options": ["potęgę władcy", "dążenie człowieka ku niebu i Bogu", "bogactwo miasta", "siłę militarną"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Strzelistość katedr gotyckich symbolizowała dążenie człowieka ku górze, ku niebu, do Boga."}', '2025-10-24 22:16:53.944', '2025-10-24 22:16:53.944', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9h600nwqhd9s9m0t4y2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co to jest farsa?', '{"options": ["dramat religijny", "komedia o charakterze groteskowym", "kronika", "pieśń satyryczna"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Farsa to komedia oparta na efektach komizmu sytuacyjnego, zawierająca elementy groteskowe i karykaturalne."}', '2025-10-24 22:16:53.947', '2025-10-24 22:16:53.947', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9h800nxqhd9afg5rygd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Z czego wykształciła się farsa?', '{"options": ["z misterium", "z moralitetu", "z intermedium", "z miraklu"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Farsa wykształciła się z intermedium - krótkiej scenki satyrycznej granej między częściami misterium."}', '2025-10-24 22:16:53.949', '2025-10-24 22:16:53.949', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9hb00nyqhd9513p0j66', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Jaka była hierarchia społeczna w średniowieczu?', '{"options": ["duchowieństwo - chłopi - szlachta", "duchowieństwo - szlachta - mieszczanie - chłopi", "szlachta - duchowieństwo - chłopi", "wszyscy równi"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Hierarchia społeczna: na szczycie duchowieństwo, potem szlachta, niżej mieszczanie i rzemieślnicy, na dole chłopi."}', '2025-10-24 22:16:53.951', '2025-10-24 22:16:53.951', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9hd00nzqhd9dd68vf7a', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Co symbolizowało światło w katedrach gotyckich?', '{"options": ["wiedzę ludzką", "Boga, dobro i piękno", "władzę króla", "bogactwo Kościoła"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Światło w gotyku miało wymiar symboliczny - jasność kojarzono z Bogiem i pięknem, ciemność ze złem."}', '2025-10-24 22:16:53.953', '2025-10-24 22:16:53.953', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9hf00o0qhd9ebzadyzt', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Co to są roczniki?', '{"options": ["kroniki historyczne", "krótkie zapisy ważnych wydarzeń na marginesach ksiąg", "kalendarze liturgiczne", "pieśni rocznicowe"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Roczniki to krótkie informacje o ważnych wydarzeniach spisywane na marginesach ksiąg, które przekształciły się w kroniki."}', '2025-10-24 22:16:53.955', '2025-10-24 22:16:53.955', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9hh00o1qhd9ov2zqcjx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Jaki był stosunek augustynizmu do ciała i duszy?', '{"options": ["ciało i dusza są równie ważne", "dusza jest ważniejsza, ciało należy umartwiać", "ciało jest ważniejsze od duszy", "nie rozróżniano ciała i duszy"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Augustynizm głosił wyższość duszy nad ciałem - dusza nieśmiertelna, ciało zniszczalne, więc należy je umartwiać."}', '2025-10-24 22:16:53.958', '2025-10-24 22:16:53.958', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9hj00o2qhd97qbhs2pt', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Jaki był stosunek tomizmu do ciała i duszy?', '{"options": ["ciało należy umartwiać", "tylko dusza jest ważna", "ciało i dusza stanowią istotę człowieka - oba są ważne", "ciało jest ważniejsze"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Tomizm głosił, że zarówno ciało jak i dusza należą do istoty człowieka i są dziełem Boga - oba są ważne."}', '2025-10-24 22:16:53.96', '2025-10-24 22:16:53.96', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9hm00o3qhd9mabkkl3i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Co według tomizmu było wrodzonymi darami boskimi?', '{"options": ["siła i zdrowie", "bogactwo i władza", "cnota i rozum", "wiara i nadzieja"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Według tomizmu cnota i rozum były wrodzonymi darami boskimi, które miały pomóc człowiekowi w życiu."}', '2025-10-24 22:16:53.962', '2025-10-24 22:16:53.962', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ho00o4qhd9ot3elf89', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Ile wieków trwało średniowiecze w Europie?', '{"options": ["5 wieków", "7 wieków", "10 wieków", "15 wieków"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Średniowiecze w Europie trwało około 10 wieków (V-XV wiek)."}', '2025-10-24 22:16:53.964', '2025-10-24 22:16:53.964', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9hq00o5qhd96o650sou', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 1, 'Jak nazywano okrągłe okna wypełnione witrażami w katedrach gotyckich?', '{"options": ["rozety", "mandorle", "wimpergi", "fiale"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Rozety to charakterystyczne okrągłe okna wypełnione witrażami w katedrach gotyckich."}', '2025-10-24 22:16:53.966', '2025-10-24 22:16:53.966', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9hs00o6qhd9jlpr1jaj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 1, 'Co stanowiło podstawę edukacji średniowiecznej?', '{"options": ["nauki przyrodnicze", "siedem sztuk wyzwolonych", "filozofia grecka", "prawo rzymskie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Podstawą edukacji było siedem sztuk wyzwolonych: triwium (gramatyka, dialektyka, retoryka) i quadrivium (arytmetyka, muzyka, geometria, astronomia)."}', '2025-10-24 22:16:53.968', '2025-10-24 22:16:53.968', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9hu00o7qhd9d0pdv9kb', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Dopasuj nurty filozoficzne do ich twórców.', '{"leftColumn": [{"id": "A", "text": "Augustynizm"}, {"id": "B", "text": "Tomizm"}, {"id": "C", "text": "Franciszkanizm"}], "rightColumn": [{"id": 1, "text": "św. Tomasz z Akwinu"}, {"id": 2, "text": "św. Augustyn"}, {"id": 3, "text": "św. Franciszek z Asyżu"}], "matchingType": "philosophy_authors"}', '[[0, 1], [1, 0], [2, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Augustynizm stworzył św. Augustyn, tomizm św. Tomasz z Akwinu, franciszkanizm św. Franciszek z Asyżu."}', '2025-10-24 22:16:53.97', '2025-10-24 22:16:53.97', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9hw00o8qhd9vdeca085', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Dopasuj gatunki literackie do ich charakterystyki.', '{"leftColumn": [{"id": "A", "text": "Hagiografia"}, {"id": "B", "text": "Misterium"}, {"id": "C", "text": "Kronika"}, {"id": "D", "text": "Plankt"}], "rightColumn": [{"id": 1, "text": "dramat religijny o tematyce biblijnej"}, {"id": 2, "text": "dziejopisarstwo historyczne"}, {"id": 3, "text": "żywoty świętych"}, {"id": 4, "text": "utwór wyrażający żal po zmarłym"}], "matchingType": "genres_characteristics"}', '[[0, 2], [1, 0], [2, 1], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Hagiografia to żywoty świętych, misterium to dramat biblijny, kronika to dziejopisarstwo, plankt wyraża żal."}', '2025-10-24 22:16:53.973', '2025-10-24 22:16:53.973', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9hz00o9qhd9ipmcju77', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Które cechy charakteryzują styl romański? (wybierz wszystkie poprawne)', '{"options": ["grube mury i małe okna", "łuk półkolisty", "funkcja obronna", "strzelistość i witraże", "masywność budowli"]}', '[0, 1, 2, 4]', NULL, '{historical_literary,closed_multiple,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Styl romański cechują: grube mury, małe okna, łuk półkolisty, funkcja obronna i masywność. Strzelistość i witraże to cechy gotyku."}', '2025-10-24 22:16:53.975', '2025-10-24 22:16:53.975', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9i100oaqhd9zcpgpuob', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Które cechy charakteryzują styl gotycki? (wybierz wszystkie poprawne)', '{"options": ["strzelistość", "łuk ostrołukowy", "małe okna", "witraże", "grube mury"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Styl gotycki cechują: strzelistość, łuk ostrołukowy i witraże. Małe okna i grube mury to cechy romanizmu."}', '2025-10-24 22:16:53.978', '2025-10-24 22:16:53.978', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9i400obqhd9u0poadr8', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Dopasuj wzorce osobowe do ich cech.', '{"leftColumn": [{"id": "A", "text": "Asceta"}, {"id": "B", "text": "Rycerz"}, {"id": "C", "text": "Władca doskonały"}], "rightColumn": [{"id": 1, "text": "wyrzeczenie się dóbr doczesnych"}, {"id": 2, "text": "honor, odwaga, wiara"}, {"id": 3, "text": "mądrość, sprawiedliwość, troska o poddanych"}], "matchingType": "models_traits"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Asceta wyrzeka się dóbr, rycerz cechuje się honorem i odwagą, doskonały władca jest mądry i sprawiedliwy."}', '2025-10-24 22:16:53.98', '2025-10-24 22:16:53.98', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9i600ocqhd91dswj7gp', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 2, 'Uzupełnij informacje o średniowieczu.', '{"gaps": [{"id": 1, "options": ["tempus medium", "medium aevum", "media tempera", "aevum medium"]}, {"id": 2, "options": ["humanizmem", "racjonalizmem", "teocentryzmem", "antropocentryzmem"]}, {"id": 3, "options": ["greka", "łacina", "hebrajski", "aramejski"]}, {"id": 4, "options": ["kapitalizm", "komunizm", "feudalizm", "republikanizm"]}], "textWithGaps": "Nazwa średniowiecze pochodzi od łacińskiego [1]. Epoka ta charakteryzowała się [2], czyli podporządkowaniem życia Bogu. Dominującym językiem był [3], a system społeczny to [4]."}', '[1, 2, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Średniowiecze pochodzi od medium aevum, charakteryzował je teocentryzm, język łaciński i feudalizm."}', '2025-10-24 22:16:53.982', '2025-10-24 22:16:53.982', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9i800odqhd9mqopi48f', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Które motywy występowały w sztuce średniowiecznej? (wybierz wszystkie poprawne)', '{"options": ["danse macabre (taniec śmierci)", "memento mori", "stabat mater", "carpe diem", "pieta"]}', '[0, 1, 2, 4]', NULL, '{historical_literary,closed_multiple,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "W sztuce średniowiecznej występowały: danse macabre, memento mori, stabat mater i pieta. Carpe diem to motyw antyczny."}', '2025-10-24 22:16:53.985', '2025-10-24 22:16:53.985', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ib00oeqhd9i41zaryy', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Dopasuj łacińskie wyrażenia do ich znaczenia.', '{"leftColumn": [{"id": "A", "text": "Memento mori"}, {"id": "B", "text": "Ars moriendi"}, {"id": "C", "text": "Ad maiorem Dei gloriam"}, {"id": "D", "text": "Stabat Mater Dolorosa"}], "rightColumn": [{"id": 1, "text": "stała Matka boleściwa"}, {"id": 2, "text": "sztuka umierania"}, {"id": 3, "text": "pamiętaj o śmierci"}, {"id": 4, "text": "ku większej chwale Boga"}], "matchingType": "latin_meanings"}', '[[0, 2], [1, 1], [2, 3], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Memento mori - pamiętaj o śmierci, ars moriendi - sztuka umierania, ad maiorem Dei gloriam - ku większej chwale Boga, stabat mater - stała Matka boleściwa."}', '2025-10-24 22:16:53.987', '2025-10-24 22:16:53.987', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9id00ofqhd9aemb79s7', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Które elementy należały do uniwersalizmu średniowiecznego? (wybierz wszystkie poprawne)', '{"options": ["jedna religia - katolicyzm", "jeden język - łacina", "jeden ustrój - feudalizm", "jedna narodowość", "jeden władca świecki i duchowy"]}', '[0, 1, 2, 4]', NULL, '{historical_literary,closed_multiple,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Uniwersalizm obejmował: jedną religię (katolicyzm), język (łacinę), ustrój (feudalizm) i wspólną władzę (papież i cesarz). Nie było jednej narodowości."}', '2025-10-24 22:16:53.99', '2025-10-24 22:16:53.99', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9if00ogqhd9y0k8s54t', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 2, 'Uzupełnij informacje o filozofii średniowiecza.', '{"gaps": [{"id": 1, "options": ["Tomizm", "Augustynizm", "Franciszkanizm", "Scholastyka"]}, {"id": 2, "options": ["Augustynizm", "Franciszkanizm", "Tomizm", "Realizm"]}, {"id": 3, "options": ["Augustynizm", "Tomizm", "Scholastyka", "Franciszkanizm"]}], "textWithGaps": "[1] nawiązywał do filozofii Platona i głosił wyższość duszy nad ciałem. [2] nawiązywał do Arystotelesa i uznawał ciało i duszę za równie ważne. [3] propagował miłość do natury i wszystkich stworzeń."}', '[1, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,middle_ages,batch-2025-01}', '{"explanation": "Augustynizm nawiązywał do Platona, tomizm do Arystotelesa, franciszkanizm propagował miłość do natury."}', '2025-10-24 22:16:53.992', '2025-10-24 22:16:53.992', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ii00ohqhd90clb5yig', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 3, 'Dopasuj gatunki dramatyczne do ich charakterystyki.', '{"leftColumn": [{"id": "A", "text": "Misterium"}, {"id": "B", "text": "Moralitet"}, {"id": "C", "text": "Mirakl"}, {"id": "D", "text": "Farsa"}], "rightColumn": [{"id": 1, "text": "dramat dydaktyczny o walce dobra ze złem"}, {"id": 2, "text": "komedia o charakterze groteskowym"}, {"id": 3, "text": "dramat biblijny"}, {"id": 4, "text": "dramat o cudach świętych"}], "matchingType": "drama_genres"}', '[[0, 2], [1, 0], [2, 3], [3, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-2,middle_ages,batch-2025-01}', '{"explanation": "Misterium - dramat biblijny, moralitet - o walce dobra ze złem, mirakl - o cudach świętych, farsa - komedia groteskowa."}', '2025-10-24 22:16:53.994', '2025-10-24 22:16:53.994', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9il00oiqhd9zzlv8wfb', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Wyjaśnij, na czym polegał teocentryzm w epoce średniowiecza.', '{"instruction": "Opisz, jak teocentryzm wpływał na życie i kulturę średniowieczną. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie, że Bóg był w centrum zainteresowań (1 pkt)", "wyjaśnienie podporządkowania wszystkich dziedzin życia Bogu (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["Bóg", "centrum", "podporządkowanie", "wszystkie dziedziny", "życie wieczne"], "expectedAnswer": "Teocentryzm oznaczał, że Bóg był centrum wszystkich zainteresowań i działań człowieka. Wszystkie dziedziny życia - sztuka, literatura, nauka, polityka - były podporządkowane Bogu i jego chwale. Ludzie tworzyli i działali nie dla ziemskiej sławy, ale Ad maiorem Dei gloriam - ku większej chwale Boga. Życie doczesne traktowano jako przygotowanie do życia wiecznego."}', '2025-10-24 22:16:53.997', '2025-10-24 22:16:53.997', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9in00ojqhd98u3pi4xx', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Opisz główne różnice między stylem romańskim a gotyckim w architekturze.', '{"instruction": "Porównaj cechy obu stylów. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie cech stylu romańskiego (1 pkt)", "wskazanie cech stylu gotyckiego (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["romański", "masywność", "gotyk", "strzelistość", "witraże", "łuk"], "expectedAnswer": "Styl romański charakteryzował się masywnością, grubymi murami, małymi oknami i łukiem półkolistym. Budowle pełniły funkcję obronną. Styl gotycki był przeciwieństwem - budowle strzeliste, smukłe, z wysokimi oknami wypełnionymi witrażami, łukiem ostrołukowym. Gotyk symbolizował dążenie ku niebu, ku Bogu. Romańskie kościoły były ciemne, gotyckie - pełne światła."}', '2025-10-24 22:16:54', '2025-10-24 22:16:54', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9it00okqhd9fcztnjzo', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Wyjaśnij, co oznaczał uniwersalizm średniowieczny.', '{"instruction": "Opisz, na czym polegała jedność średniowiecznej Europy. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie wspólnych elementów (1 pkt)", "wyjaśnienie znaczenia uniwersalizmu (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["wspólnota", "jedna religia", "łacina", "feudalizm", "jedność"], "expectedAnswer": "Uniwersalizm średniowieczny oznaczał, że cała Europa stanowiła jednolitą wspólnotę. Obowiązywała jedna religia (katolicyzm), jeden język wykształconych warstw (łacina), jeden ustrój (feudalizm), wspólna władza (papież i cesarz). Jednakowe były wzorce osobowe, style w sztuce, symbole i motywy literackie. Europa była jednością kulturową, religijną i społeczną."}', '2025-10-24 22:16:54.005', '2025-10-24 22:16:54.005', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9iw00olqhd9bh9wmzij', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Scharakteryzuj wzorzec ascety w średniowieczu.', '{"instruction": "Opisz cechy i styl życia ascety. (30-50 słów)"}', NULL, '{"criteria": ["wskazanie wyrzeczenia się dóbr doczesnych (1 pkt)", "opisanie życia w skrajnym ubóstwie i modlitwie (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["wyrzeczenie", "ubóstwo", "modlitwa", "umartwianie", "zbawienie"], "expectedAnswer": "Asceta to wzorzec osobowy charakteryzujący się całkowitym wyrzeczeniem dóbr doczesnych. Życie ascety podporządkowane było Bogu, praktykowali oni skrajne ubóstwo, pokorę i umartwianie ciała. Oddawali się modlitwie i kontemplacji, często pozostawali anonimowi, nie ujawniając swojego pochodzenia. Celem ich życia było zbawienie duszy i życie wieczne."}', '2025-10-24 22:16:54.008', '2025-10-24 22:16:54.008', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9iy00omqhd9s0cml2mq', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Wyjaśnij, czym jest hagiografia i jakie cechy miały te utwory.', '{"instruction": "Opisz gatunek hagiografii i jego charakterystykę. (40-60 słów)"}', NULL, '{"criteria": ["definicja hagiografii jako żywotów świętych (1 pkt)", "wskazanie cech charakterystycznych (elementy cudowne, schemat) (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["żywoty świętych", "legendy", "cuda", "schemat", "dydaktyzm"], "expectedAnswer": "Hagiografia to żywotopisarstwo - gatunek literacki obejmujący żywoty świętych i legendy. Utwory te opisywały życie świętych według schematu: życie w dostatku, wyrzeczenie się dóbr, umartwianie, pokora, życie w anonimowości i śmierć, której towarzyszyły cuda. Zawierały liczne elementy cudowne i fantastyczne. Miały charakter dydaktyczny - propagowały wzorzec ascety."}', '2025-10-24 22:16:54.01', '2025-10-24 22:16:54.01', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9j100onqhd9kurzrnv3', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Opisz główne założenia augustynizmu.', '{"instruction": "Wyjaśnij, jak augustynizm pojmował człowieka i świat. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie wyższości duszy nad ciałem (1 pkt)", "wyjaśnienie tragizmu kondycji ludzkiej (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["dusza", "ciało", "tragizm", "dualizm", "umartwianie"], "expectedAnswer": "Augustynizm głosił dualistyczną wizję świata podzielonego na dobro (duch) i zło (materia). Człowiek był istotą tragiczną, rozdarty między duszą upodabniającą go do aniołów a ciałem przybliżającym go do zwierząt. Dusza była nieśmiertelna i ważniejsza, ciało zniszczalne - należało je umartwiać. Człowiek wiecznie miotał się między dobrem a złem."}', '2025-10-24 22:16:54.013', '2025-10-24 22:16:54.013', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9j300ooqhd93b276o5r', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Opisz główne założenia tomizmu.', '{"instruction": "Wyjaśnij, jak tomizm pojmował człowieka i poznanie. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie równości ciała i duszy (1 pkt)", "wyjaśnienie roli rozumu w poznaniu (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["ciało i dusza", "rozum", "wiara", "drabina bytów", "harmonia"], "expectedAnswer": "Tomizm głosił, że świat jest logiczny i racjonalny, przejawem mądrości Boga. Człowiek to najniższy z duchów, składa się z ciała i duszy - oba pochodzą od Boga i są równie ważne. Poznanie dokonuje się przez rozum i wiarę - nie wykluczają się, lecz uzupełniają. Rozum i cnota to wrodzone dary boże. Bóg ustalił porządek między stworzeniami."}', '2025-10-24 22:16:54.015', '2025-10-24 22:16:54.015', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9j500opqhd9z80vzomm', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Wyjaśnij, czym charakteryzował się franciszkanizm.', '{"instruction": "Opisz główne idee filozofii św. Franciszka. (40-60 słów)"}', NULL, '{"criteria": ["miłość do natury i wszystkich stworzeń (1 pkt)", "ubóstwo bez umartwiania ciała (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["miłość do natury", "wszystkie stworzenia", "ubóstwo", "miłosierdzie", "brak umartwiania"], "expectedAnswer": "Franciszkanizm propagował wszechogarniającą miłość do świata i wszystkich stworzeń Bożych - ludzi, zwierząt, roślin. Św. Franciszek nawet zwierzęta nazywał braćmi mniejszymi. Filozofia ta głosiła prostą i szczerą wiarę, miłosierdzie, pokórę i ubóstwo. W przeciwieństwie do augustynizmu nie praktykował umartwiania ciała - chodziło o minimalizm i ofiarność wobec innych."}', '2025-10-24 22:16:54.018', '2025-10-24 22:16:54.018', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9j800oqqhd96pz206qi', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Opisz motyw ''danse macabre'' i jego znaczenie.', '{"instruction": "Wyjaśnij, co przedstawiał taniec śmierci i jaką niosł wymowę. (40-60 słów)"}', NULL, '{"criteria": ["opis przedstawienia śmierci tańczącej ze wszystkimi (1 pkt)", "wymowa - równość wobec śmierci (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["śmierć", "taniec", "równość", "wszystkie stany", "przemijanie"], "expectedAnswer": "Danse macabre (taniec śmierci) to średniowieczny motyw przedstawiający śmierć jako rozkładający się trup kobiety lub szkielet z kosą. Śmierć zapraszała do korowodu wszystkich ludzi bez względu na stan społeczny, wykształcenie czy majątek. Motyw ten symbolizował, że wobec śmierci wszyscy są równi - jedyną sprawiedliwość w świecie feudalnym. Przypominał o przemijaniu - memento mori."}', '2025-10-24 22:16:54.02', '2025-10-24 22:16:54.02', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9jb00orqhd9tr246ohj', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 2, 'Wyjaśnij, dlaczego większość utworów średniowiecznych była anonimowa.', '{"instruction": "Opisz przyczynę anonimowości dzieł średniowiecznych. (30-50 słów)"}', NULL, '{"criteria": ["wskazanie teocentryzmu jako przyczyny (1 pkt)", "wyjaśnienie tworzenia ku chwale Boga (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-1,middle_ages,batch-2025-01}', '{"keyWords": ["teocentryzm", "chwała Boża", "brak sławy", "zbawienie", "służba Bogu"], "expectedAnswer": "Utwory były anonimowe, ponieważ tworzono je na chwałę Bożą - Ad maiorem Dei gloriam, a nie dla ziemskiej sławy autora. Zgodnie z teocentryzmem Bóg był w centrum zainteresowań, dlatego twórcy nie podpisywali swoich dzieł, nie chcieli zdobywać sławy wśród ludzi. Liczyło się tylko zbawienie duszy i służba Bogu."}', '2025-10-24 22:16:54.023', '2025-10-24 22:16:54.023', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50whu0000qhhmwrvqagh3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'W jakiej epoce literackiej powstała powieść „Ludzie bezdomni”?', '{"options": ["Romantyzm", "Pozytywizm", "Młoda Polska", "Dwudziestolecie międzywojenne"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "„Ludzie bezdomni” (1899) to powieść epoki Młodej Polski (modernizmu). Łączy elementy naturalizmu, symbolizmu i impresjonizmu — typowe dla estetyki przełomu XIX i XX wieku."}', '2026-03-17 21:41:53.154', '2026-03-17 21:41:53.154', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9je00osqhd9nrsk6vss', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Scharakteryzuj wzorzec rycerza chrześcijańskiego.', '{"instruction": "Opisz cechy idealnego rycerza średniowiecznego. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie cnót rycerskich (honor, odwaga) (1 pkt)", "podkreślenie wiary i służby Bogu (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["odwaga", "honor", "wiara", "lojalność", "obrona chrześcijaństwa"], "expectedAnswer": "Rycerz chrześcijański był wzorem cnót - głęboko wierzący, odważny, honorowy i wierny. Całe życie podporządkowywał Bogu i swojemu władcy, kierując się zasadą: Bóg, Honor, Ojczyzna. Walczył w obronie wiary chrześcijańskiej, bronił słabszych. Charakteryzowały go: męstwo, szlachetność, lojalność wobec króla i Boga, gotowość do poświęcenia za wiarę."}', '2025-10-24 22:16:54.027', '2025-10-24 22:16:54.027', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ji00otqhd97ijq4ull', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Opisz wzorzec doskonałego władcy w średniowieczu.', '{"instruction": "Wyjaśnij, jakie cechy miał idealny władca średniowieczny. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie cech władcy (mądrość, sprawiedliwość) (1 pkt)", "podkreślenie roli Boga i troski o poddanych (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["następca Boga", "sprawiedliwość", "mądrość", "dobro poddanych", "kontakt z Bogiem"], "expectedAnswer": "Doskonały władca był następcą Boga na ziemi. Wszystkie jego działania miały na celu dobro ojczyzny i poddanych. Charakteryzowały go: mądrość, roztropność, sprawiedliwość, honor i wierność. Cenił lojalność poddanych. Miał kontakt z Bogiem poprzez sny i widzenia, dzięki czemu podejmował trafne decyzje. Był waleczny, pobożny i opiekuńczy wobec swoich ludzi."}', '2025-10-24 22:16:54.031', '2025-10-24 22:16:54.031', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9jl00ouqhd9lkn3k7tz', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Wyjaśnij, co to jest misterium i jaką pełniło funkcję.', '{"instruction": "Opisz gatunek misterium i jego znaczenie w kulturze średniowiecznej. (40-60 słów)"}', NULL, '{"criteria": ["definicja misterium jako dramatu religijnego (1 pkt)", "wskazanie funkcji dydaktycznej i religijnej (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["dramat religijny", "Biblia", "dydaktyzm", "uroczystości", "nauka wiary"], "expectedAnswer": "Misterium to średniowieczny dramat religijny, którego treść czerpana była ze Starego i Nowego Testamentu. Wystawiano je podczas uroczystości religijnych, głównie Wielkiego Tygodnia. Miały charakter dydaktyczny - uczyły prawd wiary i zasad moralnych. Dla analfabetów były sposobem poznania Biblii. Łączyły funkcję religijną z rozrywkową, angażując całą społeczność."}', '2025-10-24 22:16:54.033', '2025-10-24 22:16:54.033', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9jn00ovqhd9d5k660ap', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Opisz, czym był moralitet i jaka była jego budowa.', '{"instruction": "Wyjaśnij charakterystykę moralitetu jako gatunku. (40-60 słów)"}', NULL, '{"criteria": ["definicja moralitetu jako dramatu dydaktycznego (1 pkt)", "wskazanie alegorycznej walki dobra ze złem (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["dramat dydaktyczny", "Każdy", "alegoria", "dobro i zło", "cnoty i przywary"], "expectedAnswer": "Moralitet to średniowieczny dramat o charakterze dydaktyczno-moralizatorskim. Jego bohaterem był przeciętny człowiek (Każdy/Jedermann). Przedstawiał walkę dobra i zła o ludzką duszę - dobro reprezentował anioł, zło diabeł. Postacie były alegoryczne, symbolizowały cnoty i przywary. Celem było pouczenie widzów o konsekwencjach grzechu i znaczeniu cnót dla zbawienia duszy."}', '2025-10-24 22:16:54.036', '2025-10-24 22:16:54.036', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9jq00owqhd91bysvilj', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Wyjaśnij, czym różnił się mirakl od misterium.', '{"instruction": "Porównaj oba gatunki dramatyczne. (30-50 słów)"}', NULL, '{"criteria": ["wskazanie tematyki misterium (Biblia) (1 pkt)", "wskazanie tematyki miraklu (cuda świętych) (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["misterium", "Biblia", "mirakl", "święci", "cuda"], "expectedAnswer": "Misterium to dramat oparty na motywach biblijnych ze Starego i Nowego Testamentu. Mirakl natomiast przedstawiał życie Matki Boskiej, świętych i męczenników. Charakterystyczną cechą miraklu było ukazywanie licznych cudów i interwencji boskich. Oba gatunki miały charakter religijny i dydaktyczny, ale czerpały z różnych źródeł i prezentowały różne postacie."}', '2025-10-24 22:16:54.038', '2025-10-24 22:16:54.038', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9js00oxqhd9xys391ug', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Opisz charakter średniowiecznych kronik.', '{"instruction": "Wyjaśnij, jakie cechy miały kroniki średniowieczne. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie dydaktyzmu i panegiryzmu (1 pkt)", "wskazanie braku krytycyzmu i elementów fikcyjnych (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["panegiryzm", "dydaktyzm", "brak krytycyzmu", "legendy", "łacina"], "expectedAnswer": "Kroniki średniowieczne miały charakter panegiryczny - służyły wychwalaniu władców, często powstawały na ich zamówienie. Były dydaktyczne i moralizatorskie. Cechował je brak krytycyzmu - zawierały legendy i podania traktowane jako prawda historyczna, elementy fikcyjne jak listy czy pieśni. Pisane były po łacinie, kunsztownym stylem bogatym w środki artystyczne."}', '2025-10-24 22:16:54.04', '2025-10-24 22:16:54.04', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ju00oyqhd9yxykiwd1', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 1, 2, 'Wyjaśnij, co oznacza pojęcie ''chanson de geste''.', '{"instruction": "Opisz ten gatunek literacki i jego cechy. (30-50 słów)"}', NULL, '{"criteria": ["definicja jako pieśń o czynach (1 pkt)", "wskazanie bohaterskich czynów rycerzy (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-1,middle_ages,batch-2025-01}', '{"keyWords": ["pieśń o czynach", "epos", "rycerze", "bohaterskie czyny", "ideały"], "expectedAnswer": "Chanson de geste to francuskie określenie oznaczające ''pieśń o czynach''. Był to gatunek epicki - dłuższe poematy wierszowane opiewające bohaterskie czyny legendarnych lub historycznych rycerzy. Charakteryzował się patetycznym stylem, idealizacją bohaterów, rozbudowanymi opisami bitew. Propagował ideały rycerskie: honor, odwagę, wierność władcy i wiarę."}', '2025-10-24 22:16:54.043', '2025-10-24 22:16:54.043', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evahz0139qhd9n4gd9ss7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Kto namawia Makbeta do zabójstwa Duncana?', '{"options": ["Banko", "wiedźmy", "Lady Makbet", "Malcolm"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Lady Makbet przekonuje wahającego się męża do popełnienia królobójstwa."}', '2025-10-24 22:16:55.271', '2025-10-24 22:16:55.271', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evai1013aqhd9tenfvin8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Co widzi Makbet tuż przed zabójstwem Duncana?', '{"options": ["ducha ojca", "halucynacyjny sztylet", "trzech rycerzy", "płonący krzew"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Makbet ma halucynację sztyletu prowadzącego go do komnaty Duncana."}', '2025-10-24 22:16:55.273', '2025-10-24 22:16:55.273', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9jx00ozqhd9uftruqlh', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Opisz motyw ''psychomachii'' w kulturze średniowiecznej.', '{"instruction": "Wyjaśnij, czym była psychomachia i kiedy się odbywała. (30-50 słów)"}', NULL, '{"criteria": ["definicja jako walki o duszę (1 pkt)", "wskazanie momentu przed śmiercią (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["walka o duszę", "przed śmiercią", "anioły i demony", "dobro i zło", "zbawienie"], "expectedAnswer": "Psychomachia to motyw walki dobra ze złem o duszę człowieka. Odbywała się tuż przed śmiercią - demony i anioły walczyły o to, gdzie dusza trafi po śmierci. Człowiek był kuszony przez demony i wspierany przez aniołów. Ostateczna decyzja zależała od jego wyborów. Motyw ten podkreślał znaczenie cnót i grzechów dla zbawienia."}', '2025-10-24 22:16:54.045', '2025-10-24 22:16:54.045', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9jz00p0qhd9ule2c0jd', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Wyjaśnij znaczenie łaciny w kulturze średniowiecznej.', '{"instruction": "Opisz rolę języka łacińskiego w średniowieczu. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie łaciny jako języka nauki i Kościoła (1 pkt)", "podkreślenie uniwersalnego charakteru łaciny (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["uniwersalny język", "nauka", "Kościół", "komunikacja", "edukacja"], "expectedAnswer": "Łacina była uniwersalnym językiem średniowiecznej Europy. Stanowiła język nauki, literatury, Kościoła i wykształconych warstw społecznych. Wszystkie ważne dokumenty, kroniki, teksty teologiczne i filozoficzne pisano po łacinie. Dzięki temu uczeni z całej Europy mogli się komunikować i wymieniać wiedzą. Łacina była podstawą edukacji i symbolem uniwersalizmu średniowiecznego."}', '2025-10-24 22:16:54.048', '2025-10-24 22:16:54.048', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9k100p1qhd9m9u42znx', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 2, 2, 'Opisz system feudalny panujący w średniowieczu.', '{"instruction": "Wyjaśnij, na czym polegał feudalizm i jaka była hierarchia społeczna. (40-60 słów)"}', NULL, '{"criteria": ["wyjaśnienie systemu lennego (1 pkt)", "opisanie hierarchii społecznej (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,middle_ages,batch-2025-01}', '{"keyWords": ["hierarchia", "lenna", "pańszczyzna", "wasal", "zależności"], "expectedAnswer": "Feudalizm to średniowieczny system społeczno-gospodarczy oparty na hierarchii lennej i zależnościach wasalnych. Ziemia należała do panów feudalnych, chłopi musieli odpracowywać pańszczyznę. Hierarchia: na szczycie duchowieństwo i szlachta, niżej mieszczanie i rzemieślnicy, na dole chłopi. System oparty był na zależnościach osobistych, przysięgach wierności i zobowiązaniach wzajemnych między panem a wasalem."}', '2025-10-24 22:16:54.05', '2025-10-24 22:16:54.05', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9k400p2qhd9h2b5v5lj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Który filozof średniowieczny stworzył ontologiczny dowód na istnienie Boga?', '{"options": ["św. Tomasz z Akwinu", "św. Augustyn", "św. Anzelm z Canterbury", "Piotr Abelard"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Św. Anzelm z Canterbury stworzył ontologiczny dowód na istnienie Boga, argumentując, że Bóg jako byt najdoskonalszy musi istnieć, bo istnienie jest doskonałością."}', '2025-10-24 22:16:54.052', '2025-10-24 22:16:54.052', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9k600p3qhd9nol3il1u', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co oznacza łacińskie wyrażenie ''vanitas vanitatum et omnia vanitas''?', '{"options": ["pamiętaj o śmierci", "wszystko przemija", "marność nad marnościami i wszystko marność", "w zdrowym ciele zdrowy duch"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Vanitas vanitatum et omnia vanitas to cytat z Księgi Koheleta oznaczający ''marność nad marnościami i wszystko marność'' - kluczowe hasło średniowiecza o przemijaniu."}', '2025-10-24 22:16:54.054', '2025-10-24 22:16:54.054', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9k900p4qhd9ehig922n', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Jak nazywa się filozoficzny spór w średniowieczu dotyczący natury pojęć ogólnych?', '{"options": ["spór o uniwersalia", "spór o inwestyturę", "querelle des anciens et des modernes", "disputatio"]}', '0', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Spór o uniwersalia to wielki średniowieczny spór filozoficzny między realizmem a nominalizmem dotyczący tego, czy pojęcia ogólne istnieją realnie, czy tylko jako nazwy."}', '2025-10-24 22:16:54.057', '2025-10-24 22:16:54.057', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9kb00p5qhd92z4lwoin', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co to jest tympanon w architekturze romańskiej?', '{"options": ["wysoki filar", "sklepienie krzyżowe", "półkoliste pole nad portalem z rzeźbami", "okrągłe okno"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Tympanon to półkoliste lub trójkątne pole nad portalem wejściowym, bogato zdobione rzeźbami religijnymi, charakterystyczne dla architektury romańskiej."}', '2025-10-24 22:16:54.059', '2025-10-24 22:16:54.059', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wi10001qhhmy6qcr56b', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Ile tomów liczy powieść „Ludzie bezdomni”?', '{"options": ["Jeden", "Dwa", "Trzy", "Cztery"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Powieść składa się z dwóch tomów. Tom I obejmuje pobyt Judyma w Paryżu, powrót do Warszawy i przyjazd do Cisów. Tom II rozgrywa się w Cisach i Zagłębiu Dąbrowskim."}', '2026-03-17 21:41:53.161', '2026-03-17 21:41:53.161', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9kd00p6qhd99suguvxm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co oznaczała koncepcja ''drabiny bytów'' w filozofii tomistycznej?', '{"options": ["wszyscy ludzie są równi", "każde stworzenie ma swoje miejsce w hierarchii od materii po Boga", "człowiek może awansować społecznie", "aniołowie są najważniejszymi bytami"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Drabina bytów (scala naturae) to koncepcja tomistyczna hierarchii stworzeń od materii nieożywionej przez rośliny, zwierzęta, ludzi, aniołów aż po Boga jako szczyt."}', '2025-10-24 22:16:54.061', '2025-10-24 22:16:54.061', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9kf00p7qhd9ps11gi6a', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co to są łuki przyporowe w architekturze gotyckiej?', '{"options": ["łuki wewnątrz budowli", "zewnętrzne konstrukcje wzmacniające mury", "elementy dekoracyjne", "rodzaj sklepienia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Łuki przyporowe to charakterystyczne dla gotyku zewnętrzne konstrukcje wsporcze, które przejmowały ciężar wysokich ścian i pozwalały na cieńsze mury i większe okna."}', '2025-10-24 22:16:54.064', '2025-10-24 22:16:54.064', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wi40002qhhm67lg2aeg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Jak ma na imię brat Tomasza Judyma?', '{"options": ["Wacław", "Wiktor", "Władysław", "Wojciech"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Brat Tomasza Judyma ma na imię Wiktor. Pracuje przy stalowni (gruszce Bessemera), żyje w nędzy z żoną i dziećmi w robotniczej dzielnicy Warszawy."}', '2026-03-17 21:41:53.164', '2026-03-17 21:41:53.164', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9kh00p8qhd9v3utgxi5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Jaki rodzaj sklepienia charakteryzował architekturę gotycką?', '{"options": ["sklepienie kolebkowe", "sklepienie krzyżowe", "sklepienie krzyżowo-żebrowe", "kopuła"]}', '2', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Gotyk charakteryzuje się sklepieniem krzyżowo-żebrowym, które było lżejsze niż romańskie i pozwalało na budowanie wyższych konstrukcji."}', '2025-10-24 22:16:54.066', '2025-10-24 22:16:54.066', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9kj00p9qhd962fxo9cw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co symbolizowała czerwień w średniowiecznej symbolice barw?', '{"options": ["czystość i niewinność", "mądrość i wiedzę", "męczeństwo, krew Chrystusa i miłość", "nadzieję i życie wieczne"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "W symbolice średniowiecznej czerwień oznaczała męczeństwo, krew Chrystusa, miłość bożą oraz ofiarę i poświęcenie."}', '2025-10-24 22:16:54.068', '2025-10-24 22:16:54.068', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9km00paqhd9mnyjw257', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co symbolizowała biel w średniowiecznej symbolice kolorów?', '{"options": ["śmierć i żałobę", "bogactwo i władzę", "czystość, niewinność i świętość", "mądrość i prawdę"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Biel w średniowieczu symbolizowała czystość, niewinność, świętość i triumf. Była kolorem Chrystusa Zmartwychwstałego."}', '2025-10-24 22:16:54.07', '2025-10-24 22:16:54.07', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ko00pbqhd9362s1jj9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co oznacza pojęcie ''iluminacja'' w filozofii augustyńskiej?', '{"options": ["zdobienie ksiąg miniaturami", "boże oświecenie umożliwiające poznanie prawdy", "światło w katedrach", "ceremonię religijną"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Iluminacja w augustynizmie to boże oświecenie - poznanie prawdy nie dokonuje się przez rozum, ale przez Boga, który oświeca umysł człowieka."}', '2025-10-24 22:16:54.072', '2025-10-24 22:16:54.072', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9kq00pcqhd95bpprnbm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co to jest apsyda w architekturze romańskiej?', '{"options": ["wieża kościelna", "portal wejściowy", "podwyższona, półkolista absyda za ołtarzem", "sklepienie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Apsyda to charakterystyczne dla romańskiej architektury podwyższone, półkoliste zakończenie nawy głównej za ołtarzem."}', '2025-10-24 22:16:54.075', '2025-10-24 22:16:54.075', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9kt00pdqhd9xcms1h77', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Który doktryna filozoficzna głosiła, że prawda nie sprzeciwia się wierze?', '{"options": ["augustynizm", "franciszkanizm", "nominalizm", "tomizm"]}', '3', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Tomizm głosił, że wiara i rozum się uzupełniają - prawda poznana rozumem nie może być sprzeczna z prawdą objawioną przez wiarę."}', '2025-10-24 22:16:54.077', '2025-10-24 22:16:54.077', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9kv00peqhd9hgt26rny', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co to jest miniaturaświetokrzyska?', '{"options": ["mała rzeźba", "iluminacja - ozdoba rękopiśmienna ze złotem i kolorami", "typ architektury", "gatunek literacki"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Miniatura to kunsztowna iluminacja - ozdoba manuskryptów złotem, srebrem i jaskrawymi kolorami, często przedstawiająca sceny religijne."}', '2025-10-24 22:16:54.08', '2025-10-24 22:16:54.08', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wi60003qhhmtzy3yvlv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Na jakim instrumencie gra Joanna Podborska?', '{"options": ["Na skrzypcach", "Na fortepianie", "Na gitarze", "Na flecie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Joanna gra na fortepianie — muzyka jest jedną z jej pasji i sposobów wyrażania emocji. W Cisach grywa wieczorami, co zbliża ją do Judyma."}', '2026-03-17 21:41:53.167', '2026-03-17 21:41:53.167', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wi90004qhhmy5vg4qur', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Gdzie Judym pracuje po opuszczeniu Cisów?', '{"options": ["Wraca do Paryża", "Jedzie do Zagłębia Dąbrowskiego", "Otwiera gabinet w Warszawie", "Wyjeżdża do Lwowa"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Po utracie posady w Cisach Judym jedzie do Zagłębia Dąbrowskiego, gdzie pracuje jako lekarz w kopalni. Tam styka się z najcięższą nędzą robotniczą."}', '2026-03-17 21:41:53.169', '2026-03-17 21:41:53.169', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wib0005qhhmmk22hi52', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Które z poniższych postaci pojawiają się w powieści „Ludzie bezdomni”?', '{"options": ["Tomasz Judym", "Stanisław Wokulski", "Joanna Podborska", "Doktor Węglichowski"]}', '[0, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Judym, Podborska i Węglichowski to postacie z „Ludzi bezdomnych”. Stanisław Wokulski jest bohaterem „Lalki” Bolesława Prusa."}', '2026-03-17 21:41:53.172', '2026-03-17 21:41:53.172', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9kx00pfqhd9rtp7u2r2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co oznacza termin ''amor courtois'' w kulturze średniowiecznej?', '{"options": ["miłość małżeńska", "miłość dworska - wyidealizowana, niespełniona", "miłość rodzicielska", "miłość do Boga"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Amor courtois (miłość dworska) to średniowieczny model miłości rycerza do nieosiągalnej damy, pełnej szacunku, adoracji i cierpienia."}', '2025-10-24 22:16:54.082', '2025-10-24 22:16:54.082', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wie0006qhhmjewhacfu', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Które stwierdzenia o fabryce cygar są prawdziwe?', '{"options": ["Pracuje w niej bratowa Judyma", "Panuje tam duszne, pełne pyłu tytoniowego powietrze", "Fabryka jest nowoczesna i bezpieczna", "Pracownice pakują tysiąc funtów tytoniu dziennie"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Judymowa (żona Wiktora) pracuje w fabryce cygar w fatalnych warunkach — duszącym powietrzu pełnym pyłu. Zespoły czteroosobowe pakują tysiąc funtów dziennie w zabójczym tempie. Fabryka jest przeciwieństwem „nowoczesnej i bezpiecznej”."}', '2026-03-17 21:41:53.174', '2026-03-17 21:41:53.174', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wig0007qhhmj2jaeqme', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Które cechy opisują Tomasza Judyma na początku powieści?', '{"options": ["Jest młodym lekarzem po studiach", "Pochodzi z rodziny szlacheckiej", "Przebywa w Paryżu na praktyce chirurgicznej", "Jest bogaty i niezależny finansowo"]}', '[0, 2]', NULL, '{historical_literary,closed_multiple,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Na początku powieści Judym jest młodym lekarzem po studiach w Warszawie, przebywającym na praktyce w klinikach paryskich. Pochodzi z ubogiej rodziny szewca (nie szlacheckiej) i nie jest zamożny."}', '2026-03-17 21:41:53.177', '2026-03-17 21:41:53.177', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wij0008qhhm18w63tmg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Jak reaguje środowisko lekarskie na odczyt Judyma u Czerniszów?', '{"options": ["Z entuzjazmem — natychmiast popierają jego postulaty", "Z obojętnością — nikt nie słucha", "Z krytyką — uznają jego postulaty za utopijne i niestosowne", "Z agresją — Judym zostaje fizycznie zaatakowany"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Lekarze krytykują odczyt Judyma. Doktor Kalecki grzecznie, doktor Płowicz ostro — nazywają jego postulaty „mrzonkami”. Jedynym, który okazuje współczucie, jest doktor Chmielnicki."}', '2026-03-17 21:41:53.179', '2026-03-17 21:41:53.179', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wil0009qhhm2yctmjko', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Dlaczego Judym odwiedza ulicę Ciepłą i Krochmalną po powrocie z Paryża?', '{"options": ["Szuka tam nowego mieszkania", "Chce zobaczyć miejsca swojego dzieciństwa i odwiedzić brata Wiktora", "Został tam skierowany przez szpital", "Spotyka się z doktorem Czerniszem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Judym odwiedza rodzinne strony — ulicę Ciepłą, gdzie mieszkał jego ojciec szewc, i okolicę Krochmalnej, gdzie żyje brat Wiktor z rodziną. Ta wizyta konfrontuje go z nędzą, której sam doświadczał w dzieciństwie."}', '2026-03-17 21:41:53.182', '2026-03-17 21:41:53.182', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wio000aqhhm7d6m3378', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Co robi Judym w Château-Rouge?', '{"options": ["Wynajmuje pokój na czas pobytu w Paryżu", "Spędza jedną dobę w noclegowni dla nędzarzy, obserwując warunki życia biedoty", "Uczęszcza na wykłady medyczne", "Spotyka się z polską emigracją"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Château-Rouge to paryska noclegownia dla nędzarzy. Judym spędza tam dobę, widząc na własne oczy skrajną biedę — setki ludzi śpiących na podłodze, prostytutki, zbieraczy niedopałków. To doświadczenie fundamentalnie kształtuje jego poglądy."}', '2026-03-17 21:41:53.184', '2026-03-17 21:41:53.184', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wiq000bqhhm65h3pn7k', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Kim z zawodu jest Korzecki?', '{"options": ["Lekarzem", "Inżynierem", "Prawnikiem", "Pisarzem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Korzecki jest inżynierem pracującym w Zagłębiu Dąbrowskim. Jest człowiekiem wykształconym i wrażliwym, ale cierpiącym na głęboką nerwicę egzystencjalną (pavor nocturnus — lęk nocny)."}', '2026-03-17 21:41:53.186', '2026-03-17 21:41:53.186', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wis000cqhhm7ckxk5c8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Jaki tytuł nosi rozdział powieści napisany w formie dziennika?', '{"options": ["„Smutek”", "„Zwierzenia”", "„Przyjdź”", "„Ludzie”"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Rozdział „Zwierzenia” to dziennik Joanny Podborskiej — jedyny fragment powieści napisany w pierwszej osobie. Joanna prowadzi zapisy od października do czerwca, ujawniając swoje myśli, uczucia i refleksje."}', '2026-03-17 21:41:53.188', '2026-03-17 21:41:53.188', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wiu000dqhhmyyh5l71p', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'W kogo zakochuje się panna Natalia Orszeńska?', '{"options": ["W Tomasza Judyma", "W inżyniera Korzeckiego", "W Karbowskiego", "W doktora Węglichowskiego"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Natalia Orszeńska zakochuje się w Karbowskim — przystojnym, ale lekkomyślnym utracjuszu i karciarzu. Judym porównuje go do kwiatu tuberozy — pięknego, ale bezużytecznego."}', '2026-03-17 21:41:53.191', '2026-03-17 21:41:53.191', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wix000eqhhm5sg4b5r6', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Które elementy naturalizmu są obecne w „Ludziach bezdomnych”?', '{"options": ["Szczegółowe opisy warunków fizycznych w fabryce cygar", "Opis noclegowni Château-Rouge z fizjologicznymi detalami", "Idealizacja życia wiejskiego", "Sceny pokazujące choroby i brud w suterenach warszawskich"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Naturalizm w powieści objawia się w szczegółowych, fizjologicznych opisach nędzy: fabryka cygar (pył, tempo pracy), Château-Rouge (ciała, smród, choroby), sutereny Warszawy (brud, ciemnota). Żeromski nie idealizuje życia wiejskiego."}', '2026-03-17 21:41:53.194', '2026-03-17 21:41:53.194', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wiz000fqhhmaxdq5irc', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Które z podanych miejsc akcji należą do tomu II powieści?', '{"options": ["Paryż", "Cisy", "Zagłębie Dąbrowskie", "Luwr"]}', '[1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Tom II rozgrywa się w Cisach (zakład leczniczy) i w Zagłębiu Dąbrowskim (kopalnie, cynkownie). Paryż i Luwr pojawiają się na początku tomu I."}', '2026-03-17 21:41:53.196', '2026-03-17 21:41:53.196', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wj2000gqhhmiqlr7mdy', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Które stwierdzenia o ciotce Tomasza Judyma są prawdziwe?', '{"options": ["Wychowała Tomasza i opłaciła mu edukację", "Była w młodości „cudną dziewczyną” — prowadziła wystawne życie", "Traktowała Tomasza z wielką czułością i troską", "Zabrała go z domu rodzinnego na ulicy Ciepłej"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Ciotka Judyma była dawną kurtyzaną, która zebrała pieniądze i zabrała małego Tomasza od rodziny, opłacając mu edukację. Nie traktowała go jednak z czułością — była surowa i wymagająca."}', '2026-03-17 21:41:53.199', '2026-03-17 21:41:53.199', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wj5000hqhhmm4m2aes0', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Co Judym zarzuca lekarzom w swoim odczycie?', '{"options": ["Że leczą wyłącznie ludzi bogatych", "Że nie walczą z przyczynami chorób biedoty", "Że stosują przestarzałe metody chirurgiczne", "Że ignorują warunki życia w suterenach i fabrykach"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Judym zarzuca środowisku lekarskiemu trzy rzeczy: koncentrację na zamożnych pacjentach, ignorowanie systemowych przyczyn chorób (nędza, brud, fabryki) oraz bierność wobec warunków życia najuboższych. Nie krytykuje metod chirurgicznych."}', '2026-03-17 21:41:53.201', '2026-03-17 21:41:53.201', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wj7000iqhhm23mab9g7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Jakie znaczenie ma kwiat tuberozy w powieści?', '{"options": ["Symbolizuje miłość Judyma do Joanny", "Symbolizuje bezużyteczne piękno — Judym porównuje do niego utracjusza Karbowskiego", "Jest motywem przewodnim rozdziału „Zwierzenia”", "Symbolizuje nadzieję na lepsze życie robotników"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Tuberoza to kwiat piękny, ale bezużyteczny — Judym przyrównuje do niego Karbowskiego, przystojnego karciarza kochanego przez Natalię Orszeńską. Symbol podkreśla kontrast między pięknem a społeczną użytecznością."}', '2026-03-17 21:41:53.203', '2026-03-17 21:41:53.203', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wj9000jqhhm6zqgr5lu', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Co powoduje malarię wśród mieszkańców okolic Cisów?', '{"options": ["Brudna woda pitna z miejskich studni", "Stojąca woda w stawach, sadzawkach i bagnistych terenach parkowych", "Kontakt z chorymi kuracjuszami przyjezdnymi", "Praca w okolicznych kopalniach siarki"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Judym odkrywa, że malaria w Cisach pochodzi od stojącej wody w stawach i sadzawkach parkowych. Proponuje osuszenie terenu, ale napotyka opór dyrektora Węglichowskiego i administratora Krzywosąda, którzy nie chcą niszczyć „urządzeń wodnych” zakładu."}', '2026-03-17 21:41:53.206', '2026-03-17 21:41:53.206', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wjb000kqhhmjg18bw0u', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Jak ginie inżynier Korzecki?', '{"options": ["Ginie w wypadku w kopalni", "Umiera na gruźlicę", "Popełnia samobójstwo, strzelając do siebie", "Zostaje zamordowany przez robotników"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Korzecki popełnia samobójstwo — strzela do siebie. Przed śmiercią zostawia kartkę z cytatem z Platona o Dajmonionie, który „nie stawia mu oporu”. Jego śmierć jest aktem ostatecznego wyzwolenia od lęku egzystencjalnego (pavor nocturnus)."}', '2026-03-17 21:41:53.208', '2026-03-17 21:41:53.208', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wje000lqhhmd26ys2zg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Który rozdział powieści najtrafniej ilustruje technikę psychizacji pejzażu?', '{"options": ["Rozdział opisujący Château-Rouge w Paryżu", "Rozdział „Smutek” — jesienny park po nieudanym odczycie", "Rozdział z odczytem u Czerniszów", "Rozdział „Zwierzenia” — dziennik Joanny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "W rozdziale „Smutek” jesienny pejzaż — opadające liście, szarość, chłód — odpowiada stanowi psychicznemu Judyma po porażce jego odczytu. Przyroda „mówi” emocjami bohatera, co jest esencją psychizacji pejzażu."}', '2026-03-17 21:41:53.21', '2026-03-17 21:41:53.21', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wjg000mqhhmkq179fpq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Co Judym mówi Joasi w scenie rozstania?', '{"options": ["Że ją kocha, ale musi wyjechać za granicę na stypendium", "Że nie może mieć ani ojca, ani matki, ani żony, dopóki trwa nędza najuboższych", "Że Joasia nie jest mu równa społecznie i nigdy nie będzie", "Że odnalazł inną kobietę w Zagłębiu Dąbrowskim"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "W ostatnim rozdziale Judym wyznaje Joasi, że nie może mieć „ani ojca, ani matki, ani żony”, bo czuje dług wobec biedoty — jako człowiek, który sam wyszedł z nędzy, nie ma prawa budować osobistego szczęścia, dopóki inni cierpią."}', '2026-03-17 21:41:53.212', '2026-03-17 21:41:53.212', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wji000nqhhm422oo0c1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Jaka jest reakcja Joanny na rozstanie z Judymem?', '{"options": ["Akceptuje decyzję Judyma ze spokojem i wraca do pracy", "Wybucha gniewem i odchodzi, zrywając kontakt", "Płacze — jej płacz rozlega się w zakończeniu powieści obok szumu kopalni i rozdartej sosny", "Prosi Judyma, by zmienił zdanie i wyjechali razem za granicę"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Zakończenie powieści to jedna z najbardziej poruszających scen w polskiej literaturze. Joanna płacze, a Judym słyszy w ciemności płacz, którego nie potrafi zidentyfikować — „Kto płacze? Czy to Joasia? Kopalnia? A może ta sosna rozdarta?”"}', '2026-03-17 21:41:53.214', '2026-03-17 21:41:53.214', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wjk000oqhhmp338xu7d', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Które miejsca w powieści służą jako ilustracja nędzy społecznej?', '{"options": ["Sutereny na ulicy Ciepłej i Krochmalnej w Warszawie", "Noclegownia Château-Rouge w Paryżu", "Salon doktorostwa Czerniszów", "„Budy” robotnicze przy cynkowni w Zagłębiu"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Żeromski buduje panoramę nędzy: warszawskie sutereny (Ciepła, Krochmalna), paryska noclegownia (Château-Rouge), „budy” robotnicze w Zagłębiu przy cynkowniach. Salon Czerniszów to przestrzeń zamożnej inteligencji — kontrastowa wobec nędzy."}', '2026-03-17 21:41:53.217', '2026-03-17 21:41:53.217', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wjm000pqhhmlu203djy', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Które postacie okazują Judymowi współczucie lub wsparcie po nieudanym odczycie?', '{"options": ["Doktor Kalecki", "Doktor Chmielnicki", "Doktor Płowicz", "Joanna Podborska"]}', '[1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Po odczycie Judym jest odrzucony przez środowisko — Kalecki krytykuje łagodnie, Płowicz ostro. Jedynym lekarzem, który okazuje szczere współczucie, jest Chmielnicki. Joanna, choć nie jest obecna na odczycie, stanowi moralne oparcie dla Judyma."}', '2026-03-17 21:41:53.219', '2026-03-17 21:41:53.219', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wjo000qqhhmpkeo02o4', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Które tematy porusza Joanna Podborska w swoim dzienniku („Zwierzenia”)?', '{"options": ["Samotność guwernantki i tęsknotę za domem rodzinnym", "Plany podróży do Paryża", "Śmierć brata Wacława", "Refleksje o roli kobiet i feminizmie"]}', '[0, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Dziennik Joanny porusza: samotność guwernantki bez własnego domu, żałobę po bracie Wacławie (zmarł na zesłaniu/podróży naukowej), refleksje o roli kobiet w społeczeństwie. Joanna nie planuje podróży do Paryża — tam był Judym."}', '2026-03-17 21:41:53.221', '2026-03-17 21:41:53.221', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wjq000rqhhm9bjyiwfn', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Które informacje o Krzywosądzie Chobrzańskim są prawdziwe?', '{"options": ["Jest administratorem zakładu w Cisach", "Był wcześniej antykwariuszem w Monachium", "Sam naprawia urządzenia w zakładzie — jest majsterkowiczem-samoukiem", "Popiera reformy Judyma dotyczące osuszenia stawów"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Krzywosąd to administrator Cisów, dawny antykwariusz z Monachium, samouk-majsterkowicz. Nie popiera reform Judyma — wręcz przeciwnie, broni istniejących urządzeń wodnych i dochodzi do fizycznej konfrontacji z Judymem."}', '2026-03-17 21:41:53.223', '2026-03-17 21:41:53.223', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wjs000sqhhm0hbd08nv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 2, 'Dlaczego Judym czuje „dług” wobec biedoty, choć sam nie wyrządził jej krzywdy?', '{"options": ["Ponieważ wzbogacił się kosztem robotników", "Ponieważ sam pochodząc z nędzy i z niej się wydostawszy, czuje, że jego wykształcenie jest przywilejem opłaconym cierpieniem klasy, z której się wywodzi", "Ponieważ obiecał to swojemu ojcu na łożu śmierci", "Ponieważ tak nakazuje mu kodeks lekarski"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Judym uważa, że jako syn szewca, który dzięki ciotce zdobył wykształcenie, jest „zdrajcą” swojej klasy — każdy awans społeczny odbywa się kosztem tych, którzy zostali na dole. Jego dług nie jest osobisty, lecz klasowy i moralny."}', '2026-03-17 21:41:53.225', '2026-03-17 21:41:53.225', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wjv000tqhhm0ex7orqc', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 2, 'Jak można zinterpretować pytanie „Kto płacze?” z ostatniej sceny powieści?', '{"options": ["Judym po prostu nie rozpoznaje głosu Joanny w ciemności", "Pytanie rozmywa granicę między cierpieniem jednostki (Joasia) a cierpieniem zbiorowym (kopalnia, przyroda) — to wyraz uniwersalizacji bólu", "Judym halucynuje z powodu wyczerpania fizycznego", "To retoryczne pytanie skierowane do czytelnika, kto jest winny rozstania"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Pytanie „Kto płacze?” jest kulminacją symbolizmu powieści. Żeromski celowo zaciera granicę między płaczem Joasi, „płaczem” kopalni i „płaczem” rozdartej sosny — cierpienie jest wszechobecne i uniwersalne, obejmuje ludzi, przyrodę i cywilizację przemysłową."}', '2026-03-17 21:41:53.227', '2026-03-17 21:41:53.227', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wjx000uqhhmtz0cc8eb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 2, 'Jaką rolę ideową pełni postać M. Lesa (Leszczykowskiego) wobec Judyma?', '{"options": ["Jest antagonistą Judyma — bogaczem, który blokuje reformy", "Jest wzorem „idealnego pozytywisty” — łączy sukces finansowy z filantropią i marzycielskim idealizmem, ale działa z dystansu", "Jest mentorem Judyma — uczy go technik chirurgicznych", "Jest komicznym kontrapunktem — ekscentryczny kupiec bez wpływu na fabułę"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "M. Les to bogaty kupiec z Konstantynopola, największy udziałowiec Cisów, który finansuje reformy z „cichej kasy”. Łączy praktykę kupiecką z idealizmem — marzy o ucywilizowaniu rodzinnej okolicy, ale nigdy tam nie przyjeżdża. Jest pozytywnym wzorem, z którym Judym nie potrafi jednak w pełni się utożsamić — Les działa pieniędzmi, Judym — czynem."}', '2026-03-17 21:41:53.229', '2026-03-17 21:41:53.229', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wk0000vqhhm6mkbr9ag', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 2, 'Co oznacza „pavor nocturnus” Korzeckiego i jaką ma funkcję w powieści?', '{"options": ["To choroba serca, która zmusza go do rezygnacji z pracy — funkcja fabularna", "To lęk nocny — nawracający strach przed śmiercią, który symbolizuje egzystencjalną samotność wrażliwego intelektualisty bez celu życia", "To alergia na pyły kopalniane — ilustracja warunków pracy w Zagłębiu", "To metafora artystyczna oznaczająca tęsknotę za ojczyzną"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Pavor nocturnus (lęk nocny) Korzeckiego to nawracający, paraliżujący strach przed śmiercią. Symbolizuje los wrażliwego intelektualisty, który nie znalazł drogi do czynu — w przeciwieństwie do Judyma, który sublimuje cierpienie w działanie społeczne. Korzecki to ostrzeżenie: co stanie się z Judymem, jeśli straci cel."}', '2026-03-17 21:41:53.232', '2026-03-17 21:41:53.232', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wk2000wqhhmmqlzjfea', 'CLOSED_SINGLE', 'LANGUAGE_USE', 'YOUNG_POLAND', 4, 2, 'Co oznacza określenie „powieść o luźnej kompozycji” w odniesieniu do „Ludzi bezdomnych”?', '{"options": ["Powieść nie ma żadnej struktury — jest chaotyczna", "Fabuła jest epizodyczna, brak ciągłej linii akcji — poszczególne rozdziały funkcjonują jako względnie samodzielne obrazy", "Powieść składa się z niezwiązanych opowiadań różnych autorów", "Kolejność rozdziałów można dowolnie przestawiać bez utraty sensu"]}', '1', NULL, '{language_use,closed_single,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "„Luźna kompozycja” to cecha powieści młodopolskiej: zamiast ciągłej, linearnej fabuły mamy serię obrazów (Paryż, Warszawa, Cisy, Zagłębie), połączonych postacią Judyma, ale o dużej autonomii. Każdy rozdział-obraz ma własną dramaturgię i nastrój. To nie chaos, lecz świadomy zamysł artystyczny."}', '2026-03-17 21:41:53.235', '2026-03-17 21:41:53.235', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wk5000xqhhm8q40n2uu', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 2, 'Które z poniższych par postaci tworzą kontrasty ideowe w powieści?', '{"options": ["Judym i Karbowski — idealizm społeczny vs. hedonistyczna bezcelowość", "Judym i Korzecki — czyn vs. bierność (obaj wrażliwi, ale różne drogi)", "Joanna i Natalia — samodzielność intelektualna vs. romantyczne uniesienie", "Węglichowski i Krzywosąd — obaj jednoznacznie wspierają reformy Judyma"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Żeromski buduje system kontrastów: Judym (czyn) vs Karbowski (bezcelowość), Judym (działanie) vs Korzecki (bierność prowadząca do samobójstwa), Joanna (intelektualna niezależność) vs Natalia (romantyczny poryw). Węglichowski i Krzywosąd obaj PRZECIWSTAWIAJĄ się reformom Judyma."}', '2026-03-17 21:41:53.237', '2026-03-17 21:41:53.237', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wkc000yqhhmj2b6e6b3', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 2, 'Które cechy wyróżniają Joannę Podborską jako postać nowatorską na tle epoki?', '{"options": ["Prowadzi dziennik — ma własny głos narracyjny w powieści zdominowanej przez męską perspektywę", "Utrzymuje się samodzielnie z pracy nauczycielskiej", "Jest bogatą arystokratką, która z wyboru pracuje jako guwernantka", "Reflektuje o roli kobiet, edukacji i niezależności — porusza tematy feministyczne"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Joanna jest postacią nowatorską: ma własny głos narracyjny (dziennik), utrzymuje się z pracy (nauczycielka, guwernantka), porusza kwestie feministyczne. Nie jest arystokratką — pochodzi ze zubożałej rodziny ziemiańskiej, pracuje z konieczności, nie z wyboru."}', '2026-03-17 21:41:53.244', '2026-03-17 21:41:53.244', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wke000zqhhmx3zbehkg', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 2, 'Które z poniższych tez o powieści „Ludzie bezdomni” są uzasadnione?', '{"options": ["Żeromski łączy w powieści postulaty pozytywistycznej pracy u podstaw z modernistyczną wrażliwością artystyczną", "Powieść jest manifestem rewolucji robotniczej wzywającym do walki zbrojnej", "Kompozycja powieści opiera się na ruchu przestrzennym bohatera — Paryż, Warszawa, Cisy, Zagłębie", "Narracja jest wyłącznie obiektywna i zdystansowana, jak u Prusa"]}', '[0, 2]', NULL, '{historical_literary,closed_multiple,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Żeromski łączy pozytywistyczny postulat pomocy biednym z modernistyczną formą (symbolizm, impresjonizm, liryzacja). Kompozycja oparta jest na trasie bohatera: Paryż → Warszawa → Cisy → Zagłębie. Powieść NIE jest manifestem rewolucji ani narracją obiektywną — narrator jest emocjonalnie zaangażowany."}', '2026-03-17 21:41:53.246', '2026-03-17 21:41:53.246', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wkg0010qhhmrh93ma2z', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 3, 'Jak można zinterpretować scenę w Luwrze — zestawienie Wenus z Milo i „Ubogiego rybaka” — w kontekście całej powieści?', '{"options": ["To przypadkowe tło fabularne — Żeromski umieszcza bohaterów w muzeum dla kolorytu", "To ekspozycja dwóch biegunów świata Judyma — piękna i nędzy — które definiują jego wewnętrzny konflikt i zapowiadają tragiczny wybór w finale", "To krytyka sztuki muzealnej jako oderwany od życia luksus", "To wyłącznie pretekst do wprowadzenia postaci Joanny — sam kontrast dzieł nie ma znaczenia symbolicznego"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Scena w Luwrze to programowy prolog powieści: Wenus z Milo (piękno, miłość, szczęście) i „Ubogi rybak” (nędza, cierpienie) to dwa bieguny, między którymi rozgrywa się cała fabuła. Judym jest wrażliwy na oba — potrafi cieszyć się pięknem i cierpieć na widok nędzy. Ta podwójna wrażliwość skazuje go na tragizm."}', '2026-03-17 21:41:53.249', '2026-03-17 21:41:53.249', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wkj0011qhhmoqinmyvv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 3, 'Co odróżnia stosunek Żeromskiego do nędzy od pozytywistycznego ujęcia tego tematu u Prusa?', '{"options": ["Prus opisuje nędzę szczegółowiej niż Żeromski", "Żeromski łączy opis nędzy z emocjonalnym zaangażowaniem narratora i technikami lirycznymi, podczas gdy Prus zachowuje obiektywny dystans realisty", "Żeromski unika tematu nędzy — koncentruje się na psychice bohaterów", "Obaj autorzy traktują nędzę identycznie — różnią się wyłącznie fabularnie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Kluczowa różnica: Prus jako realista opisuje nędzę z dystansem, pozwalając faktom mówić za siebie (np. spacer Wokulskiego po Powiślu). Żeromski jako modernista angażuje narratora emocjonalnie — stosuje liryzację, psychizację pejzażu, mowę pozornie zależną, zmuszając czytelnika do przeżycia nędzy „od wewnątrz”."}', '2026-03-17 21:41:53.251', '2026-03-17 21:41:53.251', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wkl0012qhhmsis3zl38', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 3, 'Dlaczego powieść „Ludzie bezdomni” bywa klasyfikowana jednocześnie jako powieść społeczna, psychologiczna i symboliczna?', '{"options": ["Ponieważ krytycy literaccy nie potrafią uzgodnić jednej klasyfikacji", "Ponieważ opisuje nędzę społeczną (społeczna), analizuje wewnętrzne rozterki i motywacje bohaterów (psychologiczna) i posługuje się obrazami-symbolami: Wenus, rybak, sosna (symboliczna)", "Ponieważ Żeromski pisał ją z myślą o trzech różnych grupach czytelników", "Ponieważ każdy z dwóch tomów reprezentuje inny gatunek"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Wielogatunkowość „Ludzi bezdomnych” wynika z bogactwa tekstu: warstwa społeczna (krytyka nędzy, wyzysku, systemu klasowego), psychologiczna (analiza motywacji Judyma, dziennik Joanny, pavor nocturnus Korzeckiego) i symboliczna (Wenus = piękno, Rybak = nędza, sosna = rozdarcie) współistnieją, tworząc syntezę typową dla modernizmu."}', '2026-03-17 21:41:53.254', '2026-03-17 21:41:53.254', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wko0013qhhmg54nl1ew', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 3, 'Które z poniższych analogii między „Ludźmi bezdomnymi” a innymi tekstami kultury są uzasadnione?', '{"options": ["Judym i Antygona — oboje stawiają imperatyw moralny ponad osobiste szczęście, za co płacą samotność/śmiercią", "Judym i Raskolnikow — obaj popełniają zbrodnię motywowaną ideologicznie", "Joanna i Jane Eyre — obie są guwernatkami walczącymi o godność i niezależność", "Korzecki i Werter — obaj popełniają samobójstwo z powodu niespełnionej miłości"]}', '[0, 2]', NULL, '{historical_literary,closed_multiple,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Analogia Judym–Antygona: oboje wybierają wyższy imperatyw moralny kosztem osobistego szczęścia. Joanna–Jane Eyre: obie są guwernatkami, sierotami, walczącymi o podmiotowość. Raskolnikow popełnia zbrodnię — Judym nie. Korzecki nie ginie z powodu niespełnionej miłości, lecz z egzystencjalnego lęku."}', '2026-03-17 21:41:53.257', '2026-03-17 21:41:53.257', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wkq0014qhhmmnc3mzgp', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 3, 'Które aspekty powieści świadczą o wpływie filozofii schyłku XIX wieku na Żeromskiego?', '{"options": ["Nietzscheański motyw samotnego jednostki przekraczającej normy społeczne (Judym)", "Schopenhauerowski pesymizm — cierpienie jako fundament egzystencji (Korzecki, nędzarze)", "Bergsona intuicjonizm — Judym działa instynktownie, poza rozumem", "Dekadencki motyw bezsensu i rozpadu — samobójstwo Korzeckiego, bezsilność Judyma wobec systemu"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Żeromski czerpie z Nietzschego (Judym jako samotny „nadczłowiek na opak”), Schopenhauera (świat jako cierpienie — nędzarze, Korzecki) i dekadentyzmu (bezsilność wobec systemu, samobójstwo jako ostateczność). Bergsonowski intuicjonizm nie jest wyrazistym kontekstem powieści — Judym działa raczej z imperatywu moralnego niż z intuicji."}', '2026-03-17 21:41:53.259', '2026-03-17 21:41:53.259', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wkt0015qhhmwimwhcsi', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 3, 'Wyjaśnij, dlaczego Żeromski umieścił scenę w Luwrze na początku powieści. Jaką funkcję kompozycyjną i symboliczną pełni ten fragment?', '{"instruction": "Odwołaj się do Wenus z Milo, „Ubogiego rybaka” i pierwszego spotkania Judyma z Joasią."}', '"Scena w Luwrze pełni funkcję ekspozycji — zapowiada kluczowe wątki powieści. Wenus z Milo symbolizuje piękno, harmonię i miłość (zapowiedź wątku Judym–Joasia). „Ubogi rybak” symbolizuje nędzę i krzywdę (zapowiedź wątku społecznego). Kontrast między nimi prefiguruje centralny konflikt powieści — rozdarcie Judyma między pragnieniem pięknego życia a obowiązkiem wobec biedoty. Spotkanie z Joasią w tym samym miejscu łączy oba bieguny: miłość i idea spotykają się w muzeum, ale okaże się, że nie mogą współistnieć w życiu bohatera."', NULL, '{historical_literary,short_answer,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Kompozycyjna rola prologu muzealnego jest typowym pytaniem maturalnym. Wymaga rozpoznania techniki zapowiedzi (foreshadowing) i umiejętności łączenia symboli z fabułą."}', '2026-03-17 21:41:53.261', '2026-03-17 21:41:53.261', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wkv0016qhhmd365dtpp', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 3, 'Porównaj postawę doktora Węglichowskiego i Tomasza Judyma wobec problemów sanitarnych w Cisach. Kto ma rację?', '{}', '"Węglichowski to doświadczony lekarz, ceniony dyrektor — podchodzi do problemów pragmatycznie, chroni stabilność zakładu i interesy kuracjuszów. Judym to młody idealiasta — widzi malarię, odkrywa jej przyczynę (stojąca woda), domaga się radykalnych zmian (osuszenie stawów). Węglichowski ma rację z perspektywy zarządzania (nie można zniszczyć infrastruktury bez planu), Judym — z perspektywy medycznej (stojąca woda zabija ludzi). Konflikt ilustruje szerszy problem: czy reformy powinny być ostrożne i stopniowe, czy radykalne i natychmiastowe."', NULL, '{historical_literary,short_answer,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Pytanie wymaga umiejętności analizy konfliktu bez jednoznacznego opowiedzenia się po jednej stronie — na maturze ceniona jest umiejętność dostrzegania racji obu stron."}', '2026-03-17 21:41:53.264', '2026-03-17 21:41:53.264', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wkz0017qhhmp08b4axf', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 3, 'Czy Judym jest postacią prometeuszowską? Uzasadnij, odwołując się do mitu o Prometeuszu i do tekstu powieści.', '{"instruction": "Wskaż cechy łączące Judyma z Prometeuszem i cechy różniące ich losy."}', '"Cechy prometeuszowskie Judyma: bunt przeciw istniejącemu porządkowi, poświęcenie osobistego szczęścia dla dobra ludzkości, samotność jako cena heroizmu, sprzeciw wobec „bogów” (klasa rządząca, lekarze-konserwatyści). Różnice: Prometeusz daje ogień — konkretny dar; Judym próbuje, ale niewiele osiąga — jego walka jest syzyfowa. Prometeusz cierpi z winy Zeusa (kara); Judym cierpi z własnego wyboru. Judym jest zatem „Prometeuszem bez ognia” — niesie w sobie zapał, ale system uniemożliwia mu skuteczne działanie."', NULL, '{historical_literary,short_answer,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Porównanie z Prometeuszem to klasyczny kontekst interpretacyjny na maturze rozszerzonej. Kluczowe jest dostrzeżenie zarówno podobieństw, jak i różnic — Judym nie jest prostym powtórzeniem mitu."}', '2026-03-17 21:41:53.267', '2026-03-17 21:41:53.267', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wl10018qhhmw2zhvmn1', 'SHORT_ANSWER', 'LANGUAGE_USE', 'YOUNG_POLAND', 5, 3, 'Jakie funkcje pełnią w powieści opisy przyrody? Podaj trzy przykłady i określ, jaką techniką narracyjną posługuje się Żeromski.', '{}', '"Opisy przyrody pełnią funkcje: 1) Psychizacja pejzażu — jesienny park w „Smutku” odzwierciedla przygnębienie Judyma po nieudanym odczycie. 2) Kontrapunkt emocjonalny — wiosenna przyroda w „Przyjdź” (kwitnące krzewy, ciepło) wyraża tęsknotę miłosną i nadzieję. 3) Symbolika — rozdarta sosna na końcu powieści symbolizuje rozdarcie duszy Judyma, krople żywicy = łzy/cierpienie. Technika to „żeromszczyzna” — łączenie impresjonizmu (migotliwość wrażeń), symbolizmu (przyroda jako znak) i liryzacji prozy (poetycki, emocjonalny język opisu)."', NULL, '{language_use,short_answer,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Pytanie łączy analizę literacką z wiedzą o technikach narracyjnych. Kluczowe terminy: psychizacja pejzażu, liryzacja prozy, impresjonizm, symbolizm."}', '2026-03-17 21:41:53.27', '2026-03-17 21:41:53.27', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wl40019qhhmcmf1npp4', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 5, 3, 'Oceń decyzję Judyma z perspektywy etyki utylitarystycznej. Czy jego rozstanie z Joasią maksymalizuje „sumę szczęścia”?', '{"instruction": "Odwołaj się do pojęcia utylitaryzmu (działanie słuszne = przynoszące najwięcej dobra dla największej liczby osób)."}', '"Z perspektywy utylitarystycznej: Judym poświęca szczęście dwóch osób (swoje i Joasi), by pracować dla tysięcy biednych. Matematycznie — decyzja jest słuszna, bo suma szczęścia rośnie. ALE: Judym nie wie, czy jego praca przyniesie realne efekty — może być Syzyfem, który cierpi na darmo. Utylitarysta zapytałby: czy Judym z Joasią u boku nie byłby skuteczniejszym lekarzem? Czy szczęśliwy człowiek nie pomaga lepiej niż nieszczęśliwy samotnik? Powieść nie rozstrzyga — ale pokazuje, że Judym kieruje się etyką kantowską (obowiązek moralny), nie utylitarystyczną (efekt)."', NULL, '{historical_literary,short_answer,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Pytanie wymaga zastosowania filozofii etycznej do tekstu literackiego — to wymaganie typowe dla matury rozszerzonej na najwyższym poziomie."}', '2026-03-17 21:41:53.272', '2026-03-17 21:41:53.272', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wl6001aqhhmcp9yxmdl', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 4, 4, 'Napisz notatkę syntetyczną na podany temat:', '{"topic": "System kontrastów w „Ludziach bezdomnych” — jak Żeromski zestawia postacie, miejsca i symbole, by budować wymowę ideową powieści", "wordLimit": {"max": 200, "min": 150}, "requirements": ["Wskaż co najmniej dwie pary kontrastujących postaci (np. Judym–Karbowski, Judym–Korzecki)", "Wskaż kontrast przestrzenny (np. salon Czerniszów–sutereny, Luwr–Château-Rouge)", "Wskaż kontrast symboliczny (Wenus–Rybak)", "Wyjaśnij, jak te kontrasty budują przesłanie powieści", "150-200 słów"]}', '"Notatka powinna obejmować: kontrasty postaci — Judym (czyn, idealizm) vs Karbowski (bezcelowość, hedonizm); Judym (działanie) vs Korzecki (bierność → samobójstwo); Joanna (samodzielność) vs Natalia (romantyczne uniesienie). Kontrasty przestrzenne — Luwr (piękno) vs Château-Rouge (nędza); salon Czerniszów (elegancja) vs sutereny Ciepłej (brud); park w Cisach (przyroda) vs cynkownia w Zagłębiu (przemysł). Kontrast symboliczny — Wenus z Milo (piękno, harmonia) vs „Ubogi rybak” (cierpienie). Przesłanie: piękno i nędza współistnieją w świecie, a wrażliwy człowiek (Judym) musi wybrać, któremu biegunowi poświęci życie."', NULL, '{historical_literary,synthesis_note,difficulty-4,young_poland,batch-2025-01}', '{"explanation": "Analiza kontrastów to jedna z najskuteczniejszych metod interpretacji powieści Żeromskiego. Na maturze ceniona jest umiejętność dostrzegania opozycji binarnych i ich funkcji w tekście."}', '2026-03-17 21:41:53.274', '2026-03-17 21:41:53.274', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv50wl8001bqhhm3r1xzp1k', 'ESSAY', 'WRITING', 'YOUNG_POLAND', 5, 35, 'Czy literatura powinna budzić sumienie społeczne? Rozważ problem, odwołując się do „Ludzi bezdomnych” Żeromskiego i jednego innego tekstu kultury.', '{"wordLimit": {"min": 300}, "requirements": ["Sformułuj tezę — czy funkcją literatury jest wpływanie na postawy społeczne czytelników?", "Przeanalizuj, jak Żeromski próbuje wstrząsnąć sumieniem czytelnika (opisy nędzy, los Judyma)", "Porównaj z innym tekstem kultury zaangażowanym społecznie (np. „Przedwiośnie”, „Granica”, „Dżuma” Camusa)", "Rozważ kontrargument — literatura jako sztuka czysta, bez misji społecznej (l''art pour l''art)", "Sformułuj wniosek z argumentacją", "Minimum 300 słów"]}', '"Rozprawka powinna: zdefiniować pojęcie literatury zaangażowanej; pokazać, jak Żeromski budzi sumienie czytelnika (naturalistyczne opisy nędzy, dramatyczny los Judyma, symbol rozdartej sosny); porównać z innym tekstem (np. „Przedwiośnie” — krytyka odrodzonej Polski, „Dżuma” — solidarność wobec cierpienia); rozważyć stanowisko przeciwne (modernistyczny postulat sztuki czystej — Przybyszewski, „Confiteor”); sformułować wniosek — np. że najlepsza literatura łączy wartość artystyczną z zaangażowaniem (jak właśnie u Żeromskiego)."', NULL, '{writing,essay,difficulty-5,young_poland,batch-2025-01}', '{"explanation": "Temat łączy refleksję o literaturze z refleksją o etyce — typowy dla matury rozszerzonej. Kluczowe jest umieszczenie powieści w kontekście dyskusji o funkcjach literatury."}', '2026-03-17 21:41:53.277', '2026-03-17 21:41:53.277', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp520000qhfg5nyvqkyd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Kto jest autorem zbioru opowiadań „Sklepy cynamonowe”?', '{"options": ["Witold Gombrowicz", "Bruno Schulz", "Stanisław Ignacy Witkiewicz", "Bolesław Leśmian"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "„Sklepy cynamonowe” to zbiór opowiadań Brunona Schulza, wydany w 1933 roku (postdatowany na 1934) dzięki protekcji Zofii Nałkowskiej. Jest jednym z najważniejszych dzieł polskiego dwudziestolecia międzywojennego."}', '2026-03-17 22:22:09.734', '2026-03-17 22:22:09.734', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp580001qhfg6k7wdfkd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Jak ma na imię ojciec narratora w „Sklepach cynamonowych”?', '{"options": ["Józef", "Jakub", "Jan", "Jerzy"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Ojciec narratora ma na imię Jakub — jak biblijny patriarcha z Księgi Rodzaju. To imię jest jednym z wielu nawiązań do tradycji biblijnej i żydowskiej obecnych w zbiorze."}', '2026-03-17 22:22:09.74', '2026-03-17 22:22:09.74', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp5b0002qhfgwpahcbay', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Jak nazywa się służąca w domu narratora?', '{"options": ["Maryśka", "Paulina", "Adela", "Polda"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Adela to służąca w domu narratora. Pełni kluczową rolę w zbiorze — symbolizuje zmysłową kobiecość i posiada nad ojcem niemal nieograniczoną władzę, której się bezwzględnie poddaje."}', '2026-03-17 22:22:09.743', '2026-03-17 22:22:09.743', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp5e0003qhfg5yxddx3v', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'W jakim mieście rozgrywa się akcja „Sklepów cynamonowych”?', '{"options": ["W Warszawie", "We Lwowie", "W niewymienionym z nazwy galicyjskim miasteczku wzorowanym na Drohobyczu", "W Krakowie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Akcja toczy się w małym galicyjskim miasteczku, nigdy niewymienianym z nazwy. Schulz wzorował je na rodzinnym Drohobyczu, nadając mu cechy mityczne — labiryntową przestrzeń, metamorfozy ulic i domów."}', '2026-03-17 22:22:09.746', '2026-03-17 22:22:09.746', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp5g0004qhfgvp5a3270', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Ile opowiadań zawiera zbiór „Sklepy cynamonowe”?', '{"options": ["Dziesięć", "Dwanaście", "Piętnaście", "Dwadzieścia"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Zbiór „Sklepy cynamonowe” składa się z piętnastu opowiadań, od „Sierpnia” do „Nocy wielkiego sezonu”. Tworzą one luźną kompozycję powieściową, połączoną postaciami i przestrzenią."}', '2026-03-17 22:22:09.749', '2026-03-17 22:22:09.749', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp5j0005qhfghyxsxh5s', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Czym z zawodu zajmuje się ojciec narratora?', '{"options": ["Jest nauczycielem", "Jest kupcem — prowadzi sklep z suknem", "Jest lekarzem", "Jest rzemieślnikiem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Ojciec narratora jest kupcem — prowadzi sklep z suknem i materiałami na rynku miasteczka. Jednak w oczach syna jest kimś znacznie więcej: demiurgiem, magiem, filozofem i poetą."}', '2026-03-17 22:22:09.751', '2026-03-17 22:22:09.751', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp5l0006qhfgqhlnm1gs', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Które z wymienionych postaci pojawiają się w „Sklepach cynamonowych”?', '{"options": ["Adela — służąca", "Ciotka Agata", "Doktor Czernisz", "Wuj Marek"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Adela, ciotka Agata i wuj Marek to postacie ze „Sklepów cynamonowych”. Doktor Czernisz to postać z „Ludzi bezdomnych” Żeromskiego."}', '2026-03-17 22:22:09.754', '2026-03-17 22:22:09.754', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp5o0007qhfgd5qkcj2j', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Które opowiadania wchodzą w skład zbioru „Sklepy cynamonowe”?', '{"options": ["„Sierpień”", "„Ptaki”", "„Emeryt”", "„Karakony”"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,interwar,batch-2025-01}', '{"explanation": "„Sierpień”, „Ptaki” i „Karakony” to opowiadania ze „Sklepów cynamonowych”. „Emeryt” to opowiadanie z drugiego zbioru Schulza — „Sanatorium Pod Klepsydrą”."}', '2026-03-17 22:22:09.757', '2026-03-17 22:22:09.757', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp5r0008qhfgvh2geucq', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Które stwierdzenia o zbiorze „Sklepy cynamonowe” są prawdziwe?', '{"options": ["Narrator opowiada w pierwszej osobie", "Zbiór został wydany w 1933 roku", "Schulz napisał go w Warszawie", "Zbiór ukazał się dzięki protekcji Zofii Nałkowskiej"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Narracja jest pierwszoosobowa (narrator = Józef). Zbiór wydano w 1933 r. dzięki Nałkowskiej. Schulz pisał go w Drohobyczu, nie w Warszawie — nigdy na stałe nie opuścił rodzinnego miasta."}', '2026-03-17 22:22:09.76', '2026-03-17 22:22:09.76', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp5u0009qhfgd8orjrip', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Co ojciec narratora hoduje na strychu w opowiadaniu „Ptaki”?', '{"options": ["Koty i psy", "Egzotyczne ptaki wylęgane z zapłodnionych jaj", "Rośliny tropikalne", "Karakony w celach naukowych"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "W „Ptakach” ojciec sprowadza zapłodnione jaja ptasie z Hamburga, Holandii i Afryki, daje je do wylęgania kurom belgijskim i urządza na strychu „ptasie królestwo” — prawdziwą arkę Noego, do której zlatują się ptaki z dalekich stron."}', '2026-03-17 22:22:09.762', '2026-03-17 22:22:09.762', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp5w000aqhfg05gx3be2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Kto kończy „ptasią imprezę” ojca, rozpędzając ptaki ze strychu?', '{"options": ["Matka", "Adela", "Wuj Marek", "Narrator (Józef)"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Adela, „podobna do szalejącej Menady”, wdziera się na strych z długą szczotką i w wirze piór rozpędza całą ptasią gromadę. Ojciec schodzi ze schodów jak „król-banita, który stracił tron i królowanie”."}', '2026-03-17 22:22:09.765', '2026-03-17 22:22:09.765', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp5z000bqhfgm2h4q1gc', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Do jakiego biblijnego motywu nawiązuje dach domu narratora, gdy ojciec hoduje na nim ptaki?', '{"options": ["Wieża Babel", "Arka Noego", "Ogród Eden", "Arka Przymierza"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Schulz wprost pisze, że dach „stał się prawdziwą gospodą ptasią, arką Noego, do której zlatywały się wszelkiego rodzaju skrzydlacze z dalekich stron”. Ojciec jest kreowany na biblijnego patriarchę."}', '2026-03-17 22:22:09.767', '2026-03-17 22:22:09.767', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp61000cqhfgcbfcpb56', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Czego narrator poszukuje podczas nocnej wędrówki w tytułowym opowiadaniu „Sklepy cynamonowe”?', '{"options": ["Drogi do domu po nocnym spacerze", "Portfelu ojca — ale po drodze chce odwiedzić tajemnicze sklepy cynamonowe", "Apteki z lekami dla chorego ojca", "Szkoły, w której odbywają się nocne lekcje"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Ojciec w teatrze stwierdza, że zapomniał portfelu z pieniędzmi i dokumentami. Narrator zostaje wysłany do domu po niego, ale po drodze próbuje odnaleźć tajemnicze sklepy cynamonowe — i gubi się w labiryncie nocnych ulic."}', '2026-03-17 22:22:09.77', '2026-03-17 22:22:09.77', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp64000dqhfg4ypmm8is', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Co ojciec głosi w „Traktacie o Manekinach”?', '{"options": ["Że manekiny mają duszę i cierpią", "Że Demiurgos nie ma monopolu na tworzenie — materia jest żywa i można ją formować, tworząc „wtórego człowieka” na obraz manekina", "Że manekiny powinny zastąpić ludzi w fabrykach", "Że sztuka jest bezwartościowa wobec natury"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "W „Traktacie o Manekinach” ojciec wygłasza heretycką doktrynę o materii: twierdzi, że każdy duch może tworzyć, że materia jest żywa i płodna, i postuluje stworzenie „wtórej demiurgii” — istot prowizorycznych, z tandety, na obraz manekina."}', '2026-03-17 22:22:09.772', '2026-03-17 22:22:09.772', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp68000eqhfgc2geydki', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Które cechy charakteryzują ojca narratora w „Sklepach cynamonowych”?', '{"options": ["Jest ekscentryczny i pogrąża się w obsesyjnych zainteresowaniach", "Wygłasza pseudofilozoficzne prelekcje o materii i tworzeniu", "Jest typowym, praktycznym kupcem bez wyobraźni", "Stopniowo zanika fizycznie — maleje, chudnie, znika"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Ojciec jest ekscentrykiem, filozofem-demiurgiem, wygłasza prelekcje o materii i manekinach. Stopniowo zanika — maleje jak „orzech zsychający się w łupinie”, aż jego resztki Adela wymata jak kupkę śmieci. Nie jest praktycznym kupcem — tę rolę pełni matka."}', '2026-03-17 22:22:09.777', '2026-03-17 22:22:09.777', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp6b000fqhfgnfv01cng', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Uzupełnij zdania, wybierając poprawne opcje:', '{"gaps": [{"id": 1, "options": ["powieścią realistyczną", "prozą poetycką", "dramatem lirycznym", "poematem prozą"]}, {"id": 2, "options": ["wszechwiedzącego narratora", "dziecka / dorosłego wspominającego dzieciństwo", "ojca narratora", "Adeli"]}, {"id": 3, "options": ["linearny i historyczny", "cykliczny i mityczny", "ściśle chronologiczny", "odwrócony (od końca)"]}], "textWithGaps": "Zbiór „Sklepy cynamonowe” to gatunek zwany (1). Narrator opowiada z perspektywy (2). Czas w utworze jest (3), nie linearny."}', '[1, 1, 1]', NULL, '{historical_literary,closed_multiple,difficulty-2,interwar,batch-2025-01}', '{"explanation": "„Sklepy cynamonowe” to proza poetycka — łączy cechy prozy i poezji. Narrator opowiada z podwójnej perspektywy dziecka i dorosłego. Czas jest cykliczny i mityczny — wyznaczają go pory roku, nie daty."}', '2026-03-17 22:22:09.779', '2026-03-17 22:22:09.779', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp6d000gqhfggp0f430g', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Które z poniższych zwierząt i istot pojawiają się w „Sklepach cynamonowych”?', '{"options": ["Kondor — ogromny ptak podobny do ojca", "Piesek Nemrod", "Koń dorożkarski, który mówi ludzkim głosem", "Wilk atakujący miasteczko"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Kondor z „Ptaków” przypomina ojca fizycznie. Piesek Nemrod pojawia się w opowiadaniu o tym samym tytule. Koń dorożkarski w „Sklepach cynamonowych” mówi do narratora. Wilk nie występuje w zbiorze."}', '2026-03-17 22:22:09.782', '2026-03-17 22:22:09.782', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp6g000hqhfgh8cc4slm', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Które pory roku odgrywają kluczową rolę w strukturze zbioru?', '{"options": ["Lato — upał, dojrzewanie, zmysłowość (opowiadanie „Sierpień”)", "Zima — szarość, nuda, metamorfozy ojca (opowiadania „Ptaki”, „Manekiny”)", "Wiosna — budzenie się przyrody po powstaniu styczniowym", "Jesień — Wielki Sezon, handel, ptasie powroty (opowiadanie „Noc wielkiego sezonu”)"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Lato (żar, zmysłowość), zima (szarość, eksperymenty ojca) i jesień (Wielki Sezon handlowy, powrót ptaków) to trzy kluczowe pory w cyklu. Wiosna i powstanie styczniowe nie są motywami tego zbioru."}', '2026-03-17 22:22:09.784', '2026-03-17 22:22:09.784', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp6i000iqhfgoqnc11qw', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Kim jest Tłuja i w jakim opowiadaniu się pojawia?', '{"hints": ["opowiadanie „Sierpień”", "łóżko na śmietnisku", "córka Maryśki"]}', '"Tłuja to upośledzona umysłowo dziewczyna, córka starej Maryśki. Pojawia się w opowiadaniu „Sierpień”. Siedzi na łóżku stojącym na śmietnisku za parkanem, wśród łopuchów i chwastów. Schulz opisuje ją jako „bożka pogańskiego” — symbol dzikiej, sierpniowej płodności natury."', NULL, '{historical_literary,short_answer,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Tłuja to jedna z najbardziej naturalistycznych i jednocześnie mitycznych postaci zbioru. Jej scena na śmietnisku łączy brzydotę z sacrum — jest figurą pogańskiej płodności sierpniowej natury."}', '2026-03-17 22:22:09.787', '2026-03-17 22:22:09.787', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp6l000jqhfgyr3cxgin', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Jaką funkcję pełni postać Adeli wobec ojca w zbiorze „Sklepy cynamonowe”?', '{"options": ["Jest mu posłuszna i wykonuje wszystkie jego polecenia", "Reprezentuje niszczycielską siłę zmysłowej kobiecości — ma nad ojcem absolutną władzę i niszczy jego twórcze światy", "Jest jego intelektualną partnerką i wspiera jego eksperymenty", "Nie ma z ojcem żadnych interakcji — zajmuje się wyłącznie domem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Adela symbolizuje zmysłową kobiecość i cielesność, która triumfuje nad duchowymi dążeniami ojca. Rozpędza jego ptaki, grozi mu palcem (łaskotki), a ojciec reaguje paniką i poddańczym lękiem. To relacja masochistyczna — ojciec-demiurg upada przed zmysłową siłą służącej."}', '2026-03-17 22:22:09.789', '2026-03-17 22:22:09.789', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp6o000kqhfg92v6mw0i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Co oznacza pojęcie „demiurgia” w kontekście prelekcji ojca z „Traktatu o Manekinach”?', '{"options": ["Naukowe tworzenie sztucznych organizmów w laboratorium", "Heretyckie pragnienie tworzenia na wzór Boga — lecz z tandety, prowizoryczne, na jeden raz", "Reformę systemu edukacji w miasteczku", "Hodowlę egzotycznych zwierząt na strychu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Ojciec postuluje „wtórą demiurgię” — tworzenie istot na obraz manekina, z tandety i kłaków, prowizorycznych, „na jeden raz zrobionych”. Jest to herezja wobec doskonałości Demiurgosa (Boga), ale wyraża umiłowanie materii jako takiej — jej „puszystości i porowatości”."}', '2026-03-17 22:22:09.792', '2026-03-17 22:22:09.792', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp6v000lqhfgwuipd7co', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Co symbolizuje Ulica Krokodyli w zbiorze?', '{"options": ["Tradycyjną, szlachetną część miasteczka z bogatą historią", "Tandetną, pseudoamerykańską dzielnicę handlową — świat pozorów, imitacji i moralnej degradacji", "Dzielnicę artystów i intelektualistów", "Tajemnicze sklepy cynamonowe, do których narrator nie może trafić"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Ulica Krokodyli to dzielnica tandetnego komercjalizmu — „pseudoamerykanizm zaszczepiony na starym gruncie”. Wszystko tam jest szare, imitacyjne, papierowe. Rzeczywistość „jest cienka jak papier i zdradza swą imitatywność”. To antyświat wobec magicznego miasteczka — krytyka nowoczesnej cywilizacji."}', '2026-03-17 22:22:09.8', '2026-03-17 22:22:09.8', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp71000mqhfgm68d583s', 'CLOSED_SINGLE', 'LANGUAGE_USE', 'INTERWAR', 3, 2, 'Czym jest oniryzm w kontekście „Sklepów cynamonowych”?', '{"options": ["Techniką opisu snów bohaterów w realizmie psychologicznym", "Konwencją literacką, w której rzeczywistość kreowana jest na wzór snu — zaburzona logika, metamorfozy, zacieranie granic jawy i marzenia", "Metodą naukowej analizy snów, inspirowaną Freudem", "Gatunkiem literackim, do którego należy zbiór"]}', '1', NULL, '{language_use,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Oniryzm (z gr. oneiros = sen) to konwencja literacka, w której świat przedstawiony ma cechy marzenia sennego: irracjonalność, metamorfozy, płynność czasu i przestrzeni. U Schulza oniryzm nie jest motywem, lecz formą narracji — cała rzeczywistość zbioru ma strukturę snu."}', '2026-03-17 22:22:09.805', '2026-03-17 22:22:09.805', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp74000nqhfguu1ltiqu', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Co dzieje się z ojcem w opowiadaniu „Karakony”?', '{"options": ["Ojciec prowadzi wojnę z karakonami, ale stopniowo sam zaczyna się w nie przemieniać", "Ojciec wynajduje sposób na pozbycie się karakonów z domu", "Ojciec ucieka z domu przed inwazją karakonów", "Karakony okazują się ptakami, które ojciec hodował na strychu"]}', '0', NULL, '{historical_literary,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "W „Karakonach” ojciec najpierw wchodzi w szaloną wojnę z inwazją karakonów, ale stopniowo fascynacja wstrętem wciąga go — zaczyna naśladować ich ruchy, na ciele pojawiają się czarne plamy. W końcu „zlewa się z tym czarnym plemieniem” i nie można go odróżnić od owadów. To groteska metamorfozy, nawiązująca do Kafki."}', '2026-03-17 22:22:09.809', '2026-03-17 22:22:09.809', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp77000oqhfggc529eww', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Połącz opowiadania z ich kluczowymi motywami:', '{"leftColumn": [{"id": "A", "text": "„Sierpień”"}, {"id": "B", "text": "„Ptaki”"}, {"id": "C", "text": "„Traktat o Manekinach”"}, {"id": "D", "text": "„Ulica Krokodyli”"}], "rightColumn": [{"id": "1", "text": "Filozofia materii, wtóra demiurgia, tandeta"}, {"id": "2", "text": "Tandetna dzielnica handlowa, świat pozorów"}, {"id": "3", "text": "Upał, dojrzewanie sierpniowe, Tłuja"}, {"id": "4", "text": "Hodowla egzotycznych ptaków na strychu"}], "matchingType": "characters_to_traits"}', '[[0, 2], [1, 3], [2, 0], [3, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-3,interwar,batch-2025-01}', '{"explanation": "„Sierpień” — żar lata, Tłuja jako symbol płodności. „Ptaki” — ojciec hoduje egzotyczne ptaki, Adela je rozpędza. „Traktat o Manekinach” — ojciec głosi heretycką doktrynę o materii i wtórej demiurgii. „Ulica Krokodyli” — pseudoamerykańska dzielnica tandety i pozorów."}', '2026-03-17 22:22:09.811', '2026-03-17 22:22:09.811', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp7a000pqhfgmjpm88kn', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Które elementy biblijne i mitologiczne obecne są w „Sklepach cynamonowych”?', '{"options": ["Ojciec jako prorok Starego Testamentu dialogujący z Jehową (opowiadanie „Nawiedzenie”)", "Dach domu jako Arka Noego (opowiadanie „Ptaki”)", "Motyw Odysa wracającego do domu po wojnie trojańskiej", "Adela porównana do Menady — szalejącej kapłanki Dionizosa"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Ojciec dialoguje z Jehową jak prorok (Nawiedzenie), dach staje się Arką Noego (Ptaki), Adela jest porównana do Menady (Ptaki). Motyw Odysa nie pojawia się w zbiorze — choć motyw wędrówki i labiryntu jest obecny."}', '2026-03-17 22:22:09.814', '2026-03-17 22:22:09.814', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp7c000qqhfg2bhfcdyx', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', 'INTERWAR', 3, 2, 'Które techniki literackie stosuje Schulz w „Sklepach cynamonowych”?', '{"options": ["Mityzacja — nadawanie codzienności cech mitu", "Synestezja — łączenie wrażeń różnych zmysłów", "Konsekwentny realizm społeczny w duchu pozytywizmu", "Animizacja — ożywianie przedmiotów i materii"]}', '[0, 1, 3]', NULL, '{language_use,closed_multiple,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Schulz stosuje mityzację (ojciec jako patriarcha, miasteczko jako mityczna kraina), synestezję (dźwięki mają barwy, barwy — zapachy), animizację (tapety rosną, lampy więdną, meble „oddychają”). Realizm społeczny jest mu całkowicie obcy."}', '2026-03-17 22:22:09.817', '2026-03-17 22:22:09.817', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp7e000rqhfgymbwlzwe', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Które z poniższych metamorfoz ojca zachodzą w zbiorze?', '{"options": ["Ojciec maleje, chudnie i stopniowo zanika fizycznie", "Ojciec przybiera pozy ptaków — pieje jak kogut, trzepoce rękami", "Ojciec zamienia się w karakona", "Ojciec przekształca się w drzewo"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Ojciec maleje fizycznie (Nawiedzenie), naśladuje ptaki — pieje, trzepoce rękami (Ptaki), przemienia się w karakona — naśladuje ich ruchy, ciało pokrywają czarne plamy (Karakony). Metamorfoza w drzewo nie występuje."}', '2026-03-17 22:22:09.819', '2026-03-17 22:22:09.819', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp7h000sqhfg4govknws', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Co wydarzyło się z koniem dorożkarskim pod koniec opowiadania „Sklepy cynamonowe”?', '{"instruction": "Opisz scenę i wyjaśnij jej symboliczne znaczenie."}', '"Koń dorożkarski wiezie narratora przez magiczną zimową noc, aż zatrzymuje się wyczerpany w śniegu. Na jego brzuchu widać czarną ranę. Na pytanie narratora odpowiada: „Drogi mój — to dla ciebie” i staje się mały jak konik z drzewa. To scena poświęcenia — koń oddaje życie za podróż chłopca. Symbolizuje ofiarność, ale też oniryczną logikę snu, w którym zwierzę mówi ludzkim głosem."', NULL, '{historical_literary,short_answer,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Scena z koniem to kulminacja oniryzmu — zwierzę mówi, poświęca się, zmienia rozmiar. Łączy bajkowość (mówiący koń) z tragizmem (ofiara) i symboliką chrześcijańską (poświęcenie za kogoś)."}', '2026-03-17 22:22:09.821', '2026-03-17 22:22:09.821', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp7j000tqhfgg38okmcz', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 3, 'Napisz notatkę syntetyczną na podany temat:', '{"topic": "Metamorfozy ojca w „Sklepach cynamonowych” — od kupca do demiurga, od demiurga do owada", "wordLimit": {"max": 150, "min": 100}, "requirements": ["Wymień co najmniej trzy etapy przemiany ojca", "Wskaż opowiadania, w których zachodzą poszczególne metamorfozy", "Wyjaśnij, co te metamorfozy symbolizują", "100-150 słów"]}', '"Notatka powinna obejmować: 1) Ojciec jako kupiec i ekscentryk (Sierpień, Nawiedzenie) — choroba, monologi, dialog z Bogiem. 2) Ojciec jako demiurg — hodowla ptaków (Ptaki), prelekcje o materii (Traktat o Manekinach). 3) Ojciec jako istota zanikająca — maleje, naśladuje ptaki, pieje jak kogut (Nawiedzenie, Ptaki). 4) Ojciec jako karakon — fascynacja przeradza się w metamorfozę, zlewa się z owadami (Karakony). Symbolika: degradacja od ducha do materii, od twórcy do stworzenia, od Boga do robaka — jak biblijny Hiob."', NULL, '{historical_literary,synthesis_note,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Metamorfozy ojca są osią kompozycyjną zbioru. Schulz kreuje ojca jako figurę archetypową — od patriarchy i demiurga po istotę zanikającą, „kupkę śmieci” wymiecioną przez Adelę."}', '2026-03-17 22:22:09.823', '2026-03-17 22:22:09.823', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp7l000uqhfgr6ih4fk7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 4, 2, 'Dlaczego tytułowe sklepy cynamonowe można interpretować jako symbol utraconej arkadii dzieciństwa?', '{"options": ["Bo narrator odwiedza je regularnie i kupuje tam zabawki", "Bo istnieją jako niedościgłe pragnienie — narrator nigdy do nich nie dociera, a ich egzotyczność ucieleśnia magiczny świat dziecięcej wyobraźni, do którego dorosły nie może powrócić", "Bo są jedynym miejscem w miasteczku, gdzie ojciec jest szczęśliwy", "Bo przechowują w nich pamiątki po dzieciństwie narratora"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,interwar,batch-2025-01}', '{"explanation": "Sklepy cynamonowe to miejsce mityczne — narrator pamięta ich zapach kadzidła, egzotyczne towary, rzadkie książki, ale podczas nocnej wędrówki nigdy do nich nie dociera. Są metaforą dziecięcego zachwytu światem, który dorosły wspomina z tęsknotą, ale którego nie może odzyskać."}', '2026-03-17 22:22:09.826', '2026-03-17 22:22:09.826', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp7o000vqhfg8sxk9qmt', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 4, 2, 'Jak rozumieć zdanie ojca: „Nie ma materii martwej — martwota jest jedynie pozorem, za którym ukrywają się nieznane formy życia”?', '{"options": ["Ojciec jest naukowcem i formułuje hipotezę biologiczną", "To centralna teza jego filozofii demiurgicznej — materia jest żywa, płodna, pełna ukrytych form, czeka na impuls twórczy, by się objawić", "Ojciec cytuje podręcznik fizyki kwantowej", "To żart skierowany do szwaczek Poldy i Pauliny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,interwar,batch-2025-01}', '{"explanation": "Zdanie to jest kluczem do filozofii ojca-demiurga: materia nie jest bierna — „faluje od nieskończonych możliwości”, „kusi tysiącem słodkich okrąglizn”. To pseudoreligijna doktryna witalistyczna, w której Schulz łączy filozofię, mistykę żydowską i surrealizmem."}', '2026-03-17 22:22:09.828', '2026-03-17 22:22:09.828', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp7q000wqhfgc33teqf4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 4, 2, 'Co łączy „Karakony” Schulza z „Przemianą” Kafki?', '{"options": ["Obie opowieści rozgrywają się w Pradze", "W obu utworach bohater ulega metamorfozie w owada — u Kafki jest to nagła przemiana Gregora Samsy, u Schulza stopniowa degradacja ojca, który „zlewa się” z plemieniem karakonów", "Oba utwory są satyrą na życie urzędnicze w Austro-Węgrzech", "Kafka i Schulz byli przyjaciółmi i wspólnie wymyślili motyw metamorfozy"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,interwar,batch-2025-01}', '{"explanation": "Parallela Schulz–Kafka jest klasycznym kontekstem maturalnym. U Kafki metamorfoza jest nagła i dosłowna — Gregor budzi się jako robak. U Schulza jest stopniowa, groteskowa i mityczna — ojciec wchłania karakoni rytuał, aż staje się od nich nieodróżnialny. Obie metamorfozy wyrażają degradację i wyobcowanie."}', '2026-03-17 22:22:09.83', '2026-03-17 22:22:09.83', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp7s000xqhfg3zevrdfg', 'CLOSED_SINGLE', 'LANGUAGE_USE', 'INTERWAR', 4, 2, 'Czym jest mityzacja w prozie Schulza?', '{"options": ["Wiernym odtworzeniem mitów greckich w realiach XX-wiecznej Polski", "Zabiegiem nadającym codzienności cechy mitu — czas staje się cykliczny, ojciec archetypem, miasteczko labiryntem, a zwykłe wydarzenia zyskują wymiar sakralny", "Techniką polegającą na wymyślaniu nowych mitów dla celów propagandowych", "Opisywaniem snów, w których pojawiają się postaci mitologiczne"]}', '1', NULL, '{language_use,closed_single,difficulty-4,interwar,batch-2025-01}', '{"explanation": "Mityzacja u Schulza to kreowanie rzeczywistości na wzór mitu: czas jest cykliczny (pory roku, nie daty), ojciec to archetyp (patriarcha, demiurg, prorok), przestrzeń jest labiryntowa i metamorficzna. Schulz nie opowiada mitów — on mitologizuje codzienność galicyjskiego miasteczka."}', '2026-03-17 22:22:09.832', '2026-03-17 22:22:09.832', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp7u000yqhfgtdtjymfd', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 4, 2, 'Które z poniższych interpretacji postaci ojca są uzasadnione tekstem?', '{"options": ["Ojciec jako alter ego samego Schulza — artysta-wizjoner pokonany przez prozę codzienności", "Ojciec jako starotestamentowy Bóg — demiurg, prorok, patriarcha z imienia (Jakub)", "Ojciec jako krytyk kapitalizmu walczący z wyzyskiem robotników", "Ojciec jako figura masochistyczna — poddaje się władzy Adeli i destrukcji swoich światów"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-4,interwar,batch-2025-01}', '{"explanation": "Ojciec jest wieloznaczny: alter ego Schulza (artysta przegrywający z banałem), figura biblijna (Jakub, Noe, prorok, demiurg), postać masochistyczna (poddańcze relacje z Adelą). Nie jest krytykiem kapitalizmu — „Ulica Krokodyli” to Schulzowski komentarz, ale nie wypowiedź ojca."}', '2026-03-17 22:22:09.835', '2026-03-17 22:22:09.835', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp7x000zqhfggadbwoi8', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 4, 2, 'Które cechy „Sklepów cynamonowych” świadczą o przynależności do awangardy literackiej dwudziestolecia?', '{"options": ["Oniryzm — zacieranie granicy między jawą a snem", "Surrealistyczne metamorfozy — ludzie zamieniają się w ptaki i owady", "Linearna, chronologiczna fabuła z wyraźnym początkiem i końcem", "Proza poetycka — liryzacja języka, synestezja, metaforyczność opisu"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-4,interwar,batch-2025-01}', '{"explanation": "Schulz to awangardzista: oniryzm (senna logika narracji), surrealizm (metamorfozy, ożywianie materii), proza poetycka (język nasycony metaforą, synestezją, rytmem). Fabuła NIE jest linearna ani chronologiczna — jest luźna, epizodyczna, cykliczna."}', '2026-03-17 22:22:09.838', '2026-03-17 22:22:09.838', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp7z0010qhfga7rwixv5', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 4, 2, 'Które z poniższych opozycji organizują świat „Sklepów cynamonowych”?', '{"options": ["Ojciec (duch, wyobraźnia, kreacja) vs. Adela (ciało, zmysłowość, destrukcja)", "Lato (żar, płodność, bujność) vs. zima (szarość, nuda, pustka)", "Miasto (harmonia, piękno) vs. wieś (zacofanie, nędza)", "Magiczne miasteczko (autentyczność, mit) vs. Ulica Krokodyli (tandeta, imitacja, pozór)"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-4,interwar,batch-2025-01}', '{"explanation": "Trzy kluczowe opozycje: ojciec/Adela (duch vs ciało), lato/zima (pełnia vs pustka), miasteczko/Ulica Krokodyli (autentyczność vs tandeta). Opozycja miasto/wieś nie jest obecna — cała akcja toczy się w miasteczku."}', '2026-03-17 22:22:09.84', '2026-03-17 22:22:09.84', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp820011qhfgflq2mj4r', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'INTERWAR', 4, 3, 'Jaką rolę pełni motyw labiryntu w zbiorze? Podaj co najmniej dwa przykłady z różnych opowiadań.', '{}', '"Labirynt jest kluczową metaforą przestrzeni w zbiorze: 1) Miasteczko jako labirynt — w „Sklepach cynamonowych” narrator gubi się w nocnych ulicach, które zmieniają konfigurację, otwierają się „ulice podwójne, ulice sobowtóry”. 2) Dom rodzinny jako labirynt — w „Nawiedzeniu” mieszkanie nie ma „określonej liczby pokojów”, lokatorzy znikają, a pokoje się zapominają. 3) Psychika ojca jako labirynt — „myśl jego zapuszczała się tajnie w labirynty własnych wnętrzności”. Labirynt symbolizuje zagubienie, nieosiągalność celu i nieskończoność wyobraźni."', NULL, '{historical_literary,short_answer,difficulty-4,interwar,batch-2025-01}', '{"explanation": "Motyw labiryntu to jeden z najważniejszych w zbiorze — łączy przestrzeń, psychikę i narrację. Na maturze często pojawia się w pytaniach o kreację przestrzeni u Schulza."}', '2026-03-17 22:22:09.842', '2026-03-17 22:22:09.842', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp840012qhfg60ykhjy4', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'INTERWAR', 4, 4, 'Napisz notatkę syntetyczną na podany temat:', '{"topic": "Ojciec jako demiurg i herezjarcha — analiza „Traktatu o Manekinach” w kontekście filozofii tworzenia", "wordLimit": {"max": 200, "min": 150}, "requirements": ["Wyjaśnij, czym jest „wtóra demiurgia” i czemu ojciec ją postuluje", "Odnieś się do stosunku ojca do materii (apologia tandety)", "Porównaj demiurgię ojca z twórczością Boga-Demiurgosa", "Oceń, czy ojciec jest twórcą, czy szaleńcem", "150-200 słów"]}', '"Notatka powinna: wyjaśnić, że ojciec chce tworzyć nie w konkurencji z Bogiem, lecz „we własnej, niższej sferze” — z tandety, papier-mâché, kłaków. Jego twory mają być prowizoryczne, „na jeden raz”, z jedną ręką i jedną nogą. Apologia tandety = miłość do materii „jako takiej” — jej puszystości, oporności, niedźwiedziowatości. Kontrast z Demiurgosem: Bóg ukrywa materię pod grą życia, ojciec chce ją odsłonić. Ocena: ojciec jest jednocześnie genialnym wizjonerem (artysta tworzący nowe światy) i tragicznym szaleńcem (jego twory rozsypują się, a sam zostaje pokonany przez Adelę)."', NULL, '{historical_literary,synthesis_note,difficulty-4,interwar,batch-2025-01}', '{"explanation": "„Traktat o Manekinach” to manifest artystyczny Schulza — wyrażony ustami ojca. Apologia tandety to apologia sztuki nieperfekcyjnej, ludzkiej, skazanej na porażkę, ale przez to autentycznej."}', '2026-03-17 22:22:09.844', '2026-03-17 22:22:09.844', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp870013qhfgy5cwwwqc', 'ESSAY', 'WRITING', 'INTERWAR', 4, 5, 'Dzieciństwo jako utracony raj. Rozważ problem, odwołując się do „Sklepów cynamonowych” Brunona Schulza i jednego innego tekstu kultury.', '{"wordLimit": {"min": 300}, "requirements": ["Wyjaśnij, jak Schulz kreuje dzieciństwo narratora — jako czas mityczny, magiczny, nieodzyskiwalny", "Odwołaj się do co najmniej dwóch opowiadań ze zbioru", "Porównaj z innym tekstem kultury (np. „Pan Tadeusz” — Soplicowo, „Mały Książę” — planeta, „Ferdydurke” — powrót do dzieciństwa)", "Sformułuj wniosek: czy tęsknota za dzieciństwem jest uniwersalna?", "Minimum 300 słów"]}', '"Rozprawka powinna: pokazać dzieciństwo u Schulza jako czas magiczny (Sierpień — zmysłowość lata, Sklepy cynamonowe — ekscytacja nocnej wędrówki, Nemrod — odkrywanie życia), kreowany jako mit (czas cykliczny, przestrzeń labiryntowa, ojciec jako bóstwo). Porównanie: np. z Panem Tadeuszem (Soplicowo = utracony raj szlachecki, epilog = tęsknota emigranta) lub Małym Księciem (planeta = świat prostoty utraconej w dorosłości). Wniosek: tęsknota za dzieciństwem jest uniwersalnym doświadczeniem, ale Schulz pokazuje, że dzieciństwo nie jest wspomnieniem faktów, lecz wspomnieniem sposobu widzenia — intensywności, wrażliwości, magii."', NULL, '{writing,essay,difficulty-4,interwar,batch-2025-01}', '{"explanation": "Motyw utraconego dzieciństwa to jeden z najczęstszych tematów maturalnych w kontekście Schulza. Kluczowe: dzieciństwo u Schulza nie jest realistycznym wspomnieniem, lecz mityczną rekonstrukcją."}', '2026-03-17 22:22:09.847', '2026-03-17 22:22:09.847', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp890014qhfg4odt4f2p', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 5, 3, 'Jak można zinterpretować stosunek ojciec–Adela w kontekście masochizmu Schulzowskiego?', '{"options": ["Adela jest po prostu dobrą służącą, a ojciec szanuje jej pracę — relacja jest neutralna", "Adela reprezentuje triumf cielesności i zmysłowości nad duchem i wyobraźnią — ojciec poddaje się jej z rozkosznym lękiem, co odzwierciedla Schulzowski masochizm: ekstatyczne uleganie kobiecej sile jako formę quasi-religijnego rytuału", "Ojciec kontroluje Adelę i wykorzystuje ją do swoich eksperymentów", "Relacja jest wyłącznie komiczna — Schulz parodiuje domowe hierarchie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,interwar,batch-2025-01}', '{"explanation": "Relacja ojciec–Adela to centralna oś masochizmu Schulzowskiego, widocznego też w grafice „Xięgi Bałwochwalczej”. Ojciec-demiurg, władca ptasiego królestwa, pada na kolana przed pantofelkiem Adeli. Kobiecość jest siłą niszczycielską, ale zarazem fascynującą — ojciec doświadcza „rozkosznego spazmu” wobec jej władzy."}', '2026-03-17 22:22:09.849', '2026-03-17 22:22:09.849', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp8b0015qhfgz8sbsntg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 5, 3, 'Dlaczego „Ulicę Krokodyli” można czytać jako metapoetycką refleksję Schulza o naturze fikcji?', '{"options": ["Bo Schulz cytuje w niej innych pisarzy, budując intertekstualny dialog", "Bo narrator wprost opisuje rzeczywistość tej dzielnicy jako „cienką jak papier”, imitatywną, „fotomontaż z wycinków zeszłorocznych gazet” — dzielnica jest fikcją w fikcji, obnażającą mechanizm literackiej iluzji", "Bo opowiadanie jest autobiograficzną relacją z wizyty Schulza w wielkim mieście", "Bo ulica nosi imię zwierzęcia, co zawsze oznacza alegorię"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,interwar,batch-2025-01}', '{"explanation": "„Ulica Krokodyli” to jedyne opowiadanie, w którym narrator odsłania iluzoryczność świata przedstawionego: „rzeczywistość jest cienka jak papier”, „nic nie dochodzi do skutku”, wszystko „zdradza swą imitatywność”. To metafikcja — Schulz komentuje własną technikę tworzenia światów, które nie mają substancji, lecz tylko pozór."}', '2026-03-17 22:22:09.851', '2026-03-17 22:22:09.851', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp8d0016qhfgymo2qdmh', 'CLOSED_SINGLE', 'LANGUAGE_USE', 'INTERWAR', 5, 3, 'Co oznacza synestezja w kontekście prozy Schulza i który fragment najlepiej ją ilustruje?', '{"options": ["Synestezja to opis przyrody za pomocą metafor — „złota żyła dnia” jest zwykłą metaforą, nie synestezją", "Synestezja to łączenie wrażeń różnych zmysłów — w cytacie cisza jest zmysłowa (dotyk, wzrok), blaski „śnią” (personifikacja), melodia wydobywa się z „żyły” dnia (dźwięk = materia)", "Synestezja to technika malarstwa abstrakcyjnego, nie literatury", "Synestezja oznacza tu, że narrator nie rozróżnia swoich zmysłów z powodu choroby"], "sourceText": {"text": "Cisza drgających słojów powietrznych, kwadraty blasku, śniące żarliwy swój sen na podłodze; melodia katarynki, dobyta z najgłębszej złotej żyły dnia.", "title": "Sklepy cynamonowe — Sierpień", "author": "Bruno Schulz"}}', '1', NULL, '{language_use,closed_single,difficulty-5,interwar,batch-2025-01}', '{"explanation": "Synestezja (z gr. syn + aisthesis = współ-odczuwanie) to łączenie wrażeń z różnych zmysłów. U Schulza jest fundamentem stylu: cisza ma „słoje” (dotyk), blaski „śnią” (personifikacja), melodia wydobywa się z „złotej żyły” (dźwięk = materia, głębia). Proza Schulza jest architekturą zmysłów — nie opisuje, lecz konstruuje doznania."}', '2026-03-17 22:22:09.853', '2026-03-17 22:22:09.853', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp8f0017qhfgkhk4vx5l', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 5, 3, 'Które porównania międzytekstowe z innymi dziełami są uzasadnione?', '{"options": ["Schulz i Kafka — metamorfoza człowieka w owada (Karakony vs Przemiana)", "Schulz i Proust — dzieciństwo jako utracony czas, odzyskiwany przez wspomnienia zmysłowe", "Schulz i Sienkiewicz — panorama społeczna XIX-wiecznej Polski", "Schulz i Gombrowicz — groteska, deformacja rzeczywistości, podważanie formy (choć innymi środkami)"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-5,interwar,batch-2025-01}', '{"explanation": "Kafka: metamorfoza w owada. Proust: wspomnienie zmysłowe jako klucz do utraconego czasu (madlenka = owoce Adeli). Gombrowicz: obaj deformują rzeczywistość, stosują groteskę, podważają konwencje — choć Schulz lirycznie, a Gombrowicz intelektualnie. Sienkiewicz i panorama społeczna są Schulzowi zupełnie obcy."}', '2026-03-17 22:22:09.856', '2026-03-17 22:22:09.856', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp8h0018qhfgeymkl9p5', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 5, 3, 'Które aspekty „Sklepów cynamonowych” nawiązują do tradycji i mistyki żydowskiej?', '{"options": ["Imię ojca — Jakub, jak patriarcha z Księgi Rodzaju", "Motyw Księgi — kalendarza jako „wielkiej księgi roku” zawierającej wszelką wiedzę", "Demiurgia ojca — nawiązanie do kabalistycznego pojęcia tworzenia przez emanację", "Monotematyczny opis życia polskiej szlachty w Galicji"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-5,interwar,batch-2025-01}', '{"explanation": "Schulz czerpie z tradycji żydowskiej: Jakub = patriarcha, Księga = Tora/wiedza/kalendarz, demiurgia = kabalistyczne tworzenie przez emanację (sefirot). Ojciec jest jednocześnie prorokiem, Noem i kabalistą. Opis szlachty galicyjskiej jest obcy temu zbiorowi."}', '2026-03-17 22:22:09.858', '2026-03-17 22:22:09.858', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp8k0019qhfgvhw9enl8', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'INTERWAR', 5, 4, 'Porównaj kreację przestrzeni w „Sklepach cynamonowych” Schulza z kreacją przestrzeni w innym dziele literackim. Wskaż podobieństwa i różnice.', '{"instruction": "Odwołaj się do motywu labiryntu, metamorfozy przestrzeni i funkcji, jaką pełni przestrzeń w obu utworach."}', '"U Schulza przestrzeń jest oniryczna, labiryntowa, płynna — ulice zmieniają konfigurację, dom ma nieokreśloną liczbę pokojów, miasteczko jest zarazem konkretne i mityczne. Porównanie np. z Kafką („Proces” — biurokracja jako labirynt, sąd ukryty na strychach kamienic) lub z „Panem Tadeuszem” (Soplicowo jako arkadyjska przestrzeń zamknięta, stabilna — przeciwieństwo Schulzowskiej metamorfozy). Różnica: u Schulza przestrzeń jest projekcją psychiki narratora (dziecięca wyobraźnia przetwarza realia), u Kafki — projekcją systemu opresji, u Mickiewicza — projekcją tęsknoty emigranta."', NULL, '{historical_literary,short_answer,difficulty-5,interwar,batch-2025-01}', '{"explanation": "Kreacja przestrzeni to jedno z najczęstszych pytań maturalnych o Schulza (egzamin rozszerzony). Kluczowe: przestrzeń u Schulza nie jest tłem, lecz bohaterem — podlega metamorfozom jak postacie."}', '2026-03-17 22:22:09.86', '2026-03-17 22:22:09.86', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp8m001aqhfg02vvsquw', 'SHORT_ANSWER', 'LANGUAGE_USE', 'INTERWAR', 5, 4, 'Wyjaśnij, dlaczego „Sklepy cynamonowe” nazywane są prozą poetycką. Podaj trzy cechy stylu Schulza, które uzasadniają to określenie.', '{}', '"Proza poetycka to gatunek łączący prozę z poezją: 1) Metaforyczność — Schulz nie opisuje, lecz przetwarza rzeczywistość w łańcuchy metafor (lato to „wielka księga wakacji”, lampy „więdną jak bodiaki”, tapety „rosną” nocą). 2) Synestezja i rytm — łączenie zmysłów (cisza ma „słoje”, melodia katarynki wydobywa się z „złotej żyły dnia”), zdania mają rytm i kadencję poetycką. 3) Dominacja obrazu nad fabułą — fabuła jest pretekstowa, najważniejsza jest wizja, nastrój, barwa, intensywność doznania zmysłowego. Schulz nie opowiada historii — tworzy obrazy poetyckie w formie prozy."', NULL, '{language_use,short_answer,difficulty-5,interwar,batch-2025-01}', '{"explanation": "Pytanie o prozę poetycką Schulza jest klasycznym pytaniem maturalnym z zakresu LANGUAGE_USE. Kluczowe terminy: metaforyzacja, synestezja, liryzacja prozy, dominacja obrazu nad fabułą."}', '2026-03-17 22:22:09.862', '2026-03-17 22:22:09.862', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp8o001bqhfg5x0qxx5t', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'INTERWAR', 5, 5, 'Napisz notatkę syntetyczną na podany temat:', '{"topic": "„Sklepy cynamonowe” wobec tradycji literackiej — jak Schulz dialoguje z Biblią, surrealizmem i ekspresjonizmem", "wordLimit": {"max": 250, "min": 200}, "requirements": ["Wskaż elementy biblijne (imiona, motywy, ojciec jako prorok/demiurg)", "Wskaż elementy surrealistyczne (oniryzm, metamorfozy, logika snu)", "Wskaż elementy ekspresjonistyczne (deformacja, intensywność doznań, groteska)", "Wyjaśnij, co jest specyficznie Schulzowskie — czego nie da się sprowadzić do żadnej z tych tradycji", "200-250 słów"]}', '"Notatka powinna: wskazać Biblię (Jakub, Noe, prorocy, Demiurgos, Księga), surrealizm (metamorfozy, oniryzm, automatyzm snu, irracjonalność), ekspresjonizm (deformacja rzeczywistości, groteska, intensywność, hiperbolizacja doznań zmysłowych). Specyficznie Schulzowskie: mityzacja codzienności galicyjskiego miasteczka — żadna tradycja z osobna nie tłumaczy tego, jak Schulz z prowincjonalnego sklepu z suknem tworzy kosmogonię, z ojca-kupca — Boga-Stwórcę, z pory roku — cykl mityczny. Schulz syntetyzuje tradycje w niepowtarzalny idiom: proza poetycka, która jest jednocześnie filozofią materii, teologią tworzenia i autobiografią wyobraźni."', NULL, '{historical_literary,synthesis_note,difficulty-5,interwar,batch-2025-01}', '{"explanation": "Pytanie o tradycje literackie jest typowe dla matury rozszerzonej (poziom 5). Kluczowe: Schulz nie „należy” do surrealizmu czy ekspresjonizmu — czerpie z nich, ale tworzy idiom niepasujący do żadnej szufladki."}', '2026-03-17 22:22:09.864', '2026-03-17 22:22:09.864', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp8q001cqhfg02i1c34q', 'ESSAY', 'WRITING', 'INTERWAR', 5, 10, 'Jaką rolę w literaturze pełni groteska? Rozważ problem, odwołując się do „Sklepów cynamonowych” Brunona Schulza i jednego innego tekstu kultury.', '{"wordLimit": {"min": 300}, "requirements": ["Zdefiniuj groteskę jako kategorię estetyczną (łączenie komizmu z tragizmem, deformacja, absurd)", "Przeanalizuj groteskę u Schulza: metamorfozy ojca, scena na urynale, relacja z Adelą, Tłuja", "Porównaj z innym tekstem kultury stosującym groteskę (np. „Ferdydurke” Gombrowicza, „Proces” Kafki, „Tango” Mrożka)", "Sformułuj wniosek: czy groteska odkrywa prawdę o świecie, czy go zaciemnia?", "Minimum 300 słów"]}', '"Rozprawka powinna: zdefiniować groteskę (deformacja, mieszanie rejestrów, śmiech i groza jednocześnie). U Schulza: ojciec-prorok siedzący na urynale, demiurg uciekający przed palcem Adeli, metamorfoza w karakona — tragiczne i komiczne zarazem. Porównanie: Gombrowicz (groteska jako demaskacja formy społecznej — Ferdydurke), Kafka (groteska jako absurd systemu — Proces), Mrożek (groteska jako krytyka ideologii — Tango). Wniosek: groteska u Schulza nie zaciemnia prawdy — odsłania ją: ludzka egzystencja jest jednocześnie wzniosła i żałosna, sakralna i śmieszna. Groteska jest narzędziem prawdy, nie ucieczką od niej."', NULL, '{writing,essay,difficulty-5,interwar,batch-2025-01}', '{"explanation": "Groteska to jedno z najczęstszych zagadnień maturalnych. Schulz jest wzorcowym przykładem groteski poetyckiej — łączy liryzm z absurdem, patos z komizmem."}', '2026-03-17 22:22:09.867', '2026-03-17 22:22:09.867', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp8t001dqhfget9pknnk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Kto jest autorem "Konrada Wallenroda"?', '{"options": ["Juliusz Slowacki", "Adam Mickiewicz", "Zygmunt Krasinski", "Cyprian Kamil Norwid"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "\"Konrad Wallenrod\" to powiesc poetycka Adama Mickiewicza, wydana w 1828 roku w Petersburgu. Utwor powstal w czasie zeslania poety w Rosji."}', '2026-03-17 22:22:09.869', '2026-03-17 22:22:09.869', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp8v001eqhfghepi8wgp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Jaki gatunek literacki reprezentuje "Konrad Wallenrod"?', '{"options": ["Ballada", "Powiesc poetycka", "Dramat romantyczny", "Poemat dygresyjny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "\"Konrad Wallenrod\" to powiesc poetycka -- gatunek synkretyczny laczacy elementy epiki (narracja), liryki (wierszowana forma, piesni) i dramatu (dialogi). Tworcami gatunku byli Walter Scott i George Byron."}', '2026-03-17 22:22:09.872', '2026-03-17 22:22:09.872', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp8x001fqhfgwhkyj8zk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Jak naprawde nazywa sie glowny bohater "Konrada Wallenroda"?', '{"options": ["Konrad von Wallenrod", "Walter Alf", "Halban", "Witold"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Prawdziwe imie bohatera to Walter Alf -- Litwin porwany jako dziecko przez Krzyzakow. Przybral tozsamosc rycerza Wallenroda, aby wniknac w struktury Zakonu i zniszczyc go od srodka."}', '2026-03-17 22:22:09.874', '2026-03-17 22:22:09.874', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp90001gqhfg0b8a8oup', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Gdzie rozgrywa sie glowna akcja "Konrada Wallenroda"?', '{"options": ["W Krakowie", "W Maryjenburgu (Malborku) -- siedzibie Zakonu Krzyzackiego", "W Wilnie", "W Petersburgu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Glowna akcja toczy sie w Maryjenburgu (Malborku) -- stolicy Zakonu Krzyzackiego. Poboczne watki dzieja sie na Litwie (Kowno, zamek Kiejstuta) i na pograniczu litewsko-pruskim."}', '2026-03-17 22:22:09.876', '2026-03-17 22:22:09.876', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp92001hqhfgdqt2705d', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Kim jest Aldona w utworze?', '{"options": ["Sluzaca w zamku krzyzackim", "Zona Waltera Alfa, corka ksiecia Kiejstuta, pustelnica zamknieta w wiezy", "Matka Konrada Wallenroda", "Zakonnica z klasztoru w Malborku"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Aldona to corka litewskiego ksiecia Kiejstuta i zona Waltera Alfa. Gdy maz odjezdza realizowac plan zemsty, Aldona zamyka sie w wiezy zamkowej jako pustelnica, aby byc blisko niego."}', '2026-03-17 22:22:09.878', '2026-03-17 22:22:09.878', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp94001iqhfg2bkuqk1r', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Kim jest Halban?', '{"options": ["Wielkim mistrzem Zakonu Krzyzackiego", "Starym wajdelota litewskim, opiekunem i powiernikiem Konrada", "Bratem Aldony", "Szpiegiem Krzyzakow na Litwie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Halban to stary wajdelota (bard litewski), ktory opiekowal sie Walterem Alfem od dziecinstwa, rozbudzal w nim milosc do Litwy i nienawsc do Krzyzakow. Jest zarowno spowiednikiem, jak i powiernikiem Konrada."}', '2026-03-17 22:22:09.88', '2026-03-17 22:22:09.88', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp96001jqhfg9bkzzoxq', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Ktore z ponizszych postaci wystepuja w "Konradzie Wallenrodzie"?', '{"options": ["Halban -- stary wajdelota", "Aldona -- zona Waltera Alfa", "Jacek Soplica", "Kiejstut -- ksiaze litewski"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Halban, Aldona i Kiejstut to postacie z \"Konrada Wallenroda\". Jacek Soplica to bohater \"Pana Tadeusza\" Mickiewicza."}', '2026-03-17 22:22:09.882', '2026-03-17 22:22:09.882', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp98001kqhfg6z7sfgb3', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Ktore informacje o utworze sa prawdziwe?', '{"options": ["Utwor zostal wydany w 1828 roku", "Akcja rozgrywa sie w XIV wieku", "Mickiewicz pisal go na zeslaniu w Rosji", "Jest to dramat w pieciu aktach"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "\"Konrad Wallenrod\" ukazal sie w 1828 r., akcja toczy sie w XIV w. (czasy walk Litwy z Zakonem), Mickiewicz pisal go na zeslaniu w Rosji (1825-1827). Nie jest to dramat -- to powiesc poetycka."}', '2026-03-17 22:22:09.885', '2026-03-17 22:22:09.885', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp9a001lqhfgz5k9sakd', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Ktore formy liryczne zawarte sa w "Konradzie Wallenrodzie"?', '{"options": ["Hymn do Ducha Swietego", "Piesn Wajdeloty", "Ballada \"Alpuhara\"", "Sonet krymski"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "W utworze znajduja sie: Hymn (spiewany na kapitule), Piesn Wajdeloty (o historii Litwy), ballada \"Alpuhara\" (o podstepu Almanzora). Sonety krymskie to odrebny cykl Mickiewicza."}', '2026-03-17 22:22:09.887', '2026-03-17 22:22:09.887', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp9e001mqhfghkiwygmx', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Z jakiego dziela pochodzi motto "Konrada Wallenroda" i co ono oznacza?', '{"hints": ["Machiavelli", "lis i lew", "Ksiaze"]}', '"Motto pochodzi z \"Ksiecia\" Niccola Machiavellego. W tlumaczeniu brzmi: trzeba byc lisem i lwem -- czyli laczyc sile z podstepem. Zapowiada ono glowny problem utworu: koniecznosc uzycia zdrady (lis) w walce z poteznym wrogiem (lew)."', NULL, '{historical_literary,short_answer,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Motto z Machiavellego jest kluczem interpretacyjnym do calego utworu. Konrad Wallenrod realizuje strategie lisa -- niszczy Zakon od srodka podstepem, bo w otwartej walce (lew) Litwa nie mogla wygrać."}', '2026-03-17 22:22:09.89', '2026-03-17 22:22:09.89', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp9g001nqhfgflir3f6k', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'W jaki sposob Walter Alf trafil do Krzyzakow?', '{"options": ["Dobrowolnie uciekl z Litwy", "Zostal porwany jako dziecko podczas najazdu Krzyzakow na litewskie miasto", "Zostal sprzedany przez litewskiego kupca", "Przybyl jako ambasador Kiejstuta"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Walter Alf zostal porwany jako male dziecko podczas nocnego najazdu Krzyzakow na litewskie miasto. Pamietalegal tylko krzyk matki i pozar. Wychowywal go mistrz krzyzacki Winrych."}', '2026-03-17 22:22:09.892', '2026-03-17 22:22:09.892', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp9i001oqhfgpt2rawl1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Co opowiada ballada "Alpuhara" spiewana przez Konrada na uczcie?', '{"options": ["Historie milosci Waltera i Aldony", "Historie Almanzora, ktory wraca do Hiszpanow udajac poddanie sie, aby zaraze ich dzuma", "Legende o zalozeniu Zakonu Krzyzackiego", "Opowiesc o wajdelocie Halbanie i jego piesniach"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Ballada \"Alpuhara\" opowiada o mauretanskim krolu Almanzorze, ktory po upadku twierdzy wraca do Hiszpanow, udajac ze chce sie poddac, ale w rzeczywistosci przynosi im zarase. To parabola wlasnego planu Konrada -- niszczenia wroga od srodka."}', '2026-03-17 22:22:09.894', '2026-03-17 22:22:09.894', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp9k001pqhfg21gpyj1p', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Czym jest wallenrodyzm?', '{"options": ["Otwarta walka zbrojna z wrogiem w obronie ojczyzny", "Postawa polegajaca na niszczeniu wroga od srodka za pomoca podstepu i zdrady, nawet kosztem wlasnego honoru i szczescia", "Pokojowe negocjacje z nieprzyjacielem", "Emigracja z ojczyzny w celu szukania pomocy za granica"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Wallenrodyzm to postawa bohatera, ktory niszczy wroga od srodka -- infiltruje jego struktury, zdobywa wladze, a nastepnie celowo prowadzi do kleski. Wymaga nieetycznego postepowania (zdrada, klamstwo) w imie wyzszego celu (obrona ojczyzny). Cena: utrata honoru, milosci, zycia."}', '2026-03-17 22:22:09.897', '2026-03-17 22:22:09.897', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp9m001qqhfg65yp1vxt', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Jak reaguje Witold na piesn Wajdeloty podczas uczty?', '{"options": ["Jest obojetny i nie slucha", "Blednie, czerwieni sie, w koncu wybucha placzem -- pieśn porusza jego sumienie zdrajcy", "Smieje sie i klaska", "Wychodzi z sali protestujac przeciw obecnosci Litwina"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Witold, litewski ksiaze ktory zdrazil ojczyzne i szuka sojuszu z Zakonem, reaguje gwaltownie: blednie, sinieje, czerwieni sie, sciska szable -- a na koncu wybucha placzem, zaslaniaiac twarz plaszczem. Piesn Wajdeloty poruszyła jego sumienie."}', '2026-03-17 22:22:09.899', '2026-03-17 22:22:09.899', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp9o001rqhfgv7r97ttb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Jak ginie Konrad Wallenrod?', '{"options": ["Zostaje stracony publicznie przez Krzyzakow", "Ginie w bitwie z Litwinami", "Wypija trucizne i umiera w swojej strzelnicy, zanim Krzyzacy zdaza go schwytac", "Ucieka do Litwy i ginie na granicy"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Konrad, wiedzac o wyroku tajnego trybunalu, wypija trucizne w swojej strzelnicy. Przed smiercia ciska lampe z okna -- sygnal dla Aldony, ze juz nie wróci. Aldona wydaje przerazliwy krzyk i rowniez umiera."}', '2026-03-17 22:22:09.901', '2026-03-17 22:22:09.901', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp9r001sqhfgb4119alw', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Polacz postacie z ich rolami w utworze:', '{"leftColumn": [{"id": "A", "text": "Walter Alf / Konrad"}, {"id": "B", "text": "Aldona"}, {"id": "C", "text": "Halban"}, {"id": "D", "text": "Witold"}], "rightColumn": [{"id": "1", "text": "Litewski zdrajca szukajacy sojuszu z Zakonem"}, {"id": "2", "text": "Wajdelota, stroz pamieci i sumienia bohatera"}, {"id": "3", "text": "Pustelnica zamknieta w wiezy z milosci do meza"}, {"id": "4", "text": "Litwin udajacy Krzyzaka, wielki mistrz-sabotazysta"}], "matchingType": "characters_to_traits"}', '[[0, 3], [1, 2], [2, 1], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Walter Alf/Konrad to Litwin infiltrujacy Zakon. Aldona zamknela sie w wiezy, by byc przy mezu. Halban to straznik pamieci narodowej. Witold to zdrajca, ktory jednak pod wplywem piesni odzyskuje sumienie."}', '2026-03-17 22:22:09.903', '2026-03-17 22:22:09.903', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp9t001tqhfgnuamoq86', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Uzupelnij zdania, wybierajac poprawne opcje:', '{"gaps": [{"id": 1, "options": ["slawie wojennej i pozornej poboznosci", "bogactwu i przekupstwu", "protekcji papieskiej", "pokrewienstwu z poprzednim mistrzem"]}, {"id": 2, "options": ["otrul zrodla wody w zamku", "prowadzil wojny tak, aby je przegrywac", "wysylal listy do Litwinow", "zabiial Krzyzakow we snie"]}, {"id": 3, "options": ["Halban od dziecinstwa", "Aldona przed slubem", "papiez listem", "Witold w czasie uczty"]}], "textWithGaps": "Konrad zostal wybrany wielkim mistrzem dzieki (1). Aby zniszczyc Zakon, ceolwo (2). Plan zniszczenia Zakonu zainspirowal go (3)."}', '[0, 1, 0]', NULL, '{historical_literary,closed_multiple,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Konrad zostal mistrzem dzieki slawie rycerskiej i pozornej poboznosci. Jego plan polegeal na celowym przegrywaniu wojen -- wyniszczyl armie Zakonu na litewskich stepach. Plan zemsty rozbudzal w nim od dziecinstwa wajdelota Halban."}', '2026-03-17 22:22:09.905', '2026-03-17 22:22:09.905', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp9v001uqhfgcnn1osv4', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Ktore z ponizszych motywow sa obecne w "Konradzie Wallenrodzie"?', '{"options": ["Motyw zdrady w imie wyzszego celu", "Motyw poety/pieśniarza jako straza pamieci narodowej", "Motyw nieszczesliwej milosci -- poswieconej dla ojczyzny", "Motyw sielanki wiejskiej i szczesliwego zycia na wsi"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "\"Konrad Wallenrod\" zawiera motywy: zdrady patriotycznej (wallenrodyzm), roli poety w narodzie (Piesn Wajdeloty o pieśni gminnej), nieszczesliwej milosci (Alf i Aldona). Nie ma motywu sielanki -- utwor jest peleon tragizmu."}', '2026-03-17 22:22:09.908', '2026-03-17 22:22:09.908', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gp9x001vqhfgs8uywzjp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Czym jest zabieg "maski historycznej" zastosowany w "Konradzie Wallenrodzie"?', '{"options": ["Uzyciem kostiumow i masek na balu w Malborku", "Osadzeniem akcji w sredniowiecznej Litwie, aby pod pozorem historii opowiadac o wspolczesnej sytuacji Polski pod zaborami", "Ukryciem twarzy bohatera pod szyszakiem rycerskim", "Zmiana nazwiska bohatera z Alf na Wallenrod"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Maska historyczna to zabieg polegajacy na ukryciu wspolczesnych tresci pod szata historyczna. Mickiewicz, piszac o walce Litwinow z Zakonem Krzyzackim (XIV w.), mowil w istocie o walce Polakow z zaborca rosyjskim (XIX w.). Zabieg pozwolil ominac cenzure caraska."}', '2026-03-17 22:22:09.91', '2026-03-17 22:22:09.91', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpa0001wqhfgf7dn3bxb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jaka jest funkcja Piesni Wajdeloty w kontekscie calego utworu?', '{"options": ["Sluzy wylacznie rozrywce gości na uczcie", "Jest manifestem o roli piesni gminnej jako skarbca pamieci narodowej -- zachowujacej tozsamosc narodu nawet po utracie panstwa", "Opowiada wylacznie o milosci Waltera i Aldony", "Jest modlitwa do Boga o pomoc w walce z Krzyzakami"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Piesn Wajdeloty to hymn o roli piesni gminnej (tradycji ustnej) w zyciu narodu: ''O wiesci gminna! Ty arko przymierza / Miedzy dawnymi i mlodszymi laty''. Piesn jest skarbcem pamieci -- przetrwa, gdy plomien rozgryzie malowane dzieje, a skarby mieczowi spustosza zlodzieje."}', '2026-03-17 22:22:09.912', '2026-03-17 22:22:09.912', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpa2001xqhfgiad6muhw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Na czym polega tragizm Konrada Wallenroda?', '{"options": ["Na tym, ze ponosi porazke wojenna i nie niszczy Zakonu", "Na tym, ze musi wybierac miedzy dwoma wartosciami: etyke rycerska (honor) a patriotyzmem (zemsta za ojczyzne) -- kazdy wybor oznacza strate", "Na tym, ze Aldona nie chce na niego czekac", "Na tym, ze Halban go zdradza"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Tragizm Konrada polega na konflikcie dwoch wartosci: honoru rycerskiego (walka twarzą w twarz) i milosci do ojczyzny (jedyny sposob na pokonanie Zakonu to zdrada). Wybierając ojczyzne, traci honor, milosc, szczescie i zycie. To klasyczny konflikt tragiczny romantyzmu."}', '2026-03-17 22:22:09.915', '2026-03-17 22:22:09.915', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpa5001yqhfgvrqusrh2', 'CLOSED_SINGLE', 'LANGUAGE_USE', 'ROMANTICISM', 3, 2, 'Co oznacza porownanie sokoła w Powiesci Wajdeloty?', '{"options": ["Symbolizuje potege Zakonu Krzyzackiego", "Jest alegoria losu Waltera Alfa -- Litwina porwanego przez Krzyzakow, ktory wraca na strone ojczyzny, gdy odzyska wolnosc", "Opisuje techniki sokolnictwa w sredniowieczu", "Symbolizuje Aldone, ktora chce uciec z wiezy"], "sourceText": {"text": "Jako sokol wydarty z gniazda i w klatce zywiony, / Choc srogimi mekami lowcy odbiora mu rozum / I puszczaja, zeby braci sokolow wojowal; / Skoro wzniesie sie w chmury (...) / Pojdz, mysliwcze, do domu, z klatka nie czekaj sokola.", "title": "Konrad Wallenrod", "author": "Adam Mickiewicz"}}', '1', NULL, '{language_use,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Sokol to alegoria Waltera Alfa: porwany z ojczystego gniazda (Litwa), wyhodowany w niewoli (Zakon), puszczony na polowanie (walka z Litwinami) -- ale gdy poczuje wolnosc, wraca do swoich. ''Pojdz, mysliwcze, do domu, z klatka nie czekaj sokola''."}', '2026-03-17 22:22:09.917', '2026-03-17 22:22:09.917', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpa7001zqhfg5hm7yqs9', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Ktore cechy powiesc poetyckiej realizuje "Konrad Wallenrod"?', '{"options": ["Synkretyzm rodzajowy -- laczenie epiki, liryki i dramatu", "Inwersja czasowa -- zdarzenia nie sa przedstawiane chronologicznie", "Bohater to indywidualista rozdmierany miedzy wartosciami", "Narracja prowadzona przez wszystkowiedzacego narratora bez emocji"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "\"Konrad Wallenrod\" realizuje cechy powieci poetyckiej: synkretyzm (narracja + piesni liryczne + dialogi dramatyczne), inwersje czasowa (fabuła nie jest chronologiczna -- zaczynamy od obioru mistrza, przeszlosc poznajemy z piiesni), bohater-indywidualista (Konrad rozdierany miedzy honorem a ojczyzna). Narracja NIE jest obiektywna -- narrator jest zaangazowany."}', '2026-03-17 22:22:09.919', '2026-03-17 22:22:09.919', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9kz00pgqhd93s377333', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co symbolizował złoty kolor w sztuce średniowiecznej?', '{"options": ["bogactwo materialne", "doskonałość boską, światło i chwałę niebieską", "władze królewską", "mądrość ludzką"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Złoto symbolizowało doskonałość istoty boskiej, światło boskie, chwałę niebieską i wieczność - było najcenniejszym kolorem w sztuce średniowiecza."}', '2025-10-24 22:16:54.084', '2025-10-24 22:16:54.084', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpa90020qhfg6ml3twe3', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Ktore elementy utworu stanowia nawiazania do sytuacji Polski pod zaborami?', '{"options": ["Litwa pod naporem Zakonu = Polska pod naporem Rosji", "Wallenrodyzm jako strategia walki spiskowcow (dekabrystow)", "Piesn gminna jako straznik tozsamosci = literatura polska w niewoli", "Zamek w Malborku = siedziba krola Polski w Krakowie"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Litwa vs Zakon = Polska vs Rosja (maska historyczna). Wallenrodyzm nawiazuje do strategii spiskowcow/dekabrystow (Konrad Rylejew!). Piesn gminna jako straznik pamieci = rola literatury polskiej pod zaborami. Malbork nie symbolizuje Krakowa."}', '2026-03-17 22:22:09.922', '2026-03-17 22:22:09.922', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpac0021qhfgonvwtjji', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Ktore stwierdzenia o Aldonie sa prawdziwe?', '{"options": ["Jest corka litewskiego ksiecia Kiejstuta", "Walter nauczyl ja kochac i opowiedzial jej o Bogu chrzescijan", "Zamknela sie w wiezy z wlasnej woli, by byc blisko meza", "Na koncu utworu ucieka z wiezy i wraca na Litwe"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Aldona to corka Kiejstuta, ktora zakochala sie w Walterze -- ten nauczyl ja milosci i opowiedzial o chrzescijanstwie. Zamknela sie w wiezy przy zamku w Malborku, by byc blisko meza. NIE ucieka -- umiera w wiezy po smierci Konrada."}', '2026-03-17 22:22:09.924', '2026-03-17 22:22:09.924', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpae0022qhfgl19kagak', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Napisz notatke syntetyczna na podany temat:', '{"topic": "Plan zemsty Waltera Alfa -- od porwania po smierc. Jak krok po kroku realizowal strategie wallenrodyzmu?", "wordLimit": {"max": 150, "min": 100}, "requirements": ["Wymien kluczowe etapy: porwanie, wychowanie u Krzyzakow, ucieczka na Litwe, malzenstwo, powrot pod falszywym imieniem, obior na mistrza, sabotaz, smierc", "Wyjasnij, jaka role w planie odgrywal Halban", "Wskazz, co Konrad poswiecil dla realizacji planu", "100-150 slow"]}', '"Notatka powinna obejmowac: 1) Porwanie Waltera jako dziecka, wychowanie u Krzyzakow, ale z tajnym wplywem wajdeloty Halbana, ktory rozbudzal milosc do Litwy. 2) Ucieczka na Litwe, malzenstwo z Aldona, decyzja o zemcie. 3) Powrot do Zakonu pod imieniem Wallenroda, zdobycie slawy, obior na mistrza. 4) Celowy sabotaz -- zwlekanie z wojna, przegrywanie bitew, wyniszczenie armii Zakonu na litewskich stepach. 5) Zdemaskowanie przez tajny trybunal i smierc. Halban byl ''sumieniem'' planu, rozbudwal i podtrzymywal zemste. Konrad poswiecil: milosc (Aldona), honor (zdrada), zycie (samobojstwo)."', NULL, '{historical_literary,synthesis_note,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Plan Konrada rozciaga sie na kilkadziesiat lat -- od dziecinstwa do smierci. Kluczowa jest rola Halbana jako ''architekta'' zemsty i straznika pamieci, ktory przezyje Konrada, by opowiedziec jego historie."}', '2026-03-17 22:22:09.926', '2026-03-17 22:22:09.926', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpah0023qhfgvxy8eplo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 2, 'Dlaczego Halban odmawia wypicia trucizny razem z Konradem?', '{"options": ["Jest tchorzem i boi sie smierci", "Chce przezyc, aby zachowac slawe czynu Konrada i przekazac ja potomnym -- piesn msciciela wstanie z tej piesni", "Nie wierzy, ze Konrad naprawde zamierza umrzec", "Chce uciec do Litwy i prowadzic wojne samodzielnie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,romanticism,batch-2025-01}', '{"explanation": "Halban odmawia smierci, bo ma misje: ''Chce jeszcze zostac, zamknac twe powieki / I zyc -- azebym slawe twego czynu / Zachowal swiatu, rozglosil na wieki''. Jako wajdelota bedzie spiewal o czynie Konrada -- i ''kiedys w przyszlosci / Z tej piesni wstanie msciciel naszych kosci''. Piesn jest wieczna, bohater smiertelny."}', '2026-03-17 22:22:09.929', '2026-03-17 22:22:09.929', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpaj0024qhfgdgcinrgv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 2, 'Jak mozna zinterpretowac geneze utworu w kontekscie zycia Mickiewicza?', '{"options": ["Mickiewicz opisuje wlasne doswiadczenia wojenne z okresu powstania listopadowego", "Mickiewicz, na zeslaniu w Rosji, pracujacy dla wroga (caratu), piszzze o dylemacie czlowieka, ktory musi sluzyc nieprzyjacielowi, by go zniszczyc -- odzwierciedla to sytuacje polskich spiskowcow i dekabrystow", "Utwor jest czystą fikcja historyczna bez zwiazku z biografia autora", "Mickiewicz pisal utwor jako hommage dla cara Mikolaja I"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,romanticism,batch-2025-01}', '{"explanation": "Mickiewicz pisal \"Konrada Wallenroda\" w Rosji (1825-1827), bedac zmuszony do pracy jako urzednik carski. Poznal dekabrystow (Konrad Rylejew!) i zrozumial, ze konfrontacja z Rosja jest beznadiejna -- potrzeba podstepu. Wallenrodyzm to literacki wyraz tego dylematu: jak walczyc, gdy sluzy sie wrogowi."}', '2026-03-17 22:22:09.932', '2026-03-17 22:22:09.932', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpal0025qhfgg1gy6wfb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 2, 'Dlaczego Aldona odmawia wyjscia z wiezy, gdy Konrad ja o to blaga?', '{"options": ["Bo nie kocha go juz", "Bo zlozylla przysiegia na progu wiezy, boi sie, ze zniszczonaa przez lata pustelnictwa nie bedzie juz piekna Aldona z jego wspomnien, i woli zachowac idealny obraz w pamieci obojga", "Bo Krzyzacy strzega wejscia i nie mozna wiezy otworzyc", "Bo Halban zabronil jej wychodzic"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,romanticism,batch-2025-01}', '{"explanation": "Aldona odmawia z dwoch powodow: 1) Zlozyla sakralna przysieige, ze nie wyjdzie z wiezy az do smierci. 2) Boi sie, ze zyly upior, ktory z niej pozostal, zniszczy piekny obraz zachowany w pamieci Konrada: ''Tak motyl piekny, gdy w bursztyn utonie / Na wieki cala zachowuje postac... Alfie, nam lepiej takiemi pozostac''. To tragiczne i piekne zarazem -- woli byc wspomnieniem niz rzeczywistoscia."}', '2026-03-17 22:22:09.934', '2026-03-17 22:22:09.934', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpao0026qhfgt0xjs140', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 2, 'Ktore z ponizszych interpretacji ballady "Alpuhara" sa uzasadnione?', '{"options": ["Almanzor jest analogia Konrada -- obaj niszcza wroga od srodka, poswiecajac wlasne zycie", "Pocalunek Almanzora (zarazenie dzuma) odpowiada zdradzieckim dzialalaniom Konrada jako mistrza Zakonu", "Ballada sluzy wylacznie rozrywce gości i nie ma glebszego znaczenia", "Konrad, spiewajac ballade, nieswiadomie zdradza swoj plan -- z czego Krzyzacy nie zdaja sobie sprawy"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-4,romanticism,batch-2025-01}', '{"explanation": "\"Alpuhara\" to parabola planu Konrada: Almanzor = Konrad, Hiszpanie = Krzyzacy, pocalunek/zaraza = sabotaz od srodka. Konrad w pijanym szale sam zdradza sens ballady (''Wy chcecie wiedziec o zemstie Litwina?''), ale Krzyzacy tego nie rozumieja. Ballada NIE jest pustą rozrywka -- jest kluczem do fabuły."}', '2026-03-17 22:22:09.936', '2026-03-17 22:22:09.936', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpat0027qhfgp78rhtgm', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 2, 'Ktore porownannia miedzy Konradem Wallenrodem a innymi bohaterami romantycznymi sa uzasadnione?', '{"options": ["Konrad Wallenrod i Konrad z III cz. Dziadow -- obaj poswiecaja sie dla ojczyzny, ale Wallenrod wybiera zdrade, Konrad z Dziadow -- bunt prometejski", "Konrad Wallenrod i Jacek Soplica -- obaj ukrywaja tozsamosc i dzialaja w tajemnicy dla dobra narodu", "Konrad Wallenrod i Werter Goethego -- obaj koncza samobojstwem z powodu nieszczesliwej milosci", "Konrad Wallenrod i Kordian Slowackiego -- obaj staja przed dylematem dzialania za pomoca zdrady"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-4,romanticism,batch-2025-01}', '{"explanation": "Wallenrod-Konrad (Dziady): obaj poswiecaja sie, ale roznymi metodami (zdrada vs bunt). Wallenrod-Soplica: obaj ukrywaja tozsamosc i dzialaja w tajemnicy. Wallenrod-Kordian: obaj stoja przed dylematem dzialania (Kordian nie potrafi zabic cara -- paralizz moralny). Werter ginie z milosci, nie z patriotyzmu -- analogia powierzchowna."}', '2026-03-17 22:22:09.941', '2026-03-17 22:22:09.941', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpav0028qhfghq5dnuxh', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Wyjasnij role piesni gminnej w "Konradzie Wallenrodzie" na podstawie Piesni Wajdeloty. Dlaczego Mickiewicz poswiecil jej tak wiele miejsca?', '{}', '"Piesn gminna pelni role ''arki przymierza miedzy dawnymi i mlodszymi laty'' -- jest skarbcem pamieci narodowej. Gdy plomien zniszczy kroniki, a miecz spustoszy skarby, piesn ''ujdzie calo''. Dla narodu bez panstwa (Litwa/Polska) piesn ustna jest jedynym nosnikiem tozsamosci. Mickiewicz poswiecil jej tyle miejsca, bo pisal w sytuacji, gdy polska kultura i literatura byly zagrozone rusyfikacja -- literatura = ostatni bastion narodowej pamieci. Piesn = bron: ''Ty czasem dzierzysz i bron archaniol''."', NULL, '{historical_literary,short_answer,difficulty-4,romanticism,batch-2025-01}', '{"explanation": "Piesn Wajdeloty to manifest romantycznej idei roli poety i literatury w zyciu narodu. Przylozenie do sytuacji Polski pod zaborami jest bezposrednie: skoro nie ma panstwa, literatura staje sie straznikiem tozzsamosci."}', '2026-03-17 22:22:09.944', '2026-03-17 22:22:09.944', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpay0029qhfggel7qs9w', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 3, 'Porownaj postaci Konrada Wallenroda i Almanzora z ballady "Alpuhara". Wskazz analogie i roznice.', '{"instruction": "Odwolaj sie do metody walki, motywacji i konsekwencji czynu obu bohaterow."}', '"Analogie: obaj niszcza wroga od srodka (infiltracja), obaj poswiecaja wlasne zycie, obaj uzywaja podstepu (zdrada). Almanzor zaraza dzumma przez pocalunek, Konrad niszczy armie Zakonu przez celowy sabotaz. Roznice: Almanzor dziala impulwnie (wraca tuz po upadku twierdzy), Konrad realizuje plan przez dziesieciolecia. Almanzor umiera z smiechem na ustach (triumf), Konrad umiera w rozpaczy (utracil milosc, honor, szczescie). Almanzor nie ma dylematu moralnego, Konrad jest targany wyrzutami sumienia przez cale zycie."', NULL, '{historical_literary,short_answer,difficulty-4,romanticism,batch-2025-01}', '{"explanation": "Ballada \"Alpuhara\" to parabola -- klucz do zrozumienia wallenrodyzmu. Na maturze wazne jest dostrzezenie zarowno podobienst, jak i roznic: Almanzor jest prosty i jednowymiaarowy, Konrad -- tragiczny i wielowymiarowy."}', '2026-03-17 22:22:09.946', '2026-03-17 22:22:09.946', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpb0002aqhfgub3zlz89', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 4, 4, 'Napisz notatke syntetyczna na podany temat:', '{"topic": "Czy cel uswieca srodki? Wallenrodyzm jako problem etyczny", "wordLimit": {"max": 200, "min": 150}, "requirements": ["Wyjasnij, na czym polega dylemat moralny Konrada", "Przedstaw argumenty za i przeciw wallenrodyzmowi", "Odwolaj sie do motta z Machiavellego", "Wskazz, jaka cene placi Konrad za realizacje planu", "150-200 slow"]}', '"Notatka powinna: zdefiniowac dylemat -- Konrad musi wybrac miedzy honorem rycerskim (walka twarzą w twarz, etyczne) a patriotyzmem (jedyny skuteczny sposob to zdrada, nieetyczne). Motto z Machiavellego (''trzeba byc lisem i lwem'') mowi, ze w polityce nie wolno ogranniczac sie do etyki rycerskiej. Argumenty za: Zakon jest zbyt potezny na otwarta walke, zdrada to jedyna droga do ocalenia narodu. Argumenty przeciw: zdrada niszczy moralne samego bohatera -- Konrad traci milosc, honor, zycie, staje sie alkoholikiem, ginie samobojstwem. Cena: utrata Aldony, wyrzuty sumienia, samotnosc, smierc. Mickiewicz nie daje jednoznacznej odpowiedzi -- utwor jest tragedia, nie manifestem."', NULL, '{historical_literary,synthesis_note,difficulty-4,romanticism,batch-2025-01}', '{"explanation": "Problem ''cel uswieca srodki'' to centralne zagadnienie etyczne utworu i jedno z najczestszych pytan maturalnych dotyczacych \"Konrada Wallenroda\"."}', '2026-03-17 22:22:09.949', '2026-03-17 22:22:09.949', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpb3002bqhfggtzi17qd', 'ESSAY', 'WRITING', 'ROMANTICISM', 4, 5, 'Tragiczna milosc w literaturze. Omow problem, odwolujac sie do "Konrada Wallenroda" Adama Mickiewicza i jednego innego tekstu kultury.', '{"wordLimit": {"min": 300}, "requirements": ["Wyjasnij, dlaczego milosc Waltera i Aldony jest tragiczna", "Przeanalizuj scene rozstania i scene pozegnalaa (cz. VI)", "Porownaj z inna tragiczna miloscia (np. Romeo i Julia, Tristan i Izolda, Judym i Joanna)", "Odpowiedz na pytanie: czy milosc musi przegrac z obowiazkiem?", "Minimum 300 slow"]}', '"Rozprawka powinna: pokazac tragizm milosci Alfa i Aldony (milosc poswiecona dla wyzszego celu -- obrony ojczyzny), przeanalizowac scene pozegnania (Aldona odmawia wyjscia z wiezy, woli byc wspomnieniem niz ruina), porownac z inna para (np. Romeo i Julia -- milosc konczy smiercia z powodu konfliktu rodow; Judym i Joasia -- milosc poswiecona dla pracy spolecznej). Wniosek: u Mickiewicza milosc NIE jest slaboscia -- jest najwyzsza ofiara, jaka bohater moze zlozyc na oltarzu ojczyzny."', NULL, '{writing,essay,difficulty-4,romanticism,batch-2025-01}', '{"explanation": "Motyw tragicznej milosci to jedno z najczestszych pytan maturalnych o ''Konrada Wallenroda''. Kluczowe: milosc Alfa i Aldony nie jest sentymentalna -- jest heroiczna."}', '2026-03-17 22:22:09.951', '2026-03-17 22:22:09.951', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9l100phqhd9oakim1e2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co to jest fiale w architekturze gotyckiej?', '{"options": ["okrągłe okno", "ostrosłupowa wieżyczka zdobnicza", "portal wejściowy", "łuk przporowy"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Fiale to charakterystyczne dla gotyku smukłe, ostrosłupowe wieżyczki pełniące funkcję dekoracyjną, podkreślające strzelistość budowli."}', '2025-10-24 22:16:54.086', '2025-10-24 22:16:54.086', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpb5002cqhfgulkh0060', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 3, 'Jak mozna zinterpretowac relacje Konrad--Halban w kontekscie romantycznej koncepcji roli poety?', '{"options": ["Halban jest sluaczem Konrada -- wykonuje jego polecenia bez wlasnej woli", "Halban jest ''sumieniem narodu'' i architektem zemsty -- to on ksztaltuje Konrada od dziecinstwa, podtrzymuje plan, a po smierci bohatera zachowa jego czyn w piesni. Relacja ilustruje romantyczna idee: poeta (wajdelota) jest duchowym przywodca narodu, wazniejszym od rycerza", "Halban i Konrad sa rywalaami o milosc Aldony", "Relacja jest czysto fabularana -- nie ma glebszego sensu symbolicznego"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,romanticism,batch-2025-01}', '{"explanation": "Halban to wcielenie romantycznej idei poety-wieszcza: ksztaltuje bohaterow (wychowal Konrada), podtrzymuje paamiec narodu (piesn gminna), przezywa rycerza (odmawia trucizny). Poet jest wazniejszy od wojownika: ''Bard dla rycerzy w bitwach, a niewiasta / Bedzie ja w domu spiewac dla swych dzieci''. Konrad ginie -- pieśń Halbana zyje wiecznie."}', '2026-03-17 22:22:09.953', '2026-03-17 22:22:09.953', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpb8002dqhfgko2vc8u0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 3, 'Dlaczego Mickiewicz przedstawia wallenrodyzm jako strategie tragiczna, a nie heroiczna?', '{"options": ["Poniewaz Mickiewicz byl przeciwny walce zbrojnej w kazdej formie", "Poniewaz utwor pokazuje moralne koszty wallenrodyzmu -- bohater traci milosc, honor, tozsamosc, popada w alkoholizm i konczy samobojstwem. Mickiewicz nie gloryfikuje zdrady, lecz ukazuje ja jako desperacki srodek, za ktory placi sie wszystkim", "Poniewaz Konrad ponosi kleeske i nie niszczy Zakonu", "Poniewaz cenzura carska zmusila Mickiewicza do potepienia bohatera"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,romanticism,batch-2025-01}', '{"explanation": "Mickiewicz NIE gloryfikuje wallenrodyzmu -- ukazuje jego tragiczne konsekwencje: Konrad traci Aldone (pustelnica), honor (zdrajca), tozsamosc (zyje pod falszywym imieniem), popada w alkoholizm, a w koncu popelnia samobojstwo. Wallenrodyzm to nie program ideowy -- to desperacja. Utwor jest tragedia, nie manifestem. Pózniej Mickiewicz odrzucil wallenrodyzm na rzecz mesjanizmu (Dziady cz. III)."}', '2026-03-17 22:22:09.956', '2026-03-17 22:22:09.956', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpba002eqhfg23jdhccm', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 3, 'Ktore z ponizszych aspektow utworu swiadcza o jego romantycznym charakterze?', '{"options": ["Bohater-indywidualista rozdierany miedzy wartosciami, samotny w swoim czynie", "Historyzm maski -- ukrywanie wspolczesnych tresci pod szata sredniowieczna", "Kult piesni gminnej jako straznika pamieci narodowej (romantyczna rola poety)", "Obiektywna, racjonalna analiza konfliktu politycznego miedzy Litwa a Zakonem"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-5,romanticism,batch-2025-01}', '{"explanation": "Cechy romantyczne: bohater-indywidualista (Konrad sam przeciw calemu Zakonowi), historyzm maski (sredniowiecze = XIX w.), kult piesni gminnej i rola poety (Piesn Wajdeloty = manifest romantyzmu). Obiektywna racjonalana analiza bylaaby cechą pozytywizmu, nie romantyzmu -- utwor jest peloen emocji, tragizmu i subiektywizmu."}', '2026-03-17 22:22:09.958', '2026-03-17 22:22:09.958', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpbc002fqhfg6k21aoa1', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 4, 'Porownaj wallenrodyzm z prometeizmem Konrada z III czesci "Dziadow". Ktora postawa jest bardziej etyczna?', '{"instruction": "Uwzglednij metody walki, motywacje, moralne koszty i skutecznosc obu bohaterow."}', '"Wallenrodyzm: niszczenie wroga od srodka za pomoca zdrady, podstepu, klamstwa. Metoda: infiltracja i sabotaz. Koszt: utrata honoru, milosci, tozsamosci, smierc. Skutecznosc: Zakon zniszczony, ale bohater zniszczony razem z nim. Prometeizm (Konrad z Dziadow III): otwarty bunt przeciw Bogu i tyranowi, cierpienie za miliony. Metoda: Wielka Improwizacja -- slowo jako bron. Koszt: szalenstwo, pycha (grzech). Skutecznosc: bezposrednia -- zerowa (Konrad nie wyzwala narodu), posrednia -- mobilizacja duchowa. Etycznie: prometeizm jest bardziej ''czysty'' (otwarty bunt), ale mniej skuteczny. Wallenrodyzm jest skuteczniejszy, ale moralnie niszczacy. Mickiewicz ewoluowal od wallenrodyzmu (1828) do prometeizmu/mesjanizmu (1832)."', NULL, '{historical_literary,short_answer,difficulty-5,romanticism,batch-2025-01}', '{"explanation": "Porownanie wallenrodyzmu z prometeizmem to jedno z kluczowych zagadnien romantyzmu na maturze rozszerzonej. Wazne: Mickiewicz sam odrzucil wallenrodyzm na rzecz prometeizmu w Dziadach."}', '2026-03-17 22:22:09.96', '2026-03-17 22:22:09.96', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9l400piqhd9ollnfokn', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co to jest wimperga w architekturze gotyckiej?', '{"options": ["ostrosłupowy szczyt nad portalem lub oknem", "rodzaj sklepienia", "wieża kościelna", "witraż"]}', '0', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Wimperga to ostrosłupowy, bogato rzeźbiony szczyt umieszczany nad portalami i oknami w architekturze gotyckiej."}', '2025-10-24 22:16:54.088', '2025-10-24 22:16:54.088', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9l600pjqhd95fawb4vo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Jaki był główny przedmiot sporu między nominalizmem a realizmem?', '{"options": ["natura Boga", "istnienie duszy", "czy pojęcia ogólne (universalia) istnieją realnie", "relacja wiary i rozumu"]}', '2', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Spór dotyczył natury pojęć ogólnych: realiści twierdzili, że universalia istnieją realnie, nominaliści - że są tylko nazwami."}', '2025-10-24 22:16:54.09', '2025-10-24 22:16:54.09', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9l800pkqhd9zx1v4nrj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co symbolizowała lilia w ikonografii średniowiecznej?', '{"options": ["mądrość", "czystość i dziewictwo Maryi", "męczeństwo", "zmartwychwstanie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Lilia była atrybutem Matki Boskiej i symbolizowała czystość, dziewictwo, niewinność - często pojawia się w scenie Zwiastowania."}', '2025-10-24 22:16:54.092', '2025-10-24 22:16:54.092', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9la00plqhd95jsif6h5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co oznacza pojęcie ''teodycea'' w filozofii średniowiecznej?', '{"options": ["dowód na istnienie Boga", "usprawiedliwienie Boga wobec istnienia zła", "nauka o Trójcy Świętej", "teoria poznania"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Teodycea to próba usprawiedliwienia Boga wobec istnienia zła w świecie - problem, z którym borykali się filozofowie średniowieczni."}', '2025-10-24 22:16:54.094', '2025-10-24 22:16:54.094', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9lc00pmqhd9sx5vnh0w', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co symbolizowała róża w symbolice średniowiecznej?', '{"options": ["tylko miłość ziemską", "grzech i pokusę", "miłość boską, tajemnicę i męczeństwo", "bogactwo"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Róża symbolizowała miłość boską (czerwona róża), czystość Maryi (biała róża), tajemnicę wiary i męczeństwo (ciernie)."}', '2025-10-24 22:16:54.097', '2025-10-24 22:16:54.097', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9lf00pnqhd934bxekja', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co to jest mandorla w ikonografii średniowiecznej?', '{"options": ["korona świętych", "migdałowata aureola wokół całej postaci", "krzyż", "księga"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Mandorla (z wł. migdał) to migdałowata aureola otaczająca całą postać Chrystusa lub świętych, symbolizująca chwałę i świętość."}', '2025-10-24 22:16:54.099', '2025-10-24 22:16:54.099', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9lh00poqhd94eduphej', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co to jest kazuistyka w średniowiecznej teologii?', '{"options": ["nauka o świętach", "rozstrzyganie przypadków moralnych przez analizę szczegółową", "liturgia", "teoria poznania"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Kazuistyka to metoda rozstrzygania konkretnych przypadków moralnych przez szczegółową analizę okoliczności - ważna w średniowiecznej teologii."}', '2025-10-24 22:16:54.101', '2025-10-24 22:16:54.101', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9lj00ppqhd9ze3n5cb6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co oznacza termin ''hylomorfizm'' w filozofii tomistycznej?', '{"options": ["teoria o duszy", "teoria o złożeniu wszystkich bytów z materii i formy", "dowód na istnienie Boga", "teoria poznania"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Hylomorfizm (z gr. hyle - materia, morphe - forma) to tomistyczna teoria głosząca, że każdy byt składa się z materii i formy."}', '2025-10-24 22:16:54.103', '2025-10-24 22:16:54.103', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ll00pqqhd9papytat6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co symbolizował pelikan w ikonografii chrześcijańskiej?', '{"options": ["zmartwychwstanie", "Chrystusa karmiącego wiernych własną krwią - ofiara eucharystyczna", "Ducha Świętego", "grzech"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Pelikan symbolizował Chrystusa - według legendy pelikan karmi pisklęta własną krwią, co odnosi się do ofiary Chrystusa i Eucharystii."}', '2025-10-24 22:16:54.106', '2025-10-24 22:16:54.106', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ln00prqhd96bq3xtby', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co to jest quodlibet w średniowiecznej scholastyce?', '{"options": ["rodzaj kazania", "dysputacja na dowolny temat zadany przez audytorium", "gatunek literacki", "ceremonia religijna"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Quodlibet (łac. ''co się podoba'') to specjalna dysputacja uniwersytecka, podczas której mistrz odpowiadał na pytania zadane przez audytorium."}', '2025-10-24 22:16:54.108', '2025-10-24 22:16:54.108', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9lq00psqhd9ellmy3dm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co symbolizował feniks w średniowiecznej symbolice?', '{"options": ["wieczność Boga", "zmartwychwstanie Chrystusa", "grzech", "mądrość"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Feniks - mityczny ptak odradzający się z popiołów - symbolizował zmartwychwstanie Chrystusa i życie wieczne po śmierci."}', '2025-10-24 22:16:54.11', '2025-10-24 22:16:54.11', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ls00ptqhd9uvmfk3od', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co oznacza pojęcie ''exemplum'' w literaturze średniowiecznej?', '{"options": ["gatunek dramatu", "krótkie opowiadanie pouczające w kazaniu", "typ kroniki", "forma modlitwy"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Exemplum to krótkie opowiadanie o charakterze moralizatorskim wplatane w kazania dla zilustrowania nauki i utrwalenia przesłania."}', '2025-10-24 22:16:54.112', '2025-10-24 22:16:54.112', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9lu00puqhd9rgfhvum3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co to jest bazylikowy układ kościoła?', '{"options": ["kościół z jedną nawą", "kościół z nawą główną wyższą od naw bocznych", "kościół okrągły", "kościół na planie krzyża greckiego"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Układ bazylikowy to rozwiązanie, w którym nawa główna jest wyższa i szersza od naw bocznych - charakterystyczne dla architektury romańskiej."}', '2025-10-24 22:16:54.114', '2025-10-24 22:16:54.114', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9lw00pvqhd9sx1p7yt2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co głosił nominalizm w sporze o uniwersalia?', '{"options": ["pojęcia ogólne istnieją realnie", "pojęcia ogólne to tylko nazwy nadane przez umysł", "pojęcia ogólne są w Bogu", "pojęcia ogólne nie istnieją"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Nominalizm (od łac. nomen - nazwa) głosił, że universalia to tylko nazwy, flatus vocis - twory umysłu, nie mają realnego istnienia."}', '2025-10-24 22:16:54.116', '2025-10-24 22:16:54.116', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ly00pwqhd9dp5nt9vj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co symbolizował agnus Dei (baranek Boży) w ikonografii?', '{"options": ["niewinność ludzką", "Chrystusa jako ofiarę za grzechy świata", "pokój", "potęgę Kościoła"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Agnus Dei (Baranek Boży) symbolizował Chrystusa jako ofiarę paschalną złożoną za grzechy świata - nawiązanie do ofiar Starego Testamentu."}', '2025-10-24 22:16:54.119', '2025-10-24 22:16:54.119', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9m100pxqhd9waa1g71m', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co to jest krucjata dziecięca?', '{"options": ["mit literacki", "tragiczne wydarzenie z 1212 roku - dzieci wyruszające do Ziemi Świętej", "rodzaj kazania", "gatunek dramatu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Krucjata dziecięca (1212) to tragiczne wydarzenie, gdy tysiące dzieci wyruszyło do Ziemi Świętej - większość zginęła lub została sprzedana w niewolę."}', '2025-10-24 22:16:54.121', '2025-10-24 22:16:54.121', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9m300pyqhd9rmow388j', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co symbolizował winorośl w symbolice chrześcijańskiej?', '{"options": ["bogactwo", "Chrystusa i wiernych jako latorośle - jedność Kościoła", "grzech", "mądrość"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Winorośl symbolizowała Chrystusa jako prawdziwą winorośl, a wiernych jako latorośle - jedność mistycznego ciała Kościoła (J 15,1-5)."}', '2025-10-24 22:16:54.123', '2025-10-24 22:16:54.123', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9m600pzqhd9y91fzsg0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co to jest krypta w architekturze średniowiecznej?', '{"options": ["wieża kościelna", "podziemna kaplica z grobami świętych", "zakrystia", "chór"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Krypta to podziemna część kościoła, gdzie przechowywano relikwie świętych i grzebano dostojników kościelnych - miejsce pielgrzymek."}', '2025-10-24 22:16:54.126', '2025-10-24 22:16:54.126', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9m900q0qhd9q088w35p', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co to jest klasztor typu benedyktyńskiego?', '{"options": ["klasztor miejski", "samotnia pustelnicza", "klasztor-opactwo z życiem wspólnotowym według reguły", "klasztor żebraczego zakonu"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Klasztor benedyktyński to opactwo z życiem wspólnotowym według reguły ''ora et labora'' - modlitwa i praca, samowystarczalny organizm."}', '2025-10-24 22:16:54.129', '2025-10-24 22:16:54.129', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9mb00q1qhd9b52f1hkd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co to jest scriptorium?', '{"options": ["biblioteka klasztorna", "pracownia pisarska w klasztorze, gdzie przepisywano księgi", "refektarz", "kaplica"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Scriptorium to klasztorna pracownia pisarska, gdzie mnisi kopiowali i iluminowali manuskrypty - centra zachowania kultury antycznej."}', '2025-10-24 22:16:54.132', '2025-10-24 22:16:54.132', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9md00q2qhd9nw5ybhbe', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co symbolizował gołąb w ikonografii chrześcijańskiej?', '{"options": ["pokój ziemski", "Ducha Świętego", "niewinność", "nadzieję"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Gołąb symbolizował Ducha Świętego - nawiązanie do Chrztu Chrystusa w Jordanie i Zesłania Ducha Świętego."}', '2025-10-24 22:16:54.134', '2025-10-24 22:16:54.134', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9mf00q3qhd9xv761gvp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co to jest reguła zakonna?', '{"options": ["zbiór praw państwowych", "zbiór przepisów regulujących życie zakonne", "kodeks rycerski", "księga liturgiczna"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Reguła zakonna to zbiór przepisów regulujących życie duchowe i codzienne zakonu - np. reguła św. Benedykta, św. Franciszka."}', '2025-10-24 22:16:54.136', '2025-10-24 22:16:54.136', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9mh00q4qhd958cf93xr', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co symbolizował oliwnik w symbolice biblijnej?', '{"options": ["wojnę", "pokój i pojednanie z Bogiem", "bogactwo", "śmierć"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Oliwnik (drzewo oliwne) symbolizował pokój, pojednanie z Bogiem i błogosławieństwo - gałązka oliwna przyniesiona przez gołębia do Noego."}', '2025-10-24 22:16:54.138', '2025-10-24 22:16:54.138', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9mk00q5qhd9r2kv6prx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co to jest antyfona w liturgii średniowiecznej?', '{"options": ["rodzaj kazania", "krótka pieśń liturgiczna śpiewana naprzemiennie", "modlitwa", "gest liturgiczny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Antyfona to krótka pieśń liturgiczna śpiewana przed i po psalmie, wykonywana naprzemiennie przez dwa chóry lub solistę i chór."}', '2025-10-24 22:16:54.14', '2025-10-24 22:16:54.14', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9mm00q6qhd9sl1qd93r', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co symbolizowały cztery cnoty kardynalne w filozofii średniowiecznej?', '{"options": ["cztery kierunki świata", "roztropność, sprawiedliwość, męstwo, umiarkowanie", "cztery żywioły", "cztery ewangeliści"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Cztery cnoty kardynalne to: roztropność (prudentia), sprawiedliwość (iustitia), męstwo (fortitudo) i umiarkowanie (temperantia) - podstawy życia moralnego."}', '2025-10-24 22:16:54.142', '2025-10-24 22:16:54.142', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9mo00q7qhd9kmuffycs', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co to jest palimpsest?', '{"options": ["rodzaj pergaminu", "rękopis, z którego zeskrobano tekst i zapisano nowy", "typ iluminacji", "gatunek literacki"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Palimpsest to pergamin, z którego zeskrobano starszy tekst i zapisano nowy - praktyka z powodu kosztowności pergaminu, prowadząca do utraty dzieł antycznych."}', '2025-10-24 22:16:54.144', '2025-10-24 22:16:54.144', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9mq00q8qhd9v0j6nblz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co symbolizował wąż w ikonografii średniowiecznej?', '{"options": ["mądrość", "Szatana, grzech pierworodny i pokusę", "medycynę", "życie wieczne"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Wąż symbolizował przede wszystkim Szatana, grzech pierworodny i pokusę - nawiązanie do upadku w raju."}', '2025-10-24 22:16:54.147', '2025-10-24 22:16:54.147', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ms00q9qhd9uok39r5f', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co to jest brewiarz?', '{"options": ["księga do nauki", "księga zawierająca oficjum - modlitwy brewiarzowe", "kronika", "zbiór kazań"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Brewiarz to księga liturgiczna zawierająca oficjum - cykl modlitw odmawianym przez duchownych w ciągu dnia (jutrznia, nieszpory itp.)."}', '2025-10-24 22:16:54.149', '2025-10-24 22:16:54.149', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9mv00qaqhd9usjgyqt3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co to jest transept w architekturze kościelnej?', '{"options": ["wieża", "nawa poprzeczna tworząca ramiona krzyża", "apsyda", "krypta"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Transept to nawa poprzeczna w kościele na planie krzyża łacińskiego, przecinająca nawę główną i tworzącą ramiona krzyża."}', '2025-10-24 22:16:54.151', '2025-10-24 22:16:54.151', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9mx00qbqhd9yzxrx1mw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Co to jest kodeks średniowieczny?', '{"options": ["zbiór praw", "książka rękopiśmienna w formie zeszytu", "kronika", "rodzaj kazania"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Kodeks to średniowieczna książka rękopiśmienna w formie zszytychi zeszytu kart pergaminowych lub papierowych - zastąpił zwój."}', '2025-10-24 22:16:54.153', '2025-10-24 22:16:54.153', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9mz00qcqhd9ig3cn738', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Co symbolizowały siedem grzechów głównych?', '{"options": ["siedem dni tygodnia", "pycha, chciwość, zazdrość, gniew, nieczystość, łakomstwo, lenistwo", "siedem sakramentów", "siedem cnót"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Siedem grzechów głównych to: pycha (superbia), chciwość (avaritia), zazdrość (invidia), gniew (ira), nieczystość (luxuria), łakomstwo (gula), lenistwo (acedia)."}', '2025-10-24 22:16:54.155', '2025-10-24 22:16:54.155', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evai3013bqhd9cz1d0s8t', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 1, 'Jak nazywają się synowie Duncana?', '{"options": ["Malcolm i Donalbain", "Fleance i Siward", "Ross i Lennox", "Angus i Menteith"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,renaissance,batch-2025-01}', '{"explanation": "Synowie Duncana to Malcolm i Donalbain, którzy uciekają po śmierci ojca."}', '2025-10-24 22:16:55.275', '2025-10-24 22:16:55.275', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9n100qdqhd9cmn5zzo6', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 3, 'Dopasuj średniowieczne symbole do ich znaczeń.', '{"leftColumn": [{"id": "A", "text": "Pelikan"}, {"id": "B", "text": "Feniks"}, {"id": "C", "text": "Agnus Dei"}, {"id": "D", "text": "Winorośl"}], "rightColumn": [{"id": 1, "text": "Chrystus jako ofiara za grzechy"}, {"id": 2, "text": "zmartwychwstanie"}, {"id": 3, "text": "ofiara eucharystyczna"}, {"id": 4, "text": "jedność Kościoła"}], "matchingType": "symbols_meanings"}', '[[0, 2], [1, 1], [2, 0], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Pelikan - ofiara eucharystyczna, feniks - zmartwychwstanie, agnus Dei - ofiara za grzechy, winorośl - jedność Kościoła."}', '2025-10-24 22:16:54.157', '2025-10-24 22:16:54.157', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9n300qeqhd9o7r51669', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 3, 'Dopasuj filozofów do ich głównych koncepcji.', '{"leftColumn": [{"id": "A", "text": "Św. Augustyn"}, {"id": "B", "text": "Św. Tomasz"}, {"id": "C", "text": "Św. Anzelm"}, {"id": "D", "text": "Wilhelm Ockham"}], "rightColumn": [{"id": 1, "text": "ontologiczny dowód na istnienie Boga"}, {"id": 2, "text": "iluminacja i przewaga duszy nad ciałem"}, {"id": 3, "text": "nominalizm"}, {"id": 4, "text": "hylomorfizm i drabina bytów"}], "matchingType": "philosophers_concepts"}', '[[0, 1], [1, 3], [2, 0], [3, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Augustyn - iluminacja, Tomasz - hylomorfizm, Anzelm - dowód ontologiczny, Ockham - nominalizm."}', '2025-10-24 22:16:54.16', '2025-10-24 22:16:54.16', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9n600qfqhd9b2pppv2u', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 3, 'Które elementy należały do siedmiu sztuk wyzwolonych - triwium? (wybierz wszystkie poprawne)', '{"options": ["gramatyka", "dialektyka (logika)", "retoryka", "arytmetyka", "geometria"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Triwium (niższy poziom) obejmowało: gramatykę, dialektykę i retorykę. Arytmetyka i geometria należały do quadrivium."}', '2025-10-24 22:16:54.162', '2025-10-24 22:16:54.162', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9n800qgqhd9libp0r9b', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 3, 'Które elementy należały do siedmiu sztuk wyzwolonych - quadrivium? (wybierz wszystkie poprawne)', '{"options": ["arytmetyka", "muzyka", "geometria", "astronomia", "retoryka"]}', '[0, 1, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Quadrivium (wyższy poziom) obejmowało: arytmetykę, muzykę, geometrię i astronomię. Retoryka należała do triwium."}', '2025-10-24 22:16:54.164', '2025-10-24 22:16:54.164', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9na00qhqhd94susd6v8', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 3, 'Dopasuj kolory do ich symboliki w średniowieczu.', '{"leftColumn": [{"id": "A", "text": "Złoto"}, {"id": "B", "text": "Biel"}, {"id": "C", "text": "Czerwień"}, {"id": "D", "text": "Błękit"}], "rightColumn": [{"id": 1, "text": "czystość i niewinność"}, {"id": 2, "text": "niebiański, duchowość, Maryja"}, {"id": 3, "text": "doskonałość boska"}, {"id": 4, "text": "męczeństwo i miłość"}], "matchingType": "colors_symbolism"}', '[[0, 2], [1, 0], [2, 3], [3, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Złoto - doskonałość boska, biel - czystość, czerwień - męczeństwo, błękit - duchowość i Maryja."}', '2025-10-24 22:16:54.166', '2025-10-24 22:16:54.166', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9nc00qiqhd91tqwmo33', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 3, 'Które cechy charakteryzują scholastykę? (wybierz wszystkie poprawne)', '{"options": ["racjonalne wyjaśnianie prawd wiary", "odrzucenie rozumu", "precyzyjne wywody logiczne", "dystans do Arystotelesa", "metoda pytań i odpowiedzi"]}', '[0, 2, 4]', NULL, '{historical_literary,closed_multiple,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Scholastyka charakteryzowała się: racjonalnym wyjaśnianiem prawd wiary, precyzyjnymi wywodami logicznymi i metodą pytań-odpowiedzi. Korzystała z Arystotelesa."}', '2025-10-24 22:16:54.168', '2025-10-24 22:16:54.168', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ne00qjqhd928vlxtv2', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Uzupełnij informacje o architekturze średniowiecznej.', '{"gaps": [{"id": 1, "options": ["ostrołukowy", "pełny", "półkolisty", "podkowy"]}, {"id": 2, "options": ["cienkie", "szklane", "grube", "drewniane"]}, {"id": 3, "options": ["półkolisty", "ostrołukowy", "pełny", "płaski"]}, {"id": 4, "options": ["małe", "witrażowe", "okrągłe", "kwadratowe"]}], "textWithGaps": "W stylu romańskim dominował łuk [1], budowle miały [2] mury. W gotyku stosowano łuk [3] i charakterystyczne [4] okna."}', '[2, 2, 1, 1]', NULL, '{historical_literary,closed_multiple,difficulty-3,middle_ages,batch-2025-01}', '{"explanation": "Romanizm: łuk półkolisty i grube mury. Gotyk: łuk ostrołukowy i witrażowe okna."}', '2025-10-24 22:16:54.171', '2025-10-24 22:16:54.171', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9nh00qkqhd9j27fp926', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 3, 'Dopasuj zakony do ich charakterystyki.', '{"leftColumn": [{"id": "A", "text": "Benedyktyni"}, {"id": "B", "text": "Franciszkanie"}, {"id": "C", "text": "Dominikanie"}, {"id": "D", "text": "Cystersi"}], "rightColumn": [{"id": 1, "text": "ora et labora - modlitwa i praca"}, {"id": 2, "text": "zakon kaznodziejski walczący z herezją"}, {"id": 3, "text": "zakon żebraczy, ubóstwo"}, {"id": 4, "text": "reforma benedyktyńska, praca fizyczna"}], "matchingType": "orders_characteristics"}', '[[0, 0], [1, 2], [2, 1], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-4,middle_ages,batch-2025-01}', '{"explanation": "Benedyktyni - ora et labora, franciszkanie - ubóstwo, dominikanie - kaznodzieje, cystersi - reforma benedyktyńska."}', '2025-10-24 22:16:54.173', '2025-10-24 22:16:54.173', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evai5013cqhd9stq9zvoo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Dlaczego Makbet decyduje się zabić Banka?', '{"options": ["Banko go zdradził", "Banko odkrył prawdę o morderstwie", "wiedźmy przepowiedziały, że synowie Banka będą królami", "Banko zaatakował Makbeta"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Makbet obawia się przepowiedni, że potomkowie Banka będą królami."}', '2025-10-24 22:16:55.278', '2025-10-24 22:16:55.278', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9nj00qlqhd911d3iklf', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Wyjaśnij różnicę między realizmem a nominalizmem w średniowiecznym sporze o uniwersalia.', '{"instruction": "Opisz stanowiska obu stron sporu. (50-70 słów)"}', NULL, '{"criteria": ["wyjaśnienie stanowiska realizmu (1 pkt)", "wyjaśnienie stanowiska nominalizmu (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-3,middle_ages,batch-2025-01}', '{"keyWords": ["realizm", "nominalizm", "pojęcia ogólne", "istnienie realne", "nazwy"], "expectedAnswer": "Spór o uniwersalia dotyczył natury pojęć ogólnych. Realiści (np. św. Anzelm) twierdzili, że universalia - pojęcia ogólne jak ''człowiek'', ''dobro'' - istnieją realnie, niezależnie od jednostkowych przedmiotów, w umyśle Boga lub w rzeczach. Nominaliści (np. Wilhelm Ockham) głosili, że uniwersalia to tylko nazwy (nomina), flatus vocis - dźwięki nadane przez umysł ludzki, nie mają realnego istnienia. Istnieją tylko konkretne, jednostkowe rzeczy."}', '2025-10-24 22:16:54.175', '2025-10-24 22:16:54.175', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9nl00qmqhd9k1wydv1x', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Opisz znaczenie symboliki światła w architekturze i teologii gotyckiej.', '{"instruction": "Wyjaśnij, jaką rolę pełniło światło w kulturze gotyku. (50-70 słów)"}', NULL, '{"criteria": ["wskazanie symboliki światła jako Boga (1 pkt)", "wyjaśnienie roli witraży i architektury (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-3,middle_ages,batch-2025-01}', '{"keyWords": ["światło", "Bóg", "witraże", "sacrum", "piękno"], "expectedAnswer": "W gotyku światło miało fundamentalne znaczenie teologiczne i estetyczne. Symbolizowało Boga, prawdę i boską chwałę. Według opata Sugera światło było najdoskonalszym obrazem Boga - to, co jasne, piękne kojarzono z boskością. Stąd gotycka architektura dążyła do maksymalnego wpuszczenia światła przez wysokie okna witrażowe. Kolorowe światło przenikające przez witraże miało oczyszczać i uświęcać, wprowadzać wiernych w atmosferę sacrum."}', '2025-10-24 22:16:54.178', '2025-10-24 22:16:54.178', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9nn00qnqhd9ps7qx38k', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Wyjaśnij koncepcję ''drabiny bytów'' w filozofii tomistycznej i jej znaczenie.', '{"instruction": "Opisz hierarchię bytów według św. Tomasza. (50-70 słów)"}', NULL, '{"criteria": ["opisanie hierarchii od materii do Boga (1 pkt)", "wyjaśnienie miejsca człowieka i sensu tej koncepcji (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-4,middle_ages,batch-2025-01}', '{"keyWords": ["hierarchia", "materia", "duch", "Bóg", "człowiek", "doskonalenie"], "expectedAnswer": "Drabina bytów (scala naturae) to tomistyczna koncepcja hierarchicznego uporządkowania wszechświata. Od dołu: materia nieożywiona, rośliny (życie wegetatywne), zwierzęta (życie zmysłowe), człowiek (rozum i duch - najniższy z duchów), aniołowie (duchy czyste), Bóg na szczycie jako byt najdoskonalszy. Człowiek zajmuje środkowe miejsce - łączy świat materialny i duchowy. Każdy byt ma swoje przeznaczenie - człowiek powinien dążyć do doskonalenia się i wznoszeniapo drabinie ku Bogu."}', '2025-10-24 22:16:54.18', '2025-10-24 22:16:54.18', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9nq00qoqhd9asnwwk73', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Opisz rolę klasztorów w zachowaniu kultury antycznej i średniowiecznej.', '{"instruction": "Wyjaśnij, jak klasztory chroniły dziedzictwo kulturowe. (50-70 słów)"}', NULL, '{"criteria": ["wskazanie scriptoriów i przepisywania ksiąg (1 pkt)", "wyjaśnienie roli edukacyjnej i kulturalnej (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-3,middle_ages,batch-2025-01}', '{"keyWords": ["scriptorium", "przepisywanie", "biblioteki", "edukacja", "kultura antyczna"], "expectedAnswer": "Klasztory były głównymi ośrodkami kultury w średniowieczu. W scriptoriach mnisi przepisywali starożytne dzieła oraz teksty religijne, zachowując je dla potomności - często były jedynymi posiadaczami antycznych manuskryptów. Klasztory prowadziły szkoły, biblioteki, były centrami nauki. Benedyktyni realizowali zasadę ''ora et labora'' - łączyli pracę intelektualną z duchową. Dzięki klasztorom przetrwała literatura antyczna, rozwijała się filozofia, teologia. To główne centra cywilizacji w mrocznych wiekach."}', '2025-10-24 22:16:54.182', '2025-10-24 22:16:54.182', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ns00qpqhd9sydq460j', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 2, 'Wyjaśnij różnicę między życiem zakonów kontemplacyjnych a żebracych.', '{"instruction": "Porównaj oba typy życia zakonnego. (50-70 słów)"}', NULL, '{"criteria": ["charakterystyka zakonów kontemplacyjnych (1 pkt)", "charakterystyka zakonów żebracych (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-4,middle_ages,batch-2025-01}', '{"keyWords": ["kontemplacja", "odosobnienie", "żebractwo", "aktywność", "ubóstwo"], "expectedAnswer": "Zakony kontemplacyjne (np. benedyktyni, cystersi) prowadziły życie w odosobnieniu klasztornym, koncentrowały się na modlitwie, kontemplacji i pracy fizycznej. Realizowały zasadę stabilitas loci - stałego miejsca. Posiadały majątki i były samowystarczalne. Zakony żebracze (franciszkanie, dominikanie) powstałe w XIII w. odrzucały majątek, żyły z jałmużny, aktywnie działały wśród ludzi - głosiły kazania, nauczały, pomagali ubogim. Nie były związane z klasztorem, podróżowały głosząc Ewangelię."}', '2025-10-24 22:16:54.184', '2025-10-24 22:16:54.184', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9nu00qqqhd9x07u14ks', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Opisz funkcję exemplum w średniowiecznym kaznodziejstwie.', '{"instruction": "Wyjaśnij, czym było exemplum i jaki cel pełniło. (40-60 słów)"}', NULL, '{"criteria": ["definicja exemplum jako opowiadania (1 pkt)", "wskazanie funkcji dydaktycznej i perswazyjnej (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-3,middle_ages,batch-2025-01}', '{"keyWords": ["opowiadanie", "kazanie", "morał", "ilustracja", "perswazja"], "expectedAnswer": "Exemplum to krótkie opowiadanie moralizatorskie wplatane w kazania dla zilustrowania nauki religijnej. Miało przykładowy charakter - pokazywało konsekwencje grzechu lub nagrodę za cnotę. Przez konkretne, często sensacyjne historie było łatwiejsze do zapamiętania niż abstrakcyjne pouczenia. Exempla czyniły kazania bardziej przystępnymi dla prostego ludu, wzmacniały perswazję kaznodziei. Czerpano je z żywotów świętych, legend lub życia codziennego."}', '2025-10-24 22:16:54.187', '2025-10-24 22:16:54.187', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evai8013dqhd966qknjob', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Kto pojawia się jako duch podczas uczty?', '{"options": ["Duncan", "Banko", "Lady Makbet", "Makduf"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Duch Banka pojawia się podczas uczty, ale widzi go tylko Makbet."}', '2025-10-24 22:16:55.281', '2025-10-24 22:16:55.281', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaib013eqhd9o065cc2u', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Co się dzieje z rodziną Makdufa?', '{"options": ["uciekają do Anglii", "zostają zamordowani", "ukrywają się w lesie", "przechodzą na stronę Makbeta"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Makbet rozkazuje zamordować żonę i dzieci Makdufa."}', '2025-10-24 22:16:55.283', '2025-10-24 22:16:55.283', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9nx00qrqhd9goyqpusn', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 3, 'Wyjaśnij, na czym polegała średniowieczna metoda scholastyczna i jakie były jej główne cechy.', '{"instruction": "Opisz metodę scholastyczną w filozofii i teologii. (60-80 słów)"}', NULL, '{"criteria": ["wyjaśnienie metody pytań i odpowiedzi (1 pkt)", "wskazanie racjonalnego wyjaśniania wiary (1 pkt)", "opisanie struktury dysputy scholastycznej (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-4,middle_ages,batch-2025-01}', '{"keyWords": ["racjonalizm", "pytania", "argumenty", "logika", "wiara i rozum"], "expectedAnswer": "Scholastyka to średniowieczna metoda filozoficzno-teologiczna polegająca na racjonalnym, logicznym wyjaśnianiu prawd wiary. Wykorzystywała aparat pojęciowy Arystotelesa. Charakteryzowała się precyzyjnymi wywodami, metodą quaestio - stawianiem pytań i poszukiwaniem odpowiedzi przez analizę argumentów za i przeciw. Struktura: 1) postawienie problemu, 2) argumenty przeciwne, 3) sed contra - argument własny, 4) rozwiązanie, 5) odpowiedzi na zarzuty. Hasło: ''credo ut intelligam'' - wierzę, aby rozumieć. Scholastyka dążyła do harmonii wiary i rozumu."}', '2025-10-24 22:16:54.189', '2025-10-24 22:16:54.189', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9nz00qsqhd9elg9w8h3', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Opisz symbolikę czterech ewangelistów w ikonografii średniowiecznej.', '{"instruction": "Wymień symbole ewangelistów i wyjaśnij ich pochodzenie. (50-70 słów)"}', NULL, '{"criteria": ["wymienienie symboli czterech ewangelistów (1 pkt)", "wskazanie pochodzenia z wizji Ezechiela (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-3,middle_ages,batch-2025-01}', '{"keyWords": ["Mateusz", "Marek", "Łukasz", "Jan", "tetramorf", "symbole"], "expectedAnswer": "Czterech ewangelistów symbolizowały tzw. tetramorf - cztery istoty z wizji proroka Ezechiela i Apokalipsy. Mateusz - anioł (człowiek), bo jego Ewangelia zaczyna się od rodowodu Chrystusa jako człowieka. Marek - lew (symbol królewskości). Łukasz - wół (ofiara), bo zaczyna od ofiary Zachariasza. Jan - orzeł (symbol tego, co boskie i wysokie), bo jego Ewangelia najbardziej teologiczna. Symbole te powszechnie występowały w sztuce średniowiecznej."}', '2025-10-24 22:16:54.192', '2025-10-24 22:16:54.192', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9o200qtqhd9cngsdd23', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 3, 'Wyjaśnij problem teodycei w filozofii średniowiecznej - jak filozofowie rozwiązywali problem istnienia zła.', '{"instruction": "Opisz, jak średniowieczni myśliciele tłumaczyli istnienie zła przy wszechmocnym i dobrym Bogu. (60-80 słów)"}', NULL, '{"criteria": ["wyjaśnienie problemu teodycei (1 pkt)", "przedstawienie rozwiązania augustyńskiego (1 pkt)", "wskazanie roli wolnej woli (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-4,middle_ages,batch-2025-01}', '{"keyWords": ["teodycea", "zło", "privatio boni", "wolna wola", "Augustyn"], "expectedAnswer": "Teodycea to próba usprawiedliwienia Boga wobec istnienia zła. Problem: jeśli Bóg jest wszechmocny i dobry, dlaczego istnieje zło? Św. Augustyn twierdził, że zło nie istnieje substancjalnie - jest tylko brakiem dobra (privatio boni), niebytem. Wszystko co Bóg stworzył jest dobre. Zło powstało przez wolną wolę aniołów (upadek Lucyfera) i ludzi (grzech pierworodny). Bóg nie stworzył zła, ale pozwolił na nie, dając stworzeniom wolność. Zło ma też funkcję pedagogiczną - przez kontrast uczy dobra."}', '2025-10-24 22:16:54.194', '2025-10-24 22:16:54.194', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9o400quqhd9k2qxbhks', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 3, 2, 'Opisz koncepcję miłości dworskiej (amor courtois) i jej znaczenie w kulturze średniowiecza.', '{"instruction": "Wyjaśnij, czym charakteryzowała się miłość dworska. (50-70 słów)"}', NULL, '{"criteria": ["charakterystyka miłości dworskiej (niespełniona, wyidealizowana) (1 pkt)", "wskazanie roli w kulturze rycerskiej (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-3,middle_ages,batch-2025-01}', '{"keyWords": ["nieosiągalna", "adoracja", "cierpienie", "doskonalenie", "rycerz i dama"], "expectedAnswer": "Amor courtois (miłość dworska) to średniowieczny model miłości wykształcony w kulturze trubadurów prowansalskich. Rycerz adorował nieosiągalną damę - zazwyczaj zamężną, wyższej pozycji społecznej. Miłość była platoniczna, nieszczęśliwa, pełna cierpienia i tęsknoty. Dama była niedostępna, ale inspirowała rycerza do wielkich czynów. Model ten gloryfikował kobietę, czynił z miłości drogę doskonalenia. Łączył ars amandi z ars bellandi - miłość i waleczność."}', '2025-10-24 22:16:54.196', '2025-10-24 22:16:54.196', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9o600qvqhd93btv0mqb', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'MIDDLE_AGES', 4, 3, 'Wyjaśnij, jak średniowieczna koncepcja czasu różniła się od współczesnej i jakie to miało konsekwencje kulturowe.', '{"instruction": "Opisz średniowieczne postrzeganie czasu i jego wpływ na kulturę. (70-90 słów)"}', NULL, '{"criteria": ["wskazanie różnicy: czas liturgiczny vs linearny (1 pkt)", "wyjaśnienie rytmu życia według kalendarza kościelnego (1 pkt)", "konsekwencje kulturowe (literatura, sztuka) (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-4,middle_ages,batch-2025-01}', '{"keyWords": ["czas liturgiczny", "cykliczny", "rok kościelny", "godziny kanoniczne", "sakralny"], "expectedAnswer": "W średniowieczu dominowało sakralne, cykliczne pojmowanie czasu - nie linearny postęp, ale powtarzający się rytm roku liturgicznego. Czas mierzono godzinami kanonicznymi (jutrznia, pryma, nieszpory), dzwonami kościelnymi, nie zegarami mechanicznymi. Życie podporządkowane było kalendarzowi kościelnemu - adwent, Boże Narodzenie, Wielki Post, Wielkanoc. To czas jakościowy, nie ilościowy - święta ważniejsze niż dni powszednie. Konsekwencje: literatura i sztuka koncentrowały się na ponadczasowych prawdach wiary, nie na przemianie historycznej. Historia rozumiana jako realizacja boskiego planu zbawienia."}', '2025-10-24 22:16:54.199', '2025-10-24 22:16:54.199', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9o900qwqhd9a46zhyoj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Jakie są ramy czasowe baroku w Europie?', '{"options": ["XV-XVI wiek", "XVI-XVII wiek", "XVII-XVIII wiek", "XVIII-XIX wiek"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Barok w Europie trwał od końca XVI wieku do połowy XVIII wieku (ok. 1600-1750)."}', '2025-10-24 22:16:54.202', '2025-10-24 22:16:54.202', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ob00qxqhd99wossxny', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Skąd pochodzi nazwa ''barok''?', '{"options": ["od łacińskiego słowa oznaczającego piękno", "od portugalskiego określenia nieregularnej perły", "od nazwiska artysty", "od nazwy miasta"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Nazwa ''barok'' pochodzi z portugalskiego ''barroco'' - nieregularna, dziwaczna perła. Początkowo miała charakter pejoratywny."}', '2025-10-24 22:16:54.204', '2025-10-24 22:16:54.204', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9oe00qyqhd9igv4orni', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Jaka koncepcja filozoficzna głosiła, że źródłem poznania są zmysły?', '{"options": ["racjonalizm", "idealizm", "realizm", "sensualizm"]}', '3', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Sensualizm to kierunek filozoficzny głoszący, że źródłem poznania są zmysły i doświadczenie zmysłowe."}', '2025-10-24 22:16:54.206', '2025-10-24 22:16:54.206', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9og00qzqhd9kp75lywe', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Kto stworzył filozofię racjonalizmu opartą na haśle ''Cogito ergo sum''?', '{"options": ["Kartezjusz (Descartes)", "Pascal", "Spinoza", "Leibniz"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "René Descartes (Kartezjusz) stworzył filozofię racjonalizmu z hasłem ''Cogito ergo sum'' - myślę, więc jestem."}', '2025-10-24 22:16:54.208', '2025-10-24 22:16:54.208', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9oi00r0qhd9nl5ap5s3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co oznacza łacińskie wyrażenie ''vanitas''?', '{"options": ["piękno", "mądrość", "marność", "wieczność"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Vanitas oznacza ''marność'' - kluczowe pojęcie baroku wyrażające przekonanie o przemijaniu i marności dóbr doczesnych."}', '2025-10-24 22:16:54.21', '2025-10-24 22:16:54.21', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ok00r1qhd99jktla5w', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co oznacza hasło ''carpe diem''?', '{"options": ["pamiętaj o śmierci", "chwytaj dzień, korzystaj z chwili", "wszystko przemija", "poznaj samego siebie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Carpe diem (łac. ''chwytaj dzień'') to hasło epikurejskie nakazujące korzystanie z przyjemności chwili obecnej."}', '2025-10-24 22:16:54.213', '2025-10-24 22:16:54.213', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9om00r2qhd92uphqoa2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co oznacza pojęcie ''theatrum mundi''?', '{"options": ["teatr miejski", "teatr dworski", "świat jako teatr, życie jako gra pozorów", "dramat barokowy"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Theatrum mundi (teatr świata) to barokowa koncepcja życia jako teatru, gdzie ludzie odgrywają role, a świat jest pełen pozorów."}', '2025-10-24 22:16:54.215', '2025-10-24 22:16:54.215', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9op00r3qhd9sshz4d5s', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Jak nazywa się polski nurt ideologiczny baroku?', '{"options": ["humanizm", "sarmatyzm", "oświecenie", "romantyzm"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Sarmatyzm to specyficznie polski nurt ideologiczny baroku, gloryfikujący szlachtę jako potomków starożytnych Sarmatów."}', '2025-10-24 22:16:54.217', '2025-10-24 22:16:54.217', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9or00r4qhd9d25blzdh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Która cecha NIE charakteryzuje baroku?', '{"options": ["kontrast i antyteza", "umiłowanie przepychu", "prostota i harmonia", "paradoks"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Prostota i harmonia charakteryzowały klasycyzm i renesans. Barok cechował się kontrastem, przepychem i złożonością."}', '2025-10-24 22:16:54.219', '2025-10-24 22:16:54.219', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ot00r5qhd90rik4xzf', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co to jest koncept w literaturze barokowej?', '{"options": ["rodzaj wiersza", "pomysłowa gra słowna, dowcipne skojarzenie", "teoria filozoficzna", "gatunek dramatyczny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Koncept to charakterystyczny dla baroku pomysłowy zwrot, dowcipne skojarzenie, gra słowna oparta na nieoczekiwanym połączeniu pojęć."}', '2025-10-24 22:16:54.222', '2025-10-24 22:16:54.222', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ov00r6qhd996pywtaj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Jaki styl architektoniczny dominował w baroku?', '{"options": ["monumentalny, pełen ozdób i złoceń", "surowy i minimalistyczny", "prosty i funkcjonalny", "asymetryczny i chaotyczny"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Architektura barokowa była monumentalna, bogata w zdobienia, złocenia, rzeźby - miała olśniewać przepychem."}', '2025-10-24 22:16:54.224', '2025-10-24 22:16:54.224', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ox00r7qhd9syec59h8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co to jest antytet(e)za?', '{"options": ["rodzaj wiersza", "zestawienie przeciwieństw", "powtórzenie słów", "pytanie retoryczne"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Antyteza to figura retoryczna polegająca na zestawieniu przeciwstawnych pojęć - bardzo charakterystyczna dla baroku."}', '2025-10-24 22:16:54.226', '2025-10-24 22:16:54.226', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9p000r8qhd9g52gj68e', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co to jest oksymoron?', '{"options": ["połączenie sprzecznych pojęć", "powtórzenie słów", "pytanie retoryczne", "przesada"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Oksymoron to połączenie sprzecznych, wykluczających się pojęć (np. ''głośna cisza'', ''żywy trup'') - typowe dla baroku."}', '2025-10-24 22:16:54.228', '2025-10-24 22:16:54.228', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9p200r9qhd9ia58fyhv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co to jest kontrreformacja?', '{"options": ["reforma Kościoła katolickiego", "ruch przeciw reformacji protestanckiej", "nurt filozoficzny", "styl w sztuce"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Kontrreformacja to ruch w łonie Kościoła katolickiego mający na celu walkę z reformacją protestancką i odnowę katolicyzmu."}', '2025-10-24 22:16:54.231', '2025-10-24 22:16:54.231', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9p400raqhd93bsy0ue3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Który zakon odegrał kluczową rolę w kontrreformacji?', '{"options": ["benedyktyni", "franciszkanie", "jezuici", "cystersi"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Jezuici (Towarzystwo Jezusowe założone przez św. Ignacego Loyolę) odegrali kluczową rolę w kontrreformacji, prowadząc szkoły i misje."}', '2025-10-24 22:16:54.233', '2025-10-24 22:16:54.233', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9p700rbqhd9undcqdzv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co to jest marinizm?', '{"options": ["styl w malarstwie", "nurt w literaturze barokowej pełen kunsztu i ozdób słownych", "teoria filozoficzna", "typ architektury"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Marinizm (od włoskiego poety Marina) to nurt w poezji barokowej charakteryzujący się wyszukanym stylem, koncep­tami i ozdobnością."}', '2025-10-24 22:16:54.235', '2025-10-24 22:16:54.235', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9p900rcqhd9uljd2pd3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co to jest emblematyka w baroku?', '{"options": ["rodzaj malarstwa", "połączenie obrazu, motta i komentarza niosące przesłanie moralne", "typ architektury", "gatunek literacki"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Emblematy to charakterystyczne dla baroku kompozycje składające się z obrazu (pictura), sentencji (inscriptio) i komentarza (subscriptio)."}', '2025-10-24 22:16:54.237', '2025-10-24 22:16:54.237', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9pb00rdqhd9pv51jz93', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co to jest fraszka?', '{"options": ["krótki utwór satyryczny o charakterze żartobliwym", "długi poemat epickie", "dramat", "powieść"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Fraszka to krótki utwór poetycki o charakterze satyrycznym, żartobliwym lub moraliza­torskim - gatunek uprawiany w polskim baroku."}', '2025-10-24 22:16:54.239', '2025-10-24 22:16:54.239', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9pd00reqhd9kge6r9vj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co to jest sonet?', '{"options": ["14-wersowy wiersz o określonym układzie rymów", "krótkie opowiadanie", "utwór dramatyczny", "pieśń ludowa"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Sonet to 14-wersowy wiersz składający się z dwóch czterowierszy i dwóch trójwierszy, o określonym układzie rymów."}', '2025-10-24 22:16:54.242', '2025-10-24 22:16:54.242', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9pf00rfqhd9vgagf9bk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co to jest oda?', '{"options": ["krótki wiersz satyryczny", "uroczysty wiersz pochwalny", "utwór dramatyczny", "powieść"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Oda to uroczysty utwór poetycki o charakterze pochwalnym, wzniosłym, często adresowany do ważnej osoby lub idei."}', '2025-10-24 22:16:54.244', '2025-10-24 22:16:54.244', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9pi00rgqhd99ui62vrx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co charakteryzowało sarmatyzm?', '{"options": ["krytykę szlachty", "pochwałę mieszczaństwa", "gloryfikację szlachty jako potomków Sarmatów", "krytykę Kościoła"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Sarmatyzm gloryfikował polską szlachtę jako potomków starożytnych Sarmatów, podkreślał jej wyjątkowość i cnoty rycerskie."}', '2025-10-24 22:16:54.246', '2025-10-24 22:16:54.246', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9pk00rhqhd9t8upjhw0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co oznacza pojęcie ''vanitas vanitatum''?', '{"options": ["piękno piękności", "marność nad marnościami", "chwała chwały", "wieczność wieków"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Vanitas vanitatum to łacińskie wyrażenie oznaczające ''marność nad marnościami'' - kluczowy motyw barokowy o przemijaniu."}', '2025-10-24 22:16:54.248', '2025-10-24 22:16:54.248', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9pm00riqhd9gc8jt3e5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Jaka funkcja języka dominowała w literaturze barokowej?', '{"options": ["emotywna", "fatyczna", "perswazyjna (retoryczna)", "poetycka"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "W baroku dominowała funkcja perswazyjna - literatura miała przekonywać, wpływać na odbiorcę poprzez retorykę."}', '2025-10-24 22:16:54.251', '2025-10-24 22:16:54.251', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9pp00rjqhd9ijeq9lhi', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co to jest trompe-l''oeil w sztuce barokowej?', '{"options": ["rodzaj rzeźby", "iluzja optyczna - malarstwo oszukujące oko", "typ architektury", "technika snycerska"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Trompe-l''oeil (fr. ''oszukanie oka'') to technika malarska tworząca iluzję trójwymiarowości - typowa dla baroku."}', '2025-10-24 22:16:54.253', '2025-10-24 22:16:54.253', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ps00rkqhd9d75xwvfw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Co symbolizowała czaszka w malarstwie barokowym?', '{"options": ["mądrość", "przemijanie i śmierć", "życie wieczne", "młodość"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Czaszka w malarstwie vanitas symbolizowała śmierć, przemijanie i marność dóbr ziemskich - memento mori."}', '2025-10-24 22:16:54.256', '2025-10-24 22:16:54.256', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9pu00rlqhd9k6bwkg8s', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest alegoreza?', '{"options": ["rodzaj wiersza", "interpretacja alegoryczna tekstu", "figura retoryczna", "gatunek dramatu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Alegoreza to interpretacja tekstu w sposób alegoryczny, poszukiwanie ukrytych, symbolicznych znaczeń - typowa dla baroku."}', '2025-10-24 22:16:54.258', '2025-10-24 22:16:54.258', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9pw00rmqhd98ofk3jmu', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest hiperbola?', '{"options": ["przesada, wyolbrzymienie", "niedopowiedzenie", "porównanie", "powtórzenie"]}', '0', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Hiperbola to figura retoryczna polegająca na przesadzie, wyolbrzymieniu - bardzo charakterystyczna dla baroku."}', '2025-10-24 22:16:54.26', '2025-10-24 22:16:54.26', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9py00rnqhd9laqrbmcj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Jaki typ miłości propagowano w poezji barokowej?', '{"options": ["tylko platoniczną", "tylko zmysłową", "zarówno duchową jak i zmysłową - kontrast", "tylko małżeńską"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Barok pokazywał dwoistość miłości - kontrast między miłością duchową, platoniczną a zmysłową, cielesną."}', '2025-10-24 22:16:54.263', '2025-10-24 22:16:54.263', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9q000roqhd938pzn6cp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest koncetyzm?', '{"options": ["teoria filozoficzna", "nadużywanie konceptów, dowcipnych skojarzeń", "styl w malarstwie", "typ budowli"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Koncetyzm (konceptyzm) to tendencja w literaturze barokowej do nadużywania konceptów - pomysłowych, dowcipnych skojarzeń."}', '2025-10-24 22:16:54.265', '2025-10-24 22:16:54.265', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9q300rpqhd9eroc6hwj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co charakteryzowało barokowe malarstwo iluzjonistyczne?', '{"options": ["realizm fotograficzny", "abstrakcję", "tworzenie złudzeń przestrzennych na płaskich powierzchniach", "minimalizm"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Malarstwo iluzjonistyczne baroku tworzyło złudzenia przestrzenne - np. sklepienia wydające się niebiańskimi przestrzeniami."}', '2025-10-24 22:16:54.267', '2025-10-24 22:16:54.267', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9q500rqqhd9j3gu1o2m', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest silva rerum?', '{"options": ["gatunek poetycki", "pamiętnik szlachecki - zbiór różnych zapisków", "kronika", "dramat"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Silva rerum (łac. ''las rzeczy'') to szlachecki pamiętnik-album zawierający różnorodne zapiski, wspomnienia, dokumenty."}', '2025-10-24 22:16:54.269', '2025-10-24 22:16:54.269', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9q700rrqhd9m9vljeoy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest diariusz?', '{"options": ["gatunek dramatu", "dziennik, opis wydarzeń z życia autora", "poemat epickie", "traktat filozoficzny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Diariusz to dziennik, relacja z podróży lub wydarzeń politycznych - gatunek popularny w baroku polskim."}', '2025-10-24 22:16:54.271', '2025-10-24 22:16:54.271', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9q900rsqhd9uum8f87f', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest anachronizm?', '{"options": ["figura retoryczna", "błąd chronologiczny - umieszczenie czegoś w niewłaściwej epoce", "rodzaj wiersza", "styl w sztuce"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Anachronizm to błąd chronologiczny, częsty w baroku - np. przedstawianie postaci antycznych w strojach współczesnych."}', '2025-10-24 22:16:54.273', '2025-10-24 22:16:54.273', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9qb00rtqhd9k39lp2se', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co oznacza pojęcie ''festina lente''?', '{"options": ["chwytaj dzień", "spiesz się powoli", "pamiętaj o śmierci", "wszystko przemija"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Festina lente (łac. ''spiesz się powoli'') to paradoksalne hasło barokowe wyrażające potrzebę rozwagi w działaniu."}', '2025-10-24 22:16:54.275', '2025-10-24 22:16:54.275', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9qd00ruqhd9msmuq81a', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest petrarkizm w poezji barokowej?', '{"options": ["nurt filozoficzny", "tradycja liryki miłosnej nawiązująca do Petrarki", "typ budowli", "teoria polityczna"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Petrarkizm to tradycja liryki miłosnej nawiązująca do poezji Petrarki - idealizacja kobiety, cierpienie miłosne."}', '2025-10-24 22:16:54.278', '2025-10-24 22:16:54.278', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9qf00rvqhd9781jwwiz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co charakteryzuje epicką twórczość baroku?', '{"options": ["realizm i prostota", "mitologizacja, kontrast komizmu i patosu", "obiektywizm", "minimalizm stylistyczny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Epika barokowa cechowała się mitologizacją, kontraste komizmu i patosu, barokowymi ozdobnikami stylistycznymi."}', '2025-10-24 22:16:54.28', '2025-10-24 22:16:54.28', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9qh00rwqhd9yu4kohpg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest topos?', '{"options": ["rodzaj wiersza", "utarty motyw, schemat literacki", "figura retoryczna", "gatunek dramatu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Topos to utarty motyw, schemat tematyczny często powtarzający się w literaturze - np. topos vanitas, locus amoenus."}', '2025-10-24 22:16:54.282', '2025-10-24 22:16:54.282', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9qj00rxqhd9pf6hfkgy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest locus amoenus?', '{"options": ["miejsce straszne", "miejsce przyjemne - idealizowany pejzaż sielankowy", "miasto", "pustkowia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Locus amoenus (łac. ''miejsce przyjemne'') to topos literacki - idealizowany krajobraz sielankowy, zazwyczaj miejsce miłosnych spotkań."}', '2025-10-24 22:16:54.284', '2025-10-24 22:16:54.284', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ql00ryqhd936ks0df0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest inwokacja w poezji barokowej?', '{"options": ["zakończenie utworu", "wezwanie do muz, bóstwa lub osoby o pomoc w tworzeniu", "figura retoryczna", "typ wiersza"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Inwokacja to wezwanie do muz, bóstwa lub patrona na początku utworu o pomoc i natchnienie w tworzeniu."}', '2025-10-24 22:16:54.286', '2025-10-24 22:16:54.286', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9qo00rzqhd9mvxq03s9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Który motyw NIE jest typowy dla baroku?', '{"options": ["vanitas - marność", "carpe diem - korzystaj z chwili", "harmonia i równowaga", "theatrum mundi - świat jako teatr"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Harmonia i równowaga są typowe dla renesansu i klasycyzmu, nie dla baroku pełnego kontrastów."}', '2025-10-24 22:16:54.288', '2025-10-24 22:16:54.288', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9qq00s0qhd9p0ho7s43', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co symbolizowały klepsydry w sztuce barokowej?', '{"options": ["mądrość", "bogactwo", "upływający czas i przemijanie", "radość życia"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Klepsydra (zegar piaskowy) symbolizowała upływający czas, przemijanie życia - element malarstwa vanitas."}', '2025-10-24 22:16:54.29', '2025-10-24 22:16:54.29', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9qs00s1qhd9uoergzjc', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest panegiryzm?', '{"options": ["krytyka władzy", "przesadne wychwalanie, pochlebstwo", "obiektywny opis", "satyra"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Panegiryzm to przesadne wychwalanie, pochlebstwo - cecha literatury barokowej, szczególnie polskiej (magnackie mecenaty)."}', '2025-10-24 22:16:54.292', '2025-10-24 22:16:54.292', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9qu00s2qhd9kzaq0zgx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Jak nazywano wiersze o tematyce żałobnej w baroku?', '{"options": ["sielanki", "epitafia", "ody", "hymny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Epitafium to wiersz żałobny napisany na cześć zmarłego - gatunek popularny w baroku."}', '2025-10-24 22:16:54.295', '2025-10-24 22:16:54.295', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9qw00s3qhd98rm6h5qe', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest sielanka?', '{"options": ["wiersz satyryczny", "utwór przedstawiający idealizowane życie pasterskie", "dramat", "pieśń religijna"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Sielanka to gatunek literacki przedstawiający idealizowane, spokojne życie pasterzy na łonie natury."}', '2025-10-24 22:16:54.297', '2025-10-24 22:16:54.297', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9qy00s4qhd9bnpclcha', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest enargeia?', '{"options": ["figura retoryczna", "obrazowość, plastyczność opisu", "rodzaj wiersza", "teoria filozoficzna"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Enargeia to obrazowość, plastyczność opisu - cecha charakterystyczna barokowej retoryki mająca wywołać wrażenie ''widzenia'' sceny."}', '2025-10-24 22:16:54.299', '2025-10-24 22:16:54.299', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9r100s5qhd99sd65daw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest apoftegmat?', '{"options": ["krótkie, trafne powiedzenie, sentencja", "długi poemat", "dramat", "powieść"]}', '0', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Apoftegmat to krótkie, trafne powiedzenie, sentencja zawierająca mądrość życiową - popularne w baroku."}', '2025-10-24 22:16:54.301', '2025-10-24 22:16:54.301', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9r300s6qhd94hicbtfe', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 1, 'Jak zaczyna się typowy barokowy sonet?', '{"options": ["od dwóch tercyn", "od jednego ośmiowiersza", "od dwóch czterowierszy (kwadryny)", "od swobodnej strofy"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Klasyczny sonet składa się z dwóch kwadryn (czterowierszy) i dwóch tercyn (trójwierszy)."}', '2025-10-24 22:16:54.303', '2025-10-24 22:16:54.303', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9r500s7qhd9cd2tn8kd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 1, 'Co to jest acumen?', '{"options": ["figura retoryczna", "dowcip, pomysłowość, koncept", "rodzaj wiersza", "gatunek dramatu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Acumen (łac.) to dowcip, pomysłowość, zdolność do tworzenia konceptów - ceniona w baroku cecha poetycka."}', '2025-10-24 22:16:54.305', '2025-10-24 22:16:54.305', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9r800s8qhd9hhjpnuey', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 2, 'Dopasuj pojęcia do ich znaczeń.', '{"leftColumn": [{"id": "A", "text": "Vanitas"}, {"id": "B", "text": "Carpe diem"}, {"id": "C", "text": "Memento mori"}, {"id": "D", "text": "Theatrum mundi"}], "rightColumn": [{"id": 1, "text": "pamiętaj o śmierci"}, {"id": 2, "text": "marność dóbr doczesnych"}, {"id": 3, "text": "chwytaj dzień"}, {"id": 4, "text": "świat jako teatr"}], "matchingType": "concepts_meanings"}', '[[0, 1], [1, 2], [2, 0], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Vanitas - marność, carpe diem - chwytaj dzień, memento mori - pamiętaj o śmierci, theatrum mundi - świat jako teatr."}', '2025-10-24 22:16:54.308', '2025-10-24 22:16:54.308', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ra00s9qhd9pqxteb51', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 2, 'Które cechy charakteryzują barok? (wybierz wszystkie poprawne)', '{"options": ["kontrast i antyteza", "prostota i harmonia", "przepych i ozdobność", "paradoks", "umiłowanie natury i prostoty"]}', '[0, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,baroque,batch-2025-01}', '{"explanation": "Barok charakteryzują: kontrast, antyteza, przepych, ozdobność i paradoks. Prostota i harmonia to cechy klasycyzmu."}', '2025-10-24 22:16:54.31', '2025-10-24 22:16:54.31', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9rc00saqhd9w7wivp2c', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 2, 'Dopasuj gatunki literackie do ich charakterystyki.', '{"leftColumn": [{"id": "A", "text": "Sonet"}, {"id": "B", "text": "Fraszka"}, {"id": "C", "text": "Oda"}, {"id": "D", "text": "Sielanka"}], "rightColumn": [{"id": 1, "text": "krótki utwór satyryczny"}, {"id": 2, "text": "utwór o życiu pasterskim"}, {"id": 3, "text": "14-wersowy wiersz"}, {"id": 4, "text": "uroczysty wiersz pochwalny"}], "matchingType": "genres_characteristics"}', '[[0, 2], [1, 0], [2, 3], [3, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Sonet - 14 wersów, fraszka - satyra, oda - pochwalny, sielanka - o życiu pasterskim."}', '2025-10-24 22:16:54.313', '2025-10-24 22:16:54.313', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9rf00sbqhd9dfs9vgug', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 2, 'Które symbole występowały w malarstwie vanitas? (wybierz wszystkie poprawne)', '{"options": ["czaszka", "klepsydra (zegar piaskowy)", "kwiaty", "tęcza", "instrumenty muzyczne"]}', '[0, 1, 2, 4]', NULL, '{historical_literary,closed_multiple,difficulty-2,baroque,batch-2025-01}', '{"explanation": "W malarstwie vanitas występowały: czaszki, klepsydry, zwiędłe kwiaty, instrumenty - symbole przemijania. Tęcza nie była typowym symbolem vanitas."}', '2025-10-24 22:16:54.315', '2025-10-24 22:16:54.315', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9rh00scqhd9rawz9z40', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 2, 'Uzupełnij informacje o baroku.', '{"gaps": [{"id": 1, "options": ["XV", "XVI", "XVII", "XVIII"]}, {"id": 2, "options": ["XVII", "XVIII", "XIX", "XX"]}, {"id": 3, "options": ["piękno", "perłę nieregularną", "złoto", "światło"]}, {"id": 4, "options": ["minimalizm", "kontrast", "harmonia", "prostota"]}], "textWithGaps": "Barok to epoka trwająca w Europie od [1] do [2] wieku. Nazwa pochodzi od portugalskiego słowa oznaczającego [3]. Główną cechą baroku był [4]."}', '[2, 1, 1, 1]', NULL, '{historical_literary,closed_multiple,difficulty-1,baroque,batch-2025-01}', '{"explanation": "Barok trwał od XVII do XVIII wieku, nazwa od perły nieregularnej, główna cecha to kontrast."}', '2025-10-24 22:16:54.318', '2025-10-24 22:16:54.318', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9rk00sdqhd9z4353cfe', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 2, 'Wyjaśnij, na czym polegała koncepcja ''theatrum mundi'' w baroku.', '{"instruction": "Opisz barokową koncepcję świata jako teatru. (40-60 słów)"}', NULL, '{"criteria": ["wyjaśnienie metafory świata jako teatru (1 pkt)", "wskazanie na pozory i role społeczne (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,baroque,batch-2025-01}', '{"keyWords": ["teatr", "role", "pozory", "maski", "iluzja"], "expectedAnswer": "Theatrum mundi (teatr świata) to barokowa koncepcja życia jako przedstawienia teatralnego. Świat to scena, ludzie to aktorzy odgrywający przydzielone im role społeczne. Życie pełne jest pozorów, masek, udawania. Ta koncepcja wyrażała barokowe przekonanie o iluzoryczności rzeczywistości, grze pozorów i niemożności poznania prawdy. Człowiek nigdy nie jest sobą, zawsze gra rolę."}', '2025-10-24 22:16:54.32', '2025-10-24 22:16:54.32', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9rm00seqhd93w8kw68k', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 2, 'Opisz główne cechy sarmatyzmu jako nurtu ideologicznego.', '{"instruction": "Wyjaśnij, czym charakteryzował się sarmatyzm. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie gloryfikacji szlachty (1 pkt)", "opisanie cech sarmatyzmu (cnoty, pochodzenie) (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,baroque,batch-2025-01}', '{"keyWords": ["szlachta", "Sarmaci", "cnoty rycerskie", "wolność", "tradycja"], "expectedAnswer": "Sarmatyzm to specyficznie polski nurt ideologiczny baroku gloryfikujący szlachtę. Szlachta uważała się za potomków starożytnych Sarmatów - wojowniczego ludu. Sarmatyzm podkreślał: poczucie wyższości szlachty, cnoty rycerskie (męstwo, honor), przywiązanie do tradycji, religijność katolicką, wolność szlachecką, ksenofobię. Wyrażał się w stroju (żupan, kontusz, szabla), obyczajach i literaturze panegirycznej."}', '2025-10-24 22:16:54.322', '2025-10-24 22:16:54.322', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9rp00sfqhd994fppe21', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'BAROQUE', 1, 2, 'Wyjaśnij różnicę między hasłami ''carpe diem'' a ''memento mori''.', '{"instruction": "Porównaj oba hasła i ich przesłanie. (30-50 słów)"}', NULL, '{"criteria": ["wyjaśnienie carpe diem (1 pkt)", "wyjaśnienie memento mori (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-1,baroque,batch-2025-01}', '{"keyWords": ["chwytaj dzień", "radość", "śmierć", "przemijanie", "kontrast"], "expectedAnswer": "Carpe diem (''chwytaj dzień'') to hasło epikurejskie nakazujące korzystanie z przyjemności życia, radość z chwili obecnej. Memento mori (''pamiętaj o śmierci'') to hasło przypominające o przemijaniu i śmierci, nakazujące przygotowanie na koniec. Oba hasła współistniały w baroku, tworząc charakterystyczny kontrast między radością życia a świadomością śmierci."}', '2025-10-24 22:16:54.325', '2025-10-24 22:16:54.325', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9rr00sgqhd9fkx7j72l', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 2, 'Opisz, czym charakteryzowała się barokowa architektura.', '{"instruction": "Wymień główne cechy architektury barokowej. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie przepychu i monumentalności (1 pkt)", "opisanie elementów dekoracyjnych (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,baroque,batch-2025-01}', '{"keyWords": ["przepych", "monumentalność", "złocenia", "dynamika", "iluzjonizm"], "expectedAnswer": "Architektura barokowa charakteryzowała się monumentalnością, przepychem i bogactwem dekoracji. Budowle miały dynamiczne, faliste formy, obfitowały w złocenia, rzeźby, freski. Fasady były bogate w detale, kolumny, pilastry. Wnętrza kościołów miały olśniewać wiernych - malowidła iluzjonistyczne na sklepieniach, bogate ołtarze. Celem było wywołanie zachwytu, wzruszenia, ukazanie potęgi Kościoła i monarchii."}', '2025-10-24 22:16:54.327', '2025-10-24 22:16:54.327', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9rt00shqhd9xurh9pmj', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'BAROQUE', 2, 2, 'Wyjaśnij, czym jest koncept w literaturze barokowej i podaj przykład.', '{"instruction": "Zdefiniuj koncept i zilustruj przykładem. (40-60 słów)"}', NULL, '{"criteria": ["definicja konceptu (1 pkt)", "podanie przykładu lub wyjaśnienie mechanizmu (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,baroque,batch-2025-01}', '{"keyWords": ["pomysłowość", "gra słów", "nieoczekiwane skojarzenie", "metafora", "zaskoczenie"], "expectedAnswer": "Koncept to pomysłowy, dowcipny zwrot słowny oparty na nieoczekiwanym skojarzeniu, grze słów lub paradoksie. Był oznaką kunsztu poetyckiego w baroku. Przykład: porównanie łez do pereł, oczu do słońc, włosów do złotych nici. Koncept łączył odległe pojęcia tworząc zaskakujące metafory. Celem było wywołanie zadziwienia czytelnika pomysłowością poety, pokazanie jego acumen - dowcipu."}', '2025-10-24 22:16:54.33', '2025-10-24 22:16:54.33', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9rv00siqhd9zkemadt7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kto jest autorem tragedii Antygona?', '{"options": ["Ajschylos", "Sofokles", "Eurypides", "Arystofanes"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Autorem Antygony jest Sofokles - jeden z trzech wielkich tragików greckich obok Ajschylosa i Eurypidesa."}', '2025-10-24 22:16:54.332', '2025-10-24 22:16:54.332', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9rx00sjqhd9dxikgzvh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Gdzie toczy się akcja tragedii Antygona?', '{"options": ["w Atenach", "w Sparcie", "w Tebach", "w Koryncie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Akcja tragedii toczy się w Tebach, starożytnym mieście greckim, które było siedzibą rodu Labdakidów."}', '2025-10-24 22:16:54.334', '2025-10-24 22:16:54.334', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9s000skqhd9h1306p95', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kim jest Antygona?', '{"options": ["córką Kreona", "córką Edypa", "żoną Hajmona", "królową Teb"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Antygona jest córką Edypa i Jokasty, siostrą Eteoklesa, Polinika i Ismeny."}', '2025-10-24 22:16:54.336', '2025-10-24 22:16:54.336', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9s200slqhd96exoza5o', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jak nazywa się siostra Antygony?', '{"options": ["Helena", "Ismena", "Eurydyka", "Ifigenia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Ismena jest młodszą siostrą Antygony, córką Edypa i Jokasty."}', '2025-10-24 22:16:54.338', '2025-10-24 22:16:54.338', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9s400smqhd9v5fxc6wl', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kim jest Kreon w tragedii?', '{"options": ["ojcem Antygony", "bratem Edypa", "wujem Antygony i władcą Teb", "wróżbitą"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Kreon jest bratem Jokasty, a więc wujem Antygony. Po śmierci Eteoklesa i Polinika obejmuje tron Teb."}', '2025-10-24 22:16:54.34', '2025-10-24 22:16:54.34', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9s600snqhd980fdwee9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jak nazywają się bracia Antygony?', '{"options": ["Eteokles i Polinik", "Kastor i Polluks", "Agamemnon i Menelaos", "Akwiles i Hektor"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Eteokles i Polinik to bracia Antygony, synowie Edypa, którzy zginęli w bratobójczej walce o władzę w Tebach."}', '2025-10-24 22:16:54.343', '2025-10-24 22:16:54.343', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9s800soqhd9yvlv4k29', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Co zakazał Kreon po śmierci Polinika?', '{"options": ["mówienia o nim", "noszenia żałoby", "pochowania go", "modlitwy za jego duszę"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Kreon wydał edykt zakazujący pochowania Polinika, uznając go za zdrajcę ojczyzny, który napadł na rodzime Teby."}', '2025-10-24 22:16:54.345', '2025-10-24 22:16:54.345', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9sb00spqhd9s2ky5q1p', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jakiej karze podlegał ten, kto złamał zakaz Kreona?', '{"options": ["wygnaniu z miasta", "więzieniu dożywotniemu", "śmierci przez ukamienowanie", "utracie majątku"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Kreon zagroził karą śmierci przez ukamienowanie każdemu, kto ośmieli się pogrzebać ciało Polinika."}', '2025-10-24 22:16:54.347', '2025-10-24 22:16:54.347', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9sd00sqqhd9juvutnoq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kto pochował ciało Polinika?', '{"options": ["Ismena", "Antygona", "Hajmon", "strażnicy"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Antygona pogrzebała brata wbrew zakazowi Kreona, posypując jego ciało ziemią i dokonując obrzędów pogrzebowych."}', '2025-10-24 22:16:54.349', '2025-10-24 22:16:54.349', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9sf00srqhd9kqrd1iyo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kim jest Hajmon?', '{"options": ["bratem Antygony", "synem Kreona i narzeczonym Antygony", "strażnikiem miejskim", "ślepym wieszczem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Hajmon jest synem Kreona i narzeczonym Antygony. Kocha ją i próbuje przekonać ojca do zmiany wyroku."}', '2025-10-24 22:16:54.351', '2025-10-24 22:16:54.351', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9sh00ssqhd931c4d3nd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Do jakiej kary został zmieniony wyrok na Antygonę?', '{"options": ["spalenia na stosie", "zamurowania żywcem w grocie skalnej", "utopienia", "powieszenia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Kreon zmienił wyrok z publicznego ukamienowania na zamurowanie Antygony żywcem w grocie skalnej, by formalnie uniknąć odpowiedzialności za przelanie krwi."}', '2025-10-24 22:16:54.354', '2025-10-24 22:16:54.354', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9sp00stqhd9fd566w93', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kim jest Tejrezjasz?', '{"options": ["ślepym wieszczem", "strażnikiem", "dowódcą wojsk", "członkiem chóru"]}', '0', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Tejrezjasz to ślepý wróżbita, szanowany prorok, który ostrzega Kreona przed gniewem bogów."}', '2025-10-24 22:16:54.361', '2025-10-24 22:16:54.361', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9sr00suqhd93mdfwtos', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Dlaczego Antygona pogrzebała Polinika?', '{"options": ["bo była zakochana w bracie", "z obowiązku wobec praw boskich i rodzinnych", "z zemsty na Kreonie", "aby zostać bohaterką"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Antygona pogrzebała brata, kierując się prawami boskimi i niepisanymi prawami rodzinnymi, które dla niej były wyższe od edyktu Kreona."}', '2025-10-24 22:16:54.364', '2025-10-24 22:16:54.364', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9su00svqhd9me72q2mg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Dlaczego Ismena odmówiła pomocy Antygonie?', '{"options": ["nie kochała Polinika", "ze strachu przed karą i poczucia słabości jako kobiety", "była lojalna wobec Kreona", "nie wierzyła w bogów"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Ismena odmówiła ze strachu przed śmiercią i z przekonania, że kobiety są zbyt słabe, by sprzeciwiać się władzy mężczyzn."}', '2025-10-24 22:16:54.366', '2025-10-24 22:16:54.366', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9sw00swqhd949mbs50h', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jakie argumenty przytacza Antygona broniąc swojego czynu?', '{"options": ["mówi, że Polinik był niewinny", "odwołuje się do niepisanych praw boskich starszych od dekretów Kreona", "twierdzi, że Kreon nie ma prawa do wydawania dekretów", "odmawia wyjaśnień"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Antygona powołuje się na niepisane, niezmienne prawa boskie, które są wieczne i wyższe od praw ludzkich. Mówi: ''Nie Zeus ani Dike ogłosili ten zakaz''."}', '2025-10-24 22:16:54.368', '2025-10-24 22:16:54.368', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9sz00sxqhd9p7z1ssse', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jak Hajmon próbuje przekonać ojca do zmiany wyroku?', '{"options": ["groźbami i przemocą", "odwołując się do opinii ludu i głosu rozumu", "oferując pieniądze", "planując zamach stanu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Hajmon używa argumentów racjonalnych: mówi o opinii ludu, który sympatyzuje z Antygoną, ostrzega przed pycha ojca i radzi elastyczność w rządzeniu."}', '2025-10-24 22:16:54.371', '2025-10-24 22:16:54.371', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9t100syqhd9qwi98leg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co przepowiada Tejrezjasz Kreonowi?', '{"options": ["zwycięstwo w wojnie", "gniew bogów i śmierć kogoś bliskiego", "długie panowanie", "bogactwo i chwałę"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Tejrezjasz ostrzega Kreona, że ściągnął na siebie gniew bogów i że zapłaci synem za swoje przewiny wobec zmarłych i żywych."}', '2025-10-24 22:16:54.373', '2025-10-24 22:16:54.373', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9t300szqhd9uxy7nrur', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kiedy Kreon zmienia zdanie i postanawia uwolnić Antygonę?', '{"options": ["gdy Hajmon go o to błaga", "gdy lud się zbuntuje", "po przepowiedni Tejrezjasza", "nigdy nie zmienia zdania"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Kreon zmienia zdanie dopiero po straszliwej przepowiedni Tejrezjasza, ale jest już za późno - Antygona popełniła samobójstwo."}', '2025-10-24 22:16:54.376', '2025-10-24 22:16:54.376', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9t500t0qhd9xcofm75c', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jak ginie Antygona?', '{"options": ["zostaje ukamienowana", "popełnia samobójstwo przez powieszenie", "umiera z głodu w grocie", "zostaje zabita przez Kreona"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Antygona popełnia samobójstwo, wieszając się w grocie, zanim Kreon zdąży ją uwolnić."}', '2025-10-24 22:16:54.378', '2025-10-24 22:16:54.378', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9t800t1qhd9s5i50afh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jak ginie Hajmon?', '{"options": ["w bitwie", "zostaje zabity przez Kreona", "popełnia samobójstwo przy ciele Antygony", "umiera z rozpaczy"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Hajmon popełnia samobójstwo przy ciele ukochanej Antygony, przepełniony rozpaczą i gniewem na ojca."}', '2025-10-24 22:16:54.38', '2025-10-24 22:16:54.38', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ta00t2qhd9ts6gxao1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Kim jest Eurydyka?', '{"options": ["matką Antygony", "żoną Kreona i matką Hajmona", "siostrą Ismeny", "służącą w pałacu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Eurydyka jest żoną Kreona i matką Hajmona. Ginie w finale tragedii."}', '2025-10-24 22:16:54.382', '2025-10-24 22:16:54.382', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9tc00t3qhd9lywu0put', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jak ginie Eurydyka?', '{"options": ["z choroby", "popełnia samobójstwo po śmierci syna", "zostaje zabita w walce", "umiera ze starości"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Eurydyka popełnia samobójstwo po usłyszeniu wieści o śmierci syna Hajmona, obwiniając za to Kreona."}', '2025-10-24 22:16:54.384', '2025-10-24 22:16:54.384', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9te00t4qhd9l06nmf8x', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jaki los spotyka Kreona na końcu tragedii?', '{"options": ["zostaje królem i rządzi mądrze", "zostaje wygnany z Teb", "traci syna i żonę, pozostaje zrujnowanym człowiekiem", "popełnia samobójstwo"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Kreon traci wszystko: syna Hajmona i żonę Eurydykę. Pozostaje żywy, ale całkowicie zrujnowany psychicznie, uznając swoją głupotę i pychę."}', '2025-10-24 22:16:54.386', '2025-10-24 22:16:54.386', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9tg00t5qhd92gmpfqbz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Jak nazywa się przeklęty ród, z którego pochodzi Antygona?', '{"options": ["Atryda", "Labdakida", "Pelopida", "Tantalida"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Antygona jest ostatnią przedstawicielką przeklętego rodu Labdakidów, którego protoplastą był Labdakos, dziadek Edypa."}', '2025-10-24 22:16:54.389', '2025-10-24 22:16:54.389', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evamc0156qhd9peq5gndd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Jakim wierszem napisany jest ''Pan Tadeusz''?', '{"options": ["8-zgłoskowcem", "11-zgłoskowcem", "13-zgłoskowcem", "Wierszem białym"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "''Pan Tadeusz'' napisany jest polskim 13-zgłoskowcem (7+6) z rymami parzystymi (aabbcc...). To tradycyjny polski wers epicki."}', '2025-10-24 22:16:55.428', '2025-10-24 22:16:55.428', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ti00t6qhd9cwzy821p', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Kto w dramacie greckim komentuje wydarzenia i wyraża opinie zbiorowe?', '{"options": ["narrator", "chór", "prorok", "strażnicy"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Chór w tragedii greckiej składa się z obywateli Teb i pełni funkcję komentatora wydarzeń, wyraża opinie zbiorowe i refleksje moralne."}', '2025-10-24 22:16:54.391', '2025-10-24 22:16:54.391', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9tl00t7qhd92kjmrg37', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jaki główny konflikt stanowi oś tragedii?', '{"options": ["konflikt między Antygoną a Ismeną", "konflikt między prawami boskimi a ludzkimi", "konflikt między Tebami a wrogami", "konflikt między Hajmonem a Kreonem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Główny konflikt tragedii to starcie praw boskich (reprezentowanych przez Antygonę) z prawami ludzkimi, państwowymi (reprezentowanymi przez Kreona)."}', '2025-10-24 22:16:54.393', '2025-10-24 22:16:54.393', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9tn00t8qhd90r1q99jz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Która postać z „Antygony” mówi: „Współkochać przyszłam, nie współnienawidzieć”?', '{"options": ["Ismena", "Antygona", "Eurydyka", "Chór"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "To słowa Antygony, która wyjaśnia swoją motywację - przyszła na świat, aby kochać, nie nienawidzić. Wyraża to jej naturę i szlachetność."}', '2025-10-24 22:16:54.395', '2025-10-24 22:16:54.395', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9tr00t9qhd9ajclmxle', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co oznacza greckie pojęcie ''hybris'' w kontekście tragedii?', '{"options": ["mądrość i rozsądek", "pychę i przekroczenie granic wyznaczonych przez bogów", "odwagę w walce", "sprawiedliwość"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Hybris to pycha, zuchwałość i przekroczenie granic wyznaczonych przez bogów i naturę. W tragedii greckiej zawsze prowadzi do katastrofy."}', '2025-10-24 22:16:54.399', '2025-10-24 22:16:54.399', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9tt00taqhd9fhgxe99r', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Który z braci Antygony bronił Teb?', '{"options": ["Polinik", "Eteokles", "obaj", "żaden"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Eteokles bronił Teb i został pochowany z honorami jako bohater. Polinik natomiast zaatakował rodzinne miasto i został uznany za zdrajcę."}', '2025-10-24 22:16:54.401', '2025-10-24 22:16:54.401', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9tv00tbqhd9z15qpfnv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'Który z braci Antygony został uznany za zdrajcę?', '{"options": ["Eteokles", "Polinik", "obaj", "żaden"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Polinik został uznany za zdrajcę, ponieważ przyprowadził obce wojska i zaatakował rodzinne Teby."}', '2025-10-24 22:16:54.404', '2025-10-24 22:16:54.404', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9tx00tcqhd9r8hjmjnb', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Dopasuj postacie do ich ról w tragedii.', '{"leftColumn": [{"id": "A", "text": "Antygona"}, {"id": "B", "text": "Kreon"}, {"id": "C", "text": "Tejrezjasz"}, {"id": "D", "text": "Hajmon"}], "rightColumn": [{"id": 1, "text": "ślepý wieszcz ostrzegający przed gniewem bogów"}, {"id": 2, "text": "władca Teb wydający edykt"}, {"id": 3, "text": "córka Edypa grzebiąca brata"}, {"id": 4, "text": "syn Kreona, narzeczony Antygony"}], "matchingType": "character_role"}', '[[0, 2], [1, 1], [2, 0], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Antygona grzebie brata, Kreon jest władcą wydającym edykt, Tejrezjasz to wieszcz, Hajmon to syn Kreona i narzeczony Antygony."}', '2025-10-24 22:16:54.406', '2025-10-24 22:16:54.406', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9tz00tdqhd981jtkfro', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Które cechy charakteryzują Antygonę? (wybierz wszystkie poprawne)', '{"options": ["odważna i zdecydowana", "podporządkowuje się prawom państwowym", "lojalna wobec rodziny", "kieruje się prawami boskimi", "tchórzliwa i uległa"]}', '[0, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Antygona jest odważna, lojalna wobec rodziny i kieruje się prawami boskimi. Nie podporządkowuje się prawom państwowym Kreona i nie jest tchórzliwa."}', '2025-10-24 22:16:54.408', '2025-10-24 22:16:54.408', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9u100teqhd9tiac9vye', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Dopasuj postacie do ich końcowego losu.', '{"leftColumn": [{"id": "A", "text": "Antygona"}, {"id": "B", "text": "Hajmon"}, {"id": "C", "text": "Eurydyka"}, {"id": "D", "text": "Kreon"}], "rightColumn": [{"id": 1, "text": "samobójstwo przy ciele ukochanej"}, {"id": 2, "text": "przeżywa, ale traci wszystko"}, {"id": 3, "text": "samobójstwo przez powieszenie w grocie"}, {"id": 4, "text": "samobójstwo po śmierci syna"}], "matchingType": "character_fate"}', '[[0, 2], [1, 0], [2, 3], [3, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Antygona wiesza się w grocie, Hajmon popełnia samobójstwo przy jej ciele, Eurydyka zabija się po śmierci syna, a Kreon przeżywa jako zrujnowany człowiek."}', '2025-10-24 22:16:54.41', '2025-10-24 22:16:54.41', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9u400tfqhd9o504nkz3', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 2, 'Uzupełnij informacje o fabule tragedii.', '{"gaps": [{"id": 1, "options": ["Eteoklesa", "Hajmona", "Kreona", "Edypa"]}, {"id": 2, "options": ["Polinika", "Tejrezjasza", "Edypa", "Kreona"]}, {"id": 3, "options": ["Eteokles", "Hajmon", "Kreon", "Edyp"]}, {"id": 4, "options": ["chwalenia", "oplakiwania", "pochowania", "nazywania"]}], "textWithGaps": "Po bratobójczej walce [1] i [2], władzę w Tebach obejmuje [3]. Wydaje on edykt zakazujący [4] Polinika."}', '[0, 0, 2, 2]', NULL, '{historical_literary,closed_multiple,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Po bratobójczej walce Eteoklesa i Polinika, władzę obejmuje Kreon, który zakazuje pochowania Polinika."}', '2025-10-24 22:16:54.412', '2025-10-24 22:16:54.412', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaid013fqhd979eqpjaw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Co oznacza przepowiednia o lesie Birnam?', '{"options": ["las zostanie wycięty", "las spłonie", "Makbet będzie bezpieczny, dopóki las nie przyjdzie do Dunsinane", "w lesie ukrywa się wróg"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Wiedźmy mówią, że Makbet będzie bezpieczny, dopóki las Birnam nie przyjdzie do Dunsinane."}', '2025-10-24 22:16:55.285', '2025-10-24 22:16:55.285', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9u600tgqhd9vcex6hhv', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Które zdania dotyczące Kreona są prawdziwe? (wybierz wszystkie poprawne)', '{"options": ["jest władcą Teb", "wydaje edykt zakazujący pochówku Polinika", "od początku słucha rad Tejrezjasza", "traci syna i żonę", "jest bratem Edypa"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Prawdziwe: Kreon jest władcą Teb, wydaje edykt i traci rodzinę. Fałszywe: nie słucha od razu Tejrezjasza, jest bratem Jokasty (nie Edypa)."}', '2025-10-24 22:16:54.414', '2025-10-24 22:16:54.414', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9u800thqhd99jxjfhrv', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Dopasuj argumenty do postaci, które je wypowiadają.', '{"leftColumn": [{"id": "A", "text": "Prawa boskie są wieczne i niezmienne"}, {"id": "B", "text": "Porządek państwowy jest najważniejszy"}, {"id": "C", "text": "Lud sympatyzuje z Antygoną"}, {"id": "D", "text": "Kobiety są zbyt słabe, by sprzeciwiać się władzy"}], "rightColumn": [{"id": 1, "text": "Ismena"}, {"id": 2, "text": "Hajmon"}, {"id": 3, "text": "Antygona"}, {"id": 4, "text": "Kreon"}], "matchingType": "arguments_characters"}', '[[0, 2], [1, 3], [2, 1], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Antygona broni praw boskich, Kreon - porządku państwowego, Hajmon mówi o opinii ludu, Ismena o słabości kobiet."}', '2025-10-24 22:16:54.416', '2025-10-24 22:16:54.416', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ua00tiqhd9ryztk1z4', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 2, 'Które motywy pojawiają się w tragedii Antygona? (wybierz wszystkie poprawne)', '{"options": ["konflikt praw boskich i ludzkich", "lojalność rodzinna", "pycha władcy (hybris)", "miłość romantyczna (Hajmon i Antygona)", "podróż morska", "pogrzeb i obrzędy"]}', '[0, 1, 2, 3, 5]', NULL, '{historical_literary,closed_multiple,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "W tragedii występują: konflikt praw, lojalność rodzinna, pycha Kreona, miłość Hajmona i Antygony oraz motyw pogrzebowy. Nie ma motywu podróży morskiej."}', '2025-10-24 22:16:54.419', '2025-10-24 22:16:54.419', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ud00tjqhd9rmdqp4ip', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, dlaczego Antygona zdecydowała się pogrzebać Polinika.', '{"instruction": "Podaj główne powody decyzji Antygony i wyjaśnij, jakimi zasadami się kierowała. (30-50 słów)"}', NULL, '{"criteria": ["wskazanie obowiązku wobec rodziny i brata (1 pkt)", "odwołanie się do praw boskich jako wyższych od ludzkich (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["prawa boskie", "rodzina", "obowiązek", "Hades", "wieczne prawa"], "expectedAnswer": "Antygona pogrzebała Polinika kierując się obowiązkiem rodzinnym i prawami boskimi. Wierzyła, że niepisane, wieczne prawa bogów są wyższe od edyktów Kreona. Hades wymaga równych praw dla wszystkich zmarłych, niezależnie od ich czynów za życia."}', '2025-10-24 22:16:54.421', '2025-10-24 22:16:54.421', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9uf00tkqhd9hs3iz9xs', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Opisz, jakich argumentów używa Kreon, broniąc swojego edyktu.', '{"instruction": "Wyjaśnij, dlaczego Kreon uważa swój edykt za słuszny. (30-50 słów)"}', NULL, '{"criteria": ["wskazanie na porządek państwowy i dobro Teb (1 pkt)", "rozróżnienie na obrońców i zdrajców ojczyzny (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["porządek państwowy", "zdrajca", "dobro Teb", "Eteokles", "obrońca"], "expectedAnswer": "Kreon uważa, że porządek państwowy jest najważniejszy. Twierdzi, że Polinik był zdrajcą, który zaatakował Teby, dlatego nie zasługuje na honorowy pochówek. Eteokles bronił miasta i został pochowany z honorami. Kreon wierzy, że dobro państwa przewyższa prawa rodzinne."}', '2025-10-24 22:16:54.423', '2025-10-24 22:16:54.423', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9uh00tlqhd9ztmgf69o', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, dlaczego Ismena odmówiła pomocy Antygonie.', '{"instruction": "Opisz powody odmowy Ismeny w 2-3 zdaniach. (30-50 słów)"}', NULL, '{"criteria": ["wskazanie strachu przed śmiercią (1 pkt)", "poczucie słabości jako kobiety wobec władzy mężczyzn (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["strach", "kara", "słabość", "kobieta", "władza"], "expectedAnswer": "Ismena odmówiła ze strachu przed karą śmierci. Czuła się zbyt słaba jako kobieta, by sprzeciwiać się edyktowi męskiego władcy. W przeciwieństwie do siostry, nie miała odwagi przeciwstawić się Kreonowi."}', '2025-10-24 22:16:54.426', '2025-10-24 22:16:54.426', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9uj00tmqhd9a7ggf9rk', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Opisz, w jaki sposób Hajmon próbuje przekonać ojca do zmiany wyroku.', '{"instruction": "Wymień główne argumenty Hajmona w rozmowie z Kreonem. (40-60 słów)"}', NULL, '{"criteria": ["odwołanie się do opinii ludu (1 pkt)", "ostrzeżenie przed pychą i sztywnością w rządzeniu (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["opinia ludu", "pycha", "elastyczność", "drzewo", "rozsądek"], "expectedAnswer": "Hajmon mówi ojcu, że lud Teb sympatyzuje z Antygoną i uważa wyrok za niesprawiedliwy. Ostrzega przed pychą i brakiem elastyczności, porównując dobrego władcę do drzewa, które ugina się pod naporem wiatru. Radzi ojcu, by nie był zbyt uparty i wysłuchał głosu rozsądku."}', '2025-10-24 22:16:54.428', '2025-10-24 22:16:54.428', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ul00tnqhd9ci0zs4o9', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, co przepowiada Tejrezjasz i dlaczego Kreon w końcu zmienia zdanie.', '{"instruction": "Opisz przepowiednię wieszcza i reakcję Kreona. (40-60 słów)"}', NULL, '{"criteria": ["przepowiednia gniewu bogów i śmierci bliskiej osoby (1 pkt)", "zmiana decyzji Kreona ze strachu przed karą (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["gniew bogów", "przepowiednia", "syn", "strach", "za późno"], "expectedAnswer": "Tejrezjasz przepowiada Kreonowi gniew bogów za bezczeszczenie zmarłego i skazanie żywej na śmierć. Ostrzega, że Kreon zapłaci synem za swoje przewiny. Przerażony prorok zmienia zdanie ze strachu przed straszliwą karą, ale jest już za późno - Antygona i Hajmon giną."}', '2025-10-24 22:16:54.43', '2025-10-24 22:16:54.43', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaif013gqhd93vq8nmdi', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'W jaki sposób Lady Makbet umiera?', '{"options": ["zostaje zabita", "umiera z choroby", "popełnia samobójstwo", "ginie w bitwie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Lady Makbet popełnia samobójstwo, nie mogąc znieść wyrzutów sumienia."}', '2025-10-24 22:16:55.287', '2025-10-24 22:16:55.287', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9uo00toqhd92nvh5svw', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Opisz końcowy los Kreona i wyjaśnij, czego go nauczyło cierpienie.', '{"instruction": "Wyjaśnij, co traci Kreon i do jakich wniosków dochodzi. (40-60 słów)"}', NULL, '{"criteria": ["utrata syna Hajmona i żony Eurydyki (1 pkt)", "uznanie własnej głupoty i pychy (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["Hajmon", "Eurydyka", "samobójstwo", "pycha", "głupota", "katastrofa"], "expectedAnswer": "Kreon traci syna Hajmona, który popełnia samobójstwo, oraz żonę Eurydykę, która również się zabija obwiniając męża. Pozostaje żywy, ale całkowicie zrujnowany. Przyznaje się do własnej głupoty i pychy, prosząc o śmierć. Nauczył się, że pycha prowadzi do katastrofy."}', '2025-10-24 22:16:54.432', '2025-10-24 22:16:54.432', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9uq00tpqhd93ak7t3gz', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Scharakteryzuj krótko postawę Ismeny wobec Antygony.', '{"instruction": "Opisz różnicę między siostrami i ich wyborami. (30-50 słów)"}', NULL, '{"criteria": ["Ismena jest uległa i bojaźliwa (1 pkt)", "Antygona jest odważna i bezkompromisowa (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["uległa", "bojaźliwa", "odważna", "bezkompromisowa", "konformizm", "heroizm"], "expectedAnswer": "Ismena jest uległa, bojaźliwa i pragmatyczna. Boi się śmierci i uważa, że kobiety nie powinny sprzeciwiać się mężczyznom. Antygona jest odważna, bezkompromisowa i kieruje się wyższymi wartościami. Ismena reprezentuje konformizm, Antygona - heroizm."}', '2025-10-24 22:16:54.434', '2025-10-24 22:16:54.434', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9us00tqqhd9bx5ta4d3', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 2, 'Wyjaśnij, kim był Edyp i jaki związek miał z Antygoną.', '{"instruction": "Opisz postać Edypa i jego relację rodzinną z Antygoną. (30-50 słów)"}', NULL, '{"criteria": ["Edyp był królem Teb (1 pkt)", "był ojcem Antygony (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-1,antiquity,batch-2025-01}', '{"keyWords": ["król Teb", "ojciec", "Jokasta", "przeklęty ród", "Labdakidzi"], "expectedAnswer": "Edyp był królem Teb i ojcem Antygony. Nieświadomie zabił swojego ojca Lajosa i poślubił własną matkę Jokastę. Z tego kazirodczego związku urodziły się czworo dzieci: Antygona, Ismena, Eteokles i Polinik. Ród Labdakidów był przeklęty."}', '2025-10-24 22:16:54.436', '2025-10-24 22:16:54.436', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9uu00trqhd9yz8j8f6i', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, jaka jest rola chóru w tragedii Antygona.', '{"instruction": "Opisz funkcję chóru w dramacie greckim na przykładzie Antygony. (40-60 słów)"}', NULL, '{"criteria": ["komentowanie wydarzeń (1 pkt)", "wyrażanie opinii zbiorowej i refleksji moralnych (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["obywatele Teb", "komentarz", "opinia zbiorowa", "filozofia", "pycha"], "expectedAnswer": "Chór w Antygonie składa się z obywateli Teb i pełni funkcję komentatora wydarzeń. Wyraża opinie zbiorowe, filozofuje o kondycji ludzkiej i losie. Chór przestrzega przed pychą, mówi o potędze człowieka, a na końcu podsumowuje tragedię stwierdzając, że bogowie karzą pychę."}', '2025-10-24 22:16:54.439', '2025-10-24 22:16:54.439', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ux00tsqhd9h6y6srw1', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Wyjaśnij, co oznacza pojęcie ''tragizmu'' na przykładzie sytuacji Antygony.', '{"instruction": "Opisz sytuację tragiczną Antygony - dlaczego każdy wybór był zły. (40-60 słów)"}', NULL, '{"criteria": ["sytuacja bez wyjścia - każdy wybór jest zły (1 pkt)", "konflikt wartości: obowiązek rodzinny vs posłuszeństwo władzy (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["sytuacja bez wyjścia", "dylemat", "wartości", "konflikt", "utrata"], "expectedAnswer": "Tragizm to sytuacja bez wyjścia, gdzie każdy wybór prowadzi do utraty ważnej wartości. Antygona stoi przed dylematem: jeśli pogrzebie brata, zginie; jeśli nie pogrzebie, obrazi bogów i zdradzi rodzinę. Nie może wybrać dobrze - musi odrzucić coś, co jest dla niej ważne."}', '2025-10-24 22:16:54.441', '2025-10-24 22:16:54.441', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9uz00ttqhd9y2874siv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 1, 1, 'W jakiej epoce literackiej powstała tragedia Antygona?', '{"options": ["w średniowieczu", "w starożytności (antyk)", "w renesansie", "w oświeceniu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,antiquity,batch-2025-01}', '{"explanation": "Antygona to dramat antyczny - powstał w starożytnej Grecji w V wieku p.n.e."}', '2025-10-24 22:16:54.444', '2025-10-24 22:16:54.444', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9v200tuqhd9v0mu7b4p', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jaką funkcję pełni postać Tejrezjasza w strukturze tragedii?', '{"options": ["komicznego reliffu", "narratora opowiadającego historię", "głosu bogów i ostrzeżenia przed katastrofą", "sprzymierzeńca Kreona"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Tejrezjasz jako ślepý wieszcz reprezentuje wolę bogów, ostrzega Kreona przed katastrofą i przepowiada przyszłość - jest głosem wyższych sił."}', '2025-10-24 22:16:54.446', '2025-10-24 22:16:54.446', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9v400tvqhd90roama0v', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Dlaczego Kreon zmienił karę z ukamienowania na zamurowanie w grocie?', '{"options": ["z litości nad Antygoną", "na prośbę Hajmona", "aby formalnie uniknąć odpowiedzialności za przelanie krwi", "z rozkazu bogów"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Kreon zmienił wyrok na zamurowanie żywcem w grocie, aby formalnie uniknąć odpowiedzialności za bezpośrednie przelanie krwi - Antygona miała umrzeć ''sama'', z głodu lub pragnienia."}', '2025-10-24 22:16:54.448', '2025-10-24 22:16:54.448', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9v600twqhd9cp2chyj5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co symbolizuje bratobójcza walka Eteoklesa i Polinika?', '{"options": ["walkę dobra ze złem", "konflikt pokoleń", "ciągłość klątwy rodu i tragedii rodzinnej", "walkę o niepodległość"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Bratobójcza walka to kolejny element klątwy ciążącej na rodzie Labdakidów - synowie Edypa zabijają się nawzajem, kontynuując tragiczne dziedzictwo rodziny."}', '2025-10-24 22:16:54.451', '2025-10-24 22:16:54.451', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9v900txqhd9paxvqu5h', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jaka jest główna różnica w podejściu do prawa między Antygoną a Kreonem?', '{"options": ["Antygona wierzy w prawo ludzkie, Kreon w boskie", "Antygona wierzy w prawa boskie i niepisane, Kreon w prawo stanowione przez władcę", "oboje wierzą w te same prawa", "Antygona nie wierzy w żadne prawa"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Antygona kieruje się prawami boskimi i niepisanymi prawami natury, które są wieczne i niezmienne. Kreon natomiast uważa, że prawo stanowione przez władcę (edykt) jest najważniejsze i nadrzędne."}', '2025-10-24 22:16:54.453', '2025-10-24 22:16:54.453', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ve00tyqhd9b9c8af3f', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Które słowa Antygony najlepiej wyrażają jej pogląd na prawa boskie?', '{"options": ["Muszę słuchać Kreona, bo jest władcą", "Nie Zeus ani Dike ogłosili ten zakaz - niepisane prawa bogów są wieczne", "Prawo ludzkie jest najważniejsze", "Pogrzeb to tylko forma, nie ma znaczenia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Antygona mówi: ''Nie Zeus ani Dike ogłosili ten zakaz'' - podkreśla, że edykt Kreona nie pochodzi od bogów, a niepisane prawa boskie są wieczne i nadrzędne wobec praw ludzkich."}', '2025-10-24 22:16:54.458', '2025-10-24 22:16:54.458', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9vg00tzqhd9tncd5dmd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co oznacza stwierdzenie Antygony, że przyszła ''współkochać, nie współnienawidzieć''?', '{"options": ["że jest zakochana w Hajmonie", "że jej naturą jest miłość, nie nienawiść - nawet do wroga", "że kocha tylko swoją rodzinę", "że nienawidzi Kreona"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "To kluczowe zdanie charakteryzujące Antygonę - mówi, że przyszła na świat, aby kochać (nawet zdrajcę-brata), nie aby nienawidzić. Wyraża to jej naturę opartą na miłości i lojalności rodzinnej."}', '2025-10-24 22:16:54.46', '2025-10-24 22:16:54.46', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9vi00u0qhd9zrgyjsph', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Jak Antygona postrzega swoją śmierć?', '{"options": ["jako największe nieszczęście", "jako zysk wobec życia pełnego cierpień", "jako karę za grzechy", "jako niesprawiedliwość"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Antygona mówi, że przedwczesna śmierć to dla niej ''zysk wobec życia pełnego cierpień'' - jako ostatnia z przeklętego rodu widzi śmierć jako wyzwolenie od tragicznego losu rodziny."}', '2025-10-24 22:16:54.463', '2025-10-24 22:16:54.463', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9vl00u1qhd9hvbnwt3e', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jaką wizję władzy reprezentuje Kreon?', '{"options": ["demokratyczną - władza pochodzi z woli ludu", "teokratyczną - władza pochodzi od bogów", "absolutystyczną - władca ma nieograniczoną władzę", "anarchistyczną - brak władzy"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Kreon reprezentuje władzę absolutną - uważa, że dobro państwa jest najważniejsze, a władca ma prawo stanowić prawa bez ograniczeń. Nie uznaje praw wyższych od woli monarchy."}', '2025-10-24 22:16:54.465', '2025-10-24 22:16:54.465', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9vn00u2qhd9d42fi5t0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Co symbolizuje metafora drzewa w mowie Hajmona?', '{"options": ["siłę i potęgę władcy", "elastyczność i umiar w rządzeniu - ugięcie zamiast złamania", "słabość i tchórzostwo", "stałość i niezmienność"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Hajmon mówi, że drzewo które się ugina przetrwa burzę, a sztywne - złamie się. Symbolizuje to potrzebę elastyczności, umiaru i mądrości w rządzeniu - władca musi umieć się ugąć, nie być sztywny."}', '2025-10-24 22:16:54.467', '2025-10-24 22:16:54.467', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9vp00u3qhd9sjtvfuzk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Jaka jest ironia tragiczna w losie Kreona?', '{"options": ["chciał porządku, ale spowodował chaos i tragedię", "stał się bogatym władcą", "został obalony przez lud", "zdobył uznanie bogów"]}', '0', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Ironia tragiczna polega na tym, że Kreon chciał być wzorowym władcą strzegącym porządku państwowego, a skończył jako zrujnowany człowiek, który przez własną pychę stracił syna i żonę - sam sprowadził na siebie katastrofę."}', '2025-10-24 22:16:54.47', '2025-10-24 22:16:54.47', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9vr00u4qhd9crs4js7l', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Dlaczego Kreon oskarża strażników o przekupstwo?', '{"options": ["bo znalazł u nich pieniądze", "bo nie może uwierzyć, że ktoś złamał edykt z zasad, więc szuka materialnej motywacji", "bo strażnicy się przyznali", "bo lud go o tym poinformował"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Kreon nie potrafi zrozumieć, że ktoś mógłby złamać jego edykt z wyższych pobudek moralnych, więc szuka materialistycznego wytłumaczenia - oskarża o przekupstwo przez wrogów miasta."}', '2025-10-24 22:16:54.472', '2025-10-24 22:16:54.472', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9vt00u5qhd9rnm9z9oj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Jak Kreon postrzega płeć w kontekście władzy?', '{"options": ["uważa kobiety i mężczyzn za równych", "silnie rozdziela sfery męską i żeńską, dla niego posłuszeństwo kobiecie to hańba", "preferuje kobiety na stanowiskach władzy", "nie ma zdania na ten temat"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Kreon ''silnie i zdecydowanie oddzielał sferę męską od sfery kobiecej''. Mówi, że jeśli Antygona wygra, to on przestanie być mężczyzną - posłuszeństwo kobiecie to dla niego hańba i zagrożenie męskiego porządku władzy."}', '2025-10-24 22:16:54.474', '2025-10-24 22:16:54.474', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9vw00u6qhd9l2n67gcs', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Jaki paradoks ujawnia się w postawie Kreona?', '{"options": ["mówi o rozumie, ale zachowuje się emocjonalnie", "kocha Antygonę, ale ją skazuje", "nienawidzi Polinika, ale go grzebie", "wierzy w bogów, ale ich nie słucha"]}', '0', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Paradoks polega na tym, że Kreon przypisuje kobietom emocjonalność a mężczyznom rozum, ale ''okazuje się, że to on zachowuje się emocjonalnie i poddaje się swojej emocjonalnej naturze'' - działa impulsywnie, z pychy i gniewu."}', '2025-10-24 22:16:54.476', '2025-10-24 22:16:54.476', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9vy00u7qhd9gv1rnwem', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co oznacza pojęcie ''hamartia'' w tragedii greckiej?', '{"options": ["nagrodę bogów", "błąd tragiczny bohatera prowadzący do katastrofy", "triumf nad wrogami", "mądrość życiową"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Hamartia to błąd tragiczny - wadliwa decyzja lub cecha charakteru bohatera (np. pycha Kreona), która prowadzi do jego upadku i katastrofy zgodnie z logiką tragedii greckiej."}', '2025-10-24 22:16:54.478', '2025-10-24 22:16:54.478', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9w000u8qhd90vu8f5nx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Czym jest ''agon'' w tragedii Antygona?', '{"options": ["pieśnią chóru", "sceną pojedynku słownego między bohaterami (Antygona vs Kreon)", "monologiem bohatera", "epilogiem tragedii"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Agon to formalna debata, pojedynek słowny między antagonistami w tragedii greckiej. W Antygonie główny agon to starcie między Antygoną a Kreonem, gdzie przedstawiają swoje argumenty."}', '2025-10-24 22:16:54.48', '2025-10-24 22:16:54.48', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9w200u9qhd9ovr32vbh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Jaka jest funkcja postaci Ismeny w strukturze tragedii?', '{"options": ["komiczny relief", "kontrast podkreślający heroizm Antygony", "główna antagonistka", "narratorka"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Ismena pełni funkcję postaci kontrastowej (foil character) - jej tchórzostwo, uległość i pragmatyzm podkreślają przez kontrast odwagę, bezkompromisowość i heroizm Antygony."}', '2025-10-24 22:16:54.483', '2025-10-24 22:16:54.483', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9w400uaqhd9bm7p27ey', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co symbolizuje zakaz pochówku Polinika?', '{"options": ["tylko karę za zdradę", "konflikt między prawem państwowym a prawami boskimi i rodzinnymi", "lenistwo władcy", "obojętność wobec zmarłych"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Zakaz pochówku symbolizuje główny konflikt tragedii - starcie prawa państwowego (edykt Kreona) z prawami boskimi i niepisanymi prawami rodzinnymi, które nakazują godny pochówek każdego zmarłego."}', '2025-10-24 22:16:54.485', '2025-10-24 22:16:54.485', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9w700ubqhd9dx90rfq2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Co oznacza zdanie Chóru: ''Siła jest dziwy, lecz nad wszystkie sięga / Dziwy człowieka potęga''?', '{"options": ["że człowiek jest słaby", "że człowiek ma wielką moc i zdolności, ale też może je użyć źle", "że tylko bogowie są potężni", "że natura jest potężniejsza od człowieka"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "To oda o człowieku (stasimon) wyrażająca ambiwalencję: człowiek ma wielką potęgę (umysł, mowę, technikę), ale może użyć jej zarówno na dobre jak i na złe - może być cudem lub straszną siłą niszczącą."}', '2025-10-24 22:16:54.487', '2025-10-24 22:16:54.487', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9w900ucqhd9l76gndic', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Jaka jest funkcja sceny z wieszczem Tejrezjaszem?', '{"options": ["tylko przepowiada przyszłość", "stanowi punkt zwrotny - perypetia, po którym Kreon zmienia zdanie", "wprowadza komizm", "oskarża Antygonę"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Scena z Tejrezjaszem to perypetia (punkt zwrotny akcji) - przepowiednia wieszcza powoduje nagłą zmianę w postawie Kreona, który wreszcie decyduje się uwolnić Antygonę, ale jest już za późno."}', '2025-10-24 22:16:54.489', '2025-10-24 22:16:54.489', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9wb00udqhd9kgode6ns', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Dlaczego Ismena próbuje później przyznać się do współudziału w pogrzebie?', '{"options": ["bo naprawdę pomagała", "z lojalności wobec siostry i poczucia winy", "bo chce być sławna", "z nienawiści do Kreona"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Ismena, widząc skazanie siostry, czuje poczucie winy za swoją wcześniejszą odmowę i lojalność rodzinną. Próbuje podzielić los siostry, choć Antygona odrzuca jej ''spóźniony heroizm''."}', '2025-10-24 22:16:54.491', '2025-10-24 22:16:54.491', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9wd00ueqhd9cjf1i0nx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'W jaki sposób tragedia kończy się dla wszystkich głównych postaci?', '{"options": ["wszyscy żyją szczęśliwie", "wszyscy giną fizycznie", "Antygona, Hajmon i Eurydyka giną, Kreon żyje jako ''żywy trup''", "tylko Kreon ginie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Antygona, Hajmon i Eurydyka popełniają samobójstwo. Kreon przeżywa, ale Posłaniec nazywa go ''żywym trupem'' - jest psychicznie zniszczony, co jest najgorszą karą."}', '2025-10-24 22:16:54.493', '2025-10-24 22:16:54.493', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9wf00ufqhd9vnafvd13', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Co oznacza stwierdzenie, że Kreon ''ponosi klęskę nie przez to, kim był, ale kim nie był''?', '{"options": ["że był złym człowiekiem", "że nie był wystarczająco mądry, odważny i sprawiedliwy by być dobrym władcą", "że był zbyt dobry", "że był zbyt młody"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Ta diagnoza oznacza, że Kreon nie był ani wystarczająco inteligentny, ani odważny, by być dobrym i sprawiedliwym władcą - jego ograniczenia i pycha doprowadziły do tragedii."}', '2025-10-24 22:16:54.495', '2025-10-24 22:16:54.495', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9wh00ugqhd9jb4isalw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jaka jest rola motywu pieniądza w przemowie Kreona do strażników?', '{"options": ["Kreon krytykuje pieniądz jako źródło wszelkiej zbrodni i korupcji", "Kreon chwali pieniądz", "Kreon jest obojętny na pieniądze", "Kreon rozdaje pieniądze strażnikom"]}', '0', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Kreon mówi: ''nie ma gorszej potęgi jak pieniądz który burzy miasta, krzywi prawe dusze i jest mistrzem wszelkiej zbrodni'' - oskarża strażników o przekupstwo i krytykuje destrukcyjną moc pieniądza."}', '2025-10-24 22:16:54.497', '2025-10-24 22:16:54.497', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9wj00uhqhd9e0ryz3vq', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 3, 'Dopasuj koncepcje do postaci, które je reprezentują w „Antygonie”.', '{"leftColumn": [{"id": "A", "text": "Prawa boskie i niepisane"}, {"id": "B", "text": "Racja stanu i porządek państwowy"}, {"id": "C", "text": "Pragmatyzm i strach"}, {"id": "D", "text": "Miłość i próba mediacji"}], "rightColumn": [{"id": 1, "text": "Hajmon"}, {"id": 2, "text": "Kreon"}, {"id": 3, "text": "Antygona"}, {"id": 4, "text": "Ismena"}], "matchingType": "concepts_characters"}', '[[0, 2], [1, 1], [2, 3], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Antygona reprezentuje prawa boskie, Kreon - rację stanu, Ismena - pragmatyzm i strach, Hajmon - miłość i próbę znalezienia kompromisu."}', '2025-10-24 22:16:54.499', '2025-10-24 22:16:54.499', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9wl00uiqhd9m6icahq4', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 3, 'Które elementy składają się na tragizm sytuacji Antygony? (wybierz wszystkie poprawne)', '{"options": ["konflikt wartości nie do pogodzenia", "każdy wybór prowadzi do utraty czegoś ważnego", "ciężar klątwy rodzinnej", "możliwość uniknięcia konfliktu", "brak odpowiedzialności za czyny", "świadomość konsekwencji"]}', '[0, 1, 2, 5]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Tragizm Antygony to: konflikt niekompatybilnych wartości, sytuacja bez wyjścia (każdy wybór to strata), klątwa rodu Labdakidów i pełna świadomość konsekwencji. Nie mogła uniknąć konfliktu i była odpowiedzialna za swój wybór."}', '2025-10-24 22:16:54.502', '2025-10-24 22:16:54.502', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9wo00ujqhd9qauz7ej5', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 3, 'Dopasuj cechy do typu bohatera tragicznego.', '{"leftColumn": [{"id": "A", "text": "Antygona"}, {"id": "B", "text": "Kreon"}, {"id": "C", "text": "Hajmon"}], "rightColumn": [{"id": 1, "text": "bohater świadomy, heroiczny - wybiera wartości wyższe"}, {"id": 2, "text": "ofiara miłości i konfliktu pokoleń"}, {"id": 3, "text": "bohater z hamartią (pycha) prowadzącą do katastrofy"}], "matchingType": "tragic_hero_traits"}', '[[0, 0], [1, 2], [2, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Antygona to bohaterka heroiczna świadomie wybierająca śmierć dla wartości. Kreon to klasyczny bohater tragiczny z hamartią (pychą). Hajmon to ofiara miłości i konfliktu między ojcem a ukochaną."}', '2025-10-24 22:16:54.505', '2025-10-24 22:16:54.505', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9wr00ukqhd9g79lzrpi', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Uzupełnij analizę konfliktu w tragedii.', '{"gaps": [{"id": 1, "options": ["praw państwowych", "praw boskich", "praw rodzinnych", "praw ludzkich"]}, {"id": 2, "options": ["praw boskich", "praw rodzinnych", "praw państwowych", "tradycji"]}, {"id": 3, "options": ["woli ludu", "edyktu", "niepisanych praw bogów", "tradycji"]}, {"id": 4, "options": ["woli bogów", "tradycji", "racji stanu i edyktu", "opinii ludu"]}], "textWithGaps": "Główny konflikt w Antygonie to starcie [1] reprezentowanych przez Antygonę z [2] reprezentowanymi przez Kreona. Antygona odwołuje się do [3], podczas gdy Kreon do [4]."}', '[1, 2, 2, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Konflikt to starcie praw boskich (Antygona) z prawami państwowymi (Kreon). Antygona odwołuje się do niepisanych praw bogów, Kreon do racji stanu i swojego edyktu."}', '2025-10-24 22:16:54.507', '2025-10-24 22:16:54.507', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9wt00ulqhd94tz0wf2q', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 3, 'Które elementy struktury tragedii greckiej występują w Antygonie? (wybierz wszystkie poprawne)', '{"options": ["prolog - wprowadzenie w sytuację", "agon - pojedynek słowny", "stasimon - pieśń chóru", "perypetia - punkt zwrotny (scena z Tejrezjaszem)", "katastrofa - finalne nieszczęście", "happy end"]}', '[0, 1, 2, 3, 4]', NULL, '{historical_literary,closed_multiple,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Antygona ma wszystkie klasyczne elementy tragedii greckiej: prolog (rozmowa sióstr), agon (Antygona vs Kreon), stasimon (pieśni chóru), perypetia (Tejrezjasz), katastrofa (śmierci i upadek Kreona). Nie ma happy endu."}', '2025-10-24 22:16:54.51', '2025-10-24 22:16:54.51', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9wv00umqhd9ywhfdsze', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Dopasuj cytaty do ich znaczenia w tragedii.', '{"leftColumn": [{"id": "A", "text": "Współkochać przyszłam, nie współnienawidzieć"}, {"id": "B", "text": "Nie Zeus ani Dike ogłosili ten zakaz"}, {"id": "C", "text": "Zginie - to śmiercią sprowadzi zgon inny"}, {"id": "D", "text": "Zmieniam swe serce, zrobię to"}], "rightColumn": [{"id": 1, "text": "ostrzeżenie Hajmona o samobójstwie"}, {"id": 2, "text": "natura Antygony - miłość, nie nienawiść"}, {"id": 3, "text": "odmowa uznania edyktu Kreona za boskie prawo"}, {"id": 4, "text": "spóźniona zmiana decyzji Kreona"}], "matchingType": "quotes_meaning"}', '[[0, 1], [1, 2], [2, 0], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Cytaty wyrażają: naturę Antygony (miłość), odrzucenie edyktu jako prawa boskiego, ostrzeżenie o samobójstwie i spóźnioną przemianę Kreona."}', '2025-10-24 22:16:54.512', '2025-10-24 22:16:54.512', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9wz00unqhd9h28gwcb7', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 3, 'Które stwierdzenia o Kreonie są prawdziwe? (wybierz wszystkie poprawne)', '{"options": ["jest negatywnym odbiciem Antygony", "reprezentuje rozum, ale działa emocjonalnie", "od początku jest gotów na kompromis", "jego pycha (hybris) prowadzi do katastrofy", "uosabia ideał sprawiedliwego władcy", "kończy jako ''żywy trup'' - zrujnowany psychicznie"]}', '[0, 1, 3, 5]', NULL, '{historical_literary,closed_multiple,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Prawdziwe: Kreon to negatywne odbicie Antygony, deklaruje rozum ale jest emocjonalny, jego pycha prowadzi do tragedii, kończy zrujnowany. Fałszywe: nie jest gotów na kompromis i nie jest ideałem władcy."}', '2025-10-24 22:16:54.516', '2025-10-24 22:16:54.516', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9x200uoqhd93cacywio', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Dopasuj sceny do ich funkcji dramaturgicznych.', '{"leftColumn": [{"id": "A", "text": "Rozmowa Antygony i Ismeny na początku"}, {"id": "B", "text": "Pojedynek Antygony z Kreonem"}, {"id": "C", "text": "Przyjście Tejrezjasza"}, {"id": "D", "text": "Doniesienie o śmierci Hajmona i Eurydyki"}], "rightColumn": [{"id": 1, "text": "agon - główny konflikt ideowy"}, {"id": 2, "text": "katastrofa - finalne nieszczęście"}, {"id": 3, "text": "perypetia - punkt zwrotny"}, {"id": 4, "text": "ekspozycja - przedstawienie sytuacji"}], "matchingType": "scenes_functions"}', '[[0, 3], [1, 0], [2, 2], [3, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Rozmowa sióstr to ekspozycja, pojedynek z Kreonem to agon, przyjście Tejrezjasza to perypetia (punkt zwrotny), doniesienia o śmierciach to katastrofa."}', '2025-10-24 22:16:54.518', '2025-10-24 22:16:54.518', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9x400upqhd9c05azj9v', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 3, 'Wyjaśnij, na czym polega konflikt tragiczny w sytuacji Antygony.', '{"instruction": "Opisz dylemat Antygony i zastanów się, dlaczego każdy jej wybór był tragiczny. (50-80 słów)"}', NULL, '{"criteria": ["wskazanie konfliktu między obowiązkiem rodzinnym a posłuszeństwem władzy (1 pkt)", "wyjaśnienie, że każdy wybór prowadzi do utraty wartości (1 pkt)", "odniesienie do praw boskich vs ludzkich (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["dylemat", "konflikt wartości", "prawa boskie", "prawa ludzkie", "utrata", "sytuacja bez wyjścia"], "expectedAnswer": "Antygona stoi przed tragicznym dylematem: jeśli pogrzebie brata, złamie edykt i zginie; jeśli nie pogrzebie, obrazi bogów i zdradzi rodzinę. Każdy wybór oznacza utratę fundamentalnej wartości - nie może wybrać dobrze. To klasyczna sytuacja tragiczna: konflikt praw boskich z ludzkimi, gdzie bohaterka musi poświęcić jedno dla drugiego."}', '2025-10-24 22:16:54.521', '2025-10-24 22:16:54.521', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9x700uqqhd9f7uksw15', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 3, 'Porównaj postawy Antygony i Ismeny wobec edyktu Kreona.', '{"instruction": "Wskaż różnice w motywacji, argumentach i wyborach obu sióstr. (60-90 słów)"}', NULL, '{"criteria": ["charakterystyka postawy Antygony (bezkompromisowa, heroiczna) (1 pkt)", "charakterystyka postawy Ismeny (pragmatyczna, bojaźliwa) (1 pkt)", "wyjaśnienie różnic w wartościach i motywacji (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-3,antiquity,batch-2025-01}', '{"keyWords": ["Antygona", "Ismena", "heroizm", "pragmatyzm", "prawa boskie", "strach", "kontrast"], "expectedAnswer": "Antygona jest bezkompromisowa i heroiczna - kieruje się prawami boskimi i lojalnością rodzinną, gotowa umrzeć za zasady. Ismena jest pragmatyczna i bojaźliwa - uznaje słabość kobiet wobec męskiej władzy, wybiera życie nad zasady. Antygona wierzy w wartości wyższe od życia, Ismena w rozsądne przetrwanie. Ich kontrast pokazuje różne odpowiedzi na sytuację tragiczną."}', '2025-10-24 22:16:54.523', '2025-10-24 22:16:54.523', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9x900urqhd9uhing59h', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 4, 'Przeanalizuj ewolucję postaci Kreona w tragedii.', '{"instruction": "Opisz przemianę Kreona od pewnego siebie władcy do zrujnowanego człowieka. (80-120 słów)"}', NULL, '{"criteria": ["opis początkowej postawy - pewność siebie, pycha (1 pkt)", "odrzucanie rad Hajmona i Tejrezjasza (1 pkt)", "punkt zwrotny - przepowiednia i zmiana decyzji (1 pkt)", "finał - upadek, uznanie winy, żywy trup (1 pkt)"], "maxScore": 4}', '{historical_literary,short_answer,difficulty-3,antiquity,batch-2025-01}', '{"keyWords": ["ewolucja", "pycha", "pewność siebie", "Tejrezjasz", "punkt zwrotny", "katastrofa", "uznanie winy"], "expectedAnswer": "Na początku Kreon jest pewnym siebie władcą, który wierzy w swoją rację i porządek państwowy. Odrzuca rady syna i chóru z pychy. Dopiero straszliwa przepowiednia Tejrezjasza przeraża go i powoduje zmianę decyzji, ale jest już za późno. Traci syna i żonę przez własną głupotę i sztywność. Kończy jako ''żywy trup'' - zrujnowany psychicznie, błagający o śmierć, przyznający się do winy. Jego ewolucja pokazuje mechanizm tragedii: pycha prowadzi do katastrofy."}', '2025-10-24 22:16:54.526', '2025-10-24 22:16:54.526', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9xb00usqhd92lxj8p3z', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 3, 'Wyjaśnij znaczenie metafory drzewa w przemowie Hajmona do ojca.', '{"instruction": "Zinterpretuj metaforę i wyjaśnij, czego Hajmon próbuje nauczyć ojca. (50-70 słów)"}', NULL, '{"criteria": ["wyjaśnienie metafory: drzewo ugina się, nie łamie (1 pkt)", "odniesienie do elastyczności w rządzeniu (1 pkt)", "ostrzeżenie przed sztywnością i pychą (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["metafora", "drzewo", "elastyczność", "umiar", "pycha", "sztywność"], "expectedAnswer": "Hajmon porównuje dobrego władcę do drzewa, które ugina się pod naporem wiatru i dzięki temu przetrwa, podczas gdy sztywne drzewo się złamie. Metafora symbolizuje potrzebę elastyczności, umiaru i mądrości w rządzeniu. Hajmon ostrzega ojca, że sztywność i pycha doprowadzą do katastrofy - władca musi umieć się ugąć i słuchać głosu rozsądku."}', '2025-10-24 22:16:54.528', '2025-10-24 22:16:54.528', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9xe00utqhd9f4387nvt', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 4, 'Omów funkcję postaci Tejrezjasza w strukturze dramatu.', '{"instruction": "Wyjaśnij rolę wieszcza i znaczenie jego przepowiedni dla rozwoju akcji. (80-100 słów)"}', NULL, '{"criteria": ["określenie Tejrezjasza jako głosu bogów (1 pkt)", "przepowiednia jako punkt zwrotny (perypetia) (1 pkt)", "wymuszenie zmiany decyzji Kreona (1 pkt)", "ujawnienie prawdy o gniewie bogów (1 pkt)"], "maxScore": 4}', '{historical_literary,short_answer,difficulty-3,antiquity,batch-2025-01}', '{"keyWords": ["Tejrezjasz", "wieszcz", "głos bogów", "perypetia", "przepowiednia", "punkt zwrotny", "sprawiedliwość"], "expectedAnswer": "Tejrezjasz to ślepý wieszcz reprezentujący wolę bogów i głos wyższego porządku. Jego przyjście stanowi perypetię - punkt zwrotny akcji. Przepowiednia gniewu bogów i śmierci syna wreszcie przeraża Kreona i wymusza zmianę decyzji. Tejrezjasz ujawnia prawdę: edykt Kreona obraził bogów, bezczeszcząc zmarłego i skazując żywą na śmierć. Jest głosem transcendencji i sprawiedliwości kosmicznej, która musi zwyciężyć."}', '2025-10-24 22:16:54.53', '2025-10-24 22:16:54.53', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9xg00uuqhd9c7j79b0w', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 3, 'Wyjaśnij pojęcie ''hybris'' na przykładzie Kreona.', '{"instruction": "Zdefiniuj hybris i wskaż konkretne przejawy pychy Kreona. (50-80 słów)"}', NULL, '{"criteria": ["definicja hybris jako pychy, przekroczenia granic (1 pkt)", "przykłady pychy Kreona (edykt, odrzucanie rad) (1 pkt)", "konsekwencja - kara bogów (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["hybris", "pycha", "przekroczenie granic", "edykt", "prawa boskie", "kara", "katastrofa"], "expectedAnswer": "Hybris to pycha i przekroczenie granic wyznaczonych przez bogów i naturę. Kreon przejawia hybris gdy: wydaje edykt przeciwny prawom boskim, odmawia pochówku zmarłemu, odrzuca rady syna i chóru, uważa się za wyższego od praw boskich. Jego pycha prowadzi do nieuchronnej kary - traci wszystko. W tragedii greckiej hybris zawsze kończy się katastrofą."}', '2025-10-24 22:16:54.533', '2025-10-24 22:16:54.533', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9xi00uvqhd9xrl0spo0', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 4, 'Przeanalizuj rolę chóru w Antygonie.', '{"instruction": "Opisz funkcje chóru: komentującą, filozoficzną i dramaturgiczną. (90-120 słów)"}', NULL, '{"criteria": ["funkcja komentująca - głos zbiorowy (1 pkt)", "funkcja filozoficzna - refleksje o życiu, losie (1 pkt)", "stasimon - oda o człowieku (1 pkt)", "morał końcowy o pysze i mądrości (1 pkt)"], "maxScore": 4}', '{historical_literary,short_answer,difficulty-3,antiquity,batch-2025-01}', '{"keyWords": ["chór", "komentarz", "filozofia", "oda", "człowiek", "potęga", "morał", "pycha", "mądrość"], "expectedAnswer": "Chór w Antygonie pełni kilka funkcji. Po pierwsze, komentuje wydarzenia jako głos zbiorowy obywateli Teb, wyrażając opinie pośrednie między skrajnymi postawami. Po drugie, filozofuje o kondycji ludzkiej, losie i granicach ludzkiej potęgi - szczególnie w słynnej odzie ''Siła jest dziwy, lecz nad wszystkie sięga dziwy człowieka potęga''. Po trzecie, wyznacza strukturę dramatu przez stasimon (pieśni). Końcowy morał chóru podsumowuje tragedię: bogowie karzą pychę, największym skarbem jest rozum i umiar, a mądrości uczymy się przez cierpienie."}', '2025-10-24 22:16:54.535', '2025-10-24 22:16:54.535', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaih013hqhd90mf1cwv8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Dlaczego Makduf może zabić Makbeta?', '{"options": ["ma magiczny miecz", "jest silniejszy", "nie został urodzony z kobiety w naturalny sposób", "wiedźmy mu pomagają"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Makduf został wydarty z łona matki przez cesarskie cięcie, więc nie został ''zrodzony'' z kobiety."}', '2025-10-24 22:16:55.29', '2025-10-24 22:16:55.29', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9xl00uwqhd9fmysj0ee', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 3, 'Wyjaśnij paradoks w postawie Kreona wobec emocji i rozumu.', '{"instruction": "Opisz, jak Kreon postrzega sfery męską i żeńską, a jak faktycznie się zachowuje. (60-90 słów)"}', NULL, '{"criteria": ["poglądy Kreona: mężczyźni = rozum, kobiety = emocje (1 pkt)", "faktyczne zachowanie: Kreon działa emocjonalnie (1 pkt)", "ironia - odwrócenie stereotypów (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-3,antiquity,batch-2025-01}', '{"keyWords": ["paradoks", "Kreon", "emocje", "rozum", "stereotypy płciowe", "pycha", "gniew"], "expectedAnswer": "Kreon silnie rozdziela sferę męską od żeńskiej, przypisując mężczyznom rozum a kobietom emocjonalność. Paradoks polega na tym, że to właśnie Kreon zachowuje się emocjonalnie - działa z pychy, gniewu, urażonej dumy. Antygona natomiast postępuje racjonalnie według swoich zasad. Sofokles odwraca stereotypy płciowe pokazując, że to władca kieruje się emocjami, nie rozumem."}', '2025-10-24 22:16:54.537', '2025-10-24 22:16:54.537', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9xn00uxqhd9arxjidz6', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 3, 'Wyjaśnij znaczenie stwierdzenia Antygony o śmierci jako ''zysku''.', '{"instruction": "Zinterpretuj, dlaczego Antygona postrzega przedwczesną śmierć jako zysk. (50-70 słów)"}', NULL, '{"criteria": ["odniesienie do życia pełnego cierpień (1 pkt)", "klątwa rodu Labdakidów (1 pkt)", "śmierć jako wyzwolenie i zachowanie honoru (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-2,antiquity,batch-2025-01}', '{"keyWords": ["śmierć", "zysk", "cierpienie", "klątwa", "ród Labdakidów", "wyzwolenie", "honor"], "expectedAnswer": "Antygona mówi, że przedwczesna śmierć to dla niej ''zysk wobec życia pełnego cierpień''. Jako ostatnia przedstawicielka przeklętego rodu Labdakidów nosi ciężar tragedii rodzinnej. Śmierć traktuje jako wyzwolenie od dalszych nieszczęść i sposób na zachowanie honoru. Woli umrzeć wierna zasadom niż żyć w hańbie."}', '2025-10-24 22:16:54.54', '2025-10-24 22:16:54.54', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9xp00uyqhd9lv77pfg8', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 4, 'Omów funkcję postaci Hajmona jako mediatora między skrajnościami.', '{"instruction": "Wyjaśnij, w jaki sposób Hajmon próbuje pogodzić konflikt i dlaczego ponosi porażkę. (80-110 słów)"}', NULL, '{"criteria": ["Hajmon jako postać pośrednia, próba mediacji (1 pkt)", "argumenty: głos ludu, rozum, elastyczność (1 pkt)", "odrzucenie przez ojca z powodu pychy (1 pkt)", "tragiczny los - samobójstwo jako konsekwencja niemożności pogodzenia (1 pkt)"], "maxScore": 4}', '{historical_literary,short_answer,difficulty-3,antiquity,batch-2025-01}', '{"keyWords": ["Hajmon", "mediator", "kompromis", "miłość", "racjonalne argumenty", "odrzucenie", "samobójstwo", "tragedia"], "expectedAnswer": "Hajmon pełni rolę mediatora - próbuje pogodzić ojca z Antygoną i znaleźć kompromis. Używa argumentów racjonalnych: odwołuje się do opinii ludu, przestrzega przed pychą, radzi elastyczność w rządzeniu. Jest rozdarty między miłością do Antygony a posłuszeństwem ojcu. Jego próba mediacji kończy się porażką - Kreon odrzuca rady syna z pychy. Hajmon popełnia samobójstwo przy ciele ukochanej, stając się ofiarą niemożliwego do pogodzenia konfliktu. Jego śmierć pokazuje, że w tragedii nie ma miejsca na kompromis."}', '2025-10-24 22:16:54.542', '2025-10-24 22:16:54.542', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9xs00uzqhd90ptsxqh9', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 6, 'Napisz notatkę syntetyzującą o konflikcie tragicznym w Antygonie.', '{"topic": "Konflikt tragiczny między prawami boskimi a ludzkimi w Antygonie", "requirements": ["charakterystyka praw boskich reprezentowanych przez Antygonę", "charakterystyka praw państwowych reprezentowanych przez Kreona", "niemożność pogodzenia obu systemów wartości", "konsekwencje konfliktu dla bohaterów", "150-200 słów"]}', NULL, '{"criteria": ["omówienie praw boskich i argumentów Antygony (1,5 pkt)", "omówienie praw państwowych i argumentów Kreona (1,5 pkt)", "wyjaśnienie niemożności kompromisu (1,5 pkt)", "przedstawienie konsekwencji dla bohaterów (1,5 pkt)"], "maxScore": 6}', '{historical_literary,synthesis_note,difficulty-3,antiquity,batch-2025-01}', NULL, '2025-10-24 22:16:54.544', '2025-10-24 22:16:54.544', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9xu00v0qhd9xhzqwcar', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 7, 'Porównaj dwie główne postacie kobiece w tragedii.', '{"topic": "Kontrast między Antygoną a Ismeną jako dwa modele kobiecości", "requirements": ["charakterystyka Antygony: heroizm, bezkompromisowość", "charakterystyka Ismeny: pragmatyzm, strach", "różnice w motywacji i wyborach", "funkcja kontrastu w strukturze dramatu", "200-250 słów"]}', NULL, '{"criteria": ["charakterystyka Antygony (2 pkt)", "charakterystyka Ismeny (2 pkt)", "analiza różnic (2 pkt)", "funkcja kontrastu (1 pkt)"], "maxScore": 7}', '{historical_literary,synthesis_note,difficulty-3,antiquity,batch-2025-01}', NULL, '2025-10-24 22:16:54.547', '2025-10-24 22:16:54.547', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9y000v1qhd9usrv5lu0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jaki typ bohatera reprezentuje Antygona w tragedii greckiej?', '{"options": ["bohatera z hamartią prowadzącą do upadku", "bohatera komicznego", "bohatera heroicznego świadomie wybierającego śmierć dla zasad", "bohatera bez wad"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Antygona to bohaterka heroiczna, która świadomie wybiera śmierć dla wyższych wartości. Nie ma hamartii (błędu) jak Kreon - jej wybór jest świadomy i szlachetny."}', '2025-10-24 22:16:54.552', '2025-10-24 22:16:54.552', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9y200v2qhd95zn5njwi', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Jaką funkcję pełni w tragedii motyw klątwy rodu Labdakidów?', '{"options": ["tylko element fabularny", "tło zwiększające tragizm - bohaterowie dziedziczą ciężar przeszłości", "komiczny relief", "rozwiązanie konfliktu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Klątwa rodu Labdakidów stanowi tło zwiększające tragizm sytuacji - Antygona i jej rodzeństwo dziedziczą brzęmię grzechów Edypa, co potęguje fatalność ich losów."}', '2025-10-24 22:16:54.555', '2025-10-24 22:16:54.555', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9y500v3qhd9g7yq296v', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Co oznacza pojęcie ''katharsis'' w kontekście tragedii?', '{"options": ["oczyszczenie emocjonalne widza przez litość i trwogę", "zemstę bohaterów", "happy end", "komizm sytuacyjny"]}', '0', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Katharsis to oczyszczenie emocjonalne widza - przeżywając litość i trwogę wobec losu bohaterów, widz dokonuje wewnętrznej puryfikacji według Arystotelesa."}', '2025-10-24 22:16:54.557', '2025-10-24 22:16:54.557', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaij013iqhd9ym3d7xme', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 1, 'Kto zostaje królem Szkocji po śmierci Makbeta?', '{"options": ["Donalbain", "Makduf", "Malcolm", "Fleance"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,renaissance,batch-2025-01}', '{"explanation": "Malcolm, syn Duncana, zostaje prawowitym królem Szkocji."}', '2025-10-24 22:16:55.292', '2025-10-24 22:16:55.292', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9y700v4qhd9u1ur94b6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'W jaki sposób tragedia realizuje zasadę jedności akcji?', '{"options": ["ma wiele równoległych wątków", "wszystko podporządkowane jednej akcji: pogrzeb Polinika i jego konsekwencje", "nie ma spójnej akcji", "akcja toczy się w wielu miejscach"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Antygona realizuje klasyczną jedność akcji - wszystkie wydarzenia (pogrzeb, konfrontacje, śmierci) wynikają z jednej akcji: decyzji Antygony o pogrzebaniu brata wbrew edyktowi."}', '2025-10-24 22:16:54.56', '2025-10-24 22:16:54.56', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ya00v5qhd965a18r5q', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Jaka jest relacja między Kreonem a Hajmonem?', '{"options": ["bracia", "ojciec i syn, konflikt pokoleń", "wrogowie polityczni", "przyjaciele"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Kreon i Hajmon to ojciec i syn. Ich konflikt reprezentuje także konflikt pokoleń - młody Hajmon reprezentuje nowe wartości (miłość, elastyczność), stary Kreon - sztywność i władzę."}', '2025-10-24 22:16:54.562', '2025-10-24 22:16:54.562', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9yc00v6qhd91mk5q446', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Co symbolizuje samobójstwo Hajmona przy ciele Antygony?', '{"options": ["zwykłe nieszczęście", "triumf miłości nad władzą ojca i niemożność życia bez ukochanej", "tchórzostwo", "przypadek"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Samobójstwo Hajmona symbolizuje triumf miłości nad władzą tyrańskiego ojca oraz niemożność życia bez ukochanej. Jest też zemstą na ojcu - Kreon traci syna przez swoją pychę."}', '2025-10-24 22:16:54.564', '2025-10-24 22:16:54.564', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ye00v7qhd9il14dp6z', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 2, 'Jak interpretować samobójstwo Eurydyki?', '{"options": ["jako przypadkową śmierć", "jako akt oskarżenia Kreona i dopełnienie jego kary", "jako oznakę tchórzostwa", "jako happy end"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Eurydyka popełnia samobójstwo obwiniając męża za śmierć syna. To dopełnienie kary Kreona - traci nie tylko syna ale i żonę, zostaje całkowicie sam ze swoją winą."}', '2025-10-24 22:16:54.567', '2025-10-24 22:16:54.567', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9yh00v8qhd94avylf57', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 1, 'Dlaczego Kreon nazywany jest ''żywym trupem'' na końcu?', '{"options": ["bo faktycznie umarł", "bo jest zrujnowany psychicznie - żyje ale cierpi więcej niż gdyby umarł", "bo jest chory", "bo został wygnany"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Posłaniec nazywa Kreona ''żywym trupem'' bo choć żyje fizycznie, jest całkowicie zniszczony psychicznie. Życie w poczuciu winy i bólu jest gorsze niż śmierć."}', '2025-10-24 22:16:54.569', '2025-10-24 22:16:54.569', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9yj00v9qhd9ax1xloon', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 3, 3, 'Dopasuj terminy z tragedii greckiej do ich znaczeń.', '{"leftColumn": [{"id": "A", "text": "Hybris"}, {"id": "B", "text": "Hamartia"}, {"id": "C", "text": "Katharsis"}, {"id": "D", "text": "Perypetia"}], "rightColumn": [{"id": 1, "text": "punkt zwrotny akcji"}, {"id": 2, "text": "pycha, przekroczenie granic"}, {"id": 3, "text": "oczyszczenie emocjonalne"}, {"id": 4, "text": "błąd tragiczny bohatera"}], "matchingType": "terms_meanings"}', '[[0, 1], [1, 3], [2, 2], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-3,antiquity,batch-2025-01}', '{"explanation": "Hybris to pycha, hamartia to błąd tragiczny, katharsis to oczyszczenie emocjonalne widza, perypetia to punkt zwrotny akcji."}', '2025-10-24 22:16:54.572', '2025-10-24 22:16:54.572', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ym00vaqhd9qxoefehu', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 2, 2, 'Które cechy charakteryzują tragedię jako gatunek? (wybierz wszystkie poprawne)', '{"options": ["bohater szlachetny, o wysokim statusie", "konflikt nie do rozwiązania", "komizm i happy end", "katastrofa w finale", "obecność chóru", "wątek miłosny jako główny"]}', '[0, 1, 3, 4]', NULL, '{historical_literary,closed_multiple,difficulty-2,antiquity,batch-2025-01}', '{"explanation": "Tragedia cechuje się: bohaterem szlachetnym, konfliktem tragicznym (bez rozwiązania), katastrofą w finale i obecnością chóru. Nie ma komizmu ani happy endu, wątek miłosny nie jest główny."}', '2025-10-24 22:16:54.574', '2025-10-24 22:16:54.574', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9yo00vbqhd92clum2bb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Jaka jest fundamentalna różnica między koncepcją sprawiedliwości Antygony a Kreona?', '{"options": ["Antygona wierzy w sprawiedliwość proceduralną, Kreon w naturalną", "Antygona wierzy w sprawiedliwość uniwersalną opartą na prawach boskich, Kreon w sprawiedliwość relatywną opartą na racji stanu", "oboje wierzą w tę samą sprawiedliwość", "żadne z powyższych"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "Fundamentalny konflikt dotyczy natury sprawiedliwości: Antygona reprezentuje sprawiedliwość uniwersalną (prawa boskie niezmienne dla wszystkich), Kreon - relatywną (zależną od kontekstu politycznego i dobra państwa)."}', '2025-10-24 22:16:54.577', '2025-10-24 22:16:54.577', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9yr00vcqhd97jmudapr', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'W jaki sposób Sofokles problematyzuje tradycyjny podział ról płciowych?', '{"options": ["nie problematyzuje go wcale", "pokazuje, że przypisane kobietom emocje faktycznie cechują Kreona, a przypisany mężczyznom rozum - Antygonę", "potwierdza stereotypy płciowe", "wprowadza tylko postaci męskie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,antiquity,batch-2025-01}', '{"explanation": "Sofokles subwertuje stereotypy: Kreon, reprezentujący męską sferę władzy, działa emocjonalnie (gniew, pycha), podczas gdy Antygona postępuje konsekwentnie według racjonalnego systemu wartości. To odwrócenie tradycyjnych ról."}', '2025-10-24 22:16:54.579', '2025-10-24 22:16:54.579', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9yt00vdqhd9qm1eyozo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Jaki filozoficzny problem podejmuje Sofokles w konflikcie Antygony i Kreona?', '{"options": ["problem hedonizmu", "problem relacji między prawem naturalnym a prawem stanowionym", "problem sceptycyzmu", "problem istnienia Boga"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "Sofokles podejmuje fundamentalny problem filozofii prawa: czy istnieje prawo naturalne (boskie, uniwersalne) nadrzędne wobec prawa stanowionego przez władcę? To pytanie aktualne do dziś."}', '2025-10-24 22:16:54.582', '2025-10-24 22:16:54.582', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9yv00veqhd9vwt8z07z', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Co oznacza stwierdzenie, że Kreon jest ''negatywnym odbiciem'' Antygony?', '{"options": ["że jest jej wrogiem", "że reprezentuje odwróconą hierarchię wartości - państwo nad rodziną, prawo ludzkie nad boskie", "że jest jej lustrzanym odbiciem we wszystkim", "że nie ma z nią nic wspólnego"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,antiquity,batch-2025-01}', '{"explanation": "Kreon to negatywne odbicie Antygony - odwraca jej hierarchię wartości. Gdzie ona stawia prawa boskie, on stawia państwowe; gdzie ona rodzinę, on rację stanu. Są lustrzanymi przeciwieństwami w systemie aksjologicznym."}', '2025-10-24 22:16:54.584', '2025-10-24 22:16:54.584', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9yy00vfqhd9qqupykae', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Jaką funkcję retoryczną pełni oda o człowieku (stasimon) w strukturze tragedii?', '{"options": ["tylko wypełnia czas między scenami", "wyraża ambiwalencję wobec ludzkiej potęgi - może budować lub niszczyć", "tylkochwali człowieka", "nie ma znaczenia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "Oda ''Siła jest dziwy...'' wyraża ambiwalentną wizję człowieka: z jednej strony podziw dla jego mocy (język, myśl, technika), z drugiej ostrzeżenie - ta moc może służyć dobru lub złu. Odnosi się do Kreona i Antygony."}', '2025-10-24 22:16:54.586', '2025-10-24 22:16:54.586', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9z000vgqhd9r90nn4bz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'W jakim sensie Antygona jest tragedią ''bez winnego''?', '{"options": ["wszyscy są winni", "konflikt wynika z kolizji dwóch słusznych racji (prawa boskie vs dobro państwa), nie z moralnej winy", "nikt nie jest winny", "tylko Kreon jest winny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,antiquity,batch-2025-01}', '{"explanation": "Antygonę nazywa się tragedią ''bez winnego'' bo konflikt wynika z kolizji dwóch legitymnych wartości - prawa boskie Antygony i dobro państwa Kreona mają swoje racje. To nie kwestia winy, ale nie do pogodzenia wartości."}', '2025-10-24 22:16:54.589', '2025-10-24 22:16:54.589', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9z300vhqhd9gm6k1zk5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Jak Sofokles wykorzystuje kategorię ''philia'' (przyjaźni/miłości rodzinnej)?', '{"options": ["ignoruje ją", "pokazuje ją jako najwyższą wartość dla Antygony, nadrzędną wobec życia", "krytykuje ją", "przedstawia jako słabość"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "Philia (miłość/lojalność rodzinna) to dla Antygony wartość nadrzędna - mówi ''współkochać przyszłam''. Sofokles pokazuje, że więzy rodzinne mogą być ważniejsze od życia i prawa państwowego."}', '2025-10-24 22:16:54.591', '2025-10-24 22:16:54.591', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9z500viqhd9qaw2iutw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Jaka jest funkcja motywu ''niepisanych praw'' (agraphoi nomoi)?', '{"options": ["tylko ozdoba retoryczna", "wprowadzenie koncepcji prawa naturalnego uniwersalnego i wiecznego", "krytyka wszelkich praw", "pochwała chaosu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,antiquity,batch-2025-01}', '{"explanation": "Niepisane prawa (agraphoi nomoi) to u Sofoklesa koncepcja prawa naturalnego - uniwersalnego, wiecznego, pochodzącego od bogów, nadrzędnego wobec edyktów władców. To fundamentalna kategoria filozofii prawa."}', '2025-10-24 22:16:54.593', '2025-10-24 22:16:54.593', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9z700vjqhd9n5u9agg5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Co symbolizuje odmowa Antygony przyjęcia pomocy Ismeny w finale?', '{"options": ["nienawiść do siostry", "że heroizm wymaga autentyczności - nie można ''dołączyć'' do bohaterstwa post factum", "chęć samotności", "przypadkową decyzję"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "Antygona odrzuca ''spóźniony heroizm'' Ismeny pokazując, że bohaterstwo wymaga autentycznego wyboru w momencie próby, nie deklaracji po fakcie. Nie można kupić sobie udziału w heroizmie."}', '2025-10-24 22:16:54.596', '2025-10-24 22:16:54.596', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9z900vkqhd9np14icfz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Jaka jest relacja między ''dike'' (sprawiedliwością boską) a ''nomos'' (prawem ludzkim) w tragedii?', '{"options": ["są identyczne", "są w nierozwiązywalnym konflikcie - to esencja tragedii", "nomos zawsze przeważa", "dike zawsze przeważa"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,antiquity,batch-2025-01}', '{"explanation": "Konflikt dike (sprawiedliwość boska, Antygona) i nomos (prawo ludzkie, Kreon) to esencja tragedii. Sofokles pokazuje, że mogą być w nierozwiązywalnym konflikcie - to właśnie tworzy sytuację tragiczną."}', '2025-10-24 22:16:54.598', '2025-10-24 22:16:54.598', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9zc00vlqhd91jgru4ul', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Co oznacza określenie Kreona jako człowieka ''który mocno dystansuje się od tragicznych aspiracji Edypa''?', '{"options": ["że Kreon jest lepszy od Edypa", "że Kreon to pragmatyk odrzucający wielkie ideały, co jest jego ograniczeniem", "że Kreon jest mądrzejszy", "że Edyp był zły"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "Kreon ''dystansuje się od tragicznych aspiracji Edypa'' - jest pragmatykiem, nie poszukiwaczem prawdy. Brakuje mu wielkości Edypa, co paradoksalnie prowadzi do jego upadku - nie rozumie wyższych zasad."}', '2025-10-24 22:16:54.6', '2025-10-24 22:16:54.6', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9ze00vmqhd9lyp7fk2r', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Jaka jest różnica między tragizmem Antygony a tragizmem Kreona?', '{"options": ["nie ma różnicy", "Antygona to tragizm heroiczny (świadomy wybór wartości), Kreon to tragizm hamartii (błąd prowadzący do upadku)", "oba są identyczne", "żadne nie jest tragiczne"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,antiquity,batch-2025-01}', '{"explanation": "To dwa różne typy tragizmu: Antygona reprezentuje tragizm heroiczny (świadomy wybór śmierci dla zasad), Kreon - klasyczny tragizm hamartii (wada charakteru - pycha - prowadzi do katastrofy)."}', '2025-10-24 22:16:54.602', '2025-10-24 22:16:54.602', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9zg00vnqhd9az2p4pod', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Jak interpretować stwierdzenie, że ''bez edyktu Kreona Antygona nie mogłaby dowieść swojego bohaterstwa''?', '{"options": ["że Kreon jest bohaterem", "że bohaterstwo wymaga oporu wobec niesprawiedliwości - konflikt jest konieczny", "że Antygona nie jest bohaterką", "że nie ma znaczenia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "To paradoks tragedii: bohaterstwo Antygony wymaga niesprawiedliwości Kreona jako ''tła''. Bez konfliktu nie byłoby heroizmu. Zło jest konieczne, by dobro mogło się ujawnić - dialektyka tragiczna."}', '2025-10-24 22:16:54.604', '2025-10-24 22:16:54.604', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evail013jqhd9dzpmlaw9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Co symbolizuje krew w dramacie?', '{"options": ["tylko przemoc", "winę i wyrzuty sumienia", "odwagę", "szlachectwo"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Krew symbolizuje przede wszystkim winę i niezmywalne piętno zbrodni."}', '2025-10-24 22:16:55.294', '2025-10-24 22:16:55.294', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9zi00voqhd9h8wwyy9n', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Jaka jest funkcja motywu ''żywego grobu'' (zamurowanie Antygony)?', '{"options": ["tylko sposób egzekucji", "symbolizuje odwrócenie porządku życia i śmierci - żywa w grobie, zmarły bez grobu", "przypadkowy wybór", "najłagodniejsza kara"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,antiquity,batch-2025-01}', '{"explanation": "Żywy grób symbolizuje odwrócenie porządku: Antygona żywa trafia do grobu, Polinik martwy zostaje bez grobu. To obrazuje chaos wprowadzony przez edykt Kreona - naruszenie granic między życiem a śmiercią."}', '2025-10-24 22:16:54.606', '2025-10-24 22:16:54.606', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9zk00vpqhd98cvqys0m', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Co oznacza pojęcie ''ananke'' (konieczności) w kontekście tragedii?', '{"options": ["wolną wolę", "nieuchronność losu i przymus wynikający z charakteru bohaterów i sytuacji", "przypadek", "szczęście"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "Ananke to konieczność, nieuchronność - połączenie przeznaczenia i charakteru bohaterów. Kreon mówi ''nie można walczyć przeciw konieczności'' - rozumie za późno, że jego natura i sytuacja musiały doprowadzić do tragedii."}', '2025-10-24 22:16:54.609', '2025-10-24 22:16:54.609', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9zn00vqqhd9qlhiii1y', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Jaka jest funkcja paraleli między Antygoną a Niobe w tragedii?', '{"options": ["nie ma paraleli", "obie są matkami skazanymi na cierpienie i przemianę w kamień - symbol застывшего żalu", "obie są szczęśliwe", "nie mają nic wspólnego"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,antiquity,batch-2025-01}', '{"explanation": "Antygona porównuje się do Niobe - mitycznej matki skazanej przez bogów, która zamieniła się w kamień ciągle ronący łzy. Symbol wiecznego, skamieniałego cierpienia. Antygona również czuje się żywym pomnikiem bólu."}', '2025-10-24 22:16:54.611', '2025-10-24 22:16:54.611', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9zp00vrqhd9p6ken0xy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Co oznacza stwierdzenie, że Antygona reprezentuje ''etykę przekonań'', a Kreon ''etykę odpowiedzialności''?', '{"options": ["że oba podejścia są identyczne", "Antygona działa według absolutnych zasad niezależnie od konsekwencji, Kreon bierze pod uwagę skutki dla państwa", "że Kreon jest etyczny a Antygona nie", "nie ma różnicy"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "To rozróżnienie Maxa Webera: etyka przekonań (Antygona) opiera się na absolutnych zasadach moralnych bez względu na konsekwencje; etyka odpowiedzialności (Kreon) bierze pod uwagę skutki działań dla dobra zbiorowego."}', '2025-10-24 22:16:54.613', '2025-10-24 22:16:54.613', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9zr00vsqhd9c1nslgtr', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Jaka jest relacja między ''pathos'' (cierpieniem) a poznaniem w tragedii?', '{"options": ["nie ma żadnej relacji", "cierpienie prowadzi do poznania - ''pathei mathos'' (przez cierpienie do wiedzy)", "tylko cierpienie bez poznania", "tylko poznanie bez cierpienia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,antiquity,batch-2025-01}', '{"explanation": "Starożytna zasada ''pathei mathos'' (przez cierpienie do wiedzy) realizuje się w Kreonie - dopiero utrata wszystkiego uczy go prawdy o pysze i sprawiedliwości. To esencja tragedii jako narzędzia poznania."}', '2025-10-24 22:16:54.615', '2025-10-24 22:16:54.615', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9zt00vtqhd9ho8etumy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Co symbolizuje fakt, że Antygona grzebie brata dwukrotnie?', '{"options": ["przypadek", "demonstrację siły woli i świadomego wyboru pomimo konsekwencji", "głupotę", "nie ma znaczenia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "Drugie pogrzebanie (po usunięciu pierwszej warstwy ziemi) to demonstracja: Antygona pokazuje, że to świadomy, powtarzalny wybór, nie impuls. Potwierdza swoją decyzję pomimo świadomości konsekwencji."}', '2025-10-24 22:16:54.618', '2025-10-24 22:16:54.618', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9zw00vuqhd93be70pdp', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 4, 'Dopasuj typy ironii do ich przykładów w tragedii.', '{"leftColumn": [{"id": "A", "text": "Ironia tragiczna"}, {"id": "B", "text": "Ironia dramatyczna"}, {"id": "C", "text": "Ironia sytuacyjna"}, {"id": "D", "text": "Ironia werbalna"}], "rightColumn": [{"id": 1, "text": "Widz wie o samobójstwie, Kreon nie"}, {"id": 2, "text": "Kreon chce porządku, ale tworzy chaos"}, {"id": 3, "text": "Racjonalny Kreon działa emocjonalnie"}, {"id": 4, "text": "Hajmon udaje posłuszeństwo ojcu"}], "matchingType": "irony_types"}', '[[0, 1], [1, 0], [2, 2], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "Różne typy ironii: tragiczna (efekt odwrotny od zamierzonego), dramatyczna (widz wie więcej), sytuacyjna (paradoks racjonalista/emocjonalność), werbalna (pozorna zgoda Hajmona)."}', '2025-10-24 22:16:54.62', '2025-10-24 22:16:54.62', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5ev9zy00vvqhd9oue7n7nz', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 4, 'Przeanalizuj funkcję motywu ''niepisanych praw'' (agraphoi nomoi) w argumentacji Antygony.', '{"instruction": "Wyjaśnij, czym są niepisane prawa, dlaczego Antygona uważa je za nadrzędne i jakie ma to implikacje filozoficzne. (100-130 słów)"}', NULL, '{"criteria": ["definicja niepisanych praw jako wiecznych i boskich (1 pkt)", "argumentacja Antygony: nie Zeus ani Dike nie ogłosili edyktu (1 pkt)", "nadrzędność wobec praw ludzkich (1 pkt)", "implikacje: koncepcja prawa naturalnego, uniwersalizm moralny (1 pkt)"], "maxScore": 4}', '{historical_literary,short_answer,difficulty-4,antiquity,batch-2025-01}', '{"keyWords": ["niepisane prawa", "agraphoi nomoi", "Zeus", "Dike", "wieczne", "uniwersalne", "prawo naturalne", "nadrzędność"], "expectedAnswer": "Niepisane prawa (agraphoi nomoi) to u Antygony prawa boskie, wieczne i niezmienne, pochodzące od Zeusa i Dike. Antygona argumentuje, że edykt Kreona nie pochodzi od bogów - ''Nie Zeus ani Dike ogłosili ten zakaz''. Te prawa są nadrzędne wobec dekretów władców, bo są uniwersalne i wieczne. Filozoficznie wprowadza to koncepcję prawa naturalnego - istnieją normy moralne niezależne od stanowienia ludzkiego, obowiązujące zawsze i wszędzie. To fundament późniejszej filozofii prawa i teorii praw człowieka - uniwersalizm moralny przeciw relatywizmowi."}', '2025-10-24 22:16:54.622', '2025-10-24 22:16:54.622', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evain013kqhd984dr1i8w', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Kto mówi: ''Makbet sen zabił''?', '{"options": ["Lady Makbet", "Makbet", "Duncan", "wiedźmy"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Makbet wypowiada te słowa po zabójstwie Duncana, czując, że utracił spokój sumienia."}', '2025-10-24 22:16:55.296', '2025-10-24 22:16:55.296', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva0000vwqhd9lx4k54zc', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 4, 'Wyjaśnij, w jaki sposób Sofokles problematizuje relację między jednostką a państwem.', '{"instruction": "Przeanalizuj argumenty obu stron i wyjaśnij, dlaczego konflikt pozostaje nierozwiązany. (110-140 słów)"}', NULL, '{"criteria": ["przedstawienie racji Kreona: dobro państwa, bezpieczeństwo (1 pkt)", "przedstawienie racji Antygony: godność jednostki, prawa człowieka (1 pkt)", "wyjaśnienie, że obie strony mają legitymację (1 pkt)", "brak syntezy - tragiczność konfliktu (1 pkt)"], "maxScore": 4}', '{historical_literary,short_answer,difficulty-5,antiquity,batch-2025-01}', '{"keyWords": ["jednostka", "państwo", "Kreon", "Antygona", "racje", "konflikt", "brak syntezy", "tragizm", "legitymacja"], "expectedAnswer": "Sofokles nie daje prostej odpowiedzi na pytanie o relację jednostka-państwo. Kreon ma rację argumentując, że porządek państwowy i bezpieczeństwo zbiorowe wymagają posłuszeństwa prawu - bez tego chaos. Antygona ma rację broniąc godności jednostki i praw wyższych od państwa - są granice władzy. Problem w tym, że obie racje są legitymne ale nie do pogodzenia. Sofokles nie wskazuje syntezy - to właśnie czyni sytuację tragiczną. Pokazuje, że pytanie o granice władzy państwa wobec sumienia jednostki nie ma prostej odpowiedzi i pozostaje aktualne przez wieki."}', '2025-10-24 22:16:54.625', '2025-10-24 22:16:54.625', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva0300vxqhd9cluartne', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 4, 'Przeanalizuj funkcję kontrastu między ''wiedzieć'' a ''być mądrym'' w tragedii.', '{"instruction": "Wyjaśnij różnicę między wiedzą a mądrością na przykładzie Kreona i znaczenie zasady ''pathei mathos''. (100-130 słów)"}', NULL, '{"criteria": ["rozróżnienie wiedzy i mądrości (1 pkt)", "Kreon ma wiedzę (władza, prawo), ale brak mu mądrości (1 pkt)", "zasada pathei mathos - przez cierpienie do wiedzy (1 pkt)", "dopiero utrata uczy go prawdziwej mądrości (1 pkt)"], "maxScore": 4}', '{historical_literary,short_answer,difficulty-4,antiquity,batch-2025-01}', '{"keyWords": ["wiedza", "mądrość", "Kreon", "pathei mathos", "cierpienie", "doświadczenie", "pycha"], "expectedAnswer": "Tragedia rozróżnia wiedzę od mądrości. Kreon ma wiedzę - rozumie politykę, prawo, władzę. Ale brakuje mu mądrości - głębszego zrozumienia ludzkiej natury, granic władzy, wartości. Chór kończy mówiąc, że ''mądrości uczymy się w późnym wieku przez cierpienie'' - to zasada ''pathei mathos'' (przez cierpienie do wiedzy). Dopiero katastrofa - utrata syna i żony - uczy Kreona prawdziwej mądrości o pysze i sprawiedliwości. Wiedza intelektualna nie zastąpi mądrości nabytej przez doświadczenie egzystencjalne."}', '2025-10-24 22:16:54.627', '2025-10-24 22:16:54.627', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva0500vyqhd9aziek7xg', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 5, 'Omów paradoks tragiczny: bohaterowie mają rację i popełniają błąd jednocześnie.', '{"instruction": "Wyjaśnij, w jaki sposób zarówno Antygona jak i Kreon są jednocześnie ''w słuszności'' i ''w błędzie''. (120-150 słów)"}', NULL, '{"criteria": ["racja Antygony: prawa boskie, lojalność rodzinna (1 pkt)", "błąd Antygony: bezkompromisowość, brak elastyczności (1 pkt)", "racja Kreona: porządek państwowy, dobro wspólne (1 pkt)", "błąd Kreona: pycha, przekroczenie granic (1 pkt)", "wyjaśnienie paradoksu: tragizm wynika z konfliktu dwóch słuszności (1 pkt)"], "maxScore": 5}', '{historical_literary,short_answer,difficulty-5,antiquity,batch-2025-01}', '{"keyWords": ["paradoks", "racja", "błąd", "Antygona", "Kreon", "tragizm", "kolizja wartości", "legitymacja"], "expectedAnswer": "To esencja tragizmu: obie strony mają rację i popełniają błąd. Antygona ma rację broniąc praw boskich i lojalności rodzinnej - są wartości wyższe od edyktu. Ale popełnia błąd przez skrajny ry­goryzm - nie próbuje dialogu, odrzuca Ismenę. Kreon ma rację dbając o porządek państwowy - władca musi zapewnić bezpieczeństwo. Ale popełnia błąd przez pychę - przekracza granice, nie słucha rad, stawia się ponad bogami. Paradoks polega na tym, że tragedia nie wynika z prostego zła - wynika z kolizji dwóch legitymnych racji. Gdyby jedna strona była po prostu zła, nie byłoby tragedii - byłby tylko konflikt dobra ze złem."}', '2025-10-24 22:16:54.629', '2025-10-24 22:16:54.629', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva0700vzqhd9cbo46eyd', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 4, 'Przeanalizuj funkcję motywu ''zamurowania żywcem'' w symbolice tragedii.', '{"instruction": "Wyjaśnij symboliczne znaczenie kary zamurowania i jej związek z odwróceniem porządku życia/śmierci. (100-130 słów)"}', NULL, '{"criteria": ["zamurowanie jako forma ''żywego grobu'' (1 pkt)", "odwrócenie porządku: żywa w grobie, zmarły bez grobu (1 pkt)", "zakłócenie granic między życiem a śmiercią (1 pkt)", "symbolika chaosu wprowadzonego przez edykt (1 pkt)"], "maxScore": 4}', '{historical_literary,short_answer,difficulty-4,antiquity,batch-2025-01}', '{"keyWords": ["zamurowanie", "żywy grób", "odwrócenie porządku", "życie", "śmierć", "chaos", "granice", "kosmiczny ład"], "expectedAnswer": "Zamurowanie Antygony żywcem to ''żywy grób'' - paradoksalna kara symbolizująca odwrócenie porządku. Antygona żywa trafia do grobu (królestwo śmierci), podczas gdy Polinik martwy pozostaje bez grobu (w królestwie żywych). To obrazuje chaos wprowadzony przez edykt Kreona - naruszenie granic między życiem a śmiercią, sferą żywych i umarłych. W myśleniu greckim takie zakłócenie kosmicznego porządku musi doprowadzić do katastrofy. Zamurowanie ma też znaczenie praktyczne dla Kreona - formalnie unika przelania krwi, więc odpowiedzialność spada na bogów."}', '2025-10-24 22:16:54.632', '2025-10-24 22:16:54.632', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva0a00w0qhd9qirb09dt', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 5, 'Omów relację między ''physis'' (naturą) a ''nomos'' (prawem/konwencją) w tragedii.', '{"instruction": "Wyjaśnij ten fundamentalny konflikt sofistyczny i jego reprezentację w Antygonie. (130-160 słów)"}', NULL, '{"criteria": ["definicja physis jako natury, porządku naturalnego (1 pkt)", "definicja nomos jako prawa stanowionego, konwencji (1 pkt)", "Antygona reprezentuje physis (prawa naturalne) (1 pkt)", "Kreon reprezentuje nomos (prawo ustanowione) (1 pkt)", "kontekst sofistyczny: debata V wieku p.n.e. (1 pkt)"], "maxScore": 5}', '{historical_literary,short_answer,difficulty-5,antiquity,batch-2025-01}', '{"keyWords": ["physis", "nomos", "natura", "prawo", "konwencja", "Antygona", "Kreon", "sofiści", "konflikt", "porządek"], "expectedAnswer": "Konflikt physis-nomos to fundamentalna debata V wieku p.n.e. Physis to natura, porządek naturalny, prawa wynikające z natury rzeczy - niezmienne i uniwersalne. Nomos to prawo stanowione, konwencja społeczna, ustalenia ludzi - zmienne i relatywne. Antygona reprezentuje physis - odwołuje się do naturalnego obowiązku pochówku, praw boskich wpisanych w naturę. Kreon reprezentuje nomos - jego edykt to konwencja polityczna, ustalenie władcy. Sofiści pytali: co jeśli nomos (prawo ludzkie) sprzeciwia się physis (naturze)? Sofokles nie daje jednoznacznej odpowiedzi - pokazuje tragiczność sytuacji, gdy oba porządki kolidują. To kluczowa debata o źródłach prawa aktualna do dziś."}', '2025-10-24 22:16:54.634', '2025-10-24 22:16:54.634', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva0d00w1qhd92rh2l8xj', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 4, 'Przeanalizuj znaczenie metafory ''państwo jako statek'' w przemowie Kreona.', '{"instruction": "Wyjaśnij tę metaforę i jej implikacje dla koncepcji władzy Kreona. (90-120 słów)"}', NULL, '{"criteria": ["wyjaśnienie metafory: państwo to statek, władca to sternik (1 pkt)", "implikacja: potrzeba jednego dowódcy, hierarchii (1 pkt)", "usprawiedliwienie autorytaryzmu (1 pkt)", "krytyka Sofoklesa: sztywne sterowanie prowadzi do katastrofy (1 pkt)"], "maxScore": 4}', '{historical_literary,short_answer,difficulty-4,antiquity,batch-2025-01}', '{"keyWords": ["metafora", "państwo", "statek", "sternik", "władza", "autorytaryzm", "elastyczność", "Kreon", "Hajmon"], "expectedAnswer": "Kreon używa metafory państwa jako statku: ''nasza ojczyzna to statek, który niesie nas bezpiecznie''. Implikacje: państwo potrzebuje jednego sternika (władcy), hierarchii, dyscypliny. Jak statek w burzy, państwo wymaga silnej ręki. To usprawiedliwienie dla autorytaryzmu Kreona. Jednak Hajmon odwraca tę metaforę: sztywny sternik prowadzi statek na skały, dobry sternik musi być elastyczny. Sofokles pokazuje, że metafora może służyć obu stronom - i uzasadnieniu władzy, i jej krytyce. Kreon kończy jako sternik, który zatopił własny statek przez sztywność."}', '2025-10-24 22:16:54.637', '2025-10-24 22:16:54.637', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva0f00w2qhd9kda7eqs2', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 8, 'Napisz notatkę syntetyzującą o wielowymiarowości konfliktu tragicznego.', '{"topic": "Wielowymiarowość konfliktu w Antygonie - poziomy i interpretacje", "requirements": ["poziom teologiczny: bogowie vs ludzie", "poziom polityczny: jednostka vs państwo", "poziom rodzinny: lojalność krwi vs lojalność państwowa", "poziom płciowy: kobiece vs męskie", "poziom filozoficzny: prawo naturalne vs stanowione", "syntetyczne ujęcie: wszystkie wymiary się przenikają", "250-300 słów"]}', NULL, '{"criteria": ["omówienie poziomu teologicznego (1,5 pkt)", "omówienie poziomu politycznego (1,5 pkt)", "omówienie poziomu rodzinnego (1 pkt)", "omówienie poziomu płciowego (1 pkt)", "omówienie poziomu filozoficznego (1,5 pkt)", "synteza: wzajemne przenikanie się wymiarów (1,5 pkt)"], "maxScore": 8}', '{historical_literary,synthesis_note,difficulty-4,antiquity,batch-2025-01}', NULL, '2025-10-24 22:16:54.64', '2025-10-24 22:16:54.64', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva0i00w3qhd9z5ddj2sc', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 9, 'Omów Antygonę jako tragedię ''dialektyczną bez syntezy''.', '{"topic": "Struktura dialektyczna Antygony: teza, antyteza i brak syntezy", "requirements": ["wyjaśnienie struktury dialektycznej (Hegel)", "teza: prawa boskie, rodzina, jednostka (Antygona)", "antyteza: prawa państwowe, porządek, władza (Kreon)", "brak syntezy: konflikt pozostaje nierozwiązany", "dlaczego brak syntezy tworzy tragizm", "implikacje filozoficzne: nie wszystkie konflikty mają rozwiązanie", "300-350 słów"]}', NULL, '{"criteria": ["wyjaśnienie struktury dialektycznej (1,5 pkt)", "charakterystyka tezy - Antygona (2 pkt)", "charakterystyka antytezy - Kreon (2 pkt)", "wyjaśnienie braku syntezy (2 pkt)", "implikacje filozoficzne (1,5 pkt)"], "maxScore": 9}', '{historical_literary,synthesis_note,difficulty-5,antiquity,batch-2025-01}', NULL, '2025-10-24 22:16:54.642', '2025-10-24 22:16:54.642', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva0k00w4qhd9j28wlpsf', 'ESSAY', 'WRITING', 'ANTIQUITY', 5, 20, 'Napisz rozprawkę: Czy w konflikcie Antygony i Kreona można mówić o ''zwycięzcy''? Omów problem na podstawie tragedii Sofoklesa.', '{"thesis": "Czy w konflikcie Antygony i Kreona można mówić o ''zwycięzcy''?", "structure": {"arguments": ["Racja Antygony: triumf moralny, wierność zasadom, ale śmierć fizyczna", "Racja Kreona: przeżywa, ale w rozpaczy - ''żywy trup'', moralna klęska", "Paradoks: obie strony przegrywają - to esencja tragedii", "Interpretacja: w tragedii nie ma zwycięzców, tylko ofiary konfliktu wartości"], "conclusion": "Wnioski: tragizm polega na niemożności wygranej", "introduction": "Wprowadzenie: natura konfliktu tragicznego"}, "wordLimit": {"max": 500, "min": 400}, "requirements": ["struktura: wstęp - rozwinięcie - zakończenie", "argumenty filozoficzne i literackie", "odniesienie do tekstu tragedii", "kontekst: teoria tragedii, konfliktu tragicznego", "język eseistyczny, akademicki", "400-500 słów"]}', NULL, '{"criteria": {"formal": "Zachowanie wymogów formalnych (objętość, struktura, tytuł)", "language": "Język akademicki, precyzja, styl eseistyczny, poprawność", "literary": "Znajomość tragedii, głębokość analizy, argumenty filozoficzne, kontekst teoretyczny", "composition": "Logika wywodu, spójność, teza, argumentacja, kontrargumenty"}, "maxScore": 20, "formalScore": 2, "languageScore": 4, "literaryScore": 10, "compositionScore": 4}', '{writing,essay,difficulty-5,antiquity,batch-2025-01}', NULL, '2025-10-24 22:16:54.645', '2025-10-24 22:16:54.645', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva0n00w5qhd9ocdh1zsq', 'ESSAY', 'WRITING', 'ANTIQUITY', 5, 20, 'Napisz esej interpretacyjny: Antygona Sofoklesa jako traktat o granicach władzy państwowej. Omów aktualność problematyki.', '{"thesis": "Antygona jako traktat o granicach władzy państwowej i jej aktualność", "structure": {"main_body": ["Pozycja Kreona: władza absolutna, racja stanu", "Pozycja Antygony: sumienie jednostki, prawa nadrzędne", "Sofokles nie rozstrzyga - pokazuje tragiczność", "Aktualność: totalitaryzmy XX w., prawa człowieka, nieposłuszeństwo obywatelskie"], "conclusion": "Pytanie pozostaje otwarte - to znak wielkości dzieła", "introduction": "Problem: gdzie kończą się prawa państwa wobec jednostki?"}, "wordLimit": {"max": 550, "min": 450}, "requirements": ["forma eseju interpretacyjnego", "analiza filozoficzna i polityczna", "przykłady historyczne (XX wiek)", "odniesienia do tekstu tragedii", "język akademicki, eseistyczny", "perspektywa krytyczna", "450-550 słów"]}', NULL, '{"criteria": {"formal": "Forma eseju, objętość, struktura", "language": "Język akademicki, precyzja terminologiczna, styl eseistyczny", "literary": "Interpretacja tekstu, kontekst filozoficzny i historyczny, aktualność problemu", "composition": "Logika argumentacji, spójność, perspektywa krytyczna"}, "maxScore": 20, "formalScore": 2, "languageScore": 4, "literaryScore": 10, "compositionScore": 4}', '{writing,essay,difficulty-5,antiquity,batch-2025-01}', NULL, '2025-10-24 22:16:54.647', '2025-10-24 22:16:54.647', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva0q00w6qhd93lb9gzh7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Co oznacza określenie Antygony jako tragedii ''bez katharsis dla Kreona''?', '{"options": ["że Kreon nie przeżywa oczyszczenia emocjonalnego", "że poznanie prawdy nie przynosi mu ulgi, tylko wieczne cierpienie", "że Kreon jest szczęśliwy", "że nie ma tragedii"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "Kreon poznaje prawdę (anagnorisis), ale zamiast oczyszczenia (katharsis) dostaje wieczne cierpienie - musi żyć ze świadomością winy. To pesymistyczna wersja tragedii."}', '2025-10-24 22:16:54.65', '2025-10-24 22:16:54.65', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva0s00w7qhd9dd1sebju', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Jaka jest relacja między ''ethos'' (charakterem) a ''daimon'' (bóstwem/losem) u Heraklita: ''ethos anthropoi daimon''?', '{"options": {"options": ["los jest całkowicie zewnętrzny", "charakter człowieka jest jego losem - natura determinuje przeznaczenie", "los i charakter są niezależne", "nie ma żadnej relacji"], "contextLinks": [{"type": "text", "title": "Heraklitejska sentencja", "content": "Sentencja Heraklita ''ethos anthropoi daimon'' (charakter jest dla człowieka losem/bóstwem) wyraża ideę, że los człowieka nie jest całkowicie zewnętrzny, ale wynika z jego charakteru. To, kim jesteśmy, determinuje to, co nam się przydarzy.", "trigger": "ethos anthropoi daimon", "moreInfoLink": ""}]}}', '1', NULL, '{historical_literary,closed_single,difficulty-5,antiquity,batch-2025-01}', '{"explanation": "Sentencja Heraklita ''ethos anthropoi daimon'' (charakter jest losem) doskonale opisuje Antygonę: pycha Kreona jest jego losem, heroizm Antygony - jej przeznaczeniem. Charakter determinuje los."}', '2025-10-24 22:16:54.653', '2025-10-24 22:16:54.653', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva0v00w8qhd9jzim869i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Co oznacza pojęcie ''anagnorisis'' w kontekście Kreona?', '{"options": ["poznanie prawdy o sobie za późno by zmienić los", "szczęśliwe zakończenie", "brak świadomości", "triumf"]}', '0', NULL, '{historical_literary,closed_single,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "Anagnorisis (rozpoznanie) to moment, gdy bohater poznaje prawdę. Kreon rozpoznaje swoją pychę i błąd, ale za późno - nie może już uratować rodziny. To klasyczny element tragedii."}', '2025-10-24 22:16:54.656', '2025-10-24 22:16:54.656', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva0y00w9qhd9y2jpzafh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Jak interpretować fakt, że Antygona wybiera śmierć ''niezamężna, bez potomstwa''?', '{"options": ["nie ma to znaczenia", "podkreśla tragizm - rezygnuje z pełni życia (małżeństwo, macierzyństwo) dla zasad", "to przypadek", "Antygona tego nie chce"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,antiquity,batch-2025-01}', '{"explanation": "Antygona lamentuje, że umiera ''bez małżeństwa, bez dzieci'' - to w kulturze greckiej oznacza niepełne życie. Podkreśla wagę poświęcenia: rezygnuje z podstawowych kobiecych ról dla wyższych wartości."}', '2025-10-24 22:16:54.658', '2025-10-24 22:16:54.658', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva1100waqhd980rxizuj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 3, 'Co symbolizuje dwukrotne posypanie ciała ziemią przez Antygonę?', '{"options": ["przypadek", "demonstrację świadomego, powtarzalnego wyboru - nie impuls, ale przemyślana decyzja", "błąd", "chęć zemsty"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "Drugie pogrzebanie po usunięciu ziemi przez strażników to dowód, że to nie impuls ale świadoma, powtarzalna decyzja. Antygona potwierdza swój wybór pomimo konsekwencji."}', '2025-10-24 22:16:54.662', '2025-10-24 22:16:54.662', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva1b00wbqhd9ps66goy9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 3, 'Jaka jest funkcja motywu ''pustego grobu'' i ''pełnego grobu'' w finale?', '{"options": ["tylko realistyczny szczegół", "Hades/grób Polinika pusty (ptaki), grób Antygony pełny (ciała) - odwrócony porządek", "przypadek", "nie ma znaczenia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,antiquity,batch-2025-01}', '{"explanation": "Finałowe odkrycie: grób Polinika pusty (ciało rozszarpane), grób Antygony pełny (ona, Hajmon). To symboliczne odwrócenie - chaos wprowadzony przez edykt materializuje się w obrazie."}', '2025-10-24 22:16:54.671', '2025-10-24 22:16:54.671', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva1e00wcqhd930lykx2o', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 4, 'Dopasuj interpretacje filozoficzne tragedii do ich autorów/szkół.', '{"leftColumn": [{"id": "A", "text": "Tragedia jako konfliktu praw równie usprawiedliwionych"}, {"id": "B", "text": "Tragedia jako konflikt jednostki z totalitaryzmem"}, {"id": "C", "text": "Tragedia jako konflikt kultury i natury"}, {"id": "D", "text": "Tragedia jako ilustracja hybris i nemezis"}], "rightColumn": [{"id": 1, "text": "Interpretacja klasyczna grecka"}, {"id": 2, "text": "Hegel - dialektyka ducha"}, {"id": 3, "text": "Lektura strukturalistyczna"}, {"id": 4, "text": "Lektura polityczna XX wieku"}], "matchingType": "interpretations_schools"}', '[[0, 1], [1, 3], [2, 2], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-5,antiquity,batch-2025-01}', '{"explanation": "Różne interpretacje: Hegel (równorzędne prawa), XX wiek (jednostka vs totalitaryzm), strukturalizm (kultura vs natura), klasyczna (hybris-nemezis)."}', '2025-10-24 22:16:54.674', '2025-10-24 22:16:54.674', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva1h00wdqhd9dnu6r2a6', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 4, 4, 'Które stwierdzenia o teorii tragedii Arystotelesa są prawdziwe? (wybierz wszystkie poprawne)', '{"options": ["tragedia powinna wywoływać litość (eleos) i trwogę (phobos)", "bohater musi być absolutnie doskonały", "katharsis to oczyszczenie emocjonalne przez przeżycie tragedii", "hamartia to zawsze grzech moralny", "perypetia to nagłe odwrócenie fortuny", "anagnorisis to moment rozpoznania prawdy"]}', '[0, 2, 4, 5]', NULL, '{historical_literary,closed_multiple,difficulty-4,antiquity,batch-2025-01}', '{"explanation": "Według Arystotelesa: tragedia wywołuje litość i trwogę prowadząc do katharsis, ma perypetię i anagnorisis. Bohater nie jest doskonały (miara), hamartia to nie zawsze grzech (może być cecha charakteru)."}', '2025-10-24 22:16:54.677', '2025-10-24 22:16:54.677', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva1k00weqhd9lotg88jm', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 4, 'Dopasuj modele sprawiedliwości do ich reprezentacji w tragedii.', '{"leftColumn": [{"id": "A", "text": "Sprawiedliwość wyrównawcza"}, {"id": "B", "text": "Sprawiedliwość dystrybutywna"}, {"id": "C", "text": "Sprawiedliwość naprawcza"}, {"id": "D", "text": "Sprawiedliwość retrybutywna"}], "rightColumn": [{"id": 1, "text": "Nemezis - bogowie karzą Kreona za pychę"}, {"id": 2, "text": "Hades - równe prawa dla wszystkich zmarłych"}, {"id": 3, "text": "próba Kreona naprawienia błędu (za późno)"}, {"id": 4, "text": "edykt Kreona - rozdział nagród/kar"}], "matchingType": "justice_models"}', '[[0, 1], [1, 3], [2, 2], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-5,antiquity,batch-2025-01}', '{"explanation": "Różne modele sprawiedliwości: wyrównawcza (równość - Hades), dystrybutywna (podział - edykt), naprawcza (Kreon próbuje naprawić), retrybutywna (kara - nemezis)."}', '2025-10-24 22:16:54.68', '2025-10-24 22:16:54.68', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaip013lqhd9pqf5dl5p', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Co Lady Makbet próbuje zmyć ze swoich rąk podczas sceny lunatyzmu?', '{"options": ["truciznę", "niewidzialną krew", "perfumy", "błoto"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "W scenie lunatyzmu Lady Makbet obsesyjnie myje ręce, próbując zmyć wyimaginowaną krew."}', '2025-10-24 22:16:55.298', '2025-10-24 22:16:55.298', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva1m00wfqhd9wca97rsx', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ANTIQUITY', 5, 5, 'Omów Heglowską interpretację Antygony jako konfliktu ''dwóch równie usprawiedliwionych racji''.', '{"instruction": "Wyjaśnij interpretację Hegla, przedstaw obie racje jako równorzędne i omów implikacje dla pojmowania tragedii. (140-170 słów)"}', NULL, '{"criteria": ["Hegel: tragedia to konflikt równorzędnych zasad (1 pkt)", "Antygona reprezentuje rodzinę, bogów, jednostkę (1 pkt)", "Kreon reprezentuje państwo, prawo, wspólnotę (1 pkt)", "obie strony mają rację i to tworzy tragizm (1 pkt)", "implikacje: tragedia wyższego rzędu niż dobro vs zło (1 pkt)"], "maxScore": 5}', '{historical_literary,short_answer,difficulty-5,antiquity,batch-2025-01}', '{"keyWords": ["Hegel", "równorzędne racje", "rodzina", "państwo", "dialektyka", "tragizm", "kolizja dóbr", "synteza"], "expectedAnswer": "Hegel interpretuje Antygonę jako konflikt ''dwóch równie usprawiedliwionych racji'' - to kluczowa teoria tragedii. Antygona reprezentuje prawo rodziny, bogów, sfery prywatnej i jednostkowej - zasady równie ważne i prawdziwe. Kreon reprezentuje prawo państwa, porządku publicznego, dobra wspólnoty - zasady również ważne i prawdziwe. Tragizm wynika właśnie z tego, że obie strony mają rację - nie jest to konflikt dobra ze złem, ale kolizja dwóch dóbr. Dla Hegla to wyższa forma tragedii: nie prostota moralności, ale dialektyka ducha, gdzie teza i antyteza nie mogą się pogodzić. Tragedia ukazuje ograniczenia jednostronnych zasad i konieczność ich przezwyciężenia w syntezie - której w Antygonie brakuje."}', '2025-10-24 22:16:54.683', '2025-10-24 22:16:54.683', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva1p00wgqhd988ru3etm', 'ESSAY', 'WRITING', 'ANTIQUITY', 5, 20, 'Napisz esej krytycznoliteracki: Antygona jako arcydzieło tragedii - analiza wielowymiarowości konfliktu i uniwersalności problematyki.', '{"thesis": "Dlaczego Antygona uznawana jest za jedno z arcydzieł tragedii światowej?", "structure": {"main_body": ["Doskonałość konstrukcji dramatycznej (jedności, perypetia, katharsis)", "Wielowymiarowość konfliktu (teologiczny, polityczny, rodzinny, płciowy)", "Głębia filozoficzna (prawo naturalne, granice władzy)", "Uniwersalność: problemy aktualne przez 2500 lat", "Postaci wielowymiarowe, nie schematyczne", "Język poetycki i retoryka"], "conclusion": "Synteza: arcydzieło bo łączy doskonałość formy z głębią treści", "introduction": "Teza: wielowymiarowość i uniwersalność czynią Antygonę ponadczasową"}, "wordLimit": {"max": 600, "min": 500}, "requirements": ["forma eseju krytycznoliterackiego", "analiza formalna i treściowa", "kontekst teoretyczny (teoria tragedii)", "język akademicki, precyzyjny", "perspektywa komparatystyczna (odniesienia do innych dzieł)", "500-600 słów"]}', NULL, '{"criteria": {"formal": "Forma eseju, struktura, objętość", "language": "Język akademicki, terminologia literacka, precyzja, styl", "literary": "Analiza formalna i treściowa, kontekst teoretyczny, głębia interpretacji, perspektywa komparatystyczna", "composition": "Logika wywodu, spójność argumentacji, synteza"}, "maxScore": 20, "formalScore": 2, "languageScore": 4, "literaryScore": 10, "compositionScore": 4}', '{writing,essay,difficulty-5,antiquity,batch-2025-01}', NULL, '2025-10-24 22:16:54.685', '2025-10-24 22:16:54.685', 'Antygona');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva1s00whqhd9x08gwb1j', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 3, 'Która postać z ''Lalki'' reprezentuje typ ''organic pracownika''?', '{"options": ["Wokulski", "Rzecki", "Ochocki", "Szuman"]}', '3', NULL, '{historical_literary,closed_single,difficulty-4,positivism,batch-2025-01}', NULL, '2025-10-24 22:16:54.688', '2025-10-24 22:16:54.688', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva1u00wiqhd946hiih38', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Która postać z Lalki reprezentuje arystokrację?', '{"options": ["Stanisław Wokulski", "Ignacy Rzecki", "Izabela Łęcka", "Julian Ochocki"], "contextLinks": [{"type": "text", "title": "Arystokracja w ''Lalce'' Prusa", "content": "Arystokracja to warstwa społeczna najwyższego stanu, zazwyczaj szlachta rodowa posiadająca tytuły (hrabiów, baronów) i znaczny majątek. W ''Lalce'' Bolesława Prusa arystokracja reprezentowana przez rodzinę Łęckich symbolizuje stare, konserwatywne elity, które w epoce kapitalizmu tracą znaczenie ekonomiczne, ale zachowują prestiż społeczny. Izabela Łęcka to córka arystokratycznej rodziny, w której zakochuje się kupiec Wokulski.", "trigger": "arystokrację", "moreInfoLink": ""}]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Izabela Łęcka jest córką arystokratycznej rodziny, reprezentującą stare elity szlacheckie. Wokulski to przedsiębiorca i kupiec (burżuazja), Rzecki to wierny subiekt (drobnomieszczanin), a Ochocki to dziennikarz. Konflikt między mieszczańskim Wokulskim a arystokratyczną Izabelą jest jednym z głównych wątków powieści."}', '2025-10-24 22:16:54.69', '2025-10-24 22:16:54.69', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva1w00wjqhd92bv4wt03', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 3, 'Dopasuj postać z „Lalki” do jej roli społecznej.', '{"leftColumn": [{"id": "A", "text": "Wokulski"}, {"id": "B", "text": "Szlangbaum"}, {"id": "C", "text": "Baronowa"}], "rightColumn": [{"id": 1, "text": "arystokratka"}, {"id": 2, "text": "kupiec-idealista"}, {"id": 3, "text": "bogaty finansista"}], "matchingType": "character_role"}', '[[0, 1], [1, 2], [2, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', NULL, '2025-10-24 22:16:54.693', '2025-10-24 22:16:54.693', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva1z00wkqhd9ca6r0y4d', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 1, 'Która postać z ''Lalki'' reprezentuje idealistę-romantyka?', '{"options": ["Rzecki", "Wokulski", "Ochocki", "Szlangbaum"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', NULL, '2025-10-24 22:16:54.695', '2025-10-24 22:16:54.695', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2100wlqhd9xmjmmibw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Kto jest autorem powieści Lalka?', '{"options": ["Henryk Sienkiewicz", "Bolesław Prus", "Eliza Orzeszkowa", "Maria Konopnicka"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Autorem Lalki jest Bolesław Prus (właściwie Aleksander Głowacki)."}', '2025-10-24 22:16:54.698', '2025-10-24 22:16:54.698', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2400wmqhd9bveppiac', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Jak nazywa się główny bohater Lalki?', '{"options": ["Ignacy Rzecki", "Stanisław Wokulski", "Julian Ochocki", "Tomasz Łęcki"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Głównym bohaterem jest Stanisław Wokulski - warszawski kupiec zakochany w Izabeli Łęckiej."}', '2025-10-24 22:16:54.7', '2025-10-24 22:16:54.7', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2600wnqhd9skqa3zn9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'W kim zakochał się Stanisław Wokulski?', '{"options": ["w Helenie Stawskiej", "w baronowej Krzeszowskiej", "w Izabeli Łęckiej", "w pani Wąsowskiej"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Wokulski zakochał się bez pamięci w pięknej arystokratce Izabeli Łęckiej."}', '2025-10-24 22:16:54.702', '2025-10-24 22:16:54.702', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2800woqhd9lgzm0qar', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Jaki zawód wykonuje Stanisław Wokulski?', '{"options": ["lekarz", "nauczyciel", "kupiec", "bankier"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Wokulski jest właścicielem sklepu galanteryjnego w Warszawie."}', '2025-10-24 22:16:54.704', '2025-10-24 22:16:54.704', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2b00wpqhd9m5v9e7kk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Gdzie Wokulski zarobił swój majątek?', '{"options": ["w Paryżu jako naukowiec", "w Warszawie w handlu", "na wojnie turecko-rosyjskiej dostarczając broń", "w Moskwie jako kupiec"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Wokulski wyjechał do Bułgarii podczas wojny turecko-rosyjskiej i zarobił majątek na dostawach broni dla wojska."}', '2025-10-24 22:16:54.707', '2025-10-24 22:16:54.707', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2d00wqqhd91wx215pj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kto jest narratorem w Pamiętniku starego subiekta?', '{"options": ["Stanisław Wokulski", "Ignacy Rzecki", "Julian Ochocki", "doktor Szuman"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Fragmenty Pamiętnika starego subiekta są pisane z perspektywy Ignacego Rzeckiego - przyjaciela Wokulskiego."}', '2025-10-24 22:16:54.709', '2025-10-24 22:16:54.709', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2f00wrqhd9gq7rbv0c', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Jakiego przywódcy politycznego uwielbiał Ignacy Rzecki?', '{"options": ["Napoleona Bonaparte", "Józefa Piłsudskiego", "Tadeusza Kościuszkę", "Kazimierza Wielkiego"]}', '0', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Rzecki był zagorzałym bonapartystą - uwielbiał Napoleona Bonaparte i wierzył w bonapartyzm."}', '2025-10-24 22:16:54.712', '2025-10-24 22:16:54.712', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2h00wsqhd94pq9b89q', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Jaki pierwotny tytuł miała mieć Lalka?', '{"options": ["Idealiści", "Trzy pokolenia", "Warszawiacy", "Kupiec warszawski"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Pierwotnie Prus chciał nadać powieści tytuł Trzy pokolenia, nawiązujący do trzech generacji idealistów."}', '2025-10-24 22:16:54.714', '2025-10-24 22:16:54.714', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2j00wtqhd9bw91wujx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'W którym mieście głównie toczy się akcja Lalki?', '{"options": ["Krakowie", "Poznaniu", "Warszawie", "Lwowie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Akcja głównie toczy się w Warszawie lat 1878-1879, choć pojawiają się także sceny z Paryża i Zasławka."}', '2025-10-24 22:16:54.716', '2025-10-24 22:16:54.716', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2m00wuqhd9f00vlhgt', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 1, 'Jaka technika narracyjna charakteryzuje Lalkę?', '{"options": ["monolog wewnętrzny", "narracja pierwszoosobowa", "dwugłos: narrator trzecioosobowy + pamiętnik Rzeckiego", "narracja strumienia świadomości"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Prus zastosował dwugłos narracyjny: narrator trzecioosobowy przeplatany jest fragmentami pamiętnika Rzeckiego (narracja pierwszoosobowa)."}', '2025-10-24 22:16:54.718', '2025-10-24 22:16:54.718', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2o00wvqhd9u8efixe0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Co symbolizuje lalka w tytule powieści?', '{"options": ["tylko zabawkę w procesie sądowym", "sztuczność relacji społecznych i pustą arystokrację", "dzieciństwo bohaterów", "przemysł zabawkarski"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Lalka symbolizuje sztuczność i pustkę emocjonalną (jak Izabela), a także topos theatrum mundi - ludzie jako marionetki."}', '2025-10-24 22:16:54.72', '2025-10-24 22:16:54.72', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2q00wwqhd968xhpp5i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Kogo reprezentuje postać Juliana Ochockiego w powieści?', '{"options": ["romantycznych idealistów politycznych", "nowych pozytywistycznych idealistów naukowych", "cyniczną arystokrację", "mieszczaństwo handlowe"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Ochocki reprezentuje młode pokolenie pozytywistycznych idealistów oddanych nauce i postępowi naukowemu."}', '2025-10-24 22:16:54.723', '2025-10-24 22:16:54.723', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2s00wxqhd9sx4jbv2b', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'W jakim kierunku Prus krytykuje społeczeństwo w Lalce?', '{"options": ["krytykuje tylko arystokrację", "krytykuje tylko mieszczaństwo", "krytykuje wszystkie warstwy społeczne", "nie krytykuje żadnej warstwy"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Lalka to realizm krytyczny - Prus krytykuje wszystkie warstwy społeczne: arystokrację, mieszczaństwo i inteligencję."}', '2025-10-24 22:16:54.725', '2025-10-24 22:16:54.725', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2v00wyqhd9065owugd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Jak charakteryzuje się postać Izabeli Łęckiej?', '{"options": ["pracowita i zaradna kobieta", "inteligentna i wykształcona arystokratka", "pusta emocjonalnie i intelektualnie salonowa lalka", "oddana i zakochana w Wokulskim"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Izabela to salonowa lalka - piękna zewnętrznie, ale pusta wewnętrznie, wychowana w luksusie i oderwana od rzeczywistości."}', '2025-10-24 22:16:54.727', '2025-10-24 22:16:54.727', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva2x00wzqhd9qlgyne7u', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 2, 'Jaki kontrast przedstawia Prus w postaciach Izabeli Łęckiej i Heleny Stawskiej?', '{"options": ["bogata vs biedna", "młoda vs stara", "pusta i egoistyczna vs życzliwa i zaradna", "piękna vs brzydka"]}', '2', NULL, '{historical_literary,closed_single,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Prus kontrastuje Izabelę (emocjonalnie niedostępna, egoistyczna) z Heleną (życzliwa, zaradna, troskliwa o rodzinę)."}', '2025-10-24 22:16:54.73', '2025-10-24 22:16:54.73', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3000x0qhd9gpk4bwth', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 3, 'Jak zakończył się prawdopodobnie los Wokulskiego?', '{"options": ["ożenił się z Izabelą", "wyjechał na stałe do Paryża", "prawdopodobnie popełnił samobójstwo wysadzając zamek w Zasławiu", "został naukowcem u Geista"]}', '2', NULL, '{historical_literary,closed_single,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Zakończenie jest otwarte, ale sugeruje samobójstwo - Węgiełek pisze o wybuchu na zamku i umieszcza krzyż z napisem Non omnis moriar."}', '2025-10-24 22:16:54.732', '2025-10-24 22:16:54.732', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evair013mqhd9mgbcewla', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 1, 'Jaki jest główny temat tragedii „Makbet”?', '{"options": ["miłość romantyczna", "destrukcyjna siła ambicji", "wojna między krajami", "konflikt religijny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,renaissance,batch-2025-01}', '{"explanation": "Głównym tematem jest niszczycielska siła niepohamowanej ambicji."}', '2025-10-24 22:16:55.3', '2025-10-24 22:16:55.3', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3200x1qhd9telg41r5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 3, 'Co symbolizuje porównanie Warszawy i Paryża w powieści?', '{"options": ["obie są równie piękne", "Paryż ma plan i logikę, Warszawa jest chaotyczna i zaniedbana", "Warszawa jest lepsza od Paryża", "obie są równie chaotyczne"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Paryż przedstawiony jest jako uporządkowane miasto z planem urbanistycznym, podczas gdy Warszawa (zwłaszcza Powiśle) jest chaotyczna i zaniedbana."}', '2025-10-24 22:16:54.734', '2025-10-24 22:16:54.734', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3400x2qhd9iswsdqcj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 3, 'Jaki topos literacki Prus wykorzystuje w symbolice lalki i scenie z nakręcanymi zabawkami?', '{"options": ["locus amoenus", "carpe diem", "theatrum mundi", "vanitas"]}', '2', NULL, '{historical_literary,closed_single,difficulty-5,positivism,batch-2025-01}', '{"explanation": "Prus wykorzystuje topos theatrum mundi - świat jako teatr, a ludzie jako marionetki kierowane przez los i konwenanse społeczne."}', '2025-10-24 22:16:54.736', '2025-10-24 22:16:54.736', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3600x3qhd9l3h4bmzu', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Które cechy charakteryzują Stanisława Wokulskiego? (wybierz wszystkie poprawne)', '{"options": ["zakochany idealista", "cyniczny kapitalista", "były uczestnik powstania styczniowego", "zainteresowany nauką i postępem", "arystokrata z urodzenia"]}', '[0, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Wokulski to zakochany idealista, uczestnik powstania styczniowego i człowiek zainteresowany nauką. Nie jest cynikiem ani arystokratą."}', '2025-10-24 22:16:54.739', '2025-10-24 22:16:54.739', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3900x4qhd9mku0o5ck', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Które motywy literackie pojawiają się w Lalce? (wybierz wszystkie poprawne)', '{"options": ["motyw miłości romantycznej", "motyw miasta", "motyw nauki i postępu", "motyw przyrody", "motyw lalki/marionetki", "motyw biedy społecznej"]}', '[0, 1, 2, 4, 5]', NULL, '{historical_literary,closed_multiple,difficulty-3,positivism,batch-2025-01}', '{"explanation": "W Lalce pojawiają się motywy: miłości, miasta (Warszawa vs Paryż), nauki, lalki/marionetki i biedy. Motyw przyrody nie jest istotny."}', '2025-10-24 22:16:54.741', '2025-10-24 22:16:54.741', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3b00x5qhd9rvtr1zp7', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Dopasuj postaci do ich charakterystyki.', '{"leftColumn": [{"id": "A", "text": "Stanisław Wokulski"}, {"id": "B", "text": "Ignacy Rzecki"}, {"id": "C", "text": "Julian Ochocki"}], "rightColumn": [{"id": 1, "text": "romantyczny bonapartysta, samotnik"}, {"id": 2, "text": "idealista naukowy, młody wynalazca"}, {"id": 3, "text": "kupiec zakochany w arystokratce"}], "matchingType": "character_traits"}', '[[0, 2], [1, 0], [2, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Wokulski - kupiec zakochany w Izabeli, Rzecki - bonapartysta i samotnik, Ochocki - młody naukowiec."}', '2025-10-24 22:16:54.743', '2025-10-24 22:16:54.743', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3d00x6qhd9emsm5ih4', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 3, 'Uzupełnij analizę symboliki w Lalce.', '{"gaps": [{"id": 1, "options": ["sztuczność i pustkę emocjonalną", "piękno", "bogactwo", "mądrość"]}, {"id": 2, "options": ["locus amoenus", "carpe diem", "theatrum mundi", "vanitas"]}, {"id": 3, "options": ["pojedynkiem", "nakręcanymi zabawkami u Rzeckiego", "balem", "procesem"]}], "textWithGaps": "W powieści Lalka tytuł ma wielowymiarowe znaczenie. Lalka symbolizuje [1], co odnosi się do postaci Izabeli. Ponadto motyw lalki/marionetki wiąże się z toposem [2], co pokazuje scena z [3]."}', '[0, 2, 1]', NULL, '{historical_literary,closed_multiple,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Lalka symbolizuje sztuczność (jak Izabela), wiąże się z toposem theatrum mundi, ilustrowanym sceną z zabawkami."}', '2025-10-24 22:16:54.746', '2025-10-24 22:16:54.746', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3g00x7qhd9exry567c', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Dopasuj działania Wokulskiego do motywacji, która za nimi stała.', '{"leftColumn": [{"id": "A", "text": "Kupno kamienicy Łęckich za wygórowaną cenę"}, {"id": "B", "text": "Nauka języka angielskiego"}, {"id": "C", "text": "Organizacja aplauzu dla Rossiego"}, {"id": "D", "text": "Wyjazd do Bułgarii na wojnę"}], "rightColumn": [{"id": 1, "text": "aby spodobać się Izabeli, która mówiła po angielsku"}, {"id": 2, "text": "aby spełnić prośbę Izabeli i ją zadowolić"}, {"id": 3, "text": "aby pomóc finansowo rodzinie Łęckich"}, {"id": 4, "text": "aby zarobić majątek potrzebny do zdobycia Izabeli"}], "matchingType": "actions_motivations"}', '[[0, 2], [1, 0], [2, 1], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Wszystkie działania Wokulskiego podporządkowane były miłości do Izabeli: pomoc finansowa, nauka angielskiego, spełnianie próśb, zarabianie majątku."}', '2025-10-24 22:16:54.748', '2025-10-24 22:16:54.748', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3i00x8qhd921khgu7h', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Które zdania dotyczące Lalki są prawdziwe? (wybierz wszystkie poprawne)', '{"options": ["Akcja toczy się w latach 1878-1879", "Prus zastosował technikę dwugłosu narracyjnego", "Wokulski jest arystokratą", "Izabela jest przedstawiona jako ideał kobiety", "Powieść krytykuje wszystkie warstwy społeczne"]}', '[0, 1, 4]', NULL, '{historical_literary,closed_multiple,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Prawdziwe: akcja w latach 1878-79, dwugłos narracyjny, krytyka wszystkich warstw. Fałszywe: Wokulski to kupiec, Izabela to krytykowana lalka."}', '2025-10-24 22:16:54.75', '2025-10-24 22:16:54.75', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3k00x9qhd957qr1tfj', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 4, 'Dopasuj fragmenty tekstu do ich funkcji w kompozycji powieści.', '{"leftColumn": [{"id": "A", "text": "Pamiętnik starego subiekta"}, {"id": "B", "text": "Opis Powiśla"}, {"id": "C", "text": "Scena nakręcania zabawek przez Rzeckiego"}, {"id": "D", "text": "Wizyta Wokulskiego u Geista w Paryżu"}], "rightColumn": [{"id": 1, "text": "ilustracja toposu theatrum mundi i kompozycja klamrowa"}, {"id": 2, "text": "subiektywny głos narratora-bohatera"}, {"id": 3, "text": "motyw nauki i idealizmu pozytywistycznego"}, {"id": 4, "text": "naturalistyczny obraz biedy i nierówności społecznych"}], "matchingType": "text_function"}', '[[0, 1], [1, 3], [2, 0], [3, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-5,positivism,batch-2025-01}', '{"explanation": "Pamiętnik = subiektywny głos, Powiśle = bieda, zabawki = theatrum mundi (klamra kompozycyjna), Geist = motyw nauki."}', '2025-10-24 22:16:54.753', '2025-10-24 22:16:54.753', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3n00xaqhd9n0ok5uie', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Wyjaśnij, dlaczego Stanisław Wokulski wyjechał do Bułgarii.', '{"instruction": "Podaj powód wyjazdu Wokulskiego do Bułgarii i wyjaśnij, co chciał osiągnąć. (30-50 słów)"}', NULL, '{"criteria": ["wskazanie, że wyjechał zarobić majątek (1 pkt)", "wyjaśnienie, że chciał zdobyć Izabelę Łęcką (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"keyWords": ["majątek", "wojna", "Izabela", "zakochany"], "expectedAnswer": "Wokulski wyjechał do Bułgarii podczas wojny turecko-rosyjskiej, aby zarobić majątek na dostawach broni. Wszystko robił, żeby zdobyć środki potrzebne do zdobycia serca Izabeli Łęckiej, w której był zakochany bez pamięci."}', '2025-10-24 22:16:54.755', '2025-10-24 22:16:54.755', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3p00xbqhd99rvn1ud4', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Wyjaśnij znaczenie tytułu Lalka.', '{"instruction": "Przedstaw co najmniej dwa znaczenia tytułu powieści. (50-80 słów)"}', NULL, '{"criteria": ["odniesienie do Izabeli jako lalki salonowej (1 pkt)", "wspomnienie procesu o lalkę między Stawską a Krzeszowską (1 pkt)", "topos theatrum mundi - ludzie jako marionetki (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-3,positivism,batch-2025-01}', '{"keyWords": ["Izabela", "proces", "theatrum mundi", "marionetka", "sztuczność"], "expectedAnswer": "Tytuł ma wielowymiarowe znaczenie: po pierwsze odnosi się do Izabeli Łęckiej jako lalki salonowej - pięknej, ale pustej emocjonalnie. Po drugie nawiązuje do procesu sądowego o lalkę między panią Stawską a baronową. Po trzecie symbolizuje topos theatrum mundi - ludzi jako marionetki kierowane przez społeczeństwo i los."}', '2025-10-24 22:16:54.758', '2025-10-24 22:16:54.758', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3r00xcqhd9pq3k5kay', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Scharakteryzuj postać Ignacego Rzeckiego.', '{"instruction": "Opisz osobowość i poglądy Ignacego Rzeckiego w 3-5 zdaniach. (50-80 słów)"}', NULL, '{"criteria": ["wskazanie, że to subiekt i przyjaciel Wokulskiego (1 pkt)", "określenie jako bonapartysta, idealista romantyczny (1 pkt)", "opis jako samotnik prowadzący pamiętnik (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-3,positivism,batch-2025-01}', '{"keyWords": ["subiekt", "bonapartysta", "Napoleon", "samotnik", "pamiętnik", "romantyk"], "expectedAnswer": "Ignacy Rzecki to stary subiekt, najbliższy przyjaciel Wokulskiego. Jest zagorzałym bonapartystą i romantycznym idealistą, który uwielbia Napoleona. Prowadzi samotnicze życie, mieszka w ciemnym pokoju i pisze pamiętnik, w którym wyraża swoje emocje. Reprezentuje starsze pokolenie romantyków."}', '2025-10-24 22:16:54.76', '2025-10-24 22:16:54.76', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3u00xdqhd98tufjebr', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Porównaj postawy Stanisława Wokulskiego i Juliana Ochockiego wobec nauki.', '{"instruction": "Opisz, jak obaj bohaterowie podchodzą do nauki i postępu. Wskaż różnice. (80-120 słów)"}', NULL, '{"criteria": ["opis zainteresowań naukowych Wokulskiego (1 pkt)", "opis pasji Ochockiego do wynalazków (1 pkt)", "wskazanie, że Wokulski zrezygnował z nauki dla Izabeli (1 pkt)", "kontrast: Ochocki całkowicie oddany nauce (1 pkt)"], "maxScore": 4}', '{historical_literary,short_answer,difficulty-4,positivism,batch-2025-01}', '{"keyWords": ["Wokulski", "Ochocki", "nauka", "rezygnacja", "Izabela", "wynalazki", "idealizm"], "expectedAnswer": "Wokulski w młodości studiował na Szkole Głównej i interesował się mechaniką. Później jednak zrezygnował z kariery naukowej dla miłości do Izabeli. Ochocki natomiast reprezentuje młode pokolenie pozytywistów - całkowicie poświęcił się nauce i wynalazkom. Marzył o maszynie latającej i dla nauki odmówił małżeństwa. Wokulski zapisał mu część majątku na badania."}', '2025-10-24 22:16:54.762', '2025-10-24 22:16:54.762', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3w00xeqhd9yg11vapn', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Wyjaśnij, jak Prus przedstawia kontrast między Warszawą a Paryżem.', '{"instruction": "Opisz różnice między oboma miastami w powieści i wyjaśnij, co one symbolizują. (100-150 słów)"}', NULL, '{"criteria": ["opis Warszawy jako chaotycznej i zaniedbanej (1 pkt)", "opis Paryża jako uporządkowanego i logicznego (1 pkt)", "wspomnienie o Powiślu jako symbolu biedy (1 pkt)", "interpretacja symboliczna (Polska vs Europa) (1 pkt)"], "maxScore": 4}', '{historical_literary,short_answer,difficulty-4,positivism,batch-2025-01}', '{"keyWords": ["Warszawa", "Paryż", "chaos", "porządek", "Powiśle", "plan", "kontrast"], "expectedAnswer": "Prus przedstawia ostry kontrast: Warszawa jest chaotyczna, brudna i pozbawiona planu urbanistycznego. Szczególnie Powiśle symbolizuje biedę i zaniedbanie. Paryż natomiast ma logiczny plan, jest uporządkowany, daje możliwości rozwoju. Wokulski zauważa, że Paryż to miasto pracy, nauki i postępu. Kontrast symbolizuje różnicę między zacofaną Polską a rozwiniętą Europą Zachodnią, co wpisuje się w pozytywistyczną krytykę polskiej rzeczywistości."}', '2025-10-24 22:16:54.765', '2025-10-24 22:16:54.765', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva3z00xfqhd9swtlczt8', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 4, 'Rozwiń wypowiedź na temat otwartego zakończenia Lalki.', '{"hints": ["Non omnis moriar", "wybuch w zamku", "Węgiełek"], "instruction": "Wyjaśnij, na czym polega otwarte zakończenie powieści i jakie są możliwe interpretacje losu Wokulskiego. (120-150 słów)"}', NULL, '{"criteria": ["wskazanie, że zakończenie jest niejednoznaczne (1 pkt)", "interpretacja sugerująca samobójstwo (wybuch) (1 pkt)", "wskazanie innych możliwości (ucieczka, nowe życie) (1 pkt)", "odniesienie do cytatu Non omnis moriar (1 pkt)"], "maxScore": 4}', '{historical_literary,short_answer,difficulty-5,positivism,batch-2025-01}', '{"keyWords": ["otwarte", "samobójstwo", "Zasławie", "Non omnis moriar", "interpretacja", "idealiści"], "expectedAnswer": "Zakończenie Lalki jest otwarte i niejednoznaczne. List Węgiełka sugeruje, że Wokulski prawdopodobnie popełnił samobójstwo, wysadzając zamek w Zasławiu. Świadczy o tym krzyż z napisem Non omnis moriar (nie wszystek umrę). Jednak brak zwłok pozwala na inne interpretacje - może uciekł i zaczął nowe życie. Prus celowo nie stawia kropki nad i, dając czytelnikowi przestrzeń do własnej interpretacji i refleksji nad losem idealistów w społeczeństwie."}', '2025-10-24 22:16:54.767', '2025-10-24 22:16:54.767', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4100xgqhd9f4250qoe', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 6, 'Napisz notatkę syntetyzującą o głównych motywach w Lalce.', '{"topic": "Najważniejsze motywy literackie w Lalce Bolesława Prusa", "requirements": ["motyw miłości (romantycznej)", "motyw lalki/marionetki", "motyw miasta", "motyw nauki i postępu", "krótka charakterystyka każdego motywu", "150-200 słów"]}', NULL, '{"criteria": ["wymienienie i omówienie motywu miłości (1,5 pkt)", "wymienienie i omówienie motywu lalki (1,5 pkt)", "wymienienie i omówienie motywu miasta (1,5 pkt)", "wymienienie i omówienie motywu nauki (1,5 pkt)"], "maxScore": 6}', '{historical_literary,synthesis_note,difficulty-3,positivism,batch-2025-01}', NULL, '2025-10-24 22:16:54.77', '2025-10-24 22:16:54.77', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4400xhqhd9rz085sxd', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 7, 'Porównaj dwie kobiece postacie w Lalce.', '{"topic": "Kontrast między Izabelą Łęcką a Heleną Stawską w Lalce", "requirements": ["charakterystyka Izabeli (cechy, postawa)", "charakterystyka Heleny (cechy, postawa)", "wskazanie głównych różnic", "interpretacja: co symbolizuje ten kontrast", "200-250 słów"]}', NULL, '{"criteria": ["charakterystyka Izabeli (2 pkt)", "charakterystyka Heleny (2 pkt)", "wskazanie różnic (2 pkt)", "interpretacja symboliczna (1 pkt)"], "maxScore": 7}', '{historical_literary,synthesis_note,difficulty-4,positivism,batch-2025-01}', NULL, '2025-10-24 22:16:54.772', '2025-10-24 22:16:54.772', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4600xiqhd9vgyskcc2', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 7, 'Omów technikę narracyjną w Lalce.', '{"topic": "Dwugłos narracyjny w Lalce Bolesława Prusa", "requirements": ["narrator trzecioosobowy - charakterystyka", "pamiętnik Rzeckiego - charakterystyka", "funkcja każdego typu narracji", "efekt artystyczny dwugłosu", "180-220 słów"]}', NULL, '{"criteria": ["omówienie narratora trzecioosobowego (2 pkt)", "omówienie pamiętnika Rzeckiego (2 pkt)", "funkcje obu typów narracji (2 pkt)", "efekt artystyczny (1 pkt)"], "maxScore": 7}', '{historical_literary,synthesis_note,difficulty-4,positivism,batch-2025-01}', NULL, '2025-10-24 22:16:54.774', '2025-10-24 22:16:54.774', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4800xjqhd982jkjf17', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 8, 'Scharakteryzuj Lalkę jako powieść pozytywistyczną.', '{"topic": "Cechy pozytywizmu w Lalce Bolesława Prusa", "requirements": ["realizm krytyczny - przykłady", "scjentyzm (kult nauki) - postacie", "krytyka społeczna - które warstwy", "praca organiczna - czy jest realizowana", "idealiści a społeczny rozkład", "250-300 słów"]}', NULL, '{"criteria": ["realizm krytyczny (2 pkt)", "scjentyzm (2 pkt)", "krytyka społeczna (2 pkt)", "idealiści vs rzeczywistość (2 pkt)"], "maxScore": 8}', '{historical_literary,synthesis_note,difficulty-5,positivism,batch-2025-01}', NULL, '2025-10-24 22:16:54.777', '2025-10-24 22:16:54.777', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4b00xkqhd9xmh8k9m4', 'ESSAY', 'WRITING', 'POSITIVISM', 5, 15, 'Napisz rozprawkę na temat: Miłość – siła motywująca czy destrukcyjna? Omów zagadnienie na podstawie Lalki Bolesława Prusa.', '{"thesis": "Miłość – siła motywująca czy destrukcyjna? Omów na podstawie Lalki", "structure": {"conclusion": "Podsumowanie i synteza - miłość jako siła ambiwalentna", "introduction": "Wprowadzenie z tezą i zapowiedzią argumentów", "arguments_for": "Argumenty za tym, że miłość motywuje Wokulskiego (zarabianie majątku, pomoc innym, rozwój)", "arguments_against": "Argumenty za tym, że miłość destruuje Wokulskiego (zaślepienie, rezygnacja z nauki, samobójstwo)"}, "wordLimit": {"max": 400, "min": 300}, "requirements": ["struktura: wstęp - rozwinięcie - zakończenie", "argumenty z Lalki", "odniesienie do losów Wokulskiego", "kontekst pozytywistyczny", "300-400 słów"]}', NULL, '{"criteria": {"formal": "Zachowanie wymogów formalnych (objętość, struktura)", "language": "Poprawność językowa, styl, precyzja wypowiedzi", "literary": "Znajomość lektury, trafność argumentów, kontekst epoki", "composition": "Logika wywodu, spójność kompozycyjna, teza"}, "maxScore": 15, "formalScore": 1, "languageScore": 3, "literaryScore": 8, "compositionScore": 3}', '{writing,essay,difficulty-5,positivism,batch-2025-01}', NULL, '2025-10-24 22:16:54.779', '2025-10-24 22:16:54.779', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4d00xlqhd93n6fjw6b', 'ESSAY', 'WRITING', 'POSITIVISM', 5, 15, 'Napisz rozprawkę: Czy idealiści mogą być szczęśliwi w świecie przedstawionym Lalki?', '{"thesis": "Czy idealiści mogą być szczęśliwi w świecie przedstawionym Lalki?", "structure": {"conclusion": "Wnioski: w świecie Lalki idealiści są skazani na porażkę", "introduction": "Wprowadzenie - kim są idealiści w Lalce", "arguments_for": "Argumenty: Wokulski (miłość vs realizm), Rzecki (bonapartyzm vs rzeczywistość), Ochocki (nauka vs emigracja)", "arguments_against": "Klęska idealistów - Prus pokazuje, że społeczeństwo ich odtrąca"}, "wordLimit": {"max": 450, "min": 350}, "requirements": ["analiza losów trzech idealistów", "odniesienie do tytułu (idealiści na tle rozkładu)", "kontekst pozytywizmu", "350-450 słów"]}', NULL, '{"maxScore": 15, "formalScore": 1, "languageScore": 3, "literaryScore": 8, "compositionScore": 3}', '{writing,essay,difficulty-5,positivism,batch-2025-01}', NULL, '2025-10-24 22:16:54.782', '2025-10-24 22:16:54.782', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4g00xmqhd9e634vn73', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kto zapisał Wokulskiemu znaczną część swojego majątku na badania naukowe?', '{"options": ["Ignacy Rzecki", "Julian Ochocki", "doktor Szuman", "Wokulski sam sobie zapisał"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "To właśnie Wokulski zapisał Ochockiemu dużą część majątku, aby mógł kontynuować badania naukowe nad maszyną latającą."}', '2025-10-24 22:16:54.784', '2025-10-24 22:16:54.784', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4i00xnqhd99uvjtom0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Jaki proces sądowy miał inspirację w rzeczywistej historii przeczytanej przez Prusa?', '{"options": ["proces o kamienicę", "proces o lalkę między Stawską a Krzeszowską", "proces o sklep", "proces o dziedzictwo"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Prus przeczytał w gazecie o procesie za kradzież lalki, co zainspirowało go do zmiany tytułu z Trzy pokolenia na Lalka i wprowadzenia tego wątku."}', '2025-10-24 22:16:54.786', '2025-10-24 22:16:54.786', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4l00xoqhd94ofcm9dm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Za co został zesłany na Syberię Stanisław Wokulski?', '{"options": ["za kradzież", "za udział w powstaniu styczniowym", "za handel bronią", "za działalność naukową"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Wokulski został zesłany na Syberię do Irkucka za wzięcie udziału w powstaniu styczniowym."}', '2025-10-24 22:16:54.789', '2025-10-24 22:16:54.789', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4n00xpqhd9kcq0mjhg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Czym charakteryzuje się dzielnica Powiśle w Lalce?', '{"options": ["luksusowymi rezydencjami arystokracji", "dobrze zagospodarowanymi bulwarami", "biedą, brudem i chaosem urbanistycznym", "rozwiniętym przemysłem"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Powiśle przedstawione jest jako symbol biedy, zaniedbania i braku planu urbanistycznego - naturalistyczny obraz nędzy warszawskiej."}', '2025-10-24 22:16:54.791', '2025-10-24 22:16:54.791', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4p00xqqhd90g5rplzn', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 2, 'Z kim Wokulski spotyka się w Paryżu i kto reprezentuje ideał naukowca-wynalazcy?', '{"options": ["z Suzinem - rosyjskim kupcem", "z profesorem Geistem - genialnym chemikiem", "z Rossim - włoskim aktorem", "z Ochockim - polskim wynalazcą"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Profesor Geist to genialny chemik pracujący nad metalem lżejszym od powietrza, uznawany przez otoczenie za dziwaka, reprezentuje ideał naukowca oddanego ludzkości."}', '2025-10-24 22:16:54.794', '2025-10-24 22:16:54.794', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4s00xrqhd98viqfptj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Dlaczego Wokulski organizuje aplauz dla włoskiego tragika Rossiego?', '{"options": ["bo sam uwielbia teatr włoski", "aby spełnić prośbę Izabeli i ją zadowolić", "bo jest przyjacielem Rossiego", "aby zarobić na przedsięwzięciu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Izabela zachwycała się Rossim i Wokulski zorganizował owacje, aby jej sprawić przyjemność - wszystkie jego działania podporządkowane były zdobyciu jej serca."}', '2025-10-24 22:16:54.796', '2025-10-24 22:16:54.796', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4u00xsqhd97kfbx0x9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 3, 'Co oznacza łaciński napis Non omnis moriar umieszczony przez Węgiełka na krzyżu?', '{"options": ["tutaj spoczywam", "nie wszystek umrę", "pamiętaj o śmierci", "zawsze wierny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Non omnis moriar to cytat z Horacego oznaczający nie wszystek umrę - symbol nieśmiertelności duchowej, nawet jeśli ciało ginie."}', '2025-10-24 22:16:54.798', '2025-10-24 22:16:54.798', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4w00xtqhd92hwaj6gy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 3, 'Jaką rolę pełni scena, w której Rzecki nakręca mechaniczne zabawki w sklepie?', '{"options": ["ilustruje jego pracę jako subiekta", "wprowadza wątek zabaw dziecięcych", "symbolizuje topos theatrum mundi i tworzy klamrę kompozycyjną", "pokazuje nowoczesną technologię"]}', '2', NULL, '{historical_literary,closed_single,difficulty-5,positivism,batch-2025-01}', '{"explanation": "Scena z zabawkami otwiera i kończy powieść (klamra), symbolizując topos theatrum mundi - ludzie jako marionetki kierowane przez los."}', '2025-10-24 22:16:54.8', '2025-10-24 22:16:54.8', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva4y00xuqhd99ybzhs7i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 2, 'Dlaczego Wokulski nie mógł zostać uczonym po powrocie z Syberii?', '{"options": ["nie miał zdolności", "wolał być kupcem", "naukowcy widzieli w nim byłego subiekta, a kupcy - naukowca", "zabroniono mu uprawiania nauki"]}', '2', NULL, '{historical_literary,closed_single,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Wokulski nie został zaakceptowany ani przez świat nauki (widzieli w nim kupca), ani przez świat handlu (widzieli w nim naukowca) - symbolizuje to jego pozycję pomiędzy i niezrozumienie idealistów."}', '2025-10-24 22:16:54.803', '2025-10-24 22:16:54.803', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5100xvqhd9xybdn25i', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 3, 'Dopasuj cytaty do postaci, które je wypowiadają lub których dotyczą.', '{"leftColumn": [{"id": "A", "text": "Świat to teatr, a ludzie to marionetki"}, {"id": "B", "text": "„Lalka bezmyślna, irytująca, budząca zazdrość"}, {"id": "C", "text": "Non omnis moriar"}], "rightColumn": [{"id": 1, "text": "refleksje Rzeckiego o istocie życia"}, {"id": 2, "text": "cytat na krzyżu dla Wokulskiego"}, {"id": 3, "text": "opinia o Izabeli Łęckiej"}], "matchingType": "quotes_characters"}', '[[0, 0], [1, 2], [2, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Rzecki mówi o theatrum mundi, Izabela opisywana jako lalka, krzyż z cytatem Horacego dla Wokulskiego."}', '2025-10-24 22:16:54.805', '2025-10-24 22:16:54.805', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5300xwqhd9i2nwytul', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Jak nazywa się najbliższy przyjaciel Stanisława Wokulskiego?', '{"options": ["Julian Ochocki", "Ignacy Rzecki", "doktor Szuman", "Tomasz Łęcki"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Ignacy Rzecki to najbliższy przyjaciel Wokulskiego, stary subiekt prowadzący sklep i pamiętnik."}', '2025-10-24 22:16:54.807', '2025-10-24 22:16:54.807', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5500xxqhd90hqcf6a6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Jak długo Ignacy Rzecki mieszkał w pokoju przy sklepie?', '{"options": ["10 lat", "25 lat", "5 lat", "50 lat"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Rzecki od 25 lat mieszkał w ciemnym pokoju przy sklepie, który był jego całym światem."}', '2025-10-24 22:16:54.81', '2025-10-24 22:16:54.81', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5700xyqhd9rl3wn0mq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Z kim Wokulski wziął ślub dla pieniędzy?', '{"options": ["z Izabelą Łęcką", "z Heleną Stawską", "z Małgorzatą Minclową", "z panią Wąsowską"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Wokulski poślubił wdowę po Janie Minclu - Małgorzatę, dziedzicząc po niej sklep i trzydzieści tysięcy rubli."}', '2025-10-24 22:16:54.812', '2025-10-24 22:16:54.812', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5900xzqhd9zweo238p', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Jak nazywa się ojciec Izabeli Łęckiej?', '{"options": ["Julian Łęcki", "Stanisław Łęcki", "Tomasz Łęcki", "Kazimierz Łęcki"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Tomasz Łęcki to ojciec Izabeli, zubożały arystokrata, który stracił majątek."}', '2025-10-24 22:16:54.814', '2025-10-24 22:16:54.814', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5c00y0qhd9fxnftjok', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Gdzie Wokulski uczęszczał na wykłady jako wolny słuchacz?', '{"options": ["na Uniwersytecie Jagiellońskim", "w Szkole Głównej", "na Uniwersytecie Warszawskim", "w Akademii Medycznej"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Po rzuceniu pracy u Hopfera, Wokulski uczęszczał na wykłady w Szkole Głównej jako wolny słuchacz."}', '2025-10-24 22:16:54.816', '2025-10-24 22:16:54.816', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5e00y1qhd9uszmy793', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kto uratował życie Wokulskiego podczas próby samobójstwa?', '{"options": ["Ignacy Rzecki", "Julian Ochocki", "brat Wysockiego - dróżnik", "Tomasz Łęcki"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "W Skierniewicach życie Wokulskiego uratował dróżnik - brat Wysockiego, któremu Stanisław wcześniej pomógł."}', '2025-10-24 22:16:54.818', '2025-10-24 22:16:54.818', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5g00y2qhd907zz8hnr', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Jak nazywa się warszawska dzielnica biedy opisana w powieści?', '{"options": ["Praga", "Powiśle", "Wola", "Mokotów"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Powiśle to dzielnica nad Wisłą, symbol biedy, brudu i zaniedbania w ówczesnej Warszawie."}', '2025-10-24 22:16:54.82', '2025-10-24 22:16:54.82', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5i00y3qhd9y4twuhxv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Kto prowadził pamiętnik w powieści?', '{"options": ["Stanisław Wokulski", "Ignacy Rzecki", "Izabela Łęcka", "doktor Szuman"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Ignacy Rzecki prowadził „Pamiętnik starego subiekta”, w którym zapisywał swoje myśli i emocje."}', '2025-10-24 22:16:54.822', '2025-10-24 22:16:54.822', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5k00y4qhd96jl5l5oa', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kim był Suzin w życiu Wokulskiego?', '{"options": ["jego wrogiem", "rosyjskim kupcem i wspólnikiem", "przyjacielem z dzieciństwa", "nauczycielem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Suzin to rosyjski kupiec, wspólnik Wokulskiego, który pomógł mu zarobić majątek na wojnie."}', '2025-10-24 22:16:54.824', '2025-10-24 22:16:54.824', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5m00y5qhd9lbswcyef', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Co Wokulski kupił dla rodziny Łęckich za wygórowaną cenę?', '{"options": ["powóz", "kamienicę", "sklep", "pałac"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Wokulski kupił kamienicę Łęckich za 90 tysięcy rubli, choć była warta 70 tysięcy, aby pomóc finansowo rodzinie Izabeli."}', '2025-10-24 22:16:54.827', '2025-10-24 22:16:54.827', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5p00y6qhd9vcq444qj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Z jakiej rodziny pochodził Stanisław Wokulski?', '{"options": ["z bogatej rodziny kupieckiej", "ze zubożałej rodziny szlacheckiej", "z rodziny chłopskiej", "z rodziny arystokratycznej"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Wokulski pochodził ze zubożałej rodziny szlacheckiej, a jego ojciec ciągle procesował się o majątek."}', '2025-10-24 22:16:54.829', '2025-10-24 22:16:54.829', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5r00y7qhd9uyvvycwz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kim była Helena Stawska w powieści?', '{"options": ["arystokratką", "biedną wdową pracującą jako nauczycielka", "prostytutką", "służącą"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Helena Stawska to biedna wdowa, która utrzymywała się z korepetycji i nauczania gry na fortepianie oraz angielskiego."}', '2025-10-24 22:16:54.831', '2025-10-24 22:16:54.831', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5t00y8qhd9hsh6hewy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kim był Maruszewicz w powieści?', '{"options": ["uczciwym kupcem", "zdeklasowanym szlachcicem i oszustem", "lekarzem", "naukowcem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Maruszewicz to zdeklasowany szlachcic i oszust, który wyłudzał pieniądze od różnych osób, w tym od Wokulskiego."}', '2025-10-24 22:16:54.834', '2025-10-24 22:16:54.834', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5v00y9qhd920vikuju', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'W jakich latach toczy się akcja główna „Lalki”?', '{"options": ["1870-1871", "1878-1879", "1880-1881", "1863-1864"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Akcja główna powieści toczy się w latach 1878-1879 w Warszawie."}', '2025-10-24 22:16:54.836', '2025-10-24 22:16:54.836', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva5y00yaqhd92e8johma', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Gdzie Wokulski spotkał profesora Geista?', '{"options": ["w Warszawie", "w Paryżu", "w Berlinie", "w Moskwie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Wokulski poznał profesora Geista - genialnego chemika - podczas pobytu w Paryżu."}', '2025-10-24 22:16:54.838', '2025-10-24 22:16:54.838', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6000ybqhd9k4zapgb8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Co łączyło Rzeckiego z Wokulskim?', '{"options": ["byli braćmi", "głęboka przyjaźń", "rywalizacja", "tylko relacja pracownik-pracodawca"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Rzeckiego i Wokulskiego łączyła głęboka przyjaźń - Rzecki był najbliższym przyjacielem Stanisława."}', '2025-10-24 22:16:54.84', '2025-10-24 22:16:54.84', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6200ycqhd9gft1rfjo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Jaki interes prowadził Wokulski?', '{"options": ["sklep z bronią", "sklep galanteryjny", "fabrykę", "jadłodajnię"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Wokulski prowadził sklep galanteryjny odziedziczony po Minclowej."}', '2025-10-24 22:16:54.842', '2025-10-24 22:16:54.842', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6400ydqhd9wm9kbvig', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kto był żydowskim przyjacielem i lekarzem Wokulskiego?', '{"options": ["Szlangbaum", "doktor Szuman", "Suzin", "Geist"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Doktor Szuman to żydowski lekarz i naukowiec, przyjaciel Wokulskiego, który traktował biednych za darmo."}', '2025-10-24 22:16:54.844', '2025-10-24 22:16:54.844', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6600yeqhd9o6r98og7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kto kupił sklep Wokulskiego?', '{"options": ["Rzecki", "młody Szlangbaum", "baron Krzeszowski", "Ochocki"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Sklep Wokulskiego kupił młody Szlangbaum - syn starego Szlangbauma."}', '2025-10-24 22:16:54.847', '2025-10-24 22:16:54.847', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6800yfqhd973i6lrmb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Gdzie Wokulski poznał Izabelę Łęcką?', '{"options": ["w swoim sklepie", "w teatrze", "w kościele", "na balu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Wokulski po raz pierwszy zobaczył Izabelę w teatrze podczas spektaklu „Violetta” i zakochał się w niej od pierwszego wejrzenia."}', '2025-10-24 22:16:54.849', '2025-10-24 22:16:54.849', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6b00ygqhd9fl0mosli', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Dopasuj postaci z „Lalki” do ich głównych cech charakteru.', '{"leftColumn": [{"id": "A", "text": "Tomasz Łęcki"}, {"id": "B", "text": "Helena Stawska"}, {"id": "C", "text": "Maruszewicz"}, {"id": "D", "text": "doktor Szuman"}], "rightColumn": [{"id": 1, "text": "życzliwa, zaradna wdowa"}, {"id": 2, "text": "zdeklasowany szlachcic i oszust"}, {"id": 3, "text": "żydowski lekarz i naukowiec"}, {"id": 4, "text": "zubożały arystokrata"}], "matchingType": "character_traits"}', '[[0, 3], [1, 0], [2, 1], [3, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Tomasz Łęcki - zubożały arystokrata, Helena - życzliwa wdowa, Maruszewicz - oszust, Szuman - lekarz."}', '2025-10-24 22:16:54.851', '2025-10-24 22:16:54.851', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6e00yhqhd9jh8qwso7', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Które cechy charakteryzują Ignacego Rzeckiego? (wybierz wszystkie poprawne)', '{"options": ["bonapartysta", "samotnik", "prowadzi pamiętnik", "bogaty arystokrata", "subiekt w sklepie"]}', '[0, 1, 2, 4]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Rzecki to bonapartysta, samotnik prowadzący pamiętnik i pracujący jako stary subiekt. Nie jest arystokratą."}', '2025-10-24 22:16:54.855', '2025-10-24 22:16:54.855', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6h00yiqhd90qq3f7fe', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Uzupełnij informacje o życiu Wokulskiego.', '{"gaps": [{"id": 1, "options": ["bogatej", "zubożałej", "arystokratycznej", "chłopskiej"]}, {"id": 2, "options": ["Uniwersytetu", "Szkoły Głównej", "Akademii", "liceum"]}, {"id": 3, "options": ["powstaniu styczniowym", "powstaniu listopadowym", "wojnie", "zamachu"]}, {"id": 4, "options": ["Moskwy", "Petersburga", "Irkucka", "Omska"]}], "textWithGaps": "Stanisław Wokulski pochodził ze [1] rodziny szlacheckiej. W młodości uczęszczał do [2], ale został wyrzucony za udział w [3]. Za to zesłano go na Syberię do [4]."}', '[1, 1, 0, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Wokulski pochodził ze zubożałej szlachty, uczęszczał do Szkoły Głównej, brał udział w powstaniu styczniowym i został zesłany do Irkucka."}', '2025-10-24 22:16:54.857', '2025-10-24 22:16:54.857', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6j00yjqhd9nj9ui3jt', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Dopasuj miejsca do wydarzeń, które się w nich rozegrały.', '{"leftColumn": [{"id": "A", "text": "Powiśle"}, {"id": "B", "text": "Paryż"}, {"id": "C", "text": "Skierniewice"}, {"id": "D", "text": "Zasławek"}], "rightColumn": [{"id": 1, "text": "próba samobójstwa Wokulskiego"}, {"id": 2, "text": "spotkanie z profesorem Geistem"}, {"id": 3, "text": "obraz warszawskiej biedy"}, {"id": 4, "text": "posiadłość prezesowej Zasławskiej"}], "matchingType": "places_events"}', '[[0, 2], [1, 1], [2, 0], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Powiśle - bieda, Paryż - Geist, Skierniewice - próba samobójstwa, Zasławek - posiadłość prezesowej."}', '2025-10-24 22:16:54.86', '2025-10-24 22:16:54.86', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6m00ykqhd99zog4pyg', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Które zdania dotyczące Izabeli Łęckiej są prawdziwe? (wybierz wszystkie poprawne)', '{"options": ["jest córką zubożałego arystokraty", "wychowała się w biedzie", "jest inteligentna i wykształcona", "traktuje Wokulskiego instrumentalnie", "pochodzi z rodziny kupieckiej"]}', '[0, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Prawdziwe: Izabela jest córką zubożałego arystokraty Tomasza Łęckiego i traktuje Wokulskiego instrumentalnie. Fałszywe: wychowała się w luksusie, nie jest szczególnie inteligentna, nie pochodzi z rodziny kupieckiej."}', '2025-10-24 22:16:54.862', '2025-10-24 22:16:54.862', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6p00ylqhd9px0s9hzt', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 2, 'Dopasuj postaci do ich zawodów lub zajęć.', '{"leftColumn": [{"id": "A", "text": "Stanisław Wokulski"}, {"id": "B", "text": "Ignacy Rzecki"}, {"id": "C", "text": "Julian Ochocki"}, {"id": "D", "text": "Helena Stawska"}], "rightColumn": [{"id": 1, "text": "nauczycielka, korepetytorka"}, {"id": 2, "text": "subiekt w sklepie"}, {"id": 3, "text": "właściciel sklepu galanteryjnego"}, {"id": 4, "text": "wynalazca, naukowiec"}], "matchingType": "characters_professions"}', '[[0, 2], [1, 1], [2, 3], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Wokulski - właściciel sklepu, Rzecki - subiekt, Ochocki - wynalazca, Helena - nauczycielka."}', '2025-10-24 22:16:54.865', '2025-10-24 22:16:54.865', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6r00ymqhd9lye9e373', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Kim był Ignacy Rzecki i jaka była jego rola w życiu Wokulskiego?', '{"work": "Lalka", "instruction": "Opisz Rzeckiego i jego relację z Wokulskim w 2-3 zdaniach. (30-50 słów)"}', NULL, '{"criteria": ["określenie Rzeckiego jako starego subiekta (1 pkt)", "wskazanie, że był najbliższym przyjacielem Wokulskiego (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"keyWords": ["subiekt", "przyjaciel", "bonapartysta", "pamiętnik"], "expectedAnswer": "Ignacy Rzecki to stary subiekt prowadzący sklep Wokulskiego, jego najbliższy przyjaciel. Był bonapartystą i samotnikiem prowadzącym pamiętnik, w którym zapisywał swoje myśli o życiu i polityce."}', '2025-10-24 22:16:54.867', '2025-10-24 22:16:54.867', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6t00ynqhd9dzt8amxl', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Dlaczego Wokulski poślubił Małgorzatę Minclową?', '{"work": "Lalka", "instruction": "Wyjaśnij powód małżeństwa Wokulskiego z Minclową. (30-50 słów)"}', NULL, '{"criteria": ["wskazanie małżeństwa dla majątku (1 pkt)", "wymienienie, co odziedziczył (sklep, pieniądze) (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"keyWords": ["majątek", "sklep", "pieniądze", "odziedziczył"], "expectedAnswer": "Wokulski poślubił wdowę po Janie Minclu - Małgorzatę - dla pieniędzy. Po jej śmierci odziedziczył sklep galanteryjny i trzydzieści tysięcy rubli, co pozwoliło mu na dalszy rozwój biznesu."}', '2025-10-24 22:16:54.87', '2025-10-24 22:16:54.87', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6w00yoqhd93kf3yjh6', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Kim była Helena Stawska i czym różniła się od Izabeli Łęckiej?', '{"work": "Lalka", "instruction": "Scharakteryzuj Helenę Stawską i wskaż główną różnicę między nią a Izabelą. (40-60 słów)"}', NULL, '{"criteria": ["opis Heleny jako biednej wdowy (1 pkt)", "kontrast: Helena życzliwa vs Izabela egoistyczna (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"keyWords": ["wdowa", "biedna", "życzliwa", "kontrast", "Izabela"], "expectedAnswer": "Helena Stawska to biedna wdowa utrzymująca się z korepetycji i nauczania. W przeciwieństwie do Izabeli była życzliwa, zaradna i opiekuńcza wobec rodziny. Stanowiła pozytywny kontrast dla pustej emocjonalnie Łęckiej."}', '2025-10-24 22:16:54.872', '2025-10-24 22:16:54.872', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva6y00ypqhd9rwp4ys55', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Wyjaśnij, dlaczego Wokulski kupił kamienicę Łęckich za wygórowaną cenę.', '{"work": "Lalka", "instruction": "Podaj powód zakupu kamienicy i cenę, którą zapłacił. (30-50 słów)"}', NULL, '{"criteria": ["wskazanie, że chciał pomóc rodzinie Izabeli (1 pkt)", "podanie, że zapłacił 90 tys. zamiast 70 tys. rubli (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"keyWords": ["90 tysięcy", "pomoc", "Izabela", "wygórowana cena"], "expectedAnswer": "Wokulski kupił kamienicę Łęckich za 90 tysięcy rubli, choć była warta tylko 70 tysięcy. Zrobił to, aby pomóc finansowo rodzinie Izabeli, w której był zakochany, i zbliżyć się do niej."}', '2025-10-24 22:16:54.874', '2025-10-24 22:16:54.874', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva7000yqqhd9h08gt1zf', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Opisz dzielnicę Powiśle w „Lalce”.', '{"work": "Lalka", "instruction": "Wyjaśnij, jak Prus przedstawił Powiśle i co symbolizuje ta dzielnica. (40-60 słów)"}', NULL, '{"criteria": ["opis Powiśla jako biednej dzielnicy (1 pkt)", "wskazanie symboliki biedy i zaniedbania (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"keyWords": ["bieda", "brud", "zaniedbanie", "Wisła", "naturalizm"], "expectedAnswer": "Powiśle to dzielnica nad Wisłą pełna biedy, brudu i zaniedbania. Prus przedstawił ją w sposób naturalistyczny jako symbol warszawskiej nędzy i chaosu urbanistycznego. Dla Wokulskiego był to obraz polskiego społeczeństwa."}', '2025-10-24 22:16:54.877', '2025-10-24 22:16:54.877', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva7300yrqhd91x6xs9jb', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Kim był profesor Geist i gdzie go spotkał Wokulski?', '{"work": "Lalka", "instruction": "Opisz postać Geista i jego znaczenie dla Wokulskiego. (40-60 słów)"}', NULL, '{"criteria": ["określenie Geista jako naukowca-chemika (1 pkt)", "wskazanie spotkania w Paryżu i szansy naukowej (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"keyWords": ["chemik", "Paryż", "naukowiec", "metal", "szansa"], "expectedAnswer": "Profesor Geist to genialny chemik mieszkający w Paryżu, pracujący nad metalem lżejszym od powietrza. Wokulski spotkał go podczas pobytu w Paryżu i miał szansę zostać jego pomocnikiem naukowym, ale wybrał powrót do Polski dla Izabeli."}', '2025-10-24 22:16:54.879', '2025-10-24 22:16:54.879', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva7500ysqhd9urxkp03x', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 2, 'Z jakiej rodziny pochodził Stanisław Wokulski?', '{"work": "Lalka", "instruction": "Opisz pochodzenie społeczne Wokulskiego. (20-40 słów)"}', NULL, '{"criteria": ["wskazanie pochodzenia ze zubożałej szlachty (1 pkt)", "wzmianka o ojcu procesującym się o majątek (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-1,positivism,batch-2025-01}', '{"keyWords": ["zubożała szlachta", "ojciec", "proces", "majątek"], "expectedAnswer": "Wokulski pochodził ze zubożałej rodziny szlacheckiej. Jego ojciec ciągle procesował się o majątek po dziadku i zabierał synowi pieniądze przeznaczone na książki."}', '2025-10-24 22:16:54.882', '2025-10-24 22:16:54.882', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evait013nqhd975uli5h2', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 2, 'Które postacie giną w „Makbecie” (wybierz wszystkie poprawne)', '{"options": ["Duncan", "Banko", "Lady Makbet", "Malcolm", "Makbet", "Ross"]}', '[0, 1, 2, 4]', NULL, '{historical_literary,closed_multiple,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "W tragedii giną: Duncan, Banko, Lady Makbet i Makbet. Malcolm i Ross przeżywają."}', '2025-10-24 22:16:55.302', '2025-10-24 22:16:55.302', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaiv013oqhd9wxwv9smi', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 2, 'Które elementy nadprzyrodzone pojawiają się w „Makbecie”? (wybierz wszystkie)', '{"options": ["wiedźmy", "halucynacje", "duchy", "przepowiednie", "anioły", "demony"]}', '[0, 1, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "W dramacie występują: wiedźmy, halucynacje (sztylet), duchy (Banko) i przepowiednie."}', '2025-10-24 22:16:55.304', '2025-10-24 22:16:55.304', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaiy013pqhd9gijcbgkc', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 2, 'Dopasuj bohaterów „Makbeta” do ich losów', '{"leftColumn": [{"id": "A", "text": "Duncan"}, {"id": "B", "text": "Banko"}, {"id": "C", "text": "Lady Makbet"}, {"id": "D", "text": "Makbet"}], "rightColumn": [{"id": 1, "text": "zabity przez wynajętych morderców"}, {"id": 2, "text": "zabity przez Makdufa"}, {"id": 3, "text": "zabity we śnie"}, {"id": 4, "text": "popełnia samobójstwo"}], "matchingType": "character_fate"}', '[[0, 2], [1, 0], [2, 3], [3, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Duncan zabity we śnie, Banko przez morderców, Lady Makbet popełnia samobójstwo, Makbet ginie z ręki Makdufa."}', '2025-10-24 22:16:55.306', '2025-10-24 22:16:55.306', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpbf002gqhfgz69ny9pn', 'SHORT_ANSWER', 'LANGUAGE_USE', 'ROMANTICISM', 5, 4, 'Wyjasnij, jak Mickiewicz buduje napiecie fabularne za pomoca inwersji czasowej i fragmentaryzmu narracji. Podaj przyklady.', '{}', '"Inwersja czasowa: utwor NIE opowiada historii chronologicznie. Zaczyna sie od obioru Konrada na mistrza (terazniejszosc), przeszlosc Waltera Alfa poznajemy dopiero z Powiesci Wajdeloty (cz. IV) -- opowiadanej na uczcie jako piesn. Czytelnik sklada fabuule jak puzzle. Fragmentaryzm: kluczowe wydarzenia sa pominiete lub tylko zasugerowane (np. moment zmiany tozsamosci z Alfa na Wallenroda, lata sluzby w Zakonie). Efekt: tajemniczosc bohatera -- czytelnik dlugo nie wie, kim naprawde jest Konrad. Napiecie rosnie, bo fragmenty ukladaja sie w calosc stopniowo. To cecha powieci poetyckiej zapozyczona od Byrona."', NULL, '{language_use,short_answer,difficulty-5,romanticism,batch-2025-01}', '{"explanation": "Pytanie o kompozycje to typowe pytanie LANGUAGE_USE na maturze rozszerzonej. Kluczowe terminy: inwersja czasowa, fragmentaryzm, synkretyzm rodzajowy, powiesc poetycka."}', '2026-03-17 22:22:09.963', '2026-03-17 22:22:09.963', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpbh002hqhfgq037dpmp', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 5, 5, 'Napisz notatke syntetyczna na podany temat:', '{"topic": "Rola poety i piesni w \"Konradzie Wallenrodzie\" -- od Piesni Wajdeloty do odmowy smierci Halbana", "wordLimit": {"max": 250, "min": 200}, "requirements": ["Przeanalizuj Piesn Wajdeloty jako manifest roli pieśni w zyciu narodu", "Wyjasnij, dlaczego Halban odmawia smierci -- co to mowi o hierarchii: poeta > rycerz", "Odwolaj sie do romantycznej koncepcji poety-wieszcza", "Porownaj z inna realizacja motywu roli poety (np. Wielka Improwizacja, \"Do mlodych\" Asnyka)", "200-250 slow"]}', '"Notatka powinna: zanalizowac Piesn Wajdeloty jako manifest: piesn gminna to ''arka przymierza'', straznik pamieci, bron archanioła -- przetrwa, gdy plomien zniszczy kroniki. Odmowa Halbana = dowod, ze poeta jest wazniejszy od rycerza: Konrad ginie, ale Halban zachowa jego czyn w piesni, z ktorej ''wstanie msciciel''. Hierarchia: poeta > bohater, bo bohater umiera, a pieśn jest wieczna. Romantyczna koncepcja: poeta-wieszcz = duchowy przywodca narodu (jak pozniej Konrad w Dziadach III). Porownanie: w Wielkiej Improwizacji Konrad tez twierdzi, ze ''czuje i jestem'' -- ale jego narzedziem jest slowo, nie miecz. U Asnyka poeta juz nie jest wieszczem -- ''Do mlodych'' to pozegnanie z romantyzmem. Wniosek: Mickiewicz w Konradzie Wallenrodzie buduje fundament romantycznej hierarchii: slowo jest silniejsze od miecza."', NULL, '{historical_literary,synthesis_note,difficulty-5,romanticism,batch-2025-01}', '{"explanation": "Rola poety w narodzie to kluczowy temat romantyzmu i czeste pytanie maturalne. \"Konrad Wallenrod\" jest jednym z pierwszych tekstow, w ktorych Mickiewicz formulluje te ide -- pózniej rozwinięta w Dziadach."}', '2026-03-17 22:22:09.966', '2026-03-17 22:22:09.966', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva7o00ytqhd97ldeu568', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Kim był Maruszewicz w powieści?', '{"work": "Lalka", "instruction": "Scharakteryzuj postać Maruszewicza w 2-3 zdaniach. (30-50 słów)"}', NULL, '{"criteria": ["określenie jako zdeklasowany szlachcic (1 pkt)", "wskazanie, że był oszustem (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"keyWords": ["zdeklasowany", "oszust", "wyłudzał", "szlachcic"], "expectedAnswer": "Maruszewicz to zdeklasowany szlachcic i oszust. Wyłudzał pieniądze od różnych osób, w tym od Wokulskiego i barona Krzeszowskiego. Ostatecznie Wokulski okazał mu łaskę i zniszczył dowody jego oszustw."}', '2025-10-24 22:16:54.884', '2025-10-24 22:16:54.884', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva7s00yuqhd9j0cbhm9j', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Ile pieniędzy Wokulski przywiózł z wojny w Bułgarii?', '{"options": ["30 tysięcy rubli", "100 tysięcy rubli", "250 tysięcy rubli", "500 tysięcy rubli"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Wokulski przywiózł z Bułgarii 250 tysięcy rubli i dużo złota, podczas gdy wyjechał z 30 tysiącami - pomnożył majątek dziesięciokrotnie."}', '2025-10-24 22:16:54.905', '2025-10-24 22:16:54.905', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva7v00yvqhd9ab449ofh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kto był pierwszym pracodawcą młodego Wokulskiego?', '{"options": ["Mincel", "Hopfer", "Rzecki", "Suzin"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Wokulski jako młody człowiek pracował jako subiekt u Hopfera w winiarni, zanim rozpoczął studia."}', '2025-10-24 22:16:54.908', '2025-10-24 22:16:54.908', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva7y00ywqhd9jozxrdzo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Gdzie Rzecki walczył po śmierci ojca?', '{"options": ["w powstaniu styczniowym", "w powstaniu węgierskim", "w powstaniu listopadowym", "nigdzie nie walczył"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Po śmierci ojca Rzecki wraz z Augustem Katzem wyjechał walczyć w powstaniu węgierskim."}', '2025-10-24 22:16:54.91', '2025-10-24 22:16:54.91', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8000yxqhd90x3j5tea', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 1, 'Ile lat miał Wokulski na początku akcji powieści?', '{"options": ["36 lat", "46 lat", "56 lat", "26 lat"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Na początku powieści Stanisław Wokulski miał 46 lat."}', '2025-10-24 22:16:54.912', '2025-10-24 22:16:54.912', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8200yyqhd9cqygd8ji', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kto to była Florentyna w powieści?', '{"options": ["służąca Łęckich", "kuzynka i opiekunka Izabeli", "przyjaciółka Wokulskiego", "żona Tomasza Łęckiego"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Panna Florentyna to kuzynka Izabeli, która mieszkała z Łęckimi i pełniła rolę jej opiekunki."}', '2025-10-24 22:16:54.915', '2025-10-24 22:16:54.915', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8500yzqhd9qi40y8bl', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Uzupełnij informacje o sklepie Wokulskiego.', '{"gaps": [{"id": 1, "options": ["Hopfera", "Jana Mincla", "Rzeckiego", "Suzina"]}, {"id": 2, "options": ["Izabela", "Helena", "Małgorzata", "Florentyna"]}, {"id": 3, "options": ["dziesięć", "trzydzieści", "pięćdziesiąt", "sto"]}, {"id": 4, "options": ["kamienicę", "fabrykę", "sklep galanteryjny", "powóz"]}], "textWithGaps": "Sklep należał wcześniej do [1], którego żona nazywała się [2]. Po jego śmierci Wokulski ożenił się z wdową i odziedziczył [3] tysięcy rubli oraz [4]."}', '[1, 2, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Sklep należał do Jana Mincla, którego żona Małgorzata po śmierci męża wyszła za Wokulskiego. Odziedziczył 30 tysięcy rubli i sklep galanteryjny."}', '2025-10-24 22:16:54.917', '2025-10-24 22:16:54.917', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8700z0qhd92bvqfcos', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 1, 2, 'Które wydarzenia miały miejsce w życiu Wokulskiego? (wybierz wszystkie poprawne)', '{"options": ["studiował w Szkole Głównej", "brał udział w powstaniu styczniowym", "był zesłany na Syberię", "był profesorem uniwersytetu", "zarabiał na wojnie turecko-rosyjskiej"]}', '[0, 1, 2, 4]', NULL, '{historical_literary,closed_multiple,difficulty-1,positivism,batch-2025-01}', '{"explanation": "Prawdziwe: Wokulski studiował, brał udział w powstaniu, był zesłany i zarabiał na wojnie. Fałszywe: nie był profesorem."}', '2025-10-24 22:16:54.919', '2025-10-24 22:16:54.919', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8900z1qhd94cnndeuf', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Wyjaśnij, czym jest język ezopowy i jak Prus go stosuje w „Lalce.', '{"work": "Lalka", "instruction": "Zdefiniuj język ezopowy i podaj przykład jego zastosowania w powieści. (50-80 słów)"}', NULL, '{"criteria": ["definicja języka ezopowego (1 pkt)", "wskazanie kontekstu cenzury (1 pkt)", "przykład z powieści (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-3,positivism,batch-2025-01}', '{"keyWords": ["język ezopowy", "cenzura", "niedomówienia", "metafory", "polityka"], "expectedAnswer": "Język ezopowy to technika używania niedomówień, metafor i metonimii, zrozumiałych dla czytelnika, ale nie dla cenzora. Prus stosował go przy opisywaniu kwestii historycznych i politycznych (powstanie styczniowe, sytuacja Polski). Pozwalało to ominąć cenzurę i przekazać czytelnikom ukryte treści narodowe."}', '2025-10-24 22:16:54.921', '2025-10-24 22:16:54.921', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8b00z2qhd9y3d7az0h', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 5, 4, 'Wyjaśnij, dlaczego Wokulski rezygnuje z kariery naukowej u Geista w Paryżu.', '{"work": "Lalka", "instruction": "Opisz dylematy Wokulskiego między nauką a miłością. Co ostatecznie zadecydowało o jego wyborze? (100-150 słów)"}', NULL, '{"criteria": ["opis szansy naukowej u Geista (1 pkt)", "opis miłości do Izabeli jako przeciwwagi (1 pkt)", "wskazanie decydującego czynnika (list od prezesowej) (1 pkt)", "interpretacja tragizmu wyboru (1 pkt)"], "maxScore": 4}', '{historical_literary,short_answer,difficulty-5,positivism,batch-2025-01}', '{"keyWords": ["Geist", "Paryż", "nauka", "Izabela", "list", "wybór", "tragizm"], "expectedAnswer": "W Paryżu Wokulski miał szansę zrealizować młodzieńcze marzenia o karierze naukowej u boku geniusza - profesora Geista. Był już prawie zdecydowany zostać, gdy otrzymał list od prezesowej Zasławskiej wzmiankujący o Izabeli. To zdecydowało - miłość do Łęckiej okazała się silniejsza niż pasja naukowa. Wybór ten pokazuje tragizm postaci Wokulskiego - romantycy nie potrafią wybrać rozumu zamiast serca."}', '2025-10-24 22:16:54.924', '2025-10-24 22:16:54.924', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8e00z3qhd979syfbut', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kto był wspólnikiem Wokulskiego podczas zarabiania majątku na wojnie?', '{"options": ["doktor Szuman", "Suzin", "stary Szlangbaum", "Geist"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Suzin to rosyjski kupiec, wspólnik Wokulskiego, który pomógł mu zarobić majątek podczas wojny turecko-rosyjskiej."}', '2025-10-24 22:16:54.926', '2025-10-24 22:16:54.926', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8g00z4qhd9je0x1c0z', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Ile lat Rzecki mieszkał w swoim ciemnym pokoju przy sklepie?', '{"options": ["15 lat", "25 lat", "30 lat", "20 lat"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Rzecki mieszkał w ciemnym pokoju przy sklepie przez 25 lat, co podkreśla jego przywiązanie do miejsca i monotonię życia."}', '2025-10-24 22:16:54.928', '2025-10-24 22:16:54.928', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8i00z5qhd9tvvox2rf', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Dlaczego Wokulski nie mógł zostać naukowcem po powrocie z Syberii?', '{"options": ["nie miał odpowiedniego wykształcenia", "naukowcy widzieli w nim byłego subiekta, kupcy - naukowca", "został mu zabroniony dostęp do uniwersytetu", "wolał zajmować się handlem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Wokulski nie został zaakceptowany ani przez świat nauki (widzieli w nim kupca), ani przez świat handlu (widzieli w nim naukowca) - symbolizuje to jego pozycję pomiędzy i społeczne niezrozumienie."}', '2025-10-24 22:16:54.93', '2025-10-24 22:16:54.93', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8k00z6qhd9kjbq2rbx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Gdzie Wokulski spotkał Izabelę po raz pierwszy?', '{"options": ["w swoim sklepie", "w teatrze podczas spektaklu", "na balu u księcia", "w Łazienkach"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Wokulski po raz pierwszy zobaczył Izabelę w teatrze podczas spektaklu i zakochał się w niej od pierwszego wejrzenia. To spotkanie całkowicie zmieniło jego życie."}', '2025-10-24 22:16:54.932', '2025-10-24 22:16:54.932', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8m00z7qhd9h8kejt4w', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Co symbolizuje porównanie Warszawy do gąsienicy przez Wokulskiego w Paryżu?', '{"options": ["piękno polskiej stolicy", "chaos i brak planu urbanistycznego Warszawy", "dynamiczny rozwój miasta", "bogactwo warszawskiej architektury"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Wokulski porównuje chaotyczną Warszawę do gąsienicy, kontrastując ją z logicznie zaplanowanym Paryżem. To symbol krytyki polskiej rzeczywistości przez pozytywistów."}', '2025-10-24 22:16:54.934', '2025-10-24 22:16:54.934', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8o00z8qhd9tiucv9t2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kto uratował życie Wokulskiego podczas próby samobójstwa w Skierniewicach?', '{"options": ["Rzecki", "Szuman", "brat Wysockiego - dróżnik", "Ochocki"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Życie Wokulskiego uratował dróżnik - brat Wysockiego, któremu Stanisław wcześniej pomógł, załatwiając mu pracę na kolei. To pokazuje, jak dobro wraca."}', '2025-10-24 22:16:54.936', '2025-10-24 22:16:54.936', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8q00z9qhd9oncpc65t', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Jaką cenę zapłacił Wokulski za kamienicę Łęckich?', '{"options": ["70 tysięcy rubli (wartość rynkowa)", "80 tysięcy rubli", "90 tysięcy rubli (20 tys. ponad wartość)", "100 tysięcy rubli"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Wokulski kupił kamienicę za 90 tysięcy rubli, choć była warta tylko 70 tysięcy, aby pomóc finansowo rodzinie Izabeli i zbliżyć się do niej."}', '2025-10-24 22:16:54.938', '2025-10-24 22:16:54.938', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8s00zaqhd9aayw55db', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 2, 'Dlaczego Wokulski zrezygnował z pracy u profesora Geista w Paryżu?', '{"options": ["nie był zainteresowany nauką", "otrzymał list od prezesowej wspominający o Izabeli", "nie miał wystarczających kwalifikacji", "musiał wracać do sklepu w Warszawie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Wokulski był już prawie zdecydowany zostać w Paryżu i poświęcić się nauce, gdy otrzymał list od prezesowej Zasławskiej wspominający o Izabeli. Miłość okazała się silniejsza niż pasja naukowa."}', '2025-10-24 22:16:54.94', '2025-10-24 22:16:54.94', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8u00zbqhd99iywhd80', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Dopasuj wydarzenia do miejsc, w których się rozegrały.', '{"leftColumn": [{"id": "A", "text": "Wyścig konny i pojedynek z baronem"}, {"id": "B", "text": "Spotkanie z profesorem Geistem"}, {"id": "C", "text": "Proces o lalkę"}, {"id": "D", "text": "Spacery z Izabelą po ruinach zamku"}], "rightColumn": [{"id": 1, "text": "Zasławek - posiadłość prezesowej"}, {"id": 2, "text": "Paryż"}, {"id": 3, "text": "tor wyścigowy w Warszawie"}, {"id": 4, "text": "sąd warszawski"}], "matchingType": "events_places"}', '[[0, 2], [1, 1], [2, 3], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Wyścig i pojedynek - tor w Warszawie, Geist - Paryż, proces - sąd warszawski, spacery z Izabelą - Zasławek."}', '2025-10-24 22:16:54.943', '2025-10-24 22:16:54.943', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8x00zcqhd9mg63waqb', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Uzupełnij informacje o panu Tomaszu Łęckim.', '{"gaps": [{"id": 1, "options": ["bogaty", "zubożały", "młody", "starożytny"]}, {"id": 2, "options": ["wojny", "hazardu", "wydarzeń politycznych", "pożaru"]}, {"id": 3, "options": ["Helena", "Izabela", "Florentyna", "Ewelina"]}, {"id": 4, "options": ["Rzeckiego", "Wokulskiego", "Ochockiego", "Szumana"]}], "textWithGaps": "Tomasz Łęcki to [1] arystokrata, który utracił majątek z powodu [2] i własnej rozrzutności. Ma córkę o imieniu [3], która jest obiektem miłości [4]."}', '[1, 2, 1, 1]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Tomasz Łęcki to zubożały arystokrata, który stracił majątek z powodu wydarzeń politycznych i rozrzutności. Ma córkę Izabelę, w której zakochany jest Wokulski."}', '2025-10-24 22:16:54.945', '2025-10-24 22:16:54.945', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva8z00zdqhd9ee2ucumh', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Które zdania o Wokulskim są prawdziwe? (wybierz wszystkie poprawne)', '{"options": ["Wyjechał na Syberię za udział w powstaniu styczniowym", "Pochodził z bogatej rodziny kupieckiej", "Odziedziczył sklep po Minclowej", "Był profesorem chemii na uniwersytecie", "Zarabiał pieniądze na dostawach broni podczas wojny"]}', '[0, 2, 4]', NULL, '{historical_literary,closed_multiple,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Prawdziwe: Wokulski był na Syberii za powstanie styczniowe, odziedziczył sklep po Minclowej i zarabiał na broni podczas wojny. Fałszywe: pochodził ze zubożałej szlachty i nie był profesorem."}', '2025-10-24 22:16:54.948', '2025-10-24 22:16:54.948', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva9500zeqhd9b44lz5im', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 3, 'Dopasuj postaci do ich kluczowych decyzji życiowych.', '{"leftColumn": [{"id": "A", "text": "Wokulski"}, {"id": "B", "text": "Ochocki"}, {"id": "C", "text": "Izabela"}, {"id": "D", "text": "Rzecki"}], "rightColumn": [{"id": 1, "text": "Rezygnacja z małżeństwa dla nauki"}, {"id": 2, "text": "Oddanie życia sklepowi i pamięci o Napoleonie"}, {"id": 3, "text": "Wstąpienie do klasztoru po śmierci ojca"}, {"id": 4, "text": "Wybór miłości zamiast kariery naukowej w Paryżu"}], "matchingType": "characters_decisions"}', '[[0, 3], [1, 0], [2, 2], [3, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Wokulski wybrał miłość zamiast nauki, Ochocki zrezygnował z małżeństwa dla wynalazków, Izabela wstąpiła do klasztoru, Rzecki poświęcił życie sklepowi i bonapartyzmowi."}', '2025-10-24 22:16:54.954', '2025-10-24 22:16:54.954', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva9900zfqhd9m0eibmf2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kto prowadził Pamiętnik starego subiekta?', '{"options": ["Wokulski", "Rzecki", "Szuman", "Ochocki"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Pamiętnik starego subiekta to dziennik Ignacego Rzeckiego, w którym zapisywał swoje myśli, emocje i obserwacje życia."}', '2025-10-24 22:16:54.957', '2025-10-24 22:16:54.957', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva9b00zgqhd9fnesgys7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Co było przyczyną wyjazdu Wokulskiego z pociągu w Skierniewicach?', '{"options": ["pilna sprawa biznesowa", "nagła choroba", "podsłuchana rozmowa Izabeli ze Starskim po angielsku", "spóźnienie pociągu"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Wokulski podsłuchał rozmowę Izabeli ze Starskim po angielsku, w której flirtowali i obmawiały go. To złamało mu serce i skłoniło do opuszczenia pociągu."}', '2025-10-24 22:16:54.96', '2025-10-24 22:16:54.96', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva9e00zhqhd94r5sgh3h', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Ile pieniędzy Wokulski ofiarował podczas kwesty w kościele?', '{"options": ["10 rubli", "25 półimperiałów", "100 rubli", "5 rubli"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Podczas kwesty Wokulski hojnie ofiarował 25 półimperiałów, aby zrobić wrażenie na Izabeli i hrabinie Karolowej."}', '2025-10-24 22:16:54.962', '2025-10-24 22:16:54.962', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva9g00ziqhd94arv3zbs', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Uzupełnij informacje o finale powieści.', '{"gaps": [{"id": 1, "options": ["ucieczkę zagranicę", "samobójstwo", "morderstwo", "podpalenie"]}, {"id": 2, "options": ["sklep", "pałac księcia", "zamek w Zasławiu", "kamienicę"]}, {"id": 3, "options": ["list", "krzyż", "grób", "pomnik"]}, {"id": 4, "options": ["uciekł", "umarł", "wyemigrował", "ożenił się"]}], "textWithGaps": "Po zerwaniu z Izabelą Wokulski najprawdopodobniej popełnił [1], wysadzając w powietrze [2]. Świadczy o tym [3] z napisem Non omnis moriar. Rzecki [4], układając towary w sklepie Szlangbauma."}', '[1, 2, 1, 1]', NULL, '{historical_literary,closed_multiple,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Wokulski prawdopodobnie popełnił samobójstwo, wysadzając zamek w Zasławiu. Węgiełek postawił krzyż z napisem Non omnis moriar. Rzecki umarł w sklepie."}', '2025-10-24 22:16:54.964', '2025-10-24 22:16:54.964', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva9j00zjqhd9x34neg6t', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 3, 'Dopasuj symbole do ich znaczenia w powieści.', '{"leftColumn": [{"id": "A", "text": "Lalka"}, {"id": "B", "text": "Paryż"}, {"id": "C", "text": "Powiśle"}, {"id": "D", "text": "Sklep galanteryjny"}], "rightColumn": [{"id": 1, "text": "Miejsce uwięzienia i przyziemnej egzystencji"}, {"id": 2, "text": "Pustka emocjonalna i sztuczność"}, {"id": 3, "text": "Bieda i zaniedbanie polskiego społeczeństwa"}, {"id": 4, "text": "Cywilizacja, postęp i racjonalna organizacja"}], "matchingType": "symbols_meanings"}', '[[0, 1], [1, 3], [2, 2], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Lalka symbolizuje pustkę (jak Izabela), Paryż - postęp i cywilizację, Powiśle - polską biedę, sklep - uwięzienie w przyziemności."}', '2025-10-24 22:16:54.967', '2025-10-24 22:16:54.967', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva9l00zkqhd9smdlc290', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Wyjaśnij, dlaczego Wokulski zorganizował aplauz dla Rossiego.', '{"work": "Lalka", "instruction": "Podaj powód zorganizowania oklasków i wyjaśnij cel tej akcji. (30-50 słów)"}', NULL, '{"criteria": ["wskazanie, że Izabela zachwycała się Rossim (1 pkt)", "wyjaśnienie, że Wokulski chciał sprawić jej przyjemność (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"keyWords": ["Rossi", "Izabela", "aplauz", "przyjemność", "miłość"], "expectedAnswer": "Izabela zachwycała się włoskim tragikiem Rossim i krytykowała warszawską publiczność za brak entuzjazmu. Wokulski zorganizował owacje, aby sprawić jej przyjemność - wszystkie jego działania były podporządkowane zdobyciu serca Izabeli."}', '2025-10-24 22:16:54.97', '2025-10-24 22:16:54.97', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva9o00zlqhd931ie8feh', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Scharakteryzuj relację między Wokulskim a Rzeckim.', '{"work": "Lalka", "instruction": "Opisz, jak się poznali i jaka była ich przyjaźń w 3-4 zdaniach. (50-80 słów)"}', NULL, '{"criteria": ["wskazanie, że poznali się w latach 50. XIX w. (1 pkt)", "opis głębokiej przyjaźni i lojalności (1 pkt)", "wspomnienie, że Rzecki wspierał Wokulskiego (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-3,positivism,batch-2025-01}', '{"keyWords": ["przyjaźń", "Hopfer", "wsparcie", "lojalność", "lata 50."], "expectedAnswer": "Rzecki i Wokulski poznali się w latach 1857-1858, gdy młody Stanisław pracował u Hopfera. Ignacy od razu dostrzegł w nim potencjał i wspierał jego naukowe ambicje. Ich przyjaźń była głęboka i lojalna - Rzecki pomagał Wokulskiemu w trudnych chwilach, a Stanisław dbał o przyjaciela finansowo. To była najbliższa relacja w życiu obu mężczyzn."}', '2025-10-24 22:16:54.972', '2025-10-24 22:16:54.972', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaj0013qqhd9dm9rqpn5', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 2, 'Które tematy występują w „Makbecie”? (wybierz wszystkie poprawne)', '{"options": ["ambicja i władza", "wyrzuty sumienia", "męskość i honor", "przeznaczenie", "komedia i humor", "nadprzyrodzone"]}', '[0, 1, 2, 3, 5]', NULL, '{historical_literary,closed_multiple,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Główne tematy to: ambicja, wyrzuty sumienia, męskość, przeznaczenie i elementy nadprzyrodzone."}', '2025-10-24 22:16:55.308', '2025-10-24 22:16:55.308', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva9r00zmqhd9wx8sphkl', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Wyjaśnij, czym zajmował się doktor Szuman.', '{"work": "Lalka", "instruction": "Opisz zawód i główne zajęcia doktora Szumana. (30-50 słów)"}', NULL, '{"criteria": ["wskazanie, że był lekarzem i naukowcem (1 pkt)", "wspomnienie, że leczył biednych za darmo (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"keyWords": ["lekarz", "naukowiec", "za darmo", "badania", "Żyd"], "expectedAnswer": "Doktor Szuman był żydowskim lekarzem i naukowcem. Mimo posiadania majątku leczył biednych za darmo, traktując pacjentów jako materiał do badań. Badał włosy Polaków i prowadził obserwacje naukowe."}', '2025-10-24 22:16:54.975', '2025-10-24 22:16:54.975', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva9t00znqhd90a21uojo', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Opisz proces sądowy o lalkę między Heleną Stawską a baronową Krzeszowską.', '{"work": "Lalka", "instruction": "Wyjaśnij, o co toczyła się sprawa i jak się zakończyła. (50-80 słów)"}', NULL, '{"criteria": ["wskazanie oskarżenia o kradzież lalki (1 pkt)", "wyjaśnienie, że lalka była kupiona w sklepie Wokulskiego (1 pkt)", "informacja o uniewinnieniu Stawskiej (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-3,positivism,batch-2025-01}', '{"keyWords": ["baronowa", "kradzież", "lalka", "sklep", "uniewinniona"], "expectedAnswer": "Baronowa Krzeszowska oskarżyła Helenę Stawską o kradzież lalki, którą podglądając zauważyła u niej w mieszkaniu. W rzeczywistości Helena kupiła identyczną lalkę w sklepie Wokulskiego za 3 ruble. Podczas rozprawy służąca baronowej przyznała się, że oryginalna lalka się stłukła. Sąd uniewinnił panią Stawską."}', '2025-10-24 22:16:54.978', '2025-10-24 22:16:54.978', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva9v00zoqhd9ro8p3cvp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kto kupił sklep Wokulskiego?', '{"options": ["Rzecki", "młody Szlangbaum", "Suzin", "Ochocki"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Sklep Wokulskiego kupił młody Szlangbaum, syn starego Szlangbauma. Po przejęciu sklepu zaczął zwalniać pracowników i zachowywać się arogancko."}', '2025-10-24 22:16:54.98', '2025-10-24 22:16:54.98', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eva9y00zpqhd9yiciiwpk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Co Wokulski planował zbudować na Powiślu?', '{"options": ["nową kamienicę", "fabrykę", "bulwary nad Wisłą", "teatr"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Wokulski planował wybudować na Powiślu bulwary, aby pomóc okolicznym nędzarzom i upiększyć zaniedbane nadwiślańskie tereny. To pokazuje jego pragnienie organicznej pracy."}', '2025-10-24 22:16:54.982', '2025-10-24 22:16:54.982', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaa000zqqhd99u2quua4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Jaki prezent Wokulski kupił Mariannie (byłej prostytutce) na ślub?', '{"options": ["maszynę do szycia", "nowe mieszkanie", "500 rubli i wyprawkę", "sklep"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Wokulski dał Węgiełkowi 500 rubli na ślub, a Mariannie zapewnił wyprawkę. Pokazuje to jego dobroć i chęć pomagania potrzebującym."}', '2025-10-24 22:16:54.984', '2025-10-24 22:16:54.984', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaa200zrqhd9fkq2ei9o', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Dopasuj miejsca w Paryżu do ich symbolicznego znaczenia dla Wokulskiego.', '{"leftColumn": [{"id": "A", "text": "Laboratorium profesora Geista"}, {"id": "B", "text": "Paryskie bulwary"}, {"id": "C", "text": "Hotel Wokulskiego"}, {"id": "D", "text": "Sesje z kontrahentami Suzina"}], "rightColumn": [{"id": 1, "text": "Miejsce samotności i tęsknoty za Izabelą"}, {"id": 2, "text": "Symbol porządku i cywilizacji"}, {"id": 3, "text": "Możliwość kariery naukowej"}, {"id": 4, "text": "Świat interesów i pieniądza"}], "matchingType": "paris_places"}', '[[0, 2], [1, 1], [2, 0], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Laboratorium Geista - szansa naukowa, bulwary - porządek Paryża, hotel - samotność, sesje - świat interesów."}', '2025-10-24 22:16:54.987', '2025-10-24 22:16:54.987', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaa500zsqhd9bojsnzcj', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Które działania Wokulskiego były motywowane miłością do Izabeli? (wybierz wszystkie poprawne)', '{"options": ["Wyjazd do Bułgarii na wojnę", "Nauka języka angielskiego", "Badania naukowe z Geistem", "Kupno kamienicy Łęckich", "Organizacja aplauzu dla Rossiego"]}', '[0, 1, 3, 4]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Wokulski wyjechał na wojnę, żeby zarobić na Izabelę, uczył się angielskiego, bo ona mówiła po angielsku, kupił kamienicę Łęckich i zorganizował aplauz - wszystko dla niej. Badania z Geistem to była alternatywa dla miłości."}', '2025-10-24 22:16:54.989', '2025-10-24 22:16:54.989', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaa700ztqhd9glidvig6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kto był ojcem chrzestnym dziecka Wysockiego?', '{"options": ["Rzecki", "Wokulski", "Szuman", "Ochocki"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Wokulski został ojcem chrzestnym dziecka Wysockiego, którego wcześniej uratował z biedy, dając mu pracę i pieniądze na konia."}', '2025-10-24 22:16:54.991', '2025-10-24 22:16:54.991', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaa900zuqhd9a1tv51xm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Ile tysięcy rubli długów miał Kazimierz Starski?', '{"options": ["50 tysięcy rubli", "75 tysięcy rubli", "100 tysięcy rubli", "150 tysięcy rubli"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Starski miał 100 tysięcy rubli długów i uciekł zagranicę przed wierzycielami. Był utracjuszem i bawidamkiem."}', '2025-10-24 22:16:54.994', '2025-10-24 22:16:54.994', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaab00zvqhd9corw1wa9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kto w „Lalce” wygłosił przemówienie o małżeństwie jako związku rozumnym, a nie miłosnym?', '{"options": ["Wokulski", "Ochocki", "Starski", "baron Dalski"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Starski wygłosił wykład w altanie u prezesowej, twierdząc, że małżeństwo należy zawierać rozumnie, kierując się interesami, a nie miłością."}', '2025-10-24 22:16:54.996', '2025-10-24 22:16:54.996', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaae00zwqhd9ssfxbupt', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Jaki metal Geist chciał stworzyć jako swoje największe odkrycie?', '{"options": ["metal cięższy od platyny", "metal lżejszy od powietrza", "szkło cięższe od żelaza", "stal lekka jak piórko"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Największym, choć niedokończonym odkryciem Geista miał być materiał lżejszy od powietrza. Obawiał się jednak, że ludzkość użyje go w niewłaściwy sposób."}', '2025-10-24 22:16:54.998', '2025-10-24 22:16:54.998', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaak00zxqhd9omk8nt7l', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Ile pieniędzy Wokulski zapisał Ochockiemu w testamencie?', '{"options": ["100 tysięcy rubli", "120 tysięcy rubli", "140 tysięcy rubli", "160 tysięcy rubli"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "W testamencie Wokulski zapisał Ochockiemu 140 tysięcy rubli na badania naukowe, Rzeckiemu 25 tysięcy, a Helenie Stawskiej 20 tysięcy rubli."}', '2025-10-24 22:16:55.005', '2025-10-24 22:16:55.005', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaao00zyqhd92nt4ioww', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Kto powiedział, że Wokulski to polski romantyk i półgłówek?', '{"options": ["Rzecki", "Szuman", "Suzin", "książę"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Doktor Szuman nazwał Wokulskiego polskim romantykiem i półgłówkiem, krytykując jego ślepą miłość do Izabeli i nierealistyczne oczekiwania."}', '2025-10-24 22:16:55.008', '2025-10-24 22:16:55.008', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaar00zzqhd97ral9s4n', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Gdzie mieszkał Ludwik Stawski - zaginiony mąż Heleny?', '{"options": ["w Paryżu", "w Algierze", "w Moskwie", "w Wiedniu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Mąż Heleny Stawskiej żył i mieszkał w Algierze pod zmienionym nazwiskiem. Później dotarła wiadomość o jego śmierci."}', '2025-10-24 22:16:55.011', '2025-10-24 22:16:55.011', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaat0100qhd9evui06gw', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Dopasuj postacie do ich marzeń i aspiracji.', '{"leftColumn": [{"id": "A", "text": "Wokulski"}, {"id": "B", "text": "Rzecki"}, {"id": "C", "text": "Ochocki"}, {"id": "D", "text": "Izabela"}], "rightColumn": [{"id": 1, "text": "Napoleończyk Bonaparte i wolna Polska"}, {"id": 2, "text": "Idealny arystokrata jako mąż"}, {"id": 3, "text": "Maszyna latająca i kariera naukowa"}, {"id": 4, "text": "Miłość Izabeli i szczęście rodzinne"}], "matchingType": "characters_dreams"}', '[[0, 3], [1, 0], [2, 2], [3, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Wokulski marzył o Izabeli, Rzecki o Napoleonie i wolnej Polsce, Ochocki o wynalazkach naukowych, Izabela o idealnym arystokratycznym mężu."}', '2025-10-24 22:16:55.014', '2025-10-24 22:16:55.014', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaaw0101qhd9mowplkkw', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Uzupełnij informacje o młodości Wokulskiego.', '{"gaps": [{"id": 1, "options": ["Mincla", "Hopfera", "Szlangbauma", "Suzina"]}, {"id": 2, "options": ["Uniwersytecie Warszawskim", "Akademii", "Szkole Głównej", "Liceum"]}, {"id": 3, "options": ["powstaniu listopadowym", "powstaniu styczniowym", "manifestacjach", "strajku"]}, {"id": 4, "options": ["Moskwy", "Petersburga", "Irkucka", "Władywostoku"]}], "textWithGaps": "W młodości Wokulski pracował jako subiekt u [1], jednocześnie uczęszczając na wykłady w [2]. Za udział w [3] został zesłany na Syberię do [4], gdzie spędził kilka lat ucząc się i pracując."}', '[1, 2, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Wokulski pracował u Hopfera, uczył się w Szkole Głównej, został zesłany za powstanie styczniowe do Irkucka."}', '2025-10-24 22:16:55.016', '2025-10-24 22:16:55.016', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaay0102qhd9clp7vb1m', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 3, 'Które cechy charakteryzują prezesową Zasławską? (wybierz wszystkie poprawne)', '{"options": ["Szczodra i hojna wobec potrzebujących", "Krytyczna wobec pustych arystokratek", "Zakochana niegdyś w stryju Wokulskiego", "Przekazała majątek Starskiemu", "Prowadziła przytułek dla starców"]}', '[0, 1, 2, 4]', NULL, '{historical_literary,closed_multiple,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Prezesowa była szczodra, krytyczna wobec lalek jak Izabela, kochała stryja Wokulskiego i prowadziła przytułek. Majątek przekazała na cele charytatywne, nie Starskiemu."}', '2025-10-24 22:16:55.019', '2025-10-24 22:16:55.019', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evab10103qhd9lltpaxt5', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Dopasuj osoby do ich zawodów lub zajęć w powieści.', '{"leftColumn": [{"id": "A", "text": "Jumar"}, {"id": "B", "text": "Węgiełek"}, {"id": "C", "text": "Pani Meliton"}, {"id": "D", "text": "Geist"}], "rightColumn": [{"id": 1, "text": "Kowal i stolarz z Zasławia"}, {"id": 2, "text": "Swatka i informatórka"}, {"id": 3, "text": "Profesor chemii i wynalazca"}, {"id": 4, "text": "Doktor filozofii służący w hotelu"}], "matchingType": "people_professions"}', '[[0, 3], [1, 0], [2, 1], [3, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Jumar to doktor filozofii pracujący jako służący, Węgiełek - kowal, pani Meliton - swatka, Geist - profesor chemii."}', '2025-10-24 22:16:55.021', '2025-10-24 22:16:55.021', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evab30104qhd9b1naymrm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Co Wokulski zobaczył w konfesjonale w kościele?', '{"options": ["Izabelę i Starskiego", "Izabelę z młodym mężczyzną (Ochockim)", "księdza", "biedną kobietę z córką"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Wokulski ukrył się w konfesjonale i zobaczył Izabelę z młodym mężczyzną, który sprawił jej radość - był to Julian Ochocki, kuzyn Łęckich."}', '2025-10-24 22:16:55.024', '2025-10-24 22:16:55.024', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evab60105qhd9vp3hexru', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Ile Wokulski zapłacił za klacz wyścigową od Maruszewicza?', '{"options": ["600 rubli", "800 rubli", "1000 rubli", "1200 rubli"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Wokulski kupił klacz za 800 rubli, choć baronowa oczekiwała za nią tylko 600 rubli. Pozostałe 200 rubli bezprawnie przejął Maruszewicz."}', '2025-10-24 22:16:55.026', '2025-10-24 22:16:55.026', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evab80106qhd9zp7n3p67', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Ile wynosił zysk ze spółki handlującej z cesarstwem?', '{"options": ["10%", "15%", "18%", "20%"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Spółka przyniosła zysk 18%, podczas gdy optymistyczne założenia mówiły o 15%. To pokazało skuteczność zarządzania Wokulskiego."}', '2025-10-24 22:16:55.028', '2025-10-24 22:16:55.028', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaba0107qhd9bw27m8mp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Kto odziedziczył 60 tysięcy rubli od ciotki Hortensji?', '{"options": ["Izabela", "Starski", "Ochocki", "Wokulski"]}', '0', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Izabela otrzymała w spadku od ciotki Hortensji 60 tysięcy rubli, co poprawiło jej sytuację finansową."}', '2025-10-24 22:16:55.031', '2025-10-24 22:16:55.031', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evabd0108qhd9sslwmyzl', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Uzupełnij informacje o Henryku Szlangbaumie.', '{"gaps": [{"id": 1, "options": ["judaizm", "katolicyzm", "prawosławie", "luteranizm"]}, {"id": 2, "options": ["Szlangowski", "Kowalski", "Nowak", "Henrykowski"]}, {"id": 3, "options": ["pieniędzy", "pracy", "akceptacji", "mieszkania"]}, {"id": 4, "options": ["religii", "pracy", "polonizacji", "nauki"]}], "textWithGaps": "Henryk Szlangbaum próbował się zasymilować - przyjął [1] i zmienił nazwisko na [2]. Mimo ciężkiej pracy u Polaków nie znalazł [3], więc ostatecznie zrezygnował z [4] i wrócił do żydowskiej tożsamości."}', '[1, 0, 2, 2]', NULL, '{historical_literary,closed_multiple,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Szlangbaum przyjął katolicyzm, zmienił nazwisko na Szlangowski, ale nie znalazł akceptacji wśród Polaków i zrezygnował z polonizacji."}', '2025-10-24 22:16:55.033', '2025-10-24 22:16:55.033', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evabf0109qhd93j19pf75', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 3, 'Dopasuj cytaty do postaci, które je wypowiedziały lub ich dotyczą.', '{"leftColumn": [{"id": "A", "text": "Farewell, miss Iza, farewell"}, {"id": "B", "text": "Non omnis moriar"}, {"id": "C", "text": "Świat to teatr, ludzie to marionetki"}, {"id": "D", "text": "Polski romantyk i półgłówek"}], "rightColumn": [{"id": 1, "text": "Słowa na krzyżu Węgiełka"}, {"id": 2, "text": "Pożegnanie Wokulskiego z Izabelą"}, {"id": 3, "text": "Opinia Szumana o Wokulskim"}, {"id": 4, "text": "Refleksja Rzeckiego o życiu"}], "matchingType": "quotes_people"}', '[[0, 1], [1, 0], [2, 3], [3, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Wokulski powiedział ''Farewell'' Izabeli, Non omnis moriar to napis na krzyżu, refleksja o teatrze to Rzecki, opinia o Wokulskim to Szuman."}', '2025-10-24 22:16:55.036', '2025-10-24 22:16:55.036', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evabi010aqhd9utp5wo94', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Wyjaśnij, kim była pani Wąsowska i jaką rolę odegrała w życiu Wokulskiego.', '{"work": "Lalka", "instruction": "Opisz postać pani Wąsowskiej i jej relacje z Wokulskim. (30-50 słów)"}', NULL, '{"criteria": ["określenie jako młoda wdowa (1 pkt)", "wskazanie, że próbowała pomóc Wokulskiemu w zapomnieniu Izabeli (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"keyWords": ["wdowa", "Zasławek", "pomoc", "Izabela", "rady"], "expectedAnswer": "Pani Wąsowska to młoda, inteligentna wdowa, która przebywała u prezesowej Zasławskiej. Próbowała pomóc Wokulskiemu zapomnieć o Izabeli, flirtowała z nim i dawała mu rady dotyczące kobiet. Rozumiała jego problemy i starała się go wesprzeć."}', '2025-10-24 22:16:55.038', '2025-10-24 22:16:55.038', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evabk010bqhd998ix1oml', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Opisz, jak Wokulski pomagał ludziom w potrzebie.', '{"work": "Lalka", "instruction": "Podaj co najmniej trzy przykłady pomocy Wokulskiego innym osobom. (50-80 słów)"}', NULL, '{"criteria": ["pomoc Wysockiemu (pieniądze, koń, praca) (1 pkt)", "pomoc Marii/prostytutce (pieniądze, maszyna do szycia, praca) (1 pkt)", "pomoc innym (Helenie Stawskiej, Węgiełkowi, Obermanowi) (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-3,positivism,batch-2025-01}', '{"keyWords": ["Wysocki", "Maria", "Helena", "Węgiełek", "Oberman", "pomoc"], "expectedAnswer": "Wokulski pomagał wielu osobom: dał Wysockiemu 10 rubli, kupił mu konia i zatrudnił w sklepie; pomógł Marii (byłej prostytutce), kupując jej maszynę do szycia i zapewniając pracę; zatrudnił Helenę Stawską jako kasjerkę; dał Węgiełkowi 500 rubli na ślub; oddał Obermanowi zgubione 400 rubli. Pokazuje to jego szlachetność i pozytywistyczną postawę organicznego pracownika."}', '2025-10-24 22:16:55.04', '2025-10-24 22:16:55.04', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evabm010cqhd9m6eiog6o', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 2, 'Wyjaśnij, dlaczego baron Dalski wyzwał Starskiego na pojedynek.', '{"work": "Lalka", "instruction": "Opisz powód pojedynku i jego konsekwencje. (30-50 słów)"}', NULL, '{"criteria": ["wskazanie zdrady żony barona ze Starskim (1 pkt)", "informacja o rozwodzie lub rozstaniu (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,positivism,batch-2025-01}', '{"keyWords": ["zdrada", "Ewelina", "Starski", "Zasławie", "rozwód"], "expectedAnswer": "Baron Dalski wyzwał Starskiego na pojedynek, gdy Węgiełek powiedział mu, że jego żona Ewelina zdradza go ze Starskim w ruinach zamku w Zasławiu. Po tym zdarzeniu baron postanowił rozwieść się z żoną."}', '2025-10-24 22:16:55.043', '2025-10-24 22:16:55.043', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evabo010dqhd9cs6eat1r', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Scharakteryzuj postać Maruszewicza.', '{"work": "Lalka", "instruction": "Opisz Maruszewicza i jego działania w powieści w 3-4 zdaniach. (50-80 słów)"}', NULL, '{"criteria": ["określenie jako zdeklasowany szlachcic (1 pkt)", "wskazanie, że był oszustem (1 pkt)", "wspomnienie o łasce Wokulskiego (zniszczenie dowodów) (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-3,positivism,batch-2025-01}', '{"keyWords": ["zdeklasowany", "oszust", "wyłudzał", "łaska", "dowody"], "expectedAnswer": "Maruszewicz to zdeklasowany szlachcic i oszust. Wyłudzał pieniądze od różnych osób, w tym od Wokulskiego i barona Krzeszowskiego. Sfałszował podpisy i oszukiwał przy transakcjach, jak przy sprzedaży klacz. Mimo że Wokulski odkrył jego oszustwa, okazał mu łaskę i zniszczył wszystkie dowody, aby nie trafił do więzienia."}', '2025-10-24 22:16:55.045', '2025-10-24 22:16:55.045', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evabq010eqhd9xm1q90xy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 2, 1, 'Ile pieniędzy Wokulski ofiarował pierwszej napotkanej prostytutce?', '{"options": ["wystarczająco, żeby spłacić dług i zacząć nowe życie", "100 rubli", "50 rubli", "tylko radę i wsparcie moralne"]}', '0', NULL, '{historical_literary,closed_single,difficulty-2,positivism,batch-2025-01}', '{"explanation": "Wokulski obiecał Marii, że spłaci jej dług, załatwi pobyt u sióstr magdalenek i pomoże nauczyć się szyć, dając jej szansę na nowe życie."}', '2025-10-24 22:16:55.047', '2025-10-24 22:16:55.047', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evabt010fqhd9qstait0n', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 2, 'Za co Wokulski wypłacił premię dżokejowi po wyścigu?', '{"options": ["50 rubli", "100 rubli", "150 rubli", "200 rubli"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Wokulski obiecał dżokejowi 100 rubli dodatkowo (oprócz podstawowego wynagrodzenia) za wygraną w wyścigu z klaczą baronowej."}', '2025-10-24 22:16:55.049', '2025-10-24 22:16:55.049', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evajx0144qhd9b8ca7hk2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Kto odkrywa ciało zabitego Duncana?', '{"options": ["Lady Makbet", "Banko", "Makduf", "Malcolm"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Makduf odkrywa ciało króla Duncana rankiem po morderstwie."}', '2025-10-24 22:16:55.342', '2025-10-24 22:16:55.342', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evabv010gqhd9xq990bmx', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 3, 3, 'Które zdania o finale powieści są prawdziwe? (wybierz wszystkie poprawne)', '{"options": ["Wokulski prawdopodobnie popełnił samobójstwo", "Rzecki umarł w swoim ciemnym pokoju", "Izabela wstąpiła do klasztoru", "Ochocki został naukowcem w Polsce", "Szlangbaum przejął wszystkie interesy Wokulskiego"]}', '[0, 2, 4]', NULL, '{historical_literary,closed_multiple,difficulty-3,positivism,batch-2025-01}', '{"explanation": "Prawdziwe: Wokulski prawdopodobnie popełnił samobójstwo, Izabela wstąpiła do klasztoru, Szlangbaum przejął interesy. Fałszywe: Rzecki umarł w sklepie (nie w swoim pokoju), Ochocki wyjechał zagranicę."}', '2025-10-24 22:16:55.051', '2025-10-24 22:16:55.051', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evabx010hqhd9r3mo1j7k', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 3, 'Dopasuj wątki poboczne do ich funkcji w strukturze powieści.', '{"leftColumn": [{"id": "A", "text": "Proces o lalkę"}, {"id": "B", "text": "Historia Szlangbauma"}, {"id": "C", "text": "Losy Heleny Stawskiej"}, {"id": "D", "text": "Pojedynek z baronem"}], "rightColumn": [{"id": 1, "text": "Krytyka antysemityzmu w społeczeństwie"}, {"id": 2, "text": "Kontrast z pustą Izabelą - ideał kobiety"}, {"id": 3, "text": "Symbol sądowej sprawiedliwości i zemsty"}, {"id": 4, "text": "Honor i kodeks szlachecki vs miłość"}], "matchingType": "subplots_functions"}', '[[0, 2], [1, 0], [2, 1], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-4,positivism,batch-2025-01}', '{"explanation": "Proces o lalkę - sprawiedliwość, Szlangbaum - antysemityzm, Helena - kontrast z Izabelą, pojedynek - honor szlachecki."}', '2025-10-24 22:16:55.054', '2025-10-24 22:16:55.054', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evac0010iqhd9eo6ofn7d', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'POSITIVISM', 4, 4, 'Porównaj postawy Wokulskiego i Ochockiego wobec kobiet i małżeństwa.', '{"work": "Lalka", "instruction": "Opisz różnice w podejściu obu bohaterów do miłości i życia rodzinnego. (80-120 słów)"}', NULL, '{"criteria": ["opis Wokulskiego jako romantyka oddanego miłości (1 pkt)", "opis Ochockiego jako idealisty naukowego (1 pkt)", "kontrast: Wokulski poświęcił naukę dla miłości (1 pkt)", "kontrast: Ochocki odrzucił małżeństwo dla nauki (1 pkt)"], "maxScore": 4}', '{historical_literary,short_answer,difficulty-4,positivism,batch-2025-01}', '{"keyWords": ["Wokulski", "Ochocki", "miłość", "nauka", "Izabela", "wybór"], "expectedAnswer": "Wokulski i Ochocki reprezentują dwa różne podejścia do życia. Wokulski to romantyk, który całe życie podporządkował miłości do Izabeli - zrezygnował z kariery naukowej u Geista, zarabiał majątek tylko po to, aby ją zdobyć. Ochocki natomiast całkowicie poświęcił się nauce i wynalazkom - odmówił małżeństwa z Izabelą, bo jego pasją była maszyna latająca. Wokulski wybrał miłość zamiast nauki i był nieszczęśliwy, Ochocki wybrał naukę i spełnił się w niej."}', '2025-10-24 22:16:55.056', '2025-10-24 22:16:55.056', 'Lalka');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evac2010jqhd95ar23ndi', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Kto jest autorem powieści ''Przedwiośnie''?', '{"options": ["Władysław Reymont", "Stefan Żeromski", "Bolesław Prus", "Stanisław Wyspiański"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Autorem ''Przedwiośnia'' jest Stefan Żeromski - jeden z najważniejszych pisarzy Młodej Polski, który ukończył powieść we wrześniu 1924 roku."}', '2025-10-24 22:16:55.058', '2025-10-24 22:16:55.058', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evac4010kqhd9otr23zvb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Jak ma na imię główny bohater powieści?', '{"options": ["Seweryn", "Hipolit", "Cezary", "Antoni"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Główny bohater to Cezary Baryka, syn Seweryna i Jadwigi, którego losy śledzimy od dzieciństwa w Baku po tragiczny finał w Warszawie."}', '2025-10-24 22:16:55.061', '2025-10-24 22:16:55.061', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evac6010lqhd9t0ia23bp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'W jakim mieście Cezary Baryka spędził dzieciństwo?', '{"options": ["w Warszawie", "w Moskwie", "w Petersburgu", "w Baku"]}', '3', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Cezary spędził dzieciństwo w Baku (Azerbejdżan), gdzie jego ojciec Seweryn pracował jako wysoki urzędnik przy przemysłach naftowych."}', '2025-10-24 22:16:55.063', '2025-10-24 22:16:55.063', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evac8010mqhd9soz5b1pf', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Kim z zawodu był Seweryn Baryka?', '{"options": ["lekarzem", "prawnikiem", "inżynierem i urzędnikiem", "nauczycielem"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Seweryn Baryka był inżynierem i wysokim urzędnikiem pracującym przy przemysłach naftowych w Baku, gdzie dorobił się znacznego majątku."}', '2025-10-24 22:16:55.065', '2025-10-24 22:16:55.065', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaca010nqhd9qy7xoa3y', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Co symbolizują ''szklane domy'' w powieści?', '{"options": ["rzeczywiste budowle", "utopijne wizje idealnego społeczeństwa", "fabryki szkła", "cieplarnie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Szklane domy to metafora utopijnych wizji idealnego społeczeństwa - zarówno tych ojca Cezarego o dostatku, jak i bolszewickich o równości."}', '2025-10-24 22:16:55.067', '2025-10-24 22:16:55.067', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evacd010oqhd9rv7plyec', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Jak umiera matka Cezarego?', '{"options": ["zostaje zabita przez bolszewików", "umiera w drodze do Polski", "ginie w wybuchu", "popełnia samobójstwo"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Jadwiga Barykowa umiera z wycieńczenia i choroby podczas ucieczki z Baku do Polski, nie dochodząc do upragnionej ojczyzny."}', '2025-10-24 22:16:55.069', '2025-10-24 22:16:55.069', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evacf010pqhd9tedt8vex', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'W jakiej wojnie uczestniczy Cezary po przybyciu do Polski?', '{"options": ["w I wojnie światowej", "w wojnie polsko-bolszewickiej 1920", "w powstaniu warszawskim", "w wojnie z Niemcami"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Cezary jako ochotnik uczestniczy w wojnie polsko-bolszewickiej 1920 roku, bierze udział m.in. w wyprawie kijowskiej."}', '2025-10-24 22:16:55.071', '2025-10-24 22:16:55.071', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evach010qqhd9pu8m0dd0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Jak nazywa się majątek Wielosławskich?', '{"options": ["Leńce", "Chłodek", "Nawłoć", "Odolany"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Nawłoć to majątek rodziny Wielosławskich w powiecie opoczyńskim, gdzie Cezary spędza jesień i zimę 1920 roku."}', '2025-10-24 22:16:55.074', '2025-10-24 22:16:55.074', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evacj010rqhd9t4028avs', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Kim jest Hipolit Wielosławski?', '{"options": ["wujem Cezarego", "towarzyszem broni i przyjacielem", "nauczycielem", "bratem Laury"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Hipolit Wielosławski to towarzysz broni Cezarego z wojny polsko-bolszewickiej, który zaprasza go do rodzinnego majątku Nawłoć."}', '2025-10-24 22:16:55.076', '2025-10-24 22:16:55.076', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evacl010sqhd9xe7b03h9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Jak ma na imię ukochana Cezarego z Nawłoci?', '{"options": ["Karolina", "Wanda", "Laura", "Jadwiga"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Laura Kościeniecka to piękna wdowa z sąsiedniego majątku Leniec, w której Cezary się zakochuje."}', '2025-10-24 22:16:55.078', '2025-10-24 22:16:55.078', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaco010tqhd9nlttc152', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Za kogo wychodzi Laura Kościeniecka?', '{"options": ["za Cezarego", "za Hipolita", "za Władysława Barwickiego", "pozostaje wdową"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Laura wychodzi za mąż za Władysława Barwickiego z powodów finansowych - musi spłacić długi ciążące na majątku."}', '2025-10-24 22:16:55.08', '2025-10-24 22:16:55.08', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evacq010uqhd99rc4vqd4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Kim jest Karolina Szarłatowiczówna?', '{"options": ["siostrą Hipolita", "daleka krewna Wielosławskich, sierota", "żoną księdza", "służącą"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Karolina to daleka krewna Wielosławskich, sierota, która pracuje jako gospodyni w Nawłoci i zakochuje się w Cezarym."}', '2025-10-24 22:16:55.082', '2025-10-24 22:16:55.082', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evacs010vqhd9szkygbpa', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Jak umiera Karolina?', '{"options": ["w wypadku", "na gruźlicę", "zostaje otruta strychniną", "popełnia samobójstwo"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Karolina umiera otruta strychniną - prawdopodobnie przez zazdrosną Wandę Okszyńską, która również kochała Cezarego."}', '2025-10-24 22:16:55.084', '2025-10-24 22:16:55.084', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evacu010wqhd9enlriuww', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Gdzie Cezary mieszka po powrocie do Warszawy?', '{"options": ["w hotelu", "u Gajowca", "u Buławnika przy ulicy Miłej", "w akademiku"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Cezary mieszka u kolegi Buławnika przy ulicy Miłej w dzielnicy żydowskiej, w nędznych warunkach."}', '2025-10-24 22:16:55.087', '2025-10-24 22:16:55.087', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evacx010xqhd9vj21vh50', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Kim jest Szymon Gajowiec?', '{"options": ["komunistą", "wysokim urzędnikiem państwowym", "profesorem uniwersytetu", "księdzem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Szymon Gajowiec to wysoki urzędnik państwowy (''wiceminister''), który zatrudnia Cezarego jako sekretarza przy pisaniu książki o Polsce."}', '2025-10-24 22:16:55.089', '2025-10-24 22:16:55.089', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evacz010yqhd98b0giyfk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Kim jest Antoni Lulek?', '{"options": ["oficerem wojska", "studentem prawa i ideowcem komunistycznym", "dziennikarzem", "lekarzem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Antoni Lulek to student prawa, chorowity idealista komunistyczny, który stopniowo wpływa na Cezarego i wciąga go w działalność rewolucyjną."}', '2025-10-24 22:16:55.091', '2025-10-24 22:16:55.091', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evad1010zqhd9ql0k5j4b', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Gdzie odbywa się tajne zebranie komunistyczne?', '{"options": ["w piwnicy", "w lesie", "w biurze firmy ''Polex''", "na uniwersytecie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Tajne zebranie komunistyczne odbywa się w biurze firmy ''Polex - Polski eksport manufaktury i ziemiopłodów'', która służy jako przykrywka."}', '2025-10-24 22:16:55.094', '2025-10-24 22:16:55.094', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evad40110qhd9nlsbb8sl', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Dlaczego Cezary wybiega z zebrania komunistycznego?', '{"options": ["bo się boi policji", "bo musi iść na wykłady", "nie może znieść oskarżeń o tortury w polskich więzieniach", "kłóci się z Lulkiem"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Cezary nie wytrzymuje napięcia, gdy słyszy szczegółowe oskarżenia o torturach stosowanych w polskich więzieniach - jest wstrząśnięty i zdezorientowany."}', '2025-10-24 22:16:55.096', '2025-10-24 22:16:55.096', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evad60111qhd9ffwiduk8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Gdzie Laura spotyka się z Cezarym w Warszawie?', '{"options": ["w kawiarni", "w teatrze", "w Ogrodzie Saskim przy fontannie", "w hotelu"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Laura umawia się z Cezarym w Ogrodzie Saskim obok fontanny, gdzie dochodzi do ich ostatniego dramatycznego spotkania."}', '2025-10-24 22:16:55.099', '2025-10-24 22:16:55.099', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evad90112qhd9fay3hjrr', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Jak kończy się powieść?', '{"options": ["Cezary wraca do Nawłoci", "Cezary prowadzi komunistyczną manifestację pod Belweder", "Cezary wyjeżdża za granicę", "Cezary popełnia samobójstwo"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Powieść kończy się sceną, w której Cezary w żołnierskim mundurze prowadzi komunistyczną manifestację robotniczą pod Belweder."}', '2025-10-24 22:16:55.101', '2025-10-24 22:16:55.101', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evadb0113qhd9la9ybvof', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Co oznacza tytuł ''Przedwiośnie''?', '{"options": ["porę roku", "nazwę majątku", "czas niepewnych nadziei przed prawdziwym odrodzeniem", "pseudonim bohatera"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Przedwiośnie to metafora czasu budzących się nadziei, ale niepewnego, pełnego zwodniczych ocieplień - jak pierwsze lata niepodległej Polski."}', '2025-10-24 22:16:55.103', '2025-10-24 22:16:55.103', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evadd0114qhd9aemz1wh1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Jaki jest stosunek Jadwigi Barykowej do Rosji?', '{"options": ["całkowicie się zasymilowała", "nigdy się nie zaaklimatyzowała, tęskni za Siedlcami", "kocha Rosję bardziej niż Polskę", "jest obojętna"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Jadwiga nigdy się nie zaaklimatyzowała w Rosji, nie nauczyła się dobrze rosyjskiego i całe życie tęskniła za rodzinnymi Siedlcami."}', '2025-10-24 22:16:55.106', '2025-10-24 22:16:55.106', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evadf0115qhd9awwoeegh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Który z bohaterów reprezentuje typ polskiego karierowicza w carskiej Rosji?', '{"options": ["Cezary Baryka", "Seweryn Baryka", "Antoni Lulek", "Szymon Gajowiec"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Seweryn Baryka to typowy polski karierowicz w carskiej Rosji - bez wykształcenia, ale inteligentny, robi karierę urzędniczą, dochodzi do bogactwa."}', '2025-10-24 22:16:55.108', '2025-10-24 22:16:55.108', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evadh0116qhd9d2rbsuif', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Co się stało z ojcem Cezarego?', '{"options": ["wrócił do Polski", "został zastrzelony podczas próby ucieczki z więzienia", "zmarł na chorobę", "wyjechał za granicę"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Seweryn Baryka został aresztowany przez bolszewików, uwięziony na statku-więzieniu i zastrzelony podczas próby ucieczki wpław."}', '2025-10-24 22:16:55.11', '2025-10-24 22:16:55.11', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evadk0117qhd95ubftegc', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Jaki konflikt wewnętrzny przeżywa Cezary w Warszawie?', '{"options": ["między miłością a obowiązkiem", "między wiarą a ateizmem", "między patriotyzmem a rewolucyjnymi ideami komunistycznymi", "między nauką a pracą"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Cezary jest rozdarty między patriotyzmem (walczył za Polskę) a pokusą rewolucyjnych idei komunistycznych głoszonych przez Lulka."}', '2025-10-24 22:16:55.112', '2025-10-24 22:16:55.112', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evadm0118qhd9cyqquhw7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Dlaczego Laura nie może być z Cezarym po ślubie z Barwickim?', '{"options": ["nie kocha go", "Barwicki jej zabrania", "związało ją słowo honoru", "wyjeżdża za granicę"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Laura mówi Cezaremu podczas spotkania w Warszawie, że związało ją dane Barwickiemu słowo honoru, które jest dla niej ważniejsze niż miłość."}', '2025-10-24 22:16:55.114', '2025-10-24 22:16:55.114', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evado0119qhd93967xew9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Co symbolizuje przemiana Cezarego od żołnierza do rewolucjonisty?', '{"options": ["zwykłą zmianę poglądów", "tragiczne rozdźwięki polskiego ''przedwiośnia'' i rozczarowanie rzeczywistością", "wpływ propagandy", "chorobę psychiczną"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Droga Cezarego symbolizuje tragiczne rozdźwięki pierwszych lat niepodległości - od entuzjazmu do rozczarowania rzeczywistością społeczną."}', '2025-10-24 22:16:55.116', '2025-10-24 22:16:55.116', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evadq011aqhd9acnu9fqj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Jaką dzielnicę Warszawy obserwuje Cezary mieszkając u Buławnika?', '{"options": ["arystokratyczną", "żydowską", "robotniczą Wolę", "Stare Miasto"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Mieszkając przy ulicy Miłej, Cezary codziennie obserwuje dzielnicę żydowską - jej biedę, handel, specyficzne życie getta."}', '2025-10-24 22:16:55.118', '2025-10-24 22:16:55.118', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evads011bqhd9blc6o8eq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Jaki jest stosunek narratora do różnych klas społecznych w powieści?', '{"options": ["idealizuje ziemiaństwo", "gloryfikuje proletariat", "krytycznie przedstawia wszystkie klasy", "jest całkowicie neutralny"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Żeromski krytycznie przedstawia wszystkie klasy społeczne - zarówno ziemiaństwo, jak i biedotę miejską czy działaczy komunistycznych."}', '2025-10-24 22:16:55.12', '2025-10-24 22:16:55.12', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evadu011cqhd999ft3i8j', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Co Cezary robi batem w Leńcu?', '{"options": ["bije konia", "walczy z Barwickim", "uderza Laurę po twarzy", "niszczy meble"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "W szale zazdrości i gniewu Cezary uderza Laurę szpicrutą przez twarz, gdy ta staje w obronie Barwickiego."}', '2025-10-24 22:16:55.123', '2025-10-24 22:16:55.123', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evadw011dqhd9qnv1ox75', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 2, 'Dopasuj postacie do ich ról w powieści.', '{"leftColumn": [{"id": "A", "text": "Seweryn Baryka"}, {"id": "B", "text": "Laura Kościeniecka"}, {"id": "C", "text": "Antoni Lulek"}, {"id": "D", "text": "Szymon Gajowiec"}], "rightColumn": [{"id": 1, "text": "student prawa, komunista"}, {"id": 2, "text": "ojciec Cezarego, urzędnik w Baku"}, {"id": 3, "text": "wysoki urzędnik państwowy"}, {"id": 4, "text": "piękna wdowa z Leńca"}], "matchingType": "character_role"}', '[[0, 1], [1, 3], [2, 0], [3, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Seweryn to ojciec-urzędnik, Laura to wdowa z Leńca, Lulek to student-komunista, Gajowiec to urzędnik państwowy."}', '2025-10-24 22:16:55.125', '2025-10-24 22:16:55.125', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evadz011eqhd9youcqqvz', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 2, 'Które miejsca odwiedza Cezary podczas swojej wędrówki? (wybierz wszystkie poprawne)', '{"options": ["Baku", "Nawłoć", "Petersburg", "Warszawę", "Leniec", "Kraków"]}', '[0, 1, 3, 4]', NULL, '{historical_literary,closed_multiple,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Cezary mieszka w Baku (dzieciństwo), Nawłoci (po wojnie), Warszawie (studia) i odwiedza Leniec (majątek Laury). Nie ma wzmianki o Petersburgu czy Krakowie."}', '2025-10-24 22:16:55.127', '2025-10-24 22:16:55.127', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evae1011fqhd9t9lic9m3', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 3, 'Które cechy charakteryzują Cezarego Barykę? (wybierz wszystkie poprawne)', '{"options": ["idealizm i podatność na wpływy", "konsekwencja w działaniu", "impulsywność i gwałtowność", "wewnętrzne rozdarcie", "cynizm i obojętność", "wrażliwość na krzywdę"]}', '[0, 2, 3, 5]', NULL, '{historical_literary,closed_multiple,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Cezary jest idealistą podatnym na wpływy, impulsywny, wewnętrznie rozdarty i wrażliwy. Nie jest konsekwentny ani cyniczny."}', '2025-10-24 22:16:55.129', '2025-10-24 22:16:55.129', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evalf014rqhd936iqyfws', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Co było przyczyną zajazdu na Soplicowo?', '{"options": ["Chęć rabunku majątku", "Zemsta polityczna", "Spór o własność zamku i gniew Dobrzyńskich na Sopliców", "Rozkaz Napoleona"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Zajazd wywołał spór prawny o zamek Horeszków oraz urazy osobiste szlachty zaściankowej, zwłaszcza Dobrzyńskich, do Soplicy."}', '2025-10-24 22:16:55.395', '2025-10-24 22:16:55.395', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evae3011gqhd9xwp9hm0o', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 2, 'Uzupełnij informacje o fabule powieści.', '{"gaps": [{"id": 1, "options": ["Warszawie", "Moskwie", "Baku", "Kijowie"]}, {"id": 2, "options": ["lekarz", "inżynier i urzędnik", "nauczyciel", "kupiec"]}, {"id": 3, "options": ["Rosji", "Niemiec", "Polski", "Francji"]}, {"id": 4, "options": ["światowej", "polsko-bolszewickiej", "napoleońskiej", "krymskiej"]}], "textWithGaps": "Cezary Baryka wychowuje się w [1], gdzie jego ojciec pracuje jako [2]. Po rewolucji bolszewickiej ucieka z matką do [3], gdzie bierze udział w wojnie [4]."}', '[2, 1, 2, 1]', NULL, '{historical_literary,closed_multiple,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Cezary wychowuje się w Baku, gdzie ojciec jest inżynierem i urzędnikiem, ucieka do Polski i walczy w wojnie polsko-bolszewickiej."}', '2025-10-24 22:16:55.131', '2025-10-24 22:16:55.131', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evae5011hqhd9ilbei24d', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 3, 'Dopasuj motywy do części powieści, w których dominują.', '{"leftColumn": [{"id": "A", "text": "Utrata iluzji i śmierć rodziców"}, {"id": "B", "text": "Miłość i zdrada"}, {"id": "C", "text": "Bieda i rewolucja"}], "rightColumn": [{"id": 1, "text": "Część I - Szklane domy"}, {"id": 2, "text": "Część II - Nawłoć"}, {"id": 3, "text": "Część III - Wiatr od wschodu"}], "matchingType": "motifs_parts"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Część I - utrata iluzji w Baku, część II - romans w Nawłoci, część III - bieda i pokusa rewolucji w Warszawie."}', '2025-10-24 22:16:55.134', '2025-10-24 22:16:55.134', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evae7011iqhd9lti70x9a', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 2, 'Które kobiety są związane z Cezarym? (wybierz wszystkie)', '{"options": ["Laura Kościeniecka", "Karolina Szarłatowiczówna", "Eurydyka Wielosławska", "Wanda Okszyńska", "Ismena Barykowa", "towarzyszka Karyla"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Z Cezarym związane są: Laura (jego miłość), Karolina (kocha go i umiera), Wanda (podkochuje się, prawdopodobnie otruła Karolinę)."}', '2025-10-24 22:16:55.136', '2025-10-24 22:16:55.136', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evae9011jqhd9ionnu7pj', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 2, 'Wyjaśnij symbolikę tytułu ''Przedwiośnie'' w kontekście powieści.', '{"instruction": "Opisz znaczenie metafory przedwiośnia dla Polski lat 20. XX wieku. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie na czas niepewnych nadziei (1 pkt)", "odniesienie do pierwszych lat niepodległości Polski (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,interwar,batch-2025-01}', '{"keyWords": ["nadzieje", "niepewność", "niepodległość", "pierwsze lata", "zawieszenie"], "expectedAnswer": "Przedwiośnie to metafora pierwszych lat niepodległej Polski - czasu budzących się nadziei, ale niepewnego, pełnego zwodniczych ocieplień i powrotów zimy. To okres, gdy wszystko jest możliwe, ale nic nie jest pewne. Symbolizuje stan zawieszenia między marzeniem o lepszej przyszłości a brutalną rzeczywistością."}', '2025-10-24 22:16:55.138', '2025-10-24 22:16:55.138', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaec011kqhd9k9u2wcnl', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 2, 'Opisz, co symbolizują ''szklane domy'' w powieści.', '{"instruction": "Wyjaśnij metaforę szklanych domów i jej różne znaczenia. (40-60 słów)"}', NULL, '{"criteria": ["wskazanie na utopijne wizje (1 pkt)", "kruchość/iluzoryczność tych wizji (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,interwar,batch-2025-01}', '{"keyWords": ["utopia", "wizje", "kruche", "iluzja", "idealne społeczeństwo"], "expectedAnswer": "Szklane domy symbolizują utopijne wizje idealnego społeczeństwa - zarówno te Seweryna o dobrobycie w carskiej Rosji, jak i bolszewickie o równości społecznej. Są piękne, ale kruche i iluzoryczne - łatwo się rozpadają przy zderzeniu z rzeczywistością. Reprezentują wszystkie złudzenia bohaterów."}', '2025-10-24 22:16:55.14', '2025-10-24 22:16:55.14', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaee011lqhd956xeumfi', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 3, 'Scharakteryzuj ewolucję Cezarego Baryki od idealisty do rewolucjonisty.', '{"instruction": "Opisz przemiany bohatera i ich przyczyny. (60-80 słów)"}', NULL, '{"criteria": ["entuzjazm wojenny i patriotyzm (1 pkt)", "rozczarowanie rzeczywistością w Nawłoci i Warszawie (1 pkt)", "przystąpienie do komunistów jako akt autodestrukcji (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-3,interwar,batch-2025-01}', '{"keyWords": ["idealista", "patriota", "rozczarowanie", "bieda", "komunizm", "autodestrukcja"], "expectedAnswer": "Cezary zaczyna jako młody idealista walczący za Polskę w wojnie 1920 roku, pełen patriotycznego entuzjazmu. W Nawłoci odkrywa zepsucie ziemiaństwa i niemożność miłości. W Warszawie widzi biedę, niesprawiedliwość społeczną, tortury w więzieniach. Rozczarowany, ulega wpływowi komunisty Lulka. Finalna scena - prowadzi manifestację przeciw Polsce, za którą walczył - to akt ostatecznej autodestrukcji i symbolicnego odrzucenia wszystkich wartości."}', '2025-10-24 22:16:55.142', '2025-10-24 22:16:55.142', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaeh011mqhd9f01xr7oo', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Jaka jest wymowa ideowa zakończenia powieści?', '{"options": ["optymistyczna - zwycięstwo rewolucji", "pesymistyczna - klęska ideałów i autodestrukcja bohatera", "neutralna - brak oceny", "patriotyczna - triumf Polski"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Zakończenie jest pesymistyczne - Cezary prowadząc manifestację przeciw Polsce symbolizuje klęskę wszystkich ideałów i tragiczną autodestrukcję pokolenia."}', '2025-10-24 22:16:55.145', '2025-10-24 22:16:55.145', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaej011nqhd966pd8a53', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'W jakim roku została ukończona powieść ''Przedwiośnie''?', '{"options": ["1920", "1922", "1924", "1926"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Stefan Żeromski ukończył ''Przedwiośnie'' 21 września 1924 roku w Konstancinie."}', '2025-10-24 22:16:55.147', '2025-10-24 22:16:55.147', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evael011oqhd9z5j91qm7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Kto jest narratorem powieści?', '{"options": ["Cezary Baryka (pierwszoosobowy)", "narrator wszechwiedzący trzecioosobowy", "multiple narrators", "narrator personalny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Powieść ma narratora wszechwiedzącego trzecioosobowego, który zna myśli i uczucia wszystkich postaci, komentuje wydarzenia."}', '2025-10-24 22:16:55.149', '2025-10-24 22:16:55.149', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaen011pqhd90yvnq8ys', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 3, 'Które problemy społeczne porusza Żeromski? (wybierz wszystkie)', '{"options": ["nierówności społeczne i bieda", "problem mniejszości żydowskiej", "zacofanie wsi", "korupcja ziemiaństwa", "kwestia niepodległości", "konflikty religijne"]}', '[0, 1, 2, 3, 4]', NULL, '{historical_literary,closed_multiple,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Żeromski porusza: biedę i nierówności, problem żydowski (getto), zacofanie wsi, zepsucie ziemiaństwa, problemy młodego państwa. Nie ma głównego wątku religijnego."}', '2025-10-24 22:16:55.151', '2025-10-24 22:16:55.151', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaep011qqhd9hxd789ph', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Jakie znaczenie ma postać księdza Anastazego?', '{"options": ["główny antagonista", "reprezentant tradycyjnych wartości i wiary", "rewolucjonista", "nie ma większego znaczenia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Ksiądz Anastazy Dyaczyński reprezentuje tradycyjne wartości katolickie, próbuje kierować Cezarego ku wierze, proponuje spowiedź."}', '2025-10-24 22:16:55.154', '2025-10-24 22:16:55.154', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaes011rqhd9knwy2jri', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 2, 'Dopasuj miejsca do wydarzeń, które się tam rozgrywają.', '{"leftColumn": [{"id": "A", "text": "Baku"}, {"id": "B", "text": "Nawłoć"}, {"id": "C", "text": "Warszawa"}, {"id": "D", "text": "Chłodek"}], "rightColumn": [{"id": 1, "text": "obserwacja biedy wiejskiej"}, {"id": 2, "text": "aresztowanie ojca i ucieczka"}, {"id": 3, "text": "romans z Laurą i śmierć Karoliny"}, {"id": 4, "text": "zebranie komunistyczne"}], "matchingType": "places_events"}', '[[0, 1], [1, 2], [2, 3], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Baku - rewolucja i ucieczka, Nawłoć - romans i tragedia, Warszawa - działalność komunistyczna, Chłodek - obserwacja biedy."}', '2025-10-24 22:16:55.156', '2025-10-24 22:16:55.156', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaeu011sqhd9x7d5nj35', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Jak Żeromski przedstawia polską inteligencję?', '{"options": ["wyłącznie pozytywnie", "jako zbawców narodu", "krytycznie - jako niezdolną do działania", "nie przedstawia jej wcale"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Żeromski krytycznie przedstawia inteligencję - Gajowiec to teoretyk bez wpływu na rzeczywistość, inni to marzyciele niezdolni do realnego działania."}', '2025-10-24 22:16:55.158', '2025-10-24 22:16:55.158', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaew011tqhd9l3d2vx0y', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 2, 'Opisz relację Cezarego z Laurą Kościeniecką.', '{"instruction": "Scharakteryzuj ich związek i jego tragiczny finał. (50-70 słów)"}', NULL, '{"criteria": ["namiętny romans w Nawłoci (1 pkt)", "niemożność bycia razem - ślub z Barwickim i honor (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,interwar,batch-2025-01}', '{"keyWords": ["romans", "namiętność", "Barwicki", "bat", "honor", "niemożność"], "expectedAnswer": "Cezary i Laura przeżywają namiętny romans w Nawłoci - potajemne schadzki, namiętność w karecie. Jednak Laura musi wyjść za Barwickiego z powodów finansowych. Gdy Cezary w szale zazdrości uderza ją batem i robi awanturę, przyspiesza jej ślub. W Warszawie Laura wyznaje, że kocha Cezarego, ale związało ją słowo honoru dane mężowi - nie mogą być razem."}', '2025-10-24 22:16:55.16', '2025-10-24 22:16:55.16', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaey011uqhd9hwzrvp9l', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Co oznaczają ''czerwone sztandary'' wspominane przez Cezarego?', '{"options": ["polskie flagi", "symbole rewolucji bolszewickiej", "dekoracje na balu", "sztandary wojskowe"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Czerwone sztandary to symbol rewolucji bolszewickiej, która przyniosła śmierć rodzicom Cezarego i zniszczyła świat jego dzieciństwa."}', '2025-10-24 22:16:55.163', '2025-10-24 22:16:55.163', 'Przedwiośnie');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaf1011vqhd9a6nxxe6v', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 3, 2, 'Które zdanie najlepiej opisuje funkcję motywu snu w tragedii?', '{"options": ["Sen jest tylko tłem dla wydarzeń", "Sen to metafora śmierci i zapomnienia", "Sen symbolizuje niewinność i spokój sumienia, którego Makbet się pozbawia", "Sen reprezentuje marzenia o władzy"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,renaissance,batch-2025-01}', '{"explanation": "Sen w Makbecie symbolizuje niewinność, spokój sumienia i naturalny porządek, które bohater niszczy przez zbrodnię."}', '2025-10-24 22:16:55.165', '2025-10-24 22:16:55.165', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaf3011wqhd909g4ll7u', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 2, 'Dlaczego Shakespeare sprawia, że tylko Makbet widzi ducha Banka?', '{"options": ["To projekcja jego poczucia winy i znak rozpadu psychicznego", "Banko rzeczywiście nawiedza tylko Makbeta", "Inni udają, że nie widzą ducha", "To efekt trucizny w winie"]}', '0', NULL, '{historical_literary,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "Selektywna widoczność ducha sugeruje, że to projekcja psychologiczna - manifestacja winy i rozpadu umysłu Makbeta."}', '2025-10-24 22:16:55.167', '2025-10-24 22:16:55.167', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaf5011xqhd9y5p88hmw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 3, 'Jak interpretować dwuznaczność przepowiedni wiedźm w kontekście problemu wolnej woli?', '{"options": ["Przepowiednie są jasne - Makbet nie ma wyboru", "Wiedźmy kłamią, wszystko zależy od Makbeta", "To self-fulfilling prophecy - przepowiednie spełniają się właśnie przez działania Makbeta", "Przepowiednie są przypadkowe i nie mają znaczenia"]}', '2', NULL, '{historical_literary,closed_single,difficulty-5,renaissance,batch-2025-01}', '{"explanation": "Shakespeare celowo pozostawia kwestię nierozstrzygniętą - przepowiednie mogą być samospełniającą się przepowiednią."}', '2025-10-24 22:16:55.17', '2025-10-24 22:16:55.17', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaf7011yqhd9u6gen232', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 2, 'W którym momencie następuje perypetia (punkt zwrotny) w tragedii?', '{"options": ["Zabójstwo Duncana", "Pierwsze spotkanie z wiedźmami", "Zabójstwo Banka", "Pojawienie się ducha Banka na uczcie"]}', '3', NULL, '{historical_literary,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "Scena z duchem to punkt zwrotny - Makbet traci kontrolę publicznie, ujawnia swój rozpad psychiczny."}', '2025-10-24 22:16:55.172', '2025-10-24 22:16:55.172', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaf9011zqhd9lbzhgn7v', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 3, 2, 'Co symbolizuje niemożność wypowiedzenia ''Amen'' przez Makbeta po morderstwie?', '{"options": ["Utratę łaski Bożej i odcięcie od sacrum", "Zmęczenie po walce", "Strach przed odkryciem", "Brak wiary religijnej"]}', '0', NULL, '{historical_literary,closed_single,difficulty-3,renaissance,batch-2025-01}', '{"explanation": "Niemożność modlitwy symbolizuje duchowe potępienie - Makbet odciął się od Boga przez swoją zbrodnię."}', '2025-10-24 22:16:55.174', '2025-10-24 22:16:55.174', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evafb0120qhd956hfqwwi', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 2, 'Czym różni się podejście Makbeta i Banka do przepowiedni?', '{"options": ["Obaj natychmiast wierzą", "Obaj są sceptyczni", "Makbet jest sceptyczny, Banko wierzy", "Makbet ulega pokusie, Banko zachowuje ostrożność i moralność"]}', '3', NULL, '{historical_literary,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "Banko zachowuje dystans i integralność moralną, podczas gdy Makbet pozwala ambicji zdominować sumienie."}', '2025-10-24 22:16:55.176', '2025-10-24 22:16:55.176', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evafd0121qhd9rmk1ixdm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 3, 'Jak można interpretować halucynacje Makbeta z perspektywy psychologicznej?', '{"options": ["To objawy schizofrenii", "Projekcje stłumionych treści psychicznych i manifestacja PTSD", "Efekt zatrucia", "Zwykłe zmęczenie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,renaissance,batch-2025-01}', '{"explanation": "Halucynacje to projekcje wypartej winy i traumy - Shakespeare wyprzedza odkrycia psychologii głębi."}', '2025-10-24 22:16:55.178', '2025-10-24 22:16:55.178', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaff0122qhd9l34ev1l6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 2, 'Jak Lady Makbet podważa elżbietańskie normy płciowe?', '{"options": ["Jest posłuszną żoną", "Nie interesuje się polityką", "Odrzuca ''kobiecą'' słabość i przejmuje męską rolę w małżeństwie", "Jest typową damą dworu"]}', '2', NULL, '{historical_literary,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "Lady Makbet aktywnie odrzuca kobiecość, dominuje nad mężem i przejmuje inicjatywę - łamie wszystkie konwencje epoki."}', '2025-10-24 22:16:55.18', '2025-10-24 22:16:55.18', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evafh0123qhd9qpsr25nj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 3, 2, 'Dlaczego temat królobójstwa był szczególnie aktualny w 1606 roku?', '{"options": ["Trwała wojna domowa", "Niedawny Spisek Prochowy (1605) - próba zabicia króla Jakuba I", "Śmierć Elżbiety I", "Powstanie w Szkocji"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,renaissance,batch-2025-01}', '{"explanation": "Spisek Prochowy z 1605 roku uczynił temat królobójstwa niezwykle aktualnym i niebezpiecznym."}', '2025-10-24 22:16:55.182', '2025-10-24 22:16:55.182', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evafj0124qhd9w7eyz2p2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 3, 'Jak Shakespeare przedstawia problem teodycei (sprawiedliwości Bożej) w finale?', '{"options": ["Bóg bezpośrednio karze Makbeta", "Zło samo się niszczy, porządek moralny zostaje przywrócony przez ludzkie działania", "Nie ma żadnej sprawiedliwości", "Wiedźmy wymierzają karę"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,renaissance,batch-2025-01}', '{"explanation": "Shakespeare pokazuje, że zło nosi w sobie zarodek samozniszczenia - porządek przywracają ludzie, ale według wyższego planu."}', '2025-10-24 22:16:55.184', '2025-10-24 22:16:55.184', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evafl0125qhd99lx704bd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 2, 'Dlaczego Makbet jest najkrótszą tragedią Shakespeare''a?', '{"options": ["Shakespeare się spieszył", "Intensyfikacja dramatyczna - brak wątków pobocznych pogłębia koncentrację na psychologii zbrodni", "Część tekstu zaginęła", "Był to skrót na potrzeby dworu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "Kondensacja akcji i eliminacja pobocznych wątków intensyfikuje napięcie i skupienie na psychologicznym dramacie."}', '2025-10-24 22:16:55.186', '2025-10-24 22:16:55.186', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evafn0126qhd9e6i4mqvr', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 3, 2, 'Jaki efekt osiąga Shakespeare przez kontrast między językiem Makbeta na początku i końcu dramatu?', '{"options": ["Pokazuje degradację umysłu - od poezji do nihilistycznej prozy", "Nie ma różnicy w języku", "Język staje się bardziej wyszukany", "Makbet przestaje mówić"]}', '0', NULL, '{historical_literary,closed_single,difficulty-3,renaissance,batch-2025-01}', '{"explanation": "Ewolucja od poetyckich metafor do nihilistycznych stwierdzeń pokazuje duchowy i psychiczny rozpad bohatera."}', '2025-10-24 22:16:55.188', '2025-10-24 22:16:55.188', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evafp0127qhd9whyfqbq6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 3, 'Które stwierdzenie najlepiej opisuje moralną wymowę tragedii?', '{"options": ["Władza absolutna deprawuje absolutnie, ale człowiek zachowuje wolność wyboru", "Los jest z góry przesądzony", "Zło zawsze zwycięża", "Moralność jest względna"]}', '0', NULL, '{historical_literary,closed_single,difficulty-5,renaissance,batch-2025-01}', '{"explanation": "Shakespeare pokazuje destrukcyjną siłę władzy, ale podkreśla odpowiedzialność człowieka za swoje wybory."}', '2025-10-24 22:16:55.19', '2025-10-24 22:16:55.19', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evafs0128qhd9h1m1wjig', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 2, 'Co symbolizuje scena mycia rąk przez Lady Makbet w kontekście całego dramatu?', '{"options": ["Higienę w średniowieczu", "Obsesję czystości", "Ironiczne odwrócenie jej słów o ''odrobinie wody'' - wina jest niezmywalna", "Rytuał pogrzebowy"]}', '2', NULL, '{historical_literary,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "To tragiczna ironia - kobieta mówiąca, że ''trochę wody'' zmyje zbrodnię, nie może zmyć wyimaginowanej krwi."}', '2025-10-24 22:16:55.192', '2025-10-24 22:16:55.192', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evafu0129qhd911v1jn8a', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 3, 'Jak nihilizm Makbeta (''życie to opowieść idioty'') odnosi się do elżbietańskiego światopoglądu?', '{"options": ["Potwierdza chrześcijańską wizję świata", "Jest typowy dla epoki", "Radykalnie podważa sens istnienia w uporządkowanym kosmosie Great Chain of Being", "Nie ma związku z epoką"]}', '2', NULL, '{historical_literary,closed_single,difficulty-5,renaissance,batch-2025-01}', '{"explanation": "Nihilizm Makbeta to radykalne zaprzeczenie elżbietańskiej wizji uporządkowanego, sensownego kosmosu."}', '2025-10-24 22:16:55.194', '2025-10-24 22:16:55.194', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evafw012aqhd9tv5qrdbd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 2, 'Które źródło NIE było inspiracją dla Shakespeare''a przy pisaniu Makbeta?', '{"options": ["Kroniki Holinsheda", "Historia Szkocji Hectora Boece''a", "Daemonologie króla Jakuba I", "Boska Komedia Dantego"]}', '3', NULL, '{historical_literary,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "Shakespeare czerpał z Holinsheda, Boece''a i traktatu Jakuba I o czarach, ale nie z Dantego."}', '2025-10-24 22:16:55.196', '2025-10-24 22:16:55.196', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evafy012bqhd9zcfaqn3k', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 3, 2, 'Dlaczego rola Lady Makbet była szczególnie wymagająca w teatrze elżbietańskim?', '{"options": ["Była za długa", "Wymagała śpiewu", "Grali ją chłopcy, którzy musieli przekonująco wcielić się w dominującą kobietę", "Wymagała akrobacji"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,renaissance,batch-2025-01}', '{"explanation": "W teatrze elżbietańskim role kobiece grali chłopcy - rola dominującej, dojrzałej Lady Makbet była wyzwaniem."}', '2025-10-24 22:16:55.198', '2025-10-24 22:16:55.198', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evag0012cqhd9yu700w8z', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 3, 'Które interpretacje motywu krwi są uzasadnione w tekście? (wybierz wszystkie)', '{"options": ["Krew jako dziedzictwo i prawo do tronu", "Krew jako wina nie do odkupienia", "Krew jako ofiara religijna", "Krew jako więź rodzinna", "Krew jako znak męstwa wojennego"]}', '[0, 1, 3, 4]', NULL, '{historical_literary,closed_multiple,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "Krew funkcjonuje wieloznacznie: dynastia, wina, rodzina i wojenna chwała, ale nie jako ofiara religijna."}', '2025-10-24 22:16:55.2', '2025-10-24 22:16:55.2', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evag2012dqhd9zzqgeeg0', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 3, 'Dopasuj koncepcje filozoficzne do ich realizacji w dramacie', '{"leftColumn": [{"id": "A", "text": "Machiavellizm"}, {"id": "B", "text": "Determinizm"}, {"id": "C", "text": "Nihilizm"}, {"id": "D", "text": "Teodycea"}], "rightColumn": [{"id": 1, "text": "Monolog ''jutro, i jutro, i jutro''"}, {"id": 2, "text": "Cel uświęca środki - morderstwo dla władzy"}, {"id": 3, "text": "Przepowiednie jako przeznaczenie"}, {"id": 4, "text": "Przywrócenie porządku moralnego w finale"}], "matchingType": "philosophy_drama"}', '[[0, 1], [1, 2], [2, 0], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-5,renaissance,batch-2025-01}', '{"explanation": "Makbet realizuje machiavelizm, boryka się z determinizmem, popada w nihilizm, a finał przywraca teodiceę."}', '2025-10-24 22:16:55.203', '2025-10-24 22:16:55.203', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evag5012eqhd9ol7jmtea', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 3, 'Jak interpretować prośbę Lady Makbet o ''unsex me here''?', '{"options": ["Chce stać się mężczyzną", "Performatywne odrzucenie gender jako konstruktu społecznego ograniczającego działanie", "To tylko metafora", "Chce umrzeć"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,renaissance,batch-2025-01}', '{"explanation": "Lady Makbet rozumie płeć jako ograniczenie społeczne, które można performatywnie odrzucić dla osiągnięcia celów."}', '2025-10-24 22:16:55.205', '2025-10-24 22:16:55.205', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evag7012fqhd92750wiz6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 2, 'Z perspektywy psychoanalitycznej, czym są wiedźmy?', '{"options": ["Realnymi postaciami", "Projekcją Super-ego Makbeta", "Symbolem ojca", "Manifestacją Id - nieświadomych pragnień Makbeta"]}', '3', NULL, '{historical_literary,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "Wiedźmy można interpretować jako projekcję Id - wypowiadają stłumione, nieświadome pragnienia Makbeta."}', '2025-10-24 22:16:55.207', '2025-10-24 22:16:55.207', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evag9012gqhd9dwrh9x2p', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 3, 2, 'Jak Makbet odnosi się do jakubińskiej teorii Boskiego Prawa Królów?', '{"options": ["Popiera ją całkowicie", "Ignoruje kwestie polityczne", "Podważa ją, pokazując uzurpatora na tronie", "Ostatecznie potwierdza świętość prawowitej sukcesji"]}', '3', NULL, '{historical_literary,closed_single,difficulty-3,renaissance,batch-2025-01}', '{"explanation": "Dramat ostatecznie potwierdza Boskie Prawo - uzurpator upada, prawowity dziedzic (Malcolm) wraca."}', '2025-10-24 22:16:55.209', '2025-10-24 22:16:55.209', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evagb012hqhd9ayevwonx', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 3, 'Jak metafora ''życia jako kiepskiego aktora'' komentuje naturę teatru?', '{"options": ["Shakespeare krytykuje aktorów", "To autorefleksja o iluzorycznej naturze teatru i rzeczywistości", "Nie ma związku z teatrem", "To komplement dla aktorów"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,renaissance,batch-2025-01}', '{"explanation": "To metateatralny komentarz - teatr jako metafora życia podważa granicę między iluzją sceniczną a ''rzeczywistością''."}', '2025-10-24 22:16:55.212', '2025-10-24 22:16:55.212', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evagd012iqhd9yczb8y4i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 2, 'Jaka jest funkcja obrazowania choroby w dramacie?', '{"options": ["Szkocja pod rządami Makbeta jest ''chora'' - tyrania jako rak społeczny", "Opisuje prawdziwą epidemię", "Nie ma takiego obrazowania", "Odnosi się tylko do Lady Makbet"]}', '0', NULL, '{historical_literary,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "Choroba to rozbudowana metafora - tyrania Makbeta infekuje całą Szkocję jak zaraza."}', '2025-10-24 22:16:55.214', '2025-10-24 22:16:55.214', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evagg012jqhd9p75sykbp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 3, 2, 'Która przepowiednia NIE pojawia się w dramacie?', '{"options": ["Makbet będzie królem", "Synowie Banka będą królami", "Makbet umrze młodo", "Las Birnam przyjdzie do Dunsinane"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,renaissance,batch-2025-01}', '{"explanation": "Nie ma przepowiedni o wieku śmierci Makbeta - tylko o warunkach, w których może zginąć."}', '2025-10-24 22:16:55.216', '2025-10-24 22:16:55.216', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evagi012kqhd99y5dl9i5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 2, 'W którym momencie następuje anagnorisis (rozpoznanie) Makbeta?', '{"options": ["Gdy zabija Duncana", "Gdy spotyka wiedźmy", "Gdy dowiaduje się, że Makduf ''nie został zrodzony z kobiety''", "Gdy widzi ducha Banka"]}', '2', NULL, '{historical_literary,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "Anagnorisis następuje, gdy Makbet rozumie prawdziwą naturę przepowiedni - został oszukany."}', '2025-10-24 22:16:55.218', '2025-10-24 22:16:55.218', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evagk012lqhd93dussyux', 'ESSAY', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 5, 'Porównaj sposób przedstawienia zła w ''Makbecie'' z inną tragedią Shakespeare''a.', '{"instruction": "Przeanalizuj różnice w koncepcji zła między Makbetem a wybraną tragedią (Hamlet, Otello, Król Lear). Uwzględnij: źródło zła, rozwój, konsekwencje. (150-200 słów)"}', NULL, '{"criteria": ["Identyfikacja źródła zła w obu dramatach (1 pkt)", "Analiza rozwoju zła (1 pkt)", "Porównanie konsekwencji (1 pkt)", "Różnice w odpowiedzialności bohaterów (1 pkt)", "Synteza i wnioski (1 pkt)"], "maxScore": 5}', '{historical_literary,essay,difficulty-5,renaissance,batch-2025-01}', '{"keyWords": ["źródło zła", "świadomość", "wybór", "manipulacja", "konsekwencje", "odpowiedzialność"], "expectedAnswer": "W Makbecie zło rodzi się wewnątrz - z ambicji bohatera, choć katalizowane przez wiedźmy. W Otellu zło jest zewnętrzne - Jago manipuluje. Makbet świadomie wybiera zbrodnię, Otello jest oszukany. Rozwój: Makbet stopniowo się dehumanizuje, Otello zachowuje szlachetność do końca. Konsekwencje: Makbet niszczy całą Szkocję, Otello - tylko siebie i Desdemonę."}', '2025-10-24 22:16:55.22', '2025-10-24 22:16:55.22', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evalh014sqhd9pk0km8p8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Kto dowodził obroną Soplicowa podczas zajazdu?', '{"options": ["Sędzia", "Tadeusz", "Ksiądz Robak", "Maciej Rózeczka"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Ksiądz Robak (Jacek Soplica) dowodził obroną, choć jako ksiądz nie walczył sam, tylko dawał rady i organizował obronę."}', '2025-10-24 22:16:55.397', '2025-10-24 22:16:55.397', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evagm012mqhd90hb258n4', 'ESSAY', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 5, 'Czy Makbet jest ofiarą przeznaczenia czy własnych wyborów? Uzasadnij stanowisko.', '{"instruction": "Przeanalizuj problem determinizmu vs wolnej woli w tragedii. Odwołaj się do przepowiedni, decyzji bohatera i konstrukcji fabuły. (150-200 słów)"}', NULL, '{"criteria": ["Zdefiniowanie problemu (1 pkt)", "Argumenty za determinizmem (1 pkt)", "Argumenty za wolną wolą (1 pkt)", "Analiza ambiwalencji Shakespeare''a (1 pkt)", "Własne stanowisko z uzasadnieniem (1 pkt)"], "maxScore": 5}', '{historical_literary,essay,difficulty-5,renaissance,batch-2025-01}', '{"keyWords": ["determinizm", "wolna wola", "przepowiednie", "wybór", "self-fulfilling prophecy", "ambiwalencja"], "expectedAnswer": "Shakespeare celowo pozostawia kwestię nierozstrzygniętą. Za determinizmem: przepowiednie się spełniają dokładnie, Makbet wydaje się prowadzony. Za wolną wolą: przepowiednie nie mówią o morderstwie, Makbet sam decyduje o środkach. To self-fulfilling prophecy - przepowiednie spełniają się właśnie przez wybory Makbeta. Shakespeare sugeruje, że los i wybór są nierozdzielnie splecione."}', '2025-10-24 22:16:55.222', '2025-10-24 22:16:55.222', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evago012nqhd9hcy278y9', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 3, 'Wyjaśnij symbolikę dziecka w przepowiedniach i obrazach dramatu.', '{"instruction": "Przeanalizuj różne znaczenia motywu dziecka w Makbecie (60-80 słów)."}', NULL, '{"criteria": ["Dziecko jako symbol niewinności (1 pkt)", "Brak dzieci Makbeta - jałowość zła (1 pkt)", "Morderstwo dzieci jako przekroczenie ostatniej granicy (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-4,renaissance,batch-2025-01}', '{"keyWords": ["niewinność", "bezdzietność", "jałowość", "przyszłość", "morderstwo dzieci"], "expectedAnswer": "Dziecko symbolizuje niewinność, przyszłość i ciągłość. Makbetowie są bezdzietni - ich władza jest ''jałowa'', bez przyszłości. Zjawa dziecka w koronie to potomkowie Banka. Morderstwo dzieci Makdufa to ostateczne przekroczenie - atak na niewinność. ''Nie zrodzony z kobiety'' podważa naturalne narodziny."}', '2025-10-24 22:16:55.224', '2025-10-24 22:16:55.224', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evagq012oqhd9u1cb4rd8', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 3, 'Jak Shakespeare problematyzuje męskość w tragedii?', '{"instruction": "Omów kryzys męskości u Makbeta i innych postaci (80-100 słów)."}', NULL, '{"criteria": ["Męskość jako przemoc (1 pkt)", "Manipulacja przez kwestionowanie męskości (1 pkt)", "Paradoks - ''prawdziwa'' męskość (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-5,renaissance,batch-2025-01}', '{"keyWords": ["przemoc", "manipulacja", "paradoks", "toksyczna męskość", "prawdziwa męskość"], "expectedAnswer": "Makbet utożsamia męskość z przemocą i bezwzględnością. Lady Makbet manipuluje nim, kwestionując jego męskość. Paradoksalnie, im bardziej stara się udowodnić męskość przez przemoc, tym bardziej ją traci - staje się tchórzem. Prawdziwa męskość to panowanie nad namiętnościami (Banko, Makduf płaczący po rodzinie). Shakespeare krytykuje toksyczną męskość."}', '2025-10-24 22:16:55.227', '2025-10-24 22:16:55.227', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evagt012pqhd96tlxjn6x', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 3, 'Przeanalizuj metateatralne elementy w monologu ''życie to opowieść idioty''.', '{"instruction": "Wyjaśnij autorefleksyjność teatralną w nihilistycznym monologu (60-80 słów)."}', NULL, '{"criteria": ["Życie jako spektakl teatralny (1 pkt)", "Podważenie granicy iluzja/rzeczywistość (1 pkt)", "Komentarz do natury teatru (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-4,renaissance,batch-2025-01}', '{"keyWords": ["metateatr", "aktor", "iluzja", "rzeczywistość", "autorefleksja"], "expectedAnswer": "Makbet porównuje życie do kiepskiego aktora i bezsensownej opowieści - to metateatralny komentarz. Aktor grający Makbeta mówi o aktorstwie, podważając granicę między fikcją a rzeczywistością. Jeśli życie to teatr, to teatr jest życiem. Shakespeare sugeruje, że zarówno życie jak i teatr są iluzją."}', '2025-10-24 22:16:55.229', '2025-10-24 22:16:55.229', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evagv012qqhd9nlvnnb9y', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'RENAISSANCE', 3, 3, 'Jak dramat komentuje jakubińską koncepcję monarchii?', '{"instruction": "Omów polityczny wymiar tragedii w kontekście epoki Jakuba I (60-80 słów)."}', NULL, '{"criteria": ["Królobójstwo jako największa zbrodnia (1 pkt)", "Pochwała linii Banka (przodek Jakuba) (1 pkt)", "Przywrócenie prawowitego porządku (1 pkt)"], "maxScore": 3}', '{historical_literary,short_answer,difficulty-3,renaissance,batch-2025-01}', '{"keyWords": ["Boskie Prawo", "królobójstwo", "Banko", "Jakub I", "prawowita sukcesja"], "expectedAnswer": "Dramat potwierdza Boskie Prawo Królów - królobójstwo to zbrodnia przeciw Bogu i naturze. Szkocja cierpi pod uzurpatorem. Gloryfikacja Banka (mitycznego przodka Jakuba I) to pochlebstwo. Finał przywraca prawowitą sukcesję. Shakespeare ostrzega przed buntem, jednocześnie pokazując tyranię."}', '2025-10-24 22:16:55.231', '2025-10-24 22:16:55.231', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evagx012rqhd97pt0a6ps', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 3, 2, 'Gdzie występuje dramatyczna ironia w scenie mordowania Duncana?', '{"options": ["Duncan chwali gościnność Makbetów tuż przed śmiercią", "Makbet jest zaskoczony", "Lady Makbet śpi", "Straże są pijane"]}', '0', NULL, '{historical_literary,closed_single,difficulty-3,renaissance,batch-2025-01}', '{"explanation": "Duncan chwali zamek i gospodarzy jako przytulnych - dramatyczna ironia, bo widzowie wiedzą o planowanym morderstwie."}', '2025-10-24 22:16:55.234', '2025-10-24 22:16:55.234', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evagz012sqhd9n3eeumdl', 'CLOSED_SINGLE', 'LANGUAGE_USE', 'RENAISSANCE', 4, 2, 'Dlaczego wiedźmy mówią tetrametrem trocheicznym zamiast jambem?', '{"options": ["To błąd Shakespeare''a", "Rytm zaklęć odróżnia je od świata ludzkiego, tworzy hipnotyczny efekt", "Nie ma różnicy w metryce", "To wymóg teatralny"]}', '1', NULL, '{language_use,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "Trocheiczny tetrametr (akcent na pierwszej sylabie) brzmi jak zaklęcie, odróżnia nadprzyrodzone od ludzkiego."}', '2025-10-24 22:16:55.236', '2025-10-24 22:16:55.236', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evah1012tqhd98sof784d', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 3, 'Jak interpretować fakt, że Banko też widzi wiedźmy, ale tylko Makbet widzi sztyet i ducha?', '{"options": ["Przypadek dramaturgiczny", "Wiedźmy są zewnętrzne/obiektywne, halucynacje są wewnętrzne/subiektywne", "Banko kłamie", "Wszystko jest halucynacją"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,renaissance,batch-2025-01}', '{"explanation": "Shakespeare rozróżnia: wiedźmy jako katalizator zewnętrzny vs halucynacje jako projekcje winy."}', '2025-10-24 22:16:55.238', '2025-10-24 22:16:55.238', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evah3012uqhd9m412mxsj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 3, 2, 'Która postać została dodana przez Shakespeare''a, nie występuje w kronikach?', '{"options": ["Banko", "Duncan", "Lady Makbet jako współsprawczyni", "Malcolm"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,renaissance,batch-2025-01}', '{"explanation": "W kronikach żona Makbeta nie odgrywa aktywnej roli - Shakespeare uczynił ją współsprawczynią."}', '2025-10-24 22:16:55.24', '2025-10-24 22:16:55.24', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpbl002iqhfgp16hl07i', 'ESSAY', 'WRITING', 'ROMANTICISM', 5, 10, 'Zdrada jako forma patriotyzmu? Rozważ problem, odwolujac sie do "Konrada Wallenroda" Adama Mickiewicza i jednego innego tekstu kultury.', '{"wordLimit": {"min": 300}, "requirements": ["Zdefiniuj wallenrodyzm jako forme dzialania i problem etyczny", "Przeanalizuj moralne koszty zdrady Konrada (utrata milosci, honoru, tozsamosci, zycia)", "Porownaj z innym bohaterem, ktory poswiecil etykę dla wyzszego celu (np. Jacek Soplica, Judym, Almanzor, agent wywiadu z filmu/literatury)", "Sformuluj wlasne stanowisko: czy zdrada moze byc moralnaa, jesli sluzy ojczyznie?", "Minimum 300 slow"]}', '"Rozprawka powinna: zdefiniowac wallenrodyzm (zdrada w imie wyzszego celu), przeanalizowac moralne koszty (Konrad placi wszystkim -- miloscia, honorem, zyciem, a Mickiewicz pokazuje te cene bez gloryfikacji). Porownanie: Jacek Soplica (tez ukrywa tozsamosc i dziala w tajemnicy, ale Mickiewicz daje mu odkupienie -- Ksiadz Robak); agent wywiadu (wspolczesna realizacja wallenrodyzmu -- np. film ''Zycie za zycie'' o Pileckim). Stanowisko: otwarte -- mozna argumentowac za (desperacja usprawiedliwia) i przeciw (zdrada niszczy moraalnie samego zdrajce -- Konrad ginie jako nieszczescliwy alkoholik, nie jako triumfator)."', NULL, '{writing,essay,difficulty-5,romanticism,batch-2025-01}', '{"explanation": "Problem ''zdrada jako patriotyzm'' to jedno z najtrudniejszych i najciekawszych zagadnien maturalnych. Kluczowe: Mickiewicz sam ewoluowal w tej kwestii -- odrzucil wallenrodyzm na rzecz mesjanizmu."}', '2026-03-17 22:22:09.969', '2026-03-17 22:22:09.969', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpbn002jqhfgyykgoh9i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Kto wychowywal Waltera Alfa wśrod Krzyzakow?', '{"options": ["Halban", "Mistrz krzyzacki Winrych", "Arcykomtur Maryjenburga", "Aldona"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Waltera Alfa wychowywal mistrz krzyzacki Winrych -- sam trzymal go do chrztu, kochal i piescil jak syna. Jednoczesnie po kryjomu odwiedzal go stary wajdelota (pozniejszy Halban), ktory rozbudzal w nim milosc do Litwy."}', '2026-03-17 22:22:09.971', '2026-03-17 22:22:09.971', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpbp002kqhfgtuppyjec', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Kim jest Kiejstut w utworze?', '{"options": ["Wielkim mistrzem Zakonu Krzyzackiego", "Litewskim ksieciem, ojcem Aldony, ktory przyjal Waltera i dal mu corke za zone", "Wajdelota spiewajacym przy ognisku", "Zdrajca Litwy, ktory sprzedal Waltera Krzyzakom"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Kiejstut to historyczna postac -- litewski ksiaze, ktory w utworze przyjmuje Waltera Alfa (zbieglego od Krzyzakow), docenia jego walecznosc i daje mu za zone corke Aldone, mowiac: ''Pojdz, Walterze, badz zieciem moim i bij sie za Litwe!''."}', '2026-03-17 22:22:09.973', '2026-03-17 22:22:09.973', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpbr002lqhfg7yp2xxma', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Co symbolizuje lampa, ktora Konrad ciska z okna przed smiercia?', '{"options": ["Bunt przeciwko Bogu", "Umowiony sygnal dla Aldony -- jesli lampa zgasnie, Konrad juz nie wróci", "Probe podpalenia zamku krzyzackiego", "Rzucanie wyzwania sedziom tajnego trybunalu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Konrad umowil sie z Aldona: ''Jesli lampa przed wieczorem skona -- zamknij twe okno, moze juz nie wróce''. Ciskajac gasnaaca lampe z okna, daje Aldonie ostatni sygnal -- ze umiera. Aldona odpowiada przerazliwym krzykiem i tez umiera. Lampa to symbol ich lacznosci -- gasnacy razem z zyiciem obojga."}', '2026-03-17 22:22:09.976', '2026-03-17 22:22:09.976', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpbu002mqhfgmipncvwj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jaka role pelni tajny trybunal, ktory skazuje Konrada?', '{"options": ["Jest sądem koscielnym (inkwizycja)", "Jest tajna rada 12 zamaskowanych sedziow w podziemiach Malborka, ktorzy karza zbrodnie wladcow Zakonu -- to oni odkrywaja zdrade Konrada", "Jest rada wojenna obradujaca nad strategia bitwy", "Jest fikcyjnym sądem wymyslonym przez Halbana, by nastraszyc Konrada"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Tajny trybunal to 12 zamaskowanych sedziow w podziemnym lochu Malborka, ktorzy przysiegli karac zbrodnie wladcow Zakonu. Odkrywaja, ze Konrad nie jest prawdziwym Wallenrodem, mowi po litewsku z pustelnica i zdradza Zakon. Wydaja wyrok: ''biada!'' -- trzykrotnie powtorzony przez mury."}', '2026-03-17 22:22:09.978', '2026-03-17 22:22:09.978', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv6gpbx002nqhfgxtp3mbm1', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Ktore z ponizszych ofiar sklada Konrad na oltarzu zemsty za ojczyzne?', '{"options": ["Milosc -- rozstaje sie z Aldona i widuje ja tylko przez krate wiezy", "Honor rycerski -- zamiast walczyc twarzą w twarz, stosuje zdrade i podstep", "Tozsamosc -- zyje pod falszywym imieniem, udajac Niemca", "Wlasne zycie -- konczy samobojstwem, pijac trucizne"]}', '[0, 1, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Konrad poswiecil WSZYSTKO: milosc (Aldona w wiezy), honor (zdrajca i spiskowiec zamiast rycerza), tozsamosc (Walter Alf stal sie Konradem Wallenrodem), zycie (samobojstwo truczizna). To wlasnie sprawia, ze jest bohaterem tragicznym, a nie heroicznym -- cena jest calkowita."}', '2026-03-17 22:22:09.982', '2026-03-17 22:22:09.982', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb6d0000qhxph0xtlyz6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Kto jest autorem powieści „Dżuma”?', '{"options": ["Jean-Paul Sartre", "Albert Camus", "Gustaw Herling-Grudziński", "Franz Kafka"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "„Dżuma” (fr. „La Peste”) to powieść Alberta Camusa wydana w 1947 roku. Polskie tłumaczenie Joanny Guze ukazało się w 1957 roku. Camus otrzymał Nagrodę Nobla w dziedzinie literatury w 1957 roku."}', '2026-03-17 22:49:04.593', '2026-03-17 22:49:04.593', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb7i0001qhxpq8ehb88z', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'W jakim mieście rozgrywa się akcja „Dżumy”?', '{"options": ["W Paryżu", "W Algierze", "W Oranie — mieście na wybrzeżu algierskim", "W Marsylii"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Akcja „Dżumy” toczy się w Oranie — mieście portowym na wybrzeżu algierskim, będącym wówczas prefekturą francuską. Camus opisuje je jako miasto brzydkie, bez drzew i gołębi, żyjące handlem."}', '2026-03-17 22:49:04.638', '2026-03-17 22:49:04.638', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb7m0002qhxp1voehawm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Jaki zawód wykonuje główny bohater, Bernard Rieux?', '{"options": ["Jest dziennikarzem", "Jest lekarzem", "Jest sędzią", "Jest księdzem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Bernard Rieux jest lekarzem — to on jako pierwszy rozpoznaje objawy dżumy u pacjentów i walczy z epidemią przez cały czas jej trwania. Na końcu powieści okazuje się również narratorem kroniki."}', '2026-03-17 22:49:04.643', '2026-03-17 22:49:04.643', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb7s0003qhxpxdljbjm8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Co jest pierwszym zwiastunem epidemii w Oranie?', '{"options": ["Nagła fala upałów", "Masowe pojawianie się martwych szczurów na ulicach", "Trzęsienie ziemi", "Skażenie wody pitnej"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Epidemię zwiastują martwe szczury, które zaczynają pojawiać się na ulicach, schodach i w domach. 25 kwietnia agencja Infdok ogłosiła, że zebrano i spalono 6231 szczurów. Wkrótce potem zaczynają chorować ludzie."}', '2026-03-17 22:49:04.648', '2026-03-17 22:49:04.648', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb7v0004qhxp0qb71zba', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Kto okazuje się narratorem kroniki na końcu powieści?', '{"options": ["Jean Tarrou", "Raymond Rambert", "Doktor Bernard Rieux", "Joseph Grand"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Na końcu powieści doktor Rieux ujawnia, że to on jest autorem kroniki. Przez cały utwór mówi o sobie w trzeciej osobie, by zachować obiektywizm świadka."}', '2026-03-17 22:49:04.651', '2026-03-17 22:49:04.651', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb7z0005qhxpg145j6qb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Ile części (rozdziałów głównych) liczy powieść „Dżuma”?', '{"options": ["Trzy", "Cztery", "Pięć", "Siedem"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "„Dżuma” składa się z pięciu części. Część I — pojawienie się szczurów i rozpoznanie epidemii, II — zamknięcie miasta i rozłąka, III — szczyt epidemii, IV — walka z dżumą, V — cofanie się choroby i otwarcie bram."}', '2026-03-17 22:49:04.655', '2026-03-17 22:49:04.655', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb830006qhxp31g5aaoi', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Które z wymienionych postaci są bohaterami „Dżumy”?', '{"options": ["Jean Tarrou — tajemniczy przybysz organizujący oddziały sanitarne", "Joseph Grand — skromny urzędnik merostwa piszący książkę", "Rodion Raskolnikow — student prawa z Petersburga", "Ojciec Paneloux — uczony jezuita wygłaszający kazania"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Tarrou, Grand i ojciec Paneloux to postacie z „Dżumy”. Raskolnikow to bohater „Zbrodni i kary” Dostojewskiego."}', '2026-03-17 22:49:04.659', '2026-03-17 22:49:04.659', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb860007qhxpy2x2quvf', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Które stwierdzenia o powieści „Dżuma” są prawdziwe?', '{"options": ["Powieść została wydana w 1947 roku", "Jest powieścią-parabolą o uniwersalnym przesłaniu", "Akcja rozgrywa się w dokładnie określonym roku — 1942", "Motto pochodzi z „Dziennika roku zarazy” Daniela Defoe"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "„Dżuma” ukazała się w 1947 r., jest parabolą, a motto pochodzi od Defoe. Rok akcji NIE jest dokładnie podany — tekst mówi „194.” z celowo opuszczoną ostatnią cyfrą, co podkreśla uniwersalność."}', '2026-03-17 22:49:04.663', '2026-03-17 22:49:04.663', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb8a0008qhxpjpsqx8x0', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Które wydarzenia następują w części I powieści?', '{"options": ["Pojawiają się martwe szczury na ulicach Oranu", "Dozorca Michel umiera jako jedna z pierwszych ofiar", "Bramy miasta zostają zamknięte", "Doktor Rieux rozpoznaje objawy dżumy u pacjentów"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "W części I pojawiają się szczury, umiera dozorca Michel, Rieux rozpoznaje dżumę. Zamknięcie bram następuje dopiero na KOŃCU części I — oficjalną depeszą: „Ogłoście stan dżumy. Zamknijcie miasto”."}', '2026-03-17 22:49:04.666', '2026-03-17 22:49:04.666', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb8g0009qhxpf307zi2e', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Skąd pochodzi motto „Dżumy” i co ono oznacza?', '{"hints": ["Daniel Defoe", "uwięzienie", "ukazywanie przez coś innego"]}', '"Motto pochodzi z „Dziennika roku zarazy” Daniela Defoe i brzmi: „Jest rzeczą równie rozsądną ukazać jakiś rodzaj uwięzienia przez inny, jak ukazać coś, co istnieje rzeczywiście, przez coś innego, co nie istnieje”. Oznacza, że historii o epidemii nie należy czytać dosłownie — dżuma jest metaforą innego rodzaju zniewolenia (np. wojny, totalitaryzmu, zła)."', NULL, '{historical_literary,short_answer,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Motto od razu sygnalizuje paraboliczny charakter powieści. Defoe — autor „Robinsona Crusoe” — napisał również kronikę londyńskiej zarazy z 1665 roku, co tworzy intertekstualny dialog między obiema kronikami."}', '2026-03-17 22:49:04.672', '2026-03-17 22:49:04.672', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb8k000aqhxpvjorl2i6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Kim jest Raymond Rambert i dlaczego chce opuścić Oran?', '{"options": ["Jest lekarzem i chce uciec przed epidemią", "Jest dziennikarzem paryskim, który przyjechał pisać reportaż o Arabach i został zaskoczony zamknięciem miasta — chce wrócić do żony w Paryżu", "Jest żołnierzem, który dezerteruje z garnizonu", "Jest kupcem, który chce ratować swoje towary przed konfiskatą"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Rambert to dziennikarz z Paryża, który przyjechał do Oranu, by przeprowadzić ankietę o warunkach życia Arabów. Zamknięcie bram odcięło go od kobiety, którą kocha. Przez długi czas próbuje legalnie i nielegalnie wydostać się z miasta."}', '2026-03-17 22:49:04.677', '2026-03-17 22:49:04.677', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb8q000bqhxp8sb4tk8b', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Nad czym pracuje Joseph Grand przez całą powieść?', '{"options": ["Nad raportem dla prefektury o stanie epidemii", "Nad pierwszym zdaniem powieści o amazonce jadącej alejami Lasku Bulońskiego — nigdy nie jest z niego zadowolony", "Nad tłumaczeniem „Dżumy” na język arabski", "Nad planem ucieczki z Oranu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Grand przez lata dopracowuje jedno zdanie: „W piękny poranek majowy smukła amazonka, siedząc na wspaniałej kasztance, jechała kwitnącymi alejami Lasku Bulońskiego”. Zmienia przymiotniki, szlifuje rytm, ale nigdy nie przechodzi do dalszej części książki."}', '2026-03-17 22:49:04.683', '2026-03-17 22:49:04.683', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb8w000cqhxp3v5zkanz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Czym zajmuje się Cottard w czasie epidemii?', '{"options": ["Organizuje oddziały sanitarne i walczy z dżumą", "Bogaci się na czarnym rynku i kontrabandzie — dżuma mu odpowiada, bo chroni go przed aresztowaniem", "Pracuje jako lekarz ochotnik w szpitalu", "Pisze kronikę wydarzeń dla prasy paryskiej"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Cottard to rentier, który przed epidemią próbował popełnić samobójstwo, prawdopodobnie w obawie przed aresztowaniem. Dżuma mu odpowiada — w chaosie epidemii nikt nie prowadzi dochodzeń. Bogaci się na kontrabandzie i spekulacji."}', '2026-03-17 22:49:04.688', '2026-03-17 22:49:04.688', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb8z000dqhxp3hxdiym6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Kto jako pierwszy wypowiada słowo „dżuma” w powieści?', '{"options": ["Doktor Rieux", "Prefekt Oranu", "Stary doktor Castel", "Ojciec Paneloux"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Stary doktor Castel, który widział przypadki dżumy w Chinach i w Paryżu, jako pierwszy mówi wprost: „Pan wie oczywiście, co to jest?” i potwierdza, że to dżuma. Rieux się z nim zgadza, ale inni lekarze i władze początkowo unikają tego słowa."}', '2026-03-17 22:49:04.691', '2026-03-17 22:49:04.691', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb92000eqhxpm34rvv2z', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Jak umiera dozorca Michel — pierwsza ofiara dżumy?', '{"options": ["Nagle, bez objawów, podczas snu", "Po kilku dniach gorączki z dymienicami, wymiotami, majaczeniem i plamami na ciele — w karetce, w drodze do szpitala", "W wyniku samobójstwa z rozpaczy", "Na dżumę płucną, kaszląc krwią"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Michel umiera po kilku dniach ciężkiej choroby: gorączka do 40 stopni, obrzmiałe gruczoły (dymienice), majaczenia, plamy na ciele. Umiera w karetce, a Rieux stwierdza zgon. Śmierć Michela zamyka „okres pełen mylących oznak” i rozpoczyna panikę."}', '2026-03-17 22:49:04.694', '2026-03-17 22:49:04.694', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb95000fqhxpqnb980rq', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Połącz postacie z ich charakterystycznymi cechami:', '{"leftColumn": [{"id": "A", "text": "Doktor Rieux"}, {"id": "B", "text": "Jean Tarrou"}, {"id": "C", "text": "Joseph Grand"}, {"id": "D", "text": "Cottard"}], "rightColumn": [{"id": "1", "text": "Bogaci się na kontrabandzie, boi się aresztowania"}, {"id": "2", "text": "Organizuje oddziały sanitarne, pragnie świętości bez Boga"}, {"id": "3", "text": "Lekarz walczący z epidemią, narrator kroniki"}, {"id": "4", "text": "Skromny urzędnik szlifujący jedno zdanie powieści"}], "matchingType": "characters_to_traits"}', '[[0, 2], [1, 1], [2, 3], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Rieux to lekarz i narrator. Tarrou organizuje formacje sanitarne i pragnie „być świętym bez Boga”. Grand szlifuje zdanie o amazonce. Cottard korzysta na epidemii, bo chroni go przed wymiarem sprawiedliwości."}', '2026-03-17 22:49:04.697', '2026-03-17 22:49:04.697', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb97000gqhxpdpgwdrnm', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Uzupełnij zdania, wybierając poprawne opcje:', '{"gaps": [{"id": 1, "options": ["przypadkowym zjawiskiem przyrodniczym", "karą Bożą za grzechy mieszkańców", "wynikiem złej higieny miasta", "spiskiem władz kolonialnych"]}, {"id": 2, "options": ["uciec z miasta za wszelką cenę", "uwierzyć we wszystko albo wszystkiemu zaprzeczyć", "przestać wierzyć w Boga", "zorganizować modlitwy publiczne"]}, {"id": 3, "options": ["modlitwa i pokuta", "uczciwość — wykonywanie swego zawodu", "ucieczka z zamkniętego miasta", "pogodzenie się z losem"]}], "textWithGaps": "Ojciec Paneloux w pierwszym kazaniu twierdzi, że dżuma jest (1). Po śmierci dziecka sędziego Othona wygłasza drugie kazanie, w którym mówi, że trzeba (2). Rieux twierdzi natomiast, że jedynym sposobem walki z dżumą jest (3)."}', '[1, 1, 1]', NULL, '{historical_literary,closed_multiple,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Paneloux w I kazaniu mówi o karze Bożej. W II kazaniu (po śmierci dziecka) zmienia stanowisko — mówi o konieczności wiary totalnej: wszystko albo nic. Rieux uważa, że walka z dżumą to kwestia uczciwości: „wykonywanie zawodu”."}', '2026-03-17 22:49:04.7', '2026-03-17 22:49:04.7', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb9a000hqhxpnyv4gc47', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Które motywy literackie są obecne w „Dżumie”?', '{"options": ["Motyw oblężonego miasta i izolacji", "Motyw rozłąki z bliskimi", "Motyw pojedynku rycerskiego", "Motyw walki ze złem i solidarności ludzkiej"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Kluczowe motywy „Dżumy” to: oblężone miasto (zamknięte bramy), rozłąka (Rieux z żoną, Rambert z partnerką), walka ze złem i solidarność (formacje sanitarne). Motyw pojedynku rycerskiego nie występuje w utworze."}', '2026-03-17 22:49:04.702', '2026-03-17 22:49:04.702', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb9c000iqhxpyv9ckin7', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Kim jest stary astmatyk i jaką postawę reprezentuje?', '{"hints": ["kramarz", "groch w garnkach", "bierność", "nie wstaje z łóżka"]}', '"Stary astmatyk to emerytowany kramarz, który mając 50 lat uznał, że dosyć pracował, położył się do łóżka i już nie wstał. Mierzy czas przesypywaniem grochu z garnka do garnka zamiast zegarkiem. Reprezentuje postawę biernej akceptacji świata — nie obchodzi go dżuma, nie walczy z nią. Jego bierna filozofia kontrastuje z aktywną postawą Rieux i Tarrou."', NULL, '{historical_literary,short_answer,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Stary astmatyk jest postacią komiczną i filozoficzną zarazem. Jego zdanie „Co to jednak znaczy — dżuma? To życie, ot i wszystko” wyraża postawę fatalistyczną. Tarrou pyta, czy jest „świętym”, i odpowiada: „Tak, jeśli świętość jest zespołem przyzwyczajeń”."}', '2026-03-17 22:49:04.705', '2026-03-17 22:49:04.705', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb9f000jqhxp5vhofo8t', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Co dzieje się z żoną doktora Rieux w trakcie epidemii?', '{}', '"Żona Rieux jest chora (prawdopodobnie na gruźlicę) i wyjeżdża do sanatorium w górach dzień przed zamknięciem bram. Przez całą epidemię Rieux jest od niej oddzielony — komunikują się tylko depeszami. Na końcu powieści Rieux dowiaduje się o jej śmierci z telegramu."', NULL, '{historical_literary,short_answer,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Rozłąka Rieux z żoną jest jednym z najważniejszych osobistych wymiarów dżumy. Rieux przeżywa tę stratę w milczeniu — co pokazuje, że walka z abstrakcją (epidemią) kosztuje utratę tego, co najbardziej osobiste."}', '2026-03-17 22:49:04.707', '2026-03-17 22:49:04.707', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb9h000kqhxplr0xu69b', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Jakie zdarzenie otwiera fabułę powieści (scena z 16 kwietnia)?', '{"words": ["szczur", "podest", "dozorca"]}', '"Rankiem 16 kwietnia doktor Rieux wychodzi ze swojego gabinetu i na podeście zawadza nogą o martwego szczura. Dozorca Michel twierdzi stanowczo, że „nie ma szczurów w domu” i uważa to za czyjś kawał. Tego samego wieczoru Rieux widzi kolejnego szczura — umierającego, wyrzucającego krew z pyska. To początek serii wydarzeń zwiastujących epidemię."', NULL, '{historical_literary,short_answer,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Scena z martwym szczurem na podeście to klasyczny incipit powieści. Reakcja dozorcy (zaprzeczanie oczywistości) zapowiada postawę całego społeczeństwa wobec nadciągającej katastrofy."}', '2026-03-17 22:49:04.709', '2026-03-17 22:49:04.709', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb9j000lqhxpn8cbz7ly', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Dlaczego Rambert ostatecznie rezygnuje z ucieczki z Oranu?', '{"options": ["Nie udaje mu się zorganizować przerzutu przez bramy", "Uświadamia sobie, że „może być wstyd, że człowiek jest sam tylko szczęśliwy” — po wizycie w szpitalu decyduje się zostać i walczyć z dżumą", "Zostaje aresztowany przez policję przy próbie ucieczki", "Jego żona przyjeżdża do Oranu i nie ma powodu uciekać"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Rambert, który przez tygodnie organizował ucieczkę, zmienia zdanie po zobaczeniu pracy w szpitalu i po informacji, że żona Rieux jest w sanatorium. Mówi: „Może być wstyd, że człowiek jest sam tylko szczęśliwy”. Zostaje i dołącza do formacji sanitarnych."}', '2026-03-17 22:49:04.712', '2026-03-17 22:49:04.712', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb9m000mqhxpb3lebnj3', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Co zmienia się w postawie ojca Paneloux między pierwszym a drugim kazaniem?', '{"options": ["W pierwszym kazaniu nawołuje do ucieczki, w drugim — do walki z epidemią", "W pierwszym kazaniu mówi „wy” i interpretuje dżumę jako karę Bożą; w drugim mówi „my”, rezygnuje z prostych wyjaśnień i stwierdza, że trzeba uwierzyć we wszystko albo wszystkiemu zaprzeczyć", "W pierwszym kazaniu jest ateistą, w drugim — staje się gorliwym wierzącym", "Oba kazania są identyczne — Paneloux nie zmienia stanowiska"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Ewolucja Paneloux to jeden z najważniejszych wątków powieści. I kazanie: pewność, oskarżenie, „wy zasłużyliście”. II kazanie (po śmierci dziecka Othona): niepewność, pokora, „my”, wiara totalna jako jedyna alternatywa wobec nihilizmu. Zmiana z „wy” na „my” pokazuje, że Paneloux sam stał się ofiarą dżumy."}', '2026-03-17 22:49:04.714', '2026-03-17 22:49:04.714', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb9o000nqhxpxu361khd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Jaką scenę Camus wykorzystuje jako punkt kulminacyjny sporu o sens cierpienia?', '{"options": ["Śmierć dozorcy Michela w karetce", "Długą agonię syna sędziego Othona — dziecko umiera mimo zastosowania nowego serum, a Rieux mówi do Paneloux: „Ten przynajmniej był niewinny”", "Samobójstwo Cottarda w finale powieści", "Śmierć Tarrou na dżumę płucną"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Scena śmierci synka Othona to najważniejszy moment konfrontacji z problemem teodycei. Dziecko cierpi straszliwie, a serum Castela nie działa. Po śmierci dziecka Rieux krzyczy na Paneloux: „Nigdy nie będę kochał tego świata, gdzie dzieci są torturowane”. To zdanie jest kluczem do etyki Camusa."}', '2026-03-17 22:49:04.717', '2026-03-17 22:49:04.717', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb9r000oqhxpkjxqg0dn', 'CLOSED_SINGLE', 'LANGUAGE_USE', 'CONTEMPORARY', 3, 2, 'Dlaczego „Dżumę” nazywamy powieścią-parabolą?', '{"options": ["Ponieważ opisuje wyłącznie realne wydarzenia historyczne z II wojny światowej", "Ponieważ pod dosłowną warstwą opowieści o epidemii kryje się głębszy, uniwersalny sens — dżuma jest metaforą zła, wojny, totalitaryzmu i zła tkwiącego w człowieku", "Ponieważ zawiera przypowieści biblijne w każdym rozdziale", "Ponieważ jest napisana wierszem, jak parabola matematyczna"]}', '1', NULL, '{language_use,closed_single,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Parabola (przypowieść) to utwór, w którym warstwa dosłowna jest nośnikiem głębszego sensu. Cechy paraboli w „Dżumie”: zatarta data (194.), zamknięta przestrzeń, uniwersalne postawy bohaterów, motto z Defoe sygnalizujące alegoryczność. Dżuma = zło, wojna, totalitaryzm, ale też zło wewnętrzne człowieka."}', '2026-03-17 22:49:04.72', '2026-03-17 22:49:04.72', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb9u000pqhxpv2drpfqe', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Które interpretacje tytułu „Dżuma” są uzasadnione tekstem powieści?', '{"options": ["Dżuma jako dosłowna epidemia — choroba dziesiątkująca Oran", "Dżuma jako metafora II wojny światowej i okupacji", "Dżuma jako zło tkwiące wewnątrz każdego człowieka — „każdy nosi w sobie dżumę”", "Dżuma jako kara Boża za grzechy — jedyna interpretacja wspierana przez narratora"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Tytuł jest wieloznaczny: dosłowna epidemia, metafora wojny/totalitaryzmu, zło w człowieku (słowa Tarrou: „każdy nosi w sobie dżumę”). Interpretacja kary Bożej jest ODRZUCONA — głosi ją Paneloux w I kazaniu, ale sam wycofuje się z niej po śmierci dziecka."}', '2026-03-17 22:49:04.722', '2026-03-17 22:49:04.722', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb9w000qqhxphnvy2rh2', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Które cytaty pochodzą z „Dżumy” i kto je wypowiada?', '{"leftColumn": [{"id": "A", "text": "„Jedyny sposób walki z dżumą to uczciwość”"}, {"id": "B", "text": "„Każdy nosi w sobie dżumę”"}, {"id": "C", "text": "„Kapelusze z głów, panowie!”"}, {"id": "D", "text": "„W ludziach więcej rzeczy zasługuje na podziw niż na pogardę”"}], "rightColumn": [{"id": "1", "text": "Tarrou — o złu tkwiącym w każdym człowieku"}, {"id": "2", "text": "Grand — o swoim zdaniu o amazonce"}, {"id": "3", "text": "Rieux — o postawie wobec epidemii"}, {"id": "4", "text": "Rieux-narrator — końcowe przesłanie kroniki"}], "matchingType": "quotes_to_works"}', '[[0, 2], [1, 0], [2, 1], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Rieux mówi o uczciwości jako jedynym sposobie walki. Tarrou stwierdza, że „każdy nosi w sobie dżumę”. Grand marzy, by wydawca zdjął kapelusz. Końcowe zdanie kroniki — „w ludziach więcej rzeczy zasługuje na podziw niż na pogardę” — należy do Rieux-narratora."}', '2026-03-17 22:49:04.725', '2026-03-17 22:49:04.725', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fb9z000rqhxp6hbpm9tl', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Które postawy wobec dżumy (zła) reprezentują poszczególni bohaterowie?', '{"options": ["Rieux — aktywna walka ze złem wynikająca z obowiązku zawodowego i ludzkiej uczciwości", "Tarrou — bunt przeciw śmierci i pragnienie „świętości bez Boga”", "Cottard — bierny opór i odmowa współpracy z władzami z pobudek patriotycznych", "Paneloux — ewolucja od religijnego wyjaśnienia cierpienia do wiary totalnej"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Rieux = uczciwość i obowiązek. Tarrou = bunt i poszukiwanie świętości. Paneloux = ewolucja od pewności do pokory. Cottard NIE jest biernym opornikiem patriotycznym — jest oportunistą, który korzysta na epidemii i boi się powrotu porządku prawnego."}', '2026-03-17 22:49:04.727', '2026-03-17 22:49:04.727', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fba1000sqhxpp73go0gn', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Opisz scenę w operze (Orfeusz i Eurydyka) z notatek Tarrou. Co symbolizuje?', '{"instruction": "Odwołaj się do tego, co dzieje się na scenie i na widowni, oraz wyjaśnij symbolikę."}', '"Podczas spektaklu „Orfeusza i Eurydyki” śpiewak grający Orfeusza dodaje do arii przesadne tremola, a w scenie utraty Eurydyki nagle pada na scenę. Orkiestra milknie. Publiczność, początkowo zdumiona, zaczyna w panice opuszczać salę — cicho, potem coraz szybciej, „jak po skończonym nabożeństwie wychodzi się z kościoła”. Scena symbolizuje wtargnięcie dżumy (śmierci) w przestrzeń sztuki i pozorów — eleganckie fraki nie chronią przed zarazą. Upadek Orfeusza to upadek iluzji normalności."', NULL, '{historical_literary,short_answer,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Scena w operze to jedna z najbardziej sugestywnych scen powieści. Metateatralność: Orfeusz traci Eurydykę na scenie, jak Oran traci swoich obywateli. Publiczność ucieka, zostawiając „zapomniane wachlarze i koronki na czerwieni foteli” — symboliczny obraz porzucenia pozorów."}', '2026-03-17 22:49:04.73', '2026-03-17 22:49:04.73', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fba4000tqhxpomrmv8az', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Co oznacza zdanie Rieux: „Jedyny sposób walki z dżumą to uczciwość”? Jak je rozumie?', '{}', '"Rieux wyjaśnia, że uczciwość „w moim przypadku polega na wykonywaniu zawodu”. Nie chodzi mu o abstrakcyjną cnotę, ale o codzienną, konsekwentną pracę — leczenie chorych, diagnozowanie, izolowanie, nawet gdy nie ma nadziei na wyleczenie. Uczciwość to przeciwieństwo bohaterstwa: nie wielkie czyny, lecz wytrwałe robienie tego, co należy. To postawa Syzyfa u Camusa — świadome działanie mimo absurdu."', NULL, '{historical_literary,short_answer,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "To jedno z najważniejszych zdań powieści. Rieux odrzuca heroizm i świętość jako kategorie — zostaje uczciwość, rozumiana jako solidna, codzienna praca. To fundament etyki Camusa: sens nadaje się życiu przez działanie, nie przez wiarę."}', '2026-03-17 22:49:04.732', '2026-03-17 22:49:04.732', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fba7000uqhxpg9jmk0lh', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Dlaczego narrator uważa Josepha Granda za „bohatera” kroniki? Co jest w tym paradoksalne?', '{"hints": ["skromność", "dwa plus dwa", "dobra wola"]}', '"Narrator proponuje Granda jako bohatera, bo „miał tylko dobre serce i pozornie śmieszny ideał”. Grand nie jest spektakularny — jest skromnym urzędnikiem, który po godzinach szlifuje jedno zdanie, a jednocześnie cierpliwie prowadzi statystyki formacji sanitarnych. Paradoks polega na tym, że bohaterem zostaje człowiek najzwyklejszy: to jego szarość jest heroiczna. Camus odwraca tradycyjny wzorzec — prawdziwy bohater to ktoś, kto mówi „dwa i dwa to cztery” i robi to, co należy."', NULL, '{historical_literary,short_answer,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Narrator pisze: „dwa i dwa to cztery, a bohaterstwo — miejsce drugorzędne”. Grand ucieleśnia etykę Camusa: wielkość w zwyczajności, dobroć bez ostentacji."}', '2026-03-17 22:49:04.735', '2026-03-17 22:49:04.735', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fba9000vqhxpow0n0a4f', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 3, 'Napisz notatkę syntetyczną na podany temat:', '{"topic": "Postawy bohaterów „Dżumy” wobec epidemii — od buntu po oportunizm", "wordLimit": {"max": 150, "min": 100}, "requirements": ["Scharakteryzuj postawę co najmniej czterech bohaterów (Rieux, Tarrou, Rambert, Cottard)", "Wskaż, która postawa jest według narratora właściwa i dlaczego", "Wyjaśnij, dlaczego narrator twierdzi, że „nie jest rzeczą konieczną być bohaterem”", "100-150 słów"]}', '"Notatka powinna: 1) Rieux — aktywna walka, uczciwość, obowiązek zawodowy; nie szuka chwały, po prostu leczy. 2) Tarrou — bunt egzystencjalny, organizacja formacji sanitarnych, pragnienie „świętości bez Boga”. 3) Rambert — ewolucja od egoizmu (ucieczka) do solidarności (zostaje i walczy). 4) Cottard — oportunizm, dżuma mu sprzyja, korzysta na nieszczęściu. Narratorowi najbliższa jest postawa Granda i Rieux: zwykła uczciwość, nie bohaterstwo. „Piękne czyny mają tak wysoką cenę dlatego, że są rzadkie” — Camus odrzuca heroizm na rzecz codziennej przyzwoitości."', NULL, '{historical_literary,synthesis_note,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Spektrum postaw bohaterów to jedno z najczęstszych pytań maturalnych o „Dżumę”. Kluczowe: Camus nie dzieli bohaterów na dobrych i złych — pokazuje różne możliwe reakcje na zło."}', '2026-03-17 22:49:04.738', '2026-03-17 22:49:04.738', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbad000wqhxpbanfihts', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 2, 'Co Tarrou rozumie przez zdanie „każdy nosi w sobie dżumę”?', '{"options": ["Że wszyscy mieszkańcy Oranu są fizycznie zarażeni bakcylem", "Że w każdym człowieku tkwi potencjał zła — skłonność do zabijania, zgody na zabójstwo, obojętności; i trzeba nieustannie czuwać, by „nie tchnąć dżumy w twarz drugiego człowieka”", "Że dżuma jest chorobą dziedziczną przenoszoną genetycznie", "Że każdy powinien się bać epidemii i uciekać z miasta"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "To najważniejsze zdanie filozoficzne powieści. Tarrou mówi o „zadżumieniu” moralnym: mikrob dżumy to potencjał zła w człowieku — zgoda na wyroki śmierci, obojętność na cierpienie, „roztargnienie” pozwalające krzywdzić innych. „Uczciwy człowiek, który nie zaraża niemal nikogo, to człowiek możliwie najmniej roztargniony.”"}', '2026-03-17 22:49:04.741', '2026-03-17 22:49:04.741', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbaf000xqhxp3l97hcde', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 2, 'Jak Camus buduje postać Tarrou jako bohatera egzystencjalnego? Jakie doświadczenie go ukształtowało?', '{"options": ["Tarrou był żołnierzem i widział śmierć na polu bitwy", "Jako nastolatek widział, jak ojciec — zastępca prokuratora — żąda kary śmierci dla oskarżonego; odtąd walczy z wszelką formą „zadżumienia” — zgodą na zabijanie", "Tarrou stracił rodziców podczas epidemii w Chinach", "Tarrou był księdzem, który utracił wiarę po śmierci parafianina"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Tarrou opowiada Rieux o przełomowym doświadczeniu: jako siedemnastolatek widział ojca w sądzie, żądającego „tej głowy”. Zrozumiał, że ojciec „wstawał wcześniej” by być obecny przy egzekucjach. Odtąd walczy ze „skazywaniem” — każdą formą zgody na zabijanie. Pragnie „świętości bez Boga” i „spokoju wewnętrznego”."}', '2026-03-17 22:49:04.744', '2026-03-17 22:49:04.744', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbai000yqhxp8rsyixd2', 'CLOSED_SINGLE', 'LANGUAGE_USE', 'CONTEMPORARY', 4, 2, 'Jaką rolę pełni w powieści motyw „abstrakcji”?', '{"options": ["„Abstrakcja” oznacza naukę i teorię medyczną — Rieux woli praktykę", "Rieux nazywa „abstrakcją” dżumę jako system: statystyki, procedury, izolację — to, co odczłowiecza cierpienie, ale z czym trzeba walczyć, używając tych samych narzędzi", "„Abstrakcja” to metafora malarstwa abstrakcyjnego, które jest modne w Oranie", "To określenie filozofii Paneloux, z którą Rieux polemizuje"], "sourceText": {"text": "Kiedy abstrakcja zaczyna nas zabijać, trzeba się zająć abstrakcją.", "title": "Dżuma", "author": "Albert Camus"}}', '1', NULL, '{language_use,closed_single,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Dla Rieux „abstrakcja” to dżuma jako system: formularze, karetki, statystyki, izolacja, pogrzeby — cały aparat, który sprowadza cierpienie do liczb. Rambert zarzuca Rieux „mówienie językiem abstrakcji”. Ale Rieux wie, że „kiedy abstrakcja zaczyna zabijać, trzeba się zająć abstrakcją” — walczyć z systemem przy użyciu systemu. To paradoks etyczny powieści."}', '2026-03-17 22:49:04.747', '2026-03-17 22:49:04.747', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbal000zqhxp1aznnj0l', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 2, 'Które elementy „Dżumy” świadczą o jej parabolicznym (alegorycznym) charakterze?', '{"options": ["Celowo zatarta data — „194.” bez ostatniej cyfry", "Motto z Defoe sygnalizujące, że „jeden rodzaj uwięzienia ukazuje inny”", "Szczegółowe opisy architektoniczne Oranu z podaniem nazw ulic i numerów domów", "Uniwersalne postawy bohaterów — nie indywidualne psychologie, lecz modele reakcji na zło"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Cechy paraboli: zatarta data (uniwersalność), motto Defoe (klucz alegoryczny), bohaterowie jako modele postaw (nie głębokie psychologie). Opisy Oranu istnieją, ale nie są „szczegółowe” — Camus celowo kreuje miasto jako przestrzeń uniwersalną: brzydką, banalną, reprezentatywną."}', '2026-03-17 22:49:04.749', '2026-03-17 22:49:04.749', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fban0010qhxp9qd4qvba', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 2, 'Które porównania międzytekstowe z innymi dziełami są uzasadnione?', '{"options": ["„Dżuma” i „Inny świat” Herlinga-Grudzińskiego — obie ukazują ludzi w sytuacji ekstremalnej, testując ich moralność", "„Dżuma” i „Mit Syzyfa” Camusa — Rieux jak Syzyf: działa wiedząc, że walka może być daremna”", "„Dżuma” i „Pan Tadeusz”— obie są epopejami narodowymi", "„Dżuma” i „Proces” Kafki — absurd systemu, który przenika życie jednostki bez wyjaśnienia"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "„Inny świat” — obie powieści testują moralność w ekstremalnych warunkach. „Mit Syzyfa” — Rieux to Syzyf walczący z absurdem. „Proces” Kafki — absurdalny system pochłania jednostkę. „Pan Tadeusz” to epopeja szlachecka — nie ma żadnego związku z „Dżumą”."}', '2026-03-17 22:49:04.751', '2026-03-17 22:49:04.751', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbap0011qhxpav1ea4dd', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 3, 'Jaką rolę pełni scena nocnej kąpieli Rieux i Tarrou w morzu? Dlaczego jest ważna kompozycyjnie?', '{"instruction": "Odwołaj się do kontekstu (kiedy następuje), symboliki i relacji między bohaterami."}', '"Scena kąpieli następuje po zwierzeniach Tarrou o swoim życiu — jest momentem kulminacji ich przyjaźni. Rieux i Tarrou wymykają się z miasta na molo i pływają razem w morzu: „Przez kilka minut płynęli jednako, z tą samą mocą, samotni, daleko od świata, wolni nareszcie od miasta i dżumy”. To jedyna scena w powieści, gdzie bohaterowie doświadczają wolności i szczęścia. Symbolika: morze = wolność, natura, życie poza dżumą. Kompozycyjnie: scena jest „pauzą” przed finałem — wkrótce Tarrou zachoruje i umrze. Jest pożegnaniem, choć bohaterowie jeszcze o tym nie wiedzą."', NULL, '{historical_literary,short_answer,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Scena kąpieli jest jednym z najczęściej analizowanych fragmentów powieści. Na maturze pojawia się w kontekstach: przyjaźń w sytuacji ekstremalnej, motyw morza, chwila wolności wobec zniewolenia."}', '2026-03-17 22:49:04.754', '2026-03-17 22:49:04.754', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbas0012qhxph3t7mzhy', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 3, 'Wyjaśnij sens ostatniego zdania powieści o „bakcylu dżumy, który nigdy nie umiera”. Jakie ma przesłanie?', '{}', '"Rieux pisze, że „bakcyl dżumy nigdy nie umiera i nie znika, że może przez dziesiątki lat pozostać uśpiony w meblach i bieliźnie (...) i że nadejdzie być może dzień, kiedy na nieszczęście ludzi oraz dla ich nauki dżuma obudzi swe szczury i pośle je, by umierały w szczęśliwym mieście”. Przesłanie: zło nigdy nie znika na zawsze — może powrócić w każdej chwili pod nową postacią (wojna, totalitaryzm, nienawiść). Radość z wyzwolenia „jest zawsze zagrożona”. To ostrzeżenie przed łatwym optymizmem i wezwanie do wiecznej czujności moralnej."', NULL, '{historical_literary,short_answer,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "To zdanie zamykające powieść jest jednym z najczęściej cytowanych fragmentów Camusa. Na maturze kluczowe: nie jest to pesymizm, lecz realizm moralny — Camus nie zapowiada nieuchronnej klęski, ale mówi, że czujność i gotowość do walki muszą być stałe."}', '2026-03-17 22:49:04.756', '2026-03-17 22:49:04.756', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbav0013qhxpdjuyelvd', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 4, 'Napisz notatkę syntetyczną na podany temat:', '{"topic": "Spór Rieux z Paneloux — dwa sposoby reagowania na cierpienie niewinnych", "wordLimit": {"max": 200, "min": 150}, "requirements": ["Wyjaśnij stanowisko Rieux (bunt, odmowa akceptacji cierpienia)", "Wyjaśnij stanowisko Paneloux (wiara totalna, przyjęcie tajemnicy)", "Odwołaj się do sceny śmierci dziecka jako punktu zwrotnego", "Oceń, która postawa jest bliższa przesłaniu Camusa", "150-200 słów"]}', '"Notatka powinna: Rieux — odmawia akceptacji świata, „gdzie dzieci są torturowane”. Jego postawa to bunt bez metafizyki: leczy, bo tak trzeba, nie szuka wyjaśnień, nie wierzy w wyższy sens cierpienia. Paneloux — po śmierci dziecka porzuca łatwe odpowiedzi (kara Boża), ale zamiast buntu wybiera wiarę totalną: „trzeba we wszystko uwierzyć albo wszystkiemu zaprzeczyć”. Punkt zwrotny: agonia syna Othona — Paneloux klęka i modli się, Rieux mówi: „ten przynajmniej był niewinny”. Po scenie Rieux przeprasza, ale stwierdza: „nie chcę spierać się z księdzem. Pracujemy razem.” Bliższa Camusowi postawa Rieux — bunt i działanie, nie wiara. Ale Camus nie deprecjonuje Paneloux: daje mu godność i pokornę śmierć."', NULL, '{historical_literary,synthesis_note,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Spór Rieux–Paneloux to centralna oś filozoficzna powieści: egzystencjalizm vs. wiara. Na maturze pojawia się jako pytanie o teodycję, postawy wobec cierpienia i sens nadziei."}', '2026-03-17 22:49:04.759', '2026-03-17 22:49:04.759', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbax0014qhxpl01n3dol', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 4, 'Napisz notatkę syntetyczną na podany temat:', '{"topic": "Rozłąka jako centralne doświadczenie bohaterów „Dżumy” — formy, skutki i sens", "wordLimit": {"max": 200, "min": 150}, "requirements": ["Wskaż co najmniej trzy przykłady rozłąki w powieści", "Opisz psychologiczne skutki rozłąki, jakie obserwuje narrator", "Wyjaśnij, dlaczego narrator nazywa rozłąkę „wygnaniem we własnym domu”", "150-200 słów"]}', '"Notatka powinna: Przykłady rozłąki: 1) Rieux — żona w sanatorium, umiera bez niego. 2) Rambert — partnerka w Paryżu, nie może wyjechać. 3) Castel — żona w sąsiednim mieście, wraca mimo ryzyka. 4) Wszyscy mieszkańcy Oranu — odcięci od świata, kontakt tylko przez 10-słowowe depesze. Skutki: utrata pamięci o bliskich (twarze stają się „bezcielesne”), rezygnacja z przyszłości, monotonia cierpienia, stępienie emocji — „przyzwyczajenie się do rozpaczy gorsze niż sama rozpacz”. „Wygnanie we własnym domu” — bo ludzie są we własnym mieście, ale odcięci od tego, co stanowiło ich życie (bliscy, przyzwyczajenia, wolność). Sens: rozłąka to forma śmierci za życia — pozbawia ludzi tego, co ludzkie: czułości, miłości, nadziei."', NULL, '{historical_literary,synthesis_note,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Motyw rozłąki to jeden z najczęstszych tematów maturalnych. Camus poświęca mu obszerne fragmenty w części II i III, analizując psychologię ludzi oddzielonych od bliskich."}', '2026-03-17 22:49:04.762', '2026-03-17 22:49:04.762', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbb00015qhxp58znio6g', 'ESSAY', 'WRITING', 'CONTEMPORARY', 4, 5, 'Czy uczciwość wystarczy, by walczyć ze złem? Rozważ problem, odwołując się do „Dżumy” Alberta Camusa i jednego innego tekstu kultury.', '{"wordLimit": {"min": 300}, "requirements": ["Wyjaśnij, jak Rieux rozumie uczciwość w kontekście walki z epidemią", "Przeanalizuj postawy innych bohaterów — Tarrou, Granda, Ramberta — jako warianty uczciwości", "Porównaj z innym tekstem kultury (np. „Inny świat” — postawa Herlinga wobec zła w łagrze, „Lord Jim” — poczucie obowiązku)", "Sformułuj wniosek: czy codzienna przyzwoitość to odpowiedź na wielkie zło?", "Minimum 300 słów"]}', '"Rozprawka powinna: zdefiniować uczciwość u Camusa (wykonywanie zawodu, brak zgody na zło, brak heroicznej retoryki), pokazać warianty: Tarrou (bunt + pragnienie świętości), Grand (skromna praca), Rambert (ewolucja od egoizmu do solidarności). Porównanie: „Inny świat” — w łagrze uczciwość to odmowa kolaboracji z systemem; Herling podobnie jak Camus stawia na indywidualną moralność w obliczu absurdu. Wniosek: uczciwość NIE gwarantuje zwycięstwa nad złem, ale jest jedyną postawą zachowującą godność — „w ludziach więcej rzeczy zasługuje na podziw niż na pogardę”."', NULL, '{writing,essay,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Problem uczciwości wobec zła to centralny temat maturalny. Kluczowe: Camus nie obiecuje, że uczciwość wygra — mówi, że jest jedynym godnym wyborem."}', '2026-03-17 22:49:04.765', '2026-03-17 22:49:04.765', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbb40016qhxpf07z6ns2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 5, 3, 'Jak „Dżuma” realizuje filozofię absurdu Camusa z eseju „Mit Syzyfa”?', '{"options": ["Bohaterowie rezygnują z walki i godzą się z absurdem istnienia", "Rieux jest współczesnym Syzyfem: wie, że walka z dżumą (śmiercią) jest skazana na porażkę, ale nadaje jej sens poprzez sam akt buntu — „nie kończącą się klęskę” przyjmuje z godnością i kontynuuje pracę", "Powieść odrzuca filozofię absurdu i proponuje wiarę religijną jako rozwiązanie", "Absurd polega na tym, że epidemia jest losowa — Camus krytykuje medycynę za bezradność"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "W „Micie Syzyfa” Camus pisze, że „trzeba wyobrażać sobie Syzyfa szczęśliwego” — sens tkwi w samym buntowniczym działaniu, nie w jego wyniku. Rieux jest Syzyfem: leczy, choć wie, że większość chorych umrze. Jego zwycięstwa „zawsze będą tymczasowe”, ale to nie powód, by zaprzestać walki. Tarrou pyta: „czym ta dżuma jest dla pana?” Rieux odpowiada: „Nie kończącą się klęską”."}', '2026-03-17 22:49:04.768', '2026-03-17 22:49:04.768', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbb60017qhxpbrct1rdt', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 5, 3, 'Dlaczego Tarrou pragnie „świętości bez Boga” i dlaczego tej świętości nie osiąga?', '{"options": ["Bo Tarrou jest zbyt leniwy, by konsekwentnie walczyć ze złem", "Bo jest ateistą i nie akceptuje kary śmierci w żadnej formie — chce być „niewinnym mordercą”, żyć „po stronie ofiar”; nie osiąga świętości, bo umiera na dżumę tuż przed końcem epidemii — jego bunt prometeuszowy kończy się klęską fizyczną, choć moralnym zwycięstwem", "Bo Paneloux odmawia udzielenia mu rozgrzeszenia", "Bo Tarrou jest w istocie nihilistą i nie wierzy w żadne wartości"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "Tarrou jest postacią tragiczną: syn prokuratora, który zobaczył „brudne usta” wymiaru sprawiedliwości, odtąd odmawia zgody na jakąkolwiek formę zabijania. Pragnie „świętości bez Boga” — czystej etyki bez transcendencji. Nie osiąga świętości, bo dżuma zabiera go tuż przed wyzwoleniem. Rieux mówi: „Tarrou przegrał partię” — ale jego bunt nadał sens życiu."}', '2026-03-17 22:49:04.771', '2026-03-17 22:49:04.771', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbb90018qhxp2rwp4bjn', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 5, 3, 'Które aspekty „Dżumy” świadczą o jej związku z egzystencjalizmem?', '{"options": ["Absurd istnienia: cierpienie jest bezprzyczynowe i nie ma wyższego sensu (odrzucenie teodycei)", "Wolność i odpowiedzialność: bohaterowie definiują się przez swoje wybory (Rambert: zostać czy uciec?)", "Bunt jako nadanie sensu: Rieux i Tarrou walczą, wiedząc, że zwycięstwo jest tymczasowe", "Deterministyczna wizja: bohaterowie nie mają wpływu na swój los i biernie poddają się epidemii"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "Egzystencjalizm w „Dżumie”: absurd (dżuma bez przyczyny, cierpienie bez sensu), wolność (każdy bohater dokonuje wyboru — Rambert, Paneloux, Cottard), bunt (Rieux/Tarrou walczą bez nadziei na ostateczne zwycięstwo). Wizja NIE jest deterministyczna — bohaterowie MAJĄ wpływ na swoje postawy, co jest fundamentem egzystencjalizmu: „człowiek jest tym, co z siebie uczyni”."}', '2026-03-17 22:49:04.773', '2026-03-17 22:49:04.773', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbbb0019qhxpshn3n93l', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 5, 4, 'Porównaj „Dżumę” Camusa z „Innym światem” Herlinga-Grudzińskiego. Co łączy obie powieści w ujęciu problemu zła i reakcji człowieka na nie?', '{"instruction": "Uwzględnij sytuację graniczną, postawy bohaterów, problem solidarności i samotności oraz przesłanie."}', '"Oba utwory: 1) Ukazują człowieka w sytuacji granicznej — zamknięte miasto (Camus) i łagier (Herling) jako laboratoria ludzkiej natury. 2) Testują moralność: czy człowiek zachowa godność, gdy system (dżuma/Gułag) dąży do jego zniszczenia? 3) Pokazują spektrum postaw — od heroizmu (Rieux/Tarrou — Kostylew) po oportunizm (Cottard — donosiciele). 4) Akcentują solidarność i samotność jednocześnie: bohaterowie walczą razem, ale cierpią samotnie. Różnice: u Camusa zło jest abstrakcyjne (bakcyl, absurd), u Herlinga — ma twarz systemu sowieckiego. Camus mówi: „w ludziach więcej rzeczy zasługuje na podziw niż na pogardę”. Herling jest mniej optymistyczny — łagier odsłania ciemne strony natury ludzkiej brutalniej."', NULL, '{historical_literary,short_answer,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "Porównanie „Dżumy” z „Innym światem” to klasyczne zestawienie maturalne: obie powieści z epoki CONTEMPORARY, obie o sytuacji granicznej, obie o etyce w obliczu absurdu."}', '2026-03-17 22:49:04.775', '2026-03-17 22:49:04.775', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbbd001aqhxp1esmeu3p', 'SHORT_ANSWER', 'LANGUAGE_USE', 'CONTEMPORARY', 5, 4, 'Wyjaśnij, dlaczego Rieux ujawnia się jako narrator dopiero na końcu powieści. Jaką funkcję pełni ten zabieg narracyjny?', '{}', '"Rieux prowadzi narrację w trzeciej osobie przez całą powieść, by zachować „ton obiektywnego świadka”. Ujawnia się dopiero w ostatniej części: „Czas więc, żeby doktor Bernard Rieux wyznał, że jest jej autorem”. Funkcje zabiegu: 1) Obiektywizm — Rieux chce „świadczyć na korzyść zadżumionych”, nie na własną korzyść; mówienie o sobie w trzeciej osobie eliminuje subiektywizm. 2) Wiarygodność kroniki — narrator-lekarz ma dokumenty, świadectwa, doświadczenie. 3) Pokora — nie czyni z siebie bohatera; przez cały utwór mówi „doktor”, nie „ja”. 4) Efekt zaskoczenia — ujawnienie dodaje emocjonalny wymiar: czytelnik retrospektywnie rozumie, ile kosztowała ta „obiektywność” człowieka, który stracił żonę i przyjaciela."', NULL, '{language_use,short_answer,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "Pytanie o narrację to typowe pytanie LANGUAGE_USE na maturze rozszerzonej. Kluczowe: opóźnione ujawnienie narratora to zabieg przemyślany — Camus buduje efekt dokumentalności i pokory."}', '2026-03-17 22:49:04.778', '2026-03-17 22:49:04.778', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbbg001bqhxp1pxtghm4', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 5, 5, 'Napisz notatkę syntetyczną na podany temat:', '{"topic": "„Dżuma” jako powieść o kondycji ludzkiej — jak Camus diagnozuje człowieczeństwo w sytuacji granicznej?", "wordLimit": {"max": 250, "min": 200}, "requirements": ["Wyjaśnij, czym jest „sytuacja graniczna” w filozofii egzystencjalnej i jak realizuje się w powieści", "Wskaż, jakie postawy ujawnia dżuma: od solidarności po oportunizm", "Odwołaj się do końcowego przesłania: „w ludziach więcej rzeczy zasługuje na podziw niż na pogardę”", "Porównaj z jednym innym tekstem o sytuacji granicznej (np. „Inny świat”, „Lord Jim”)", "200-250 słów"]}', '"Notatka powinna: Sytuacja graniczna (Jaspers) = moment, w którym człowiek staje wobec śmierci, cierpienia, walki — i musi się określić. W „Dżumie” granica = zamknięte miasto, epidemia, groźba śmierci. Postawy: solidarność (Rieux, Tarrou, Grand — formacje sanitarne), bunt (Tarrou — „nie zgadzam się na zabijanie”), ewolucja (Rambert — od egoizmu do wspólnoty, Paneloux — od pewności do pokory), oportunizm (Cottard — korzysta na chaosie). Przesłanie: Camus nie idealizuje — pokazuje słabości (Rambert chce uciec, ludzie piją, kradną), ale bilans jest pozytywny: „więcej rzeczy zasługuje na podziw”. Porównanie: „Inny świat” — łagier odsłania te same postawy, ale Herling jest surowszy: system sowiecki niszczy solidarność skuteczniej niż dżuma. „Lord Jim” — jedna chwila tchórzostwa definiuje całe życie; u Camusa nie ma jednorazowego testu — jest codzienna praca. Wniosek: Camus proponuje humanizm bez iluzji — człowiek nie jest z natury dobry ani zły, jest zdolny do obu, a sytuacja graniczna wymusza wybór."', NULL, '{historical_literary,synthesis_note,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "Pytanie o kondycję ludzką to jeden z najważniejszych tematów maturalnych. „Dżuma” jest do niego idealnym tekstem — Camus celowo projektuje powieść jako laboratorium postaw."}', '2026-03-17 22:49:04.78', '2026-03-17 22:49:04.78', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbbo001cqhxpd6qr2sfv', 'ESSAY', 'WRITING', 'CONTEMPORARY', 5, 10, 'Czy bunt wobec zła może nadać sens ludzkiemu życiu? Rozważ problem, odwołując się do „Dżumy” Alberta Camusa i jednego innego tekstu kultury.', '{"thesis": "Bunt wobec zła jako sposób na nadanie sensu egzystencji", "structure": {"conclusion": "Sformułuj wniosek: bunt u Camusa to nie nadzieja na wygraną, lecz odmowa zgody na zło — i w tej odmowie tkwi godność człowieka", "introduction": "Przedstaw problem: absurd istnienia, brak wyższego sensu cierpienia, potrzeba buntu", "arguments_for": "Rieux i Tarrou jako modele buntu — walczą wiedząc, że zwycięstwo jest tymczasowe; Syzyf „szczęśliwy” mimo bezsensu", "arguments_against": "Paneloux — wiara jako alternatywa buntu; Cottard — rezygnacja z buntu; czy bunt nie jest kolejnym złudzeniem?"}, "wordLimit": {"max": 600, "min": 400}, "requirements": ["Odwołaj się do filozofii absurdu (Camus, „Mit Syzyfa”)", "Przeanalizuj postawy Rieux i Tarrou jako formy buntu", "Porównaj z innym tekstem kultury (np. „Antygona” — bunt wobec prawa, „Dziady” III — bunt prometejski, „Inny świat” — bunt wobec systemu)", "Sformułuj własne stanowisko wobec tezy", "Minimum 400 słów"]}', '"Rozprawka powinna: przedstawić filozofię absurdu (świat bez sensu, cierpienie bez przyczyny) i bunt jako odpowiedź (nie nadzieja, lecz odmowa rezygnacji). Rieux: buntuje się lekcząc, choć wie, że „zwycięstwa zawsze będą tymczasowe”. Tarrou: buntuje się odmawiając zgody na zabijanie, pragnie „niewinności”. Porównanie: Antygona — buntuje się przeciw prawu Kreona w imię prawa boskiego (bunt moralny vs. bunt egzystencjalny); Konrad z Dziadów — bunt prometejski wobec Boga (u Camusa Boga nie ma — bunt jest wobec absurdu, nie wobec Stwórcy). Stanowisko: bunt u Camusa nie obiecuje zwycięstwa, ale nadaje sens działaniu — „bakcyl dżumy nigdy nie umiera”, więc walka nigdy się nie kończy. To pesymizm metafizyczny, ale optymizm etyczny."', NULL, '{writing,essay,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "Bunt wobec zła to centralny temat egzystencjalizmu i jeden z najczęstszych tematów maturalnych. „Dżuma” jest wzorcowym tekstem do tego zagadnienia — łączy filozofię (absurd, bunt) z konkretnymi postawami bohaterów."}', '2026-03-17 22:49:04.789', '2026-03-17 22:49:04.789', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbbu001dqhxpb7c5k3ot', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'W ktorym roku zostala wydana powiessc "Dzuma" Alberta Camusa?', '{"options": ["1942", "1947", "1957", "1951"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "\"Dzuma\" ukazala sie w 1947 roku nakladem Editions Gallimard w Paryzu. Polskie tlumaczenie Joanny Guze wydano w 1957 roku. Camus otrzymal Nagrode Nobla w 1957 roku."}', '2026-03-17 22:49:04.794', '2026-03-17 22:49:04.794', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbbx001eqhxpv98p2hlk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Jak nazywa sie dozorca, ktory jest jedna z pierwszych ofiar dzumy?', '{"options": ["Joseph", "Michel", "Jean", "Raymond"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Michel to stary dozorca w kamienicy doktora Rieux. Stanowczo zaprzeczal, ze w domu sa szczury. Zachorowal na dzume z wysokimi goraczkami, dymienicami i majakami, i zmarl w karetce w drodze do szpitala."}', '2026-03-17 22:49:04.797', '2026-03-17 22:49:04.797', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbc0001fqhxpx2fk52ze', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Kim jest Jean Tarrou?', '{"options": ["Lekarze ze szpitala miejskiego", "Tajemniczy przybysz zamieszkaly w hotelu, ktory organizuje ochotnicze oddzialy sanitarne", "Prefekt miasta Oran", "Ksiadz wygłaszajacy kazania o karze Bozej"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Jean Tarrou to zamozny przybysz, ktory zamieszkal w Oranie na kilka tygodni przed epidemia. Prowadzi notatnik, w ktorym opisuje zycie miasta. Gdy wybucha dzuma, organizuje oddzialy sanitarne i walczy u boku Rieux az do smierci."}', '2026-03-17 22:49:04.801', '2026-03-17 22:49:04.801', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbc3001gqhxpasz62rt9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Co robi prefekt po oficjalnym stwierdzeniu epidemii?', '{"options": ["Ewakuuje ludnosc drogami morskimi", "Nakazuje zamkniecie bram miasta i izolacje Oranu od swiata", "Prosi o pomoc militarna z Paryza", "Rozkazuje spalic zarazone dzielnice"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Prefekt, po otrzymaniu depeszy z Urzedu Generalnego Gubernatora: \"Ogloscie stan dzumy. Zamknijcie miasto\", nakazuje zamkniecie bram. Od tej chwili Oran jest odciete od swiata — nie kursuja pociagi, statki omijaja port, korespondencje ograniczono do dziesiecioslowowych telegramow."}', '2026-03-17 22:49:04.803', '2026-03-17 22:49:04.803', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbc5001hqhxp27f0laq5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Co stalo sie z Cottardem na poczatku powiesci, przed wybuchem epidemii?', '{"options": ["Wyjechał z Oranu do Paryza", "Probowal popelnic samobojstwo przez powieszenie", "Zachorowal na dzume jako pierwszy", "Zostal aresztowany za przemyt"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Cottard probowal sie powiesic w swoim mieszkaniu. Uratowal go sasiad Grand, ktory odcial go w pore. Na drzwiach wisiala kartka: \"Wejdzcie, powiesilem sie\". Prawdopodobnie powodem byly obawy przed aresztowaniem za jakas dawna sprawe."}', '2026-03-17 22:49:04.805', '2026-03-17 22:49:04.805', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbc7001iqhxp90yuwhu7', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Ile slow mogl liczyc telegram wysylany z zamknietego Oranu?', '{"options": ["Piec", "Dziesiec", "Dwadziescia", "Nie bylo ograniczen"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Telegramy z Oranu mogly liczyc tylko dziesiec slow. Formuly takie jak \"Mam sie dobrze. Mysle o tobie. Serdecznosci\" zastepowaly calą komunikacje miedzy rozlaczonymi. Listy byly zabronione, telefony miedzynarodowe przerwane."}', '2026-03-17 22:49:04.808', '2026-03-17 22:49:04.808', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbca001jqhxp7u361ut1', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Ktore z ponizszych postaci sa bohaterami drugoplanowymi "Dzumy"?', '{"options": ["Stary astmatyk — pacjent Rieux, ktory liczy czas grochem", "Pan Othon — sedzia sledczy z rodzina", "Doktor Castel — stary lekarz, ktory przygotowuje surowice", "Meursault — urzednik zabijajacy Araba na plazy"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Stary astmatyk, sedzia Othon i doktor Castel to postacie z \"Dzumy\". Meursault to bohater innej powiesci Camusa — \"Obcego\" (1942)."}', '2026-03-17 22:49:04.81', '2026-03-17 22:49:04.81', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbcg001kqhxpt8janebn', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Ktore skutki epidemii dotknely mieszkancow Oranu?', '{"options": ["Zamkniecie bram miasta i zakaz opuszczania go", "Ograniczenie korespondencji do dziesiecioslowowych telegramow", "Calkowite zniszczenie miasta przez pozar", "Racjonowanie zywnosci i wzrost cen na czarnym rynku"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Oran zostal zamkniety, korespondencje ograniczono, ceny zywnosci rosly, rozwijaI sie czarny rynek. Miasto NIE zostalo zniszczone pozarem — pojedyncze pożary wybuchaly w domach osob wracajacych z kwarantanny, ale nie zniszczyly miasta."}', '2026-03-17 22:49:04.816', '2026-03-17 22:49:04.816', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbcj001lqhxpsdxtg1nm', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Ktore zdania poprawnie opisuja narracje w "Dzumie"?', '{"options": ["Narrator mowi o sobie w trzeciej osobie przez cala powieść", "Na koncu okazuje sie, ze narratorem jest doktor Rieux", "Narracja jest prowadzona przez Tarrou od poczatku do konca", "Narrator korzysta z notatek Tarrou, zeznań i dokumentow"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Rieux prowadzi narracje w trzeciej osobie dla zachowania obiektywnosci. Ujawnia sie dopiero w czesci V. Korzysta ze zrodel: wlasne doswiadczenie, notatki Tarrou, zeznania swiadkow, dokumenty urzedowe. Tarrou NIE jest narratorem — prowadzi tylko swoje prywatne notatki."}', '2026-03-17 22:49:04.819', '2026-03-17 22:49:04.819', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbcl001mqhxpp3eysqgd', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 1, 1, 'Jak Camus opisuje Oran na poczatku powiesci? Wymien trzy cechy miasta.', '{"hints": ["brzydkie", "bez drzew", "handel"]}', '"Oran jest opisany jako miasto brzydkie, bez golebii, bez drzew i ogrodow, pozbawione malowniczosci i duszy. Jego mieszkancy zajmuja sie przede wszystkim handlem i robieniem interesow. Zycie toczy sie wedlug stalych przyzwyczajen — praca, kawiarnie, kino, kapiele morskie w weekendy. Miasto jest zbudowane tylem do zatoki, wiec nie widac morza."', NULL, '{historical_literary,short_answer,difficulty-1,contemporary,batch-2025-01}', '{"explanation": "Opis Oranu na poczatku pelni wazna funkcje: pokazuje banalnosc, ktora zostanie rozbita przez dzume. Brak drzew, piekna i glębi duchowej symbolizuje spoleczenstwo zyjace bez refleksji — az do momentu, gdy epidemia zmusi je do zastanowienia."}', '2026-03-17 22:49:04.821', '2026-03-17 22:49:04.821', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbcn001nqhxppcu795ob', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Kto uratowal Cottarda po probie samobojczej?', '{"options": ["Doktor Rieux", "Joseph Grand — sasiad, ktory uschlyszal halas i odcial go od sznura", "Jean Tarrou", "Ojciec Paneloux"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Grand wychodzil z domu, uslyszal halas i zobaczyl napis na drzwiach. Odcial Cottarda w pore i wezwal doktora Rieux. Od tego momentu Grand czuje sie odpowiedzialny za Cottarda i czuwa nad nim."}', '2026-03-17 22:49:04.824', '2026-03-17 22:49:04.824', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbcq001oqhxpvsj11y0k', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Co robi maly staruszek obserwowany przez Tarrou z balkonu hotelu?', '{"options": ["Karmi golębie na placu miejskim", "Wychodzi na balkon, wola koty, drze papier i pluje na nie z sila i precyzja", "Gra na akordeonie dla przechodniow", "Liczy przejeżdżajace tramwaje i notuje wyniki"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Maly staruszek to jedna z ulubionych postaci Tarrou. Codziennie o tej samej porze wychodzi na balkon, wabi koty, drze papier na kawałki, a gdy koty sie zbliżają — pluje na nie z duzą precyzja i smieje sie, gdy trafia. Gdy dżuma zabiera koty (zastrzelone przez patrole), staruszek popada w smutek."}', '2026-03-17 22:49:04.826', '2026-03-17 22:49:04.826', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbcs001pqhxpsjsqm2b0', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Co doktor Richard, sekretarz syndykatu lekarzy, sadzil o epidemii?', '{"options": ["Od poczatku twierdzil, ze to dzuma, i zadal natychmiastowych srodkow", "Wahal sie, uwazal, ze nie nalezy panikować, unikal slowa \"dzuma\" i proponowal ostrozne formy: \"goraczka z komplikacjami pachwinowymi\"", "Natychmiast opuscil Oran, zostawiajac pacjentow", "Twierdzil, ze to zatrucie pokarmowe, nie choroba zakazna"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Richard reprezentuje postawe biurokratycznej ostroznosci — odmawia nazwania choroby po imieniu, bo oficjalne orzeczenie \"zmuszaloby do zastosowania bezlitosnych srodkow\". Rieux ripostuje: \"Nie chodzi o to, by malowac w czarnych kolorach. Chodzi o to, by przedsięwziac srodki ostroznosci.\""}', '2026-03-17 22:49:04.828', '2026-03-17 22:49:04.828', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbcu001qqhxpjdt98edt', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Jak zmienil sie sedzia Othon po smierci syna?', '{"options": ["Opuscil Oran i wrocil do Francji", "Po zakonczeniu kwarantanny poprosil o powrot do obozu jako ochotnik — chcial byc blizej syna", "Zaczal glosic kazania religijne w zastepstwie Paneloux", "Nie zmienil sie wcale — pozostal sztywny i oficjalny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Othon, dotychczas sztywny i oficjalny sedzia-\"sowa\", po smierci synka calkowicie sie zmienia. Po zakonczeniu kwarantanny prosi o powrot do obozu internowanych jako ochotnik: \"Czulbym sie blizej mego chlopca\". Rieux dostrzega w jego oczach nowa lagodnosc. Ostatecznie Othon takze umiera na dzume."}', '2026-03-17 22:49:04.831', '2026-03-17 22:49:04.831', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbcw001rqhxpwl1evasb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Kto pomagal Rambertowi w organizacji ucieczki z Oranu?', '{"options": ["Doktor Rieux i prefekt", "Cottard, ktory znal siec przemytnikow — oraz Garcia, Raoul, Gonzales, Marcel i Louis", "Tarrou i oddzialy sanitarne", "Ojciec Paneloux i parafie koscielne"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Rambert probowal ucieczki kanałami nielegalnym. Cottard skontaktowal go z Garcią, ten z Raoulem, a Raoul z dwoma mlodymi straznikami — Marcelem i Louisem. Plan wielokrotnie sie komplikowal: spotkania nie dochodziły do skutku, dzielnice byly zamykane, straznikow zmieniano. Ostatecznie Rambert zrezygnowal z ucieczki."}', '2026-03-17 22:49:04.833', '2026-03-17 22:49:04.833', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbd0001sqhxpg5nsiiu3', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Ktore z ponizszych scen wystepuja w powiesci?', '{"options": ["Spektakl operowy \"Orfeusza i Eurydyki\", podczas ktorego spiewak pada na scene", "Nocna kapiel Rieux i Tarrou w morzu", "Bunt wiezniow i ich ucieczka z obozu internowania", "Grand mdleje na ulicy w Wigilie i ledwo przetrywa dzume"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Opera (spiewak pada, publicznosc ucieka), kapiel w morzu (Rieux i Tarrou po nocnej rozmowie) oraz choroba Granda (mdleje pod Boze Narodzenie, cudownie wraca do zdrowia) — to sceny z powiesci. Bunt wiezniow nie wystepuje — sa rozruchy przy bramach miasta, ale nie ucieczka wiezniow."}', '2026-03-17 22:49:04.836', '2026-03-17 22:49:04.836', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbd2001tqhxp8iajazuu', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Uzupelnij zdania, wybierajac poprawne opcje:', '{"gaps": [{"id": 1, "options": ["oficjalna kronikę dla prefektury", "prywatny notatnik", "dziennik religijny", "pamietnik dla syna"]}, {"id": 2, "options": ["zegara slonecznego", "dwoch garnkow z grochem", "klepsydry", "kalendarza"]}, {"id": 3, "options": ["raportem statystycznym", "listem do zony", "zdaniem o amazonce jadacej alejami Lasku Bulonskiego", "przemowieniem dla prefekta"]}], "textWithGaps": "Tarrou prowadzi (1), w ktorym opisuje zycie miasta. Stary astmatyk mierzy czas za pomoca (2). Grand pracuje nad jednym (3) przez cala powiessc."}', '[1, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Tarrou prowadzi prywatny notatnik (kronikę pisze Rieux). Stary astmatyk odmierza czas przesypujac groch z garnka do garnka. Grand szlifuje zdanie: \"W piekny poranek majowy smukla amazonka, siedzac na wspanialej kasztance, jechala kwitnacymi alejami Lasku Bulonskiego\"."}', '2026-03-17 22:49:04.839', '2026-03-17 22:49:04.839', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbd4001uqhxpw6lt5r9d', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Ktore formy ograniczenia wolnosci dotknely mieszkancow Oranu?', '{"options": ["Zakaz opuszczania miasta — zamkniete bramy strzeżone przez żandarmów", "Ograniczenie korespondencji — listy zabronione, tylko telegramy", "Calkowity zakaz wychodzenia z domow przez caly dzien", "Zaciemnienie i godzina policyjna od jedenastej wieczor"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Bramy zamknieto, korespondencje ograniczono do telegramow, wprowadzono zaciemnienie i godzine policyjną. Nie bylo calkowitego zakazu wychodzenia — ludzie mogli chodzic po miescie w ciagu dnia, chodzili do kawiarni, kin i restauracji. Ograniczano natomiast poruszanie sie noca."}', '2026-03-17 22:49:04.841', '2026-03-17 22:49:04.841', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbd8001vqhxpgphkgm3f', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Opisz krotko rodzine pana Othona wedlug notatek Tarrou.', '{"hints": ["sowa", "czarna mysz", "tresowane psy"]}', '"Tarrou opisuje rodzine Othona z ironia: ojciec-sedzia to \"dobrze wychowana sowa\" — wysoki, chudy, w sztywnym kolnierzyku, z lysym srodkiem czaszki. Zona to \"czarna mysz\" — drobna i cicha. Dwojka dzieci (chlopiec i dziewczynka) wygladaja jak \"tresowane pudle\" — ubrane elegancko, karnie siedzace przy stole. Othon recytuje \"uprzejme zlosliwosci\" pod adresem zony i \"zdania o charakterze ostatecznym\" do dzieci: \"Nicole jest w najwyzszym stopniu antypatyczna!\""', NULL, '{historical_literary,short_answer,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Opis rodziny Othona to jeden z najzabawniejszych fragmentow notatek Tarrou. Sluzy jako kontrast: sztywny, bezduszny sedzia po smierci syna stanie sie postacia wzruszajaca i ludzka."}', '2026-03-17 22:49:04.844', '2026-03-17 22:49:04.844', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbdb001wqhxppmiebi8p', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Kim jest Gonzales i jaka role pelni w watku ucieczki Ramberta?', '{}', '"Gonzales to gracz w pilke nozna (srodkowy napastnik), z ktorym Rambert umawia sie przez posrednikow (Garcię i Raoula). Gonzales zna dwoch mlodych straznikow — Marcela i Louisa — ktorzy moga otworzyc droge przez bramy. Kontakty z Gonzalesem sa wielokrotnie przerywane, bo zamykane sa calye dzielnice. Gonzales kopie kamyki na ulicy, celujac w otwory scieków, i mowi o pilce noznej — to jedyny temat, ktory naprawde go ozywia."', NULL, '{historical_literary,short_answer,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Gonzales jest postacia epizodyczna, ale wazna fabularnie — to ostatnie ogniwo lancucha kontaktow prowadzacych do ucieczki. Jego pasja do pilki noznej humanizuje swiaty przemytu i kontrabandy."}', '2026-03-17 22:49:04.847', '2026-03-17 22:49:04.847', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbdd001xqhxps769kz12', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 2, 1, 'Dlaczego Rieux odmawia wydania Rambertowi zaswiadczenia o zdrowiu?', '{}', '"Rieux tllumaczy, ze nie moze zaswiadczyc, iz Rambert nie ma dzumy, poniewaz miedzy wizyta w gabinecie a wizyta w prefekturze dziennikarz moze zostac zarazony. Poza tym nawet gdyby wydal zaswiadczenie, nie przydaloby sie ono na nic — w miescie tysiace ludzi jest w tym samym polozeniu, a mimo to nie mozna im pozwolic wyjechac. Rieux nie odmawia ze zlosliwosci, lecz z uczciwosci: nie chce dawac falszywyych gwarancji."', NULL, '{historical_literary,short_answer,difficulty-2,contemporary,batch-2025-01}', '{"explanation": "Scena ta ustanawia postawe Rieux wobec Ramberta: szacunek, ale odmowa robienia wyjatkow. Rieux mowi: \"Tu chodzi o dobra wole\" — ale system (dzuma) nie uznaje dobrych woli. To zapowiada temat abstrakcji."}', '2026-03-17 22:49:04.849', '2026-03-17 22:49:04.849', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbdf001yqhxp0j59dxns', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Jaka ewolucje przechodzi Rambert w ciagu powiesci?', '{"options": ["Zaczyna jako bohater i konczy jako tchorz", "Zaczyna jako indywidualista walczacy o prywatne szczescie, a konczy jako czlonek wspolnoty — rezygnuje z ucieczki i dolacza do formacji sanitarnych", "Zaczyna jako ateista i konczy jako wierzacy pod wplywem Paneloux", "Nie przechodzi zadnej ewolucji — od poczatku walczy z dzuma"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Rambert przechodzi od indywidualizmu do solidarnosci. Na poczatku mowi: \"Nie jestem stad\" i walczy o prywatne szczescie (powrot do zony). Ale po wizycie w szpitalu i rozmowach z Rieux i Tarrou zrozumial: \"Moze byc wstyd, ze czlowiek jest sam tylko szczesliwy\". Jego ewolucja ilustruje teze Camusa, ze dzuma jest \"sprawa nas wszystkich\"."}', '2026-03-17 22:49:04.852', '2026-03-17 22:49:04.852', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbdh001zqhxpjefd11ym', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Co Tarrou notuje o zachowaniu mieszkancow Oranu w szczycie epidemii?', '{"options": ["Ze ludzie stali sie bardziej pobozni i spedzaja czas w kosciolach", "Ze ludzie pija duzo, trafia sie im w jedzeniu i rozrywkach, zyja na pelnych obrotach — jakby probowali przezywac intensywnie każdy dzien, bo moze byc ostatni", "Ze ludzie z calkowitym spokojem akceptuja swoj los", "Ze ludzie organizuja strajki i demonstracje przeciwko prefekturze"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Tarrou opisuje goraczke zycia: \"Alkohol zdrowiu sprzyja, zabija bakcyla\" — glosi wywieszcka w kawiarni. Ludzie trwonia pieniadze, jedza w drogich restauracjach, pija bez umiaru. Wieczorami tlum wypelnia ulice w poszukiwaniu ciepla ludzkiego. To reakcja na bliskosc smierci — intensywnosc zycia jako bunt wobec zagłady."}', '2026-03-17 22:49:04.854', '2026-03-17 22:49:04.854', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbdk0020qhxpjgub42c5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Dlaczego narrator uwaza, ze "dwa i dwa to cztery" jest wazna prawda w kontekscie walki z dzuma?', '{"options": ["Bo lekarze potrzebuja dokladnych obliczen statystycznych", "Bo walka z dzuma to kwestia prostej logiki i uczciwosci — trzeba stwierdzac oczywiste fakty (\"to jest dzuma\", \"trzeba izolowac chorych\") nawet gdy inni nie chca ich przyjac do wiadomosci", "Bo Grand jest matematykiem i uczy dzieci w szkole", "Bo prefekt wymaga raportow liczbowych co tydzien"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Narrator pisze: \"Nie gratuluje sie nauczycielowi, jesli uczy, ze dwa i dwa to cztery\". Sens: walka z dzuma to nie heroizm, lecz prosta uczciwosc — stwierdzanie faktow, robienie tego, co oczywiste. Ludzie z formacji sanitarnych \"wiedzieli, ze byla to jedyna rzecz do zrobienia: nie wejsc do nich to dopiero byloby niewiarygodne\"."}', '2026-03-17 22:49:04.856', '2026-03-17 22:49:04.856', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbdm0021qhxpkc8ciatb', 'CLOSED_SINGLE', 'LANGUAGE_USE', 'CONTEMPORARY', 3, 2, 'Jaki zabieg kompozycyjny stosuje Camus, umieszczajac akcje w roku "194." bez ostatniej cyfry?', '{"options": ["Jest to blad w rekopisie, ktory wydawca nie poprawil", "Jest to celowe zatarcie daty — sygnal parabolicznosci: historia Oranu mogla wydarzyc sie w kazdym roku i kazdym miejscu, jest uniwersalna", "Oznacza, ze akcja rozgrywa sie w przyszlosci", "Wskazuje na tajnosc dokumentow, z ktorych korzysta narrator"]}', '1', NULL, '{language_use,closed_single,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Zatarcie daty to jeden z kluczowych sygnalow parabolicznosci. Razem z mottem z Defoe i uniwersalnoscia postaw bohaterow mówi czytelnikowi: nie chodzi o konkretna epidemie, lecz o kazda forme zła, ktora moze dotknac ludzkość. Podobne zabiegi stosuja inne parabole — np. \"Proces\" Kafki (nieokreslone miasto i czas)."}', '2026-03-17 22:49:04.858', '2026-03-17 22:49:04.858', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbdo0022qhxpfgv9kr0u', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Polacz bohaterow z ich kluczowymi wypowiedziami:', '{"leftColumn": [{"id": "A", "text": "\"Chcialbym nauczyc sie wypowiadac\""}, {"id": "B", "text": "\"Mam wstret do wyrokow smierci\""}, {"id": "C", "text": "\"Co to jednak znaczy — dzuma? To zycie, ot i wszystko\""}, {"id": "D", "text": "\"Nie jestem stad\""}], "rightColumn": [{"id": "1", "text": "Tarrou — o zrodle swojego buntu"}, {"id": "2", "text": "Rambert — prosze o prawo wyjazdu"}, {"id": "3", "text": "Grand — o trudnosci ze slowami"}, {"id": "4", "text": "Stary astmatyk — filozofia zyciowa"}], "matchingType": "quotes_to_works"}', '[[0, 2], [1, 0], [2, 3], [3, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Grand chce \"nauczyc sie wypowiadac\" — cale jego zycie to walka ze slowami. Tarrou ma \"wstret do wyrokow smierci\" — to fundament jego postawy. Stary astmatyk rownowazy dzume z zyciem — filozofia biernej akceptacji. Rambert powtarza \"nie jestem stad\" — argumentujac za prawem do wyjazdu."}', '2026-03-17 22:49:04.861', '2026-03-17 22:49:04.861', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbdr0023qhxpddbiro1o', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Ktore elementy "Dzumy" nawiazuja do doswiadczen II wojny swiatowej?', '{"options": ["Zamkniecie miasta = okupacja, izolacja ludnosci pod terrorem", "Obozy kwarantanny i internowania = obozy koncentracyjne", "Formacje sanitarne = ruch oporu, walka podziemna ze zlem", "Bitwa morska pod Oranem miedzy flotami francuskaa i brytyjska"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Camus pisal \"Dzume\" w latach 1941-1947, w kontekscie okupacji Francji. Zamkniete miasto = okupacja, izolacja = utrata wolnosci, obozy = obozy jenieckie/koncentracyjne, formacje sanitarne = ruch oporu. Bitwa morska pod Oranem (1940, operacja Catapult) nie jest tematem powiesci."}', '2026-03-17 22:49:04.864', '2026-03-17 22:49:04.864', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbdt0024qhxpj7t45zdb', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Ktore z ponizszych stwierdzen o smierci Tarrou sa prawdziwe?', '{"options": ["Tarrou zachorowal na dzume tuz przed koncem epidemii", "Rieux pielegnował go w swoim domu zamiast w szpitalu", "Tarrou wyzdrowiał dzieki surowicy Castela", "Przy lozku Tarrou czuwala matka Rieux"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Tarrou zachorowal pod koniec epidemii, Rieux zatrymał go w domu (zamiast szpitalnej izolacji — akt przyjaźni). Matka Rieux czuwala przy łóżku. Tarrou NIE wyzdrowiał — umarl po calej nocy walki z choroba. Rieux pisze: \"Tarrou przegral partie\"."}', '2026-03-17 22:49:04.866', '2026-03-17 22:49:04.866', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbdw0025qhxprt9vpcfz', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Jak ewoluowaly pogrzeby w miare trwania epidemii? Opisz co najmniej trzy etapy.', '{"instruction": "Odwolaj sie do zmian w ceremoniale, transporcie i miejscach pochowku."}', '"Etapy: 1) Poczatek — przyspieszony pogrzeb: cialo umyte, trumna zamknieta, rodzina podpisuje dokumenty, auto wiezie na cmentarz, ksiadz odprawia krotki obrzad. 2) Srodek — trumny wielorazowe: ciala ladowane grupowo, wozzone w ambulansach, opróżniane do dolow, dezynfekcja trumien, krewni usuwani z ceremonii. 3) Szczyt — kremacja: doly przepelnione, wywłaszczono stare groby, uzyto pieca krematoryjnego za miastem. Tramwaje bez pasazerow wozily trupy skalna droga nadmorska. Mieszkancy rzucali kwiaty do srodka przejezdzajacych tramwajow. Dym z pieca unosil sie nad dzielnicami wschodnimi."', NULL, '{historical_literary,short_answer,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Ewolucja pogrzebow to jeden z najwazniejszych motywow czesci IV. Camus pokazuje, jak system (administracja, skuteczność) stopniowo odbiera smierci ludzkii wymiar — az trupy wozi sie tramwajami jak towary."}', '2026-03-17 22:49:04.868', '2026-03-17 22:49:04.868', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbdz0026qhxpr1iqui3y', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Co sie stalo z Josephem Grandem pod Boze Narodzenie?', '{}', '"Grand placze pod sklepem przybranym na swieta — wspomina Jeanne, swoja dawna zone. Rieux znajduje go na ulicy, placzacego i trzesacego sie. Grand mdleje z goraczka — ma objawy dzumy plucnej. Przed utrata przytomnosci blaga, by spalono jego rekopis (szlifowane zdanie). Rieux wrzuca kartki do ognia. Ale wbrew wszelkim regułom Grand wraca do zdrowia nastepnego dnia — co jest jednym z pierwszych znakow cofania sie epidemii. Po wyzdrowieniu mowi: \"Nie mialem racji. Ale zaczne na nowo\"."', NULL, '{historical_literary,short_answer,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Choroba i cudowne wyzdrowienie Granda to punkt zwrotny powiesci — pierwszy sygnał, ze dzuma slabnie. Spalenie rekopisu jest symboliczne: Grand poswiecił to, co najcenniejsze, ale przeżył i \"zaczyna na nowo\" — co streszcza przeslanie calej powiesci."}', '2026-03-17 22:49:04.871', '2026-03-17 22:49:04.871', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbe10027qhxpr6dntgvn', 'SHORT_ANSWER', 'LANGUAGE_USE', 'CONTEMPORARY', 3, 2, 'Jaka role pelnia notatki Tarrou w kompozycji powiesci?', '{}', '"Notatki Tarrou stanowia drugie zrodlo narracji obok kroniki Rieux. Pelnia kilka funkcji: 1) Dostarczaja innej perspektywy — Tarrou obserwuje detale, ktore Rieux pomija (mały staruszek z kotami, rodzina Othona, kasjer hotelu). 2) Wprowadzaja ton osobisty — notatki sa subiektywne, ironiczne, czasem poetyckie, podczas gdy Rieux dazy do obiektywnosci. 3) Buduja portret Tarrou jako postaci — pozwalaja poznac jego filozofie zanim sam ja wyjawi. 4) Uzupelniaja fabuły o \"historię tego, co nie ma historii\" — codzienność podczas epidemii, drobne gesty, absurdy."', NULL, '{language_use,short_answer,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Notatki Tarrou to wazny element kompozycji — tworzą polifonię narracyjna. Na maturze pojawia się pytanie o konstrukcje narracji w \"Dzumie\" i role roznych zrodel (kronika Rieux, notatki Tarrou, dokumenty, zeznania)."}', '2026-03-17 22:49:04.873', '2026-03-17 22:49:04.873', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbe30028qhxpmf0n5p61', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 3, 'Napisz notatke syntetyczna na podany temat:', '{"topic": "Motyw rozlaki i wygnania w \"Dzumie\" — jak epidemia zmienia psychike rozlaczonych?", "wordLimit": {"max": 150, "min": 100}, "requirements": ["Wymien co najmniej trzy przyklady rozlaki (Rieux, Rambert, ogol mieszkancow)", "Opisz etapy psychologiczne: od bolu, przez otepienie, do zobojętnienia", "Wyjasnij, dlaczego narrator mowi o \"wygnaniu we wlasnym domu\"", "100-150 slow"]}', '"Notatka powinna: Rieux — zona w sanatorium, komunikacja przez depesze, na koncu smierć. Rambert — partnerka w Paryzu, desperacka proba ucieczki, ostatecznie rezygnacja. Ogol — rodziny rozdzielone zamknieciem bram, kontakt przez 10 slow telegramu. Etapy: 1) Ostry bol rozlaki, zylwe wspomnienia. 2) Stopniowe blakniecie pamieci — twarze bliskich staja sie \"bezcielesne\". 3) Otepienie — ludzie przestaja cierpiec indywidualnie, wchodza w \"rytm dzumy\". \"Wygnanie we wlasnym domu\" — bo ludzie sa w swoim miescie, ale odcięci od tego, co stanowilo ich zycie: bliskich, wolnosci, przyszlosci."', NULL, '{historical_literary,synthesis_note,difficulty-3,contemporary,batch-2025-01}', '{"explanation": "Motyw rozlaki zajmuje znaczna czesc II czesci powiesci. Camus analizuje psychologie rozlaczonych z precyzja kliniczna — od bolu, przez nadzieje, po zobojętnienie."}', '2026-03-17 22:49:04.876', '2026-03-17 22:49:04.876', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbe50029qhxp98kpjfhp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 2, 'Dlaczego Cottard jest jedynym bohaterem, ktoremu dzuma "dogadza"?', '{"options": ["Poniewaz jest lekarzem i zarabia na epidemii", "Poniewaz przed dzuma grozilo mu aresztowanie — w chaosie epidemii policja nie prowadzi dochodzen, a Cottard czuje sie bezpieczny i rowny innym: \"wreszcie wszyscy sa w jednym worku\"", "Poniewaz jest immiigrantem i chce, by Francuzi cierpieli", "Poniewaz wierzy, ze dzuma jest kara Boza za grzechy innych"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Cottard to czlowiek \"z ciezarem na sumieniu\" — ciazy nad nim stare sledztwo. Dzuma go wyzwala: w zarazonym miescie nikt nie prowadzi dochodzen, a wszyscy boja sie tak jak on bał sie wczescniej. Tarrou pisze: \"to czlowiek, ktory rosnie\" — Cottard odzywa w chorobie. Gdy epidemia sie konczy, wpada w panike i strzela do ludzi."}', '2026-03-17 22:49:04.878', '2026-03-17 22:49:04.878', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbe9002aqhxpst5i2m9i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 2, 'Jakie znaczenie ma scena finalowa z Cottardem?', '{"options": ["Cottard ucieka z Oranu i nigdy nie zostaje zlappany", "W dniu otwarcia bram Cottard strzela z okna do przechodniow, zostaje pobity i aresztowany — symbolizuje powrot porzadku prawnego i koniec \"wolnosci\" dawaanej przez dzume", "Cottard przeprasza za swoje czyny i dolacza do formacji sanitarnych", "Cottard popelnia samobojstwo, powtarzajac swoją probe z poczatku powiesci"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Cottard, wiedzac ze koniec dzumy oznacza powrot policji i dochodzen, szaleje — zamyka sie w mieszkaniu i strzela do ludzi na ulicy. Policja go aresztuje, bijac go piescciami. Rieux odwraca wzrok. Scena to kontrast z powszechna radoscia — przypomina, ze nie dla wszystkich wyzwolenie jest szczesliwe."}', '2026-03-17 22:49:04.881', '2026-03-17 22:49:04.881', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbeb002bqhxpa5hztby9', 'CLOSED_SINGLE', 'LANGUAGE_USE', 'CONTEMPORARY', 4, 2, 'Jaka funkcje pelni zdanie Granda o amazonce w strukturze powiesci?', '{"options": ["Jest komicznym przerywnikiem bez glebszego sensu", "Symbolizuje dazenie do doskonalosci i poszukiwanie wlasciwego slowa — Grand robi to samo co Camus jako pisarz i co Rieux jako lekarz: probuje \"dokladnie oddac obraz\" rzeczywistosci, wiedzac, ze nigdy nie bedzie doskonały", "Jest cytatem z innej powiesci, do ktorej Camus nawiazuje", "Sluzy wylacznie charakterystyce Granda jako czlowieka umyslowo chorego"]}', '1', NULL, '{language_use,closed_single,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Zdanie o amazonce to metafora pisarstwa samego Camusa i kazdej twórczosci: szlifowanie, poprawianie, poszukiwanie doskonalosci — ktora jest nieosiagalna. Grand pisze tak, jak Rieux leczy: ze swiadomoscia porażki, ale z uporem. Spalenie rekopisu i \"zaczynamy na nowo\" to najkrótsza formuła egzystencjalizmu."}', '2026-03-17 22:49:04.883', '2026-03-17 22:49:04.883', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbed002cqhxpw19uc8pt', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 2, 'Ktore z ponizszych stwierdzeen o roli narratora-Rieux sa prawdziwe?', '{"options": ["Rieux mowi o sobie w trzeciej osobie, by zachowac obiektywnosc swiadka", "Korzysta z wielu zrodel: wlasne doswiadczenie, notatki Tarrou, zeznania, dokumenty", "Celowo ukrywa wlasne cierpienia (smierć zony, zmeczenie), by nie przeslonic cierpienia zbiorowego", "Napisal kronike, zeby slaawic wlasne bohaterstwo i domagac sie uznania"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Rieux-narrator: mowi w 3. osobie (obiektywnosc), zbiera zrodla (wieloglos), ukrywa osobiste cierpienia (pokora). Nie pisze dla slawy — pisze \"zeby swiadczyc na korzysc zadzumionych\" i \"zeby nie nalezec do tych, co milczą\". Jego kronika jest aktem solidarnosci, nie promocji osobistej."}', '2026-03-17 22:49:04.886', '2026-03-17 22:49:04.886', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbeg002dqhxpzbayfg4g', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 2, 'Ktore konteksty historyczne i filozoficzne sa kluczowe dla interpretacji "Dzumy"?', '{"options": ["Doswiadczenie II wojny swiatowej i okupacji Francji (1940-1944)", "Filozofia egzystencjalna Camusa — absurd, bunt, solidarnosc", "Wojna trzydziestoletnia w Europie (1618-1648)", "Filozofia Camusa z \"Mitu Syzyfa\" — sens zycia wobec absurdu"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Kluczowe konteksty: II wojna swiatowa (Camus pisal powiessc w 1941-1947, dzuma = metafora okupacji), egzystencjalizm (absurd, wolnosc, odpowiedzialnosc, bunt), \"Mit Syzyfa\" (Rieux = Syzyf: dziala bez nadziei na ostateczne zwyciestwo). Wojna trzydziestoletnia nie ma zwiazku z \"Dzuma\"."}', '2026-03-17 22:49:04.889', '2026-03-17 22:49:04.889', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbej002eqhxpjhz7asoh', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 3, 'Porownaj Rieux i Tarrou jako dwa modele walki ze zlem. Czym sie roznia, a co ich laczy?', '{}', '"Lacza ich: obaj walczaa z dzuma czynnie, obaj sa ateistami, obaj odrzucaja heroiczna retoryke, obaj poswiecaja sie bezinteresownie. Roznice: Rieux walczy z obowiazku zawodowego i uczciwosci — \"to sprawa, ktora czlowiek taki jak pan potrafi zrozumiec\"; to pragmatyk, lekarz. Tarrou walczy z glebokich przekonan filozoficznych — pragnie \"swietosci bez Boga\", szuka \"spokoju wewnetrznego\", chce byc \"niewinnym morderca\". Rieux mowi o \"nie konczacej sie klesce\"; Tarrou szuka odkupienia za to, ze sam byl kiedys \"zadzumiony\" (zgadzal sie na kare smierci). Rieux przetrywa, Tarrou ginie — co podkresla tragizm idealizmmu wobec pragmatyzmu."', NULL, '{historical_literary,short_answer,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Porownanie Rieux-Tarrou to klasyczne pytanie maturalne. Kluczowe: Rieux = uczciwość zawodowa, Tarrou = bunt metafizyczny. Obaj dochodzą do tego samego punktu (solidarność), ale rozna droga."}', '2026-03-17 22:49:04.891', '2026-03-17 22:49:04.891', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbel002fqhxpnvt9208r', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 3, 'Wyjasnij, dlaczego smierc dziecka sedziego Othona jest punktem kulminacyjnym powiesci. Jak reaguja na nia rozni bohaterowie?', '{"instruction": "Odwolaj sie do reakcji Rieux, Paneloux, Castela i Tarrou."}', '"Dziecko umiera mimo zastosowania nowego serum Castela — w dlugiej, męczarniowej agonii: konwulsje, krzyk, pot, goraczka. Reakcje: Castel zamknal ksiazke i patrzyl bezradnie. Tarrou otarl dziecku twarz. Paneloux kleczal i modlil sie: \"Boze moj, uratuj to dziecko\". Rieux wyszedl z sali — nie mogl tego zniesc — i powiedzial do Paneloux: \"Ten przynajmniej byl niewinny\". Scena jest kulminacyjna, bo konfrontuje wszystkich z problemem cierpienia niewinnych — centralnym pytaniem teodycei. Paneloux nie ma odpowiedzi. Rieux odmawia kochania swiata, ktory torturuje dzieci. To zderzenie stanowi rdzen filozoficzny powiesci."', NULL, '{historical_literary,short_answer,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Scena smierci dziecka jest jednym z najczesciej analizowanych fragmentow \"Dzumy\" na maturze. Kluczowe: cierpienie niewinnego podwaza zarowno religijne wyjaśnienie (Paneloux), jak i optymizm medycyny (Castel)."}', '2026-03-17 22:49:04.893', '2026-03-17 22:49:04.893', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbeo002gqhxp1s9vodt8', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 3, 'Co Tarrou opowiada Rieux o swoim ojcu i jak to doswiadczenie uformowalo jego postawe zyciowa?', '{}', '"Ojciec Tarrou byl zastepca prokuratora generalnego — \"poczciwy czlowiek\" z mania rozkladu jazdy Chaixa. Gdy Tarrou mial 17 lat, ojciec zabral go do sadu przysieglych. Tarrou zobaczyl oskarzonego — \"rudego czlowieczka\" — i zrozumial, ze ojciec zada jego smierci: \"ta glowa powinna spasc\". Odtad nie mogl patrzec na ojca tak samo. Uciekl z domu. Angażowal sie w politykę po stronie walczacych z systemem, ale odkryl, ze i oni skazuja na smierć. Zrozumial, ze \"przez te wszystkie dlugie lata bylm zadzumionym\" — ze zgadzal sie posrednio na zabijanie. Odtad postanowil \"odrzucic wszystko, co z bliska czy z daleka powoduje smierć lub usprawiedliwia zabojstwo\"."', NULL, '{historical_literary,short_answer,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Spowiedz Tarrou (czesc IV, scena na tarasie) to jeden z najdluzszych monologow w powiesci. Wyjasnnia, dlaczego Tarrou pragnie \"swietosci bez Boga\" — chce zyc \"po stronie ofiar\", nigdy \"po stronie zaraz\"."}', '2026-03-17 22:49:04.897', '2026-03-17 22:49:04.897', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbeq002hqhxpie26yj9h', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 4, 'Napisz notatke syntetyczna na podany temat:', '{"topic": "Cottard jako anty-bohater \"Dzumy\" — dlaczego dzuma jest dla niego wyzwoleniem?", "wordLimit": {"max": 200, "min": 150}, "requirements": ["Opisz sytuacje Cottarda przed epidemia (proba samobojcza, lęk przed aresztowaniem)", "Wyjasnij, dlaczego w czasie dzumy Cottard \"rosnie\" i czuje sie dobrze", "Zanalizuj jego zalamanie po koncu epidemii (strzaly z okna, aresztowanie)", "Porownaj postawe Cottarda z postawa Rieux lub Tarrou", "150-200 slow"]}', '"Notatka powinna: Przed dzuma — prooba samobojcza, ciazy nad nim sledztwo, zyje w strachu i izolacji. W czasie dzumy — odzywa: \"wreszcie wszyscy sa w jednym sosie\". Nie prowadzi sie dochodzen, policja zajeta epidemia, Cottard moze zyc swobodnie. Bogaci sie na kontrabandzie, bywa w restauracjach, jest towarzyski. Mowi: \"Dobrze mi z dzuma\". Po koncu — zalamanie: powrot porzadku = powrot sledztwa. Strzela z okna do ludzi, zostaje pobity i aresztowany. Porownanie: Rieux i Tarrou walcza Z dzuma, Cottard KORZYSTA na dzumie. Oni definiuja sie przez bunt wobec zla — on przez zgode na zło, ktore chroni go przed innym zlłem (wymiarem sprawiedliwosci). Cottard to \"wspolwinowajca\" — uosabia postawe ludzi, ktorym chaos sluzy."', NULL, '{historical_literary,synthesis_note,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Cottard to fascynujaca postac moralna: jedyny czlowiek, dla ktorego epidemia jest korzystna. Tarrou mowi o nim: \"To czlowiek, ktory rosnie\". Na maturze pojawia sie w kontekscie postaw wobec zla."}', '2026-03-17 22:49:04.899', '2026-03-17 22:49:04.899', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbet002iqhxp8udn0z26', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 4, 4, 'Napisz notatke syntetyczna na podany temat:', '{"topic": "Motyw miasta w \"Dzumie\" — Oran jako przestrzen zamknieta, wiezienie i laboratorium postaw", "wordLimit": {"max": 200, "min": 150}, "requirements": ["Opisz, jak Camus kreuje Oran na poczatku (banalnosc, brzydota, brak duszy)", "Wyjasnij, jak zamkniecie bram zmienia przestrzen — miasto jako wiezienie", "Wskazz, dlaczego zamknieta przestrzen sluzy jako \"laboratorium\" postaw ludzkich", "Porownaj z motywem zamknietej przestrzeni w innym utworze", "150-200 slow"]}', '"Notatka powinna: Oran na poczatku — brzydki, banalny, \"bez golębi, bez drzew\", zyje handlem, jest \"miastem bez podejrzen\". Zamkniecie — bramy strzezone, port pusty, tramwaje jako jedyny transport, zaciemnienie noca. Miasto staje sie wiezieniem: \"nawet niebo pełne gwiazd stalo sie sufitem celi\". Laboratorium — zamknieta przestrzen wymusza konfrontacje z dzumą (złem): nie mozna uciec, trzeba wybrac postawe (walka, rezygnacja, oportunizm). Kazdy bohater definiuje sie wobec zamkniecia: Rambert chce uciec, Rieux walczy, Cottard kwitnie. Porownanie: \"Proces\" Kafki — Josef K. tez jest \"zamkniety\" w systemie, ktory nie daje sie zrozumiec; ale u Kafki nie ma solidarnosci (K. jest sam), u Camusa ludzie laczą sie we wspolnocie."', NULL, '{historical_literary,synthesis_note,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Motyw zamknietego miasta to topos oblezzonego miasta — czesty temat maturalny (pytania jawne 2026-2028). Kluczowe: Oran = mikrokosmos ludzkosci."}', '2026-03-17 22:49:04.901', '2026-03-17 22:49:04.901', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbew002jqhxpd1d44y7d', 'ESSAY', 'WRITING', 'CONTEMPORARY', 4, 5, 'Solidarnosc ludzi w obliczu zagrozenia. Omow zagadnienie, odwolujac sie do "Dzumy" Alberta Camusa i jednego innego tekstu kultury.', '{"wordLimit": {"min": 300}, "requirements": ["Zdefiniuj solidarnosc w kontekscie powiesci (formacje sanitarne, wspolna walka, rezygnacja z egoizmu)", "Przeanalizuj ewolucje Ramberta jako przykład drogi od indywidualizmu do solidarnosci", "Odwolaj sie do roli Tarrou i Granda w budowaniu wspolnoty", "Porownaj z innym tekstem kultury (np. \"Kamienie na szaniec\", \"Inny swiat\", \"Medaliony\")", "Minimum 300 slow"]}', '"Rozprawka powinna: zdefiniowac solidarnosc u Camusa (nie heroizm, lecz codzienna praca — \"dwa i dwa to cztery\"), pokazac Ramberta (od \"nie jestem stad\" do \"ta sprawa dotyczy nas wszystkich\"), Tarrou (organizator formacji, solidarny z ofiarami), Granda (cichhy bohater, ktory \"mial tylko dobre serce\"). Porownanie: \"Kamienie na szaniec\" — solidarnosc mlodziezy w AK (bohaterstwo spektakularne vs. codzienne u Camusa); \"Inny swiat\" — w łagrze solidarnosc jest rzadsza, ale istnieje (Kostylew); \"Medaliony\" — brak solidarnosci jako forma zla. Wniosek: solidarnosc u Camusa nie jest sentymentalna — to jedyna etyczna odpowiedz na absurd."', NULL, '{writing,essay,difficulty-4,contemporary,batch-2025-01}', '{"explanation": "Solidarnosc w obliczu zagrozenia to jedno z pytan jawnych na mature ustna 2026-2028 dotyczących \"Dzumy\"."}', '2026-03-17 22:49:04.904', '2026-03-17 22:49:04.904', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbey002kqhxp56pq94jb', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 5, 3, 'Jak "Dzuma" odpowiada na pytanie: czy mozna byc swietym bez Boga?', '{"options": ["Powiessc potwierdza, ze mozna — Tarrou osiaga swietosc i umiera w pokoju", "Powiessc nie daje jednoznacznej odpowiedzi: Tarrou pragnie swietosci, ale umiera na dzume, nie osiagajac \"spokoju\"; Rieux mowi, ze woli \"byc czlowiekiem\" niz swietym — Camus sugeruje, ze swietosc bez Boga moze byc nieosiagalna, ale dazenie do niej nadaje sens zyciu", "Powiessc odrzuca swietosc jako pojecie bez sensu i zastepuje ja hedonizmem", "Powiessc pokazuje, ze tylko wiara religijna (Paneloux) moze dac czlowiekowi swietosc"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "Pytanie \"czy mozna byc swietym bez Boga\" to centralne zagadnienie powiesci. Tarrou pragnie swietosci, ale nie dzyje dostatecznie dlugo, by ja osiagnac — umiera na dzume. Rieux mowi: \"Nie ide tak daleko. Interesuje mnie zdrowie czlowieka\". Camus nie odpowiada \"tak\" ani \"nie\" — pokazuje, ze samo dazenie jest wartosce, nawet jesli cel jest nieosiagalny. To logika Syzyfa: szczescliwy mimo absurdu."}', '2026-03-17 22:49:04.906', '2026-03-17 22:49:04.906', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbf0002lqhxpcfmvm6nh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 5, 3, 'Dlaczego Camus wybral Oran — brzydkie, banalne miasto handlowe — jako miejsce akcji?', '{"options": ["Poniewaz sam mieszkal w Oranie i chcial napisac autobiografie", "Poniewaz banalnosc Oranu podkresla uniwersalnosc paraboli: dzuma (zlo) nie spada na wyjatkowe miasta, lecz na zwyczajne — Oran \"bez podejrzen\" reprezentuje kazde spoleczenstwo, ktore zyje bez refleksji, az katastrofa zmusi je do zastanowienia", "Poniewaz Oran byl jedynym miastem w Algierii, w ktorym wybuuchla prawdziwa epidemia dzumy w XX wieku", "Poniewaz wydawca zakazal umieszczania akcji w Paryzu ze wzgledow cenzuralnych"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "Banalnosc Oranu to swiadomy wybor: \"miasto bez podejrzen, to znaczy miasto calkowicie nowoczesne\". Zwyczajnosc podkresla, ze zlo moze spasc na kazdego — nie potrzeba do tego miejsca wyjatkowego. Camus pisze: \"Nasi wspolobywatele nie mysleli nigdy, ze nasze male miasto moze byc miejscem szczegolnie wybranym\" — co czyni z Oranu symbol ludzkosci zaskoczonej katastrofa."}', '2026-03-17 22:49:04.909', '2026-03-17 22:49:04.909', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbf2002mqhxpxgfvny97', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 5, 3, 'Ktore stwierdzenia o przeslaniu "Dzumy" sa uzasadnione?', '{"options": ["\"W ludziach wiecej rzeczy zasługuje na podziw niz na pogarde\" — Camus jest ostatecznie humanista wierzacym w ludzi", "\"Bakcyl dzumy nigdy nie umiera\" — zlo jest stale obecne, a czujnosc moralna musi byc permanentna", "Powiessc naucza, ze czlowiek powinien pogodzic sie ze zlem, bo walka jest bezsensowna", "Sens zycia nadaje sie przez dzialanie i solidarnosc, nie przez wiare w wyzszy porzadek"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "Camus jest humanista (\"wiecej podziwu niz pogardy\"), ostrzega przed zlym optymizmem (\"bakcyl nie umiera\"), proponuje sens przez dzialanie (Rieux, Tarrou, Grand). Powiessc NIE naucza pogodzenia ze zlem — wprost przeciwnie: cala jej etyka opiera sie na buncie i odmowie akceptacji cierpienia."}', '2026-03-17 22:49:04.911', '2026-03-17 22:49:04.911', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbf5002nqhxpgain97ie', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 5, 4, 'Porownaj "Dzume" Camusa z "Antygona" Sofoklesa w kontekscie buntu wobec porzadku swiata. Czym sie rozni bunt Rieux od buntu Antygony?', '{"instruction": "Uwzglednij zrodlo buntu, motywacje, stosunek do transcendencji i konsekwencje."}', '"Antygona buntuje sie wobec prawa ludzkiego (Kreona) w imie prawa boskiego — jej bunt ma oparcie w transcendencji (bogowie, prawo natury). Rieux buntuje sie wobec cierpienia i smierci BEZ oparcia w transcendencji — nie wierzy w Boga, a mimo to walczy. Motywacja Antygony: milosc do brata + obowiazek religijny. Motywacja Rieux: uczciwosc + odmowa akceptacji swiata, gdzie dzieci sa torturowane. Konsekwencje: Antygona ginie, ale wie, ze bogowie sa po jej stronie. Rieux przetrywa, ale nie ma pewnosci co do sensu walki — \"zwyciestwa zawsze beda tymczasowe\". Roznica fundamentalna: Antygona ma pewnosc metafizyczna (prawo boskie), Rieux nie ma żadnej — jego bunt jest samotny i \"absurdalny\" w sensie Camusa. Ale wlasnie ta samotnosc nadaje mu wielkosc."', NULL, '{historical_literary,short_answer,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "Porownanie z Antygona to klasyczne zestawienie maturalne: bunt z oparciem metafizycznym (Antygona) vs. bunt bez oparcia (Rieux). Obie postacie sa szlachetne, ale ich bunty maja rozne fundamenty."}', '2026-03-17 22:49:04.913', '2026-03-17 22:49:04.913', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbf7002oqhxpkarvjlum', 'SHORT_ANSWER', 'LANGUAGE_USE', 'CONTEMPORARY', 5, 4, 'Wyjasnij, na czym polega styl narracyjny "Dzumy" i dlaczego Camus wybral forme kroniki. Jak wplywa to na odbiór powiesci?', '{}', '"Styl: 1) Kronikarski ton — narracja pozornie obiektywna, sprawozdawcza, bez patosu. Rieux celowo unika emocjonalnych opisow na rzecz faktow, statystyk, relacji. 2) Trzecia osoba — dystans narratora do samego siebie. 3) Wieloglososc — obok kroniki Rieux sa notatki Tarrou (subiektywne, ironiczne), zeznania swiadkow, dokumenty. 4) Brak psychologizmu — bohaterowie sa raczej modelami postaw niz glebokimi postaciami psychologicznymi (cecha paraboli). Forma kroniki: Camus wybral ja, bo kronika udaje dokument — wzmacnia wiarygodnosc paraboli. Czytelnik czyta \"relacje\", nie \"powiessc\", co sprawia, ze traktuje historia serio. Efekt: styl suchy, pozornie chlodny — ale wlasnie dlatego momenty emocjonalne (smierc dziecka, smierc Tarrou, Grand placzacy pod sklepem) uderzaja z ogromna sila na tle kroniczarskiej powsciagliwosci."', NULL, '{language_use,short_answer,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "Pytanie o styl narracyjny to typowe pytanie LANGUAGE_USE na maturze rozszerzonej. Kluczowe: forma kroniki to swiadomy wybor stylistyczny — pozorna obiektywnosc poteguje emocjonalny efekt."}', '2026-03-17 22:49:04.915', '2026-03-17 22:49:04.915', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbf9002pqhxpnb6oum42', 'SYNTHESIS_NOTE', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 5, 5, 'Napisz notatke syntetyczna na podany temat:', '{"topic": "\"Dzuma\" jako manifest nowego humanizmu — jak Camus definiuje czlowieczenstwo po doswiadczeniu II wojny swiatowej?", "wordLimit": {"max": 250, "min": 200}, "requirements": ["Wyjasnij, dlaczego \"Dzume\" okrzyknięto \"manifestem nowego humanizmu\" po publikacji", "Wskazz, na czym polega humanizm Camusa: solidarnosc, uczciwosc, bunt, odrzucenie heroicznej retoryki", "Porownaj z tradycyjnym humanizmem (wiara w postep, rozum, doskonalenie) — co Camus odrzuca?", "Odwolaj sie do kontkstu II wojny i pytania: czy po Auschwitz mozna byc humanista?", "200-250 slow"]}', '"Notatka powinna: \"Dzuma\" jako nowy humanizm — nie opiera sie na wierze w postep ani doskonalosc czlowieka, lecz na \"prostej ludzkiej solidarnosci i moralnosci, bez patosu i wielkich slow\" (jak piszą krytycy). Humanizm Camusa: solidarnosc (formacje sanitarne), uczciwosc (\"robic, co nalezy\"), bunt (odmowa akceptacji cierpienia), pokora (\"nie chodzi o heroizm, chodzi o dwa i dwa to cztery\"). Co Camus odrzuca z tradycyjnego humanizmu: optymizm co do natury ludzkiej (\"kazdy nosi w sobie dzume\"), wiare w postep (epidemia wroci), ideologie (\"cale nieszcze ludzi plynie stad, ze nie mowia jasnym jezykiem\"). Kontekst II wojny: po Auschwitz wiara w rozum i doskonalosc czlowieka jest nie do utrzymania. Camus proponuje humanizm bez iluzji: \"w ludziach wiecej rzeczy zasługuje na podziw niz na pogarde\" — ale nie dlatego, ze czlowiek jest z natury dobry, lecz dlatego, ze MOZE dokonywac dobrych wyborow mimo absurdu. To humanizm syzyfowy — szlachetny i tragiczny zarazem."', NULL, '{historical_literary,synthesis_note,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "Pytanie o \"nowy humanizm\" to wazny kontekst maturalny. Kluczowe: Camus po Auschwitz nie moze byc naiwnym humanista — proponuje humanizm oparty na buncie i solidarnosci, nie na optymizmie."}', '2026-03-17 22:49:04.918', '2026-03-17 22:49:04.918', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv7fbfd002qqhxp9kutkrpy', 'ESSAY', 'WRITING', 'CONTEMPORARY', 5, 10, 'Czlowiek wobec cierpienia i smierci. Rozważ problem, odwolujac sie do "Dzumy" Alberta Camusa i jednego innego tekstu kultury.', '{"thesis": "Cierpienie i smierc jako probierz czlowieczenstwa", "structure": {"conclusion": "Sformuluj wniosek: czy cierpienie uczy, niszczy, czy obydwa — i jak Camus proponuje reagowac?", "introduction": "Przedstaw problem: jak cierpienie odsłania prawde o czlowieku — jego slabosci i wielkosc?", "arguments_for": "Podaj przyklady postaw wobec cierpienia w \"Dzumie\": Rieux (walka), Tarrou (bunt), Paneloux (wiara), Cottard (oportunizm)", "arguments_against": "Rozważ, czy cierpienie moze nie miec zadnego sensu — ani ksztalcacego, ani oczyszczajacego (Rieux: \"nigdy nie bede kochał tego swiata, gdzie dzieci sa torturowane\")"}, "wordLimit": {"max": 600, "min": 400}, "requirements": ["Przeanalizuj scene smierci dziecka Othona jako kulminacje problemu cierpienia", "Odwolaj sie do filozofii absurdu i buntu Camusa", "Porownaj z innym tekstem kultury (np. Ksiega Hioba, \"Inny swiat\", \"Antygona\", \"Medaliony\")", "Sformuluj wlasne stanowisko wobec tezy, ze cierpienie \"uszlachetnia\"", "Minimum 400 slow"]}', '"Rozprawka powinna: Postawy wobec cierpienia: Rieux — odmowa akceptacji, walka mimo beznadziejnosci; Tarrou — bunt i pragnienie niewinnosci; Paneloux — ewolucja od wyjasnnia (kara Boza) do wiary totalnej; Cottard — ucieczka w oportunizm. Scena smierci dziecka: kulminacja — cierpienie niewinnego podwaza wszelkie racjonalizacje. Rieux krzyczy: \"ten przynajmniej byl niewinny\". Camus odrzuca ide, ze cierpienie \"uszlachetnia\" — to zdanie Paneloux z I kazania, ktore sam potem porzuca. Porownanie: Ksiega Hioba — Hiob cierpi niewinnie, Bog odpowiada tajemnicza; u Camusa nie ma Boga, ktory odpowiada. \"Inny swiat\" — Herling pokazuje, ze cierpienie w łagrze degraduje, ale jednoczesnie wyostrza moralnosc. \"Antygona\" — cierpienie wynika z konfliktu wartosci, ma sens tragiczny. Stanowisko: cierpienie nie uszlachetnia automatycznie — u Camusa moze zniszczyc (Paneloux umiera) lub obudzic (Rambert zmienia sie). Jedyną wlasciwa odpowiedzia jest bunt i solidarnosc — nie akceptacja."', NULL, '{writing,essay,difficulty-5,contemporary,batch-2025-01}', '{"explanation": "\"Czlowiek wobec cierpienia i smierci\" to jedno z pytan jawnych na mature ustna 2026-2028 dotyczacych \"Dzumy\". Kluczowe: Camus NIE gloryfikuje cierpienia — odrzuca ide \"uszlachetniajacego bolu\" na rzecz buntu."}', '2026-03-17 22:49:04.922', '2026-03-17 22:49:04.922', 'Dżuma');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x07s0000qhyfpj6ucssm', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'W jakim roku zostala napisana powiesc "Ludzie bezdomni"?', '{"options": ["1885", "1899", "1905", "1912"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "\"Ludzie bezdomni\" zostali napisani w 1899 roku w Zakopanem. Powiesc naleezy do epoki Mlodej Polski i jest jednym z najwazniejszych dziel Stefana Zeromskiego."}', '2026-03-17 23:30:49.816', '2026-03-17 23:30:49.816', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0840001qhyfeyebeupr', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Jak nazywa sie glowna bohaterka kobieca powiesci?', '{"options": ["Helena Kalinowicz", "Joanna Podborska", "Natalia Orszenska", "Wanda Orszenska"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Glowna bohaterka kobieca to Joanna Podborska -- nauczycielka i guwernantka, opiekujaca sie wnuczkami pani Niewadzkiej. Jest rowniez autorka dziennika z rozdzialu \"Zwierzenia\"."}', '2026-03-17 23:30:49.828', '2026-03-17 23:30:49.828', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0870002qhyfbtcczi1c', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Na jakiej ulicy w Warszawie mieszkal ojciec Tomasza Judyma?', '{"options": ["Na ulicy Marszalkowskiej", "Na ulicy Cieplej", "Na ulicy Krochmalnej", "Na ulicy Nowy Swiat"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Ojciec Judyma, szewc, mieszkal na ulicy Cieplej w Warszawie. Sam Judym wyznaje to otwarcie przy spotkaniu z pania Niewadzka w Luwrze."}', '2026-03-17 23:30:49.831', '2026-03-17 23:30:49.831', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0890003qhyfug0p2nme', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Gdzie Judym odbywal praktyki chirurgiczne przed powrotem do Warszawy?', '{"options": ["W Berlinie", "W Wiedniu", "W Paryzu", "W Londynie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Judym odbywal praktyki chirurgiczne w klinikach paryskich. Wlasnie w Paryzu, w Luwrze, spotyka po raz pierwszy Joanne Podborska i panny Orszenskie."}', '2026-03-17 23:30:49.834', '2026-03-17 23:30:49.834', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x08c0004qhyf92sbxwsd', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Ktore z ponizszych zdan o Tomaszu Judymie sa prawdziwe?', '{"options": ["Jest lekarzem z wyksztalcenia", "Pochodzi z rodziny arystokratycznej", "Jego ojciec byl szewcem", "Ukonczyl studia medyczne w Warszawie"]}', '[0, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Judym jest lekarzem, synem szewca z ulicy Cieplej, ukonczyl medycyne w Warszawie. NIE pochodzi z arystokracji -- jego niskie pochodzenie jest zrodlem kompleksow i poczucia dlugu wobec biedoty."}', '2026-03-17 23:30:49.836', '2026-03-17 23:30:49.836', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x08e0005qhyf8a9446u0', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 1, 1, 'Ktore postacie sa lekarzami w powiesci "Ludzie bezdomni"?', '{"options": ["Tomasz Judym", "Doktor Weglichowski", "Korzecki", "Doktor Chmielnicki"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,young_poland,batch-2025-01}', '{"explanation": "Judym, Weglichowski (dyrektor Cisow) i Chmielnicki (lekarz zydowskiego pochodzenia) sa lekarzami. Korzecki jest inzynierem, nie lekarzem."}', '2026-03-17 23:30:49.839', '2026-03-17 23:30:49.839', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x08h0006qhyfflknjrnr', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Kto jest dyrektorem zakladu leczniczego w Cisach?', '{"options": ["Doktor Chmielnicki", "Doktor Weglichowski", "Doktor Kalecki", "Doktor Plowicz"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Doktor Weglichowski to dyrektor zakladu w Cisach -- ceniony lekarz, ale konserwatywny, niecheetny reformom Judyma dotyczacym osuszenia stawow."}', '2026-03-17 23:30:49.841', '2026-03-17 23:30:49.841', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x08k0007qhyfbqo8iwcf', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Jaki obraz w Luwrze gleboko porusza Judyma i staje sie symbolem nedzy?', '{"options": ["\"Mona Lisa\" Leonarda da Vinci", "\"Ubogi rybak\" Puvis de Chavannes''a", "\"Wolnosc wiodaca lud na barykady\" Delacroix", "\"Przysieega Horacjuszy\" Davida"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "\"Ubogi rybak\" Puvis de Chavannes''a symbolizuje w powiesci nedze i krzywde spoleczna. Stanowi kontrast wobec Wenus z Milo, symbolizujacej piekno i harmonie. Oba dziela zapowiadaja centralny konflikt powiesci."}', '2026-03-17 23:30:49.844', '2026-03-17 23:30:49.844', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x08m0008qhyfzx9n4a0c', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Co Judym robi po utracie posady w Cisach?', '{"options": ["Wraca do Paryza", "Otwiera prywatny gabinet w Warszawie", "Jedzie do Zaglebia Dabrowskiego i pracuje jako lekarz w kopalni", "Emigruje do Ameryki"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Po wyrzuceniu z Cisow (za pobicie Krzywosada) Judym jedzie do Zaglebia Dabrowskiego, gdzie pracuje jako lekarz przy kopalni. Tam styka sie z najciezsza nedza robotnicza."}', '2026-03-17 23:30:49.847', '2026-03-17 23:30:49.847', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x08p0009qhyf322lny7y', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Czego dotyczy slynne zdanie Judyma: "Lekarz dzisiejszy -- to lekarz ludzi bogatych"?', '{"options": ["Pochwalenia lekarzy za ich poswiecenie", "Zarzutu, ze lekarze koncentruja sie na zamoznych pacjentach i zaniedbuja biedote", "Reklamy prywatnego gabinetu Judyma", "Opisu systemu opieki zdrowotnej w Paryzu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "To centralna teza odczytu Judyma u Czerniszow. Zarzuca lekarzom, ze lecza tylko bogatych, ignorujac przyczyny chorob biedoty -- sutereny, fabryki, brud. Odczyt konczy sie porazka -- srodowisko lekarskie odrzuca jego postulaty."}', '2026-03-17 23:30:49.849', '2026-03-17 23:30:49.849', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x08r000aqhyftax7jhhf', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Kto jedyny okazuje Judymowi wspolczucie po nieudanym odczycie?', '{"options": ["Doktor Plowicz", "Doktor Kalecki", "Doktor Chmielnicki", "Pani Czerniszowa"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Doktor Chmielnicki -- lekarz zydowskiego pochodzenia -- jako jedyny okazuje Judymowi szczere wspolczucie. To on posredniczy w znalezieniu mu posady w Cisach u doktora Weglichowskiego."}', '2026-03-17 23:30:49.851', '2026-03-17 23:30:49.851', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x08t000bqhyfo3o3e8kx', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Ktore stwierdzenia o rozdziale "Zwierzenia" sa prawdziwe?', '{"options": ["Narratorka jest Joanna Podborska", "Rozdzial ma forme dziennika", "Jest napisany w trzeciej osobie jak reszta powiesci", "Joanna porusza tematy samotnosci, smierci brata i roli kobiet"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "\"Zwierzenia\" to dziennik Joanny Podborskiej -- jedyny fragment powiesci pisany w pierwszej osobie. Joanna porusza tematy samotnosci guwernantki, smierci brata Waclawa i refleksji o roli kobiet. NIE jest w trzeciej osobie."}', '2026-03-17 23:30:49.854', '2026-03-17 23:30:49.854', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x08w000cqhyfbfxqctuf', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 2, 1, 'Ktore miejsca w powiesci sluza jako ilustracja nedzy spolecznej?', '{"options": ["Sutereny ulicy Cieplej i Krochmalnej w Warszawie", "Salon doktorostwa Czerniszow", "Fabryka cygar, w ktorej pracuje bratowa Judyma", "\"Budy\" robotnicze przy cynkowni w Zaglebiu"]}', '[0, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,young_poland,batch-2025-01}', '{"explanation": "Sutereny warszawskie, fabryka cygar i budy robotnicze w Zaglebiu to trzy kluczowe miejsca ilustrujace nedze. Salon Czerniszow to przestrzen zamoznej inteligencji -- kontrastowa wobec nedzy."}', '2026-03-17 23:30:49.856', '2026-03-17 23:30:49.856', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x08z000dqhyfiq83wq8u', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Co symbolizuje rozdarta sosna w zakonczeniu powiesci?', '{"options": ["Sile przyrody i odpornosc natury", "Wewnetrzne rozdarcie Judyma miedzy miloscia a obowiazkiem wobec biedoty", "Zniszczenie lasow przez przemysl w Zaglebiu", "Nadzieje na lepsze jutro"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Rozdarta sosna to centralny symbol powiesci. Jej pien rozszarpany odzwierciedla rozdarcie duszy Judyma po rozstaniu z Joasia. Krople zywicy odpowiadaja jego lzom. Pytanie \"Kto placze?\" wskazuje na uniwersalnosc cierpienia."}', '2026-03-17 23:30:49.859', '2026-03-17 23:30:49.859', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x091000eqhyfzffgk8sh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Dlaczego Judym w zakonczeniu rezygnuje z milosci do Joanny?', '{"options": ["Bo Joanna go odrzucila", "Bo uwaza, ze nie moze miec domu i rodziny, dopoki trwa nedza najubozszych -- czuje dlug wobec klasy, z ktorej sie wywodzi", "Bo zakonczyl sie mu kontrakt w Zaglebiu i musi wyjechac", "Bo Halban zabronil mu sie zenic"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Judym mowi Joasi, ze nie moze miec \"ani ojca, ani matki, ani zony\", dopoki trwa nedza. Jako czlowiek ktory sam wyszedl z biedy, czuje moralny dlug wobec tych, ktorzy zostali na dole. Rezygnacja z milosci jest cena za wiernosc idealom."}', '2026-03-17 23:30:49.862', '2026-03-17 23:30:49.862', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x093000fqhyfppqdzhds', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Czym jest "zeromeszczyzna" jako styl literacki?', '{"options": ["Stylem polegajacym na uzywaniu wylacznie krotkich, prostych zdan", "Stylem laczacym realizm z symbolizmem, impresjonizmem i liryzacja prozy -- opisy przyrody odzwierciedlaja stany psychiczne bohaterow", "Technika dialogu opartego wylacznie na slanggu ulicznym", "Metoda pisania pamietnikow w pierwszej osobie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "\"Zeromeszczyzna\" to styl laczacy rozne techniki: realizm (opisy nedzy), symbolizm (Wenus, sosna), impresjonizm (migotliwosc opisu przyrody), liryzacje prozy (poetycki jezyk narracji). Charakterystyczna jest psychizacja pejzazu -- przyroda odzwierciedla emocje bohatera."}', '2026-03-17 23:30:49.864', '2026-03-17 23:30:49.864', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x095000gqhyfeps5rxp9', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Ktore motywy literackie sa obecne w "Ludziach bezdomnych"?', '{"options": ["Motyw poswiecenia osobistego szczescia dla dobra ogolu", "Motyw bezdomnosci w sensie doslownym i metaforycznym", "Motyw walki zbrojnej o niepodleglosc", "Motyw niespelnionej milosci"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "W powiesci obecne sa motywy: poswiecenia (Judym rezygnuje ze szczescia), bezdomnosci (doslowna -- nedzarze; metaforyczna -- Judym, Joasia), niespelnionej milosci (Judym i Joanna). Walka zbrojna o niepodleglosc nie jest motywem tej powiesci."}', '2026-03-17 23:30:49.866', '2026-03-17 23:30:49.866', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x098000hqhyfutr5vseb', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'YOUNG_POLAND', 3, 2, 'Kim jest Karbowski i dlaczego Judym porownuje go do kwiatu tuberozy?', '{}', '"Karbowski to przystojny, lekkomyslny utracjusz i karciarz, w ktorym zakochuje sie Natalia Orszenska. Judym porownuje go do kwiatu tuberozy -- pieknego, ale bezuzytecznego. Symbol podkresla kontrast miedzy powierzchownym pieknem a brakiem spolecznej wartosci."', NULL, '{historical_literary,short_answer,difficulty-3,young_poland,batch-2025-01}', '{"explanation": "Porownanie do tuberozy jest jednym z kluczowych symboli powiesci -- ilustruje Judymowski poglad, ze piekno bez uzytecznosci spolecznej jest puste."}', '2026-03-17 23:30:49.868', '2026-03-17 23:30:49.868', 'Ludzie bezdomni');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x09a000iqhyf5ohjnnai', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'W jakiej epoce literackiej powstaly "Sklepy cynamonowe"?', '{"options": ["Pozytywizm", "Mloda Polska", "Dwudziestolecie miedzywoojenne", "Wspolczesnosc"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "\"Sklepy cynamonowe\" to zbior opowiadan Brunona Schulza wydany w 1933 roku -- naleza do epoki dwudziestolecia miedzywojennego. Proza Schulza reprezentuje nurt awangardowy i surrealistyczny."}', '2026-03-17 23:30:49.87', '2026-03-17 23:30:49.87', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x09c000jqhyf8k5ai09y', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Kto pomog Schulzowi wydac "Sklepy cynamonowe"?', '{"options": ["Witold Gombrowicz", "Zofia Nalkowska", "Julian Tuwim", "Jaroslaw Iwaszkiewicz"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Zbior ukazal sie dzieki protekcji Zofii Nalkowskiej, ktora rozpropagowala tworczosc Schulza i pomogla mu w wydaniu debiutanckiej ksiazki w warszawskim wydawnictwie \"Roj\"."}', '2026-03-17 23:30:49.873', '2026-03-17 23:30:49.873', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x09e000kqhyf2gr8xohj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Jak nazywa sie narrator zbioru "Sklepy cynamonowe"?', '{"options": ["Bruno", "Jakub", "Jozef", "Narrator nie ma imienia"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Narrator zbioru ma na imie Jozef -- opowiada z perspektywy dziecka/doroslego wspominajacego dziecinstwo. W postaci narratora odbijaja sie cechy samego Schulza."}', '2026-03-17 23:30:49.875', '2026-03-17 23:30:49.875', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x09h000lqhyfgrglkycu', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Jakie rodzinne miasto Schulza bylo wzorem dla miasteczka w zbiorze?', '{"options": ["Krakow", "Lwow", "Drohobycz", "Warszawa"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Miasteczko ze zbioru jest wzorowane na Drohobyczu -- rodzinnym miescie Schulza na Kresach (dzisiejsza Ukraina). Schulz nigdy na stale nie opuscil Drohobycza."}', '2026-03-17 23:30:49.877', '2026-03-17 23:30:49.877', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x09j000mqhyfpg50z8zm', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Ktore z podnizszych opowiadan naleza do zbioru "Sklepy cynamonowe"?', '{"options": ["\"Manekiny\"", "\"Traktat o Manekinach\"", "\"Emeryt\"", "\"Wichura\""]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,interwar,batch-2025-01}', '{"explanation": "\"Manekiny\", \"Traktat o Manekinach\" i \"Wichura\" naleza do zbioru. \"Emeryt\" to opowiadanie z drugiego tomu Schulza -- \"Sanatorium Pod Klepsydra\"."}', '2026-03-17 23:30:49.879', '2026-03-17 23:30:49.879', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x09l000nqhyfarublwy5', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 1, 1, 'Ktore cechy opisuja ojca narratora w zbiorze?', '{"options": ["Jest kupcem prowadzacym sklep z suknem", "Jest ekscentrykiem fascynujacym sie ptakami i materia", "Jest typowym, spokojnym ojcem rodziny", "Stopniowo maleje i zanika fizycznie"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,interwar,batch-2025-01}', '{"explanation": "Ojciec (Jakub) formalnie jest kupcem, ale w oczach syna to ekscentryk -- hoduje egzotyczne ptaki, wyklada o materii, maleje i zanika. NIE jest typowym spokojnym ojcem -- to postac niezwykla, groteskowa i tragiczna."}', '2026-03-17 23:30:49.881', '2026-03-17 23:30:49.881', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x09o000oqhyf1xqdqo62', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Do jakiego ptaka jest porownywany ojciec w opowiadaniu "Ptaki"?', '{"options": ["Do orla", "Do kondora", "Do pawia", "Do slowika"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Ojciec jest porownywany do kondora -- ogromnego ptaka o nagiej szyi, pomarszczonej twarzy i kamiennym profilu. Narrator widzi w nim \"starszego brata ojca\" i mumie. Kondor uzywa nawet wspólnego naczynia nocnego z ojcem."}', '2026-03-17 23:30:49.884', '2026-03-17 23:30:49.884', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x09q000pqhyf9iebq7ql', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Kim sa Polda i Paulina w zbiorze?', '{"options": ["Corkami ciotki Agaty", "Dziewczetami do szycia, ktore przychodzaa wieczorami do domu narratora", "Nauczycielkami w szkole", "Sasiadkami z sassiedniego domu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Polda i Paulina to szwaczki -- dziewczeta do szycia, ktore przychodzą wieczorami. W ich obecnosci ojciec wyglasza prelekcje o manekinach. Sa jednoczesnie jego audytorium i -- w pewnym sensie -- obiektem badan anatomicznych."}', '2026-03-17 23:30:49.886', '2026-03-17 23:30:49.886', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x09s000qqhyfmxxgt89s', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Co ojciec postuluje stworzyc "na obraz i podobienstwo" w Traktacie o Manekinach?', '{"options": ["Boga", "Czlowieka -- na obraz i podobienstwo manekina", "Zwierze doskonalsze od ptakow", "Nowy rodzaj tkaniny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Ojciec konkluduje: chce stworzyc po raz wtory czlowieka, na obraz i podobienstwo manekina -- z tandety, klakow i trocin. To parodia biblijnego aktu stworzenia -- \"wtora demiurgia\" zamiast doskonalych tworow Boga."}', '2026-03-17 23:30:49.888', '2026-03-17 23:30:49.888', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x09v000rqhyf4bj0wufz', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Co stalo sie z ciotka Perazja w opowiadaniu "Wichura"?', '{"options": ["Uciekla z domu przed wichura", "W paroksyzmie zlosci malala, biegala na szczudlach i ostatecznie zetlala sie w proch jak spalony papier", "Usnela spokojnie przy piecu", "Poszla po pomoc do sasiadow"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Ciotka Perazja w gniewie zaczyna maleec, wskakuje na szczudla z drzazg, biega po pólkach i wreszcie sczerniala, zwineela sie jak zwiedely papier i zetlala w proch. To jedna z najbardziej groteskowych scen zbioru -- czlowiek dosownie znika w paroksyzmie emocji."}', '2026-03-17 23:30:49.891', '2026-03-17 23:30:49.891', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x09y000sqhyfb9qygjx1', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Ktore stwierdzenia o tytulowych sklepach cynamonowych sa prawdziwe?', '{"options": ["Ich nazwa pochodzi od koloru ciemnych boazerii", "Sprzedaja egzotyczne towary: ognie bengalskie, salamandry, rzadkie ksiazki", "Narrator regularnie robi w nich zakupy", "Narrator szuka ich nocą, ale nigdy do nich nie dociera"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,interwar,batch-2025-01}', '{"explanation": "Sklepy cynamonowe maja ciemne boazerie (stad nazwa), sprzedaja towary egzotyczne i fantastyczne. Narrator pamieta je z przeszlosci, ale podczas nocnej wedrowki nigdy do nich nie dociera -- sa nieosiagalne, symbolizuja utracona arkadie."}', '2026-03-17 23:30:49.894', '2026-03-17 23:30:49.894', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0a1000tqhyfelvsb6db', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 2, 1, 'Co ojciec robi na uczcie w opowiadaniu "Noc wielkiego sezonu"?', '{"options": ["Wspina sie na polki i trabi na puzonie na alarm", "Wola: \"Jakubie, handlowac!\" i zaczyna sprzedawac sukno", "Rozrzuca bele sukna, tworzac gorski krajobraz z materii", "Spokojnie handluje z klientami za lada"]}', '[0, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,interwar,batch-2025-01}', '{"explanation": "W \"Nocy wielkiego sezonu\" ojciec w szale wspina sie na polki, trabi na puzonie i rozrzuca bele sukna, tworzac fantastyczny gorski krajobraz. \"Jakubie, handlowac!\" wolaja do niego ludzie -- to nie on. Nie handluje spokojnie -- jest jak szalony prorok na gorze Synaj."}', '2026-03-17 23:30:49.897', '2026-03-17 23:30:49.897', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0a3000uqhyf20y5vbce', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Co spotkalo Brunona Schulza podczas wojny?', '{"options": ["Emigrowal do Stanow Zjednoczonych", "Zostal zastrzelony na ulicy przez gestapowca w 1942 roku w Drohobyczu", "Przetrwal wojne w ukryciu i umarl po wojnie", "Zostal deportowany do obozu i tam zmarl"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Bruno Schulz zostal zastrzelony na ulicy Drohobycza 19 listopada 1942 roku przez gestapowca Gunthera. Zofia Nalkowska probowala zorganizowac jego przerzut do Warszawy, ale nie zdazyla. Jego smierc jest jedną z najwiekszych strat polskiej literatury."}', '2026-03-17 23:30:49.899', '2026-03-17 23:30:49.899', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0a5000vqhyfps9fwm28', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Jakim terminem okresla sie czas w "Sklepach cynamonowych"?', '{"options": ["Czas historyczny -- konkretne daty i wydarzenia", "Czas mityczny i cykliczny -- wyznaczony porami roku, nie datami, krazacy w kolo jak w micie", "Czas linearny -- od narodzin do smierci narratora", "Czas realny -- biezacy, odpowiadajacy dacie pisania"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "U Schulza czas jest mityczny i cykliczny -- wyznaczony porami roku (lato/sierpien, zima, jesien), nie konkretnymi datami. Czas krazy jak w micie: lato wraca, zima wraca, pory roku powtarzaja sie jak rytualy. To czas mitu, nie historii."}', '2026-03-17 23:30:49.901', '2026-03-17 23:30:49.901', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0a7000wqhyf6gjori35', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Jaka jest relacja miedzy Ulica Krokodyli a reszta miasteczka?', '{"options": ["Ulica Krokodyli jest centrum handlowym i duma miasta", "Jest tandetna, pseudonowoczesna dzielnica -- kontrastem wobec magicznego miasteczka: swiaat pozorow, imitacji, szarosci, moralnej degradacji", "Jest najstarsza, najbardziej szacowna dzielnica miasta", "Jest dzielnica artystow i intelektualistow"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,interwar,batch-2025-01}', '{"explanation": "Ulica Krokodyli to antysswiat wobec magicznego miasteczka: tandetna, bezbarwna, peln pozoru. Rzeczywistosc jest tam \"cienka jak papier\" i \"zdradza swa imitatywnosc\". To krytyka pseudonowoczesnej komercjalizacji, ktora niszczy autentycznosc."}', '2026-03-17 23:30:49.903', '2026-03-17 23:30:49.903', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0a9000xqhyfvgtcgavw', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Ktore z ponizszych metamorfoz ojca wystepuja w zbiorze?', '{"options": ["Ojciec naśladuje ptaki -- pieje jak kogut, trzepoce rekami", "Ojciec stopniowo zamienia sie w karakona", "Ojciec maleje fizycznie az staje sie \"kupka smieci\"", "Ojciec przemienia sie w drzewo"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-3,interwar,batch-2025-01}', '{"explanation": "W zbiorze ojciec: nasladuje ptaki i pieje (Ptaki), przemienia sie w karakona (Karakony), maleje fizycznie az zanika (Nawiedzenie). Metamorfoza w drzewo nie wystepuje."}', '2026-03-17 23:30:49.906', '2026-03-17 23:30:49.906', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0ab000yqhyflugj5uwu', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'INTERWAR', 3, 2, 'Opisz krotko, co dzieje sie z ojcem w opowiadaniu "Nawiedzenie". Jakie dziwne zachowania przejawia?', '{"hints": ["choroba", "monologi", "dialog z Bogiem", "zanikanie fizyczne"]}', '"W \"Nawiedzeniu\" ojciec zapada na zdrowiu, lezy w lozku otoczony flaszkami i ksiegami handlowymi. Prowadzi samotne monologi, kloci sie z soba, jakby jego osobowosc rozpadla sie na wiele jazni. Nocami dialoguje z Bogiem jak starotestamentowy prorok. Stopniowo maleje -- \"jak orzech zsychajacy sie w lupinie\" -- wspina sie na szafy, pieje jak kogut, znika na wiele dni w zakamarkach mieszkania. Na koncu jego resztki Adela wymiata jak kupke smieci."', NULL, '{historical_literary,short_answer,difficulty-3,interwar,batch-2025-01}', '{"explanation": "\"Nawiedzenie\" to kluczowe opowiadanie dla motywu degradacji ojca -- od kupca przez proroka do nicosci. Zanikanie jest zarowno komiczne (pieje jak kogut), jak i tragiczne (\"zniknal nie zauwaiony\")."}', '2026-03-17 23:30:49.908', '2026-03-17 23:30:49.908', 'Sklepy cynamonowe');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0ae000zqhyfmwq68qf9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'W jakim wieku rozgrywa sie akcja "Konrada Wallenroda"?', '{"options": ["W XII wieku", "W XIV wieku", "W XVI wieku", "W XIX wieku"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Akcja rozgrywa sie w XIV wieku, w czasach walk Litwy z Zakonem Krzyzackim. To historyczne tlo zostalo celowo wybrane przez Mickiewicza jako maska historyczna -- sredniowiecze ukrywa treści o wspolczesnej Polsce pod zaborami."}', '2026-03-17 23:30:49.911', '2026-03-17 23:30:49.911', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0ah0010qhyf27rvcaie', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Jakie stanowisko obejmuje Konrad Wallenrod w Zakonie Krzyzackim?', '{"options": ["Kapelan zakonny", "Wielki mistrz Zakonu Krzyzackiego", "Komtur twierdzy Malbork", "Giermek arcykomtura"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Konrad Wallenrod zostaje wybrany wielkim mistrzem Zakonu Krzyzackiego -- najwyzszym dowodca. To kluczowe dla jego planu: jako mistrz moze celowo prowadzic Zakon do kleski."}', '2026-03-17 23:30:49.913', '2026-03-17 23:30:49.913', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0aj0011qhyfjs6onoj2', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Z ktorym narodem walczy Zakon Krzyzacki w utworze?', '{"options": ["Z Francuzami", "Z Litwinami", "Z Turkami", "Z Anglikami"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Zakon Krzyzacki walczy z Litwinami -- pogańskim ludem nad Niemnem. W utworze Litwa to ojczyzna Waltera Alfa, ktorej broni on podstepem od wewnatrz struktur wroga."}', '2026-03-17 23:30:49.915', '2026-03-17 23:30:49.915', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0al0012qhyf4hsulbew', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Co to jest wajdelota?', '{"options": ["Litewski rycerz konny", "Litewski bard/pieśniarz -- straznik tradycji ustnej i pamieci narodowej", "Niemiecki zakonnik", "Litewski kapłan ognia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Wajdelota to litewski bard -- spiiewak i straznik tradycji ustnej narodu. W utworze te role pelni Halban, ktory spieewa piesni o Litwie i przechowuje pamiec narodowa. Wajdelota jest odpowiednikiem romantycznego poety-wieszcza."}', '2026-03-17 23:30:49.917', '2026-03-17 23:30:49.917', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0ao0013qhyfze7u47dc', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Ktore rzeki i miejsca pojawiaja sie w "Konradzie Wallenrodzie"?', '{"options": ["Niemen -- granica miedzy Litwa a Prusami", "Maryjensburg (Malbork) -- siedziba Zakonu", "Wisla -- stoleczna rzeka Krakowa", "Kowno -- miasto litewskie"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Niemen to granica miedzy swiatami (Litwa/Prusy), Maryjensburg/Malbork to siedziba Zakonu, Kowno to miasto litewskie (zamek Kiejstuta, blonia Peruna). Wisla i Krakow nie pojawiaja sie w utworze."}', '2026-03-17 23:30:49.921', '2026-03-17 23:30:49.921', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0ar0014qhyfu0dxfq6d', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Ktore z ponizszych stwierdzen o genezie utworu sa prawdziwe?', '{"options": ["Mickiewicz pisal go na zesslaniu w Rosji", "Utwor zostal wydany w 1828 roku", "Mickiewicz dedykowal go Bonawendurze i Joannie Zaleskim", "Utwor powstal po powstaniu listopadowym"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Utwor piisany w Rosji (1825-1827), wydany w 1828, dedykowany Zaleskim. NIE powstal po powstaniu listopadowym (1830) -- powstanie wybuchlo DWA LATA PO wydaniu. To wazna roznica -- Wallenrod wpisuje sie w kontekst spiskow dekabrystow, nie powstania."}', '2026-03-17 23:30:49.923', '2026-03-17 23:30:49.923', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0at0015qhyfqai9mjg9', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Czego dotyczy piesn Halbana o Wiliji?', '{"options": ["O historii walk Litwinow z Krzyzakami", "O pieknej Litwince, ktora pokochala cudzoziemca i placzze w pustelniczej wiezy -- alegoria losu Aldony", "O zwyciestwach litewskiego ksiecia Kiejstuta", "O budowie zamku w Malborku"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Piesn o Wiliji to alegoria losu Aldony: rzeka Wilija plynie do Niemna (oblubieńca) i ginie w morzu, tak jak Litwinka pokochala przybysza i placzze w pustelniczej wiezy. Halban spieewa ja po wyborze Konrada na mistrza."}', '2026-03-17 23:30:49.925', '2026-03-17 23:30:49.925', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0av0016qhyfmjx0v77c', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'W jakim celu Walter Alf pojechal z zona Aldona do klasztoru zakonnic?', '{"options": ["Zeby sie pomodlic przed wyruszeniem na wojne", "Zeby ukryc Aldone bezpiecznie, zanim sam wrocil do Zakonu pod falszywym imieniem realizowac plan zemsty", "Zeby Aldona zostala zakonnica z przekonania religijnego", "Zeby spotkac sie z Halbanem w tajemnicy"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Walter Alf odwozi Aldone do klasztoru zakonnic za Niemnem, zanim sam wraca do Zakonu pod imieniem Wallenroda. Aldona pozniej opuszcza klasztor i zamyka sie w wiezy przy zamku w Malborku, by byc blisko meza."}', '2026-03-17 23:30:49.928', '2026-03-17 23:30:49.928', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0ax0017qhyflhq71mbq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Jaka wade ma Konrad Wallenrod wedlug Krzyzakow?', '{"options": ["Jest tchorzem na polu bitwy", "Zamkniety w samotnym pokoju, pije alkohol, spiewa smutne piesni i wpada w szal", "Kradnie pieniadze Zakonu", "Odmawia modlitwy i uczestnictwa w nabozenstwach"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Jedyna znana Krzyzakom wada Konrada to alkoholizm -- zamkniety w pokoju pije i spiewa posepne piesni w obcym jezyku (litewskim). W szale krzyczy rozkazy, grozi komus nieznanemu. Halban uspokaja go jednym spojrzeniem."}', '2026-03-17 23:30:49.93', '2026-03-17 23:30:49.93', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0az0018qhyfcfafg8m4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'O czym opowiada Powieść Wajdeloty (historia Waltera Alfa)?', '{"options": ["O budowie zamku krzyzackiego w Malborku", "O dziecinstwie Waltera Alfa -- porwanie przez Krzyzakow, wychowanie u Winrycha, nauki wajdeloty, ucieczka na Litwe, malzeenstwo z Aldona i decyzja o zemsce", "O walkach Kiejstuta z Tatarami", "O historii Zakonu Krzyzackiego od zalozenia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Powiesc Wajdeloty to kluczowy fragment -- opowiada cala przeszlosc bohatera: porwanie z Litwy, wychowanie u mistrza Winrycha, tajne nauki wajdeloty, ucieczke na Litwe, malzenstwo z Aldona (corka Kiejstuta) i decyzje o zemście na Krzyzakach."}', '2026-03-17 23:30:49.932', '2026-03-17 23:30:49.932', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0b10019qhyffvzexyx1', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Ktore elementy sluza budowaniu tajemniczosci bohatera?', '{"options": ["Konrad nosi przylbice i unika okazywania emocji publicznie", "Jedynym przyjacielem Konrada jest tajemniczy mnich Halban", "Nocami kleeczy pod wieza pustelnicy i rozmawia z nia po litewsku", "Konrad otwarcie opowiada wszystkim o swoim planie zemsty"]}', '[0, 1, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Konrad jest postacia tajemnicza: nosi przylbice, ukrywa emocje, jego jedynym przyjacielem jest Halban, a nocami potajemnie odwiedza wieze Aldony. NIE opowiada nikomu o planie -- to tajna misja."}', '2026-03-17 23:30:49.934', '2026-03-17 23:30:49.934', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0b4001aqhyfjj4vrlu6', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Co wpllynelo na Waltera Alfa w dzieciństwie u Krzyzakow i podtrzymalo jego litewska tozsamosc?', '{"options": ["Stary wajdelota (Halban) uczyl go litewskiego jezyka i piesni", "Halban prowadzil go nad Niemen, skad patrzyli na litewskie gory", "Walter czytal litewskie ksiazki w bibliotece zakonnej", "Halban rozbudzal w nim nienawissc do Krzyzakow i chec zemsty"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Halban uczyl Waltera litewskiego, prowadzil nad Niemen i rozbudzal nienawissc do Krzyzakow. Walter NIE czytal litewskich ksiazek -- tradycja litewska byla ustna (piesni, opowiesci), nie pisana. To wlasnie rola wajdeloty -- straz pamieci ustnej."}', '2026-03-17 23:30:49.936', '2026-03-17 23:30:49.936', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0b6001bqhyfh1qf23oj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Dlaczego Witold zrywa sojusz z Zakonem po uczcie?', '{"options": ["Bo Krzyzacy nie zaplacili mu obiecanej nagrody", "Bo Piesn Wajdeloty poruszyła jego sumienie -- przypomniala mu o zdradzie ojczyzny i hanbie zdrajcy", "Bo Konrad go publicznie obrazil", "Bo dowiedzial sie o tajnym trybunale w zamku"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Piesn Wajdeloty, mowiaca o zdrajcach Litwy i o tym, ze na tamtym swiecie ich przodkowie ich nie uznaja, gleboko poruszyla Witolda. Zbledl, zsinial, plakal -- a potem zerwaal sojusz z Zakonem i wrocil bronic Litwy. Piesn okazala sie skuteczniejsza od miecza."}', '2026-03-17 23:30:49.938', '2026-03-17 23:30:49.938', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0b8001cqhyf1nl08shh', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jak Konrad sabotuje wojne z Litwa bedac wielkim mistrzem?', '{"options": ["Otwarcie odmawia prowadzenia wojny i rezzygnuje ze stanowiska", "Celowo zwleka, narzuca posty i pokuty, a w czasie wyprawy na Litwe prowadzi wojsko w zasadzke -- dlugu oblega Wilno, pozwala na gld i choroby, az armia ginie na litewskich stepach", "Przechodzi na strone Litwinow i walczy otwarcie z Krzyzakami", "Wysyla tajne listy do Litwinow z planami wojennymi Zakonu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Konrad sabotuje Zakon od srodka: narzuca posty i pokuty zamiast wojowac, a gdy Krzyzacy wymuszajaa wojne -- prowadzi ja celowo zle: dlugo oblega Wilno, pozwala na glod i choroby w obozie, odcina dowozy. Armia ginie od mroozu i glodu na litewskich stepach. Sam wraca z garstka zywych."}', '2026-03-17 23:30:49.941', '2026-03-17 23:30:49.941', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0bb001dqhyfpgwrur09', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jaki zarzut stawia tajny trybunal Konradowi Wallenrodowi?', '{"options": ["Ze nie jest prawdziwym Wallenrodem, ze zabill prawdziwego rycerza, ze jest heretykiem i zdrajca Zakonu", "Ze za malo sie modli i nie uchodzi do kaplicy", "Ze jest alkoholikiem i nie nadaje sie na mistrza", "Ze ma zone ukryta w wiezy zamkowej"]}', '0', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Tajny trybunal stawia cztery zarzuty: falsz (nie jest Wallenrodem), zabojstwo (zabil prawdziwego Wallenroda), herezja i zdrada Zakonu. Oskarrzyciel przysieega na krucyfiks, a dwunastu zamaskowanych sedziow wydaje wyrok: \"biada!\" -- trzykrotnie powtorzony echem."}', '2026-03-17 23:30:49.943', '2026-03-17 23:30:49.943', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0bd001eqhyf0gm5jlfg', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Ktore z ponizszych stwierdzen o kompozycji "Konrada Wallenroda" sa prawdziwe?', '{"options": ["Fabuła jest przedstawiona chronologicznie od dziecinstwa do smierci bohatera", "Przeszlosc bohatera poznajemy dopiero z Powiesi Wajdeloty w czesci IV (na uczcie)", "Utwor zawiera formy liryczne wplecione w narracje: hymn, piesni, ballade", "Utwor laaczy cechy epiki, liryki i dramatu -- jest gatunkiem synkretycznym"]}', '[1, 2, 3]', NULL, '{historical_literary,closed_multiple,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Fabuła NIE jest chronologiczna -- zaczyna sie od obioru mistrza, przeszlosc Waltera poznajemy dopiero z piesni Wajdeloty (cz. IV). Utwor zawiera formy liryczne (hymn, piesni, ballada Alpuhara) i jest synkretyczny (epika + liryka + dramat). To cechy powiesci poetyckiej."}', '2026-03-17 23:30:49.945', '2026-03-17 23:30:49.945', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmmv8x0bf001fqhyfbcv5y8sz', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Wyjasnij, dlaczego Aldona zamknela sie w wiezy przy zamku w Malborku. Jakie byly jej motywacje?', '{"hints": ["bliskosc meza", "oczekiwanie na powrot", "milosc"]}', '"Aldona zamknela sie w wiezy z milosci do meza. Wiedzala, ze Walter Alf planuje zemste na Krzyzakach i wroci kiedys do Malborka. Chciala byc blisko niego -- slyszec chociaz glos rycerza przechodzaccego obok wiezy, moze rozpoznac ukochanego. Mowiila: \"niech twarz odmieni... jeszcze serce moje z daleka nawet kochanka odgadnie\". Zamurowanie w wiezy bylo aktem desperackiej milosci i poswiecenia -- zywcem pogrzebala sie, by czekac na jednoego czlowieka."', NULL, '{historical_literary,short_answer,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Motywacja Aldony to czysta, poswiecona milosc -- zamknela sie w grobie za zycia, by byc blisko meza. Jest jednoczesnie tragiczna i heroiczna -- jej ofiara dorownuje ofierze Konrada."}', '2026-03-17 23:30:49.948', '2026-03-17 23:30:49.948', 'Konrad Wallenrod');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evame0157qhd9uxlv1i7t', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Co Zosia dała Tadeuszowi przed jego wyjazdem?', '{"options": ["Pierścionek", "List", "Obrazek i relikwiarz", "Chusteczkę"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Zosia dała Tadeuszowi obrazek ze świętą Genowefą i relikwiarz z suknią świętego Józefa, mówiąc ''niech pamięta o Zosi''."}', '2025-10-24 22:16:55.431', '2025-10-24 22:16:55.431', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evah5012vqhd98s0cht6q', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 2, 'Co zapowiada uwaga kapitana o Makdonwaldzie ''od pępka do szczęki''?', '{"options": ["Nic szczególnego", "Sposób śmierci Duncana", "Los samego Makbeta - ścięcie głowy", "Śmierć Lady Makbet"]}', '2', NULL, '{historical_literary,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "Makbet zabija zdrajcę Makdonwalda przez ścięcie - sam zginie identycznie jako zdrajca."}', '2025-10-24 22:16:55.242', '2025-10-24 22:16:55.242', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evah8012wqhd9xai68kip', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 3, 'Jak zaburzenia w naturze po morderstwie odzwierciedlają elżbietański worldview?', '{"options": ["To tylko efekty specjalne", "Makrokosmos reaguje na naruszenie Great Chain of Being", "To realistyczny opis pogody", "Nie ma zaburzeń w naturze"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,renaissance,batch-2025-01}', '{"explanation": "W elżbietańskiej kosmologii naruszenie hierarchii (królobójstwo) zaburza cały porządek natury."}', '2025-10-24 22:16:55.244', '2025-10-24 22:16:55.244', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaha012xqhd9k7ybwt7w', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 2, 'Dlaczego Makbet zabija strażników Duncana?', '{"options": ["Z zemsty", "Panicznie improwizuje, by ukryć winę i pokazać ''gniew''", "To był plan Lady Makbet", "Przypadkiem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "To improwizacja - zabija potencjalnych świadków, udając sprawiedliwy gniew. Lady Makbet jest zaskoczona."}', '2025-10-24 22:16:55.246', '2025-10-24 22:16:55.246', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evahc012yqhd9uf1jtmrf', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 3, 2, 'Jak interpretować podwójne znaczenie ''nie zrodzony z kobiety''?', '{"options": ["To tylko zagadka", "Gra słów: ''zrodzony'' (naturalnie) vs ''wydarty'' (cesarskie cięcie)", "Makduf jest bogiem", "To błąd w tłumaczeniu"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,renaissance,batch-2025-01}', '{"explanation": "Dwuznaczność językowa: cesarskie cięcie to nie ''zrodzenie'' w naturalnym sensie."}', '2025-10-24 22:16:55.248', '2025-10-24 22:16:55.248', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evahe012zqhd9r5a2e17n', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 5, 3, 'Co krytykuje Malcolma test lojalności Makdufa (Akt IV)?', '{"options": ["Pokazuje mądrość przyszłego króla", "Ujawnia, że nawet ''dobrzy'' używają manipulacji i kłamstwa", "To niepotrzebna scena", "Nic nie krytykuje"]}', '1', NULL, '{historical_literary,closed_single,difficulty-5,renaissance,batch-2025-01}', '{"explanation": "Malcolm kłamie o swojej deprawacji - Shakespeare pokazuje, że polityka zawsze wymaga moralnych kompromisów."}', '2025-10-24 22:16:55.25', '2025-10-24 22:16:55.25', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evahg0130qhd9kirc7cw5', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 2, 'Jak zmienia się percepcja czasu u Makbeta?', '{"options": ["Nie zmienia się", "Od obsesji przyszłością do uwięzienia w teraźniejszości pełnej przeszłości", "Zapomina o czasie", "Czas przyspiesza"]}', '1', NULL, '{historical_literary,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "Początkowo obsesja przyszłością (przepowiednie), potem uwięzienie między winą przeszłości a lękiem o przyszłość."}', '2025-10-24 22:16:55.252', '2025-10-24 22:16:55.252', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evahi0131qhd9osbu6pkp', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 3, 2, 'Co oznacza odniesienie do ''Golgoty'' w opisie bitwy?', '{"options": ["Zwykłe pole bitwy", "Porównanie do męki Chrystusa - zapowiedź ofiary i odkupienia", "Nazwę miejscowości", "Nic szczególnego"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,renaissance,batch-2025-01}', '{"explanation": "Golgota to miejsce ukrzyżowania - zapowiada motyw ofiary, ale ironicznie Makbet stanie się Judaszem, nie Chrystusem."}', '2025-10-24 22:16:55.254', '2025-10-24 22:16:55.254', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evahk0132qhd9l0fhmknv', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 4, 2, 'Dlaczego motyw snu jest kluczowy dla zrozumienia tragedii?', '{"options": ["Sen to metafora śmierci, niewinności i naturalnego porządku - Makbet niszczy wszystkie trzy", "To tylko dekoracja", "Sen nie jest ważny", "Wszyscy są zmęczeni"]}', '0', NULL, '{historical_literary,closed_single,difficulty-4,renaissance,batch-2025-01}', '{"explanation": "Sen łączy śmierć (''wieczny sen''), niewinność (spokój sumienia) i naturę (rytm dnia/nocy) - Makbet ''morduje sen''."}', '2025-10-24 22:16:55.256', '2025-10-24 22:16:55.256', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaj2013rqhd9f1kjw607', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 2, 'Dopasuj cytaty do postaci', '{"leftColumn": [{"id": "A", "text": "Brzydkie jest piękne, piękne brzydkie"}, {"id": "B", "text": "Czy cały ocean wielkiego Neptuna zmyje tę krew?"}, {"id": "C", "text": "Precz, przeklęta plamo!"}, {"id": "D", "text": "Życie jest tylko cieniem"}], "rightColumn": [{"id": 1, "text": "Lady Makbet"}, {"id": 2, "text": "Makbet"}, {"id": 3, "text": "wiedźmy"}, {"id": 4, "text": "Banko"}], "matchingType": "quote_character"}', '[[0, 2], [1, 1], [2, 0], [3, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Wiedźmy mówią o względności, Makbet o krwi i cieniu życia, Lady Makbet o plamie."}', '2025-10-24 22:16:55.311', '2025-10-24 22:16:55.311', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaj5013sqhd9k310q3pm', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 2, 'Uzupełnij lukę w fabule', '{"gaps": [{"id": 1, "options": ["duchami", "wiedźmami", "rycerzami", "wróżbitami"]}, {"id": 2, "options": ["wygnany", "zabity", "królem", "tanem Ross"]}, {"id": 3, "options": ["Banka", "Duncana", "Lady Makbet", "Makdufa"]}, {"id": 4, "options": ["Banka", "Duncana", "Malcolma", "Makdufa"]}], "textWithGaps": "Po spotkaniu z [1], Makbet dowiaduje się, że zostanie [2]. Namówiony przez [3], zabija [4] i obejmuje tron."}', '[1, 2, 2, 1]', NULL, '{historical_literary,closed_multiple,difficulty-1,renaissance,batch-2025-01}', '{"explanation": "Po spotkaniu z wiedźmami Makbet dowiaduje się o królestwie, Lady Makbet namawia go do zabicia Duncana."}', '2025-10-24 22:16:55.313', '2025-10-24 22:16:55.313', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaj7013tqhd9res696gh', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 2, 'Które symbole pojawiają się w dramacie? (wybierz wszystkie)', '{"options": ["krew", "korona", "sztylet", "sen", "róża", "burza"]}', '[0, 1, 2, 3, 5]', NULL, '{historical_literary,closed_multiple,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Główne symbole to: krew (wina), korona (władza), sztylet (morderstwo), sen (spokój) i burza (chaos)."}', '2025-10-24 22:16:55.316', '2025-10-24 22:16:55.316', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaja013uqhd9gc0ylae3', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 2, 'Dopasuj role do postaci', '{"leftColumn": [{"id": "A", "text": "Malcolm"}, {"id": "B", "text": "Makduf"}, {"id": "C", "text": "Fleance"}, {"id": "D", "text": "Siward"}], "rightColumn": [{"id": 1, "text": "syn Banka"}, {"id": 2, "text": "dowódca wojsk angielskich"}, {"id": 3, "text": "syn Duncana"}, {"id": 4, "text": "tan Fife"}], "matchingType": "character_role"}', '[[0, 2], [1, 3], [2, 0], [3, 1]]', NULL, '{historical_literary,closed_multiple,difficulty-1,renaissance,batch-2025-01}', '{"explanation": "Malcolm - syn Duncana, Makduf - tan Fife, Fleance - syn Banka, Siward - dowódca Anglików."}', '2025-10-24 22:16:55.318', '2025-10-24 22:16:55.318', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evajc013vqhd9sjw8u68o', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Jaki zabieg dramaturgiczny stosuje Shakespeare, pokazując las Birnam „idący” do Dunsinane?', '{"options": ["metaforę", "ironię dramatyczną", "alegorię", "personifikację"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "To ironia dramatyczna - żołnierze niosą gałęzie, tworząc iluzję poruszającego się lasu."}', '2025-10-24 22:16:55.32', '2025-10-24 22:16:55.32', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaje013wqhd9t6vefckd', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Dla którego króla angielskiego Shakespeare napisał ''Makbeta''?', '{"options": ["Henryka VIII", "Elżbiety I", "Jakuba I", "Karola I"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Makbet został napisany dla Jakuba I, króla pochodzenia szkockiego."}', '2025-10-24 22:16:55.322', '2025-10-24 22:16:55.322', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evajg013xqhd96hc6yybk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Ile aktów ma tragedia ''Makbet''?', '{"options": ["trzy", "cztery", "pięć", "siedem"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Makbet, jak większość tragedii Shakespeare''a, ma pięć aktów."}', '2025-10-24 22:16:55.325', '2025-10-24 22:16:55.325', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evajj013yqhd9siq8va2j', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 1, 'Kim jest Hekate w dramacie „Makbet”?', '{"options": ["żoną Makbeta", "królową wiedźm", "córką Duncana", "służącą"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,renaissance,batch-2025-01}', '{"explanation": "Hekate jest boginią czarów i przywódczynią wiedźm."}', '2025-10-24 22:16:55.327', '2025-10-24 22:16:55.327', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evajl013zqhd9qk4tg2uy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Co oznacza „jutro, i jutro, i jutro” w monologu Makbeta?', '{"options": ["nadzieję na lepszą przyszłość", "bezsens i pustkę życia", "plany na przyszłość", "obietnicę zemsty"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Monolog wyraża nihilizm Makbeta - życie jest puste i pozbawione sensu."}', '2025-10-24 22:16:55.33', '2025-10-24 22:16:55.33', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evajo0140qhd9jfnytulg', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 1, 'Czego Lady Makbet prosi duchy w swojej inwokacji?', '{"options": ["o śmierć", "o bogactwo", "o „odniewieścenie” - pozbawienie kobiecych uczuć", "o piękno"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,renaissance,batch-2025-01}', '{"explanation": "Lady Makbet prosi duchy o pozbawienie jej kobiecych uczuć litości i współczucia."}', '2025-10-24 22:16:55.333', '2025-10-24 22:16:55.333', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evajr0141qhd99izkj40l', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Dokąd uciekają synowie Duncana po śmierci ojca?', '{"options": ["Malcolm do Francji, Donalbain do Hiszpanii", "obaj do Irlandii", "Malcolm do Anglii, Donalbain do Irlandii", "obaj do Norwegii"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Malcolm ucieka do Anglii, a Donalbain do Irlandii."}', '2025-10-24 22:16:55.335', '2025-10-24 22:16:55.335', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evajt0142qhd9xoce5z42', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 1, 'Jaki tytuł otrzymuje Makbet po pierwszej bitwie?', '{"options": ["tan Ross", "tan Cawdor", "książę Szkocji", "lord Glamis"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,renaissance,batch-2025-01}', '{"explanation": "Makbet otrzymuje tytuł tana Cawdor po zwycięskiej bitwie."}', '2025-10-24 22:16:55.337', '2025-10-24 22:16:55.337', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evajv0143qhd9ym3e0r5u', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 1, 'Co symbolizuje bezsenność Makbeta?', '{"options": ["chorobę fizyczną", "utratę spokoju sumienia", "lenistwo", "słabość"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,renaissance,batch-2025-01}', '{"explanation": "Bezsenność symbolizuje utratę spokoju sumienia po zbrodni."}', '2025-10-24 22:16:55.34', '2025-10-24 22:16:55.34', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evak00145qhd9f1fdibr8', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 2, 'Wyjaśnij, jaką rolę odgrywają wiedźmy w tragedii.', '{"instruction": "Opisz funkcję wiedźm w rozwoju akcji i ich wpływ na Makbeta (40-60 słów)."}', NULL, '{"criteria": ["wskazanie roli katalizatora akcji (1 pkt)", "dwuznaczność przepowiedni i manipulacja (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,renaissance,batch-2025-01}', '{"keyWords": ["katalizator", "przepowiednie", "ambicja", "manipulacja", "dwuznaczność"], "expectedAnswer": "Wiedźmy pełnią rolę katalizatora - ich przepowiednie rozbudzają ambicję Makbeta. Nie zmuszają go do zbrodni, ale manipulują dwuznacznymi przepowiedniami. Reprezentują siły chaosu i zła, ale też mogą być projekcją pragnień bohatera."}', '2025-10-24 22:16:55.344', '2025-10-24 22:16:55.344', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evak20146qhd9uf1m1640', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 2, 'Opisz przemianę Lady Makbet w trakcie dramatu.', '{"instruction": "Wyjaśnij, jak zmienia się Lady Makbet od początku do końca sztuki (40-60 słów)."}', NULL, '{"criteria": ["początkowa siła i determinacja (1 pkt)", "załamanie psychiczne i samobójstwo (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-1,renaissance,batch-2025-01}', '{"keyWords": ["siła", "determinacja", "obłęd", "lunatyzm", "wyrzuty sumienia", "samobójstwo"], "expectedAnswer": "Lady Makbet początkowo jest silna, bezwzględna i dominuje nad mężem. Planuje morderstwo i dodaje mu odwagi. Później popada w obłęd, cierpi na lunatyzm, obsesyjnie myje ręce z niewidzialnej krwi. Kończy życie samobójstwem, zniszczona wyrzutami sumienia."}', '2025-10-24 22:16:55.346', '2025-10-24 22:16:55.346', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evak40147qhd9pssexeeq', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 2, 'Wyjaśnij symbolikę krwi w „Makbecie”.', '{"instruction": "Opisz, co symbolizuje krew i jak zmienia się jej znaczenie (30-50 słów)."}', NULL, '{"criteria": ["krew jako symbol winy (1 pkt)", "niemożność zmycia/odkupienia (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,renaissance,batch-2025-01}', '{"keyWords": ["wina", "piętno", "obsesja", "wyrzuty sumienia", "niezmywalność"], "expectedAnswer": "Krew symbolizuje winę i niezmywalne piętno zbrodni. Początkowo to znak odwagi wojennej, potem staje się obsesją - Makbet widzi krwawe sztylety, Lady Makbet nie może zmyć plam. Reprezentuje wyrzuty sumienia, których nie da się usunąć."}', '2025-10-24 22:16:55.349', '2025-10-24 22:16:55.349', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evak70148qhd9vxn5k6ao', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 2, 'Dlaczego Makbet zabija Banka?', '{"instruction": "Wyjaśnij motywacje Makbeta do zabójstwa przyjaciela (30-50 słów)."}', NULL, '{"criteria": ["przepowiednia o potomkach Banka (1 pkt)", "strach i paranoja Makbeta (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-1,renaissance,batch-2025-01}', '{"keyWords": ["przepowiednia", "potomkowie", "królowie", "zagrożenie", "świadek"], "expectedAnswer": "Makbet zabija Banka z dwóch powodów: wiedźmy przepowiedziały, że synowie Banka będą królami, co zagraża jego dynastii. Dodatkowo Banko był świadkiem przepowiedni i mógł domyślić się prawdy o morderstwie Duncana."}', '2025-10-24 22:16:55.351', '2025-10-24 22:16:55.351', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evak90149qhd9usmgsnja', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 2, 'Opisz scenę z duchem Banka podczas uczty.', '{"instruction": "Wyjaśnij znaczenie pojawienia się ducha i reakcję Makbeta (40-60 słów)."}', NULL, '{"criteria": ["duch jako projekcja winy (1 pkt)", "publiczne ujawnienie szaleństwa (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,renaissance,batch-2025-01}', '{"keyWords": ["duch", "halucynacja", "wina", "panika", "kompromitacja"], "expectedAnswer": "Duch Banka pojawia się podczas uczty, zajmując miejsce Makbeta. Tylko Makbet go widzi, co sugeruje halucynację wywołaną poczuciem winy. Jego paniczna reakcja kompromituje go przed gośćmi, Lady Makbet desperacko próbuje zatuszować sytuację."}', '2025-10-24 22:16:55.353', '2025-10-24 22:16:55.353', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evakb014aqhd972lr2xhc', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 2, 'Jak rozumiesz słowa wiedźm ''Brzydkie jest piękne, piękne brzydkie''?', '{"instruction": "Wyjaśnij paradoks i jego znaczenie dla całego dramatu (30-50 słów)."}', NULL, '{"criteria": ["względność dobra i zła (1 pkt)", "przewrotność świata w dramacie (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,renaissance,batch-2025-01}', '{"keyWords": ["paradoks", "względność", "odwrócenie", "chaos moralny", "pozory"], "expectedAnswer": "Paradoks wyraża względność wartości i odwrócenie porządku moralnego. W świecie Makbeta zło wydaje się dobre (władza przez zbrodnię), a dobro złe. Zapowiada moralny chaos, gdzie nie można odróżnić prawdy od fałszu."}', '2025-10-24 22:16:55.356', '2025-10-24 22:16:55.356', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evake014bqhd9vt8agwkq', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 2, 'Zinterpretuj metaforę życia jako ''cienia'' z monologu Makbeta.', '{"instruction": "Wyjaśnij nihilistyczną wizję życia w słynnym monologu (40-60 słów)."}', NULL, '{"criteria": ["życie jako iluzja/pustka (1 pkt)", "bezsens istnienia (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,renaissance,batch-2025-01}', '{"keyWords": ["cień", "iluzja", "pustka", "nihilizm", "bezsens", "teatr"], "expectedAnswer": "Życie jako ''cień'' to metafora pustki i iluzoryczności istnienia. Makbet widzi życie jako pozbawione substancji, jak teatralną rolę bez znaczenia. To wyraz nihilizmu - po utracie wszystkiego odkrywa, że życie jest ''opowieścią idioty'', bez sensu."}', '2025-10-24 22:16:55.358', '2025-10-24 22:16:55.358', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evakg014cqhd9h8x0k4xr', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 2, 'Wyjaśnij ironię w spełnieniu przepowiedni o lesie Birnam.', '{"instruction": "Opisz, jak spełnia się przepowiednia i dlaczego to ironia dramatyczna (30-50 słów)."}', NULL, '{"criteria": ["żołnierze z gałęziami jako ''las'' (1 pkt)", "dosłowna interpretacja Makbeta (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,renaissance,batch-2025-01}', '{"keyWords": ["ironia", "dosłowność", "gałęzie", "kamuflaż", "iluzja"], "expectedAnswer": "Makbet interpretuje przepowiednię dosłownie - las nie może chodzić. Ironia polega na tym, że żołnierze niosą gałęzie jako kamuflaż, tworząc iluzję poruszającego się lasu. Przepowiednia spełnia się w nieoczekiwany sposób."}', '2025-10-24 22:16:55.36', '2025-10-24 22:16:55.36', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaki014dqhd9u1fr6yb9', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'RENAISSANCE', 1, 2, 'Kim jest Makduf i dlaczego jest ważny dla fabuły „Makbeta”?', '{"instruction": "Opisz postać Makdufa i jego rolę w upadku Makbeta (40-60 słów)."}', NULL, '{"criteria": ["tan Fife, odkrywa morderstwo (1 pkt)", "zabija Makbeta - cesarskie cięcie (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-1,renaissance,batch-2025-01}', '{"keyWords": ["tan Fife", "odkrycie", "rodzina", "zemsta", "cesarskie cięcie"], "expectedAnswer": "Makduf to tan Fife, który odkrywa zamordowanego Duncana. Gdy Makbet zabija jego rodzinę, Makduf przyłącza się do Malcolma. Jest narzędziem zemsty - może zabić Makbeta, bo urodził się przez cesarskie cięcie, nie był ''zrodzony'' z kobiety."}', '2025-10-24 22:16:55.363', '2025-10-24 22:16:55.363', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evakl014eqhd9cxld6t53', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'RENAISSANCE', 2, 2, 'Wyjaśnij pojęcie ''tragicznej wady'' (hamartia) na przykładzie Makbeta.', '{"instruction": "Zdefiniuj hamartię i wskaż, jaka jest tragiczna wada Makbeta (40-60 słów)."}', NULL, '{"criteria": ["definicja hamartii (1 pkt)", "ambicja jako wada Makbeta (1 pkt)"], "maxScore": 2}', '{historical_literary,short_answer,difficulty-2,renaissance,batch-2025-01}', '{"keyWords": ["hamartia", "tragiczna wada", "ambicja", "upadek", "władza"], "expectedAnswer": "Hamartia to tragiczna wada bohatera prowadząca do jego upadku. U Makbeta jest to niepohamowana ambicja - pragnienie władzy silniejsze niż sumienie. Ta wada sprawia, że bohater sam przyczynia się do własnej katastrofy."}', '2025-10-24 22:16:55.365', '2025-10-24 22:16:55.365', 'Makbet');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evakn014fqhd9vouh2nea', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Kto jest autorem ''Pana Tadeusza''?', '{"options": ["Juliusz Słowacki", "Adam Mickiewicz", "Zygmunt Krasiński", "Cyprian Kamil Norwid"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "''Pan Tadeusz'' został napisany przez Adama Mickiewicza w latach 1832-1834 w Paryżu, podczas emigracji po upadku powstania listopadowego."}', '2025-10-24 22:16:55.367', '2025-10-24 22:16:55.367', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evakp014gqhd9yr9rwwic', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Jaki jest pełny tytuł epopei Mickiewicza?', '{"options": ["Pan Tadeusz", "Pan Tadeusz czyli Ostatni zajazd na Litwie", "Pan Tadeusz - historia szlachecka", "Pan Tadeusz i Zosia"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Pełny tytuł brzmi: ''Pan Tadeusz czyli Ostatni zajazd na Litwie. Historia szlachecka z roku 1811 i 1812 we dwunastu księgach wierszem''."}', '2025-10-24 22:16:55.37', '2025-10-24 22:16:55.37', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaks014hqhd9cpee5732', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'W jakich latach toczy się akcja ''Pana Tadeusza''?', '{"options": ["1795-1796", "1811-1812", "1830-1831", "1863-1864"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Akcja toczy się w latach 1811-1812, tuż przed wyprawą Napoleona na Moskwę, która dawała Polakom nadzieję na odzyskanie niepodległości."}', '2025-10-24 22:16:55.372', '2025-10-24 22:16:55.372', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaku014iqhd9a70rwdjy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Gdzie głównie toczy się akcja ''Pana Tadeusza''?', '{"options": ["W Warszawie", "W Krakowie", "W Soplicowie na Litwie", "W Wilnie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Akcja toczy się głównie w Soplicowie - majątku rodziny Sopliców na Litwie, oraz w pobliskim zamku Horeszków."}', '2025-10-24 22:16:55.374', '2025-10-24 22:16:55.374', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evakw014jqhd9smj6wkx6', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Jak ma na imię główny bohater epopei „Pan Tadeusz”?', '{"options": ["Stanisław", "Jacek", "Tadeusz", "Gerwazy"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Główny bohater to Tadeusz Soplica, młody szlachcic powracający z Wilna do rodzinnego Soplicowa."}', '2025-10-24 22:16:55.377', '2025-10-24 22:16:55.377', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evakz014kqhd9df7ghrlq', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Kim jest Zosia?', '{"options": ["Córką Sędziego", "Córką Telimeny", "Wychowanicą Sędziego, wnuczką Stolnika Horeszki", "Służącą w Soplicowie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Zosia jest wychowanicą Sędziego, a w rzeczywistości wnuczką zamordowanego Stolnika Horeszki. Jej rodzice zginęli na Syberii."}', '2025-10-24 22:16:55.379', '2025-10-24 22:16:55.379', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eval2014lqhd9umjikbqt', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Kto jest ojcem Tadeusza?', '{"options": ["Sędzia Soplica", "Jacek Soplica", "Hrabia", "Gerwazy"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Ojcem Tadeusza jest Jacek Soplica, ukrywający się jako ksiądz Robak. Sędzia jest stryjem Tadeusza."}', '2025-10-24 22:16:55.382', '2025-10-24 22:16:55.382', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eval4014mqhd969yxu2ao', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Kto ukrywa się pod postacią księdza Robaka?', '{"options": ["Gerwazy", "Jacek Soplica", "Hrabia", "Jankiel"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Pod postacią bernardyna księdza Robaka ukrywa się Jacek Soplica, zabójca Stolnika Horeszki, ojciec Tadeusza, który w ten sposób pokutuje za swój czyn."}', '2025-10-24 22:16:55.385', '2025-10-24 22:16:55.385', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eval6014nqhd9k8nln1yi', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Który z chartów wygrał zakład według orzeczenia Wojskiego?', '{"options": ["Sokół", "Kusy", "Oba wygrały równo", "Żaden nie wygrał"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Wojski orzekł remis - oba charty jednocześnie dopadły zająca, więc oba wygrały. ''Godzien jest pałac Paca, godzien Pac pałaca''."}', '2025-10-24 22:16:55.387', '2025-10-24 22:16:55.387', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5eval9014oqhd9mglszyof', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'Jak nazywa się słynna szabla Gerwazego?', '{"options": ["Szczerbiec", "Scyzoryk", "Rózeczka", "Kropidło"]}', '1', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Gerwazy władał słynnym mieczem zwanym Scyzorykiem - ogromnym rapierem, który na końcu utworu podarował generałowi Kniaziewiczowi."}', '2025-10-24 22:16:55.389', '2025-10-24 22:16:55.389', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evalb014pqhd9kl0wui5i', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Za kogo Tadeusz wziął Telimenę przy pierwszym spotkaniu?', '{"options": ["Za służącą", "Za matkę Zosi", "Za białą postać na tle drzew - wziął ją za dziewczynę z portretu", "Za Hrabinę"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Tadeusz zobaczył Telimenę w ogrodzie na tle brzóz i wziął ją za młodą dziewczynę z portretu, który wcześniej podziwiał w Soplicowie."}', '2025-10-24 22:16:55.391', '2025-10-24 22:16:55.391', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evald014qqhd9mrhjh27l', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Kto zabił niedźwiedzia podczas polowania?', '{"options": ["Hrabia", "Tadeusz i ksiądz Robak - obaj strzelili jednocześnie", "Asesor", "Rejent"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Niedźwiedzia zabili wspólnie Tadeusz i ksiądz Robak, strzelając jednocześnie. To wywołało spór o to, kto powinien otrzymać skórę."}', '2025-10-24 22:16:55.393', '2025-10-24 22:16:55.393', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evalj014tqhd90ecq105h', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 1, 'W jakiej porze roku rozpoczyna się akcja „Pana Tadeusza”?', '{"options": ["Wiosną", "Jesienią", "Zimą", "Latem"]}', '4', NULL, '{historical_literary,closed_single,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Akcja rozpoczyna się latem - w inwokacji czytamy o ''pagórkach zielonych'' i ''łąkach zielonych, szeroko nad błękitnym Niemnem rozciągnionych''."}', '2025-10-24 22:16:55.4', '2025-10-24 22:16:55.4', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evalm014uqhd9t4e1nwqj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Jak nazywał się ostatni żyjący niedźwiedź w okolicach Soplicowa?', '{"options": ["Kusy", "Dobrzyński", "Bestia", "Matecznik"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Niedźwiedź nazywał się ''Dobrzyński'' od Macieja Dobrzyńskiego, który kiedyś próbował go zabić, ale tylko postrzał w ucho."}', '2025-10-24 22:16:55.402', '2025-10-24 22:16:55.402', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evalo014vqhd97k7bc106', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Co symbolizuje zegar w dworze Sopliców z kurantem grającym Mazurka Dąbrowskiego?', '{"options": ["Bogactwo rodziny", "Nowoczesność dworu", "Pamięć o tradycji i nadzieję na niepodległość", "Umiłowanie muzyki"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Zegar z kurantem grającym Mazurka Dąbrowskiego symbolizuje pamięć o polskiej tradycji i nadzieję na odzyskanie niepodległości."}', '2025-10-24 22:16:55.404', '2025-10-24 22:16:55.404', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evalq014wqhd9rjw6x837', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Co oznacza tytuł ''Ostatni zajazd na Litwie''?', '{"options": ["Ostatnie polowanie", "Ostatni pojedynek", "Koniec tradycji szlacheckich najazdów zbrojnych na sąsiadów", "Ostatnia bitwa z Rosjanami"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Zajazd na Soplicowo to ostatni tradycyjny szlachecki najazd zbrojny w sporze sąsiedzkim - symbol odchodzącego świata staropolskich obyczajów."}', '2025-10-24 22:16:55.406', '2025-10-24 22:16:55.406', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evals014xqhd9pfj3kdhv', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Które postacie zakochane były w Zosi? (wybierz wszystkie poprawne)', '{"options": ["Tadeusz Soplica", "Hrabia", "Sak Dobrzyński", "Ksiądz Robak", "Asesor"]}', '[0, 2]', NULL, '{historical_literary,closed_multiple,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "W Zosi zakochani byli Tadeusz (którego ona też pokochała) oraz Sak Dobrzyński (syn Macieja Chrzciciela). Hrabia był zainteresowany Telimeną."}', '2025-10-24 22:16:55.409', '2025-10-24 22:16:55.409', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evalu014yqhd9yfe20p26', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Które zwierzęta odgrywają ważną rolę w fabule „Pana Tadeusza”? (wybierz wszystkie poprawne)', '{"options": ["Charty Kusy i Sokół", "Niedźwiedź", "Koń Hrabiego", "Zając podczas polowania", "Kogut w Soplicowie"]}', '[0, 1, 3]', NULL, '{historical_literary,closed_multiple,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Ważne role odgrywają: charty (spór o lepszego), niedźwiedź (polowanie), zając (rozstrzygnięcie sporu o charty). Koń i kogut nie mają istotnego znaczenia."}', '2025-10-24 22:16:55.411', '2025-10-24 22:16:55.411', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evalw014zqhd9060pbf95', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Jakie warstwy społeczne są przedstawione w ''Panu Tadeuszu''? (wybierz wszystkie poprawne)', '{"options": ["Szlachta zamożna (Sędzia, Telimena)", "Szlachta zaściankowa (Dobrzyńscy)", "Arystokracja (Hrabia)", "Chłopi", "Mieszczaństwo", "Żydzi (Jankiel)"]}', '[0, 1, 2, 3, 5]', NULL, '{historical_literary,closed_multiple,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "W utworze przedstawiona jest szlachta zamożna i zaściankowa, arystokracja, chłopi oraz Żydzi. Brak jest mieszczaństwa - akcja toczy się na wsi."}', '2025-10-24 22:16:55.413', '2025-10-24 22:16:55.413', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evalz0150qhd9fd8zxa3b', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 4, 'Dopasuj postać z „Pana Tadeusza” do jej charakterystycznego przedmiotu lub atrybutu.', '{"leftColumn": [{"id": "A", "text": "Gerwazy"}, {"id": "B", "text": "Wojski"}, {"id": "C", "text": "Telimena"}, {"id": "D", "text": "Maciej Dobrzyński"}], "rightColumn": [{"id": 1, "text": "Rózeczka (szabla)"}, {"id": 2, "text": "tabakiera"}, {"id": 3, "text": "Scyzoryk"}, {"id": 4, "text": "modne stroje paryskie"}], "matchingType": "character_attribute"}', '[[0, 2], [1, 1], [2, 3], [3, 0]]', NULL, '{historical_literary,closed_multiple,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Gerwazy władał Scyzorykiem, Wojski słynął z tabakiery, Telimena nosiła modne stroje z Petersburga, a Maciej Rózeczka miał słynną szablę Rózeczkę."}', '2025-10-24 22:16:55.415', '2025-10-24 22:16:55.415', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evam10151qhd98d1ciyck', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Dopasuj zdarzenie do księgi „Pana Tadeusza”, w której miało miejsce.', '{"leftColumn": [{"id": "A", "text": "Powrót Tadeusza do Soplicowa"}, {"id": "B", "text": "Polowanie na niedźwiedzia"}, {"id": "C", "text": "Zajazd na Soplicowo"}], "rightColumn": [{"id": 1, "text": "Księga I"}, {"id": 2, "text": "Księga IV"}, {"id": 3, "text": "Księga VIII"}], "matchingType": "event_book"}', '[[0, 0], [1, 1], [2, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Powrót Tadeusza to Księga I (''Gospodarstwo''), polowanie to Księga IV (''Dyplomatyka i łowy''), zajazd to Księga VIII (''Zajazd'')."}', '2025-10-24 22:16:55.417', '2025-10-24 22:16:55.417', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evam30152qhd93ro9xdwl', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Kto wypowiada słowa: „Kochajmy się!” w „Panu Tadeuszu”?', '{"options": ["Tadeusz do Zosi", "To tytuł ostatniej księgi", "Sędzia podczas uczty", "Ksiądz Robak przed śmiercią"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "„Kochajmy się” to tytuł XII (ostatniej) księgi „Pana Tadeusza”, będący zarazem przesłaniem całego utworu."}', '2025-10-24 22:16:55.42', '2025-10-24 22:16:55.42', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evam50153qhd9t09coj8y', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Uzupełnij cytat z inwokacji: ''Litwo! Ojczyzno moja! ty jesteś jak...''', '{"options": ["słońce", "matka", "zdrowie", "raj"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Pełny cytat: ''Litwo! Ojczyzno moja! ty jesteś jak zdrowie. Ile cię trzeba cenić, ten tylko się dowie, kto cię stracił.''"}', '2025-10-24 22:16:55.422', '2025-10-24 22:16:55.422', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evam80154qhd9f3z8zj5a', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Jakie wydarzenie historyczne kończy akcję ''Pana Tadeusza''?', '{"options": ["Bitwa pod Grunwaldem", "Powstanie listopadowe", "Wkroczenie wojsk Napoleona na Litwę w 1812", "Trzeci rozbiór Polski"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Akcja kończy się wkroczeniem wojsk napoleońskich na Litwę w 1812 roku podczas wyprawy na Moskwę. To daje nadzieję na odzyskanie niepodległości."}', '2025-10-24 22:16:55.424', '2025-10-24 22:16:55.424', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evamg0158qhd9cft7gbze', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 1, 'Na jakim instrumencie grał Jankiel podczas ostatniej uczty?', '{"options": ["Na skrzypcach", "Na fortepianie", "Na cymbałach", "Na flecie"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Jankiel grał na cymbałach. Jego koncert był punktem kulminacyjnym uczty - zagrał poloneza Trzeciego Maja i ''Jeszcze Polska nie zginęła''."}', '2025-10-24 22:16:55.433', '2025-10-24 22:16:55.433', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evamj0159qhd9sqtfn59d', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Jakie polskie obyczaje szlacheckie przedstawione są w utworze? (wybierz wszystkie poprawne)', '{"options": ["Polowanie", "Zajazd", "Polonez", "Uczta", "Sejmik", "Zaręczyny"]}', '[0, 1, 2, 3, 4, 5]', NULL, '{historical_literary,closed_multiple,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Wszystkie wymienione to tradycyjne obyczaje szlacheckie przedstawione w ''Panu Tadeuszu'' - polowania, zajazdy, tańce, uczty, sejmiki i zaręczyny."}', '2025-10-24 22:16:55.435', '2025-10-24 22:16:55.435', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaml015aqhd9zcpv1y0o', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Dlaczego Jacek Soplica zabił Stolnika Horeszkę?', '{"options": ["Z zemsty politycznej", "Dla pieniędzy", "Z zazdrości miłosnej - kochał córkę Stolnika", "Z rozkazu Rosjan"]}', '2', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Jacek zabił Stolnika w afekcie z zazdrości - kochał jego córkę Ewę, ale Stolnik wydał ją za wojewodę. Jacek strzelił w przypływie rozpaczy i gniewu."}', '2025-10-24 22:16:55.437', '2025-10-24 22:16:55.437', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evamn015bqhd91rv4jzg8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Co symbolizuje koncert Jankiela w ostatniej księdze?', '{"options": ["Tylko rozrywkę podczas uczty", "Historię Polski i nadzieję na niepodległość", "Talent muzyczny Żydów", "Bogactwo Sopliców"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Koncert Jankiela to muzyczna historia Polski - od radości (Trzeci Maj), przez upadek (Targowica), rzeź Pragi, tułaczkę, po nadzieję (Mazurek Dąbrowskiego)."}', '2025-10-24 22:16:55.44', '2025-10-24 22:16:55.44', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evamp015cqhd9zu4vn3pk', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Jaki typ narracji dominuje w ''Panu Tadeuszu''?', '{"options": ["Pierwszoosobowa", "Trzecioosobowa wszechwiedzący narrator", "Drugoosobowa", "Strumień świadomości"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "W ''Panu Tadeuszu'' dominuje narracja trzecioosobowa z narratorem wszechwiedzącym, choć miejscami ujawnia się ''ja'' narratora (np. w inwokacji i epilogu)."}', '2025-10-24 22:16:55.442', '2025-10-24 22:16:55.442', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evams015dqhd9hzhkx3p9', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Wymień trzy główne rody szlacheckie występujące w „Panu Tadeuszu”.', '{"maxWords": 10, "expectedKeywords": ["Soplicowie", "Horeszkowie", "Dobrzyńscy"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Główne rody to: Soplicowie (Sędzia, Tadeusz), Horeszkowie (dawni właściciele zamku), Dobrzyńscy (szlachta zaściankowa)."}', '2025-10-24 22:16:55.444', '2025-10-24 22:16:55.444', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evamu015eqhd9nz5qr176', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Krótko wyjaśnij, dlaczego „Pan Tadeusz” nazywany jest „epopeją narodową”.', '{"maxWords": 50, "expectedKeywords": ["historia", "tradycja", "obyczaje", "Polska", "naród"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "''Pan Tadeusz'' to epopeja narodowa, bo przedstawia historię i obyczaje polskiej szlachty, stanowi obraz ginącego świata Rzeczpospolitej i wyraża tęsknotę za ojczyzną."}', '2025-10-24 22:16:55.447', '2025-10-24 22:16:55.447', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evamw015fqhd9sb5l19lj', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Opisz krótko, jak zmieniają się uczucia Tadeusza - od Telimeny do Zosi.', '{"maxWords": 60, "expectedKeywords": ["zauroczenie", "rozczarowanie", "miłość", "dojrzewanie"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Tadeusz najpierw ulega zauroczeniu dojrzałą Telimeną, ale szybko się rozczarowuje jej próżnością. Stopniowo odkrywa prawdziwe uczucie do młodej, skromnej Zosi."}', '2025-10-24 22:16:55.449', '2025-10-24 22:16:55.449', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evamz015gqhd9lidwfamb', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 1, 2, 'Podaj tytuły trzech dowolnych ksiąg „Pana Tadeusza”.', '{"maxWords": 15, "expectedKeywords": ["Gospodarstwo", "Zamek", "Umizgi", "Dyplomatyka", "Kłótnia", "Zaścianek", "Rada", "Zajazd", "Bitwa", "Emigracja", "Rok 1812", "Kochajmy się"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-1,romanticism,batch-2025-01}', '{"explanation": "Przykładowe tytuły: ''Gospodarstwo'', ''Zamek'', ''Umizgi'', ''Dyplomatyka i łowy'', ''Kłótnia'', ''Zaścianek'', ''Rada'', ''Zajazd'', ''Bitwa'', ''Emigracja. Jacek'', ''Rok 1812'', ''Kochajmy się''."}', '2025-10-24 22:16:55.451', '2025-10-24 22:16:55.451', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evan1015hqhd9684e0aaa', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 4, 'Wyjaśnij symbolikę tytułu ostatniej księgi „Pana Tadeusza” - „Kochajmy się”.', '{"maxWords": 70, "expectedKeywords": ["pojednanie", "zgoda", "miłość", "jedność", "naród"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "''Kochajmy się'' to wezwanie do narodowej zgody i jedności. Po wszystkich sporach i walkach następuje pojednanie - osobiste (małżeństwa) i narodowe (nadzieja na niepodległość)."}', '2025-10-24 22:16:55.453', '2025-10-24 22:16:55.453', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evan3015iqhd9yes5ov2m', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Opisz krótko postać Gerwazego - kim był i jaką rolę odgrywał w „Panu Tadeuszu”.', '{"maxWords": 60, "expectedKeywords": ["Klucznik", "Horeszków", "wierny", "zemsta", "Scyzoryk"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Gerwazy to Klucznik rodu Horeszków, wierny sługa pragnący zemsty za śmierć swojego pana. Posługuje się słynnym mieczem Scyzorykiem i organizuje zajazd na Soplicowo."}', '2025-10-24 22:16:55.455', '2025-10-24 22:16:55.455', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evan5015jqhd9n7hgdqwc', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Która postać reprezentuje typ romantycznego indywidualisty w ''Panu Tadeuszu''?', '{"options": ["Tadeusz", "Hrabia", "Sędzia", "Gerwazy"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Hrabia to jedyna postać o cechach romantycznego indywidualisty - melancholik, esteta, człowiek tajemniczy, marzyciel oderwany od rzeczywistości."}', '2025-10-24 22:16:55.457', '2025-10-24 22:16:55.457', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evan7015kqhd9tvwcfya8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jak można interpretować postać Telimeny w kontekście społecznym?', '{"options": ["Przedstawicielka tradycyjnej szlachty", "Symbol nowych, kosmopolitycznych wpływów kultury miejskiej", "Typowa matka polska", "Wzór cnót niewieścich"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Telimena reprezentuje nowe wpływy - mieszkała w Petersburgu, nosi modne stroje, jest kokieteryjną damą salonową, obcą tradycyjnemu światu szlacheckiemu."}', '2025-10-24 22:16:55.459', '2025-10-24 22:16:55.459', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evan9015lqhd9dgkz2e3r', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Dlaczego postać Jacka Soplicy/Robaka można uznać za tragiczną?', '{"options": ["Bo był biedny", "Bo popełnił zbrodnię z miłości i całe życie pokutował", "Bo był księdzem", "Bo umarł młodo"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Jacek to postać tragiczna - zabił z miłości, stracił wszystko (miłość, honor, ojczyznę), całe życie pokutował jako Robak, by odkupić winę."}', '2025-10-24 22:16:55.462', '2025-10-24 22:16:55.462', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evanb015mqhd913qgd32j', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Co symbolizuje spór o zamek między Hrabią a Soplicami?', '{"options": ["Tylko chciwość szlachty", "Konflikt między starą arystokracją a nową szlachtą", "Spór rodzinny", "Walkę o kobietę"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Spór o zamek symbolizuje konflikt między odchodzącą arystokracją (Horeszkowie/Hrabia) a wzmacniającą się szlachtą średnią (Soplicowie)."}', '2025-10-24 22:16:55.464', '2025-10-24 22:16:55.464', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evand015nqhd9he5rqbec', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Jaka jest funkcja motywu polowania w strukturze utworu?', '{"options": ["Tylko rozrywka dla czytelnika", "Pokazanie obyczajów myśliwskich", "Metafora sporów społecznych i walki o dominację", "Wypełnienie fabuły"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Polowanie to metafora - spory o charty i niedźwiedzia odzwierciedlają konflikty społeczne, rywalizację między postaciami i walkę o pozycję."}', '2025-10-24 22:16:55.466', '2025-10-24 22:16:55.466', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evanf015oqhd9mrengq82', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Co symbolizuje ogród w Soplicowie?', '{"options": ["Bogactwo rodziny", "Arkadyjską sielankę i utracony raj dzieciństwa", "Nowoczesne gospodarstwo", "Tylko tło wydarzeń"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Ogród to symbol arkadii, utraconego raju dzieciństwa i harmonii. To przestrzeń idealizowana, związana z niewinnością i szczęściem."}', '2025-10-24 22:16:55.468', '2025-10-24 22:16:55.468', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evanh015pqhd9v2687jmy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Dlaczego Mickiewicz umieścił akcję w latach 1811-1812?', '{"options": ["Bo wtedy się urodził", "To czas nadziei na odzyskanie niepodległości dzięki Napoleonowi", "Przypadkowy wybór", "Bo wtedy pisał utwór"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Lata 1811-1812 to czas wielkiej nadziei - Napoleon szedł na Moskwę, Polacy wierzyli że pomoże odbudować Rzeczpospolitą."}', '2025-10-24 22:16:55.47', '2025-10-24 22:16:55.47', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evank015qqhd9t8b4igo1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jakie pokolenia idealistów reprezentują główne postacie według koncepcji ''trzech pokoleń''?', '{"options": ["Wszyscy to jedno pokolenie", "Rzecki (bonapartysta), Jacek (powstaniec), młodzież (nauka)", "Maciej Dobrzyński (konfederaci barscy), Jacek (powstaniec), Tadeusz (nowe czasy)", "Nie ma takiego podziału"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Trzy pokolenia idealistów: konfederaci barscy (Maciej), powstańcy (Jacek/Robak), młode pokolenie czekające na Napoleona (Tadeusz)."}', '2025-10-24 22:16:55.472', '2025-10-24 22:16:55.472', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evanm015rqhd9bzitgnpy', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Jak Mickiewicz przedstawia stosunek do Napoleona?', '{"options": ["Jednoznacznie pozytywny - Napoleon jako zbawca", "Całkowicie negatywny", "Ambiwalentny - nadzieja połączona z wątpliwościami (postać Macieja)", "Nie porusza tego tematu"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Stosunek jest ambiwalentny - większość wierzy w Napoleona, ale Maciej Dobrzyński wyraża wątpliwości (''idzie do Moskwy bez Boga'')."}', '2025-10-24 22:16:55.474', '2025-10-24 22:16:55.474', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evano015sqhd9qgovd6xi', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jaka jest funkcja retrospekcji w ''Panu Tadeuszu''?', '{"options": ["Tylko wydłużenie fabuły", "Wyjaśnienie tajemnic przeszłości kluczowych dla zrozumienia teraźniejszości", "Urozmaicenie narracji", "Pokazanie historii Polski"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Retrospekcje (np. historia Jacka i Stolnika) wyjaśniają motywy działań postaci i źródła konfliktów, są kluczowe dla zrozumienia fabuły."}', '2025-10-24 22:16:55.476', '2025-10-24 22:16:55.476', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evanq015tqhd9fx3ahxff', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Dlaczego ''Pan Tadeusz'' określany jest mianem ''epopei odmienionej''?', '{"options": ["Bo jest krótszy niż klasyczne epopeje", "Bo łączy cechy eposu z sielanką, nie ma wielkiego bohatera epickiego", "Bo jest napisany prozą", "Bo nie ma bóstw"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "''Pan Tadeusz'' to epopeja odmieniona - łączy epos z sielanką, zamiast heroicznych czynów opisuje codzienne życie szlachty."}', '2025-10-24 22:16:55.478', '2025-10-24 22:16:55.478', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evans015uqhd9f9lekm0z', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jaki zabieg stylistyczny dominuje w opisach przyrody?', '{"options": ["Naturalizm", "Animizacja i antropomorfizacja", "Abstrakcja", "Minimalizm"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Mickiewicz stosuje animizację i antropomorfizację - przyroda jest ożywiona, uczestniczy w wydarzeniach (np. drzewa ''patrzą'', stawy ''rozmawiają'')."}', '2025-10-24 22:16:55.48', '2025-10-24 22:16:55.48', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evanu015vqhd92ffjr9z8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jaka jest funkcja języka gawędowego w ''Panu Tadeuszu''?', '{"options": ["Tylko ozdoba stylistyczna", "Stworzenie atmosfery autentyczności i swojskości", "Utrudnienie lektury", "Pokazanie niewykształcenia szlachty"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Język gawędowy (dygresje, anegdoty, bezpośrednie zwroty) tworzy atmosferę swojskości, autentyczności i szlacheckiej gawędy."}', '2025-10-24 22:16:55.483', '2025-10-24 22:16:55.483', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evanx015wqhd9c24o4uy8', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Jak interpretować scenę koncertu Jankiela?', '{"options": ["Rozrywka podczas uczty", "Muzyczna synteza historii Polski i pojednania narodowego", "Pokaz umiejętności muzycznych", "Element folklorystyczny"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Koncert Jankiela to muzyczna synteza - historia Polski od triumfu przez upadek po nadzieję, symbol pojednania wszystkich warstw narodu."}', '2025-10-24 22:16:55.485', '2025-10-24 22:16:55.485', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evanz015xqhd9u4qm9ulj', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Co oznacza gest uwolnienia chłopów przez Tadeusza?', '{"options": ["Tylko hojność", "Symbol nowego porządku społecznego i idei demokratycznych", "Naśladowanie Napoleona", "Chęć zubożenia Hrabiego"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Uwolnienie chłopów to symbol nowych idei demokratycznych, zapowiedź przemian społecznych i końca feudalizmu."}', '2025-10-24 22:16:55.487', '2025-10-24 22:16:55.487', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evao1015yqhd9bwtitto0', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Które elementy świadczą o nostalgicznym charakterze utworu? (wybierz wszystkie)', '{"options": ["Idealizacja przeszłości", "Inwokacja do ojczyzny", "Epilog napisany na emigracji", "Szczegółowe opisy obyczajów", "Wątek miłosny", "Motyw ''kraju lat dziecinnych''"]}', '[0, 1, 2, 3, 5]', NULL, '{historical_literary,closed_multiple,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "O nostalgii świadczą: idealizacja przeszłości, tęsknota w inwokacji, epilog emigracyjny, dokumentowanie ginących obyczajów, motyw dzieciństwa. Wątek miłosny nie jest nostalgiczny."}', '2025-10-24 22:16:55.489', '2025-10-24 22:16:55.489', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evao3015zqhd9qykyb120', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Które konflikty społeczne przedstawia Mickiewicz? (wybierz wszystkie)', '{"options": ["Arystokracja vs szlachta średnia", "Szlachta zaściankowa vs szlachta zamożna", "Starzy (tradycja) vs młodzi (nowoczesność)", "Patrioci vs zdrajcy", "Polacy vs Rosjanie", "Idealiści vs realiści"]}', '[0, 1, 2, 3, 4]', NULL, '{historical_literary,closed_multiple,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Mickiewicz przedstawia konflikty: między warstwami szlachty, pokoleniami, patriotami i kolaborantami, Polakami i zaborcami. Konflikt idealistów z realistami jest marginalny."}', '2025-10-24 22:16:55.491', '2025-10-24 22:16:55.491', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evao50160qhd93v86e2bk', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Które elementy kultury sarmackiej przedstawione są w „Panu Tadeuszu”? (wybierz wszystkie)', '{"options": ["Kontusz i żupan", "Zajazd", "Gościnność", "Kult przodków", "Wolność szlachecka", "Religijność"]}', '[0, 1, 2, 3, 4, 5]', NULL, '{historical_literary,closed_multiple,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Wszystkie wymienione to elementy kultury sarmackiej: strój, obyczaje (zajazd, gościnność), wartości (kult przodków, wolność), religijność."}', '2025-10-24 22:16:55.494', '2025-10-24 22:16:55.494', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evao80161qhd9jbmregst', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Dopasuj postać do jej funkcji symbolicznej w utworze.', '{"leftColumn": [{"id": "A", "text": "Jacek/Robak"}, {"id": "B", "text": "Hrabia"}, {"id": "C", "text": "Jankiel"}, {"id": "D", "text": "Maciej Dobrzyński"}], "rightColumn": [{"id": 1, "text": "Romantyczny indywidualista"}, {"id": 2, "text": "Pokuta i odkupienie"}, {"id": 3, "text": "Tradycja i konserwatyzm"}, {"id": 4, "text": "Integracja społeczna różnych grup"}], "matchingType": "character_symbol"}', '[[0, 1], [1, 0], [2, 3], [3, 2]]', NULL, '{historical_literary,closed_multiple,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Jacek symbolizuje pokutę i odkupienie win, Hrabia - romantyzm, Jankiel - harmonijne współżycie różnych grup, Maciej - przywiązanie do tradycji."}', '2025-10-24 22:16:55.496', '2025-10-24 22:16:55.496', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaoa0162qhd9egv100r5', 'CLOSED_MULTIPLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Dopasuj motyw literacki do jego znaczenia w ''Panu Tadeuszu''.', '{"leftColumn": [{"id": "A", "text": "Motyw ogrodu"}, {"id": "B", "text": "Motyw polowania"}, {"id": "C", "text": "Motyw uczty"}, {"id": "D", "text": "Motyw domu"}], "rightColumn": [{"id": 1, "text": "Pojednanie i wspólnota"}, {"id": 2, "text": "Arkadia i utracony raj"}, {"id": 3, "text": "Konflikty i rywalizacja"}, {"id": 4, "text": "Tradycja i ciągłość"}], "matchingType": "motif_meaning"}', '[[0, 1], [1, 2], [2, 0], [3, 3]]', NULL, '{historical_literary,closed_multiple,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Ogród = arkadyjski raj, polowanie = metafora konfliktów społecznych, uczta = moment pojednania, dom = symbol tradycji i ciągłości."}', '2025-10-24 22:16:55.498', '2025-10-24 22:16:55.498', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaoc0163qhd9lk61da6t', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 3, 'Czym różni się ''Pan Tadeusz'' od typowej epopei romantycznej?', '{"options": ["Jest dłuższy", "Ma więcej bohaterów", "Opisuje codzienność zamiast czynów heroicznych", "Jest napisany prozą"]}', '2', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "''Pan Tadeusz'' różni się od romantycznych epopei skupieniem na codzienności, zwyczajnych ludziach i obyczajach, a nie na heroicznych czynach."}', '2025-10-24 22:16:55.501', '2025-10-24 22:16:55.501', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaoe0164qhd9rsjemgn1', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jak Mickiewicz godzi elementy klasyczne z romantycznymi?', '{"options": ["Nie godzi - są tylko elementy romantyczne", "Klasyczna forma epopei z romantyczną nostalgią i uczuciowością", "Są tylko elementy klasyczne", "Przypadkowe połączenie"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Mickiewicz łączy klasyczną formę epopei (12 ksiąg, wers epicki) z romantyczną treścią (nostalgia, uczucia, indywidualizm Hrabiego)."}', '2025-10-24 22:16:55.503', '2025-10-24 22:16:55.503', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaog0165qhd9gkh6txqw', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 2, 'Dlaczego Mickiewicz napisał „Pana Tadeusza” na emigracji?', '{"options": ["Dla zarobku", "Z tęsknoty za ojczyzną po upadku powstania listopadowego", "Na zamówienie wydawcy", "Dla rozrywki"]}', '1', NULL, '{historical_literary,closed_single,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Mickiewicz pisał ''Pana Tadeusza'' w Paryżu z tęsknoty za utraconą ojczyzną po klęsce powstania listopadowego (1831)."}', '2025-10-24 22:16:55.505', '2025-10-24 22:16:55.505', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaoj0166qhd9b3pwe0z4', 'CLOSED_SINGLE', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 2, 'Jak epilog zmienia perspektywę interpretacji całego utworu?', '{"options": ["Nie zmienia", "Ujawnia osobisty, nostalgiczny charakter i genezę utworu", "Zaprzecza wcześniejszej treści", "Jest tylko dodatkiem"]}', '1', NULL, '{historical_literary,closed_single,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Epilog ujawnia osobistą perspektywę - utwór powstał z tęsknoty emigranta, jako próba ocalenia w literaturze ginącego świata."}', '2025-10-24 22:16:55.508', '2025-10-24 22:16:55.508', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaom0167qhd9p9faxvh0', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Wyjaśnij, na czym polega tragizm postaci Jacka Soplicy.', '{"maxWords": 80, "expectedKeywords": ["miłość", "zabójstwo", "pokuta", "honor", "wygnanie", "odkupienie"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Jacek to bohater tragiczny - z miłości do Ewy zabił jej ojca, stracił honor, ojczyznę, ukochana zmarła. Całe życie pokutował jako Robak, walcząc za Polskę."}', '2025-10-24 22:16:55.51', '2025-10-24 22:16:55.51', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaoo0168qhd91yxwppxx', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Opisz rolę przyrody w ''Panu Tadeuszu'' - podaj 2-3 funkcje.', '{"maxWords": 70, "expectedKeywords": ["tło", "uczestnik", "symbol", "arkadia", "ojczyzna", "harmonia"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Przyroda: 1) tło wydarzeń i element sielanki, 2) uczestnik akcji (antropomorfizacja), 3) symbol ojczyzny i utraconego raju, 4) element harmonii świata."}', '2025-10-24 22:16:55.512', '2025-10-24 22:16:55.512', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaoq0169qhd9te4rss8z', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Porównaj postacie Telimeny i Zosi - wskaż główne różnice.', '{"maxWords": 80, "expectedKeywords": ["wiek", "doświadczenie", "prostota", "kokieteria", "miasto", "wieś", "tradycja", "nowoczesność"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Telimena: dojrzała, kokieteryjna, miejska, nowoczesna, wyrachowana. Zosia: młoda, niewinna, wiejska, tradycyjna, naturalna. Reprezentują dwa modele kobiecości."}', '2025-10-24 22:16:55.514', '2025-10-24 22:16:55.514', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaos016aqhd9l32xvl7l', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Wyjaśnij symbolikę zajazdu jako ''ostatniego zajazdu na Litwie''.', '{"maxWords": 70, "expectedKeywords": ["tradycja", "koniec", "epoka", "szlachta", "obyczaje", "przemiana"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Ostatni zajazd symbolizuje koniec epoki - staropolskich obyczajów, tradycyjnych sporów szlacheckich rozwiązywanych siłą. Zapowiada nowe czasy i nowy porządek."}', '2025-10-24 22:16:55.516', '2025-10-24 22:16:55.516', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaou016bqhd9vp8hggcx', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Jak Mickiewicz przedstawia relacje polsko-żydowskie na przykładzie Jankiela?', '{"maxWords": 60, "expectedKeywords": ["harmonia", "szacunek", "patriotyzm", "wspólnota", "tolerancja", "integracja"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Jankiel to przykład harmonijnego współżycia - szanowany przez szlachtę, patriota polski (''Żyd poczciwy Ojczyznę jako Polak kochał''), symbol tolerancji i integracji."}', '2025-10-24 22:16:55.519', '2025-10-24 22:16:55.519', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaow016cqhd97snkdoy4', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 5, 'Zinterpretuj znaczenie słów ''Kochajmy się'' jako przesłania utworu.', '{"maxWords": 90, "expectedKeywords": ["pojednanie", "zgoda", "jedność", "naród", "przebaczenie", "wspólnota", "miłość"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "''Kochajmy się'' to wezwanie do narodowej zgody, przebaczenia win, pojednania po sporach. To przesłanie jedności wobec nadziei na niepodległość, uniwersalne przesłanie miłości."}', '2025-10-24 22:16:55.521', '2025-10-24 22:16:55.521', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evaoz016dqhd9yf1weanp', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 3, 4, 'Wyjaśnij, dlaczego ''Pan Tadeusz'' jest utworem nostalgicznym.', '{"maxWords": 80, "expectedKeywords": ["emigracja", "tęsknota", "przeszłość", "idealizacja", "utrata", "pamięć", "dzieciństwo"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-3,romanticism,batch-2025-01}', '{"explanation": "Nostalgia wynika z: sytuacji autora (emigracja), idealizacji przeszłości, tęsknoty za utraconą ojczyzną, chęci ocalenia ginącego świata w pamięci, motywu ''kraju lat dziecinnych''."}', '2025-10-24 22:16:55.523', '2025-10-24 22:16:55.523', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evap1016eqhd99axavr01', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'ROMANTICISM', 2, 3, 'Jakie cechy epopei zachowuje „Pan Tadeusz”? Wymień 3-4.', '{"maxWords": 60, "expectedKeywords": ["inwokacja", "księgi", "narrator", "wers", "katalog", "porównania", "epitety"]}', NULL, NULL, '{historical_literary,short_answer,difficulty-2,romanticism,batch-2025-01}', '{"explanation": "Cechy epopei: inwokacja, podział na 12 ksiąg, narrator wszechwiedzący, wers epicki (13-zgłoskowiec), rozbudowana fabuła, katalogi postaci, porównania homeryckie, stały epitet."}', '2025-10-24 22:16:55.525', '2025-10-24 22:16:55.525', 'Pan Tadeusz');
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evap3016fqhd9z6wg9z9m', 'SHORT_ANSWER', 'HISTORICAL_LITERARY', 'CONTEMPORARY', 3, 2, 'Jak Czesław Miłosz w wierszu ''Piosenka'' nawiązuje do Księgi Koheleta?', '{"hint": "Motyw przemijania i marności"}', NULL, NULL, '{historical_literary,short_answer,difficulty-3,contemporary,batch-2025-01,Miłosz,Kohelet,przemijanie}', NULL, '2025-10-24 22:16:55.527', '2025-10-24 22:16:55.527', NULL);
INSERT INTO public."Exercise" (id, type, category, epoch, difficulty, points, question, content, "correctAnswer", rubric, tags, metadata, "createdAt", "updatedAt", work) VALUES ('cmh5evap5016gqhd9rs017675', 'CLOSED_MULTIPLE', 'LANGUAGE_USE', NULL, 2, 2, 'Które cechy charakteryzują styl nominalny?', '{"options": ["Przewaga rzeczowników", "Dużo czasowników", "Konstrukcje bezosobowe", "Zdania pojedyncze", "Rozbudowane zdania złożone", "Abstrakcyjność"]}', '[0, 2, 5]', NULL, '{language_use,closed_multiple,difficulty-2,batch-2025-01,style,język}', NULL, '2025-10-24 22:16:55.53', '2025-10-24 22:16:55.53', NULL);
